/* ============================================================
   Procedure: [dbo].[Serv_Ticket_Feedback_Submit]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC Serv_Ticket_Feedback_Submit           
(              
@ticketid NVARCHAR(50),              
@Rating nvarchar(20),              
@Comments nvarchar(max)          
)              
as              
begin              
              
declare  @roweff int         
declare @ticket bigint        
        
set @ticket = (select distinct TicketID from serv_tickethistory         
WHERE TicketHistoryID = convert(bigint,left(SUBSTRING(@ticketid,CHARINDEX('_',@ticketid,CHARINDEX('_',@ticketid)+1)+1,(((LEN(@ticketid))-CHARINDEX('_', REVERSE(@ticketid)))-CHARINDEX('_',@ticketid))),CHARINDEX('_',SUBSTRING
(@ticketid,CHARINDEX('_',@ticketid,CHARINDEX('_',@ticketid)+1)+1,(((LEN(@ticketid))-CHARINDEX('_', REVERSE(@ticketid)))-CHARINDEX('_',@ticketid))))-1)))          
              
              
IF NOT EXISTS ( SELECT '*' FROM Serv_ticket_feedback_tbl             
WHERE TicketHistoryID = convert(bigint,left(SUBSTRING(@ticketid,CHARINDEX('_',@ticketid,CHARINDEX('_',@ticketid)+1)+1,(((LEN(@ticketid))-CHARINDEX('_', REVERSE(@ticketid)))-CHARINDEX('_',@ticketid))),CHARINDEX('_',SUBSTRING
(@ticketid,CHARINDEX('_',@ticketid,CHARINDEX('_',@ticketid)+1)+1,(((LEN(@ticketid))-CHARINDEX('_', REVERSE(@ticketid)))-CHARINDEX('_',@ticketid))))-1)))          
          
BEGIN  
declare @id table(fdbkid bigint)
declare @fdbkid bigint            
INSERT INTO Serv_ticket_feedback_tbl (TicketHistoryID,Rating,Comments,SUBMITDATE,TICKETID) output inserted.id  into @id      
VALUES (convert(bigint,left(SUBSTRING(@ticketid,CHARINDEX('_',@ticketid,CHARINDEX('_',@ticketid)+1)+1,(((LEN(@ticketid))-CHARINDEX('_', REVERSE(@ticketid)))-CHARINDEX('_',@ticketid))),CHARINDEX('_',SUBSTRING(@ticketid,CHARINDEX
('_',@ticketid,CHARINDEX('_',@ticketid)+1)+1,(((LEN(@ticketid))-CHARINDEX('_', REVERSE(@ticketid)))-CHARINDEX('_',@ticketid))))-1)),              
  @Rating, @Comments, GETDATE(),@ticket )              
select  @roweff = @@ROWCOUNT              
select top 1 @fdbkid= fdbkid from @id             
END              
              
select @roweff              
   
   
  /* Start Lead activity */   
  
   Begin try  
  
   Declare @TicketID_LDACTV bigint = @ticketid   
   Declare @UserID_LDACTV bigint = 0  
   Declare @ParentID_LDACTV bigint = 0  
   Declare @kit19UserID bigint = 0   
   Declare @TicketTitle_LDACTV nvarchar(500) = ''  
   Declare @TicketCreationDate nvarchar(50) = ''  
   Declare @TicketRating_LDACTV nvarchar(100) = @Rating    
  
    
   select top 1 @UserID_LDACTV = isnull(USER_ID,0),@ParentID_LDACTV = isnull(ParentID,0),@TicketTitle_LDACTV = isnull(Subject,'')  
     from Serv_TicketMaster where TicketID =  ISNULL(@TicketID_LDACTV,0)   
    
  
  Declare @LeadID_LDACTV bigint = 0  
    
  Select top 1 @LeadID_LDACTV = isnull(LeadID,0)  from Serv_User_Detail where ser_user_id = @UserID_LDACTV  
   
   if(exists(select 1 from Serv_User_Master where Service_id = @UserID_LDACTV and kit19_User = 1))  
       Begin  
        select @kit19UserID = isnull(kit19_id,0)  from Serv_User_Master where Service_id = @UserID_LDACTV  
    End  
 else  
    Begin  
       set  @kit19UserID = @ParentID_LDACTV   
    End  
      
  
  create table #tblEventDescrb  
   (  
     EVNT_Description nvarchar(max)   
   )  
  
  if( isnull(@LeadID_LDACTV,0) > 0)  
   Begin  
      
   insert into #tblEventDescrb  
      exec  Usp_EventTemplate_DynamicVarReplacement 'Lead reviews a ticket',@kit19UserID,'','',@LeadID_LDACTV,'',null  
   ,0,0,'','',0,'',0,null,null,null,null,null,null,null,@TicketTitle_LDACTV,null  
   ,null,null,null,null,null,null,null,null,  
   0,0,0,null,null,null,@TicketRating_LDACTV,null,null,null,0,null,null  
       
   declare @evntMessage nvarchar(max) = ''   
   select @evntMessage = isnull( EVNT_Description,'') from #tblEventDescrb  
   
   if(@evntMessage <> '')  
   Begin  
   exec UspSaveLeadActivity_withid @LeadID_LDACTV,@kit19UserID,@ParentID_LDACTV,@evntMessage,    'Lead reviews a ticket','Serv_ticket_feedback_tbl',@fdbkid  
   end  
  
  
   End    
  
   end try  
   Begin catch  
     
      exec usp_InsertErrorInfo  
  
   end catch  
  
   IF OBJECT_ID('tempdb..#tblEventDescrb') IS NOT NULL -- Check for table existence    
   Begin    
        DROP TABLE #tblEventDescrb   
   End    
    
  
   /*End Lead activity */  
  
  
              
end


GO

/* ============================================================
   Procedure: [dbo].[SERV_TICKET_STATUS_RESOLVE]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROC SERV_TICKET_STATUS_RESOLVE
AS
BEGIN

DECLARE @roweff INT
DECLARE @roweff1 INT

SELECT M.TicketID, MAX(H.TicketHistoryID) AS TicketHistoryID  INTO #CLOSE 
FROM Serv_TicketMaster M
INNER JOIN Serv_TicketHistory H
ON M.TicketID = H.TicketID AND M.User_id = H.user_id AND M.ParentID = H.ParentID
WHERE M.Status = 2 AND DATEDIFF(HH,update_date,GETDATE())>= 48 GROUP BY M.TicketID

UPDATE Serv_TicketMaster
SET Status = 4, resolved_dt = GETDATE(), update_date = GETDATE()
WHERE TicketID =  (SELECT TicketID FROM #CLOSE) 

select  @roweff = @@ROWCOUNT

INSERT INTO Serv_TicketHistory
SELECT TicketID,user_id,ParentID,ResponseTime,GETDATE(),Note,4,GETDATE(),TransferredTo,Remarks,Priority,
Transfered_from,Activity_lavel,Assign_Group,Ticket_Response,raisedby,Ticket_type
FROM Serv_TicketHistory WHERE Status = 4 AND TicketHistoryID =  (SELECT TicketHistoryID FROM #CLOSE)

select  @roweff1 = @@ROWCOUNT

DROP TABLE #CLOSE

END



GO

/* ============================================================
   Procedure: [dbo].[Serv_TicketBeingHandled]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Serv_TicketBeingHandled] --3
(
 @TicketID bigint
)
as
Begin
--declare @TicketID bigint = 3
  declare @SLAIDs nvarchar(200); 
  SELECT
       ss.[SLAID]  
      --,[appl_id]
      --,[Apply_to]  
      --,[Apply_val]  
      --,[SLA_Name]  
      --,[SLA_Desc]  
      --,[DateCreated]  
      --,[Active]  
      --,[ord_no]  
        into #SLARulesData
     
  FROM   Serv_SLA_Setting SS  left outer join  [Serv_SLA_ApplyRule](nolock) AR on   SS.SLAId = Ar.SLAID
    
   where ss.ParentID in ( select ParentID from Serv_TicketMaster where TicketID = @TicketID
                         )
          and
             (
              ss.SLAId in (
              
              select  SLAID  from Serv_SLA_ApplyRule where (Apply_to = 'Company' and Apply_val like '%' + (                select ISNULL(Company,'')  from [Serv_TicketMaster]  where TicketID = @TicketID)+ '%
        ')   
          or   
       ( Apply_to = 'Source' and Apply_val like '%' + ( select ISNULL(Source,'')  from [Serv_TicketMaster]  where TicketID = @TicketID) + '%' )   
         or  
        ( Apply_to = 'Product' and Apply_val like '%' + ( select ISNULL(Product,'')  from [Serv_TicketMaster]  where TicketID = @TicketID) + '%' )  
         or  
        ( Apply_to = 'Type' and Apply_val =  ( select CONVERT(varchar,ISNULL(Ticket_type,0))  from [Serv_TicketMaster]  where TicketID = @TicketID)           )   
              or  
       ( Apply_to = 'Group' and Apply_val =  ( select CONVERT(varchar, ISNULL(Assign_Group,0))  from [Serv_TicketMaster]  where TicketID = @TicketID ))  
                            
             and (Parent_id in ( select ParentID from Serv_TicketMaster where TicketID = @TicketID))  
  
              
              
              )     
               or
              
     ss.SLAId not in (
              
                             
  select  SLAID  from Serv_SLA_ApplyRule where (Apply_to = 'Company' and Apply_val like '%' + (                select ISNULL(Company,'')  from [Serv_TicketMaster]  where TicketID = @TicketID)+ '%
        ')   
          or   
       ( Apply_to = 'Source' and Apply_val like '%' + ( select ISNULL(Source,'')  from [Serv_TicketMaster]  where TicketID = @TicketID) + '%' )   
         or  
        ( Apply_to = 'Product' and Apply_val like '%' + ( select ISNULL(Product,'')  from [Serv_TicketMaster]  where TicketID = @TicketID) + '%' )  
         or  
        ( Apply_to = 'Type' and Apply_val =  ( select CONVERT(varchar,ISNULL(Ticket_type,0))  from [Serv_TicketMaster]  where TicketID = @TicketID)           )   
              or  
       ( Apply_to = 'Group' and Apply_val =  ( select CONVERT(varchar, ISNULL(Assign_Group,0))  from [Serv_TicketMaster]  where TicketID = @TicketID ))  
                            
             and (Parent_id in ( select ParentID from Serv_TicketMaster where TicketID = @TicketID))  
              
              )
            
            )
             
             order by ord_no asc
    
    -- select @ApplyRuleID = ISNULL(STUFF((SELECT ',' + CONVERT(varchar,appl_id)
    
    
     select @SLAIDs = ISNULL(STUFF((SELECT ',' + CONVERT(varchar,SLAID) from (select distinct SLAID from #SLARulesData ) as tbl
     
      FOR XML PATH('')  
            ), 1, 1, ''),'')
     
    
    select @SLAIDs
    
    Drop table #SLARulesData
                          
End


GO

