   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Serv_TranbsferHandleToOtherUser  
(  
 @AgentID Bigint,  
 @ToBeAssigned bigint  
)    
as  
Begin  
  declare @UserID bigint = 0  
  select @UserID = Userid From Serv_Agent_Mast where Agent_Id = @AgentID  
  if(@UserID > 0)  
    Begin  
      update Serv_TicketMaster set AssignTo = @ToBeAssigned  where AssignTo = @UserID and Status <> 2  
      select 'Transfered'      
    End  
  
  
End


