CREATE   PROC [dbo].[Serv_Update_sourcesetting]  
     (  
     @parentid bigint,  
     @email int,   
     @website int,   
     @api int,   
     @webform_access varchar(100),   
     @modified_by varchar(100)  
     )    
AS    
  
begin   
  
declare @webfrm as int =0;  
if @webform_access!=''  
 set @webfrm = 1  
     
 if exists ( select 1  from dbo.serv_source_setting_master where ParentId=@parentid )  
  update serv_source_setting_master set email=@email, website=@website,   
  api=@api,  modified_by= @modified_by,  
  last_modified = getdate() where ParentId=@parentid   
 else  
 insert into serv_source_setting_master  
  (ParentId, email, website, api,  modified_by)  
  select @ParentId, @email, @website,  @api,  @modified_by  
  
declare @spos as int,@lpos int  
declare @frmid as bigint  
declare @val as bit  
declare @subj as varchar(20)  
  
while LEN(@webform_access) > 0                    
begin                    
 --Declare @compsubject varchar(max)='',                    
 --@compbody varchar(max)=''                    
                 
 select @spos = CHARINDEX( ',' , @webform_access , 0 )           
 if @spos=0          
 begin          
  set @lpos =CHARINDEX( '#' , @webform_access , 0 )   
  set @frmid = cast(SUBSTRING(@webform_access,0,@lpos) as bigint)   
  set @val = CAST( SUBSTRING(@webform_access,@lpos+1,LEN(@webform_access)-@lpos) as bit)    
set @webform_access =''  
   
 end  
else  
begin  
  set @subj = SUBSTRING(@webform_access,0,@spos)   
 set @webform_access = SUBSTRING(@webform_access,@spos+1,LEN(@webform_access)-@spos)  
     
  set @lpos =CHARINDEX( '#' , @subj , 0 )   
  set @frmid = cast(SUBSTRING(@subj,0,@lpos) as int)   
   set @val = CAST( SUBSTRING(@subj,@lpos+1,LEN(@subj)-@lpos) as bit)     
end            
 update WebFormTbl set isticket = @val where  FormId = @frmid  
  
end                    
  
  
  
 select 'Updated'  
  
  
--end  
  
  
