/* ============================================================
   Procedure: [dbo].[Serv_Update_Ticket_Dispatch_Order]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Serv_Update_Ticket_Dispatch_Order]    
     (  
     @tbl Serv_tickttbl_Order READONLY,
     @opt varchar(20)
     )    
AS    
     
begin    
if @opt='Dispatch'
begin
update ss set ord_no = tp.ord_no
from Serv_Ticket_Dispatch ss
inner join @tbl tp on tp.ID = ss.TResp_Rule_Id
end
if @opt='Sla'
begin
update ss set ord_no = tp.ord_no
from dbo.Serv_SLA_Setting ss
inner join @tbl tp on tp.ID = ss.SLAId
end
select 'Updated' resp  
end


GO

/* ============================================================
   Procedure: [dbo].[Serv_Update_Ticket_status]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Serv_Update_Ticket_status]                          
(                          
@TicketID bigint,                           
@Remarks nvarchar(max) ='',                
@Note nvarchar(max) ='',                          
@assign_id bigint,                      
@groupid bigint,                      
@Priority int,                     
@raisedby  bigint,                    
@Status  int,        
@ticket_type int                       
)                         
            
            
AS                          
begin                          
declare @TicketNo nvarchar(16),                          
@prifix nvarchar(15),                           
@curNo int                          

                     
declare @User_ID bigint,                     
@ParentID bigint, @Subject  nvarchar(max) ='',                    
@agent nvarchar(100), @group  nvarchar(100)                     
                    
select @User_ID = User_ID, @ParentID= ParentID, @TicketNo= TicketNo ,                    
 @Subject = Subject from                     
Serv_TicketMaster  where TicketID = @TicketID                     
                    
select @agent =Name , @group = Group_Name from Serv_User_Detail um inner join                    
Serv_Agent_Mast am on um.User_id = am.Userid inner join Serv_Group_Mast gm                    
on gm.Groupid = am.Group_id                    
                    
                      
--declare @assign_id bigint =0, @groupid as int=0                     
                      
--select @assign_id = User_id from  Serv_User_Detail where                       
--Login_id = @AssignTo                      
                      
--select @groupid =Groupid from  Serv_Group_Mast where Group_Name = @Assign_Group                      
                      
insert into dbo.Serv_TicketHistory (TicketID, ParentID,User_id, SubmittedDate, Status,         HistoryDate, Remarks, Priority, Assign_Group,TransferredTo, Transfered_from, raisedby,                
Note,ticket_type)                     
 select TicketID, ParentID, User_id, GETDATE(), @Status,GETDATE(),@Remarks,Priority,                    
  @groupid, @assign_id, AssignTo ,@raisedby, @Note, @ticket_type                      
 from Serv_TicketMaster where TicketID = @TicketID                      
                      
update Serv_TicketMaster  set Remarks =@Remarks,                      
AssignTo=@assign_id, Assign_Group =@groupid,                      
Priority=@Priority, Status=@Status  ,AssignedDateTime = GETDATE(), Assignedby = @raisedby                   
where TicketID = @TicketID                      
                    
                      
select @@ROWCOUNT mrow,'Updated' resp                      
if @Status=4  
   Begin                 
exec serv_Raise_emailNotification @TicketID,@ParentID,0 , @User_ID,@User_ID,'Agent Solves the Ticket','Requester'                  
      
	  
  /* Start Lead Activity ticket resolved  */

  Begin try


   Declare @TicketID_LDACTV_1 bigint = @TicketID 
   Declare @SLAID_LDACTV_1 bigint = 0
   
   Declare @Priority_LDACTV_1 int  = @Priority  

   Declare @UserID_LDACTV_1 bigint = 0
  
   Declare @ParentID_LDACTV_1 bigint = 0
   Declare @kit19UserID_1 bigint = 0 
   
   Declare @RaisedBy_1 bigint = @raisedby; 

   Declare @TicketTitle_LDACTV_1 nvarchar(500) = ''
   
   Declare @LatencyHours_LDACTV_1 int = 0
   Declare @TotaltimeinHours_LDACTV_1 int = 0 

   Declare @CreatedDate_LDACTV_1 datetime = null; 
   Declare @ResponseWithinDate_LDACTV_1 datetime  = getdate();
   Declare @ResolveDate_LDACTV_1 datetime = getdate()  




  
   select top 1 @UserID_LDACTV_1 = isnull(USER_ID,0),@ParentID_LDACTV_1 = isnull(ParentID,0),@TicketTitle_LDACTV_1 = isnull(Subject,'')
        ,@Priority_LDACTV_1 = isnull(Priority,0) , @CreatedDate_LDACTV_1 = Date_Created from Serv_TicketMaster where TicketID =  ISNULL(@TicketID_LDACTV_1,0) 
		
  
   select top 1 @SLAID_LDACTV_1 = isnull(SLAID,0)  from Serv_SLA_Response(nolock)            
      where  ParentID = @ParentID_LDACTV_1 and Priority_ID = @Priority_LDACTV_1  

    select @ResponseWithinDate_LDACTV_1 = isnull(RSPWithinDate,getdate())  from  Serv_TicketTimelyPRM where TicketID = ISNULL(@TicketID_LDACTV_1,0) and SLAID = isnull(@SLAID_LDACTV_1,0)


	select

	  @ResolveDate_LDACTV_1 =  COALESCE(AfterA4RSLVDate,AfterA3RSLVDate,AfterA2RSLVDate,AfterA1RSLVDate
	  ,AfterARSPNSDate,BeforeRSLVDate,BeforeRSPNSDate,RSLVWithinDate,getdate()) 
		
	 from  Serv_TicketTimelyPRM where TicketID = ISNULL(@TicketID_LDACTV_1,0) and SLAID = isnull(@SLAID_LDACTV_1,0)

	 select @TotaltimeinHours_LDACTV_1 = isnull(DATEDIFF(HH,@CreatedDate_LDACTV_1,@ResolveDate_LDACTV_1),0)

	 select @LatencyHours_LDACTV_1 = isnull(DATEDIFF(HH,@ResponseWithinDate_LDACTV_1,@ResolveDate_LDACTV_1),0)


   Declare @LeadID_LDACTV_1 bigint = 0
  
   Select top 1 @LeadID_LDACTV_1 = isnull(LeadID,0)  from Serv_User_Detail where ser_user_id = @UserID_LDACTV_1
  	   
   set  @kit19UserID_1  = @RaisedBy_1

	 select top 1  @ParentID_LDACTV_1 = ISNULL(ParentID,0) from User_Detail where User_ID = @kit19UserID_1

  create table #tblEventDescrb_1
   (
     EVNT_Description nvarchar(max) 
   )

  if( isnull(@LeadID_LDACTV_1,0) > 0)
   Begin
    
	  insert into #tblEventDescrb_1
      exec  Usp_EventTemplate_DynamicVarReplacement 'Leads ticket resolved',@kit19UserID_1,'','',@LeadID_LDACTV_1,'',null
	  ,0,0,'','',0,'',0,null,null,null,null,null,null,null,@TicketTitle_LDACTV_1,null
	  ,null,@LatencyHours_LDACTV_1,@TotaltimeinHours_LDACTV_1,null,null,null,null,null,
	  0,0,0,null,null,null,null,null,null,null,0,null,null
		   
	  declare @evntMessage_1 nvarchar(max) = '' 
	  select @evntMessage_1 = isnull( EVNT_Description,'') from #tblEventDescrb_1
	
	  if(@evntMessage_1 <> '')
	  Begin
	  exec UspSaveLeadActivity @LeadID_LDACTV_1,@kit19UserID_1,@ParentID_LDACTV_1,@evntMessage_1,
	  'Leads ticket resolved'
	  end


   End  

   end try
   Begin catch
   
     exec usp_insertErrorInfo

   End catch


   IF OBJECT_ID('tempdb..#tblEventDescrb_1') IS NOT NULL -- Check for table existence  
    Begin  
        DROP TABLE #tblEventDescrb_1  
    End  
  
   /* End Lead Activity ticket resolved  */

   end 	              
if @Status=2                   
exec serv_Raise_emailNotification @TicketID,@ParentID,0 , @User_ID,@User_ID,'Agent Closes the Ticket','Requester'                  
                  
if @groupid > 0                  
begin                  
 exec serv_Raise_emailNotification @TicketID,@ParentID,@groupid, @User_ID,@User_ID,'Ticket Assigned to Group','Agent'                  
end                  
if @assign_id > 0                  
 exec serv_Raise_emailNotification @TicketID,@ParentID,@groupid,@User_ID, @assign_id,'Ticket Assigned to Agent','Agent'                  
                  
           
     
      /* Start lead activity  */  
  
   Begin try  
  
  
  
   Declare @TicketID_LDACTV bigint =  @TicketID  
   Declare @SLAID_LDACTV bigint = 0  
     
   Declare @Priority_LDACTV int  = @Priority    
  
   Declare @UserID_LDACTV bigint = 0  
    
   Declare @ParentID_LDACTV bigint = 0  
   Declare @kit19UserID bigint = 0   
     
   Declare @RaisedBy_LDACTV bigint = @raisedby;   
  
   Declare @TicketTitle_LDACTV nvarchar(500) = ''  
     
   Declare @LatencyHours_LDACTV int = 0  
   Declare @TotaltimeinHours_LDACTV int = 0   
  
   Declare @CreatedDate_LDACTV datetime = null;   
   Declare @ResponseWithinDate_LDACTV datetime  = getdate();  
   Declare @ResolveDate_LDACTV datetime = getdate()    
  
  
  
  
    
   select top 1 @UserID_LDACTV = isnull(USER_ID,0),@ParentID_LDACTV = isnull(ParentID,0),@TicketTitle_LDACTV = isnull(Subject,'')  
        ,@Priority_LDACTV = isnull(Priority,0) , @CreatedDate_LDACTV = Date_Created from Serv_TicketMaster where TicketID =  ISNULL(@TicketID_LDACTV,0)   
    
    
   select top 1 @SLAID_LDACTV = isnull(SLAID,0)  from Serv_SLA_Response(nolock)              
      where  ParentID = @ParentID_LDACTV and Priority_ID = @Priority_LDACTV    
  
    select @ResponseWithinDate_LDACTV = isnull(RSPWithinDate,getdate())  from  Serv_TicketTimelyPRM where TicketID = ISNULL(@TicketID_LDACTV,0) and SLAID = isnull(@SLAID_LDACTV,0)  
  
  
 select  
  
   @ResolveDate_LDACTV =  COALESCE(AfterA4RSLVDate,AfterA3RSLVDate,AfterA2RSLVDate,AfterA1RSLVDate  
   ,AfterARSPNSDate,BeforeRSLVDate,BeforeRSPNSDate,RSLVWithinDate,getdate())   
    
  from  Serv_TicketTimelyPRM where TicketID = ISNULL(@TicketID_LDACTV,0) and SLAID = isnull(@SLAID_LDACTV,0)  
  
  select @TotaltimeinHours_LDACTV = isnull(DATEDIFF(HH,@CreatedDate_LDACTV,@ResolveDate_LDACTV),0)  
  
  select @LatencyHours_LDACTV = isnull(DATEDIFF(HH,@ResponseWithinDate_LDACTV,@ResolveDate_LDACTV),0)  
  
  
   Declare @LeadID_LDACTV bigint = 0  
    
   Select top 1 @LeadID_LDACTV = isnull(LeadID,0)  from Serv_User_Detail where ser_user_id = @UserID_LDACTV  
   
 --  if(exists(select 1 from Serv_User_Master where Service_id = @UserID_LDACTV and kit19_User = 1))  
 --      Begin  
 --       select @kit19UserID = isnull(kit19_id,0)  from Serv_User_Master where Service_id = @UserID_LDACTV  
 --   End  
 --else  
 --   Begin  
 --      set  @kit19UserID = @ParentID_LDACTV   
 --   End  
      
  set  @kit19UserID  = @RaisedBy  
  
  select top 1  @ParentID_LDACTV = ISNULL(ParentID,0) from User_Detail where User_ID = @kit19UserID  
  
  create table #tblEventDescrb  
   (  
     EVNT_Description nvarchar(max)   
   )  
  
  if( isnull(@LeadID_LDACTV,0) > 0)  
   Begin  
      
   insert into #tblEventDescrb  
      exec  Usp_EventTemplate_DynamicVarReplacement 'Leads ticket answered',@kit19UserID,'','',@LeadID_LDACTV,'',null  
   ,0,0,'','',0,'',0,null,null,null,null,null,null,null,@TicketTitle_LDACTV,null  
   ,@CreatedDate_LDACTV,@LatencyHours_LDACTV,null,null,null,null,null,null,  
   0,0,0,null,null,null,null,null,null,null,0,null,null  
       
   declare @evntMessage nvarchar(max) = ''   
   select @evntMessage = isnull( EVNT_Description,'') from #tblEventDescrb  
   
   if(@evntMessage <> '')  
   Begin  
   exec UspSaveLeadActivity @LeadID_LDACTV,@kit19UserID,@ParentID_LDACTV,@evntMessage,    'Leads ticket answered'  
   end  
  
  
   End    
  
  
   end try  
   Begin catch  
     
     exec usp_insertErrorInfo  
     
   End catch  
  
  
   IF OBJECT_ID('tempdb..#tblEventDescrb') IS NOT NULL -- Check for table existence    
   Begin    
        DROP TABLE #tblEventDescrb    
   End    
     
   --  Drop table #tblEventDescrb  
  
  
   /* End lead activity  */  
     
     
              
