/* ============================================================
   Procedure: [dbo].[Serv_updateTicketSLA]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--Serv_updateTicketSLA 116, 16301 
CREATE   PROCEDURE [dbo].[Serv_updateTicketSLA]        
(  
@TicketID bigint,@ParentID bigint  
)  
as        
Begin        
 Declare @TicketCount int = 0          
 Declare @i int = 1        
     
   select ss.[SLAId]    
      ,ss.[ParentID]    
      ,ss.[SLA_Name]    
      ,ss.[SLA_Desc]    
      ,ss.[DateCreated]    
      ,ss.[Active]    
      ,ss.[ord_no]    
      ,AR.[appl_id]    
      ,Ar.[Apply_to]    
      ,Ar.[Apply_val] ,ROW_NUMBER() OVER (ORDER BY ss.ord_no DESC) AS RowID into #TempSLA1         
   from  Serv_SLA_Setting SS  left outer join  [Serv_SLA_ApplyRule](nolock) AR        
    on   SS.SLAId = Ar.SLAID where ss.ParentID = @ParentID order by ss.ord_no           
           
   declare @RowNum int ,@MaxRowNum int        
           
   select @RowNum = MIN(RoWID) ,@MaxRowNum = MAX(RowID) from #TempSLA1        
   while(@RowNum <= @MaxRowNum )        
      Begin        
     declare @result int = 0        
           declare @slaid as bigint        
           select @slaid = slaid from #TempSLA1 where RowID =@RowNum        
           if(exists(select 'x' from Serv_SLA_ApplyRule where SLAID = @slaid))         
     begin        
        if (select COUNT(*)  from  Serv_SLA_ApplyRule where SLAId = @SLAId )   > 0        
    begin  
     
     exec Serv_apply_slarule_FurtherUse @TicketID,@slaid, @result         
         
     if @result = 1        
     break;   
    end                 
     --         end        
     --         else        
     --           begin        
     --         --    exec Serv_ApplyEmailRule        
     end        
            
  set @RowNum = @RowNum +1;        
      End        
 drop table #TempSLA1      
End


GO

