/* ============================================================
   Procedure: [dbo].[Serv_ValidateGUID]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Serv_ValidateGUID      
(      
 @GUID nvarchar(200)      
)      
as      
Begin      
     Declare @UserID int = 0      
      
     if(exists(select 'x' from Serv_User_Detail where resetguid = @GUID))      
       Begin      
             select @UserID = USER_ID from Serv_User_Detail where resetguid = @GUID      
             
             if(exists(select 'x' from Serv_User_Detail where USER_ID = @UserID       
                   
             and resetexpired = 1 ))      
                begin      
                    select 'Expired'      
                End      
                      
             else      
                Begin      
                    select 'Valid'      
                End         
             
       End      
     else      
       Begin      
            select 'NotExists'      
       End        
             
End


GO

