CREATE   PROCEDURE [dbo].[serv_verify_requester]
(                                    
@email_id as nvarchar(100),                                    
@vmail_id as nvarchar(100),                                
@ParentID as bigint=0 ,                      
@Name as varchar(100)                                  
)                                    
AS                                      
BEGIN                                    
DECLARE @Leadno BIGINT  =0                                  
declare @newusr int= 0                                    
declare @ser_user_id as bigint,                                    
 @user_id as bigint, @pwd varchar(100)='', @Login_id varchar(100)                                    
                                
 if @ParentID <=0                                   
 SELECT @ParentID = ParentId                                    
 FROM serv_user_domain where virtual_mail = @vmail_id                                   
                        
if @ParentID > 0                        
begin                                     
if exists(select * from  Serv_User_Detail where Email = @email_id and ParentID = @ParentID)                                   
 begin                                    
 select @user_id = User_id, @ParentId = ParentId, @pwd = pwd                                      
  from Serv_User_Detail where Email = @email_id and ParentID = @ParentID                                   
 end                                    
else                                    
begin                                    
 if exists(select * from  User_Detail where Email = @email_id and ParentID = @ParentID)                                    
 Begin                                    
  --select User_id, ParentId  from Serv_User_Detail where Email = @email_id                                    
    select @pwd= pwd, @user_id=user_id, @Login_id= User_Login from  User_Detail                                 
         where Email = @email_id  and ParentID = @ParentID                      
 if (not exists(select 'x' from Serv_User_Detail where ParentID = @ParentID and Login_id = @Login_id))         
  begin                
     insert into Serv_User_Detail(ParentId, User_id,Name, Login_id, Pwd,  Mobile,                                      
   Email, Company, Country, City, State, Address, Zip, country_code,User_id_old)
  select ParentId,user_id, FName, User_Login,                                       
   Pwd, str(mobile,20,0) Mobile , EMail , CompnayName,Country,  City, State,                    
   Address ,  Pincode , CountryCode, User_id
   from user_detail where EMail = @email_id and ParentID = @ParentID                                     
                                        
  select @ser_user_id = SCOPE_IDENTITY()               
  update Serv_User_Detail set user_id=@ser_user_id  where ser_user_id = @ser_user_id                                    
  --set @user_id = @ser_user_id    
  if (not exists(select '*' from Serv_User_Master where ParentID = @ParentID and Service_id = @ser_user_id and kit19_id = @user_id))    
  begin                                   
   insert into Serv_User_Master (ParentID,Email_id,Service_User,Service_id, kit19_id, kit19_User)                 
        Values (@ParentID, @email_id, 1, @ser_user_id ,@user_id, 1)                                      
 end  
 end                       
                                        
   --goto mail_send                                    
   END                                    
   else                                    
 begin                                 
  set @pwd= ROUND((2998+ 25678)* RAND(),0)     
  if (not exists(select 'x' from Serv_User_Detail where ParentID = @ParentID and Login_id = @Login_id))                
 begin                                   
  insert into Serv_User_Detail(ParentId, Login_id, Pwd, user_id,                                     
 Email)                                       
     select @ParentId,@email_id, @pwd, 0 ,                                     
     @email_id             
                                
  select @ser_user_id = SCOPE_IDENTITY()                                      
  --set @user_id = @ser_user_id                                     
    set @newusr = 1                                    
    set @Login_id=@email_id                               
    update Serv_User_Detail set user_id = @ser_user_id where ser_user_id = @ser_user_id                                    
 if (not exists(select '*' from Serv_User_Master where ParentID = @ParentId and Service_id = @ser_user_id and kit19_id = @user_id))    
  begin              
    insert into Serv_User_Master (ParentID,Email_id,Service_User,Service_id, kit19_id, kit19_User)                                 
 Values (@ParentID, @email_id, 1, @ser_user_id ,'', 0)                                    
 end  
 end  
                       
if not EXISTS(select 'x' from userleads where (EmailID = @email_id or EmailID1 = @email_id                      
or EmailID2 = @email_id) and ParentID =@ParentID )                               
 begin                                
    select @Leadno  = isnull((select MAX(LeadNo)                            
  FROM   UserLeads WHERE  ParentID = @ParentId),0)+1                                 
                      
declare @SourceID bigint                      
select @SourceID=SourceID                      
 from UserSourceSettings                                      
     where NAME='ServiceTicketSignup' and UserID= @ParentID                            
                             
    Insert into userleads (LeadNo,PersonName,EmailID,                      
    AssignedTo,SourceName,ParentID,                                        
   Remarks,CreatedOn,CreatedBy,FollowUpStatus,NextStatusDate,FollowupDate)                                         
   select @leadno,@Name,@email_id,@ParentId,                        
   @SourceID,@ParentId,'Lead Added from New Support Ticket',GETDATE(),@ParentId,1 ,GETDATE(),GETDATE()                                         
   declare @leadid bigint                           
  --@Sourceid,@MediumID                              
  end                         
                         
 exec serv_Raise_emailNotification 0,@ParentID,0 , @User_ID,@User_ID,'User Activation Email','Agent'                            
 exec serv_Raise_emailNotification 0,@ParentID,0 , @User_ID,@User_ID,'User Activation Email','Requester'                                    
---- This will create a random number between 1 and 999                                    
                    
declare @balance int =0                     
SELECT TOP 1 @balance=isnull(balance,0) FROM   MailCreditDetails with(nolock) WHERE  --m_id = @m_id  AND                       
USER_ID = @ParentID  ORDER BY credit_id       DESC                        
                      
                   
 end                                     
end                                    
end                                    
 select @user_id user_id,@ParentId ParentId, @Login_id login_id, @newusr as emailtkt, @Leadno Leadno                                      
END 



GO

/* ============================================================
   Procedure: [dbo].[serv_verify_requester_support]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- exec serv_verify_requester_support @email_id=N'mayank.nigam@pelsoftlabs.in',@vmail_id=N'',@ParentID=32222,@Name=''
-- exec serv_verify_requester_support @email_id=N'mayank.nigam@pelsoftlabs.in',@vmail_id=N'',@ParentID=32222,@Name='',@leadid=116
CREATE   PROCEDURE [dbo].[serv_verify_requester_support]  
(                                      
@email_id as nvarchar(100),                                      
@vmail_id as nvarchar(100),                                  
@ParentID as bigint ,                        
@Name as varchar(100)
--,@leadid bigint=0
)                                      
AS                                        
BEGIN                                      
	DECLARE @Leadno BIGINT  =0                                    
	declare @newusr int= 0                                      
	declare @ser_user_id as bigint, @user_id as bigint, @pwd varchar(100)='', @Login_id varchar(100)                                      
	declare @leadid bigint=0
                                  
	if @ParentID <=0                                     
		SELECT @ParentID = ParentId FROM serv_user_domain where virtual_mail = @vmail_id                                     
                          
	if @ParentID > 0                          
	begin                                       
		if exists(select * from  Serv_User_Detail where Email = @email_id and ParentID = @ParentID)                                     
		begin
			select @user_id = ser_user_id, @ParentId = ParentId, @pwd = pwd, @leadid = LEADID
			from Serv_User_Detail 
			where Email = @email_id and ParentID = @ParentID
		end
		else                                      
		begin                                      
			if exists(select * from User_Detail where Email = @email_id and ParentID = @ParentID)
			Begin
				--select User_id, ParentId  from Serv_User_Detail where Email = @email_id                                      
				select @pwd= pwd, @user_id=user_id, @Login_id= User_Login from  User_Detail where Email = @email_id  and ParentID = @ParentID
	
				if (not exists(select 'x' from Serv_User_Detail where ParentID = @ParentID and ser_user_id = @user_id))
				begin
					insert into Serv_User_Detail
					(ParentId, User_id,Name, Login_id, Pwd, Mobile, Email, Company, Country, City, State, 
					Address, Zip, country_code, User_id_old, LEADID)
					select ParentId,user_id, FName, User_Login, Pwd, str(mobile,20,0) Mobile , EMail , CompnayName,Country, City, State,
					Address , Pincode , CountryCode, User_id, @leadid
					from user_detail 
					where EMail = @email_id and ParentID = @ParentID

					select @ser_user_id = SCOPE_IDENTITY()
			
					update Serv_User_Detail set user_id=@ser_user_id where ser_user_id = @ser_user_id
			
					set @user_id = @ser_user_id
			
			
					insert into Serv_User_Master (ParentID,Email_id,Service_User,Service_id, kit19_id, kit19_User)
					Values (@ParentID, @email_id, 1, @ser_user_id ,@user_id, 1)
				end             
		   --goto mail_send                                      
			END                                      
			else
			begin
			  set @pwd= ROUND((2998+ 25678)* RAND(),0)                                       
			  insert into Serv_User_Detail(ParentId, Login_id, Pwd, user_id, Email, LEADID)                                         
			  select @ParentId,@email_id, @pwd, 0, @email_id, @leadid
                                  
			  select @ser_user_id = SCOPE_IDENTITY()

			  set @user_id = @ser_user_id                                       
			  set @newusr = 1                                    
			  set @Login_id=@email_id                                 
  
			  update Serv_User_Detail set user_id = @user_id where ser_user_id = @user_id                                      
               
			  insert into Serv_User_Master (ParentID,Email_id,Service_User,Service_id, kit19_id, kit19_User)                        
			  Values (@ParentID, @email_id, 1, @ser_user_id ,'', 0)                                      
                         
			  if not EXISTS(select 'x' from userleads where (EmailID = @email_id or EmailID1 = @email_id or EmailID2 = @email_id) and ParentID =@ParentID )
			  begin
				select @Leadno  = isnull((select MAX(LeadNo) FROM UserLeads WHERE  ParentID = @ParentId),0)+1                                   
                        
				declare @SourceID bigint

				select @SourceID=SourceID
				from UserSourceSettings
				where NAME='ServiceTicketSignup' and UserID= @ParentID                              
                               
				Insert into userleads
				(LeadNo, PersonName, EmailID, AssignedTo, SourceName, ParentID, Remarks, CreatedOn, CreatedBy, FollowUpStatus, NextStatusDate, FollowupDate)
				select @leadno,@Name,@email_id,@ParentId,@SourceID,@ParentId,'Lead Added from New Support Ticket',GETDATE(),@ParentId,1,GETDATE(),GETDATE()
			  --@Sourceid,@MediumID                                
				Set @leadid = SCOPE_IDENTITY()
			  end
                           
			  exec serv_Raise_emailNotification_support 0,@ParentID,0 , @User_ID,@User_ID,'User Activation Email','Agent'
			  exec serv_Raise_emailNotification_support 0,@ParentID,0 , @User_ID,@User_ID,'User Activation Email','Requester'
			---- This will create a random number between 1 and 999                                      
                      
			  declare @balance int =0

			  SELECT TOP 1 @balance=isnull(balance,0) FROM   MailCreditDetails with(nolock) WHERE  --m_id = @m_id  AND                         
			  USER_ID = @ParentID  ORDER BY credit_id DESC                          
			end
		end                                      
	end       

	select @user_id user_id,@ParentId ParentId, @Login_id login_id, @newusr, @Leadno Leadno, isnull(@leadid,0) leadid

END     



GO

