/* ============================================================
   Procedure: [dbo].[serv_verify_requester1]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- exec serv_verify_requester1 @email_id='asd@Support.appmails.in.net',@vmail_id='asd@Support.appmails.in.net',@ParentID=0,@Name=''        
-- create table supportmailforwarding(id int identity(1,1),parentid bigint,usermail nvarchar(200),virtualmail nvarchar(200),isactive int default 1,createdon datetime default getdate(),lastmodified datetime)          
CREATE   PROCEDURE [dbo].[serv_verify_requester1]  -- 'asd@Support.appmails.in.net','asd@Support.appmails.in.net',0,''          
(                                                    
 @email_id as nvarchar(100),        
 @vmail_id as nvarchar(max),        
 @ParentID as bigint ,        
 @Name as varchar(100)        
)                                                    
AS                                                      
BEGIN        
        
DECLARE @Leadno BIGINT  =0                                                  
declare @newusr int= 0                                                    
declare @ser_user_id as bigint, @user_id as bigint, @pwd varchar(100)='', @Login_id varchar(100)        
        
select value as vmail_id,position into #vmail from dbo.fn_split(@vmail_id,'|')        
          
 --Code added to prevent circular mails--          
 declare @duplemail nvarchar(200)        
        
 if @ParentID <=0                                                   
 SELECT top 1 @ParentID = ParentId,@duplemail=virtual_mail        
 FROM serv_user_domain s(nolock) join #vmail v         
 on s.virtual_mail = vmail_id         
 order by position               
           
 if isnull(@parentid,0)=0          
 select top 1 @parentid=parentid,@duplemail=isnull(@duplemail,vmail_id)         
 from supportmailforwarding(nolock) s join #vmail v         
 on s.usermail = vmail_id and isactive=1          
 order by position          
          
if @duplemail=@email_id          
set @parentid=0          
        
IF @ParentID > 0        
BEGIN        
    IF EXISTS(SELECT * FROM Serv_User_Detail(NOLOCK) WHERE Email = @email_id AND ParentID = @ParentID)        
    BEGIN        
        SELECT @ser_user_id = ser_user_id, @ParentId = ParentId, @pwd = pwd        
        FROM  Serv_User_Detail(NOLOCK)        
        WHERE Email = @email_id AND ParentID = @ParentID;        
    END;        
    ELSE        
    BEGIN        
        IF EXISTS(SELECT * FROM User_Detail(NOLOCK) WHERE Email = @email_id AND ParentID = @ParentID AND isverify = 1)        
        BEGIN        
            --select User_id, ParentId  from Serv_User_Detail where Email = @email_id                                                    
            SELECT @pwd = pwd, @user_id = user_id, @Login_id = User_Login        
            FROM User_Detail        
            WHERE Email = @email_id AND ParentID = @ParentID;        
        
            IF(NOT EXISTS(SELECT 'x' FROM Serv_User_Detail(NOLOCK) WHERE ParentID = @ParentID AND user_id_old = @user_id))        
            BEGIN        
                INSERT INTO Serv_User_Detail        
                (ParentId, User_id, Name, Login_id, Pwd, Mobile, Email, Company, Country,         
     City, State, Address, Zip, country_code, User_id_old)        
                SELECT ParentId, user_id, FName, User_Login, Pwd, STR(mobile, 20, 0) Mobile, EMail, CompnayName, Country,         
                       City, State, Address, Pincode, CountryCode, user_id        
                FROM user_detail(NOLOCK)        
                WHERE EMail = @email_id AND ParentID = @ParentID;        
        
                SELECT @ser_user_id = SCOPE_IDENTITY();        
                        
    UPDATE Serv_User_Detail SET user_id = @ser_user_id WHERE ser_user_id = @ser_user_id;                      
                --set @user_id = @ser_user_id        
        
                INSERT INTO Serv_User_Master        
                (ParentID, Email_id, Service_User, Service_id, kit19_id, kit19_User)        
                VALUES        
                (@ParentID, @email_id, 1, @ser_user_id, @user_id, 1);        
            END;        
            --goto mail_send                                                    
  END;        
  ELSE        
  BEGIN        
   SET @pwd = ROUND((2998 + 25678) * RAND(), 0);        
   INSERT INTO Serv_User_Detail        
   (ParentId, Login_id, Pwd, user_id, Email)        
   SELECT @ParentId, @email_id, @pwd, 0, @email_id;        
        
   SELECT @ser_user_id = SCOPE_IDENTITY();                                                      
   --set @user_id = @ser_user_id            
   SET @newusr = 1;        
   SET @Login_id = @email_id;        
                
   UPDATE Serv_User_Detail SET user_id = @ser_user_id WHERE ser_user_id = @ser_user_id;        
        
   INSERT INTO Serv_User_Master        
   (ParentID, Email_id, Service_User, Service_id, kit19_id, kit19_User)        
   VALUES        
   (@ParentID, @email_id, 1, @ser_user_id, '', 0);        
        
   IF NOT EXISTS(SELECT 'x' FROM userleads(NOLOCK) WHERE @email_id in
   (isnull(EmailID,'1'),isnull(EmailID1,'1'),isnull(EmailID2,'1')) AND ParentID = @ParentID)        
   BEGIN        
    DECLARE @SourceID BIGINT,@leadid bigint;        
        
    SELECT TOP 1 @SourceID = SourceID        
    FROM UserSourceSettings(NOLOCK)        
    WHERE NAME = 'ServiceTicketSignup' AND UserID = @ParentID        
    ORDER BY SourceID DESC;        
        
    select @leadno=isnull(max(Leadno),0)+1 from userleads where parentid=@ParentID        
        
    --INSERT INTO userleads        
    -- (LeadNo, PersonName, EmailID, AssignedTo, SourceName, ParentID, Remarks,        
    --  CreatedOn, CreatedBy, FollowUpStatus, NextStatusDate, FollowupDate)        
    --SELECT @leadno, @Name, @email_id, @ParentId, @SourceID, @ParentId, 'Lead Added from New Support Ticket',         
    --  GETDATE(), @ParentId, 1, GETDATE(), GETDATE();        
        
  --if(exists (select 1 from crmCampaignSettings(nolock) where UserID = @ParentID  and isnull(AutoLeadFollowup,0) = 1))      
  --    Begin      
        --set @FollowUpStatus = 0      
            
 INSERT INTO userleads        
     (LeadNo, PersonName, EmailID, AssignedTo, SourceName, ParentID, Remarks,        
      CreatedOn, CreatedBy,enquirysource)        
    SELECT @leadno, @Name, @email_id, @ParentId, @SourceID, @ParentId, 'Lead Added from New Support Ticket',         
      GETDATE(), @ParentId,25;    
	  select @leadid=scope_identity()
  
  /*     
  End    
    else    
    Begin    
      INSERT INTO userleads        
     (LeadNo, PersonName, EmailID, AssignedTo, SourceName, ParentID, Remarks,        
      CreatedOn, CreatedBy, FollowUpStatus, NextStatusDate, FollowupDate)        
    SELECT @leadno, @Name, @email_id, @ParentId, @SourceID, @ParentId, 'Lead Added from New Support Ticket',         
      GETDATE(), @ParentId, 1, GETDATE(), GETDATE();    
     
  End
  */    
    
 exec usp_insertdefaultfollowup @parentid,@leadid   
        
 update Serv_User_Detail set leadid=@leadid where ser_user_id=@ser_user_id      
    --SELECT @Leadno = LeadNo FROM UserLeads(NOLOCK) WHERE ParentID = @ParentId AND id = @leadid;        
        
    --@Sourceid,@MediumID                                              
   END;        
        
