/* ============================================================
   Procedure: [dbo].[sms19_app_Balance_Refund_ToAppMsg]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


-- =============================================    
-- AUTHOR:  <RATNA KUMARI>    
-- CREATE DATE: <08/22/2015 16:06:26>    
-- DESCRIPTION: <THIS SP IS USED TO FETCH BATCHID FROM THE DATABASE FOR SMS19 APP>    
-- =============================================    
CREATE   PROCEDURE [dbo].[sms19_app_Balance_Refund_ToAppMsg] 
AS    
SET NOCOUNT ON           
BEGIN   
----------------------------------------------------------------EXPIRY TIME--------------------------------------------------------------
DECLARE @EXPIRY AS INT;
SELECT @EXPIRY = TIME FROM [MYSMS].[DBO].[SMS19_APP_EXPIRY_MASTER](nolock) WHERE TYPE='SMS19APP'; 

----------------------------------------------------------------BALANCE REFUND-----------------------------------------------------------	
	
		DECLARE @BATCHID AS BIGINT; 
		SELECT TOP 1 @BATCHID = BATCHID FROM [SMS19_App_Master_Message](nolock) WHERE [CHECKUNCHECK]='1' AND ISNULL(ISREFUND,0) = '0' 
		AND --DATEDIFF(MI,MESSAGEINSERTDATETIME,GETDATE())>@EXPIRY 
		DeliveredIn='APP' AND 
		GETDATE() > DATEADD(MI, CONVERT(INT, @EXPIRY), MESSAGEINSERTDATETIME) 
		ORDER BY MESSAGEINSERTDATETIME 
		
		DECLARE @EXPIREDCOUNT AS BIGINT; 
		SELECT @EXPIREDCOUNT = COUNT(MESSAGE) FROM [SMS19_APP_MESSAGE_INAPP](nolock) WHERE BATCHID = @BATCHID AND [CHECKUNCHECK]='1' AND ISNULL(ISREFUND,0) = '0'
		
		DECLARE @USERID AS INT; 
		SELECT TOP 1 @USERID = SENDERUSERID FROM [SMS19_APP_MESSAGE_INAPP](nolock) WHERE BATCHID = @BATCHID 

		
		UPDATE [SMS19_APP_MESSAGE_INAPP] SET ISREFUND='1' WHERE BATCHID = @BATCHID 
		UPDATE [SMS19_APP_MASTER_MESSAGE] SET ISREFUND='1' WHERE BATCHID = @BATCHID AND DeliveredIn='APP' 
		
		EXEC USP_CREDITUPDATE @USERID,@EXPIREDCOUNT,'' 

--------------------------------------------------------------BATCHINFO-----------------------------------------------------------------
--INSERT INTO BATCHINFO(USERID,BATCHID,TOTALRECORDS,ISPRORITY,ISALLOWDND,BATCHINSERTTIME,BATCHPROCESSTIME,ISUNICODE,PAGENAME,USERFILTER,TABLENAME)	VALUES(@USERID,@BATCHID,@EXPIREDCOUNT,7,0,GETDATE(),GETDATE(),0,'APP',1,'SMS19_APP_MASTER_MESSAGE')	
----------------------------------------------------------------------------------------------------------------------------------------

SET NOCOUNT OFF;    
END





GO

/* ============================================================
   Procedure: [dbo].[SMS19_App_Check_Friend_InApp]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


-- =============================================    
-- AUTHOR:  <RATNA KUMARI>    
-- CREATE DATE: <07/09/2015 12:12:40>    
-- DESCRIPTION: <THIS SP IS USED TO CHECK PRESENCE OF USER IN THE DATABASE FOR SMS19 APP>    
-- =============================================    
CREATE   PROCEDURE [dbo].[SMS19_App_Check_Friend_InApp] --  '9643853169' --'7840002738'  --,''

@SenderUserID  VARCHAR(12),
@RECIPIENTMOBILE VARCHAR(20)    
AS    
SET NOCOUNT ON    
BEGIN   
SELECT User_ID, FNAME AS RecipientName,  SUBSTRING(LTRIM(STR(MOBILE, 20, 0)), 0, 11) AS RecipientPhoneNo FROM USER_DETAIL(NOLOCK) WHERE MOBILE = @RECIPIENTMOBILE AND LOGINTYPE = '1'
SET NOCOUNT OFF;    
END



GO

/* ============================================================
   Procedure: [dbo].[SMS19_App_Check_User_Detail]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


-- =============================================    
