   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  
-- =============================================      
-- AUTHOR:  <RATNA KUMARI>      
-- CREATE DATE: <08/10/2015 19:35:45>      
-- DESCRIPTION: <THIS SP IS USED TO CHECK BALANCE OF USER IN THE DATABASE FOR SMS19 APP>      
-- =============================================      
CREATE   PROCEDURE [dbo].[SMS19_App_Fetch_Credit_Detail]    --  '20705' --'20705'  --'20717'  
@USERID VARCHAR(10),  
@MID VARCHAR(10)  
AS      
SET NOCOUNT ON      
BEGIN     
         Declare @ParentID bigint = ( select top 1 isnull(ParentID,0) from User_Detail with(nolock) where User_ID = @USERID ) 
		 Declare @MID_P bigint = ( select top 1 isnull(M_ID,0) from User_Detail with(nolock) where User_ID = @ParentID ) 
		                
SELECT TOP 1 ISNULL(BALANCE,0)AS Balance, Validity FROM CREDIT_DETAILS(NOLOCK) WHERE M_ID=@MID_P AND USER_ID=@ParentID ORDER BY CREDIT_ID DESC   
SET NOCOUNT OFF;      
END  


