/* ============================================================
   Procedure: [dbo].[SMS19_App_Fetch_Merchant_Detail]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  --[SMS19_App_Fetch_Merchant_Detail] ''
-- =============================================      
-- AUTHOR:  <RATNA KUMARI>      
-- CREATE DATE: <07/24/2015 09:59:34>      
-- DESCRIPTION: <THIS SP IS USED TO FETCH MERCHANT DETAILS FOR SMS19 APP>      
-- =============================================      
CREATE   PROCEDURE [dbo].[SMS19_App_Fetch_Merchant_Detail]  --''  
@MERCHANT_CODE VARCHAR(20) = NULL  
AS      
SET NOCOUNT ON      
BEGIN     
DECLARE @PROFILEPICTUREPATH VARCHAR(100);      
SELECT @PROFILEPICTUREPATH = DEFAULTAPPLOGO FROM SMS19_APP_LOGO_MASTERTABLE(nolock)  
DECLARE @NEW_MERCHANT_PROFILEPICTUREPATH VARCHAR(100);   
SELECT @NEW_MERCHANT_PROFILEPICTUREPATH=PROFILEPICTUREPATH FROM USER_DETAIL(NOLOCK) WHERE USER_ID=@MERCHANT_CODE     
IF(@MERCHANT_CODE='')  
BEGIN  
print '1'
SELECT @PROFILEPICTUREPATH = DEFAULTAPPLOGO FROM SMS19_APP_LOGO_MASTERTABLE(nolock) 
select @PROFILEPICTUREPATH AS ProfilePicturePath,0 User_ID,'NA' FName,'NA' LName,'NA' Merchant_Url 
END  
ELSE  
BEGIN  
IF(@NEW_MERCHANT_PROFILEPICTUREPATH != '')  
BEGIN  
SELECT @NEW_MERCHANT_PROFILEPICTUREPATH AS ProfilePicturePath,User_ID,FName,LName,Merchant_Url FROM USER_DETAIL(nolock) WHERE USER_ID=@MERCHANT_CODE  
END  
ELSE  
BEGIN  
SELECT @PROFILEPICTUREPATH AS ProfilePicturePath,User_ID,FName,LName,Merchant_Url FROM USER_DETAIL(nolock) WHERE USER_ID=@MERCHANT_CODE  
END  
END  
SET NOCOUNT OFF;      
END  


GO

/* ============================================================
   Procedure: [dbo].[SMS19_App_Fetch_Message_Detail]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


-- =============================================    
-- AUTHOR:  <RATNA KUMARI>    
-- CREATE DATE: <07/06/2015 07:19:58>    
-- UPDATE DATE: <17/06/2015 05:00:00>   
-- DESCRIPTION: <THIS SP IS USED TO FETCH LAST MESSAGE DETAIL FOR SMS19 APP>    
-- =============================================    
CREATE   PROCEDURE [dbo].[SMS19_App_Fetch_Message_Detail]   --  '20792'

@RECIPIENTUSERID VARCHAR(30)    --OPTOPTION = 1 MEANS UNBLOCKED ONES    
AS    
SET NOCOUNT ON           
BEGIN   
DECLARE @MESSAGEINSERTDATETIME  DATETIME;
SELECT @MESSAGEINSERTDATETIME = CONVERT(DATETIME,MAX(MESSAGEINSERTDATETIME),104)FROM SMS19_APP_MESSAGE_INAPP(NOLOCK)  WHERE (RECIPIENTUSERID = @RECIPIENTUSERID)
--SELECT @MESSAGEINSERTDATETIME AS MESSAGEINSERTDATETIME

DECLARE @TEMPTABLE1 TABLE(SENDERUSERID BIGINT, SENDERPHONENO VARCHAR(50), SENDERNAME VARCHAR(100))   
DECLARE @TEMPTABLE2 TABLE(SENDERUSERID BIGINT, MESSAGEINSERTDATETIME VARCHAR(100), FILENAME VARCHAR(3000), FILETYPE VARCHAR(50), FILEPATH VARCHAR(1000))   
DECLARE @TEMPTABLE3 TABLE(SENDERUSERID BIGINT, MESSAGE VARCHAR(5000)) 
DECLARE @TEMPTABLE4 TABLE(SENDERUSERID BIGINT, COUNTMESSAGE INT)   
DECLARE @TEMPTABLE5 TABLE(USER_ID BIGINT, PROFILEPICTURENAME VARCHAR(3000), PROFILEPICTUREPATH VARCHAR(1000)) 

-- COUNT(MESSAGE)COUNTMESSAGE
INSERT INTO @TEMPTABLE1   
SELECT DISTINCT SENDERUSERID,SENDERPHONENO,SENDERNAME FROM SMS19_APP_MESSAGE_INAPP(NOLOCK)  WHERE (RECIPIENTUSERID = @RECIPIENTUSERID AND MESSAGETYPE != 'B' AND ISREAD = 'N') --AND ID IN(SELECT MAX(ID) FROM SMS19_APP_MESSAGE_INAPP(NOLOCK) GROUP BY SENDERUSERID)
--AND OPTOPTION  IN(SELECT OPTOPTION FROM SMS19_APP_OPTOPTION  WHERE RECIPIENTUSERID = @RECIPIENTUSERID AND  OPTOPTION != 0) 
GROUP BY SENDERUSERID, SENDERPHONENO,SENDERNAME 

INSERT INTO @TEMPTABLE2   
SELECT DISTINCT SENDERUSERID, CONVERT(DATETIME,MAX(MESSAGEINSERTDATETIME),104)MESSAGEINSERTDATETIME, FILENAME, FILETYPE, FILEPATH FROM SMS19_APP_MESSAGE_INAPP(NOLOCK) WHERE (RECIPIENTUSERID = @RECIPIENTUSERID AND MESSAGETYPE != 'B' AND ISREAD = 'N') --AND ID IN(SELECT MAX(ID) FROM SMS19_APP_MESSAGE_INAPP(NOLOCK) GROUP BY SENDERUSERID)
--AND OPTOPTION  IN(SELECT OPTOPTION FROM SMS19_APP_OPTOPTION  WHERE RECIPIENTUSERID = @RECIPIENTUSERID AND  OPTOPTION != 0) 
GROUP BY SENDERUSERID, FILENAME, FILETYPE, FILEPATH

INSERT INTO @TEMPTABLE3   
SELECT SENDERUSERID, MESSAGE FROM SMS19_APP_MESSAGE_INAPP(NOLOCK) WHERE ID IN(SELECT MAX(ID) FROM SMS19_APP_MESSAGE_INAPP(NOLOCK) WHERE RECIPIENTUSERID = @RECIPIENTUSERID AND MESSAGETYPE != 'B'  GROUP BY SENDERUSERID) GROUP BY SENDERUSERID, MESSAGE

INSERT INTO @TEMPTABLE4
SELECT SENDERUSERID, COUNT(MESSAGE)COUNTMESSAGE FROM SMS19_APP_MESSAGE_INAPP(NOLOCK) WHERE (RECIPIENTUSERID = @RECIPIENTUSERID AND MESSAGETYPE != 'B' AND ISREAD = 'N') GROUP BY SENDERUSERID


INSERT INTO @TEMPTABLE5
SELECT U.USER_ID, U.PROFILEPICTURENAME, U.PROFILEPICTUREPATH FROM USER_DETAIL(nolock) U JOIN @TEMPTABLE1 T1 ON U.USER_ID = T1.SENDERUSERID WHERE U.USER_ID=T1.SENDERUSERID

SELECT T1.SenderUserID, T1.SenderPhoneNo, T1.SenderName, T3.Message,CONVERT(DATETIME,T2.MessageInsertDateTime,100)MessageInsertDateTime, T4.CountMessage, T5.ProfilePictureName, T5.ProfilePicturePath, T2.FileName, T2.FileType, T2.FilePath FROM @TEMPTABLE1 T1 JOIN @TEMPTABLE2 T2 ON T1.SENDERUSERID = T2.SENDERUSERID JOIN @TEMPTABLE3 T3 ON T2.SENDERUSERID = T3.SENDERUSERID  JOIN @TEMPTABLE4 T4 ON T1.SENDERUSERID = T4.SENDERUSERID  JOIN @TEMPTABLE5 T5 ON T1.SENDERUSERID = T5.USER_ID

SET NOCOUNT OFF;    
END



GO

