/* ============================================================
   Procedure: [dbo].[SMS19_App_Fetch_Total_Message_SingleUser]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


-- =============================================    
-- AUTHOR:  <RATNA KUMARI>    
-- CREATE DATE: <07/06/2015 07:19:58>    
-- DESCRIPTION: <THIS SP IS USED TO FETCH MESSAGE DETAILS FOR SMS19 APP>    
-- =============================================    
CREATE   PROCEDURE [dbo].[SMS19_App_Fetch_Total_Message_SingleUser]  --   '312','1'    

@RECIPIENTUSERID VARCHAR(12),
@SENDERUSERID VARCHAR(12)   
AS    
SET NOCOUNT ON     
BEGIN   
SELECT RecipientUserID,SenderUserID, Message, CONVERT(DATETIME,MessageInsertDateTime,100)MessageInsertDateTime,
SenderUserID AS Type, FilePath, FileType, FileName FROM SMS19_APP_MESSAGE_INAPP(NOLOCK) WHERE ISREAD = 'N' 
AND (RECIPIENTUSERID = @RECIPIENTUSERID AND SENDERUSERID = @SENDERUSERID) 
ORDER BY MESSAGEINSERTDATETIME DESC

UPDATE SMS19_APP_MESSAGE_INAPP SET ISDELIVERED = 'Y', DELIVEREDDATETIME = GETDATE(), ISREAD = 'Y', READDATETIME = GETDATE() WHERE RECIPIENTUSERID = @RECIPIENTUSERID AND SENDERUSERID = @SENDERUSERID

UPDATE SMS19_App_Master_Message SET ISDELIVERED = 'Y', DELIVEREDDATETIME = GETDATE(), ISREAD = 'Y', READDATETIME = GETDATE() WHERE RECIPIENTUSERID = @RECIPIENTUSERID AND SENDERUSERID = @SENDERUSERID

SET NOCOUNT OFF;    
END



GO

/* ============================================================
   Procedure: [dbo].[SMS19_App_Fetch_Undelivered_Message_Count]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


-- =============================================      
-- AUTHOR:  <RATNA KUMARI>      
-- CREATE DATE: <07/06/2015 07:19:58>      
-- DESCRIPTION: <THIS SP IS USED TO FETCH MESSAGE DETAILS FOR SMS19 APP>      
-- =============================================      
CREATE   PROCEDURE [dbo].[SMS19_App_Fetch_Undelivered_Message_Count]   --   '20798'   --'19762'  

@RECIPIENTUSERID VARCHAR(12)      

AS      
SET NOCOUNT ON      

BEGIN     

DECLARE @GENERALMESSAGECOUNT INT;  
DECLARE @BROADCASTMESSAGECOUNT INT;  
DECLARE @BROADCASTID INT;  
DECLARE @MESSAGEID INT;  
DECLARE @BROADCASTTITLE VARCHAR(100);  
   

--INSERT INTO @TEMPTABLE1   
SELECT @GENERALMESSAGECOUNT = COUNT(MESSAGE) FROM [SMS19_APP_MESSAGE_INAPP](NOLOCK) WHERE RECIPIENTUSERID = @RECIPIENTUSERID AND ISDELIVERED = 'N' AND MESSAGETYPE != 'B' --GROUP BY RECIPIENTUSERID  

--INSERT INTO @TEMPTABLE2  
SELECT @BROADCASTMESSAGECOUNT = COUNT(MESSAGE) FROM [SMS19_APP_MESSAGE_INAPP](NOLOCK) WHERE RECIPIENTUSERID = @RECIPIENTUSERID AND ISREADBROADCAST='N' AND MESSAGETYPE = 'B' --GROUP BY RECIPIENTUSERID  

--SELECT @BROADCASTID = ID FROM [SMS19_APP_MESSAGE_INAPP](NOLOCK) WHERE RECIPIENTUSERID = @RECIPIENTUSERID AND ISREADBROADCAST='N' AND MESSAGETYPE = 'B' AND ID IN(SELECT MAX(ID) FROM SMS19_APP_MESSAGE_INAPP(NOLOCK) WHERE  RECIPIENTUSERID = @RECIPIENTUSERID 
--AND ISREADBROADCAST='N' AND MESSAGETYPE = 'B')--GROUP BY  --GROUP BY RECIPIENTUSERID  

SELECT @BROADCASTID = MAX(ID) FROM SMS19_APP_MESSAGE_INAPP(NOLOCK) WHERE  RECIPIENTUSERID = @RECIPIENTUSERID 
AND ISREADBROADCAST='N' AND MESSAGETYPE = 'B'



--SELECT @MESSAGEID = ID FROM [SMS19_APP_MESSAGE_INAPP](NOLOCK) WHERE RECIPIENTUSERID = @RECIPIENTUSERID AND ISDELIVERED='N' AND MESSAGETYPE = 'G' AND ID IN(SELECT MAX(ID) FROM SMS19_APP_MESSAGE_INAPP(NOLOCK) WHERE  RECIPIENTUSERID = @RECIPIENTUSERID 
--AND ISDELIVERED='N' AND MESSAGETYPE = 'G')--GROUP BY  --GROUP BY RECIPIENTUSERID  

SELECT @MESSAGEID = MAX(ID) FROM SMS19_APP_MESSAGE_INAPP(NOLOCK) WHERE  RECIPIENTUSERID = @RECIPIENTUSERID 
AND ISDELIVERED='N' AND MESSAGETYPE = 'G'

SELECT @BROADCASTTITLE = BROADCASTTITLE FROM [SMS19_APP_MESSAGE_INAPP](NOLOCK) WHERE RECIPIENTUSERID = @RECIPIENTUSERID AND ISDELIVERED='N' AND MESSAGETYPE = 'B' AND ID IN(SELECT MAX(ID) FROM SMS19_APP_MESSAGE_INAPP(NOLOCK) 
WHERE  RECIPIENTUSERID = @RECIPIENTUSERID AND ISDELIVERED='N' AND MESSAGETYPE = 'B')--GROUP BY  --GROUP BY RECIPIENTUSERID  
 

SELECT @GENERALMESSAGECOUNT AS GeneralMessageCount, @MESSAGEID AS MessageID, @BROADCASTMESSAGECOUNT AS BroadcastMessageCount, @BROADCASTID AS BroadcastID, @BROADCASTTITLE AS BroadcastTitle,GETDATE() AS Time  

SET NOCOUNT OFF;      
END  



GO

