/* ============================================================
   Procedure: [dbo].[SMS19_App_Insert_App_Message_Detail_1]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  
-- =============================================      
-- AUTHOR:  <RATNA KUMARI>      
-- CREATE DATE: <07/27/2015 13:34:59>      
-- DESCRIPTION: <THIS SP IS USED TO INSERT MESSAGE DETAILS FOR SMS19 APP>      
-- =============================================      
CREATE   PROCEDURE [dbo].[SMS19_App_Insert_App_Message_Detail_1]  --  '20705','1111111111','II','9808744275','','10482215'  
  
@SENDERUSERID VARCHAR(20),      
@SENDERPHONENO VARCHAR(20),    
@SENDERMSG VARCHAR(5000),    
@RECIPIENTPHONENO VARCHAR(20),      
@RECIPIENTUSERID VARCHAR(20) = '',  
@BATCHID VARCHAR(500),  
@CHECKUNCHECK VARCHAR(2),  
@M_ID BIGINT,  
@TEMPID VARCHAR(50)=''    
AS      
SET NOCOUNT ON      
  
BEGIN     
  
--DECLARE @RUSERID BIGINT;  
--SELECT @RUSERID = USER_ID FROM USER_DETAIL(NOLOCK) WHERE MOBILE = @RECIPIENTPHONENO  
  
  
DECLARE @SENDERNAME VARCHAR(50);  
SELECT @SENDERNAME = FNAME FROM USER_DETAIL(NOLOCK) WHERE USER_ID = @SENDERUSERID  
  
DECLARE @RECIPIENTNAME VARCHAR(50);  
SELECT @RECIPIENTNAME = FNAME FROM USER_DETAIL(NOLOCK) WHERE USER_ID = @RECIPIENTUSERID  
  
DECLARE @EXPIRYTIME INT;  
SELECT @EXPIRYTIME = TIME FROM SMS19_APP_EXPIRY_MASTER(nolock) WHERE TYPE='SMS19APP'  
  
DECLARE @OPTOPTION INT;-- ADDED BY RATNA ON 08-08-2015  
SELECT @OPTOPTION = OPTOPTION FROM SMS19_APP_OPTOPTION(nolock)  WHERE RECIPIENTUSERID = @RECIPIENTUSERID AND SENDERUSERID = @SENDERUSERID  
IF(@OPTOPTION = 0) --0 IS FOR OPTOUT AND 1 IS FOR OPTIN   
BEGIN  
--SELECT 'INSIDE SMS19_APP_BLOCKEDMESSAGES' AS MESSAGE  
INSERT INTO SMS19_APP_BLOCKEDMESSAGES ([SENDERUSERID],[RECIPIENTUSERID],[OPTOUT],[MESSAGE],[INSERTDATE]) VALUES(@SENDERUSERID,@RECIPIENTUSERID,@OPTOPTION,@SENDERMSG,GETDATE())  
END  
ELSE  
BEGIN  
  
-- SENDER USER TYPE IS ADMIN --  
--INSERT ALL USERS MESSAGES INTO MASTER TABLE--  
INSERT INTO SMS19_APP_MASTER_MESSAGE (SENDERUSERID,SENDERPHONENO,RECIPIENTUSERID,RECIPIENTPHONENO,MESSAGE,MESSAGEINSERTDATETIME,ISREAD,READDATETIME,
ISDELIVERED,DELIVEREDDATETIME,ISFEEDBACK,FEEDBACKDATETIME,SENDERID,TYPE,SENDERNAME,RECIPIENTNAME,MESSAGETYPE,PRIORITY,BATCHID,CHECKUNCHECK,ISREFUND,[DELIVEREDIN],ISREPORTED,M_ID,EXPIRY,TEMPID)   
VALUES(@SENDERUSERID,@SENDERPHONENO,@RECIPIENTUSERID,@RECIPIENTPHONENO,@SENDERMSG,GETDATE(),'N','','N','','N','','TXTSMS','1',@SENDERNAME,@RECIPIENTNAME,'G',0,@BATCHID,@CHECKUNCHECK,'0','APP','FALSE',@M_ID,@EXPIRYTIME,@TEMPID)  
  
--DELETE FROM SMS19_APP_MASTER_MESSAGE WHERE RECIPIENTUSERID=0 AND (RECIPIENTPHONENO=0 OR RECIPIENTPHONENO='')  
DECLARE @ID BIGINT;  
SELECT TOP 1 @ID = ID FROM SMS19_APP_MASTER_MESSAGE(nolock) WHERE BATCHID = @BATCHID  
  
IF(@RECIPIENTUSERID!='')  
BEGIN  
INSERT INTO SMS19_APP_MESSAGE_INAPP (ID,SENDERUSERID,SENDERPHONENO,RECIPIENTUSERID,RECIPIENTPHONENO,MESSAGE,MESSAGEINSERTDATETIME,ISREAD,
READDATETIME,ISDELIVERED,DELIVEREDDATETIME,ISFEEDBACK,FEEDBACKDATETIME,SENDERID,TYPE,SENDERNAME,RECIPIENTNAME,MESSAGETYPE,PRIORITY,BATCHID,CHECKUNCHECK,ISREFUND,M_ID,ISREPORTED,TEMPID)   
VALUES(@ID,@SENDERUSERID,@SENDERPHONENO,@RECIPIENTUSERID,@RECIPIENTPHONENO,@SENDERMSG,GETDATE(),'N','','N','','N','','TXTSMS','1',@SENDERNAME,@RECIPIENTNAME,'G',0,@BATCHID,@CHECKUNCHECK,'0',@M_ID,'FALSE',@TEMPID)  
END  
--DELETE FROM SMS19_APP_MESSAGE_INAPP WHERE RECIPIENTUSERID=0 AND (RECIPIENTPHONENO=0 OR RECIPIENTPHONENO='')  
  
END  
SET NOCOUNT OFF;      
END  
--MESSAGETYPE != 'B'  


GO

/* ============================================================
   Procedure: [dbo].[sms19_app_Insert_BatchInfo]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


-- =================================================================================
-- AUTHOR:  <RATNA KUMARI>    
-- CREATE DATE: <SCRIPT DATE: 08/27/2015 17:33:27>    
-- DESCRIPTION: <THIS SP IS USED TO INSERT SUMMARY IN BATCHINFO TABLE FOR SMS19 APP>    
-- =================================================================================
CREATE   PROCEDURE [dbo].[sms19_app_Insert_BatchInfo]  
AS    
SET NOCOUNT ON           
BEGIN   
--------------------------------------------------------------BATCHINFO-----------------------------------------------------------------
DECLARE @BATCHID AS BIGINT;
SELECT TOP 1 @BATCHID = BATCHID FROM [SMS19_APP_MASTER_MESSAGE](nolock) WHERE CHECKUNCHECK='1' AND ISDELIVERED = 'Y' AND DELIVEREDIN='INBOX' AND ISREPORTED='FALSE' ORDER BY MESSAGEINSERTDATETIME DESC

DECLARE @EXPIREDCOUNT AS BIGINT;
SELECT @EXPIREDCOUNT = COUNT(MESSAGE) FROM [SMS19_APP_MASTER_MESSAGE](nolock) WHERE BATCHID = @BATCHID AND CHECKUNCHECK='1' AND ISDELIVERED = 'Y' AND DELIVEREDIN='INBOX' AND ISREPORTED='FALSE'

DECLARE @USERID AS INT;
SELECT TOP 1 @USERID = SENDERUSERID FROM [SMS19_APP_MASTER_MESSAGE](nolock) WHERE BATCHID = @BATCHID

--IF NOT EXISTS (SELECT BATCHID FROM [DBO].[BATCHINFO] WHERE BATCHID = @BATCHID)
INSERT INTO BATCHINFO(USERID,BATCHID,TOTALRECORDS,ISPRORITY,ISALLOWDND,BATCHINSERTTIME,BATCHPROCESSTIME,ISUNICODE,PAGENAME,USERFILTER,TABLENAME)VALUES(@USERID,@BATCHID,@EXPIREDCOUNT,0,0,GETDATE(),GETDATE(),0,'APP',1,'SMS19_APP_MASTER_MESSAGE')	
--ELSE
--UPDATE BATCHINFO SET USERID = @USERID,TOTALRECORDS = @EXPIREDCOUNT WHERE BATCHID = @BATCHID 
UPDATE [SMS19_APP_MASTER_MESSAGE] SET ISREPORTED='TRUE' WHERE BATCHID = @BATCHID 

----------------------------------------------------------------------------------------------------------------------------------------
SET NOCOUNT OFF;    
END

--SELECT TOP 1 BATCHID FROM [SMS19_APP_MASTER_MESSAGE](nolock) WHERE CHECKUNCHECK='1' AND ISDELIVERED = 'Y' AND DELIVEREDIN='INBOX' AND ISREPORTED='TRUE' ORDER BY MESSAGEINSERTDATETIME DESC




GO

