INSERT INTO SMS19_APP_OPTOPTION (SENDERUSERID,RECIPIENTUSERID,SENDERMOBILENO,OPTOPTION,INSERTEDDATE) VALUES(@SENDERUSERID,@RECIPIENTUSERID,@SENDERMOBILENO,@OPTOPTION,GETDATE())

