@RECIPIENTPHONENO VARCHAR(10),  
@RECIPIENTNAME VARCHAR(100),  
@INSERTTIME NVARCHAR(30),  
@SENDERID VARCHAR(30)  
  
AS      
SET NOCOUNT ON      
  
BEGIN     
  
SET @SENDERMSG = @SENDERPHONENO + ' Download this App to chat free ' + 'j.mp/pel9';  
--SET @INSERTTIME = GETDATE();  
  
--IF NOT EXISTS (SELECT [RECIPIENTPHONENO] FROM [DBO].[SMS19_APP_REFER_DETAIL] WHERE SENDERUSERID = @SENDERUSERID)  
INSERT INTO SMS19_APP_REFER_DETAIL (SENDERUSERID,SENDERPHONENO,SENDERMSG,RECIPIENTNAME,RECIPIENTPHONENO,INSERTEDDATE) VALUES(@SENDERUSERID,@SENDERPHONENO,@SENDERMSG,@RECIPIENTNAME,@RECIPIENTPHONENO,@INSERTTIME) --GETDATE())  
  
--ELSE   
--UPDATE SMS19_APP_REFER_DETAIL  
--SET   
-- MERCHANT_PICTURE_NAME=@FILENAME,  
-- MERCHANT_PICTURE_PATH=@FILEPATH,  
-- UPDATEDDATE=GETDATE()  
--WHERE MERCHANT_USER_ID = @USERID   
---------------------------------------------------------------------------------------------------------------------------  
DECLARE @SMPPID INT;  
DECLARE @ISUNICODE INT;    
DECLARE @ISDND INT;  
DECLARE @OPERATOR VARCHAR(5);     
DECLARE @ISALLOWDND INT;  
DECLARE @PRIORITY INT;  
DECLARE @BATCHID INT;  
  
SET @PRIORITY = 0;  
SET @ISUNICODE = 0;  
SET @ISDND = 0;  
SET @OPERATOR = 'UI';  
SET @BATCHID = 0;  
SET @ISALLOWDND = 0;  
SET @SMPPID = 1;  
  
  
----------------------------------------------------------------------------------------------------------------------------  
DECLARE @TEMPTABLE1_SMS19_APP_REFER_DETAIL TABLE(PRIORITY INT,ISUNICODE INT,ISDND INT,OPERATOR VARCHAR(5),BATCHID INT,ISALLOWDND INT,SMPPID INT, ID INT, MOBILE VARCHAR(12),MESSAGE VARCHAR(3000),SENDERID INT,INSERTEDDATE DATETIME,U_ID INT)  
  
INSERT INTO @TEMPTABLE1_SMS19_APP_REFER_DETAIL  
 SELECT @PRIORITY AS PRIORITY,@ISUNICODE AS ISUNICODE, @ISDND AS ISDND, @OPERATOR AS OPERATOR, @BATCHID AS BATCHID, @ISALLOWDND AS ISALLOWDND,   
 @SMPPID AS SMPPID, ID, RECIPIENTPHONENO AS MOBILE, SENDERMSG AS MESSAGE, SENDERID, INSERTEDDATE, SENDERUSERID AS U_ID    
 FROM [MYSMS].[DBO].[SMS19_APP_REFER_DETAIL] WHERE SENDERUSERID=@SENDERUSERID AND INSERTEDDATE = @INSERTTIME  
  
----------------------------------------------------------------------------------------------------------------------------  
INSERT INTO MessageQueueNew   
(MessageID,Mobile,Message,SenderID,SmppID,MessageInsertDate,Priority,U_ID,IsUniCode,IsDND,Operator,BatchID,Isallowdnd)  
SELECT ID,MOBILE,MESSAGE,SENDERID,SMPPID,INSERTEDDATE,PRIORITY,U_ID,ISUNICODE,ISDND,OPERATOR,BATCHID,ISALLOWDND FROM @TEMPTABLE1_SMS19_APP_REFER_DETAIL  
  
 UPDATE [MYSMS].[DBO].[SMS19_APP_REFER_DETAIL] SET REFERRED='1', UPDATEDDATE=@INSERTTIME WHERE ID IN (SELECT ID FROM @TEMPTABLE1_SMS19_APP_REFER_DETAIL)  
  
  
SET NOCOUNT OFF;      
END  


