SET NOCOUNT ON           
BEGIN   

--DECLARE @RUSERID BIGINT;
--SELECT @RUSERID = USER_ID FROM USER_DETAIL(NOLOCK) WHERE MOBILE = @RECIPIENTPHONENO

set @SENDERMSG = @FILETYPE + ' - ' + @FILENAME

DECLARE @SENDERNAME VARCHAR(50);
SELECT @SENDERNAME = FNAME FROM USER_DETAIL(NOLOCK) WHERE USER_ID = @SENDERUSERID

DECLARE @RECIPIENTNAME VARCHAR(50);
SELECT @RECIPIENTNAME = FNAME FROM USER_DETAIL(NOLOCK) WHERE USER_ID = @RECIPIENTUSERID

DECLARE @EXPIRYTIME INT;
SELECT @EXPIRYTIME = TIME FROM SMS19_APP_EXPIRY_MASTER(nolock) WHERE TYPE='SMS19APP'

DECLARE @OPTOPTION INT;-- ADDED BY RATNA ON 08-08-2015  
SELECT @OPTOPTION = OPTOPTION FROM SMS19_APP_OPTOPTION(nolock)  WHERE RECIPIENTUSERID = @RECIPIENTUSERID AND SENDERUSERID = @SENDERUSERID  
IF(@OPTOPTION = 0) --0 IS FOR OPTOUT AND 1 IS FOR OPTIN   
BEGIN  
--SELECT 'INSIDE SMS19_APP_BLOCKEDMESSAGES' AS MESSAGE  
INSERT INTO SMS19_APP_BLOCKEDMESSAGES ([SENDERUSERID],[RECIPIENTUSERID],[OPTOUT],[MESSAGE],[INSERTDATE]) VALUES(@SENDERUSERID,@RECIPIENTUSERID,@OPTOPTION,@SENDERMSG,GETDATE())  
END
ELSE
BEGIN
-- SENDER USER TYPE IS ADMIN --
--INSERT ALL USERS MESSAGES INTO MASTER TABLE--
INSERT INTO SMS19_APP_MASTER_MESSAGE (SENDERUSERID,SENDERPHONENO,RECIPIENTUSERID,RECIPIENTPHONENO,MESSAGE,MESSAGEINSERTDATETIME,ISREAD,READDATETIME,ISDELIVERED,DELIVEREDDATETIME,ISFEEDBACK,FEEDBACKDATETIME,SENDERID,TYPE,SENDERNAME,RECIPIENTNAME,MESSAGETYPE,FILENAME,FILEPATH,FILETYPE,BATCHID,CHECKUNCHECK,ISREFUND,[DELIVEREDIN],ISREPORTED,M_ID,EXPIRY,TEMPID) 
VALUES(@SENDERUSERID,@SENDERPHONENO,@RECIPIENTUSERID,@RECIPIENTPHONENO,@SENDERMSG,GETDATE(),'N','','N','','N','','TXTSMS','1',@SENDERNAME,@RECIPIENTNAME,'G',@FILENAME,@FILEPATH,@FILETYPE,@BATCHID,@CHECKUNCHECK,'0','APP','FALSE',@M_ID,@EXPIRYTIME,@TEMPID)


DECLARE @ID BIGINT;
SELECT TOP 1 @ID = ID FROM SMS19_APP_MASTER_MESSAGE(nolock) WHERE BATCHID = @BATCHID

INSERT INTO SMS19_APP_MESSAGE_INAPP (ID,SENDERUSERID,SENDERPHONENO,RECIPIENTUSERID,RECIPIENTPHONENO,MESSAGE,MESSAGEINSERTDATETIME,ISREAD,READDATETIME,ISDELIVERED,DELIVEREDDATETIME,ISFEEDBACK,FEEDBACKDATETIME,SENDERID,TYPE,SENDERNAME,RECIPIENTNAME,MESSAGETYPE,FILENAME,FILEPATH,FILETYPE,BATCHID,CHECKUNCHECK,ISREFUND,M_ID,ISREPORTED,TEMPID) 
VALUES(@ID,@SENDERUSERID,@SENDERPHONENO,@RECIPIENTUSERID,@RECIPIENTPHONENO,@SENDERMSG,GETDATE(),'N','','N','','N','','TXTSMS','1',@SENDERNAME,@RECIPIENTNAME,'G',@FILENAME,@FILEPATH,@FILETYPE,@BATCHID,@CHECKUNCHECK,'0',@M_ID,'FALSE',@TEMPID)
END
SET NOCOUNT OFF;    
END
--MESSAGETYPE != 'B'



GO

