/* ============================================================
   Procedure: [dbo].[SP_Adword_campaignname]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


-- exec SP_Adword_campaignname 335,0,2
CREATE PROCEDURE [dbo].[SP_Adword_campaignname]
(            
@User_ID bigint,           
@AdwordGroupId bigint,           
@opt int            
)            
as            
begin            
            
if(@opt=1)            
begin            
select  CampAd_id, CampaignName from tblCampaign where User_ID=@User_ID and InProcess=1 order by CampaignId desc            
end            
else if(@opt=2)          
begin          
    select AdGroupId,AdwordGroupId+','+gp.CampAd_id as AdwordGroupId,GroupName,cp.CampaignName+'-> '+GroupName as cmpnm, Keyword, cp.Location, cp.Budget, 
		  cp.CmpStartDate, cp.CmpEndDate, cp.CampaignType, cp.CampaignSubType
    from tblAdGroup gp inner join tblCampaign cp on cp.CampAd_id = gp.CampAd_id        
    where gp.User_ID=@User_ID and  gp.InProcess=1 and AdwordGroupId is not null
    order by AdGroupId desc            
end          
else if(@opt=3)          
begin          
 select GroupName,Keyword from tblAdGroup where User_ID=@User_ID and AdwordGroupId=@AdwordGroupId          
end  
else if(@opt=4)--for Adgroup name report          
begin          
select  CampAd_id [value], CampaignName [key] from tblCampaign where User_ID=@User_ID and InProcess=1 order by CampaignId desc  
select  AdwordGroupId [value],GroupName [key]   
from tblAdGroup gp        
where gp.User_ID=@User_ID and  gp.InProcess=1 and AdwordGroupId is not null   order by AdGroupId          
 desc            
end          
  
          
end  



GO

