/* ============================================================
   Procedure: [dbo].[Sp_adword_exception]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE PROCEDURE Sp_adword_exception  
(  
@id bigint,  
@msg varchar(max),  
@InProcess tinyint,  
@type varchar(10)  
)  
as  
begin  
if(@type='camp')  
begin  
update tblCampaign  set InProcess=@InProcess,errormessage=@msg where CampaignId=@id  
update tblAdGroup  set InProcess=@InProcess,errormessage='asscoicate Campaign Rejected' where CampAd_id=@id 
update tblAds  set InProcess=@InProcess,errormessage='asscoicate Campaign Rejected' where CampaignId=@id   
end  
if(@type='group')  
begin  
update tblAdGroup  set InProcess=@InProcess,errormessage=@msg where AdGroupId=@id  
  
end  
if(@type='adword')  
begin  
update tblAds  set InProcess=@InProcess,errormessage=@msg where AdwordAdsId=@id  
  
end  
end


GO

