SET QUOTED_IDENTIFIER ON

CREATE PROCEDURE [dbo].[SP_Adword_Getreport] --'2018-10-17','2018-10-17', 335, ,2    
(    
@fmdate datetime,    
@toDate datetime,    
@user_id bigint,    
@opt int    
)    
as    
begin  

declare @ParentID  bigint = 0

select  @ParentID = ParentID from user_detail where USER_ID = @user_id

  
if(@opt=1)    
begin    
select 
[GroupPerformaneRepId]
      ,[AdGroupId]
      ,[AdGroupName]
      ,[AdGroupStatus]
      ,[AverageCost]
      ,[AverageCpc]
      ,[AverageCpe]
      ,[AverageCpm]
      ,[CampaignId]
      ,[CampaignName]
      ,[CampaignStatus]
      ,[Clicks]
      ,[ConversionRate]
      ,[Conversions]
      ,[ConversionValue]
      ,[Cost]
      ,[CpcBid]
      ,[CpmBid]
      ,[CpvBid]
      ,[Ctr]
      ,[User_id]
      ,[Impressions]
      ,[InteractionRate]
      ,[Interactions]
      ,[InteractionTypes]
      ,[TargetCpa]
      ,[TargetCpaBidSource]
      , dbo.[fn_getusertimefromindiantime](@ParentID,CreatedDate)  as CreatedDate
from  tblAdwordsGroupPerformanceRep      
end    
if(@opt=2)    
begin    
 select 
 
  
 
 rpt.[GroupPerformaneRepId]
      ,rpt.[AdGroupId]
      ,rpt.[AdGroupName]
      ,rpt.[AdGroupStatus]
      ,rpt.[AverageCost]
      ,rpt.[AverageCpc]
      ,rpt.[AverageCpe]
      ,rpt.[AverageCpm]
      ,rpt.[CampaignId]
      ,rpt.[CampaignName]
      ,rpt.[CampaignStatus]
      ,rpt.[Clicks]
      ,rpt.[ConversionRate]
      ,rpt.[Conversions]
      ,rpt.[ConversionValue]
      ,rpt.[Cost]
      ,rpt.[CpcBid]
      ,rpt.[CpmBid]
      ,rpt.[CpvBid]
      ,rpt.[Ctr]
      ,rpt.[User_id]
      ,rpt.[Impressions]
      ,rpt.[InteractionRate]
      ,rpt.[Interactions]
      ,rpt.[InteractionTypes]
      ,rpt.[TargetCpa]
      ,rpt.[TargetCpaBidSource]
      ,dbo.[fn_getusertimefromindiantime](@ParentID,rpt.CreatedDate)  as CreatedDate
 
 
 from  tblAdwordsGroupPerformanceRep rpt    
 inner join tblCampaign cmp on cmp.CampAd_id = rpt.CampaignId    
 where cmp.User_ID = @user_id and Convert(date, rpt.CreatedDate) between      
 Convert(date, dbo.[fn_getISTtimefromusertime](@ParentID,@fmdate) ) and Convert(date,dbo.[fn_getISTtimefromusertime](@ParentID,@toDate))    
end    
end 



