(        
  @CampaignId int                       
, @CampAd_id varchar(50)                        
,@User_ID varchar(250)                                
,@CampaignName varchar(250)                                
,@Location varchar(1000)                               
,@Budget varchar(50)                                
,@Bidding float               
,@IPAddress varchar(50)                             
,@Source varchar(50)                                         
,@BudgetId varchar(50)                          
,@BudgetName varchar(50)                      
, @stdate datetime                       
, @endate datetime                  
, @Status bit                  
, @Gcampaignname varchar(250)          
, @Gbudgetname varchar(250)                     
 ,@locid varchar(50) = ''        
 ,@InProcess tinyint ,         
 @opt int,    
 @oldBudgetId bigint        
)        
as        
begin    
    
if(@opt=1)        
begin      
      
update tblCampaign set CampAd_id=@CampAd_id,BudgetId=@BudgetId,Gcampaignname=@Gcampaignname, ApprovalDate=GETDATE(),       
InProcess=@InProcess,CmpStartDate=@stdate,CmpEndDate=@endate,locid =@locid  where CampaignName=@CampaignName   
        
 update tblAdwordBudget set BudgetId=@BudgetId,BudgetName=@BudgetName,Budgetamt=@Budget,Gbudgetname=@Gbudgetname        
 where BudgetId=@oldBudgetId        
--Insert Into tblAdwordBudget(BudgetId,BudgetName,Budgetamt, Gbudgetname)                  
-- values(@BudgetId,@BudgetName,@Budget,@Gbudgetname)                          
    set @CampaignId=(select IDENT_CURRENT('tblCampaign'))                        
        select 'success' as result,@CampAd_id  as CampAd_id         
                
end        
end    



