/* ============================================================
   Procedure: [dbo].[SP_Adword_windowservice_camp]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


-- exec SP_Adword_windowservice_camp @opt=1
CREATE PROCEDURE [SP_Adword_windowservice_camp]
(        
    @opt int        
)        
as        
begin

If(@opt=1)
begin        

    SELECT [Camp].[CampaignId], [Camp].[CampAd_id], [Camp].User_ID, [Camp].[CampaignName], [Camp].[Location], [Camp].[BidStrategyType], [Camp].[CampaignType], [Camp].[Budget], [Camp].[BudgetId], [Camp].[BiddingClick], [Camp].[Bidding], [Camp].STATUS, [Camp].[SortId], [Camp].[Source], [Camp].[IPAddress], [Camp].[IsActive], [Camp].[IsPublished], [Camp].[CreatedDate], [Camp].[ModifiedDate], [Camp].[CreatedBy], [Camp].[ModifiedBy], [Camp].[CmpStartDate], [Camp].[CmpEndDate], [Camp].[Starton], [Camp].[GCampaignName], [Camp].[minbal], [Camp].[locid], [Camp].[InProcess], [Camp].[errormessage], [Camp].[radious], [Camp].[longitude], [Camp].[latitude], [Camp].[IsDeleted], [Camp].[CampaignSubType], [Camp].[radunit], [Camp].[ApprovalDate], 
    [tblgrp].[AdGroupId], [tblgrp].[AdwordGroupId], [tblgrp].[GroupName], [tblgrp].[Adword_Name], [tblgrp].[Keyword], [tblgrp].[KeywordId], [tblgrp].[match_type], [tblgrp].[Gender], [tblgrp].[AgeRanges], [tblgrp].[Platform], [tblgrp].[Incomepercentilerange], [tblgrp].[Parentalstatus], [tblgrp].[Affinitycategories], [tblgrp].[DaysofWeek], 
    [tbadd].[AdsId], [tbadd].[AdwordAdsId], [tbadd].[BusinessName], [tbadd].[Description1], [tbadd].[Description2], [tbadd].[DisplayUrl], [tbadd].[DestinationUrl], [tbadd].[Headline3], [tbadd].[DescriptionTwo], [tbadd].[DisplayUrlPath1], [tbadd].[DisplayUrlPath2], 
    [tblRad].[tblAds_Rad_Id], [tblRad].[Ref_AdsId], [tblRad].[FinalUrl], [tblRad].[ShortHeadline1], [tblRad].[ShortHeadline2], [tblRad].[ShortHeadline3], [tblRad].[ShortHeadline4], [tblRad].[ShortHeadline5], [tblRad].[LongHeadline], [tblRad].[Description1] AS [Rad_Description1], [tblRad].[Description2] AS [Rad_Description2], [tblRad].[Description3] AS [Rad_Description3], [tblRad].[Description4] AS [Rad_Description4], [tblRad].[Description5] AS [Rad_Description5], [tblRad].[BusinessName] AS [Rad_BusinessName], [tblRad].[MarketingImage1_AssetId], [tblRad].[MarketingImage2_AssetId], [tblRad].[MarketingImage3_AssetId], [tblRad].[MarketingImage4_AssetId], [tblRad].[MarketingImage5_AssetId], [tblRad].[MarketingSquareImage1_AssetId], [tblRad].[MarketingSquareImage2_AssetId], [tblRad].[MarketingSquareImage3_AssetId], [tblRad].[MarketingSquareImage4_AssetId], [tblRad].[MarketingSquareImage5_AssetId], [tblRad].[LogoImage1_AssetId], [tblRad].[LogoImage2_AssetId], [tblRad].[LogoImage3_AssetId], [tblRad].[LogoImage4_AssetId], [tblRad].[LogoImage5_AssetId]
    FROM tblCampaign AS Camp INNER JOIN tblAdGroup AS tblgrp
    ON Camp.CampAd_id = tblgrp.CampAd_id INNER JOIN tblAds AS tbadd
    ON tblgrp.CampAd_id = tbadd.CampaignId LEFT OUTER JOIN tblAds_ResponsiveAdForDisplay AS tblRad
    ON tbadd.AdsId = tblRad.Ref_AdsId
    WHERE([tblgrp].[InProcess] = 0) AND ([Camp].[InProcess] = 0) AND ([tbadd].[InProcess] = 0);

end

end



GO

