CREATE   PROCEDURE [dbo].[sp_Calc_price_New11]                                          
(                                          
 @userID         BIGINT,                                    
 @tmptbl tbl_IntMobtbl READONLY,                              
 @OptType nvarchar(10),                              
 --@OriginCountryCode nvarchar(5),                              
 @AccTypeValue nvarchar(10) ='',                            
 @mCount bigint=0,                            
 @OCName nvarchar(10) ='',                        
 @duration int                              
)                                          
                                         
AS                                          
BEGIN                                          
 DECLARE @BatchID BIGINT                                          
                                      
CREATE TABLE #tmpfl(                                      
 [row_no] [int] NOT NULL,                                  
 [user_id] [bigint] NULL,                                  
 [message] [nvarchar](max) NULL,                                  
 [unicode] [bit] NULL,                                  
 [credit] [float] NULL,                                  
 [BatchID] [bigint]  NULL,                                  
 [Country_code] [varchar](10) NULL,                                  
 [Mobile] [varchar](20) NULL,                                  
 [MessageStatus] [varchar](20) NULL,                                  
 [SenderID] [nchar](20) NULL,                                  
 [ScheduledDate] [varchar](50) NULL,                                  
 [ScheduledTime] [varchar](50) NULL,                                  
 [SmppID] [tinyint]  NULL,                                  
 [U_ID] [int]  NULL,                                  
 [IsUniCode] [bit]  NULL,                                  
 [IsDnd] [bit]  NULL,                                  
 [MobileSubSet] [bigint] NULL,                                  
 [IsPrority] [tinyint] NULL,                                  
 [IsAllowDND] [tinyint] NULL,                                  
 [price] decimal(18,4) NULL,                            
  AccType varchar(10)                                  
)                                    
  -- declare  @tmptbl tbl_IntMobtbl                                   
declare @country_code nvarchar(10)='',                                      
 @Mobile varchar(20)='',                                      
 @message nvarchar(max)='',                                      
 @price decimal(18,4)=0,                                      
 @unicode bit=0,                                      
 @user_id bigint =0,                                      
 @OriginCountryCode nvarchar(5)  ,                              
 @Actualbalance decimal(18,4),                          
 @OriginCountryID int ,                           
 @Cr_amt decimal(18,4),              
 @balance decimal(18,4)                 
                           
 select @OriginCountryCode=mc1.CountryCode,@OriginCountryID=mc1.Country_ID from user_detail ud join m_country1 mc1                              
  on ud.Country_ID=mc1.Country_ID and ud.User_ID=@userID                              
select top 1 @Actualbalance = Balance from dbo.IntCredit_Details where USER_ID = @userid                                      
 order by Credit_ID desc                                      
                              
if @AccTypeValue ='' --if account type is not provided                              
begin                              
select @AccTypeValue=userfilter from user_detail(nolock) where user_id=@userid                              
end                            
              
if @OptType = 'smsold'                              
Begin                              
              
select top 1 @price =  PRICE from (          
 select CASE @AccTypeValue                              
                WHEN  'MTIX_TR' then PTrns                               
    WHEN  'MTIX_PRO' then PPromo      
    WHEN  'MTIX_TRC' then PTrnsScurb                               
    WHEN  'CRITICAL' then PCritical                                
 END AS PRICE from dbo.Price_Base_SMS_Rate_Exception where USERID = @userid                               
      and destinationCountryid =101 and OriginCountryid=101                                
  union                                   
   select CASE @AccTypeValue                              
   WHEN  'MTIX_TR' then PTrns                               
    WHEN  'MTIX_PRO' then PPromo                              
    WHEN  'MTIX_TRC' then PTrnsScurb                        
    WHEN  'CRITICAL' then PCritical                                
    END  AS PRICE from dbo.Price_Base_SMS_Rate where                                      
       destinationCountryid =101 and OriginCountryid=101                              
  )   aa               
              
 set @Cr_amt=@price * @mCount                           
if @Actualbalance > @Cr_amt                            
  select @Actualbalance-@Cr_amt balance,'ok' msg                            
else                                      
  select 0 balance,'err' msg                  
              
End -- End of SMS old                                    
else if @OptType = 'sms'                              
Begin                              
                                       
insert into #tmpfl (row_no,user_id, message, unicode, credit, BatchID,                                  
  Country_code, Mobile, MessageStatus ,SenderID, ScheduledDate,                                  
  ScheduledTime, SmppID, U_ID,IsUniCode ,IsDnd, MobileSubSet,                                  
  IsPrority, IsAllowDND, price)                                     
select row_no,user_id, message, unicode, credit, BatchID,                                  
  Country_code, Mobile, MessageStatus ,SenderID, ScheduledDate,                                  
  ScheduledTime, SmppID, U_ID,IsUniCode ,IsDnd, MobileSubSet,                                  
  IsPrority, IsAllowDND, price from @tmptbl                                     
                             
                                    
update u set country_code = m.CountryCode                                     
from #tmpfl u (nolock) join m_country1 m on                                     
ltrim(rtrim(str(u.mobile,20,0))) like ltrim(rtrim(str(m.CountryCode,20,0)))+ '%'                              
where u.country_code = ''                                    
                                     
                                   
declare @strow as int, @ndrow as int                          
select @strow = MIN(row_no) , @ndrow = MAX(row_no) from #tmpfl                                      
                              
   --   select * from m_country1 where Country_Name='nigeria'                      
   --select * from m_country1 where Country_Name='india'                      
                              
   --       select  PTrns from dbo.Price_Base_SMS_Rate_Exception where USERID = 335                                      
   --   and destinationCountryCode ='+234' and OriginCountryCode='+91'                     
                            
                            
if @AccTypeValue = 'MTIX_TR'                            
Begin                            
                            
WHILE( @strow <= @ndrow) --loop in all number to calculate balance                                      
begin                               
                                     
select @country_code =country_code,@Mobile =Mobile,                                      
 @message=message,@user_id = user_id ,                                      
 @unicode =[unicode] from  #tmpfl where row_no = @strow                                    
                                 
--select * from User_Filter                              
-- select * from Price_Base_SMS_Rate_Exception                              
                              
 --select @price =CASE @AccTypeValue                             
 --               WHEN  'MTIX_TR' then PTrns                               
 --   WHEN  'MTIX_PRO' then PPromo                              
 --   WHEN  'MTIX_TRC' then PTrnsScurb                               
 --   WHEN  'CRITICAL' then PCritical                                
 --   END from dbo.Price_Base_SMS_Rate_Exception where USERID = @userid                               
 --     and destinationCountryCode =@country_code and OriginCountryCode=@OriginCountryCode                                
        
 -- if(@price=0)                              
 -- Begin                              
 --  select @price =CASE @AccTypeValue                              
 --               WHEN  'MTIX_TR' then PTrns                               
 --   WHEN  'MTIX_PRO' then PPromo                              
 --   WHEN  'MTIX_TRC' then PTrnsScurb                               
 --   WHEN  'CRITICAL' then PCritical                                
 --   END from dbo.Price_Base_SMS_Rate where USERID = @userid                                      
 --     and destinationCountryCode =@country_code and OriginCountryCode=@OriginCountryCode                              
 -- End                              
   set @price =                 
   (                
      select PTrns from dbo.Price_Base_SMS_Rate_Exception where USERID = @userid                                      
      and destinationCountryCode =@country_code and OriginCountryCode=@OriginCountryCode                                
    Union              
  --if(@price=0)                              
  --Begin                              
   select PTrns from dbo.Price_Base_SMS_Rate where                     
   --USERID = @userid and                     
      destinationCountryCode =@country_code and OriginCountryCode=@OriginCountryCode                    
   )                
   --set @price=8                            
  --End                                  
                                 
-- declare @Credit float, @len int                                      
                                      
 --select @len = len(@message)                                      
 --  ,@Credit = (case when @unicode=0 and len(@message)<=160  then 1                                       
 --  when @unicode=0 and LEN(@message)>160 then ceiling(LEN(@message)/cast(153 as FLOat))                                       
 --  when @unicode=1                                       
 --  and len(@message)<=70 then 1 else ceiling(LEN(@message)/cast(67 as float)) end ) ,                                      
 --  @price = (case when @unicode=0 and len(@message)<=160  then 1                                       
 --  when @unicode=0 and LEN(@message)>160 then ceiling(LEN(@message)/cast(153 as FLOat))                                       
 --  when @unicode=1                                       
 --  and len(@message)<=70 then 1 else ceiling(LEN(@message)/cast(67 as float)) end )*@price                                      
                                 
 --update #tmpfl set price = @price,Credit= @Credit where row_no = @strow                                      
update #tmpfl set price = dbo.Price_GetSMSCost(@message,@unicode,@price) where row_no = @strow                                      
set @strow = @strow+1                                      
end                                 
                            
End                            
                            
else if @AccTypeValue = 'MTIX_PRO'                            
Begin                            
WHILE( @strow <= @ndrow) --loop in all number to calculate balance                               
begin                               
 select @country_code =country_code,@Mobile =Mobile,                                      
 @message=message,@user_id = user_id ,                                      
 @unicode =[unicode] from  #tmpfl where row_no = @strow                                    
                                
          
 select @price = PTrns from dbo.Price_Base_SMS_Rate_Exception where USERID = @userid                                      
      and destinationCountryCode =@country_code and OriginCountryCode=@OriginCountryCode                                
                                
  if(@price=0)                              
  Begin                              
   select @price = PTrns from dbo.Price_Base_SMS_Rate where USERID = @userid                                      
      and destinationCountryCode =@country_code and OriginCountryCode=@OriginCountryCode                              
  End                                  
update #tmpfl set price = dbo.Price_GetSMSCost(@message,@unicode,@price) where row_no = @strow                                      
set @strow = @strow+1                                      
end                                 
                            
End                            
                            
else if @AccTypeValue = 'MTIX_TRC'                            
Begin                            
WHILE( @strow <= @ndrow) --loop in all number to calculate balance                                      
begin                               
 select @country_code =country_code,@Mobile =Mobile,                                      
 @message=message,@user_id = user_id ,                                      
 @unicode =[unicode] from  #tmpfl where row_no = @strow                                    
                                
                                   
 select @price = PTrnsScurb from dbo.Price_Base_SMS_Rate_Exception where USERID = @userid                                      
      and destinationCountryCode =@country_code and OriginCountryCode=@OriginCountryCode                                
                                
  if(@price=0)                              
  Begin                              
   select @price = PTrnsScurb from dbo.Price_Base_SMS_Rate where USERID = @userid                                      
      and destinationCountryCode =@country_code and OriginCountryCode=@OriginCountryCode                              
  End                                  
update #tmpfl set price = dbo.Price_GetSMSCost(@message,@unicode,@price) where row_no = @strow                                      
set @strow = @strow+1                                      
end                                 
                            
End                            
else if @AccTypeValue = 'CRITICAL'                            
Begin                            
WHILE( @strow <= @ndrow) --loop in all number to calculate balance                                      
begin                               
 select @country_code =country_code,@Mobile =Mobile,                                      
 @message=message,@user_id = user_id ,                                      
 @unicode =[unicode] from  #tmpfl where row_no = @strow                                    
                                
                                   
 select @price = PCritical from dbo.Price_Base_SMS_Rate_Exception where USERID = @userid                                      
      and destinationCountryCode =@country_code and OriginCountryCode=@OriginCountryCode                                
                                
  if(@price=0)                              
  Begin                              
   select @price = PCritical from dbo.Price_Base_SMS_Rate where USERID = @userid                                      
      and destinationCountryCode =@country_code and OriginCountryCode=@OriginCountryCode                              
  End                                  
update #tmpfl set price = dbo.Price_GetSMSCost(@message,@unicode,@price) where row_no = @strow                                      
set @strow = @strow+1                                      
end                                 
                            
End                            
                            
                                     
 select @Cr_amt = SUM(price) from #tmpfl                                      
                                      
 select top 1 @balance= Balance from dbo.IntCredit_Details where USER_ID = @user_id                                      
 order by Credit_ID desc                                      
                                      
if @balance >= @Cr_amt                                      
 select @balance-@Cr_amt balance,'ok' msg,* from #tmpfl                                      
else                                      
 select 0 balance,'err' msg, * from #tmpfl                                      
                                       
 drop table #tmpfl                                 
END -- end of SMS                              
Else If @OptType='voice'                              
Begin                              
                        
declare @intdur as bigint                        
, @fracdur as bigint                        
,@Pulse_Rate as bigint                        
                        
--set @price=                        
if exists(                        
select case when @AccTypeValue = 'MTIX_TR' then LocalRTrns                        
            when @AccTypeValue = 'MTIX_PRO' then LocalRPromo                        
   when @AccTypeValue = 'MTIX_TRC' then LocalRTrnsScurb                        
   when @AccTypeValue = 'CRITICAL' then LocalRCritical end as pprice                       
      from Price_Base_Voice_Rate_Exception where OriginCountryId=101 and USERID=@userID and destinationCountryid=101)  
      begin  
 select @price=(                        
select case when @AccTypeValue = 'MTIX_TR' then LocalRTrns                        
            when @AccTypeValue = 'MTIX_PRO' then LocalRPromo                        
   when @AccTypeValue = 'MTIX_TRC' then LocalRTrnsScurb                        
   when @AccTypeValue = 'CRITICAL' then LocalRCritical end as pprice                       
      from Price_Base_Voice_Rate_Exception where OriginCountryId=101 and USERID=@userID and destinationCountryid=101)  
 end     
 else  
 begin  
 select @price=(select case when @AccTypeValue = 'MTIX_TR' then LocalRTrns            
            when @AccTypeValue = 'MTIX_PRO' then LocalRPromo                        
   when @AccTypeValue = 'MTIX_TRC' then LocalRTrnsScurb                        
   when @AccTypeValue = 'CRITICAL' then LocalRCritical end as pprice                         
         from Price_Base_Voice_Rate where OriginCountryId=101 and destinationCountryid=101                        
)     
 end                     
--union                                             
                    
--set @Pulse_Rate=                        
--(                        
--select 60 from Price_Base_Voice_Rate_Exception where OriginCountryId=@OriginCountryCode and USERID=@userid                        
--union                        
--select 60 from Price_Base_Voice_Rate where OriginCountryId=@OriginCountryCode                        
--)                        
set @Pulse_Rate=30                        
                        
select @intdur =Convert(int,@duration/@Pulse_Rate),                        
 @fracdur= @duration%@Pulse_Rate                         
                        
if @fracdur >0                        
 set @intdur = @intdur+1                          
                        
set @Cr_amt=@price * @mCount * @intdur       

declare @avilablebalance as decimal(18,4)
set @avilablebalance = dbo.GetAvailableBalanceForService(@userID, 1)

                        
if @avilablebalance > @Cr_amt                        
 select @Cr_amt balance,'ok' msg,@Pulse_Rate PulseRate,@Price Price                        
else                                  
  select 0 balance,'err' msg,@Pulse_Rate PulseRate,@Price Price                      
                         
END   --end of voice                            
Else If @OptType='mail'                              
Begin                              
                            
set @price=                            
(                            
select Price from Price_Base_Mail_Rate_Exception where OriginCountryId=@OriginCountryID and USERID=@userid                            
union                            
select Price from Price_Base_Mail_Rate where OriginCountryId=@OriginCountryID                            
)                           
                          
set @Cr_amt=@price * @mCount                           
                          
                          
if @Actualbalance > @Cr_amt                      
  select @Actualbalance-@Cr_amt balance,'ok' msg                            
else                                      
  select 0 balance,'err' msg                              
                            
END   -- end of mail                               
                                      
END   



GO

/* ============================================================
   Procedure: [dbo].[sp_Calc_price_New111]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[sp_Calc_price_New111]                                        
(                                        
 @userID         BIGINT,                                  
 @tmptbl tbl_IntMobtbl READONLY,                            
 @OptType nvarchar(10),                            
 --@OriginCountryCode nvarchar(5),                            
 @AccTypeValue nvarchar(10) ='',                          
 @mCount bigint=0,                          
 @OCName nvarchar(10) ='',                      
 @duration int                            
)                                        
                                       
AS                                        
BEGIN                                        
 DECLARE @BatchID BIGINT                                        
                                    
CREATE TABLE #tmpfl(                                    
 [row_no] [int] NOT NULL,                                
 [user_id] [bigint] NULL,                                
 [message] [nvarchar](max) NULL,                                
 [unicode] [bit] NULL,                                
 [credit] [float] NULL,                                
 [BatchID] [bigint]  NULL,                                
 [Country_code] [varchar](10) NULL,                                
 [Mobile] [varchar](20) NULL,                                
 [MessageStatus] [varchar](20) NULL,                                
 [SenderID] [nchar](20) NULL,                                
 [ScheduledDate] [varchar](50) NULL,                                
 [ScheduledTime] [varchar](50) NULL,                                
 [SmppID] [tinyint]  NULL,                                
 [U_ID] [int]  NULL,                                
 [IsUniCode] [bit]  NULL,                                
 [IsDnd] [bit]  NULL,                                
 [MobileSubSet] [bigint] NULL,                                
 [IsPrority] [tinyint] NULL,                                
 [IsAllowDND] [tinyint] NULL,                                
 [price] decimal(18,4) NULL,                          
  AccType varchar(10)                                
)                                  
  -- declare  @tmptbl tbl_IntMobtbl                                 
declare @country_code nvarchar(10)='',                                    
 @Mobile varchar(20)='',                                    
 @message nvarchar(max)='',                                    
 @price decimal(18,4)=0,                                    
 @unicode bit=0,                                    
 @user_id bigint =0,                                    
 @OriginCountryCode nvarchar(5)  ,                            
 @Actualbalance decimal(18,4),                        
 @OriginCountryID int ,                         
 @Cr_amt decimal(18,4),            
 @balance decimal(18,4)               
                         
 select @OriginCountryCode=mc1.CountryCode,@OriginCountryID=mc1.Country_ID from user_detail ud join m_country1 mc1                            
  on ud.Country_ID=mc1.Country_ID and ud.User_ID=@userID                            
select top 1 @Actualbalance = Balance from dbo.IntCredit_Details where USER_ID = @userid                                    
 order by Credit_ID desc                                    
                            
if @AccTypeValue ='' --if account type is not provided                            
begin                            
select @AccTypeValue=userfilter from user_detail(nolock) where user_id=@userid                            
end                          
            
if @OptType = 'smsold'                            
Begin                            
            
select top 1 @price =  PRICE from (        
 select CASE @AccTypeValue                            
                WHEN  'MTIX_TR' then PTrns                             
    WHEN  'MTIX_PRO' then PPromo                            
    WHEN  'MTIX_TRC' then PTrnsScurb                             
    WHEN  'CRITICAL' then PCritical                              
 END AS PRICE from dbo.Price_Base_SMS_Rate_Exception where USERID = @userid                             
      and destinationCountryid =101 and OriginCountryid=101                              
  union                                 
   select CASE @AccTypeValue                            
   WHEN  'MTIX_TR' then PTrns                             
    WHEN  'MTIX_PRO' then PPromo                            
    WHEN  'MTIX_TRC' then PTrnsScurb                      
    WHEN  'CRITICAL' then PCritical                              
    END  AS PRICE from dbo.Price_Base_SMS_Rate where                                    
       destinationCountryid =101 and OriginCountryid=101                            
  )   aa             
            
 set @Cr_amt=@price * @mCount                         
if @Actualbalance > @Cr_amt                          
  select @Actualbalance-@Cr_amt balance,'ok' msg                          
else                                    
  select 0 balance,'err' msg                
            
End -- End of SMS old                                  
else if @OptType = 'sms'                            
Begin                            
                                     
insert into #tmpfl (row_no,user_id, message, unicode, credit, BatchID,                                
  Country_code, Mobile, MessageStatus ,SenderID, ScheduledDate,                                
  ScheduledTime, SmppID, U_ID,IsUniCode ,IsDnd, MobileSubSet,                                
  IsPrority, IsAllowDND, price)                                   
select row_no,user_id, message, unicode, credit, BatchID,                                
  Country_code, Mobile, MessageStatus ,SenderID, ScheduledDate,                                
  ScheduledTime, SmppID, U_ID,IsUniCode ,IsDnd, MobileSubSet,                                
  IsPrority, IsAllowDND, price from @tmptbl                                   
                           
                                  
update u set country_code = m.CountryCode                                   
from #tmpfl u (nolock) join m_country1 m on                                   
ltrim(rtrim(str(u.mobile,20,0))) like ltrim(rtrim(str(m.CountryCode,20,0)))+ '%'                            
where u.country_code = ''                                  
                                   
                                 
declare @strow as int, @ndrow as int                        
select @strow = MIN(row_no) , @ndrow = MAX(row_no) from #tmpfl                                    
                            
   --   select * from m_country1 where Country_Name='nigeria'                    
   --select * from m_country1 where Country_Name='india'                    
                            
   --       select  PTrns from dbo.Price_Base_SMS_Rate_Exception where USERID = 335                                    
   --   and destinationCountryCode ='+234' and OriginCountryCode='+91'                   
                          
                          
if @AccTypeValue = 'MTIX_TR'                          
Begin                          
                          
WHILE( @strow <= @ndrow) --loop in all number to calculate balance                                    
begin                             
                                   
select @country_code =country_code,@Mobile =Mobile,                                    
 @message=message,@user_id = user_id ,                                    
 @unicode =[unicode] from  #tmpfl where row_no = @strow                                  
                               
--select * from User_Filter                            
-- select * from Price_Base_SMS_Rate_Exception                            
                            
 --select @price =CASE @AccTypeValue                            
 --               WHEN  'MTIX_TR' then PTrns                             
 --   WHEN  'MTIX_PRO' then PPromo                            
 --   WHEN  'MTIX_TRC' then PTrnsScurb                             
 --   WHEN  'CRITICAL' then PCritical                              
 --   END from dbo.Price_Base_SMS_Rate_Exception where USERID = @userid                             
 --     and destinationCountryCode =@country_code and OriginCountryCode=@OriginCountryCode                              
      
 -- if(@price=0)                            
 -- Begin                            
 --  select @price =CASE @AccTypeValue                            
 --               WHEN  'MTIX_TR' then PTrns                             
 --   WHEN  'MTIX_PRO' then PPromo                            
 --   WHEN  'MTIX_TRC' then PTrnsScurb                             
 --   WHEN  'CRITICAL' then PCritical                              
 --   END from dbo.Price_Base_SMS_Rate where USERID = @userid                                    
 --     and destinationCountryCode =@country_code and OriginCountryCode=@OriginCountryCode                            
 -- End                            
   set @price =               
   (              
      select PTrns from dbo.Price_Base_SMS_Rate_Exception where USERID = @userid                                    
      and destinationCountryCode =@country_code and OriginCountryCode=@OriginCountryCode                              
    Union            
  --if(@price=0)                            
  --Begin                            
   select PTrns from dbo.Price_Base_SMS_Rate where                   
   --USERID = @userid and                   
      destinationCountryCode =@country_code and OriginCountryCode=@OriginCountryCode                  
   )              
   --set @price=8                          
  --End                                
                               
-- declare @Credit float, @len int                                    
                                    
 --select @len = len(@message)                                    
 --  ,@Credit = (case when @unicode=0 and len(@message)<=160  then 1                                     
 --  when @unicode=0 and LEN(@message)>160 then ceiling(LEN(@message)/cast(153 as FLOat))                                     
 --  when @unicode=1                                     
 --  and len(@message)<=70 then 1 else ceiling(LEN(@message)/cast(67 as float)) end ) ,                                    
 --  @price = (case when @unicode=0 and len(@message)<=160  then 1                                     
 --  when @unicode=0 and LEN(@message)>160 then ceiling(LEN(@message)/cast(153 as FLOat))                                     
 --  when @unicode=1                                     
 --  and len(@message)<=70 then 1 else ceiling(LEN(@message)/cast(67 as float)) end )*@price                                    
                               
 --update #tmpfl set price = @price,Credit= @Credit where row_no = @strow                                    
update #tmpfl set price = dbo.Price_GetSMSCost(@message,@unicode,@price) where row_no = @strow                                    
set @strow = @strow+1                                    
end                               
                          
End                          
                          
else if @AccTypeValue = 'MTIX_PRO'                          
Begin                          
WHILE( @strow <= @ndrow) --loop in all number to calculate balance                             
begin                             
 select @country_code =country_code,@Mobile =Mobile,                                    
 @message=message,@user_id = user_id ,                                    
 @unicode =[unicode] from  #tmpfl where row_no = @strow                                  
                              
                                 
 select @price = PTrns from dbo.Price_Base_SMS_Rate_Exception where USERID = @userid                                    
      and destinationCountryCode =@country_code and OriginCountryCode=@OriginCountryCode                              
                              
  if(@price=0)                            
  Begin                            
   select @price = PTrns from dbo.Price_Base_SMS_Rate where USERID = @userid                                    
      and destinationCountryCode =@country_code and OriginCountryCode=@OriginCountryCode                            
  End                                
update #tmpfl set price = dbo.Price_GetSMSCost(@message,@unicode,@price) where row_no = @strow                                    
set @strow = @strow+1                                    
end                               
                          
End                          
                          
else if @AccTypeValue = 'MTIX_TRC'                          
Begin                          
WHILE( @strow <= @ndrow) --loop in all number to calculate balance                                    
begin                             
 select @country_code =country_code,@Mobile =Mobile,                                    
 @message=message,@user_id = user_id ,                                    
 @unicode =[unicode] from  #tmpfl where row_no = @strow                                  
                              
                                 
 select @price = PTrnsScurb from dbo.Price_Base_SMS_Rate_Exception where USERID = @userid                                    
      and destinationCountryCode =@country_code and OriginCountryCode=@OriginCountryCode                              
                              
  if(@price=0)                            
  Begin                            
   select @price = PTrnsScurb from dbo.Price_Base_SMS_Rate where USERID = @userid                                    
      and destinationCountryCode =@country_code and OriginCountryCode=@OriginCountryCode                            
  End                                
update #tmpfl set price = dbo.Price_GetSMSCost(@message,@unicode,@price) where row_no = @strow                                    
set @strow = @strow+1                                    
end                               
                          
End                          
else if @AccTypeValue = 'CRITICAL'                          
Begin                          
WHILE( @strow <= @ndrow) --loop in all number to calculate balance                                    
begin                             
 select @country_code =country_code,@Mobile =Mobile,                                    
 @message=message,@user_id = user_id ,                                    
 @unicode =[unicode] from  #tmpfl where row_no = @strow                                  
                              
                                 
 select @price = PCritical from dbo.Price_Base_SMS_Rate_Exception where USERID = @userid                                    
      and destinationCountryCode =@country_code and OriginCountryCode=@OriginCountryCode                              
                              
  if(@price=0)                            
  Begin                            
   select @price = PCritical from dbo.Price_Base_SMS_Rate where USERID = @userid                                    
      and destinationCountryCode =@country_code and OriginCountryCode=@OriginCountryCode                            
  End                                
update #tmpfl set price = dbo.Price_GetSMSCost(@message,@unicode,@price) where row_no = @strow                                    
set @strow = @strow+1                                    
end                               
                          
End                          
                          
                                   
 select @Cr_amt = SUM(price) from #tmpfl                                    
                                    
 select top 1 @balance= Balance from dbo.IntCredit_Details where USER_ID = @user_id                                    
 order by Credit_ID desc                                    
                                    
if @balance >= @Cr_amt                                    
 select @balance-@Cr_amt balance,'ok' msg,* from #tmpfl                                    
else                                    
 select 0 balance,'err' msg, * from #tmpfl                                    
                                     
 drop table #tmpfl                               
END -- end of SMS                            
Else If @OptType='voice'                            
Begin                            
                      
declare @intdur as bigint                      
, @fracdur as bigint                      
,@Pulse_Rate as bigint                      
                      
set @price=                      
(                      
select case when @AccTypeValue = 'MTIX_TR' then LocalRTrns                      
            when @AccTypeValue = 'MTIX_PRO' then LocalRPromo                      
   when @AccTypeValue = 'MTIX_TRC' then LocalRTrnsScurb                      
   when @AccTypeValue = 'CRITICAL' then LocalRCritical end as pprice                     
      from Price_Base_Voice_Rate_Exception where OriginCountryId=101 and USERID=@userID and destinationCountryid=101                      
union                      
select case when @AccTypeValue = 'MTIX_TR' then LocalRTrns          
            when @AccTypeValue = 'MTIX_PRO' then LocalRPromo                      
   when @AccTypeValue = 'MTIX_TRC' then LocalRTrnsScurb                      
   when @AccTypeValue = 'CRITICAL' then LocalRCritical end as pprice                       
         from Price_Base_Voice_Rate where OriginCountryId=101 and destinationCountryid=101                      
)                      
                  
--set @Pulse_Rate=                      
--(                      
--select 60 from Price_Base_Voice_Rate_Exception where OriginCountryId=@OriginCountryCode and USERID=@userid                      
--union                      
--select 60 from Price_Base_Voice_Rate where OriginCountryId=@OriginCountryCode                      
--)                      
set @Pulse_Rate=30                      
                      
select @intdur =Convert(int,@duration/@Pulse_Rate),                      
 @fracdur= @duration%@Pulse_Rate                       
                      
if @fracdur >0                      
 set @intdur = @intdur+1                        
                      
set @Cr_amt=@price * @mCount * @intdur                      
                      
if @Actualbalance > @Cr_amt                      
 select @Cr_amt balance,'ok' msg,@Pulse_Rate PulseRate,@Price Price                      
else                                
  select 0 balance,'err' msg,@Pulse_Rate PulseRate,@Price Price                    
                       
END   --end of voice                          
Else If @OptType='mail'                            
Begin                            
                          
set @price=                          
(                          
select Price from Price_Base_Mail_Rate_Exception where OriginCountryId=@OriginCountryID and USERID=@userid                          
union                          
select Price from Price_Base_Mail_Rate where OriginCountryId=@OriginCountryID                          
)                         
                        
set @Cr_amt=@price * @mCount                         
                        
                        
if @Actualbalance > @Cr_amt                    
  select @Actualbalance-@Cr_amt balance,'ok' msg                          
else                                    
  select 0 balance,'err' msg                            
                          
END   -- end of mail                             
                                    
END 


GO

/* ============================================================
   Procedure: [dbo].[sp_Calcint_price]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

 
---------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------
CREATE   PROCEDURE [dbo].[sp_Calcint_price]            
(            
 @userID         BIGINT,      
 @tmptbl tbl_IntMobtbl READONLY            
)            
           
AS            
BEGIN            
 DECLARE @BatchID BIGINT            
        
CREATE TABLE #tmpfl(        
 [row_no] [int] NOT NULL,    
 [user_id] [bigint] NULL,    
 [message] [nvarchar](max) NULL,    
 [unicode] [bit] NULL,    
 [credit] [float] NULL,    
 [BatchID] [bigint]  NULL,    
 [Country_code] [varchar](10) NULL,    
 [Mobile] [varchar](20) NULL,    
 [MessageStatus] [varchar](20) NULL,    
 [SenderID] [nchar](20) NULL,    
 [ScheduledDate] [varchar](50) NULL,    
 [ScheduledTime] [varchar](50) NULL,    
 [SmppID] [tinyint]  NULL,    
 [U_ID] [int]  NULL,    
 [IsUniCode] [bit]  NULL,    
 [IsDnd] [bit]  NULL,    
 [MobileSubSet] [bigint] NULL,    
 [IsPrority] [tinyint] NULL,    
 [IsAllowDND] [tinyint] NULL,    
 [price] [float] NULL    
)      
        
declare @country_code nvarchar(10)='',        
 @Mobile varchar(20)='',        
 @message nvarchar(max)='',        
 @price float=0,        
 @unicode bit=0,        
 @user_id bigint =0        
         
         
insert into #tmpfl (row_no,user_id, message, unicode, credit, BatchID,    
  Country_code, Mobile, MessageStatus ,SenderID, ScheduledDate,    
  ScheduledTime, SmppID, U_ID,IsUniCode ,IsDnd, MobileSubSet,    
  IsPrority, IsAllowDND, price)       
select row_no,user_id, message, unicode, credit, BatchID,    
  Country_code, Mobile, MessageStatus ,SenderID, ScheduledDate,    
  ScheduledTime, SmppID, U_ID,IsUniCode ,IsDnd, MobileSubSet,    
  IsPrority, IsAllowDND, price from @tmptbl       
      
update u set country_code = m.CountryCode       
from #tmpfl u (nolock) join m_country1 m on       
ltrim(rtrim(str(u.mobile,20,0))) like ltrim(rtrim(str(m.CountryCode,20,0)))+ '%'  where       
 u.country_code = ''      
       
     
declare @strow as int, @ndrow as int        
select @strow = MIN(row_no) , @ndrow = MAX(row_no) from #tmpfl        
        
WHILE( @strow <= @ndrow)         
begin        
select @country_code =country_code,@Mobile =Mobile,        
 @message=message,@user_id = user_id ,        
 @unicode =unicode from  #tmpfl where row_no = @strow        
        
if exists(select 1 from dbo.Int_sms_price_exc where user_id = @user_id        
and country_code =@country_code)        
 select @price =price from dbo.Int_sms_price_exc where user_id = @user_id        
      and country_code =@country_code        
else        
 select @price =price from dbo.IntSMSRateMast where country_code =@country_code        
        
 declare @Credit float, @len int        
        
 select @len = len(@message)        
   ,@Credit = (case when @unicode=0 and len(@message)<=160  then 1         
   when @unicode=0 and LEN(@message)>160 then ceiling(LEN(@message)/cast(153 as FLOat))         
   when @unicode=1         
   and len(@message)<=70 then 1 else ceiling(LEN(@message)/cast(67 as float)) end ) ,        
   @price = (case when @unicode=0 and len(@message)<=160  then 1         
   when @unicode=0 and LEN(@message)>160 then ceiling(LEN(@message)/cast(153 as FLOat))         
   when @unicode=1         
   and len(@message)<=70 then 1 else ceiling(LEN(@message)/cast(67 as float)) end )*@price        
         
 update #tmpfl set price = @price,Credit= @Credit where row_no = @strow        
      
set @strow = @strow+1        
end        
declare @Cr_amt float,@balance float        
 select @Cr_amt = SUM(price) from #tmpfl 

 DECLARE @avilablebalance as decimal(18,4)
 set @avilablebalance = dbo.GetAvailableBalanceForService(@user_id , 3)
        
 select top 1 @balance= Balance from dbo.IntCredit_Details where USER_ID = @user_id        
 order by Credit_ID desc        
        
if @avilablebalance >= @Cr_amt        
 select @balance-@Cr_amt balance,'ok' msg,* from #tmpfl        
else        
 select 0 balance,'err' msg, * from #tmpfl        
         
 drop table #tmpfl           
        
END 



GO

