/* ============================================================
   Procedure: [dbo].[Sp_check_IP_link]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE PROCEDURE [dbo].Sp_check_IP_link              
 (@opt int )            
as              
begin              
update Link_smsTrack set Isprocessed=1 from Link_smsTrack st        
 inner join  dbo.SMS_Link_Location lt         
 on lt.ipAddress = st.ipAddress        
 where Isprocessed=0        
      
update  st set Isprocessed=1 from User_IP_Track st        
 inner join  dbo.SMS_Link_Location lt         
 on lt.ipAddress = st.ipAdd      
 where Isprocessed=0      
     
    
update  st set Isprocessed=1 from VisitPageDetails st        
 inner join  dbo.SMS_Link_Location lt         
 on lt.ipAddress = st.IPAddress      
 where Isprocessed=0      
    
    
    
       
if @opt =1        
select top 1 ipAddress,Long_Url from dbo.Link_smsTrack(nolock)  where Isprocessed=0       
  order by trackid asc      
else if(@opt =2)      
select top 1 ipAdd as ipAddress,Url from dbo.User_IP_Track(nolock)  where Isprocessed=0       
  order by trackid asc            
else if(@opt = 3)      
select top 1 IPAddress as ipAddress  ,PageName as  Long_Url from dbo.VisitPageDetails(nolock)  where Isprocessed=0       
  order by id asc            
      
    
    
          
end   
  
--select st.* from Link_smsTrack st        
-- inner join  dbo.SMS_Link_Location lt         
-- on lt.ipAddress = st.ipAddress        
-- where Isprocessed=0        
  
  
-- select st.* from User_IP_Track st        
-- inner join  dbo.SMS_Link_Location lt         
