/* ============================================================
   Procedure: [dbo].[SP_check_onofff]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE PROCEDURE dbo.SP_check_onofff (    
 @onduty INT    
 ,@userid BIGINT    
 )    
AS    
BEGIN    
 
    DECLARE @activity VARCHAR(MAX)=''    
    DEclare @ParentID bigint =  isnull((select top 1 ParentID from user_detail with(nolock) where user_id = @userid ),0)
 

 UPDATE User_Detail    
 SET onduty = @onduty    
 WHERE User_ID = @userid    
    
 INSERT INTO Cloud_Agent_OnDutyHistory (    
  user_id    
  ,onduty    
  ,createddatetime,mode , ParentId    
  )    
 VALUES (    
  @userid    
  ,@onduty    
  ,GetDate(),'App' , @ParentID  
  )    
    
 SELECT '1'    
    
 IF @onduty=0    
 BEGIN     
  SET @activity='Updt_offduty'    
 END    
 IF @onduty=1    
 BEGIN    
  SET @activity='Updt_onduty'    
 END    
    
 DECLARE @rowJson NVARCHAR(MAX) = (    
   SELECT *    
   FROM User_Detail    
   WHERE User_ID = @userid    
   FOR JSON AUTO    
    ,INCLUDE_NULL_VALUES    
   )    
    
 EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @userid    
  ,@Activity_type = @activity    
  ,@ActionType = 'U'    
  ,@RowJson = @rowJson    
  ,@Table_name = 'User_Detail'    
END 


GO

/* ============================================================
   Procedure: [dbo].[SP_check_onofff_agents]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE PROCEDURE dbo.SP_check_onofff_agents (  
 @onduty INT  
 ,@agentid BIGINT  
 )  
AS  
BEGIN  
 DECLARE @activity VARCHAR(MAX)='',@uid bigint  ,@cid bigint
  
 UPDATE Calling_Agents  
 SET onduty = @onduty  
 WHERE id = @agentid  

 select @uid=kit19userid from Calling_Agents(nolock) where id=@agentid
  
 INSERT INTO Cloud_Agent_OnDutyHistory (  
  user_id  
  ,onduty  
  ,createddatetime,mode,calling_agentid  
  )  
 VALUES (  
  @uid  
  ,@onduty  
  ,GetDate(),'App',@agentid
  )  
  select @cid=SCOPE_IDENTITY()
 SELECT '1'  
 if isnull(@uid,0)<>0
  begin 
 IF @onduty=0  
 BEGIN   
  SET @activity='Updt_offduty'  
 END  
 IF @onduty=1  
 BEGIN  
  SET @activity='Updt_onduty'  
 END  
  
  
 DECLARE @rowJson NVARCHAR(MAX) = (  
   SELECT user_login,c.createddatetime,c.mode,c.onduty  
   FROM Cloud_Agent_OnDutyHistory c (nolock) join User_Detail u(nolock) on u.User_ID=c.user_id
   WHERE c.User_ID = @uid  and c.id=@cid
   FOR JSON AUTO  
    ,INCLUDE_NULL_VALUES  
   )  
  
 EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @uid  
  ,@Activity_type = @activity  
  ,@ActionType = 'U'  
  ,@RowJson = @rowJson  
  ,@Table_name = 'Cloud_Agent_OnDutyHistory'  
  end
END  


GO

