CREATE  PROCEDURE [dbo].[SP_checksupport_onofff]      
(      
 @onduty int,      
 @userid bigint      
 )      
 as       
 begin      
 update User_Detail set onduty=@onduty where User_ID=@userid      
 update a set a.Active =  @onduty from Serv_Agent_Mast a inner join Serv_User_Detail b on a.userid = b.ser_user_id  
 where b.User_id = @userid  
update Serv_User_Detail set Status =  @onduty where User_id = @userid  
 select '1'      
 end     


