/* ============================================================
   Procedure: [dbo].[SP_DeleteImportedlist]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


    
CREATE PROCEDURE [dbo].[SP_DeleteImportedlist] --'1002'    
 @listid NVARCHAR(20)    
AS    
Begin    
    
DELETE FROM UserMailTemplate WHERE ListID = @listid    
    
update UserMailsFilters SET MappedList = 0 WHERE MappedList = @listid    
    
DELETE FROM UserImportedListColumn WHERE ID = @listid    
    
DELETE FROM UserSearchData WHERE ImportedListID = @listid    
    
IF EXISTS(SELECT 1 FROM UserCampaignMaster WHERE Applicabilty=@listid)    
begin    
update usercampaignmaster SET IsActive = 0, Applicabilty = '' WHERE Applicabilty = @listid     
END    
IF EXISTS(SELECT 1 FROM UserCampaignMaster WHERE @listid IN (SELECT VALUE from dbo.fn_Split(Applicabilty,'#')) AND Applicabilty <> @listid)    
BEGIN    
DECLARE @last NVARCHAR(20) = '#'+@listid    
DECLARE @begmid NVARCHAR(20) = @listid+'#'    
 IF EXISTS(SELECT 1 FROM UserCampaignMaster WHERE RIGHT(Applicabilty, LEN(@listid)+1)= @last)    
 Begin    
 UPDATE UserCampaignMaster SET applicabilty=REPLACE(Applicabilty,@last,'') WHERE RIGHT(Applicabilty, LEN(@listid)+1) = @last    
 END    
 ELSE    
    begin    
 UPDATE  UserCampaignMaster SET applicabilty=REPLACE(Applicabilty,@begmid,'') WHERE @listid IN (SELECT VALUE from dbo.fn_Split(Applicabilty,'#')) AND Applicabilty <> @listid    
 END    
    
END    
    
--delete from UserSearchList  where ID=@listid  
     
Select 'Success'    
    
End    








GO

