/* ============================================================
   Procedure: [dbo].[sp_edt_getInvoiceColumns]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE PROCEDURE [dbo].[sp_edt_getInvoiceColumns]
    @jsonData NVARCHAR(MAX)
AS
BEGIN
    SET NOCOUNT ON;

    BEGIN TRY
        IF ISJSON(@jsonData) = 0
            THROW 50001, 'Invalid JSON input', 1;

        DECLARE 
            @mode VARCHAR(100),
            @Id INT = NULL,
            @Name NVARCHAR(255),
            @Description NVARCHAR(MAX),
            @Quantity INT,
            @Price DECIMAL(18,2),
            @Total DECIMAL(18,2),
            @DiscountRate DECIMAL(5,2),
            @ItemHsnSacCode NVARCHAR(100),
            @ItemTax NVARCHAR(100),
            @ItemTaxAmount NVARCHAR(100),
            @parentId INT,
            @userId INT;

        -- Extract JSON parameters
        SELECT 
            @mode = Mode,
            @Id = SrNo,
            @Name = Name,
            @Description = Description,
            @Quantity = Quantity,
            @Price = Price,
            @Total = Total,
            @DiscountRate = DiscountRate,
            @ItemHsnSacCode = ItemHsnSacCode,
            @ItemTax = ItemTax,
            @ItemTaxAmount = ItemTaxAmount,
            @parentId = ParentId,
            @userId = UserId
        FROM OPENJSON(@jsonData)
        WITH (
            Mode VARCHAR(20) '$.mode',
            SrNo INT '$.srNo',
            ParentId INT '$.parentId',
            UserId INT '$.userId',
            Name NVARCHAR(255) '$.Name',
            Description NVARCHAR(MAX) '$.Description',
            Quantity INT '$.Quantity',
            Price DECIMAL(18,2) '$.Price',
            Total DECIMAL(18,2) '$.Total',
            DiscountRate DECIMAL(5,2) '$.DiscountRate',
            ItemHsnSacCode NVARCHAR(100) '$.ItemHsnSacCode',
            ItemTax NVARCHAR(100) '$.ItemTax',
            ItemTaxAmount NVARCHAR(100) '$.ItemTaxAmount'
        );

        -- Handle modes
        IF @mode = 'getcolumns'
        BEGIN
            SELECT (
                SELECT COLUMN_NAME
                FROM INFORMATION_SCHEMA.COLUMNS
                WHERE TABLE_NAME = 'tbl_testInvoice'
                AND COLUMN_NAME IN (
                    'Name', 'Description', 'Quantity', 'Price', 'Total',
                    'DiscountRate', 'ItemHsnSacCode', 'ItemTax', 'ItemTaxAmount'
                )
                FOR JSON PATH
            ) AS jsonResult;
        END

        ELSE IF @mode = 'invoice'
        BEGIN
            IF @Id IS NULL
            BEGIN
                SELECT (
                    SELECT 
                        Id AS srNo,
                        Name,
                        Description,
                        Quantity,
                        Price,
                        Total,
                        DiscountRate,
                        ItemHsnSacCode,
                        ItemTax,
                        ItemTaxAmount
                    FROM tbl_testInvoice
                    FOR JSON PATH, INCLUDE_NULL_VALUES
                ) AS jsonResult;
            END
            ELSE
            BEGIN
                SELECT (
                    SELECT 
                        Id AS srNo,
                        Name,
                        Description,
                        Quantity,
                        Price,
                        Total,
                        DiscountRate,
                        ItemHsnSacCode,
                        ItemTax,
                        ItemTaxAmount
                    FROM tbl_testInvoice
                    WHERE Id = @Id
                    FOR JSON PATH, INCLUDE_NULL_VALUES, WITHOUT_ARRAY_WRAPPER
                ) AS jsonResult;
            END
        END

        ELSE IF @mode = 'addinvoice'
        BEGIN
            INSERT INTO tbl_testInvoice (
                Name, Description, Quantity, Price, Total,
                DiscountRate, ItemHsnSacCode, ItemTax, ItemTaxAmount
            )
            VALUES (
                @Name, @Description, @Quantity, @Price, @Total,
                @DiscountRate, @ItemHsnSacCode, @ItemTax, @ItemTaxAmount
            );

            SELECT (
                SELECT 'success' AS status, 'Record inserted successfully' AS message
                FOR JSON PATH, WITHOUT_ARRAY_WRAPPER
            ) AS jsonResult;
        END

        ELSE IF @mode = 'saveconfig'
        BEGIN
            -- For future config saving
            INSERT INTO tbl_testInvoiceConfig (ParentId, UserId, ColumnName)
            VALUES (
                @parentId,
                @userId,
                JSON_QUERY(@jsonData, '$.config')
            );

            SELECT (
                SELECT 'success' AS status, 'Configuration saved successfully' AS message
                FOR JSON PATH, WITHOUT_ARRAY_WRAPPER
            ) AS jsonResult;
        END

    END TRY
    BEGIN CATCH
        SELECT (
            SELECT 
                'error' AS status,
                ERROR_MESSAGE() AS message,
                ERROR_NUMBER() AS errorCode,
                ERROR_SEVERITY() AS severity,
                ERROR_STATE() AS [state]
            FOR JSON PATH, WITHOUT_ARRAY_WRAPPER
        ) AS jsonResult;
    END CATCH
END





GO

/* ============================================================
   Procedure: [dbo].[sp_edt_InvoiceQuotationTemplatesAction]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

 CREATE  PROCEDURE [dbo].[sp_edt_InvoiceQuotationTemplatesAction]
    @jsonData NVARCHAR(MAX)
AS
BEGIN
--declare  @jsonData NVARCHAR(MAX)='{
--  "operation": "GET",
--  "parentId": 34594,
--  "templateId": null,
--  "templateType": "Invoice"
--}'
    SET NOCOUNT ON;
    
    DECLARE @operation VARCHAR(20) = JSON_VALUE(@jsonData, '$.operation');
    DECLARE @templateId INT = JSON_VALUE(@jsonData, '$.templateId');
    DECLARE @templateName VARCHAR(200) = JSON_VALUE(@jsonData, '$.templateName');
    DECLARE @parentId BIGINT = JSON_VALUE(@jsonData, '$.parentId');
    DECLARE @templateType VARCHAR(50) = JSON_VALUE(@jsonData, '$.templateType');
    DECLARE @createdBy BIGINT = JSON_VALUE(@jsonData, '$.createdBy');
    DECLARE @modifiedBy BIGINT = JSON_VALUE(@jsonData, '$.modifiedBy');
    DECLARE @isActive BIT = JSON_VALUE(@jsonData, '$.isActive');
    DECLARE @TemplateContent Nvarchar(max) = JSON_VALUE(@jsonData, '$.TemplateContent');

    
IF @operation = 'CREATE'
BEGIN
    IF EXISTS (
        SELECT 1
        FROM tbl_invoiceQuotationTemplateList
        WHERE templateName = @templateName AND parentId = @parentId
    )
    BEGIN
        SELECT (
            SELECT 'template Already exists' AS message
        FOR JSON PATH, INCLUDE_NULL_VALUES, WITHOUT_ARRAY_WRAPPER
        ) AS jsonResult;
    END
    ELSE
    BEGIN
        INSERT INTO tbl_invoiceQuotationTemplateList (
            templateName, parentId, templateType, TemplateContent, createdBy, isActive
        )
        VALUES (
            @templateName, @parentId, @templateType, @TemplateContent, @createdBy, ISNULL(@isActive, 1)
        );

        SELECT (
            SELECT SCOPE_IDENTITY() AS templateId
        FOR JSON PATH, INCLUDE_NULL_VALUES, WITHOUT_ARRAY_WRAPPER
        ) AS jsonResult;
    END
END

IF @operation = 'SETDEFAULT'
BEGIN
    UPDATE tbl_invoiceQuotationTemplateList
    SET isdefault = CASE 
                       WHEN templateId = @templateId THEN 1 
                       ELSE 0 
                   END
    WHERE parentId = @parentId AND templateType = @templateType;

    DECLARE @rc INT = @@ROWCOUNT;

    SELECT (
        SELECT @rc AS rowsAffected
        FOR JSON PATH, INCLUDE_NULL_VALUES, WITHOUT_ARRAY_WRAPPER
    ) AS jsonResult;
END


    
    ELSE IF @operation = 'GET'
	
	BEGIN

    IF @templateId IS NULL 
    BEGIN
        SELECT (
            SELECT 
                templateId,
                templateName,
				TemplateContent,
                parentId,
                templateType,
                createdBy,
                createdOn,
                modifiedBy,
                modifiedOn,
				isdefault,
                isActive
            FROM 
                tbl_invoiceQuotationTemplateList(nolock) 
            WHERE 
				 parentId = @parentId and isnull(isActive,0) = 1
        AND (@templateType IS NULL OR templateType = @templateType)

            ORDER BY 
                templateId desc
            FOR JSON PATH, INCLUDE_NULL_VALUES
        ) AS jsonResult;
    END
    ELSE
    BEGIN
        SELECT (
            SELECT 
                templateId,
                templateName,
				TemplateContent,
                parentId,
                templateType,
                createdBy,
                createdOn,
                modifiedBy,
                modifiedOn,
				isdefault,
                isActive
            FROM 
                tbl_invoiceQuotationTemplateList(nolock)
            WHERE 
                templateId = @templateId and parentId=@parentId
				--AND isActive = 1 
				order by templateId desc
            FOR JSON PATH, INCLUDE_NULL_VALUES, WITHOUT_ARRAY_WRAPPER
        ) AS jsonResult;
    END
	END
        ELSE IF @operation = 'GETAll'
	BEGIN
    IF @templateId IS NULL
    BEGIN
	print @parentId
        SELECT (
            SELECT 
                templateId,
                templateName,
				TemplateContent,
                parentId,
                templateType,
                createdBy,
                createdOn,
                modifiedBy,
                modifiedOn,
				isdefault, 
                isActive
            FROM 
                tbl_invoiceQuotationTemplateList(nolock) 
            WHERE   parentId=@parentId
				--isActive = 1 AND
    --            (@isActive IS NULL OR isActive = @isActive)
    --            AND (@templateType IS NULL OR templateType = @templateType)
            ORDER BY 
                templateId desc
            FOR JSON PATH, INCLUDE_NULL_VALUES
        ) AS jsonResult;
    END
    ELSE
    BEGIN
        SELECT (
            SELECT 
                templateId,
                templateName,
				TemplateContent,
                parentId,
                templateType,
                createdBy,
                createdOn,
                modifiedBy,
                modifiedOn,
				isdefault, 
                isActive
            FROM 
                tbl_invoiceQuotationTemplateList(nolock)
            WHERE  parentId=@parentId
    --            templateId = @templateId
				--AND isActive = 1 
				order by templateId desc
            FOR JSON PATH, INCLUDE_NULL_VALUES, WITHOUT_ARRAY_WRAPPER
        ) AS jsonResult;
    END
	END

	       ELSE IF @operation = 'Invactive'
	BEGIN
    IF @templateId IS NULL
    BEGIN
        SELECT (
            SELECT 
                templateId,
                templateName,
				TemplateContent,
                parentId,
                templateType,
                createdBy,
                createdOn,
                modifiedBy,
                modifiedOn,
                isActive
            FROM 
                tbl_invoiceQuotationTemplateList(nolock) 
            WHERE 
				isActive = 0 and parentId=@parentId
               ORDER BY 
                templateId desc
            FOR JSON PATH, INCLUDE_NULL_VALUES
        ) AS jsonResult;
    END
    ELSE
    BEGIN
        SELECT (
            SELECT 
                templateId,
                templateName,
				TemplateContent,
                parentId,
                templateType,
                createdBy,
                createdOn,
                modifiedBy,
                modifiedOn,
                isActive
            FROM 
                tbl_invoiceQuotationTemplateList
            WHERE 
                templateId = @templateId and parentId=@parentId
				AND isActive = 0 
				order by templateId desc
            FOR JSON PATH, INCLUDE_NULL_VALUES, WITHOUT_ARRAY_WRAPPER
        ) AS jsonResult;
    END
	END
ELSE IF @operation = 'UPDATE' 
BEGIN
    IF EXISTS (
        SELECT 1
        FROM tbl_invoiceQuotationTemplateList
        WHERE templateName = @templateName 
          AND parentId = @parentId
          AND templateId <> @templateId -- Exclude the current record
    )
    BEGIN
        SELECT (
            SELECT 'Template name Already exists' AS message
        FOR JSON PATH, INCLUDE_NULL_VALUES, WITHOUT_ARRAY_WRAPPER
        ) AS jsonResult;
    END
    ELSE
    BEGIN
        UPDATE tbl_invoiceQuotationTemplateList
        SET 
            templateName = ISNULL(@templateName, templateName),
            parentId = ISNULL(@parentId, parentId),
            templateType = ISNULL(@templateType, templateType),
            TemplateContent = ISNULL(@TemplateContent, TemplateContent),
            modifiedBy = @modifiedBy,
            modifiedOn = GETDATE(),
            isActive = ISNULL(@isActive, isActive)
        WHERE 
            templateId = @templateId;
            
        SELECT (
            SELECT @@ROWCOUNT AS rowsAffected
        FOR JSON PATH, INCLUDE_NULL_VALUES, WITHOUT_ARRAY_WRAPPER
        ) AS jsonResult;
    END
END

    ELSE IF @operation = 'DELETE'  
    BEGIN
     UPDATE tbl_invoiceQuotationTemplateList
SET 
    isActive = CASE 
                  WHEN isActive = 1 THEN 0 
                  ELSE 1 
               END,
    modifiedBy = @modifiedBy,
    modifiedOn = GETDATE()
WHERE 
    templateId = @templateId;

            
        SELECT (
            SELECT @@ROWCOUNT AS rowsAffected
            FOR JSON PATH, INCLUDE_NULL_VALUES, WITHOUT_ARRAY_WRAPPER
        ) AS jsonResult;
    END
END




