CREATE PROCEDURE [dbo].[SP_ImportPredefinedCampaignByID] --17626,1,17626    
@parentid  BIGINT, @acctused BIGINT  , @ID  INT  
AS    
BEGIN     
declare @campaignname nvarchar(100) =(select CampaignName from ImportPredefinedCampaign where ID=@ID)    
declare @campaignname1 table (campaignname nvarchar(100))    
insert into @campaignname1    
exec [GetNewName] @parentid,'usercampaignmaster','campaignname',@campaignname    
declare @NotificationMail nvarchar(200)= (select u.EMail from user_detail u where user_id=@acctused)    
declare @sender nvarchar(50) = (select top 1 Sender_Name from Default_SenderID where USER_ID=@acctused and sender_name<>'' order by datecreated desc)    
declare @newschedule bigint=null    
declare @newsearchid bigint=null    
declare @templateid bigint= (select templateid from ImportPredefinedCampaign where ID=@ID)    
declare @applicabilty bigint= (select Applicabilty from ImportPredefinedCampaign where ID=@ID and Applicabilty<>'')    
declare @schedule bigint=(select ScheduleID from ImportPredefinedCampaign where ID=@ID and ScheduleID<>0)    
create table #nextexecute(campaignid bigint,Nextdate datetime)    
if exists(select 'x' from ImportPredefinedCampaign where ID=@ID and iseventbased=0)    
begin    
insert into #nextexecute    
exec [usp_getNextScheduleDate] @id    
end    
declare @NextExecuteDateTime datetime = (select nextdate from #nextexecute)    
declare @searchname nvarchar(100)=(select searchname from ImportPreDefUserSearchList     
       WHERE  ID = @Applicabilty)    
--declare @templatetobecreated bit=0    
if @applicabilty is not null and (select ispredefined from ImportPreDefUserSearchList where ID = @Applicabilty)<>1      
begin    
           
declare @searchname1 table (searchname nvarchar(100))    
insert into @searchname1    
exec [GetNewName] @parentid,'usersearchlist','SearchName',@searchname     
    
INSERT into UserSearchList (ParentID, SearchName, SearchType, Medium, Source,    
       Campaign, SpecificName, SpecificAddress, SpecificMobileNo, SpecificEmail,    
       SpecificCity, SpecificState, SpecificCountry, CurrentlyAssignedTo,    
       FollowUpStatus, CreatedBetweenFrom, CreatedBetweenTo, NextFollowUpDateFrom,    
       NextFollowUpDateTo, NextFollowUpDaysFrom, NextFollowUpDaysTo,    
       ConvertedWithinFrom, ConvertedWithinTo, DataListName, TotalOrdersFrom,    
       TotalOrdersTo, TotalBusinessFrom, TotalBusinessTo, NameGRP, CompanyGRP,    
       MobileGRP, EmailGRP, CityGRP, StateGRP, CountryGRP, AddressGRP,    
       BirthBetweenFromGRP, BirthBetweenToGRP, ANVBetweenFromGRP, ANVBetweenToGRP,    
       CreatedBetweenFromGRP, CreatedBetweenToGRP, GroupsGRP, IsPredefined,    
       IsResponse, IsUnsubscribe, IsSearch, IsCustom, IsRestrictToConversionDate,    
       IsENQLeadCNV, IsGroup, CreatedOn, CreatedBy, ModifiedOn, ModifiedBy)    
SELECT @parentid, (select top 1 SearchName from @searchname1), SearchType, Medium, Source,    
       Campaign, SpecificName, SpecificAddress, SpecificMobileNo, SpecificEmail,    
       SpecificCity, SpecificState, SpecificCountry, CurrentlyAssignedTo,    
       FollowUpStatus, CreatedBetweenFrom, CreatedBetweenTo, NextFollowUpDateFrom,    
       NextFollowUpDateTo, NextFollowUpDaysFrom, NextFollowUpDaysTo,    
       ConvertedWithinFrom, ConvertedWithinTo, DataListName, TotalOrdersFrom,    
       TotalOrdersTo, TotalBusinessFrom, TotalBusinessTo, NameGRP, CompanyGRP,    
       MobileGRP, EmailGRP, CityGRP, StateGRP, CountryGRP, AddressGRP,    
       BirthBetweenFromGRP, BirthBetweenToGRP, ANVBetweenFromGRP, ANVBetweenToGRP,    
       CreatedBetweenFromGRP, CreatedBetweenToGRP, GroupsGRP, 1,    
       IsResponse, IsUnsubscribe, IsSearch, IsCustom, IsRestrictToConversionDate,    
       IsENQLeadCNV, IsGroup, GETDATE(), CreatedBy, ModifiedOn, ModifiedBy FROM ImportPreDefUserSearchList     
       WHERE  ID = @Applicabilty    
set @newsearchid=SCOPE_IDENTITY()    
end    
else    
begin    
set @newsearchid=(select Id from UserSearchList where parentid=@parentid and SearchName=@searchname)    
end    
    
if @schedule is not null    
begin    
declare @schedulename nvarchar(50) =(select [SceduleName] from PredefinedUserSchedules where ID=@schedule)    
declare @schedulename1 table (schedulename nvarchar(100))    
insert into @schedulename1    
exec [GetNewName] @parentid,'userschedules','SceduleName',@schedulename    
insert into UserSchedules ([ParentID],[SceduleName],    
 [IsOnce],    
 [OnceHours],    
 [OnceMins],    
 [IsDaily],    
 [DailyHours],    
 [DailyMins],    
 [IsWeekly],    
 [WeeklyDayNo],    
 [WeeklyHours],    
 [WeeklyMins],    
 [IsMonthly],    
 [MonthlyHours],    
 [MonthlyMins],    
 [MonthNo],    
 [MonthlyDayNo],    
 [IsActive],    
 [CreatedOn],    
 [CreatedBy],    
 [ModifiedOn],    
 [ModifiedBy])    
select @parentid,(select top 1 SceduleName from @schedulename1),    
 [IsOnce],    
 [OnceHours],    
 [OnceMins],    
 [IsDaily],    
 [DailyHours],    
 [DailyMins],    
 [IsWeekly],    
 [WeeklyDayNo],    
 [WeeklyHours],    
 [WeeklyMins],    
 [IsMonthly],    
 [MonthlyHours],    
 [MonthlyMins],    
 [MonthNo],    
 [MonthlyDayNo],    
 [IsActive],    
 GETDATE(),    
 @acctused,    
