 [ModifiedBy]    
 from PredefinedUserSchedules where ID=@schedule    
 set @newschedule=SCOPE_IDENTITY()    
end    
declare @newtemplateid bigint    
declare @templatename nvarchar(50)= (select name from [PredefinedUserMailTemplate] where ID=@templateid)    
declare @templatename1 table (templatename nvarchar(100))    
insert into @templatename1    
exec [GetNewName] @parentid,'usermailtemplate','Name',@templatename    
     
insert into UserMailTemplate([ParentID],    
 [Name],    
 [MailSubject],    
 [MailContent],    
 [CreatedOn],    
 [CreatedBy],    
 [IsSMS],    
 [IsMail],    
 [IsLeads],    
 [IsEnquiry],    
 [IsConversion],    
 [IsList],    
 [ListID],    
 [isGroup],    
