 from [PredefinedUserMailTemplate] where ID=@templateid    
set @newtemplateid = scope_identity()    
    
INSERT UserCampaignMaster(ParentID, CampaignName, IsEventBased,IsScheduled, Applicabilty, ExclusionsNumber,Exclusions, InclusionsNumber, AccountUsed, SenderID,     
[Message], TemplateID, TemplateGroupID, IsUnicode, MailReplyTo, MailSubject, MailContent, TrackResponse, TrackShortURL, UnsubscribePage, UnsubscribeShortURL,     
Tags, IsRunAfter, IsSchedule, ScheduleID, ExecutedDateTime, NextExecuteDateTime, IsActive,     
CreatedOn, CreatedBy, ModifiedOn, ModifiedBy, StartDate, ExpiryDate, EventsName, ApplicabiltyGroupList, ExclusionsGroupList, NotificationMail,     
SuccessNotificationEmail, FailureNotificationEmail, IsRecurring, IsEnding, TemplateGroupSequence, IsNeverExpire, RunAtHours, RunAtMin,     
IsSurplusExclusions)    
SELECT @parentid,(select top 1 CampaignName from @campaignname1), IsEventBased,IsScheduled, isnull(@newsearchid,''), ExclusionsNumber,Exclusions, InclusionsNumber, @acctused, @sender,     
[Message], @newtemplateid, TemplateGroupID, IsUnicode, MailReplyTo, MailSubject, MailContent, TrackResponse, TrackShortURL, UnsubscribePage, UnsubscribeShortURL,     
