GETDATE(), @acctused, ModifiedOn, ModifiedBy,GETDATE(), ExpiryDate, EventsName, ApplicabiltyGroupList, ExclusionsGroupList, @NotificationMail,    
@NotificationMail, @NotificationMail,  IsRecurring, IsEnding, TemplateGroupSequence, IsNeverExpire, RunAtHours, RunAtMin,     
IsSurplusExclusions    
FROM ImportPredefinedCampaign WHERE ID = @ID    
    
DECLARE @check Int = CASE WHEN @@ROWCOUNT = 0 THEN 0 ELSE 1 END    
SELECT @check    
           
END    


