/* ============================================================
   Procedure: [dbo].[SP_insert_Cloud_userkyc]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON



CREATE PROCEDURE SP_insert_Cloud_userkyc    
 (    
 @id int,    
 @parentd_id bigint,    
@MainDocID int,    
@MainDocSUBID int,    
 @DocPath varchar(500),    
 @Approved int,    
 @IsIndividual int,  
 @opt int    
     
    
     
 )    
 as    
 begin    
 if(@opt=1)    
 begin    
    
 if exists(select MainDocID from   Cloud_userkyc where MainDocID=@MainDocID and parentd_id=@parentd_id)    
     
 begin    
 declare  @idval int    
select @idval= id from   Cloud_userkyc where MainDocID=@MainDocID  and parentd_id=@parentd_id    
 update Cloud_userkyc set MainDocID= @MaindocID ,MainDocSUBID=@MainDocSUBID,DocPath=@DocPath,Approved=0,IsIndividual=@IsIndividual where id=@idval and parentd_id=@parentd_id    
  update Cloud_userkyc set IsIndividual=@IsIndividual where parentd_id=@parentd_id  
 select 2    
    
 end    
 else    
 begin    
 update Cloud_userkyc set IsIndividual=@IsIndividual where parentd_id=@parentd_id  
 insert into Cloud_userkyc(parentd_id,MainDocID,MainDocSUBID,DocPath,IsIndividual)values(@parentd_id,@MaindocID,@MainDocSUBID,    
 @DocPath,@IsIndividual)    
 select 1    
 end    
 end    
 if(@opt=2)    
 begin    
    
 select KD.Name as MainDocName,KS.name as MainDocSUBName,Uk.IsIndividual as IsIndividual,DocPath, CreatedDate, Approved,    
 parentd_id=(select User_Login from user_detail where USER_ID= @parentd_id)     
 from Cloud_userkyc UK     
 join Cloud_KYCDoc  KD on uk.MainDocID=KD.id    
 join Cloud_KYCSubDoc KS on uk.MainDocSUBID=KS.id     
 where  parentd_id=@parentd_id    
 end    
     
  if(@opt=8)    
 begin    
    
 select id,MainDocID,MainDocSUBID,DocPath,CreatedDate, Approved,parentd_id=(select User_Login from user_detail where USER_ID= 28214),IsIndividual from Cloud_userkyc where  parentd_id=28214    
     
    
 end    
  if(@opt=3)    
 begin    
    
 select uk.id,KD.Name as MainDocName,KS.name as MainDocSUBName,DocPath,CreatedDate,UD.User_Login as parentd_id ,Approved   from Cloud_userkyc UK     
 join Cloud_KYCDoc  KD on uk.MainDocID=KD.id    
 join Cloud_KYCSubDoc KS on uk.MainDocSUBID=KS.id  join  User_Detail UD on UD.User_ID=UK.parentd_id order by UK.id desc    
 end    
 if(@opt=4)    
 begin    
 update Cloud_userkyc set Approved=@Approved,CreatedDate=getdate() where id=@id    
 select 3    
 end    
 if(@opt=5)    
 begin    
 select * from Cloud_kycdoc where Isindividual=1    
    
 end    
     
 if(@opt=6)    
 begin    
 select id,name from Cloud_kycsubdoc where MainId=@MaindocID    
    
 end    
   if(@opt=7)    
 begin    
 select * from Cloud_kycdoc   
    
 end    
 end



GO

/* ============================================================
   Procedure: [dbo].[SP_insert_Credit_keyword_updateAdmin]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE PROC [dbo].[SP_insert_Credit_keyword_updateAdmin]  --10203,3560,1        
@m_id bigint,                            
@user_id bigint, -- change bigint to int by abhishek                            
@credits bigint,    
@validitynew bigint            
as                          
declare @credit bigint,@balanceN bigint,@default_credit bigint,@balance bigint,@rmid bigint,@validity bigint,@ruid bigint,@rbal bigint,@rcid bigint,@newvalidity bigint,@credit_idR bigint                  
  
select @rmid=m_id,@ruid=user_id from reseller_detail where reseller_id in (select m_id from reseller_detail where reseller_id=10203)          
select top 1 @credit=credits,@balance=balance,@validity=validity,@default_credit=default_credit,@credit_idR=credit_id from keyword_credit_details where m_id=@m_id and user_id=@user_id order by credit_id desc                      
set @balanceN=@credits+@balance      
set @default_credit=10      
--old validity            
set @newvalidity=@validitynew+@validity           
--end old validity            
if(@rbal<@credits)                    
begin                    
select 'Insufficient Balance'                    
end                    
else                    
begin             
         
insert into keyword_credit_details (m_id,user_id,credits,balance,validity,default_credit,FromDate,ToDate) values        
(@m_id,@user_id,@credits,@balanceN,@newvalidity,@default_credit,getdate(),getdate())                          
select 'SMS Credited Successfully'                    
end




GO

