CREATE PROCEDURE SP_kit19call_last_status  
as  
begin  
select dialstatus as Disposition from  
(  
select  row_number() over (partition by kcd.puniqueid order by kcd.call_end_time desc)   
as rn, KCD.dialstatus from kit19calls as LG(nolock) inner join Kit19CallsDialled as KCD(nolock) on  
KCD.puniqueid=lg.uniqueid    
)tt   
where rn=1  
end


