/* ============================================================
   Procedure: [dbo].[SP_Price_CheckUserPricingPlan]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--sp_helptext Price_InsertUserSubscriptionData                
                      
--**************************************                                
--***********History*****************                                
--Created By : Vivek Joshi , 10/12/2018                                 
--**************************************                                
CREATE PROCEDURE [dbo].[SP_Price_CheckUserPricingPlan]  --39680,26,19528                                    
@ParentID BIGINT,                                
@ModuleID nvarchar(100),                              
@MassLeadCount BIGINT = 0                                
   -- (-2) for do'nt have rights  message                                
AS                                 
DECLARE @PlanId int = 0 ,                                
        @countryId int=0 ,                                
  @getTotalCount int =0 ,                                    
  @setValue nvarchar(Max) = '',                                
  @setSubValue nvarchar(Max) = '',                                
  @result int = 1 -- output                                 
BEGIN                                     
    select @PlanId= PlanId from [dbo].[Price_UserSubscriptionDetails] where IsNewPlan=1 and UserID=@ParentID                                 
     set @countryId=0 --only for testing                                
   select @setValue=[value] from Price_ServiceCategoryLinkUserCopy where PlanId=@PlanId                                
     and countryid=@countryId and CategoryID=@ModuleID and Userid= @ParentID                             
   if @setValue = 1                              
      set @result= 1 --pass                                      
   else                              
   set @result = -2                               
IF @ModuleID = 1  --Lead Automation                              
    select @result               
ELSE IF @ModuleID = 2  -- Lead Management               
    select @result                         
ELSE IF @ModuleID = 26   -- No of Lead Management                              
  BEGIN                
   select @setValue=[value] from Price_ServiceCategoryLinkUserCopy where PlanId=@PlanId                                
     and countryid=@countryId and CategoryID=26 and UserId =  @ParentID                  
                                
 if @setValue = 0                                
    set @result = 0   --set @result = -2                                
 else                                
  BEGIN                                 
    select @getTotalCount=count(1) from UserLeads(nolock) where ParentID=@ParentID                               
      if @MassLeadCount <> 0                              
        set @getTotalCount=@getTotalCount+@MassLeadCount                              
                              
      select @setSubValue=[value] from Price_ServiceCategoryLinkUserCopy where PlanId=@PlanId                                
      and countryid=@countryId  and CategoryID=26 and UserId =  @ParentID                            
                                    
   if(@getTotalCount <= cast(@setSubValue as int))                                
     set @result = 0 -- set @result=@getTotalCount --pass                                
   else                                
     set @result = 0 -- set @result=-1 --fail                                
   END                                
 END         
 ELSE IF @ModuleID = 3 -- Eshop         
   select @result        
 ELSE IF @ModuleID = 33 -- Eshop product                               
    BEGIN                          
     
     --select @getTotalCount=count(1) from ProductMaster where UserID=@ParentID and IsPublished=1    
       
  exec Usp_createProductMasterTable @ParentID  
  Declare @Queryprdct nvarchar(max) = N' select @TempCount = count(1) from tbl_ProductMaster_'+ cast( @ParentID as nvarchar(max)) +'  where UserID='+ cast( @ParentID as nvarchar(max)) + ' and IsPublished = 1 '  
  exec sp_executesql @Queryprdct, N' @TempCount int out ', @getTotalCount out  
  
  
        
 select @setSubValue=[value] from Price_ServiceCategoryLinkUserCopy where PlanId=@PlanId                                
      and countryid=@countryId  and CategoryID=33                          
                             
    if(@getTotalCount < cast(@setSubValue as int))                                
          set @result=@getTotalCount --pass                                
       else                                
          set @result=-1 --fail                                
 END  --eshop end                                 
 ELSE IF @ModuleID = 4 -- ticket                               
 BEGIN                          
 --select @getTotalCount=count(1) from ProductMaster where UserID=@ParentID                               
 --select @setSubValue=[value] from Price_ServiceCategoryLinkUserCopy where PlanId=@PlanId               
 --    and countryid=@countryId  and CategoryID=33                              
                                    
 --  if(@getTotalCount < cast(@setValue as int))                                    
 --  set @result=@getTotalCount --pass                                
 --  else                                
 --     set @result=-1 --fail         
 select @result                              
 END   --Eshop End                      
 ELSE IF @ModuleID = 30 -- Landing Page                               
  BEGIN
  
   /* 
   select @getTotalCount=count(1) from ClientPageDetail where User_ID=@ParentID                               
   if(@getTotalCount < cast(@setValue as int))                                
      set @result=@getTotalCount --pass                                
   else                                
      set @result=-1 --fail             
       select @result 
   */
    set @result= 1
    select @result
	
 END   --landingpage End                       
 ELSE IF @ModuleID = 29 -- Webform Page                               
  BEGIN                          
   select @getTotalCount=count(1) from WebFormTbl where ParentId=@ParentID                         
   if(@getTotalCount < cast(@setValue as int))                                
      set @result=@getTotalCount --pass                                
   else                                
      set @result=-1 --fail                                
 END   --Webform End                      
                     
                                    
SELECT @result                                  
END 


GO

