/* ============================================================
   Procedure: [dbo].[SP_Search_LongCodeHit]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

/*
Author	: Abhishek Singh
Date	: 28-Oct-2013
Purchase: Searching All Longcode Mobile number with response
*/


CREATE PROCEDURE [dbo].[SP_Search_LongCodeHit] --'','Select','07/09/2013','10/21/2013',''	
	@Mobile varchar(10),
	@Catagory varchar(20),
	@SubKeyWord Varchar(50),
	@FromDate varchar(30),
	@ToDate varchar(30)
AS
	SET NOCOUNT ON
	if @Mobile =''
		set @Mobile = null
	if @Catagory ='Select'
		set @Catagory= null
	if @SubKeyWord =''
		set @SubKeyWord= null
	if @FromDate=''
		set @FromDate='01/01/1900'
	if @ToDate=''
		set @ToDate=1
	
if (@FromDate='01/01/1900')
begin
select LongCode_ID,Mobile,Category,SubKeyword,Convert(Varchar(10),Date,101)AS CDate,Convert(Varchar(10),Date,108)AS Time,Keyword, Message, Reply  FROM [MySMS].[dbo].[LongCodeHit](nolock) Where (Mobile = isnull(@Mobile,Mobile)) AND (Category =isnull(@Catagory,Category)) AND (SubKeyword like +isnull(@SubKeyWord,SubKeyword)+'%')  order by [date] desc
End
Else
BEGIN
select LongCode_ID,Mobile,Category,SubKeyword,Convert(Varchar(10),Date,101)AS CDate,Convert(Varchar(10),Date,108)AS Time ,Keyword, Message, Reply FROM [MySMS].[dbo].[LongCodeHit] (nolock) Where (Mobile = isnull(@Mobile,Mobile)) AND (Category =isnull(@Catagory,Category)) AND (SubKeyword like +isnull(@SubKeyWord,SubKeyword)+'%') AND [Date] between convert(datetime,@FromDate,103) and convert(datetime,@ToDate,103)+1 order by [date] desc
end

SET NOCOUNT off
RETURN

select * from [MySMS].[dbo].[LongCodeHit]



