/* ============================================================
   Procedure: [dbo].[spmove2another]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[spmove2another]  
as  
Begin  
INSERT INTO Messagequeuevoda(MessageID,Mobile,[Message],SenderID,SmppID,MessageInsertDate,priority,U_ID,IsUniCode,IsDND,Operator,BatchID,Isallowdnd)            
 SELECT Messageid, Mobile ,[Message],SenderID,smppid,MessageInsertDate,priority,U_ID,IsUniCode,0,IsNull(Operator,'UI'),BatchID,1           
 FROM Messagequeuefour where mobile in (select mobile from cno) or priority =2  
      
 delete FROM Messagequeuefour where mobile in (select mobile from cno) or priority =2  
  
INSERT INTO Messagequeueairteldirect(MessageID,Mobile,[Message],SenderID,SmppID,MessageInsertDate,priority,U_ID,IsUniCode,IsDND,Operator,BatchID,Isallowdnd)            
 SELECT Messageid, Mobile ,[Message],SenderID,smppid,MessageInsertDate,priority,U_ID,IsUniCode,0,IsNull(Operator,'UI'),BatchID,1           
 FROM Messagequeuefour where priority <>2  
      
 delete FROM Messagequeuefour where priority <>2  
  
INSERT INTO Messagequeueairteldirect(MessageID,Mobile,[Message],SenderID,SmppID,MessageInsertDate,priority,U_ID,IsUniCode,IsDND,Operator,BatchID,Isallowdnd)            
 SELECT Messageid, Mobile ,[Message],SenderID,smppid,MessageInsertDate,priority,U_ID,IsUniCode,0,IsNull(Operator,'UI'),BatchID,1           
 FROM Messagequeuethree  
      
 delete FROM Messagequeuethree  
  
  
INSERT INTO Messagequeuevoda(MessageID,Mobile,[Message],SenderID,SmppID,MessageInsertDate,priority,U_ID,IsUniCode,IsDND,Operator,BatchID,Isallowdnd)            
 SELECT Messageid, Mobile ,[Message],SenderID,smppid,MessageInsertDate,priority,U_ID,IsUniCode,0,IsNull(Operator,'UI'),BatchID,1           
 FROM Messagequeueairteldirect where mobile in (select mobile from cno)   
      
 delete FROM Messagequeueairteldirect where mobile in (select mobile from cno)   
  
End  
  
--update Messagequeueairteldirect set priority =2 where u_id = 335  
   


GO

/* ============================================================
   Procedure: [dbo].[spTodaysConsumption]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC spTodaysConsumption  
as  
Begin 
select message,count(u_id) as SMSsent,u_id,balance,user_login,userfilter from messagedeliverystatus M join credit_details C on M.u_id = C.user_id join user_detail U on U.user_id = M.u_id where C.credit_id in (select max(credit_id) from credit_details group by user_id) and u_id not in (16301,16300,364,17626,335,16343) group by u_id,balance,message,user_login,userfilter order by balance 
End


GO

