/* ============================================================
   Procedure: [dbo].[Support_SP_Adduser]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--exec Support_SP_Adduser @userid=37443,@parentid=32222,@Support_Access=2,@opt='Insert',@GroupID=343,@RoleID=349   
CREATE   PROCEDURE [dbo].[Support_SP_Adduser]    
(            
@userid bigint,            
@parentid bigint,       
@Support_Access int,      
@opt varchar(10),      
@GroupID bigint,      
@RoleID int            
)            
as            
BEGIN        
       
Declare @Access_level nvarchar(100), @email_id varchar(250), @ser_user_id bigint, @CompnayName as nvarchar(100)    
    
if @Support_Access = '0'      
begin      
set @Access_level = 'Self'      
end      
if @Support_Access = '1'      
begin      
set @Access_level = 'Within Group'      
end      
if @Support_Access = '2'      
begin      
set @Access_level = 'All Group'      
end      
      
 select @email_id=Email,@CompnayName=CompnayName from user_detail where  User_id = @userid    
      
if(@opt='Insert')            
BEGIN          
    
if not exists (select '*' from Serv_User_Detail where  (User_id = @userid or Email=@email_id) and ParentID = @parentid )      
BEGIN             
insert into Serv_User_Detail(ParentId, User_id,Name, Login_id, Pwd,  Mobile,    
Email, Company, Country, City, State, Address, Zip, Status,user_id_old)                                 
select ParentId,user_id, FName+','+LName, User_Login,                                 
Pwd, CONVERT(varchar(20), Cast(Mobile as BigInt)) Mobile,      
EMail, CompnayName,Country,  City, State,  Address ,  Pincode, 1, @userid                               
from user_detail where  User_id = @userid and ParentID = @parentid           
  
Exec usp_tp_CreateInternalUser @parentid, @userid  
  
END      
    
set @ser_user_id=SCOPE_IDENTITY()    
      
UPDATE User_Detail      
set Support_Access = 1      
where User_ID = @userid      
      
      
UPDATE Serv_User_Detail SET user_id = @ser_user_id where ser_user_id =@ser_user_id      
          
if not exists (select '*' from Serv_User_Master where ParentID = @parentid and kit19_id = @userid and Service_id = @ser_user_id  )      
BEGIN           
insert into Serv_User_Master (ParentID,Email_id,Service_User,Service_id,kit19_id, kit19_User )       
Values (@parentid, @email_id, 1 ,@ser_user_id, @userid, 1)        
END    
    
if( not exists (select 'x' from Serv_Agent_Mast where ParentId = @ParentID and UserID = @UserID and Group_ID = @GroupID ))                      
Begin    
     insert into Serv_Agent_Mast(ParentID,UserID,Active,Group_ID,Internal,Access_level,RoleId,user_id_old)    
     values(@ParentID,@ser_user_id,1,@GroupID,1,@Access_level,@RoleID,@UserID)        
end      
    
  if(not exists(select 1 from usersourcesettings with(nolock) where name = 'ServiceTicketSignup' and userid = @ParentID ))
  begin
	  INSERT INTO UserSourceSettings                              
		 (NAME, UserID, IsEditable,IsActive,CreatedDate,ModifiedDate,ModifiedBy )                              
	   VALUES                              
		 ('ServiceTicketSignup', @ParentID, 0, 1, GETDATE(), GETDATE(), @ParentID)                         
                        
   end
   
   exec Serv_DefaultEntryCreation_support @ParentID, @ser_user_id, @CompnayName                        
                         
 select 'Record Saved'                        
         
END       
    
if(@opt='Update')            
begin         
 UPDATE Serv_User_Detail      
 SET Status = 0      
 where  user_id_old = @userid and ParentID = @parentid       
      
 UPDATE User_Detail      
 set Support_Access = 0      
 where User_ID = @userid      
END         
    
END            


GO

/* ============================================================
   Procedure: [dbo].[Support_User_masterUpdate]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Support_User_masterUpdate]                      
(                        
@uid bigint,      
@Active bit                  
)                        
as                        
begin           
 declare @id  bigint   
 update User_Detail
 set Support_Access = @Active where      USER_ID = @uid           
  Update Serv_User_Detail      
  set [Status] =@Active where USER_ID = @uid    
  Update a      
  set Active =@Active from Serv_Agent_Mast a inner join Serv_User_Detail b  
  on a.Userid = b.ser_user_id  
  where b.USER_ID = @uid         
end 



GO

/* ============================================================
   Procedure: [dbo].[support_User_role_edit]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.support_User_role_edit (
	@userid BIGINT
	,@Cloudrole VARCHAR(50)
	)
AS
BEGIN
	UPDATE a
	SET a.RoleId = @Cloudrole
	FROM serv_agent_mast a(NOLOCK)
	INNER JOIN Serv_User_Detail b(NOLOCK) ON a.Userid = b.ser_user_id
		AND b.ParentId = a.ParentId
	WHERE b.User_id_old = @userid

	DECLARE @rowJson NVARCHAR(MAX) = (
			SELECT *
			FROM serv_agent_mast WITH (NOLOCK)
			WHERE RoleId = @Cloudrole
			FOR JSON AUTO
				,INCLUDE_NULL_VALUES
			)

	EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @userid
		,@Activity_type = 'Updt_Spprt_usrrol'
		,@ActionType = 'U'
		,@RowJson = @rowJson
		,@Table_name = 'serv_agent_mast'
END



