CREATE   PROCEDURE tbl_ai_GetOutboxPayloadByIds(
	@queueIds nvarchar(max)
)
as
begin

	--declare  @queueIds nvarchar(max) = '12,13,14'


	drop table if exists #queueIds
	create table #queueIds (
		queueId bigint
	)

	insert into #queueIds( queueId )
	select [value] from string_split(@queueIds, ',') where isnull([value], '') <> ''

	select id, payload from tbl_ai_agent_execution_outbox with (nolock) 
		where id in ( select queueId from #queueIds )

end



