/* ============================================================
   Procedure: [dbo].[tbl_et_UpdateDistanceCalculationsDateWise]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[tbl_et_UpdateDistanceCalculationsDateWise](
	@UserId bigint,
	@CurrentDateTime date
)
as
begin
	--declare
	--	@UserId bigint = 43754,
	--	@CurrentDateTime date = cast(getdate() as date)

drop table if exists #userLoctionTracking

select UserLocationTrackingId, UserId, LocationDateTime, MovementCode, 
	cast(Latitude as float) as Latitude, 
	cast(Longitude as float) as Longitude, Distance into #userLoctionTracking
	from TBL_ET_UserLocationTracking(nolock) where UserId = @UserId and cast(LocationDateTime as date) = @CurrentDateTime
		and isnull([Address], '') <> ''

drop table if exists #temp
create table #temp(UserLocationTrackingId bigint, locationdatetime datetime,movementcode nvarchar(50),latitide float,longitude float,cumulativedistance float)

DECLARE @lastNonZeroLat float = NULL;
DECLARE @lastNonZeroLon float = NULL;
DECLARE @lastCumulativeDistance float = 0;
DECLARE @UserLocationTrackingId bigint = 0;
DECLARE @LocationDateTime DATETIME;
DECLARE @MovementCode VARCHAR(50);
DECLARE @Latitude float;
DECLARE @Longitude float;
DECLARE @prevLat float;
DECLARE @prevLon float;

--DECLARE location_cursor CURSOR FOR
--    SELECT LocationDateTime, MovementCode, Latitude, Longitude, 
--           LAG(Latitude) OVER (ORDER BY LocationDateTime) AS prevLat,
--           LAG(Longitude) OVER (ORDER BY LocationDateTime) AS prevLon
--    FROM tempLocationDataTest;

DECLARE location_cursor CURSOR FOR
    SELECT UserLocationTrackingId, LocationDateTime, MovementCode, Latitude, Longitude, 
           LAG(Latitude) OVER (ORDER BY LocationDateTime) AS prevLat,
           LAG(Longitude) OVER (ORDER BY LocationDateTime) AS prevLon
    FROM #userLoctionTracking

OPEN location_cursor;
FETCH NEXT FROM location_cursor INTO @UserLocationTrackingId, @LocationDateTime, @MovementCode, @Latitude, @Longitude, @prevLat, @prevLon;

WHILE @@FETCH_STATUS = 0
BEGIN
    IF @Latitude = 0 AND @Longitude = 0
    BEGIN
        declare @a int-- Do nothing, keep the previous cumulative distance
    END
    ELSE IF @prevLat IS NULL
    BEGIN
        SET @lastNonZeroLat = @Latitude;
        SET @lastNonZeroLon = @Longitude;
        SET @lastCumulativeDistance = 0;
    END
    ELSE IF @prevLat = 0 AND @prevLon = 0
    BEGIN
        IF @Latitude <> @lastNonZeroLat OR @Longitude <> @lastNonZeroLon
        BEGIN
            SET @lastCumulativeDistance = @lastCumulativeDistance +  geography::Point(@lastNonZeroLat, @lastNonZeroLon, 4326).STDistance(geography::Point(@Latitude, @Longitude, 4326));
        END
    END
    ELSE
    BEGIN
        SET @lastCumulativeDistance = @lastCumulativeDistance + geography::Point(@prevLat, @prevLon, 4326).STDistance(geography::Point(@Latitude, @Longitude, 4326));
        SET @lastNonZeroLat = @Latitude;
        SET @lastNonZeroLon = @Longitude;
    END

    -- Output the result
    --PRINT CONVERT(VARCHAR(23), @LocationDateTime, 121) + ', ' + @MovementCode + ', ' + CONVERT(VARCHAR(50), @Latitude) + ', ' + CONVERT(VARCHAR(50), @Longitude) + ', ' + CONVERT(VARCHAR(50), @lastCumulativeDistance);
	insert into #temp(UserLocationTrackingId, locationdatetime,movementcode,latitide,longitude,cumulativedistance)
	select @UserLocationTrackingId, CONVERT(VARCHAR(23), @LocationDateTime, 121) LocationDateTime, @MovementCode MovementCode, 
	CONVERT(float, @Latitude) Latitude, 
	CONVERT(float, @Longitude)Longitude, 
	CONVERT(float, @lastCumulativeDistance) CumulativeDistance;
    FETCH NEXT FROM location_cursor INTO @UserLocationTrackingId, @LocationDateTime, @MovementCode, @Latitude, @Longitude, @prevLat, @prevLon;
END

CLOSE location_cursor;
DEALLOCATE location_cursor;

--select * from #temp t

update u set u.Distance = t.CumulativeDistance from #temp t
	inner join TBL_ET_UserLocationTracking(nolock)  u on  t.UserLocationTrackingId = u.UserLocationTrackingId

end



GO

