/* ============================================================
   Procedure: [dbo].[tbl_obd_GetBatchMobileNos]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[tbl_obd_GetBatchMobileNos](  
	@BatchId bigint,  
	@ServiceType nvarchar(5) = null,
	@OffsetValue int = 0,  
	@PagingSize int  = 10  
)  
as  
begin  

	--declare 
	--	@BatchId bigint = 29,  
	--	@ServiceType nvarchar(5) = 'IVR',
	--	@OffsetValue int = 100,  
	--	@PagingSize int  = 100  
	
	if(isnull(@ServiceType, '') = '')
	begin
		set @ServiceType = 'OBD'
	end

	if(@ServiceType = 'OBD')
	begin
		select count(ObdId) over() as TotalRow, ObdId, 
			MobileNo, CallerID, isnull(CallStatus, 'Submitted') as CallStatus, 
			ScheduleDate, DTMFPressTime, DTMFKeyPress, CallStartTime, CallEndTime
		from tbl_obd_ScheduleRecord(nolock) where BatchId = @BatchId  
		order by BatchId desc offset @OffsetValue rows fetch next @PagingSize rows only  
	end

	if(@ServiceType = 'IVR')
	begin
		select count(Id) over() as TotalRow, Id as [ObdId], 
			MobileNo, CallerID, isnull(CallStatus, 'Submitted') as CallStatus, 
			ScheduleDate, DTMFPressTime, DTMFKeyPress, CallStartTime, CallEndTime
		from tbl_obd_IvrDesignDataContact(nolock) where IvrDesignId = @BatchId  
		order by IvrDesignId desc offset @OffsetValue rows fetch next @PagingSize rows only  
	end

end  



GO

