/* ============================================================
   Procedure: [dbo].[udf_GetAgentToAssigned]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[udf_GetAgentToAssigned](    
 @ParentId bigint,    
 @AgentId bigint output    
)    
as    
begin    
	
	
	--declare @ParentId bigint = 48827    -- 48827
	
	declare @tempAgentTable as table(    
		id int identity(1, 1),    
		AgentId bigint    
	)    
    
	insert into @tempAgentTable( AgentId  ) 
	SELECT VALUE FROM fn_Split( (SELECT agents FROM CRMCampaignSettings WHERE userid=@ParentId),'#')   
	
	delete from @tempAgentTable where AgentId in ( select User_ID from User_Detail(nolock) where ParentId = @ParentId and status = 0)
    
	declare @AgentCount int = ( select count(1)  from @tempAgentTable )    
	declare @SelectedAgent bigint = @ParentId    
    
	if( @AgentCount > 0)    
	begin    
	declare @LastAgentId  bigint =  (SELECT top 1 LastUserAssigned FROM CRMCampaignSettings WHERE userid= @ParentId )    
	declare @LastSrNo  int = ( select top 1 (id + 1) from @tempAgentTable where AgentId = @LastAgentId )    
	if( not exists(select 1 from @tempAgentTable where AgentId = @LastAgentId))   
		begin  
		set  @LastSrNo = 1  
	end  
    
	select top 1 @SelectedAgent = AgentId from @tempAgentTable where id = case when ( @LastSrNo % @AgentCount) =  0      
	then @AgentCount else @LastSrNo % @AgentCount end     
    
	update CRMCampaignSettings set LastUserAssigned = @SelectedAgent where UserID = @ParentId    
	end 
	
	--select @SelectedAgent  

	select @AgentId = @SelectedAgent  
	
end 


GO

/* ============================================================
   Procedure: [dbo].[udp_pt_GetDomainStatus]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

----------------------------------------------------------------------
CREATE   PROCEDURE dbo.udp_pt_GetDomainStatus  -- latest running
    @CRMDomainName NVARCHAR(200)='',
    @TDomainName NVARCHAR(200)='',
    @MDomainName NVARCHAR(200)='',
    @UserID BIGINT
AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @CRMStatus NVARCHAR(50) = '0';
    DECLARE @TStatus NVARCHAR(50) = '0';
    DECLARE @MStatus NVARCHAR(50) = '0';

    BEGIN TRY
        -- Check CRM Domain
        IF EXISTS (
            SELECT 1
            FROM tbl_pt_DomainVerification WITH (NOLOCK)
            WHERE domain = @CRMDomainName
              AND userid = @UserID
        )
        BEGIN
            SELECT @CRMStatus = CASE 
                                   WHEN isverified = 1 THEN 1 
                                   ELSE 0
                               END
            FROM tbl_pt_DomainVerification WITH (NOLOCK)
            WHERE domain = @CRMDomainName
              AND userid = @UserID;
        END

        -- Check T Domain
        IF EXISTS (
            SELECT 1
            FROM tbl_pt_DomainVerification WITH (NOLOCK)
            WHERE domain = @TDomainName
              AND userid = @UserID
        )
        BEGIN
            SELECT @TStatus = CASE 
                                  WHEN isverified = 1 THEN 1
                                  ELSE 0
                              END
            FROM tbl_pt_DomainVerification WITH (NOLOCK)
            WHERE domain = @TDomainName
              AND userid = @UserID;
        END

        -- Check M Domain
        IF EXISTS (
            SELECT 1
            FROM tbl_pt_DomainVerification WITH (NOLOCK)
            WHERE domain = @MDomainName
              AND userid = @UserID
        )
        BEGIN
            SELECT @MStatus = CASE 
                                  WHEN isverified = 1 THEN 1 
                                  ELSE 0 
                              END
            FROM tbl_pt_DomainVerification WITH (NOLOCK)
            WHERE domain = @MDomainName
              AND userid = @UserID;
        END

        -- Return the statuses in a single row
        SELECT @CRMStatus AS CRMStatus, 
               @TStatus AS TStatus, 
               @MStatus AS MStatus;
    END TRY
    BEGIN CATCH
        EXEC usp_InsertErrorInfo;
    END CATCH
END;



GO

/* ============================================================
   Procedure: [dbo].[udp_pt_GetyDomainStatus]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


---------------------------------------------


CREATE   PROCEDURE dbo.udp_pt_GetyDomainStatus
    @DomainName NVARCHAR(200),
    @UserID BIGINT
AS
BEGIN
    SET NOCOUNT ON;
    
    BEGIN TRY
        -- Check if any record exists for the given domain, user ID, and isverified = 0
        IF EXISTS (
            SELECT 1
            FROM tbl_pt_DomainVerification
            WHERE domain = @DomainName
              AND userid = @UserID
              --AND isverified = 0
        )
        BEGIN
            -- If a record exists, retrieve the record_value
            SELECT isverified
            FROM tbl_pt_DomainVerification with(nolock)
            WHERE domain = @DomainName
              AND userid = @UserID
        END
        ELSE
        BEGIN
            -- If no record exists, return a status message
            SELECT 'No record found' AS StatusMessage;
        END
    END TRY
    BEGIN CATCH
       EXEC usp_InsertErrorInfo;
    END CATCH
END



GO

/* ============================================================
   Procedure: [dbo].[uid]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE uid
as
begin
SET NOCOUNT ON;
declare @rt varchar(5);
declare @ct int;
declare @cnt int;
set @cnt=0;
select num into #target from un_number;
select TextData into #source from tbl_StringAllCombinations;
with cte as
(
  SELECT distinct a.TextData as p
FROM #source a
join #source b on b.TextData in (a.TextData)
union all
SELECT distinct a.TextData as p
FROM #source a
join #source b on b.TextData not in (a.TextData)
)
select top(1) p into #temp1 from cte where p not in (select num from #target) order by p asc
select @ct=COUNT (p) from #temp1
if(@ct > 0)
begin
   select @rt= p from #temp1
   drop table #temp1
   set @cnt=1
end
 
if(@cnt=0)
begin
drop table #temp1;
with cte as
(
  SELECT distinct a.TextData+b.TextData as p
FROM #source a
join #source b on b.TextData in (a.TextData)
join #source c on c.TextData in (a.TextData, b.TextData)
union all
SELECT distinct a.TextData+b.TextData as p 
FROM #source a
join #source b on b.TextData not in (a.TextData)
join #source c on c.TextData not in (a.TextData, b.TextData)
)
select top(1) p into #temp2 from cte where p not in (select num from #target) order by p asc;
select @ct=COUNT (p) from #temp2;
if(@ct > 0)
begin
   select @rt= p from #temp2;
   drop table #temp2;
   set @cnt=1;
end
end
  if(@cnt=0)
  begin
  drop table #temp2;
with cte as
(
  SELECT distinct a.TextData+b.TextData+c.TextData as p
FROM #source a
join #source b on b.TextData in (a.TextData)
join #source c on c.TextData in (a.TextData, b.TextData)
join #source d on d.TextData in (a.TextData, b.TextData, c.TextData)
union all
SELECT distinct a.TextData+b.TextData+c.TextData as p
FROM #source a
join #source b on b.TextData not in (a.TextData)
join #source c on c.TextData not in (a.TextData, b.TextData)
join #source d on d.TextData not in (a.TextData, b.TextData, c.TextData)
 
)
select top(1) p into #temp3 from cte where p not in (select num from #target) order by p asc;
select @ct=COUNT (p) from #temp3;
if(@ct > 0)
begin
   select @rt= p from #temp3;
   drop table #temp3;
   set @cnt=1;
end
end
 
 if(@cnt=0)
  begin
  drop table #temp3;
with cte as
(
  SELECT distinct a.TextData+b.TextData+c.TextData+d.TextData as p
FROM #source a
join #source b on b.TextData in (a.TextData)
join #source c on c.TextData in (a.TextData, b.TextData)
join #source d on d.TextData in (a.TextData, b.TextData, c.TextData)
join #source e on e.TextData in (a.TextData, b.TextData, c.TextData, d.TextData)
union all
SELECT distinct a.TextData+b.TextData+c.TextData+d.TextData as p
FROM #source a
join #source b on b.TextData not in (a.TextData)
join #source c on c.TextData not in (a.TextData, b.TextData)
join #source d on d.TextData not in (a.TextData, b.TextData, c.TextData)
join #source e on e.TextData not in (a.TextData, b.TextData, c.TextData, d.TextData)
)
select top(1) p into #temp4 from cte where p not in (select num from #target) order by p asc;
select @ct=COUNT (p) from #temp4;
if(@ct > 0)
begin
   select @rt= p from #temp4;
   drop table #temp4;
   set @cnt=1;
end
end
 
if(@cnt=0)
  begin
  drop table #temp4;
with cte as
(
  SELECT distinct a.TextData+b.TextData+c.TextData+d.TextData+e.TextData as p
FROM #source a
join #source b on b.TextData in (a.TextData)
join #source c on c.TextData in (a.TextData, b.TextData)
join #source d on d.TextData in (a.TextData, b.TextData, c.TextData)
join #source e on e.TextData in (a.TextData, b.TextData, c.TextData, d.TextData)
join #source f on f.TextData in (a.TextData, b.TextData, c.TextData, d.TextData, e.TextData)
union all
SELECT distinct a.TextData+b.TextData+c.TextData+d.TextData+e.TextData as p
FROM #source a
join #source b on b.TextData not in (a.TextData)
join #source c on c.TextData not in (a.TextData, b.TextData)
join #source d on d.TextData not in (a.TextData, b.TextData, c.TextData)
join #source e on e.TextData not in (a.TextData, b.TextData, c.TextData, d.TextData)
join #source f on f.TextData not in (a.TextData, b.TextData, c.TextData, d.TextData, e.TextData)
)
select top(1) p into #temp5 from cte where p not in (select num from #target) order by p asc;
select @ct=COUNT (p) from #temp5;
if(@ct > 0)
begin
   select @rt= p from #temp5;
   drop table #temp5;
   set @cnt=1;
end
drop table #temp5;
end
drop table #source;
drop table #target;
print @rt;
end


GO

/* ============================================================
   Procedure: [dbo].[up_updtins_source]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON



CREATE   PROC up_updtins_source
(
@ParentID Bigint, --pass userid here          
@C_uid Bigint,                               
@FormId Bigint,        
@PageName varchar(200)                                  
--@SmsMessage nvarchar(200),                              
--@IsUniCode bit,                              
--@EmailReplyTo nvarchar(100),                              
--@EmailSubject nvarchar(100),                              
--@EmailMessgae nvarchar(200),                              
--@SmsSenderName nvarchar(100),                              
--@IsSms bit,                               
--@IsEmail bit,                            
--@SmsAccountName nvarchar(100),                            
--@EmailAccountName nvarchar(100),              
--@SMStemplateid bigint,              
--@Mailtemplateid bigint,        
--@webform varchar(10)=''        
)
as
 begin 
-----------------------
declare @namesource nvarchar(100)='Landing Page'          ----Changes by Sanjeeva        
     set @namesource ='WebForm Page' +@PageName        
declare @sourceId bigint                                   
IF NOT EXISTS (                                    
        SELECT 'x'                                    
        FROM   UserSourceSettings AS uss                    
        WHERE  uss.UserID = @C_uid                                 
        and Name =@namesource                                 
    )                                
 begin          
       INSERT INTO UserSourceSettings                                    
       (                                    
         -- SourceID -- this column value is auto-generated                                    
         NAME,                                    
         UserID,                                 
         IsEditable,                                    
         IsActive,                                    
         CreatedDate,                                    
         ModifiedDate,                                    
         ModifiedBy                                    
       )                                    
     VALUES                                    
       (                                    
      @namesource,                                    
         @C_uid,                                    
         0,                                    
         1,                                    
         GETDATE(),                                    
         GETDATE(),                                    
         @parentid                                    
       )                             
 select  @sourceId = SCOPE_IDENTITY()    
END                              
 else              
 begin              
 select  @sourceId = sourceid                                    
        FROM   UserSourceSettings AS uss                       
        WHERE  uss.UserID = @C_uid                                 
         and Name =@namesource              
 end 
 update  dbo.WebFormTbl set sourceid= @sourceId where FormId = @FormId
 
end



