/* ============================================================
   Procedure: [dbo].[Ups_ApiCustomFieldMapping]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

          
              
CREATE   PROCEDURE [dbo].[Ups_ApiCustomFieldMapping]              
              
              
@fieldjson nvarchar(max) = '',              
@ApiName nvarchar(max) ,              
@apikey nvarchar(max)=null,              
@createdOn DATETIME = NULL,              
@createdBy BIGINT = NULL,              
@userId BIGINT,              
@mode varchar(10)              
              
AS              
BEGIN              
              
 declare @id int = 0 ,@count int =0 , @rowid int=0, @fieldid bigint =0, @ctrlname varchar(max) ='', @ctrltype varchar(max)=''               
 declare @parentid bigint = 0, @ModifiedBy bigint=null, @ModifiedON datetime=null;              
              
 set @parentid = (select parentid from User_Detail (nolock) where user_id =@userId)              
              
 set @createdOn=GETDATE()              
 set @createdBy=@userId              
               
 drop table if exists #temp              
              
 create Table #temp              
 (              
  rowid int identity(1,1),              
  FieldId Varchar(max) ,              
  Field_Name Varchar(max) ,              
  ApiLeadField Varchar(max),          
  Maptype varchar(max),          
  iscust bit          
 )              
            
              
 IF @mode='Save'              
 BEGIN              
  SELECT @ModifiedON=CreatedOn,@ModifiedBy=CreatedBY FROM tbl_ApiCustomFieldMapping (nolock)WHERE ApiName=@ApiName and ParentId=@parentId               
  IF @ModifiedON is not null              
  BEGIN              
   DELETE FROM tbl_ApiCustomFieldMapping where  ParentId=@parentId and ApiName=@ApiName and ApiKey=@apikey              
   Select @createdOn=@ModifiedON,@createdBy=@ModifiedBy              
   Select @ModifiedON=GETDATE(),@ModifiedBy=@userId              
  END              
              
  insert into #temp (FieldId, Field_Name, ApiLeadField,Iscust)              
  SELECT FieldId, Field_Name, ApiLeadField ,Iscust             
  from OPENJSON (@fieldjson)              
  WITH               
  (              
   FieldId varchar(max) '$.custFieldId',              
   Field_Name Varchar(max) '$.custFieldName',              
   ApiLeadField Varchar(max) '$.LeadName',             
   Iscust bit '$.iscust'          
  )               
              
   INSERT INTO tbl_ApiCustomFieldMapping (Field_id, Field_Name, ApileadField, ApiName, ApiKey, ParentId, CreatedOn, CreatedBY,ModifiedON,ModifiedBy,iscustom)              
   SELECT FieldId, Field_Name, ApiLeadField,@ApiName, @apikey, @parentId, @createdOn,@createdBy,@ModifiedON,@ModifiedBy,Iscust              
   From #temp              
              
   Select 'Data Inserted'              
 END              
          
 ELSE IF @mode='Select'              
 BEGIN              
  if @apiName='IndiaMart'                  
 begin                  
 insert into #temp (FieldId, Field_Name, ApiLeadField,Maptype)          
  select COLUMN_NAME as ID,            
  CASE          
  WHEN COLUMN_NAME ='SENDERNAME'          
  THEN 'PersonName'          
  WHEN COLUMN_NAME ='mob'          
  THEN 'MobileNo'          
  WHEN COLUMN_NAME ='senderemail'          
  THEN 'EmailID'          
  WHEN COLUMN_NAME ='mobile_alt'          
  THEN 'MobileNo1'          
  WHEN COLUMN_NAME ='EMAIL_ALT'          
  THEN 'EmailID1'          
  WHEN COLUMN_NAME ='GLUSR_USR_COMPANYNAME'          
  THEN 'CompanyName'          
  WHEN COLUMN_NAME ='ENQ_ADDRESS'          
  THEN 'OfficeAddress'          
  WHEN COLUMN_NAME ='ENQ_ADDRESS'          
  THEN 'ResidentialAddress'          
   WHEN COLUMN_NAME ='ENQ_CITY'          
  THEN 'City'          
   WHEN COLUMN_NAME ='ENQ_State'          
  THEN 'State'          
   WHEN COLUMN_NAME ='COUNTRY_ISO'          
  THEN 'Country_Name'          
  END  Pre_mapped,COLUMN_NAME,          
  'PreMap' as Maptype           
            
  from INFORMATION_SCHEMA.COLUMNS where TABLE_NAME='IndiamartLeads' and TABLE_CATALOG=db_name() and COLUMN_NAME not in                       
  ('Id', 'INDIAMARTKEY', 'DateReceived', 'QUERY_ID', 'QTYPE', 'isprocessed','Processederror','Processeddate','Enquiryid','isvalid',          
  'PRODUCT_NAME','ENQ_MESSAGE','DATE_R','DATE_TIME_RE','LOG_TIME','ENQ_CALL_DURATION','ENQ_RECEIVER_MOB', 'PHONE', 'PHONE_ALT', 'SUBJECT','i_createddate'          
  )                       
 end                  
                  
 if @apiName='JustDial'                  
 begin           
 insert into #temp (FieldId, Field_Name, ApiLeadField,Maptype)          
  select COLUMN_NAME as Field_id,            
  CASE          
  WHEN COLUMN_NAME ='Name'          
  THEN 'PersonName'          
  WHEN COLUMN_NAME ='mobile'          
  THEN 'MobileNo'          
  WHEN COLUMN_NAME ='email'          
  THEN 'EmailID'          
  WHEN COLUMN_NAME ='City'          
  THEN 'City'          
  WHEN COLUMN_NAME ='pincode'          
  THEN 'PinCode'          
  END  ApileadField, COLUMN_NAME,          
  'PreMap' as Maptype          
  from INFORMATION_SCHEMA.COLUMNS  jd where TABLE_NAME='JustdialLeads' and TABLE_CATALOG=DB_NAME() and COLUMN_NAME not in                       
  ('id','DateReceived','leadid', 'leadtype', 'prefix', 'isprocessed', 'Processederror','Processeddate','Enquiryid','isvalid', 'date','phone', 'category',          
 'Area', 'brancharea', 'dncmobile', 'dncphone', 'company', 'jdparentid','ndate','ntime' ,'time','branchpin')                    
 end                  
                  
 if @apiName='TradeIndia'                  
 begin                  
 insert into #temp (FieldId, Field_Name, ApiLeadField,Maptype)          
  select COLUMN_NAME as ID,           
  CASE          
  WHEN COLUMN_NAME ='SENDER_NAME'          
  THEN 'PersonName'          
  WHEN COLUMN_NAME ='sender_mobile'          
  THEN 'MobileNo'          
  WHEN COLUMN_NAME ='sender_email'          
  THEN 'EmailID'          
  WHEN COLUMN_NAME ='sender_other_mobiles'          
  THEN 'MobileNo1'          
  WHEN COLUMN_NAME ='sender_other_emails'          
  THEN 'EmailID1'          
  WHEN COLUMN_NAME ='sender_co'          
  THEN 'CompanyName'          
  WHEN COLUMN_NAME ='address'          
  THEN 'OfficeAddress'          
   WHEN COLUMN_NAME ='sender_city'          
  THEN 'City'          
   WHEN COLUMN_NAME ='sender_state'          
  THEN 'State'          
   WHEN COLUMN_NAME ='sender_country'          
  THEN 'Country_Name'          
  END  Pre_mapped,COLUMN_NAME,           
  'PreMap' as Maptype           
  from INFORMATION_SCHEMA.COLUMNS where TABLE_NAME='TradeIndiaData' and TABLE_CATALOG=DB_NAME() and COLUMN_NAME not in                       
  ('Id', 'TradeIndiaKey', 'Trade_UserID', 'Trade_ProfileID','sender_city', 'ago_time','att_data','attachment_cnt','fax_number','generated',          
  'generated_date','generated_time','inquiry_type','landline_number','member_since','message','month_slot','order_value_min','pref_supp_location'          
 ,'product_id','product_name','product_source','quantity','receiver_co','receiver_mobile','receiver_name','receiver_uid','responded','rfi_id','sender',          
 'source', 'isprocessed','Processederror','Processeddate','Enquiryid','isvalid','DateReceived','sender_uid','subject','unread_res_cnt','view_status','website')                      
 end                  
                
 if @apiName='Sulekha'                  
 begin                  
  insert into #temp (FieldId, Field_Name, ApiLeadField,Maptype)          
 select COLUMN_NAME as ID,           
  CASE          
  WHEN COLUMN_NAME ='UserName'          
  THEN 'PersonName'          
  WHEN COLUMN_NAME ='Usermobile'          
  THEN 'MobileNo'          
  WHEN COLUMN_NAME ='Useremail'          
  THEN 'EmailID'          
   WHEN COLUMN_NAME ='Usercity'          
  THEN 'City'          
  END  Pre_mapped,COLUMN_NAME,           
  'PreMap' as Maptype            
 from INFORMATION_SCHEMA.COLUMNS where TABLE_NAME='SulekhaLeads' and TABLE_CATALOG=DB_NAME() and COLUMN_NAME not in                       
  ('Id', 'InsertDate', 'InsertTime', 'thired_party_url','UserLocalities','UserComments','Keywords','Sul_Lead','Sul_Biz','Sul_Customer',          
  'CreatedOn','ResponseJson','IsProcess','Processederror','Processeddate','EnquiryId','ParentId')                      
 end              
               
               
 if @apiName='MagicBricks'                  
 begin                  
   insert into #temp (FieldId, Field_Name, ApiLeadField,Maptype)          
 select COLUMN_NAME as ID,           
  CASE          
  WHEN COLUMN_NAME ='Name'          
  THEN 'PersonName'          
  WHEN COLUMN_NAME ='Mobile'          
  THEN 'MobileNo'          
    WHEN COLUMN_NAME ='isd'          
  THEN 'City'          
  WHEN COLUMN_NAME ='EmailID'          
  THEN 'EmailID'          
    WHEN COLUMN_NAME ='Locality'          
