  END  Pre_mapped,COLUMN_NAME,       
  'PreMap' as Maptype          
  from INFORMATION_SCHEMA.COLUMNS where TABLE_NAME='MagicBrickLeads' and TABLE_CATALOG=DB_NAME() and COLUMN_NAME not in                       
  ('Id', 'MagicBricksKey', 'RefID', 'Loginid','pid','ph','Project','Subject','DateOfContact','TimeOfContact','TranType','VTime','VDate','MSG',          
  'isprocessed','Processederror','Processeddate','Enquiryid','isvalid','CreatedOn')                  
