  'PreMap' as Maptype            
 from INFORMATION_SCHEMA.COLUMNS where TABLE_NAME='Acres99_Leads' and TABLE_CATALOG=DB_NAME() and COLUMN_NAME not in                       
  ('Id', 'Acres_Username','ResType', 'RcvdOn', 'QueryID', 'PhoneVerificationStatus','EmailVerificationStatus','Acres_IDENTITY','QryInfo','ProjID',          
  'SubUserName','ProdId','ProductStatus','ProductType',          
