/* ============================================================
   Procedure: [dbo].[ups_c2c_UpdateIntialRemarks]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[ups_c2c_UpdateIntialRemarks]
(
	@EntityName NVARCHAR(255) = '', 
	 @EntityId   BIGINT, 
	 @Remarks    NVARCHAR(MAX)
)
AS
BEGIN
    IF(@EntityName = 'lead')
        BEGIN
            UPDATE UserLeads
                SET 
                    InitialRemarks = @Remarks
            WHERE ID = @EntityId;
    END;
    IF(@EntityName = 'enquiry')
        BEGIN
            UPDATE UserEnquiry
                SET 
                    InitialRemarks = @Remarks
            WHERE EnquiryID = @EntityId;
    END
END



GO

/* ============================================================
   Procedure: [dbo].[Ups_CustomFieldWebFormFieldMapping]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Ups_CustomFieldWebFormFieldMapping] @fieldjson NVARCHAR(max) = ''  
 ,@webFormId BIGINT  
 ,@createdOn DATETIME = NULL  
 ,@createdBy BIGINT = NULL  
 ,@userId BIGINT = ''  
 ,@mode nVARCHAR(20)  
AS  
BEGIN  
 DECLARE @id INT = 0  
  ,@count INT = 0  
  ,@rowid INT = 0  
  ,@fieldid BIGINT = 0  
  ,@ctrlname nVARCHAR(max) = ''  
  ,@ctrltype nVARCHAR(max) = ''  
 DECLARE @parentid BIGINT = 0  
  ,@ModifiedBy BIGINT = NULL  
  ,@ModifiedON DATETIME = NULL;  
  
 SET @parentid = (  
   SELECT parentid  
   FROM User_Detail(NOLOCK)  
   WHERE user_id = @userId  
   )  
 ---------------Altered By Rajneesh Mishra 16/05/2022--------------------------------      
 SET @createdOn = GETDATE()  
 SET @createdBy = @userId  
  
 --------------------------------------------------------------------------      
 DROP TABLE  
  
 IF EXISTS #temp  
  CREATE TABLE #temp (  
   rowid INT identity(1, 1)  
   ,FieldId BIGINT  
   ,CtrlName nVARCHAR(max)  
   ,CtrlType nVARCHAR(max)  
   )  
  
 IF @mode = 'Save'  
 BEGIN  
  SELECT @ModifiedON = CreatedOn  
   ,@ModifiedBy = CreatedBY  
  FROM tbl_CustomFieldWebFormFieldMapping(NOLOCK)  
  WHERE WebFormId = @webFormId  
   AND ParentId = @parentId  
  
  IF @ModifiedON IS NOT NULL  
  BEGIN  
   DELETE  
   FROM tbl_CustomFieldWebFormFieldMapping  
   WHERE WebFormId = @webFormId  
    AND ParentId = @parentId  
  
   SELECT @createdOn = @ModifiedON  
    ,@createdBy = @ModifiedBy  
  
   SELECT @ModifiedON = GETDATE()  
    ,@ModifiedBy = @userId  
  END  
  
  INSERT INTO #temp (  
   FieldId  
   ,CtrlName  
   ,CtrlType  
   )  
  SELECT FieldId  
   ,CtrlName  
   ,CtrlType  
  FROM OPENJSON(@fieldjson) WITH (  
    FieldId BIGINT '$.custFieldId'  
    ,CtrlName nVARCHAR(max) '$.ctrlName'  
    ,CtrlType nVARCHAR(max) '$.CtrlType'  
    )  
  
  INSERT INTO tbl_CustomFieldWebFormFieldMapping (  
   FieldId  
   ,CtrlName  
   ,CtrlType  
   ,WebFormId  
   ,ParentId  
   ,CreatedOn  
   ,CreatedBY  
   ,ModifiedON  
   ,ModifiedBy  
   )  
  SELECT FieldId  
   ,CtrlName  
   ,CtrlType  
   ,@webFormId  
   ,@parentId  
   ,@createdOn  
   ,@createdBy  
   ,@ModifiedON  
   ,@ModifiedBy  
  FROM #temp  

  Select 'Successfully Saved'
 END  
 ELSE IF @mode = 'Select'  
 BEGIN  
  SELECT cf.fieldname  
   ,cfwf.*  
  FROM tbl_CustomFieldWebFormFieldMapping cfwf  
  JOIN customfields cf ON cfwf.FieldId = cf.field_ID  
  WHERE cfwf.WebFormId = @webFormId  
   AND cfwf.ParentId = @parentId  
 END  
  
 IF @mode = 'Save'  
 BEGIN  
  DECLARE @rowJson nVARCHAR(MAX) = (  
    SELECT *  
    FROM tbl_CustomFieldWebFormFieldMapping(NOLOCK)  
    WHERE WebFormId = @webFormId  
      
    FOR JSON AUTO  
     ,INCLUDE_NULL_VALUES  
    )  
  
  IF @rowJson IS NOT NULL  
  BEGIN  
   EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @userId  
    ,@Activity_type = 'Insert Custom Field Web Form Field Mapping'  
    ,@ActionType = 'I'  
    ,@RowJson = @rowJson  
    ,@Table_name = 'tbl_CustomFieldWebFormFieldMapping'  
  END  
 END  
END  


GO

/* ============================================================
   Procedure: [dbo].[ups_et_ProccessUserLocationTrackingBulkRequest]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[ups_et_ProccessUserLocationTrackingBulkRequest]
as
begin
		
		drop table if exists #tblUserId
		 
		select  UserId, cast(0 as int) as IsProcessed into #tblUserId
			from tbl_et_UserLocationTrackingBulkRequest(nolock) where (IsProcess = 0 or (IsProcess=2 
			and ProcessAt < DATEADD(HH,-2,GETDATE()) and createddate >DATEADD(DAY,-1,GETDATE())))
				group by UserId

		drop table if exists #tempLocationData
		create table #tempLocationData (
			[UserLocationTrackingId] [bigint],
			[MovementCode] [varchar](20) NULL,
			[Remarks] [varchar](1000) NULL,
			[UserId] [bigint] NULL,
			[LocationDateTime] [datetime] NULL,
			[Latitude] [float] NULL,
			[Longitude] [float] NULL,
			[Address] [nvarchar](500) NULL,
			[BatteryPerc] [float] NULL,
			[NetworkPerc] [float] NULL,
			[CreatedDate] [datetime] NULL,
			[CreatedBy] [bigint] NULL,
			[IsActive] [bit] NULL,
			[IsMock] [bit] NULL,
			[IsBulk] [bit] NULL,
			[Speed] [varchar](50) NULL,
			[Distance] [varchar](50) NULL,
			[LocationMetaData] [nvarchar](max) default N'{}',
			[IsDistanceCalc] [bit] default 0,
		)
		declare @UserId bigint = 0

		drop table if exists #tempLocationDataCopy
		

		while(exists(select 1 from #tblUserId(nolock) where IsProcessed = 0))
		begin
			
			select top 1 @UserId = UserId from #tblUserId(nolock) u where IsProcessed = 0

			insert into  #tempLocationData ( UserLocationTrackingId, MovementCode, Remarks, UserId, LocationDateTime, Latitude, Longitude, Address, BatteryPerc, NetworkPerc, CreatedDate, CreatedBy, IsActive, IsMock, IsBulk, Speed, Distance, LocationMetaData, IsDistanceCalc ) 
			select top 100  UserLocationTrackingId, MovementCode, Remarks, UserId, LocationDateTime, Latitude, Longitude, Address, BatteryPerc, NetworkPerc, CreatedDate, CreatedBy, IsActive, IsMock, IsBulk, Speed, Distance, LocationMetaData, IsDistanceCalc
			from tbl_et_UserLocationTrackingBulkRequest(nolock) 
				where (IsProcess = 0 or (IsProcess=2 
					and ProcessAt < DATEADD(HH,-2,GETDATE()) and createddate >DATEADD(DAY,-1,GETDATE()))) 
				and UserId = @UserId order by UserLocationTrackingId

			select * into #tempLocationDataCopy from #tempLocationData

			update r set r.IsProcess = 2, r.ProcessAt = getdate()
			from  #tempLocationData t  inner join tbl_et_UserLocationTrackingBulkRequest(nolock) r 
				on t.UserLocationTrackingId = r.UserLocationTrackingId

			begin try

				--deleting duplicate check_in || check_out
				delete b  from ( select
						ROW_NUMBER() OVER (PARTITION BY t.MovementCode, 
							TRY_CONVERT(bigint, JSON_VALUE(t.LocationMetaData, '$.PhysicalAppointmentId'))
							 order by t.LocationDateTime asc
						) as [CheckCount]
					from #tempLocationData t  where MovementCode in ('CHECK_IN', 'CHECK_OUT') 
						and TRY_CONVERT(bigint, JSON_VALUE(t.LocationMetaData, '$.PhysicalAppointmentId'))  > 0
				) b where b.[CheckCount] > 1

				--deleting duplicate sign_in || sign_out
				 delete b  from ( select
						ROW_NUMBER() OVER (PARTITION BY t.MovementCode, 
							TRY_CONVERT(bigint, JSON_VALUE(t.LocationMetaData, '$.AttendanceId'))
							 order by t.LocationDateTime asc
						) as [SignCount]
					from #tempLocationData t  where MovementCode in ('SIGN_IN', 'SIGN_OUT')
						and TRY_CONVERT(bigint, JSON_VALUE(t.LocationMetaData, '$.AttendanceId'))  > 0
				) b where b.[SignCount] > 1

				--deleting duplicate break_in || break_out
				 delete b  from ( select
						ROW_NUMBER() OVER (PARTITION BY t.MovementCode, 
							TRY_CONVERT(bigint, JSON_VALUE(t.LocationMetaData, '$.BreakTransactionId'))
							 order by t.LocationDateTime asc
						) as [BreakCount]
					from #tempLocationData t  where MovementCode in ('BREAK_IN', 'BREAK_OUT')
						and TRY_CONVERT(bigint, JSON_VALUE(t.LocationMetaData, '$.BreakTransactionId'))  > 0
				) b where b.[BreakCount] > 1
				
				delete l from #tempLocationData(nolock) l 
				inner join ( select t.UserLocationTrackingId, t.SNO from (select
					UserLocationTrackingId, LocationDateTime,
				ROW_NUMBER() over (partition by UserId, MovementCode, LocationDateTime order by UserLocationTrackingId ) as SNO
				from #tempLocationData(nolock) ) t where t.SNO > 1 ) r on l.UserLocationTrackingId = r.UserLocationTrackingId

				
				declare @alreadyProcessed as table(
					UserLocationTrackingId bigint
				)
				
				delete t
					output deleted.UserLocationTrackingId into @alreadyProcessed
				from #tempLocationData(nolock) t 
					inner join TBL_ET_UserLocationTracking(nolock) u
						on t.LocationDateTime between DATEADD(mi, -2, u.LocationDateTime)  and DATEADD(mi, 2, u.LocationDateTime)
						and t.MovementCode = u.MovementCode
						and t.UserId = u.UserId
						and isnull(t.LocationMetaData, '') <> '' 
						and isnull(u.LocationMetaData, '') <> ''
						and isnull(t.LocationMetaData, '') like '%Timestamp%' 
						and isnull(u.LocationMetaData, '') like '%Timestamp%'
						and TRY_CONVERT(bigint, JSON_VALUE(t.LocationMetaData, '$.Timestamp')) 
							= TRY_CONVERT(BIGINT, JSON_VALUE(u.LocationMetaData, '$.Timestamp'))
						and TRY_CONVERT(bigint, JSON_VALUE(t.LocationMetaData, '$.Timestamp'))  > 0
						and TRY_CONVERT(BIGINT, JSON_VALUE(u.LocationMetaData, '$.Timestamp')) > 0
						
					 WHERE  isnull(t.LocationMetaData, '') <> '' and isnull(u.LocationMetaData, '') <> '' 
						and isnull(t.LocationMetaData, '') like '%Timestamp%'  and isnull(u.LocationMetaData, '') like '%Timestamp%'
						and ISJSON(t.LocationMetaData) > 0 and ISJSON(u.LocationMetaData) > 0 
					
				update c set c.IsProcess = 5, c.ErrorDescription = 'Already Processed' from @alreadyProcessed p 
					inner join tbl_et_UserLocationTrackingBulkRequest(nolock) c on p.UserLocationTrackingId = c.UserLocationTrackingId

				delete t from (select UserLocationTrackingId, LocationDateTime, 
						LAG(LocationDateTime, 1, LocationDateTime) over (partition by UserId, MovementCode order by LocationDateTime asc) as [preLocationDateTime]
					from #tempLocationData
							) d inner join 	#tempLocationData t
				on d.UserLocationTrackingId = t.UserLocationTrackingId 
					where  DATEDIFF(SECOND, d.preLocationDateTime, d.LocationDateTime) > 0 
							and DATEDIFF(SECOND, d.preLocationDateTime, d.LocationDateTime) <= 60

				drop table if exists #TBL_ET_UserLocationTracking
				select u.*  into #TBL_ET_UserLocationTracking from #tempLocationData(nolock) t 
					inner join TBL_ET_UserLocationTracking(nolock) u 
					on t.UserId = u.UserId and t.MovementCode = u.MovementCode
				where CAST(t.LocationDateTime as date) = CAST(u.LocationDateTime as date) 
					and ISJSON(u.LocationMetaData) > 0 
					and u.MovementCode in ( 'CHECK_IN', 'CHECK_OUT', 'SIGN_IN', 'SIGN_OUT','BREAK_IN' ,'BREAK_OUT' ) 

				delete t  from #tempLocationData(nolock) t 
					inner join #TBL_ET_UserLocationTracking(nolock) u 
						on   t.UserId = u.UserId and t.MovementCode = u.MovementCode 
							and t.MovementCode in ('CHECK_IN', 'CHECK_OUT') and u.MovementCode in ('CHECK_IN', 'CHECK_OUT')
							and (
							( 
								TRY_CONVERT(bigint, JSON_VALUE(t.LocationMetaData, '$.PhysicalAppointmentId')) 
									= TRY_CONVERT(bigint, JSON_VALUE(u.LocationMetaData, '$.PhysicalAppointmentId'))
								and TRY_CONVERT(bigint, JSON_VALUE(t.LocationMetaData, '$.PhysicalAppointmentId')) > 0
								and TRY_CONVERT(bigint, JSON_VALUE(u.LocationMetaData, '$.PhysicalAppointmentId')) > 0
							) 
						)

				delete t  from #tempLocationData(nolock) t 
					inner join #TBL_ET_UserLocationTracking(nolock) u 
						on   t.UserId = u.UserId and t.MovementCode = u.MovementCode 
							and t.MovementCode in ('SIGN_IN', 'SIGN_OUT') and u.MovementCode in ('SIGN_IN', 'SIGN_OUT')
							and (
							( 

								TRY_CONVERT(bigint, JSON_VALUE(t.LocationMetaData, '$.AttendanceId')) 
									= TRY_CONVERT(bigint, JSON_VALUE(u.LocationMetaData, '$.AttendanceId'))
								and TRY_CONVERT(bigint, JSON_VALUE(t.LocationMetaData, '$.AttendanceId')) > 0
								and TRY_CONVERT(bigint, JSON_VALUE(u.LocationMetaData, '$.AttendanceId')) > 0
							)
						)
				
				delete t from #tempLocationData(nolock) t 
					inner join #TBL_ET_UserLocationTracking(nolock) u 
						on   t.UserId = u.UserId and t.MovementCode = u.MovementCode
							and t.MovementCode in ('BREAK_IN' ,'BREAK_OUT') and u.MovementCode in ('BREAK_IN' ,'BREAK_OUT')
							and ( 
							(
								TRY_CONVERT(bigint, JSON_VALUE(t.LocationMetaData, '$.BreakTransactionId')) 
									= TRY_CONVERT(bigint, JSON_VALUE(u.LocationMetaData, '$.BreakTransactionId'))
								and TRY_CONVERT(bigint, JSON_VALUE(t.LocationMetaData, '$.BreakTransactionId')) > 0
								and TRY_CONVERT(bigint, JSON_VALUE(u.LocationMetaData, '$.BreakTransactionId')) > 0
							)
						)
			
					delete l from #tempLocationData(nolock) l
						inner join TBL_ET_UserLocationTracking(nolock) r 
					on l.LocationDateTime = r.LocationDateTime and l.UserId =r.UserId and l.MovementCode = r.MovementCode

					--declare @hasBreakInTable bit = 0, @isFirstBreakOut bit = 0, @hasBreakInDT bit = 0, 
					--		@hasBreakOutDT bit = 0, @LocationDateTime datetime = getdate(), @BreakOutLocationDate datetime = getdate()

					--select top 1  @isFirstBreakOut = ( case when MovementCode = 'BREAK_OUT' then 1 else 0 end ) ,
					--	@LocationDateTime = LocationDateTime from #tempLocationData order by  LocationDateTime asc

					--set  @hasBreakInDT = IIF(exists(select 1 from #tempLocationData where  MovementCode = 'BREAK_IN'), 1, 0)
					--set  @hasBreakOutDT = IIF(exists(select 1 from #tempLocationData where  MovementCode = 'BREAK_OUT'), 1, 0)

					--select top 1 @BreakOutLocationDate =  LocationDateTime  from #tempLocationData where  MovementCode = 'BREAK_OUT' order by  LocationDateTime asc

					--select  @hasBreakInTable = ( case when MovementCode = 'BREAK_IN' then 1 else 0 end ) 
					--	from TBL_ET_UserLocationTracking(nolock) where CAST(LocationDateTime as date) = CAST(@LocationDateTime as date) 
					--		and UserId = @UserId and MovementCode in ('BREAK_IN', 'BREAK_OUT') order by  LocationDateTime desc
	
					--if(@hasBreakInTable = 1 and @hasBreakOutDT = 0 )
					--begin
					--	insert into #tempLocationData( MovementCode, Remarks, UserId, LocationDateTime, Latitude, Longitude, Address, BatteryPerc, NetworkPerc, CreatedDate, CreatedBy, IsActive, IsMock, IsBulk, Speed, Distance, LocationMetaData, IsDistanceCalc)
					--	select top 1 'BREAK_OUT', Remarks, UserId, dateadd(second, -1, LocationDateTime), Latitude, Longitude, Address, BatteryPerc, NetworkPerc, CreatedDate, CreatedBy, IsActive, IsMock, IsBulk, Speed, Distance, LocationMetaData, IsDistanceCalc from #tempLocationData order by  cast(LocationDateTime as datetime) asc
					--end
		

					--declare @BreakTransId bigint = 0
					--set @BreakTransId = dbo.fn_GetBreakStatus(@UserId)
		
					--if(@hasBreakInTable = 1 and @hasBreakOutDT = 1 )
					--begin
					--	delete from #tempLocationData where LocationDateTime < @BreakOutLocationDate
					--end                                                                                                                             

					--if( @BreakTransId > 0 and 
					--	exists(select 1 from #tempLocationData where  MovementCode = 'BREAK_OUT'))
					--begin
					--	update TBL_ET_BreakTransaction set EndDate = @BreakOutLocationDate where BreakTransactionId = @BreakTransId
					--end

					--select @LocationDateTime as [@LocationDateTime], 
					--	@hasBreakInTable as [@hasBreakInTable], @isFirstBreakOut as[@isFirstBreakOut],
					--	@hasBreakInDT as [@hasBreakInDT]

					--print concat('------------------------------------Calculating Distance start', '-----------------------------------------------------------')

					--DECLARE @lastNonZeroLat DECIMAL(18, 14) = NULL;
					--DECLARE @lastNonZeroLon DECIMAL(18, 14) = NULL;
					--DECLARE @lastCumulativeDistance DECIMAL(18, 14) = 0;

					--declare @lastDate date = null;
					--select top 1 @lastDate = cast(LocationDateTime as date) from #tempLocationData order by LocationDateTime

					--if(@lastDate is null)
					--begin
					--	set @lastDate = cast(getdate() as date)
					--end

					--drop table if exists #tempDistance
					--create table #tempDistance(UserLocationTrackingId bigint, locationdatetime datetime,movementcode nvarchar(50),latitide nvarchar(50), 
					--	longitude nvarchar(50), cumulativedistance nvarchar(50))

					--select top 1 @lastCumulativeDistance = TRY_CONVERT(decimal(18,14), Distance), @lastNonZeroLat = TRY_CONVERT(decimal(18, 14), Latitude), 
					--		@lastNonZeroLon = TRY_CONVERT(decimal(18,14), Longitude)

					--	from TBL_ET_UserLocationTracking(nolock) where UserId =  @UserId 
					--		and cast(LocationDateTime as date) = cast(@lastDate as date) order by LocationDateTime desc

					--if(@lastCumulativeDistance is null)
					--begin
					--	set @lastCumulativeDistance = 0
					--end

					--DECLARE @UserLocationTrackingId DATETIME;
					--DECLARE @LocationDateTime DATETIME;
					--DECLARE @MovementCode VARCHAR(50);
					--DECLARE @Latitude DECIMAL(18, 14);
					--DECLARE @Longitude DECIMAL(18, 14);
					--DECLARE @prevLat DECIMAL(18, 14);
