					--		SET @lastNonZeroLon = @Longitude;
					--	END

					--	-- Output the result
					--	--PRINT CONVERT(VARCHAR(23), @LocationDateTime, 121) + ', ' + @MovementCode + ', ' + CONVERT(VARCHAR(50), @Latitude) + ', ' + CONVERT(VARCHAR(50), @Longitude) + ', ' + CONVERT(VARCHAR(50), @lastCumulativeDistance);
					--	insert into #tempDistance(UserLocationTrackingId,locationdatetime,movementcode,latitide,longitude,cumulativedistance)
					--	select cast(@UserLocationTrackingId as bigint), CONVERT(VARCHAR(23), @LocationDateTime, 121) LocationDateTime, @MovementCode MovementCode, 
					--	CONVERT(VARCHAR(50), @Latitude) Latitude, CONVERT(VARCHAR(50), @Longitude)Longitude, CONVERT(VARCHAR(50), @lastCumulativeDistance) CumulativeDistance;
					--	FETCH NEXT FROM location_cursor INTO @UserLocationTrackingId, @LocationDateTime, @MovementCode, @Latitude, @Longitude, @prevLat, @prevLon;
					--END

