					--	@lastNonZeroLon = NULL, @lastCumulativeDistance = 0, @lastDate = null

					--drop table if exists #tempDistance
					
					--print concat('------------------------------------Calculating Distance end', '-----------------------------------------------------------')

					declare @insertedRec as tblScheduleIds


					insert into TBL_ET_UserLocationTracking (MovementCode, Remarks, LocationDateTime, Latitude, Longitude, IsMock, UserId, CreatedDate, CreatedBy, IsActive, IsBulk, Address, BatteryPerc, NetworkPerc, Speed, Distance, LocationMetaData)
					output inserted.UserLocationTrackingId as [ScheduledId] into @insertedRec
					select distinct MovementCode, Remarks, LocationDateTime, Latitude, Longitude, IsMock, UserId, CreatedDate, CreatedBy, IsActive, 1, Address, BatteryPerc, NetworkPerc, Speed, Distance, LocationMetaData from #tempLocationData order by cast(LocationDateTime as datetime) asc

					exec tbl_et_UpdateDistanceCalculations @UserId

					begin try	
						exec usp_et_GenerateGpsOnOffActivity @insertedRec
					end try
					begin catch
						exec usp_InsertErrorInfo
					end catch


					delete c from @alreadyProcessed a inner join
						#tempLocationDataCopy c on a.UserLocationTrackingId = c.UserLocationTrackingId
					
					update r set r.IsProcess = 4, r.ProcessAt = getdate(), r.ErrorDescription = 'Duplicate or removed'
					from #tempLocationDataCopy c inner join tbl_et_UserLocationTrackingBulkRequest r on c.UserLocationTrackingId = r.UserLocationTrackingId
						left join #tempLocationData o on c.UserLocationTrackingId = o.UserLocationTrackingId where o.UserLocationTrackingId is null

					update r set r.IsProcess = 1, r.ProcessAt = getdate() from  #tempLocationData t 
						inner join tbl_et_UserLocationTrackingBulkRequest(nolock) r on t.UserLocationTrackingId = r.UserLocationTrackingId


					update #tblUserId set IsProcessed = 1 where UserId = @UserId
					select @UserId = 0
					truncate table #tempLocationData
					drop table if exists #tempLocationDataCopy
					print 'Success'
			end try
			begin catch
				
				update r set r.IsProcess = 3, r.ProcessAt = getdate(), ErrorDescription = error_message() 
				from  #tempLocationData t 
						inner join tbl_et_UserLocationTrackingBulkRequest(nolock) r on t.UserLocationTrackingId = r.UserLocationTrackingId
				
				exec usp_insertErrorInfo
				
				update #tblUserId set IsProcessed = 1 where UserId = @UserId
				select @UserId = 0
				truncate table #tempLocationData
				drop table if exists #tempLocationDataCopy

				print 'Error'
			end catch
		end
end



