/* ============================================================
   Procedure: [dbo].[ups_GetColumnsForFxByUid]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[ups_GetColumnsForFxByUid](
	@UserId bigint
)
as
begin
select COLUMN_NAME as [name], 
(
	case when DATA_TYPE = 'bigint'
		then 'long'
	when DATA_TYPE = 'varchar'
		then 'string'
	when DATA_TYPE = 'nvarchar'
		then 'string'
	when DATA_TYPE = 'char'
		then case when [length] = 1
					then 'char'
				else 'string'end
	when DATA_TYPE = 'bit'
		then 'bool'
	when DATA_TYPE = 'numeric'
		then 'double'
	else  DATA_TYPE end
) as [type],
Entity as [entity]
 from (
 select  COLUMN_NAME, DATA_TYPE , [Entity], [length] from (select ROW_NUMBER() over ( partition by COLUMN_NAME order by COLUMN_NAME, DATA_TYPE ) as ct, COLUMN_NAME, DATA_TYPE, 'common' as [Entity], CHARACTER_MAXIMUM_LENGTH AS [length] from INFORMATION_SCHEMA.COLUMNS(NOLOCK) WHERE TABLE_NAME IN ( 'userleads', 'userenquiry')
	AND COLUMN_NAME NOT IN  ('id', 'ModifiedOn', 'ModifiedBy', 'FollowupDate', 'LeadImage', 'temp_id', 'img_ext', 'ProfileImgFileName', 'enquirysource', 'WhatsAppNoColName', 'LastFollowupCreatedBy','parentid')) c WHERE c.ct = 1
union
select COLUMN_NAME, DATA_TYPE, 'lead' as [Entity], CHARACTER_MAXIMUM_LENGTH AS [length] from INFORMATION_SCHEMA.COLUMNS(NOLOCK) WHERE TABLE_NAME IN ( 'userleads')
	AND COLUMN_NAME NOT IN  (select distinct COLUMN_NAME from INFORMATION_SCHEMA.COLUMNS(NOLOCK) WHERE TABLE_NAME IN ( 'userenquiry')
	AND COLUMN_NAME NOT IN  ('id', 'ModifiedOn', 'ModifiedBy', 'FollowupDate', 'LeadImage', 'temp_id', 'img_ext', 'ProfileImgFileName', 'enquirysource', 'WhatsAppNoColName', 'LastFollowupCreatedBy','parentid', 'LeadNo')
	
	) AND COLUMN_NAME NOT IN  ('id', 'ModifiedOn', 'ModifiedBy', 'FollowupDate', 'LeadImage', 'temp_id', 'img_ext', 'ProfileImgFileName', 'enquirysource', 'WhatsAppNoColName', 'LastFollowupCreatedBy','parentid', 'Products', 'CreatedOn')
union
select  fieldname, LOWER((
	case datatype when 'd' then 'datetime' when 'f' then 'double' when 'v' then 'string' when 'r'    
     then 'string'    
    when 'm'     
     then 'string'    
    when 's'     
     then 'string'    
    when 'c'     
     then 'bool'     
  end)) as [datatype],  'custom' as [Entity], 0 AS [length] from customfields(nolock) where parentid=(select ParentID from User_Detail(nolock) where User_ID = @UserId)
  ) a order by 3 
end



GO

/* ============================================================
   Procedure: [dbo].[ups_ims_GetEnquiryDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


-- exec ups_ims_GetEnquiryDetails 4156413      
-- exec ups_ims_GetEnquiryDetails 987398        
CREATE   PROCEDURE [dbo].[ups_ims_GetEnquiryDetails]        
(        
    @enqid bigint        
)        
as                                        
begin    
set nocount on                                    
declare @uid bigint                                    
declare @cnt_start int                                      
declare @cnt_max int                                      
declare @grp_id int                                      
declare @out varchar(max)=''                                       
select @uid=parentid from UserEnquiry where EnquiryID=@enqid;                                     
set @cnt_start=0;                                      
select distinct Group_Name, Group_ID into #group from Group_Detail where USER_ID=@uid                                      
select @cnt_max=COUNT(Group_Name) from #group                                      
while (@cnt_start < @cnt_max)                                      
begin                                      
select @grp_id=MAX(group_id) from #group;                                      
if(@cnt_start>0)                                      
begin                                      
select @out=@out+', '+group_name from #group where Group_ID=@grp_id;                                      
end                                      
else                                      
begin                                      
select @out=group_name from #group where Group_ID=@grp_id;                                      
end                                      
delete From #group where Group_ID=@grp_id;                                      
set @cnt_start=@cnt_start+1;                                      
end                                      
drop table #group;                                    
SELECT en.EnquiryID,         
       en.PersonName,         
       en.CompanyName,         
       ISNULL(en.MobileNo, '') AS mobileno,         
       en.emailid,         
       ISNULL(en.city, '') AS city,         
       ISNULL(en.[state], '') AS [state],         
       ISNULL(en.country, '') AS country,         
       ISNULL(en.pincode, '') AS pincode,         
       ISNULL(en.residentialaddress, '') AS residentialaddress,         
       src.[name] AS [source],         
       ISNULL(md.[name], '') AS medium,         
       ISNULL(cmp.[Name], '') AS campaignname,         
       en.InitialRemarks AS remark,         
       CONVERT(VARCHAR(20), en.CreatedDate, 113) AS createdon,         
       ud.user_login AS createdby,         
       @out AS groups,         
       ISNULL(en.mobileno1, '') AS mobileno1,         
       ISNULL(en.mobileno2, '') AS mobileno2,         
       ISNULL(en.emailid1, '') AS emailid1,         
       ISNULL(en.emailid2, '') AS emailid2,         
       en.officeaddress,         
       en.countrycode,         
       en.SourceName AS source_id,         
       en.MediumName AS medium_id,         
       en.CampaignName AS camp_id,         
       ISNULL(en.LeadNo, '') AS LeadNo,         
       (Case when ISNULL(en.LeadNo, 0) > 0 then 0 else 1 end) as IsOpen,         
       ltrim(ISNULL(en.countrycode, '') + ' ' + ISNULL(en.MobileNo, '')) + CASE        
                                                                  WHEN ISNULL(en.MobileNo1, '') <> ''        
                                                                  THEN ', ' + ltrim(ISNULL(en.countrycode1, '') + ' ' + ISNULL(en.MobileNo1, ''))        
                                                                  ELSE ''        
                                                              END + CASE        
                                                                        WHEN ISNULL(en.MobileNo2, '') <> '        
'        
                                                                        THEN ', ' + ltrim(ISNULL(en.countrycode2, '') + ' ' + ISNULL(en.MobileNo2, ''))        
     ELSE ''        
                                                                    END AS phones,         
       ISNULL(en.CountryCode1, '') AS CountryCode1,         
       ISNULL(en.CountryCode2, '') AS CountryCode2,         
       ISNULL(en.EmailID, '') + CASE        
                                    WHEN ISNULL(en.EmailID1, '') <> ''        
                                    THEN ', ' + ISNULL(en.EmailID1, '')        
                                    ELSE ''        
                                END + CASE        
                                   WHEN ISNULL(en.EmailID2, '') <> ''        
                                          THEN ', ' + ISNULL(en.EmailID2, '')        
                                          ELSE ''        
                                      END AS emails,      
  ltrim(en.Countrycode + ' ' + en.Mobileno) + case when isnull(en.Mobileno1,'') <> '' then ', ...' else '' end as Mobile,      
  ltrim(en.EmailId) + case when isnull(en.EmailId1,'') <> '' then ', ...' else '' end as Email,      
  IsConflictWithLead=dbo.ufn_IsEnquiryConflictsLead(en.EnquiryID),    
  IsLeadDeleted=case when isnull(en.LeadNo,0) > 0 then ~dbo.ufn_IsLeadExists(en.LeadNo,en.ParentID) else cast(0 as bit) end ,  
  en.ProfileImgFileName,
  en.ParentID as [ParentId],
 ( select STRING_AGG(tm.Tag, ',' ) from EntityTagMapping(nolock) etm
	inner join  TagMaster(nolock) tm on etm.TagID   = tm.ID
		where etm.Entity = 'enquiry' and etm.EntityID = en.EnquiryID ) as [Tags],
 cn.Shortname as CountryISO
FROM UserEnquiry(nolock) en        
     LEFT JOIN user_detail(nolock) ud ON en.CreatedBy = ud.user_id        
     LEFT JOIN usersourcesettings src ON en.sourcename = src.sourceid        
     LEFT JOIN usermediumsettings md ON en.mediumname = md.mediumid        
     LEFT JOIN UserCampaignSettings cmp ON en.campaignname = cmp.CampaignID
	 left join m_country1(nolock) cn on en.Country = cn.Country_Name     
WHERE en.EnquiryID = @enqid;        
        
end 



GO

/* ============================================================
   Procedure: [dbo].[ups_las_Replica_UpdateLeadAssignmentUser]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

----sp_helptext    ups_las_UpdateLeadAssignmentUser @EntityId = @LeadId    --14363159    
CREATE   PROCEDURE [dbo].[ups_las_Replica_UpdateLeadAssignmentUser] --14641025     
(                
    @EntityId BIGINT,@assignee bigint   out             
)                        
AS    

BEGIN                        
 BEGIN TRY      
        
        -- Uncomment the following line to enable debugging.      
  --DECLARE @EntityId bigint = 17780752 --1691907       
      
  DECLARE @ParentId BIGINT, @LeadNo bigint, @EnquirySource bigint = 0, @MobileNo varchar(100)= '', @isnewlead int = 1,@error nvarchar(2000),@OldAssignedTo bigint;      
      
  
  SELECT @ParentId = [ParentID], @LeadNo = LeadNo, @OldAssignedTo=AssignedTo, @EnquirySource = isnull(enquirysource, 0), @MobileNo = MobileNo      
   FROM UserLeads(NOLOCK) WHERE [ID] = @EntityId;      
      
  
  --If(@ParentId=40204 and @MobileNo='7303590417')      
  --begin      
  --print '--force exited (ups_las_UpdateLeadAssignmentUser)---'      
  --return;      
  --end      
      
  DROP TABLE IF EXISTS #tempRules      
      
      
  DECLARE @defaultAssignee BIGINT = 0, @OverwriteAssignedUser BIT, @RuleId BIGINT = 0, @leadAssignmentId bigint = 0;      
      
  if exists (select 1 from tbl_LeadAssignmentMaster(NOLOCK) WHERE [ParentId] = @ParentId AND [is_active] = 1 )    
  begin    
  SELECT @defaultAssignee = [default_agent], @OverwriteAssignedUser = [overwrite_agent], @leadAssignmentId = id      
   FROM tbl_LeadAssignmentMaster(NOLOCK) WHERE [ParentId] = @ParentId AND [is_active] = 1;     
   end    
  else    
  begin    
  select @error='No active asssignment rule'    
  print 'No active rule for parent'    
  goto UPDATERECORD    
  end    
    
        print concat('Start @defaultAssignee => ', @defaultAssignee)      
      
  --Code is commented because segmentation needs to run in parallel.      
  --if(exists(select 1 from tbl_LeadAssignmentRules(nolock) where lam_id = @leadAssignmentId and RuleType = 'SegmentCondition'))      
  --begin      
  --print 'Checking SegmentCondition Rule'      
  --exec ups_las_UpdateLeadAssignmentUserBySegment @EntityId      
  --return;      
  --end      
      
  if isnull(@EnquirySource, 0) in(12, 13, 14, 15, 22, 23, 24, 28, 29, 30,21)       
   and ( select count(1) from leadinteractionhistory(nolock) where id_lead = @entityid) > 1       
  begin       
   select @isnewlead = 0       
  end       
      
  IF(@OverwriteAssignedUser = 1 OR ( @OverwriteAssignedUser = 0       
     and ( isnull(@EnquirySource, 0) not in(12, 13, 14, 15, 22, 23, 24, 28, 29, 30,21) or @isnewlead = 0)))       
  BEGIN       
   print 'Overwrite'      
   SELECT *, 0 AS [isProcess] INTO #tempRules FROM tbl_LeadAssignmentRules(NOLOCK)      
    WHERE [lam_id] IN( SELECT [id] FROM [tbl_LeadAssignmentMaster](NOLOCK)       
    WHERE [ParentId] = @ParentId) AND [is_active] = 1 --and isnull(assignment_expression, '') != ''       
   ORDER BY [rule_priority];      
       
   if(exists(select 1 from #tempRules))                
   begin       
    WHILE(EXISTS(SELECT 1 FROM #tempRules WHERE [isProcess] = 0))      
    BEGIN       
     DECLARE @AssignmentExpression NVARCHAR(MAX), @SelectedUser NVARCHAR(500), @RuleType nvarchar(255) = '',       
      @SettingJSON nvarchar(max) = '{}', @logicalOperator nvarchar(25) = '', @isSegmentMatched bit = 0;      
      
     SELECT TOP 1 @RuleId = [id], @AssignmentExpression = [assignment_expression], @SelectedUser = [selected_users],      
      @RuleType = RuleType, @SettingJSON = SettingJSON, @logicalOperator = logical_operator       
       FROM #tempRules WHERE [isProcess] = 0 ORDER BY [rule_priority] ASC;      
      
     declare @isRuleMatched bit = 0;      
      
     if(isnull(@RuleType, '') = '')      
     begin      
      if(isnull(@AssignmentExpression, '') <> '')      
      begin      
       print 'Conditional'      
      
       DROP TABLE IF EXISTS #tempColName;      
      
       SELECT  ROW_NUMBER() OVER( ORDER BY [colName] ASC ) AS [SRNo],       
        *,  0 AS [isProcess] INTO #tempColName FROM  ( SELECT      
         LOWER([COLUMN_NAME]) AS [colName], 'predefined' AS [columnType], 0 AS [FieldId],       
         UPPER( CASE [column_name]       
          WHEN 'CampaignName' THEN 'VARCHAR'       
          WHEN 'MediumName' THEN 'VARCHAR'       
        WHEN 'SourceName' THEN 'VARCHAR'       
          WHEN 'FollowupStatus' THEN 'VARCHAR'       
          WHEN 'LastFollowupCreatedBy' THEN 'VARCHAR'      
          WHEN 'AssignedTo' THEN 'VARCHAR'      
          WHEN 'CreatedBy' THEN 'VARCHAR'      
         ELSE [DATA_TYPE] END ) AS [DATA_TYPE]       
         FROM INFORMATION_SCHEMA.COLUMNS(NOLOCK) AS colName       
          WHERE [TABLE_NAME] = 'UserLeads' and [COLUMN_NAME] not in ('Id', 'productsjson')       
        UNION       
        SELECT       
         [fieldname] AS [colName],       
         'custom' AS [columnType],      
         [field_ID] AS [FieldId],       
         LOWER(( CASE [datatype]       
          WHEN 'd' THEN 'DateTime'       
          WHEN 'f' THEN 'Numeric'       
          WHEN 'v' THEN 'VARCHAR'       
          WHEN 'm' THEN 'VARCHAR'       
          WHEN 'e' THEN 'VARCHAR'       
          WHEN 'r' THEN 'VARCHAR'       
          WHEN 'c' THEN 'VARCHAR'       
          WHEN 's' THEN 'VARCHAR'       
         END )) AS [DATA_TYPE]      
         FROM customfields(NOLOCK)       
          WHERE [ParentID] = @ParentId ) AS col;      
              
       -- select * from #tempColName      
       DECLARE @CondtionString NVARCHAR(MAX) = @AssignmentExpression;      
       WHILE( EXISTS(SELECT 1 FROM #tempColName WHERE [isProcess] = 0))                        
       BEGIN       
        DECLARE @SRNo INT, @colName NVARCHAR(255), @columnType NVARCHAR(255), @FieldId BIGINT, @paramQuery NVARCHAR(MAX), @DataType NVARCHAR(255);      
        SELECT TOP 1 @SRNo = [SRNo], @colName = [colName], @columnType = [columnType], @FieldId = [FieldId], @DataType = [DATA_TYPE]       
         FROM  #tempColName WHERE [isProcess] = 0;      
      
        DECLARE @retParamValue SQL_VARIANT, @ParmDefinition NVARCHAR(500);      
      
        SET @ParmDefinition = N'@retValInnerOut sql_variant OUTPUT';      
        SET @paramQuery = ( CASE       
          WHEN @columnType = 'predefined'       
           THEN concat('select @retValInnerOut = ', @colName, ' from UserLeads(nolock) where ID = ', @EntityId)       
          WHEN @columnType = 'custom'       
           THEN concat( 'select @retValInnerOut = fieldvalue from customfieldLeadvalue(nolock) where LeadID = ', @EntityId, ' and fieldID = ', @FieldId)      
         END);      
      
        -- print @paramQuery                            
        EXECUTE sp_executesql @paramQuery, @ParmDefinition, @retValInnerOut = @retParamValue OUTPUT;      
                  
        SET @retParamValue = ( CASE       
         WHEN @colName = 'assignedto'       
          THEN (SELECT [User_Login] FROM User_Detail(NOLOCK) WHERE User_Id = CAST(@retParamValue AS BIGINT))       
         WHEN @colName = 'sourcename'       
          THEN (SELECT [Name] FROM UserSourceSettings(NOLOCK) WHERE [SourceID] = CAST(@retParamValue AS BIGINT))       
         WHEN @colName = 'mediumname'       
          THEN (SELECT [Name] FROM UserMediumSettings(NOLOCK) WHERE [MediumID] = CAST(@retParamValue AS BIGINT))       
         WHEN @colName = 'campaignname'       
          THEN (SELECT [Name] FROM UserCampaignSettings(NOLOCK) WHERE [CampaignID] = CAST(@retParamValue AS BIGINT))      
         WHEN @colName = 'parentid'       
          THEN (SELECT [User_Login] FROM User_Detail(NOLOCK) WHERE User_Id = CAST(@retParamValue AS BIGINT))      
         WHEN @colName = 'followupstatus'       
          THEN (SELECT [FollowupStatus] FROM FollowUp_Status(NOLOCK) WHERE [ID] = CAST(@retParamValue AS BIGINT))       
         WHEN @colName = 'createdby'       
          THEN (SELECT [User_Login] FROM User_Detail(NOLOCK) WHERE User_Id = CAST(@retParamValue AS BIGINT))       
         WHEN @colName = 'modifiedby'       
          THEN (SELECT [User_Login] FROM User_Detail(NOLOCK) WHERE User_Id = CAST(@retParamValue AS BIGINT))      
         WHEN @colName = 'enquirysource'       
          THEN (SELECT [Sourcename] FROM enquirysources(NOLOCK) WHERE [id] = CAST(@retParamValue AS INT))       
         WHEN @colName = ''       
          THEN (SELECT [User_Login] FROM User_Detail(NOLOCK) WHERE User_Id = CAST(@retParamValue AS BIGINT))              ELSE @retParamValue END);      
                  
        --print concat('@DataType => ', @DataType, ' @retParamValue => ', cast(@retParamValue as nvarchar), ' @CondtionString  => ', @CondtionString, ' @colName => ', @colName, ' @RuleId => ', @RuleId );      
      
        SET @CondtionString = replace(LOWER(@CondtionString), concat( '#', LOWER(@colName), '#'),       
          (CASE LOWER(@DataType)       
           WHEN 'nvarchar' THEN concat('''', ISNULL(cast(@retParamValue as nvarchar),''),'''')       
           WHEN 'varchar' THEN concat('''', ISNULL(CAST(@retParamValue AS NVARCHAR(255)),''), '''')       
           WHEN 'datetime' THEN concat('''', ISNULL(CAST(@retParamValue AS NVARCHAR(255)), ''), '''')       
           ELSE ISNULL(CAST( @retParamValue AS NVARCHAR(255)), '')       
          END ));      
      
        --print concat('@@CondtionString => ', @CondtionString);      
        UPDATE #tempColName SET [isProcess] = 1 WHERE [SRNo] = @SRNo;      
      
       END;      
      
       DECLARE @retContionValue NVARCHAR(50), @ParmConditionDefinition NVARCHAR(500), @paramConditionQuery NVARCHAR(MAX);      
              
       SET @ParmConditionDefinition = N'@retConditionValInnerOut nvarchar(50) OUTPUT';      
       SET @paramConditionQuery = concat(N'set @retConditionValInnerOut =  ( select iif( ', @CondtionString, ',''true''', ',''false''))');      
      
       --select @ParmConditionDefinition, @paramConditionQuery                           
       EXECUTE sp_executesql @paramConditionQuery, @ParmConditionDefinition, @retConditionValInnerOut = @retContionValue OUTPUT;      
      
       print concat('@retContionValue => ', @retContionValue)       
              
       IF(@retContionValue = 'true')       
       BEGIN       
        set @isRuleMatched = 1;       
        update #tempRules set isProcess = 1        
       END;      
       select @CondtionString = ''      
      end      
     end      
     else      
     begin      
      print 'Segmentations'      
      
      if(isnull(@SettingJSON, '') <> '')        
      begin        
       declare         
        @EntityName nvarchar(20) = 'lead', @CriteriaID bigint, @outStatus int = 0        
             
       print @SettingJSON        
        
       drop table if exists #tempSegmentations        
        
       select SegmentId, SegmentName, cast(0 as bit) isProccess into #tempSegmentations         
        from openjson(json_query(@SettingJSON, '$.Segmentations')) with (        
        SegmentId bigint '$.SegmentId',        
        SegmentName nvarchar(255) '$.SegmentName'        
       )        
        
       declare @segmentId bigint = 0        
       while(exists(select 1 from #tempSegmentations where isProccess = 0))        
       begin        
        select top 1 @segmentId = SegmentId from #tempSegmentations(nolock) where isProccess = 0        
        
        print concat('@segmentId => ', @segmentId)      
        print concat('@logicalOperator => ', @logicalOperator)      
        
        print concat('before Usp_ContactExistsInSearch @outStatus => ', @outStatus)        
        exec Usp_ContactExistsInSearch          
        @entityname = @EntityName, @entityid = @EntityId, @CriteriaID = @segmentId,  @Status = @outStatus output                       
        print concat('after Usp_ContactExistsInSearch @outStatus => ', @outStatus)        
          
             
        if(@logicalOperator = 'or' and @outStatus = 1)       
        begin        
         print 'OR Rule Matched'        
         update #tempSegmentations set isProccess = 1        
        end        
             
        if(@logicalOperator = 'and' and @outStatus =  0)        
        begin        
         print 'And Rule Matched'        
         update #tempSegmentations set isProccess = 1         
        end        
        
        set @isSegmentMatched = @outStatus        
        
        update #tempSegmentations set isProccess = 1 where SegmentId = @segmentId        
        select @outStatus = 0        
       end        
           
                            if(@isSegmentMatched = 1)  -- check @isSegmentMatched is true or not      
                            begin        
                             set @isRuleMatched = 1;       
        set @retContionValue = 'true'      
                                update #tempRules set isProcess = 1        
                            end      
                                  
                            print concat('All Segment is completed of ruleId => ', @RuleId)        
                        end        
        
      print concat(' @isSegmentMatched => ', @isSegmentMatched)      
     end      
      
     --Reset veriable      
     select @logicalOperator = '', @SettingJSON = '', @AssignmentExpression = ''      
      
     --updating current rule that is processed      
     UPDATE #tempRules SET [isProcess] = 1 WHERE [id] = @RuleId;      
    END -- #tempRules whle end      
      
    if(@isRuleMatched = 1)      
    begin      
         
     DECLARE @tempAgentTable AS TABLE ( [id] INT IDENTITY(1, 1), [AgentId] BIGINT );                  
     INSERT INTO @tempAgentTable([AgentId])      
      SELECT [VALUE] FROM fn_Split(@SelectedUser, ',');      
      
     DECLARE @AgentCount INT = (SELECT COUNT(1) FROM @tempAgentTable );      
      
     IF(@AgentCount > 0)       
     BEGIN      
             
      print concat('@SelectedUser => ', @SelectedUser)      
             
      DECLARE @LastAgentId BIGINT = (SELECT [lastAssignedUser] FROM tbl_LeadAssignmentRules(nolock) WHERE [id] = @RuleId);      
      DECLARE @LastSrNo INT = (SELECT [id] + 1 FROM @tempAgentTable WHERE [AgentId] = @LastAgentId);      
      
      IF(NOT EXISTS(SELECT 1 FROM @tempAgentTable WHERE [AgentId] = @LastAgentId))      
      BEGIN       
       SET @LastSrNo = 1;      
      END;      
      
      SELECT @defaultAssignee = [AgentId] FROM @tempAgentTable       
       WHERE [id] = CASE WHEN(@LastSrNo % @AgentCount) = 0 THEN @AgentCount ELSE @LastSrNo % @AgentCount END;      
             
      UPDATE tbl_LeadAssignmentRules SET [lastAssignedUser] = @defaultAssignee WHERE [id] = @RuleId;      
      
      print concat( 'After rule matched @defaultAssignee: ', @defaultAssignee)       
      
     END;      
    END      
      
    print concat( 'Final: @defaultAssignee: ', @defaultAssignee)      
      
     select @assignee= @defaultAssignee
    declare @LeadInteractionId bigint = 0;      
    update UserLeads SET [AssignedTo] = @defaultAssignee WHERE [ID] = @EntityId;      
      
  set context_info 0x55555  
  
    if exists(select 1 from LeadInteractionHistory(nolock) where leadno = @leadno and parentid = @parentid )       
    begin    
     insert into LeadInteractionHistory(LeadNo, FollowUpStatus, NextStatusDate,Remarks, Products, AmountPaid, AssignedTo,      
      ParentID, CreatedOn, CreatedBy, FollowupDate, IsReassign, id_lead)      
     select top 1 LeadNo,  FollowUpStatus, NextStatusDate, Remarks, Products, AmountPaid, @defaultAssignee,      
       ParentID, getdate(), CreatedBy, FollowupDate, IsReassign, @entityid from LeadInteractionHistory(nolock)       
      where ParentID = @ParentId and LeadNo = @LeadNo order by ID desc       
                  
     set @LeadInteractionId = scope_identity()    
  
    end       
    else       
    begin       
     insert into LeadInteractionHistory(LeadNo, FollowUpStatus, NextStatusDate, Remarks, Products, AmountPaid, AssignedTo,       
      ParentID, CreatedOn, CreatedBy, FollowupDate, IsReassign, id_lead )       
     select LeadNo, FollowUpStatus, NextStatusDate, Remarks, Products, AmountPaid, @defaultAssignee,       
      ParentID, getdate(), CreatedBy, FollowupDate, 0, id       
      from userleads(nolock) where id = @EntityId       
                  
     set @LeadInteractionId = scope_identity()       
    end       
   set context_info 0x00000  
  
  
              
    if( isnull(@LeadInteractionId, 0) > 0 )       
    begin       
     insert into tbl_LeadEventHistory(leadid, UserID, parentid, EventID, EventDescription, RefTables, refids)       
     select @EntityId, ul.createdby, ul.parentid, 37,  concat( 'Lead with ', case when isnull(       
       nullif(ul.personname, ''), '' ) <> '' then concat('name ', ul.personname) else concat( 'leadno ',      
       cast(ul.leadno as nvarchar) ) end, ' is assigned to ', a.user_login ), 'LeadInteractionhistory', @LeadInteractionId       
      from userleads(nolock) ul inner join User_Detail(nolock) a on ul.AssignedTo = a.User_ID       
     where ul.ID = @EntityId       
    end       
        
       
      
    insert into tbl_lam_UserAssignmentHistory( parentid, assignedUserId, ruleid, leadId)       
                  
    select @ParentId, @defaultAssignee, (case when @retContionValue = 'true' then @RuleId else 0 end),      
     @EntityId declare @assignHistoryId bigint = scope_identity()       
      
    begin try       
     declare @UserName nvarchar(255) = '', @RuleName nvarchar(255) = '';      
                      
     if(@defaultAssignee > 0)       
     begin      
      select @UserName = User_Login from User_Detail(nolock) where User_ID = @defaultAssignee       
     end       
                      
     if( @defaultAssignee > 0 and @retContionValue = 'true' )       
     begin       
      select @RuleName = rule_name from tbl_LeadAssignmentRules(nolock) where id = @RuleId       
     end       
      
     begin try       
      if (@RuleId <= 0)       
      begin       
       if not exists(select 1 from tbl_LeadEventHistory(nolock) where leadid = @EntityId and eventid = 10)       
        and exists (select 1 from leadinteractionhistory_latest(nolock) where leadno = @LeadNo and parentid = @ParentId)       
       begin       
        declare @lih_idf bigint, @assi_id bigint, @fo_status bigint, @createdby bigint, @createduser nvarchar(100), @assign_user nvarchar(100),       
         @eventdate datetime, @ev nvarchar(200)= 'New Interaction added', @eve_d nvarchar(2000), @foll_status nvarchar(100)       
                                  
        select top 1 @lih_idf = id, @assi_id = AssignedTo, @fo_status = FollowUpStatus, @createdby = createdby, @eventdate = CreatedOn       
         from  leadinteractionhistory_latest(nolock)  where leadno = @LeadNo and parentid = @ParentId       
                                  
        select @assign_user = user_login from user_detail(nolock) where user_id = @assi_id       
        select @createduser = user_login from user_detail(nolock) where user_id = isnull(nullif(@createdby, 0), @parentid)      
        select @foll_status = FollowupStatus from followup_status(nolock) where ID = @fo_status      
        select @eve_d = concat(@createduser, ' added a followup with status ', @foll_status, '. Lead was assigned to ', isnull(@assign_user, 'no one'))      
                                  
        exec UspSaveEntityActivity_withid 'lead', @EntityId, @ParentId, @ParentId, @eve_d, @ev, 'leadinteractionhistory', @lih_idf       
       end       
      end       
     end try       
     begin catch       
      exec usp_InsertErrorInfo       
     end catch       
                      
     declare @EventName nvarchar(255) = ( case when @RuleId > 0        
      and @retContionValue = 'true' then 'Lead is reassigned' else 'Lead is no reassigned' end);      
      
     declare @EventTemplate nvarchar(max) = (case when @RuleId > 0 and @retContionValue = 'true'       
       then concat( 'The lead is reassigned to ', @UserName, ' as per lead assignment rule where the rule name is ', @RuleName, '.')       
       else 'The lead is not reassigned to anyone because no lead assignment rule matches' end);      
                      
     exec UspSaveEntityActivity_withid 'lead', @EntityId, @ParentId, @ParentId, @EventTemplate, @EventName, 'tbl_lam_UserAssignmentHistory', @assignHistoryId       
      
           
    end try       
    begin catch       
     exec usp_InsertErrorInfo       
    end catch       
      
   END      
  END      
  UPDATERECORD:    
  if @error is not null    
  begin    
  update t set is_processed=1,processed_on=getdate(),error_description=@error from    
  (select top 1 * from tbl_las_LeadRequest(nolock) where leadid=@entityid order by id desc) t    
  end    
    
 END TRY      
 BEGIN CATCH                        
  EXEC usp_InsertErrorInfo;                        
 END CATCH                    
END 


GO

/* ============================================================
   Procedure: [dbo].[ups_las_ReplicaLeadAssignmentUser]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE ups_las_ReplicaLeadAssignmentUser
(
	@EntityId bigint,
	@AsigneeId bigint output
)        
AS        
BEGIN        
BEGIN TRY        
 
 --declare
 --	@EntityId bigint = 8687195 ,
	--@AsigneeId bigint

 DECLARE @ParentId BIGINT,@LeadNo bigint, --@EntityId bigint = 8687195,  
 @EnquirySource bigint = 0, @MobileNo varchar(100)='';    
    
 SELECT @ParentId = [ParentID],@LeadNo=LeadNo, @EnquirySource = isnull(enquirysource, 0), @MobileNo=MobileNo  
 FROM UserLeads(NOLOCK) WHERE [ID] = @EntityId;        
  

 --If(@ParentId=40204 and @MobileNo='7303590417')  
 --Begin  
 --print '--force exited (ups_las_UpdateLeadAssignmentUser)---'  
 --return;  
 --End  
        
 DROP TABLE IF EXISTS #tempRules;        
        
 DECLARE @defaultAssignee BIGINT = 0, @OverwriteAssignedUser BIT, @RuleId BIGINT = 0;        
 SELECT @defaultAssignee = [default_agent], @OverwriteAssignedUser = [overwrite_agent]        
 FROM   tbl_LeadAssignmentMaster(NOLOCK)        
 WHERE  [ParentId] = @ParentId        
     AND [is_active] = 1;        
    
       
  SELECT *, 0 AS [isProcess] INTO [#tempRules]  FROM   tbl_LeadAssignmentRules(NOLOCK)        
  WHERE  [lam_id] IN(SELECT [id] FROM [tbl_LeadAssignmentMaster](NOLOCK) WHERE [ParentId] = @ParentId)        
   AND [is_active] = 1 and isnull(assignment_expression,'') != ''        
  ORDER BY [rule_priority];      
 
	if(exists(select * from [#tempRules]))
	begin
	  WHILE( EXISTS(SELECT 1 FROM #tempRules WHERE [isProcess] = 0) )
	  BEGIN
	   DECLARE @AssignmentExpression NVARCHAR(MAX), @SelectedUser NVARCHAR(500);        
	   SELECT TOP 1 @RuleId = [id], @AssignmentExpression = [assignment_expression], @SelectedUser = [selected_users]      
	   FROM         #tempRules        
	   WHERE        [isProcess] = 0        
	   ORDER BY [rule_priority] ASC;        
        
	   DROP TABLE IF EXISTS #tempColName;        
        
	   SELECT     ROW_NUMBER() OVER(ORDER BY [colName] ASC) AS [SRNo], *, 0 AS [isProcess]        
	   INTO [#tempColName]        
	   FROM             
	   ( SELECT LOWER([COLUMN_NAME]) AS [colName], 'predefined' AS [columnType], 0 AS [FieldId], UPPER(CASE [column_name] WHEN 'CampaignName' THEN 'VARCHAR' WHEN 'MediumName' THEN 'VARCHAR' WHEN 'SourceName' THEN 'VARCHAR' WHEN 'FollowupStatus'  THEN 'VARCHAR' WHEN 'LastFollowupCreatedBy' THEN 'VARCHAR'  WHEN 'AssignedTo' THEN 'VARCHAR'  
		WHEN 'CreatedBy' THEN 'VARCHAR' ELSE [DATA_TYPE] END) AS [DATA_TYPE]        
		FROM     INFORMATION_SCHEMA.COLUMNS(NOLOCK) AS colName        
		WHERE   [TABLE_NAME] = 'UserLeads' and [COLUMN_NAME] not in ('Id')       
		UNION        
		SELECT [fieldname] AS [colName], 'custom' AS [columnType], [field_ID] AS [FieldId], LOWER(( CASE [datatype] WHEN 'd' THEN 'DateTime' WHEN 'f' THEN 'Numeric' WHEN 'v' THEN 'VARCHAR' WHEN 'm' THEN 'VARCHAR' WHEN 'e' THEN 'VARCHAR' WHEN 'r' THEN 'VARCHAR'    
	  WHEN 'c' THEN 'VARCHAR' WHEN 's' THEN 'VARCHAR' END )) AS [DATA_TYPE]      
	   FROM   customfields(NOLOCK)        
	   WHERE  [ParentID] = @ParentId) AS col;        
        
	   -- select * from #tempColName            
	   DECLARE @CondtionString NVARCHAR(MAX) = @AssignmentExpression;        
        
	   WHILE( EXISTS(SELECT 1 FROM #tempColName WHERE [isProcess] = 0) )        
	   BEGIN        
        
		DECLARE @SRNo INT, @colName NVARCHAR(255), @columnType NVARCHAR(255), @FieldId BIGINT, @paramQuery NVARCHAR(MAX), @DataType        
		NVARCHAR(255);        
        
		SELECT TOP 1 @SRNo = [SRNo], @colName = [colName], @columnType = [columnType], @FieldId = [FieldId], @DataType = [DATA_TYPE]        
		FROM         #tempColName        
		WHERE        [isProcess] = 0;        
        
		DECLARE @retParamValue SQL_VARIANT, @ParmDefinition NVARCHAR(500);        
		SET @ParmDefinition = N'@retValInnerOut sql_variant OUTPUT';        
        
		SET @paramQuery = CASE WHEN @columnType = 'predefined'        
		 THEN concat('select @retValInnerOut = ', @colName, ' from UserLeads(nolock) where ID = ', @EntityId)        
		WHEN @columnType = 'custom'        
		 THEN concat('select @retValInnerOut = fieldvalue from customfieldLeadvalue(nolock) where LeadID = ',       
		 @EntityId, ' and fieldID = ', @FieldId)        
		END;        
        
		-- print @paramQuery            
		EXECUTE sp_executesql @paramQuery, @ParmDefinition, @retValInnerOut = @retParamValue OUTPUT;        
        
		SET @retParamValue = (CASE WHEN @colName = 'assignedto'        
		THEN(SELECT [User_Login] FROM User_Detail(NOLOCK) WHERE User_Id = CAST(@retParamValue AS BIGINT))        
		  WHEN @colName = 'sourcename'        
		THEN(SELECT [Name] FROM UserSourceSettings(NOLOCK) WHERE [SourceID] = CAST(@retParamValue AS BIGINT))        
		  WHEN @colName = 'mediumname'        
		THEN(SELECT [Name] FROM UserMediumSettings(NOLOCK) WHERE [MediumID] = CAST(@retParamValue AS BIGINT))        
	  WHEN @colName = 'campaignname'        
		THEN(SELECT [Name] FROM UserCampaignSettings(NOLOCK) WHERE [CampaignID] = CAST(@retParamValue AS        
		BIGINT))        
		  WHEN @colName = 'parentid'        
		THEN(SELECT [User_Login] FROM User_Detail(NOLOCK) WHERE User_Id = CAST(@retParamValue AS BIGINT))        
		  WHEN @colName = 'followupstatus'        
		THEN(SELECT [FollowupStatus] FROM FollowUp_Status(NOLOCK) WHERE [ID] = CAST(@retParamValue AS BIGINT))        
		  WHEN @colName = 'createdby'        
		THEN(SELECT [User_Login] FROM User_Detail(NOLOCK) WHERE User_Id = CAST(@retParamValue AS BIGINT))        
		  WHEN @colName = 'modifiedby'        
		THEN(SELECT [User_Login] FROM User_Detail(NOLOCK) WHERE User_Id = CAST(@retParamValue AS BIGINT))        
		  WHEN @colName = 'enquirysource'        
		THEN(SELECT [Sourcename] FROM enquirysources(NOLOCK) WHERE [id] = CAST(@retParamValue AS INT))        
		  WHEN @colName = ''        
		THEN(SELECT [User_Login] FROM User_Detail(NOLOCK) WHERE User_Id = CAST(@retParamValue AS BIGINT))        
		  ELSE @retParamValue        
		  END );        
        
		print concat('@DataType => ', @DataType, ' @retParamValue => ', cast(@retParamValue as nvarchar), ' @CondtionString  => ', @CondtionString, ' @colName => ', @colName, ' @RuleId => ', @RuleId);

		SET @CondtionString = replace(LOWER(@CondtionString), concat('#', LOWER(@colName), '#'),        
		 ( CASE LOWER(@DataType) 
				WHEN 'nvarchar' THEN concat('''', ISNULL(cast(@retParamValue as nvarchar), ''), '''')        
				WHEN 'varchar' THEN concat('''', ISNULL(CAST(@retParamValue AS NVARCHAR(255)), ''), '''')   
				WHEN 'datetime' THEN concat('''', ISNULL(CAST(@retParamValue AS NVARCHAR(255)), ''), '''')  
			ELSE ISNULL(CAST(@retParamValue AS NVARCHAR(255)), '')  END));        
        
		print concat('@@CondtionString => ', @CondtionString);

		UPDATE #tempColName SET [isProcess] = 1 WHERE [SRNo] = @SRNo;        
        
	   END;        
        
	   DECLARE @retContionValue NVARCHAR(50), @ParmConditionDefinition NVARCHAR(500), @paramConditionQuery NVARCHAR(MAX);        
	   SET @ParmConditionDefinition = N'@retConditionValInnerOut nvarchar(50) OUTPUT';        
	   SET @paramConditionQuery = concat('set @retConditionValInnerOut =  ( select iif( ', @CondtionString, ',''true''', ',''false''))');        
        
	    --select @ParmConditionDefinition, @paramConditionQuery           
		EXECUTE sp_executesql @paramConditionQuery, @ParmConditionDefinition, @retConditionValInnerOut = @retContionValue OUTPUT;        
       

	    --print concat('@retContionValue => ', @retContionValue)            
		IF( @retContionValue = 'true' )        
		BEGIN        
        
			DECLARE @tempAgentTable AS TABLE ( [id] INT IDENTITY(1, 1), [AgentId] BIGINT );        
        
			INSERT INTO @tempAgentTable([AgentId])        
				SELECT [VALUE] FROM fn_Split(@SelectedUser, ',');        
        
			DECLARE @AgentCount INT= (SELECT COUNT(1) FROM @tempAgentTable);        
        
			IF( @AgentCount > 0 )        
			BEGIN        
				DECLARE @LastAgentId BIGINT= (SELECT [lastAssignedUser] FROM tbl_LeadAssignmentRules(nolock) WHERE [id] = @RuleId);        
				DECLARE @LastSrNo INT= (SELECT [id] + 1 FROM @tempAgentTable WHERE [AgentId] = @LastAgentId);        
				IF( NOT EXISTS(SELECT 1 FROM @tempAgentTable WHERE [AgentId] = @LastAgentId) )        
				BEGIN        
				SET @LastSrNo = 1;        
				END;        
        
				SELECT @defaultAssignee = [AgentId] FROM   @tempAgentTable WHERE  [id] = CASE WHEN( @LastSrNo % @AgentCount ) = 0 THEN @AgentCount        
				ELSE @LastSrNo % @AgentCount END;
				UPDATE tbl_LeadAssignmentRules SET [lastAssignedUser] = @defaultAssignee WHERE [id] = @RuleId;        
			END;        
			BREAK;        
			END;        
				select @CondtionString = ''
				UPDATE #tempRules SET [isProcess] = 1 WHERE [id] = @RuleId;     
		END;        
	 
		select @AsigneeId = @defaultAssignee 

		--select @AsigneeId

	end 

END TRY        
BEGIN CATCH        
 EXEC usp_InsertErrorInfo;        
END CATCH    
END



GO

/* ============================================================
   Procedure: [dbo].[ups_las_ReplicaLeadAssignmentUser_bulk]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE ups_las_ReplicaLeadAssignmentUser_bulk      
(      
 @Entities as entities readonly,@batchid bigint,@sequenceactionid bigint,@type nvarchar(50)      
 )              
AS              
BEGIN              
              
      
 DECLARE @ParentId BIGINT,@LeadNo bigint, @EntityId bigint = 0, @AsigneeId bigint,       
 @EnquirySource bigint = 0, @MobileNo varchar(100)='',@e_count int;      
 DECLARE @defaultAssignee BIGINT = 0, @OverwriteAssignedUser BIT, @RuleId BIGINT = 0;              
    
 drop table if exists #entity_assigned     
 create table #entity_assigned (entityid bigint,assignedto bigint)    
    
 select @e_count=count(1) from @Entities    
 print concat('Entries to be reassigned:',@e_count)   
 while @e_count>0    
 begin    
 print 'entered while loop'  
 select @EntityId=min(entityid) from @entities where entityid>@entityid    
 SELECT @ParentId = [ParentID],@LeadNo=LeadNo, @EnquirySource = isnull(enquirysource, 0), @MobileNo=MobileNo        
 FROM UserLeads(NOLOCK) WHERE [ID] = @EntityId;              
        
BEGIN TRY      
 DROP TABLE IF EXISTS #tempRules;              
              
 SELECT @defaultAssignee = [default_agent], @OverwriteAssignedUser = [overwrite_agent]              
 FROM   tbl_LeadAssignmentMaster(NOLOCK) WHERE  [ParentId] = @ParentId AND [is_active] = 1;              
   
   
             
  SELECT *, 0 AS [isProcess] INTO [#tempRules]  FROM   tbl_LeadAssignmentRules(NOLOCK)              
  WHERE  [lam_id] IN(SELECT [id] FROM [tbl_LeadAssignmentMaster](NOLOCK) WHERE [ParentId] = @ParentId)              
   AND [is_active] = 1 and isnull(assignment_expression,'') != ''              
  ORDER BY [rule_priority];            
   
 --select '#temprules',* from #temprules  
  if not exists(select 1 from #temprules)  
  begin  
  print 'No active assignment rules found'  
  end  
  
 if(exists(select * from [#tempRules]))      
 begin      
   WHILE( EXISTS(SELECT 1 FROM #tempRules WHERE [isProcess] = 0) )      
   BEGIN  
   --SELECT '#tempRules',* FROM #tempRules WHERE [isProcess] = 0  
    DECLARE @AssignmentExpression NVARCHAR(MAX), @SelectedUser NVARCHAR(500);              
    SELECT TOP 1 @RuleId = [id], @AssignmentExpression = [assignment_expression], @SelectedUser = [selected_users]            
    FROM         #tempRules              
    WHERE        [isProcess] = 0              
    ORDER BY [rule_priority] ASC;              
              
    DROP TABLE IF EXISTS #tempColName;              
              
    SELECT     ROW_NUMBER() OVER(ORDER BY [colName] ASC) AS [SRNo], *, 0 AS [isProcess]              
    INTO [#tempColName]              
    FROM                   
    ( SELECT LOWER([COLUMN_NAME]) AS [colName], 'predefined' AS [columnType], 0 AS [FieldId], UPPER(CASE [column_name]     
WHEN 'CampaignName' THEN 'VARCHAR' WHEN 'MediumName' THEN 'VARCHAR' WHEN 'SourceName' THEN 'VARCHAR' WHEN 'FollowupStatus'    
  THEN 'VARCHAR' WHEN 'LastFollowupCreatedBy' THEN 'VARCHAR'  WHEN 'AssignedTo' THEN 'VARCHAR'        
  WHEN 'CreatedBy' THEN 'VARCHAR' ELSE [DATA_TYPE] END) AS [DATA_TYPE]              
  FROM     INFORMATION_SCHEMA.COLUMNS(NOLOCK) AS colName              
  WHERE   [TABLE_NAME] = 'UserLeads' and [COLUMN_NAME] not in ('Id')             
  UNION              
  SELECT [fieldname] AS [colName], 'custom' AS [columnType], [field_ID] AS [FieldId], LOWER(( CASE [datatype] WHEN 'd'     
THEN 'DateTime' WHEN 'f' THEN 'Numeric' WHEN 'v' THEN 'VARCHAR' WHEN 'm' THEN 'VARCHAR' WHEN 'e' THEN 'VARCHAR' WHEN 'r'     
THEN 'VARCHAR'     
         
   WHEN 'c' THEN 'VARCHAR' WHEN 's' THEN 'VARCHAR' END )) AS [DATA_TYPE]            
    FROM   customfields(NOLOCK)              
    WHERE  [ParentID] = @ParentId) AS col;              
              
    -- select * from #tempColName                  
    DECLARE @CondtionString NVARCHAR(MAX) = @AssignmentExpression;              
              
    WHILE( EXISTS(SELECT 1 FROM #tempColName WHERE [isProcess] = 0) )              
    BEGIN              
    --select '#tempColName',* from   #tempColName where isprocess=0        
  DECLARE @SRNo INT, @colName NVARCHAR(255), @columnType NVARCHAR(255), @FieldId BIGINT, @paramQuery NVARCHAR(MAX), @DataType              
  NVARCHAR(255);              
              
  SELECT TOP 1 @SRNo = [SRNo], @colName = [colName], @columnType = [columnType], @FieldId = [FieldId], @DataType = [DATA_TYPE]              
  FROM         #tempColName              
  WHERE        [isProcess] = 0;              
              
  DECLARE @retParamValue SQL_VARIANT, @ParmDefinition NVARCHAR(500);              
  SET @ParmDefinition = N'@retValInnerOut sql_variant OUTPUT';              
              
  SET @paramQuery = CASE WHEN @columnType = 'predefined'              
   THEN concat('select @retValInnerOut = ', @colName, ' from UserLeads(nolock) where ID = ', @EntityId)              
  WHEN @columnType = 'custom'              
   THEN concat('select @retValInnerOut = fieldvalue from customfieldLeadvalue(nolock) where LeadID = ',             
   @EntityId, ' and fieldID = ', @FieldId)              
  END;              
              
  -- print @paramQuery                  
  EXECUTE sp_executesql @paramQuery, @ParmDefinition, @retValInnerOut = @retParamValue OUTPUT;              
              
  SET @retParamValue = (CASE WHEN @colName = 'assignedto'              
  THEN(SELECT [User_Login] FROM User_Detail(NOLOCK) WHERE User_Id = CAST(@retParamValue AS BIGINT))              
    WHEN @colName = 'sourcename'              
  THEN(SELECT [Name] FROM UserSourceSettings(NOLOCK) WHERE [SourceID] = CAST(@retParamValue AS BIGINT))              
    WHEN @colName = 'mediumname'              
  THEN(SELECT [Name] FROM UserMediumSettings(NOLOCK) WHERE [MediumID] = CAST(@retParamValue AS BIGINT))              
   WHEN @colName = 'campaignname'              
  THEN(SELECT [Name] FROM UserCampaignSettings(NOLOCK) WHERE [CampaignID] = CAST(@retParamValue AS              
  BIGINT))              
    WHEN @colName = 'parentid'              
  THEN(SELECT [User_Login] FROM User_Detail(NOLOCK) WHERE User_Id = CAST(@retParamValue AS BIGINT))              
    WHEN @colName = 'followupstatus'              
  THEN(SELECT [FollowupStatus] FROM FollowUp_Status(NOLOCK) WHERE [ID] = CAST(@retParamValue AS BIGINT))              
    WHEN @colName = 'createdby'              
  THEN(SELECT [User_Login] FROM User_Detail(NOLOCK) WHERE User_Id = CAST(@retParamValue AS BIGINT))              
    WHEN @colName = 'modifiedby'              
  THEN(SELECT [User_Login] FROM User_Detail(NOLOCK) WHERE User_Id = CAST(@retParamValue AS BIGINT))              
    WHEN @colName = 'enquirysource'              
  THEN(SELECT [Sourcename] FROM enquirysources(NOLOCK) WHERE [id] = CAST(@retParamValue AS INT))              
    WHEN @colName = ''              
  THEN(SELECT [User_Login] FROM User_Detail(NOLOCK) WHERE User_Id = CAST(@retParamValue AS BIGINT))              
    ELSE @retParamValue              
    END );              
              
  print concat('@DataType => ', @DataType, ' @retParamValue => ', cast(@retParamValue as nvarchar), ' @CondtionString  =>     
', @CondtionString, ' @colName => ', @colName, ' @RuleId => ', @RuleId);      
      
  SET @CondtionString = replace(LOWER(@CondtionString), concat('#', LOWER(@colName), '#'),              
   ( CASE LOWER(@DataType)       
    WHEN 'nvarchar' THEN concat('''', ISNULL(cast(@retParamValue as nvarchar), ''), '''')              
    WHEN 'varchar' THEN concat('''', ISNULL(CAST(@retParamValue AS NVARCHAR(255)), ''), '''')         
    WHEN 'datetime' THEN concat('''', ISNULL(CAST(@retParamValue AS NVARCHAR(255)), ''), '''')        
   ELSE ISNULL(CAST(@retParamValue AS NVARCHAR(255)), '')  END));              
              
  print concat('@@CondtionString => ', @CondtionString,', sno: ',@SRNo);      
      
  UPDATE #tempColName SET [isProcess] = 1 WHERE [SRNo] = @SRNo;              
              
    END;              
              
    DECLARE @retContionValue NVARCHAR(50), @ParmConditionDefinition NVARCHAR(500), @paramConditionQuery NVARCHAR(MAX);              
    SET @ParmConditionDefinition = N'@retConditionValInnerOut nvarchar(50) OUTPUT';              
    SET @paramConditionQuery = concat('set @retConditionValInnerOut =  ( select iif( ', @CondtionString, ',''true''', ',''false''))');              
              
     --select @ParmConditionDefinition, @paramConditionQuery                 
  EXECUTE sp_executesql @paramConditionQuery, @ParmConditionDefinition, @retConditionValInnerOut = @retContionValue OUTPUT;              
             
      
     --print concat('@retContionValue => ', @retContionValue)                  
  IF( @retContionValue = 'true' )              
  BEGIN              
              
   DECLARE @tempAgentTable AS TABLE ( [id] INT IDENTITY(1, 1), [AgentId] BIGINT );              
              
   INSERT INTO @tempAgentTable([AgentId])              
    SELECT [VALUE] FROM fn_Split(@SelectedUser, ',');              
              
   DECLARE @AgentCount INT= (SELECT COUNT(1) FROM @tempAgentTable);              
              
   IF( @AgentCount > 0 )              
   BEGIN              
    DECLARE @LastAgentId BIGINT= (SELECT [lastAssignedUser] FROM tbl_LeadAssignmentRules(nolock) WHERE [id] = @RuleId);              
    DECLARE @LastSrNo INT= (SELECT [id] + 1 FROM @tempAgentTable WHERE [AgentId] = @LastAgentId);              
    IF( NOT EXISTS(SELECT 1 FROM @tempAgentTable WHERE [AgentId] = @LastAgentId) )              
    BEGIN              
    SET @LastSrNo = 1;              
    END;              
              
    SELECT @defaultAssignee = [AgentId] FROM   @tempAgentTable WHERE  [id] = CASE WHEN( @LastSrNo % @AgentCount ) = 0 THEN    
 @AgentCount              
    ELSE @LastSrNo % @AgentCount END;      
    UPDATE tbl_LeadAssignmentRules SET [lastAssignedUser] = @defaultAssignee WHERE [id] = @RuleId;              
   END;              
   BREAK;              
   END;              
    select @CondtionString = ''      
    UPDATE #tempRules SET [isProcess] = 1 WHERE [id] = @RuleId;           
  END;              
        
  select @AsigneeId = @defaultAssignee       
      
  print concat( '@AsigneeId: ',@AsigneeId    )  
      
 end       
      
END TRY              
BEGIN CATCH              
 EXEC usp_InsertErrorInfo;              
 print 'entered catch block'  
END CATCH          
    
insert into #entity_assigned(entityid,assignedto)    
select @EntityId,isnull(nullif(@AsigneeId,0),dbo.fn_getleadowner(@entityid))    
set @e_count=@e_count-1    
  
declare @a_c int=(select count(1) from #entity_assigned)  
print concat('entities assigned till now: ',@a_c,', total left: ',@e_count)  
END      
  
  
insert into mass_replaced_content(entity,entityid,replacedcontent,batchid,sequenceactionid,type)    
select 'lead',entityid,assignedto,@batchid,@sequenceactionid,@type from #entity_assigned    
end


GO

/* ============================================================
   Procedure: [dbo].[ups_las_UpdateLeadAssignmentUser]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--sp_helptext    ups_las_UpdateLeadAssignmentUser @EntityId = @LeadId    --14363159  
CREATE   PROCEDURE [dbo].[ups_las_UpdateLeadAssignmentUser] --14641025   
(              
    @EntityId BIGINT              
)                      
AS    
BEGIN                      
 BEGIN TRY    
      
        -- Uncomment the following line to enable debugging.    
  --DECLARE @EntityId bigint = 14641025 --1691907     
    
  DECLARE @ParentId BIGINT, @LeadNo bigint, @EnquirySource bigint = 0, @MobileNo varchar(100)= '', @isnewlead int = 1,@error nvarchar(2000),@OldAssignedTo bigint;    
    

  SELECT @ParentId = [ParentID], @LeadNo = LeadNo, @OldAssignedTo=AssignedTo, @EnquirySource = isnull(enquirysource, 0), @MobileNo = MobileNo    
   FROM UserLeads(NOLOCK) WHERE [ID] = @EntityId;    
    

  --If(@ParentId=40204 and @MobileNo='7303590417')    
  --begin    
  --print '--force exited (ups_las_UpdateLeadAssignmentUser)---'    
  --return;    
  --end    
    
  DROP TABLE IF EXISTS #tempRules    
    
    
  DECLARE @defaultAssignee BIGINT = 0, @OverwriteAssignedUser BIT, @RuleId BIGINT = 0, @leadAssignmentId bigint = 0;    
    
  if exists (select 1 from tbl_LeadAssignmentMaster(NOLOCK) WHERE [ParentId] = @ParentId AND [is_active] = 1 )  
  begin  
  SELECT @defaultAssignee = [default_agent], @OverwriteAssignedUser = [overwrite_agent], @leadAssignmentId = id    
   FROM tbl_LeadAssignmentMaster(NOLOCK) WHERE [ParentId] = @ParentId AND [is_active] = 1;   
   end  
  else  
  begin  
  select @error='No active asssignment rule'  
  print 'No active rule for parent'  
  goto UPDATERECORD  
  end  
  
        print concat('Start @defaultAssignee => ', @defaultAssignee)    
    
  --Code is commented because segmentation needs to run in parallel.    
  --if(exists(select 1 from tbl_LeadAssignmentRules(nolock) where lam_id = @leadAssignmentId and RuleType = 'SegmentCondition'))    
  --begin    
  --print 'Checking SegmentCondition Rule'    
  --exec ups_las_UpdateLeadAssignmentUserBySegment @EntityId    
  --return;    
  --end    
    
  if isnull(@EnquirySource, 0) in(12, 13, 14, 15, 22, 23, 24, 28, 29, 30,21)     
   and ( select count(1) from leadinteractionhistory(nolock) where id_lead = @entityid) > 1     
  begin     
   select @isnewlead = 0     
  end     
    
  IF(@OverwriteAssignedUser = 1 OR ( @OverwriteAssignedUser = 0     
     and ( isnull(@EnquirySource, 0) not in(12, 13, 14, 15, 22, 23, 24, 28, 29, 30,21) or @isnewlead = 0)))     
  BEGIN     
   print 'Overwrite'    
   SELECT *, 0 AS [isProcess] INTO #tempRules FROM tbl_LeadAssignmentRules(NOLOCK)    
    WHERE [lam_id] IN( SELECT [id] FROM [tbl_LeadAssignmentMaster](NOLOCK)     
    WHERE [ParentId] = @ParentId) AND [is_active] = 1 --and isnull(assignment_expression, '') != ''     
   ORDER BY [rule_priority];    
     
   if(exists(select 1 from #tempRules))              
   begin     
    WHILE(EXISTS(SELECT 1 FROM #tempRules WHERE [isProcess] = 0))    
    BEGIN     
     DECLARE @AssignmentExpression NVARCHAR(MAX), @SelectedUser NVARCHAR(500), @RuleType nvarchar(255) = '',     
      @SettingJSON nvarchar(max) = '{}', @logicalOperator nvarchar(25) = '', @isSegmentMatched bit = 0;    
    
     SELECT TOP 1 @RuleId = [id], @AssignmentExpression = [assignment_expression], @SelectedUser = [selected_users],    
      @RuleType = RuleType, @SettingJSON = SettingJSON, @logicalOperator = logical_operator     
       FROM #tempRules WHERE [isProcess] = 0 ORDER BY [rule_priority] ASC;    
    
     declare @isRuleMatched bit = 0;    
    
     if(isnull(@RuleType, '') = '')    
     begin    
      if(isnull(@AssignmentExpression, '') <> '')    
      begin    
       print 'Conditional'    
    
       DROP TABLE IF EXISTS #tempColName;    
    
       SELECT  ROW_NUMBER() OVER( ORDER BY [colName] ASC ) AS [SRNo],     
        *,  0 AS [isProcess] INTO #tempColName FROM  ( SELECT    
         LOWER([COLUMN_NAME]) AS [colName], 'predefined' AS [columnType], 0 AS [FieldId],     
         UPPER( CASE [column_name]     
          WHEN 'CampaignName' THEN 'VARCHAR'     
          WHEN 'MediumName' THEN 'VARCHAR'     
        WHEN 'SourceName' THEN 'VARCHAR'     
          WHEN 'FollowupStatus' THEN 'VARCHAR'     
          WHEN 'LastFollowupCreatedBy' THEN 'VARCHAR'    
          WHEN 'AssignedTo' THEN 'VARCHAR'    
          WHEN 'CreatedBy' THEN 'VARCHAR'    
         ELSE [DATA_TYPE] END ) AS [DATA_TYPE]     
         FROM INFORMATION_SCHEMA.COLUMNS(NOLOCK) AS colName     
          WHERE [TABLE_NAME] = 'UserLeads' and [COLUMN_NAME] not in ('Id', 'productsjson')     
        UNION     
        SELECT     
         [fieldname] AS [colName],     
         'custom' AS [columnType],    
         [field_ID] AS [FieldId],     
         LOWER(( CASE [datatype]     
          WHEN 'd' THEN 'DateTime'     
          WHEN 'f' THEN 'Numeric'     
          WHEN 'v' THEN 'VARCHAR'     
          WHEN 'm' THEN 'VARCHAR'     
          WHEN 'e' THEN 'VARCHAR'     
          WHEN 'r' THEN 'VARCHAR'     
          WHEN 'c' THEN 'VARCHAR'     
          WHEN 's' THEN 'VARCHAR'     
         END )) AS [DATA_TYPE]    
         FROM customfields(NOLOCK)     
          WHERE [ParentID] = @ParentId ) AS col;    
            
       -- select * from #tempColName    
       DECLARE @CondtionString NVARCHAR(MAX) = @AssignmentExpression;    
       WHILE( EXISTS(SELECT 1 FROM #tempColName WHERE [isProcess] = 0))                      
       BEGIN     
        DECLARE @SRNo INT, @colName NVARCHAR(255), @columnType NVARCHAR(255), @FieldId BIGINT, @paramQuery NVARCHAR(MAX), @DataType NVARCHAR(255);    
        SELECT TOP 1 @SRNo = [SRNo], @colName = [colName], @columnType = [columnType], @FieldId = [FieldId], @DataType = [DATA_TYPE]     
         FROM  #tempColName WHERE [isProcess] = 0;    
    
        DECLARE @retParamValue SQL_VARIANT, @ParmDefinition NVARCHAR(500);    
    
        SET @ParmDefinition = N'@retValInnerOut sql_variant OUTPUT';    
        SET @paramQuery = ( CASE     
          WHEN @columnType = 'predefined'     
           THEN concat('select @retValInnerOut = ', @colName, ' from UserLeads(nolock) where ID = ', @EntityId)     
          WHEN @columnType = 'custom'     
           THEN concat( 'select @retValInnerOut = fieldvalue from customfieldLeadvalue(nolock) where LeadID = ', @EntityId, ' and fieldID = ', @FieldId)    
         END);    
    
        -- print @paramQuery                          
        EXECUTE sp_executesql @paramQuery, @ParmDefinition, @retValInnerOut = @retParamValue OUTPUT;    
                
        SET @retParamValue = ( CASE     
         WHEN @colName = 'assignedto'     
          THEN (SELECT [User_Login] FROM User_Detail(NOLOCK) WHERE User_Id = CAST(@retParamValue AS BIGINT))     
         WHEN @colName = 'sourcename'     
          THEN (SELECT [Name] FROM UserSourceSettings(NOLOCK) WHERE [SourceID] = CAST(@retParamValue AS BIGINT))     
         WHEN @colName = 'mediumname'     
          THEN (SELECT [Name] FROM UserMediumSettings(NOLOCK) WHERE [MediumID] = CAST(@retParamValue AS BIGINT))     
         WHEN @colName = 'campaignname'     
          THEN (SELECT [Name] FROM UserCampaignSettings(NOLOCK) WHERE [CampaignID] = CAST(@retParamValue AS BIGINT))    
         WHEN @colName = 'parentid'     
          THEN (SELECT [User_Login] FROM User_Detail(NOLOCK) WHERE User_Id = CAST(@retParamValue AS BIGINT))    
         WHEN @colName = 'followupstatus'     
          THEN (SELECT [FollowupStatus] FROM FollowUp_Status(NOLOCK) WHERE [ID] = CAST(@retParamValue AS BIGINT))     
         WHEN @colName = 'createdby'     
          THEN (SELECT [User_Login] FROM User_Detail(NOLOCK) WHERE User_Id = CAST(@retParamValue AS BIGINT))     
         WHEN @colName = 'modifiedby'     
          THEN (SELECT [User_Login] FROM User_Detail(NOLOCK) WHERE User_Id = CAST(@retParamValue AS BIGINT))    
         WHEN @colName = 'enquirysource'     
          THEN (SELECT [Sourcename] FROM enquirysources(NOLOCK) WHERE [id] = CAST(@retParamValue AS INT))     
         WHEN @colName = ''     
          THEN (SELECT [User_Login] FROM User_Detail(NOLOCK) WHERE User_Id = CAST(@retParamValue AS BIGINT))              ELSE @retParamValue END);    
                
        --print concat('@DataType => ', @DataType, ' @retParamValue => ', cast(@retParamValue as nvarchar), ' @CondtionString  => ', @CondtionString, ' @colName => ', @colName, ' @RuleId => ', @RuleId );    
    
        SET @CondtionString = replace(LOWER(@CondtionString), concat( '#', LOWER(@colName), '#'),     
          (CASE LOWER(@DataType)     
           WHEN 'nvarchar' THEN concat('''', ISNULL(cast(@retParamValue as nvarchar),''),'''')     
           WHEN 'varchar' THEN concat('''', ISNULL(CAST(@retParamValue AS NVARCHAR(255)),''), '''')     
           WHEN 'datetime' THEN concat('''', ISNULL(CAST(@retParamValue AS NVARCHAR(255)), ''), '''')     
           ELSE ISNULL(CAST( @retParamValue AS NVARCHAR(255)), '')     
          END ));    
    
        --print concat('@@CondtionString => ', @CondtionString);    
        UPDATE #tempColName SET [isProcess] = 1 WHERE [SRNo] = @SRNo;    
    
       END;    
    
       DECLARE @retContionValue NVARCHAR(50), @ParmConditionDefinition NVARCHAR(500), @paramConditionQuery NVARCHAR(MAX);    
            
       SET @ParmConditionDefinition = N'@retConditionValInnerOut nvarchar(50) OUTPUT';    
       SET @paramConditionQuery = concat(N'set @retConditionValInnerOut =  ( select iif( ', @CondtionString, ',''true''', ',''false''))');    
    
       --select @ParmConditionDefinition, @paramConditionQuery                         
       EXECUTE sp_executesql @paramConditionQuery, @ParmConditionDefinition, @retConditionValInnerOut = @retContionValue OUTPUT;    
    
       print concat('@retContionValue => ', @retContionValue)     
            
       IF(@retContionValue = 'true')     
       BEGIN     
        set @isRuleMatched = 1;     
        update #tempRules set isProcess = 1      
       END;    
       select @CondtionString = ''    
      end    
     end    
     else    
     begin    
      print 'Segmentations'    
    
      if(isnull(@SettingJSON, '') <> '')      
      begin      
       declare       
        @EntityName nvarchar(20) = 'lead', @CriteriaID bigint, @outStatus int = 0      
           
       print @SettingJSON      
      
       drop table if exists #tempSegmentations      
      
       select SegmentId, SegmentName, cast(0 as bit) isProccess into #tempSegmentations       
        from openjson(json_query(@SettingJSON, '$.Segmentations')) with (      
        SegmentId bigint '$.SegmentId',      
        SegmentName nvarchar(255) '$.SegmentName'      
       )      
      
       declare @segmentId bigint = 0      
       while(exists(select 1 from #tempSegmentations where isProccess = 0))      
       begin      
        select top 1 @segmentId = SegmentId from #tempSegmentations(nolock) where isProccess = 0      
      
        print concat('@segmentId => ', @segmentId)    
        print concat('@logicalOperator => ', @logicalOperator)    
      
        print concat('before Usp_ContactExistsInSearch @outStatus => ', @outStatus)      
        exec Usp_ContactExistsInSearch        
        @entityname = @EntityName, @entityid = @EntityId, @CriteriaID = @segmentId,  @Status = @outStatus output                     
        print concat('after Usp_ContactExistsInSearch @outStatus => ', @outStatus)      
        
           
        if(@logicalOperator = 'or' and @outStatus = 1)     
        begin      
         print 'OR Rule Matched'      
         update #tempSegmentations set isProccess = 1      
        end      
           
        if(@logicalOperator = 'and' and @outStatus =  0)      
        begin      
         print 'And Rule Matched'      
         update #tempSegmentations set isProccess = 1       
        end      
      
        set @isSegmentMatched = @outStatus      
      
        update #tempSegmentations set isProccess = 1 where SegmentId = @segmentId      
        select @outStatus = 0      
       end      
         
                            if(@isSegmentMatched = 1)  -- check @isSegmentMatched is true or not    
                            begin      
                             set @isRuleMatched = 1;     
        set @retContionValue = 'true'    
                                update #tempRules set isProcess = 1      
                            end    
                                
                            print concat('All Segment is completed of ruleId => ', @RuleId)      
                        end      
      
      print concat(' @isSegmentMatched => ', @isSegmentMatched)    
     end    
    
     --Reset veriable    
     select @logicalOperator = '', @SettingJSON = '', @AssignmentExpression = ''    
    
     --updating current rule that is processed    
     UPDATE #tempRules SET [isProcess] = 1 WHERE [id] = @RuleId;    
    END -- #tempRules whle end    
    
    if(@isRuleMatched = 1)    
    begin    
       
     DECLARE @tempAgentTable AS TABLE ( [id] INT IDENTITY(1, 1), [AgentId] BIGINT );                
     INSERT INTO @tempAgentTable([AgentId])    
      SELECT [VALUE] FROM fn_Split(@SelectedUser, ',');    
    
     DECLARE @AgentCount INT = (SELECT COUNT(1) FROM @tempAgentTable );    
    
     IF(@AgentCount > 0)     
     BEGIN    
           
      print concat('@SelectedUser => ', @SelectedUser)    
           
      DECLARE @LastAgentId BIGINT = (SELECT [lastAssignedUser] FROM tbl_LeadAssignmentRules(nolock) WHERE [id] = @RuleId);    
      DECLARE @LastSrNo INT = (SELECT [id] + 1 FROM @tempAgentTable WHERE [AgentId] = @LastAgentId);    
    
      IF(NOT EXISTS(SELECT 1 FROM @tempAgentTable WHERE [AgentId] = @LastAgentId))    
      BEGIN     
       SET @LastSrNo = 1;    
      END;    
    
      SELECT @defaultAssignee = [AgentId] FROM @tempAgentTable     
       WHERE [id] = CASE WHEN(@LastSrNo % @AgentCount) = 0 THEN @AgentCount ELSE @LastSrNo % @AgentCount END;    
           
      UPDATE tbl_LeadAssignmentRules SET [lastAssignedUser] = @defaultAssignee WHERE [id] = @RuleId;    
    
      print concat( 'After rule matched @defaultAssignee: ', @defaultAssignee)     
    
     END;    
    END    
    
    print concat( 'Final: @defaultAssignee: ', @defaultAssignee)    
    
    
    declare @LeadInteractionId bigint = 0;    
    update UserLeads SET [AssignedTo] = @defaultAssignee WHERE [ID] = @EntityId;    
    
		set context_info 0x55555

    if exists(select 1 from LeadInteractionHistory(nolock) where leadno = @leadno and parentid = @parentid )     
    begin  
     insert into LeadInteractionHistory(LeadNo, FollowUpStatus, NextStatusDate,Remarks, Products, AmountPaid, AssignedTo,    
      ParentID, CreatedOn, CreatedBy, FollowupDate, IsReassign, id_lead)    
     select top 1 LeadNo,  FollowUpStatus, NextStatusDate, Remarks, Products, AmountPaid, @defaultAssignee,    
       ParentID, getdate(), CreatedBy, FollowupDate, IsReassign, @entityid from LeadInteractionHistory(nolock)     
      where ParentID = @ParentId and LeadNo = @LeadNo order by ID desc     
                
     set @LeadInteractionId = scope_identity()  

    end     
    else     
    begin     
     insert into LeadInteractionHistory(LeadNo, FollowUpStatus, NextStatusDate, Remarks, Products, AmountPaid, AssignedTo,     
      ParentID, CreatedOn, CreatedBy, FollowupDate, IsReassign, id_lead )     
     select LeadNo, FollowUpStatus, NextStatusDate, Remarks, Products, AmountPaid, @defaultAssignee,     
      ParentID, getdate(), CreatedBy, FollowupDate, 0, id     
      from userleads(nolock) where id = @EntityId     
                
     set @LeadInteractionId = scope_identity()     
    end     
	 	set context_info 0x00000


            
    if( isnull(@LeadInteractionId, 0) > 0 )     
    begin     
     insert into tbl_LeadEventHistory(leadid, UserID, parentid, EventID, EventDescription, RefTables, refids)     
     select @EntityId, ul.createdby, ul.parentid, 37,  concat( 'Lead with ', case when isnull(     
       nullif(ul.personname, ''), '' ) <> '' then concat('name ', ul.personname) else concat( 'leadno ',    
       cast(ul.leadno as nvarchar) ) end, ' is assigned to ', a.user_login ), 'LeadInteractionhistory', @LeadInteractionId     
      from userleads(nolock) ul inner join User_Detail(nolock) a on ul.AssignedTo = a.User_ID     
     where ul.ID = @EntityId     
    end     
      
     
    
    insert into tbl_lam_UserAssignmentHistory( parentid, assignedUserId, ruleid, leadId)     
                
    select @ParentId, @defaultAssignee, (case when @retContionValue = 'true' then @RuleId else 0 end),    
     @EntityId declare @assignHistoryId bigint = scope_identity()     
    
    begin try     
     declare @UserName nvarchar(255) = '', @RuleName nvarchar(255) = '';    
                    
     if(@defaultAssignee > 0)     
     begin    
      select @UserName = User_Login from User_Detail(nolock) where User_ID = @defaultAssignee     
     end     
                    
     if( @defaultAssignee > 0 and @retContionValue = 'true' )     
     begin     
      select @RuleName = rule_name from tbl_LeadAssignmentRules(nolock) where id = @RuleId     
     end     
    
     begin try     
      if (@RuleId <= 0)     
      begin     
       if not exists(select 1 from tbl_LeadEventHistory(nolock) where leadid = @EntityId and eventid = 10)     
        and exists (select 1 from leadinteractionhistory_latest(nolock) where leadno = @LeadNo and parentid = @ParentId)     
       begin     
        declare @lih_idf bigint, @assi_id bigint, @fo_status bigint, @createdby bigint, @createduser nvarchar(100), @assign_user nvarchar(100),     
         @eventdate datetime, @ev nvarchar(200)= 'New Interaction added', @eve_d nvarchar(2000), @foll_status nvarchar(100)     
                                
        select top 1 @lih_idf = id, @assi_id = AssignedTo, @fo_status = FollowUpStatus, @createdby = createdby, @eventdate = CreatedOn     
         from  leadinteractionhistory_latest(nolock)  where leadno = @LeadNo and parentid = @ParentId     
                                
        select @assign_user = user_login from user_detail(nolock) where user_id = @assi_id     
        select @createduser = user_login from user_detail(nolock) where user_id = isnull(nullif(@createdby, 0), @parentid)    
        select @foll_status = FollowupStatus from followup_status(nolock) where ID = @fo_status    
        select @eve_d = concat(@createduser, ' added a followup with status ', @foll_status, '. Lead was assigned to ', isnull(@assign_user, 'no one'))    
                                
        exec UspSaveEntityActivity_withid 'lead', @EntityId, @ParentId, @ParentId, @eve_d, @ev, 'leadinteractionhistory', @lih_idf     
       end     
      end     
     end try     
     begin catch     
      exec usp_InsertErrorInfo     
     end catch     
                    
     declare @EventName nvarchar(255) = ( case when @RuleId > 0      
      and @retContionValue = 'true' then 'Lead is reassigned' else 'Lead is no reassigned' end);    
    
     declare @EventTemplate nvarchar(max) = (case when @RuleId > 0 and @retContionValue = 'true'     
       then concat( 'The lead is reassigned to ', @UserName, ' as per lead assignment rule where the rule name is ', @RuleName, '.')     
       else 'The lead is not reassigned to anyone because no lead assignment rule matches' end);    
                    
     exec UspSaveEntityActivity_withid 'lead', @EntityId, @ParentId, @ParentId, @EventTemplate, @EventName, 'tbl_lam_UserAssignmentHistory', @assignHistoryId     
    
         
    end try     
    begin catch     
     exec usp_InsertErrorInfo     
    end catch     
    
   END    
  END    
  UPDATERECORD:  
  if @error is not null  
  begin  
  update t set is_processed=1,processed_on=getdate(),error_description=@error from  
  (select top 1 * from tbl_las_LeadRequest(nolock) where leadid=@entityid order by id desc) t  
  end  
  
 END TRY    
 BEGIN CATCH                      
  EXEC usp_InsertErrorInfo;                      
 END CATCH                  
END 


GO

/* ============================================================
   Procedure: [dbo].[ups_las_UpdateLeadAssignmentUserBySegment]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON





------ modify  this  sp lead assignment behalf  on collaborator  also

CREATE   PROCEDURE [dbo].[ups_las_UpdateLeadAssignmentUserBySegment]
(
    @EntityId bigint
)
AS
BEGIN
    SET NOCOUNT ON;

   --declare @EntityId bigint = 18727504  
   
    DECLARE @ParentId bigint = 0, @EnquirySource int = 0, @IsNewlead int = 1, @LeadNo bigint, @MobileNo varchar(100) = '';
    
    SELECT @ParentId = [ParentID], @LeadNo = LeadNo, @EnquirySource = ISNULL(enquirysource, 0), @MobileNo = MobileNo
    FROM UserLeads(NOLOCK) WHERE [ID] = @EntityId;

    drop table if exists #tblRule 
    
    DECLARE @defaultAssignee bigint = 0, @OverwriteAssignedUser bit, @RuleId bigint = 0;
    SELECT @defaultAssignee = [default_agent], @OverwriteAssignedUser = [overwrite_agent]
    FROM tbl_LeadAssignmentMaster(NOLOCK) WHERE [ParentId] = @ParentId AND [is_active] = 1;  
   
    IF ISNULL(@EnquirySource, 0) IN (12, 13, 14, 15, 22, 23, 24, 28, 29, 30) AND
       (SELECT COUNT(1) FROM leadinteractionhistory(NOLOCK) WHERE id_lead = @entityid) > 1
    BEGIN
        SET @IsNewlead = 0
    END

    
    
    IF (@OverwriteAssignedUser = 1 OR (@OverwriteAssignedUser = 0 AND (ISNULL(@EnquirySource, 0) NOT IN (12, 13, 14, 15, 22, 23, 24, 28, 29, 30) OR @IsNewlead = 0)))  
    BEGIN
        DROP TABLE IF EXISTS #tempRules;
        SELECT *, 0 AS [isProcess] INTO #tempRules FROM tbl_LeadAssignmentRules(NOLOCK)
        WHERE [lam_id] IN (SELECT [id] FROM [tbl_LeadAssignmentMaster](NOLOCK) WHERE [ParentId] = @ParentId)
        AND [is_active] = 1 AND RuleType = 'SegmentCondition'
        ORDER BY [rule_priority] ASC;

        DECLARE @SettingJSON nvarchar(max) = '{}', @logicalOperator nvarchar(25) = 'and', @isSegmentMatched bit = 0, @SelectedUser NVARCHAR(500);

        WHILE (EXISTS(SELECT * FROM #tempRules WHERE isProcess = 0))
        BEGIN
            print 'Segment Condition exists'  
            
            SELECT TOP 1 @RuleId = id, @SettingJSON = SettingJSON, @logicalOperator = logical_operator, @SelectedUser = selected_users
            FROM #tempRules WHERE isProcess = 0 ORDER BY rule_priority ASC;

            IF (ISNULL(@SettingJSON, '') <> '')
            BEGIN
            print @SettingJSON 
                DROP TABLE IF EXISTS #tempSegmentations;
                SELECT SegmentId, SegmentName, CAST(0 AS bit) isProccess INTO #tempSegmentations
                FROM OPENJSON(JSON_QUERY(@SettingJSON, '$.Segmentations')) WITH (
                    SegmentId bigint '$.SegmentId',
                    SegmentName nvarchar(255) '$.SegmentName'
                );

                DECLARE @EntityName nvarchar(20) = 'lead', @CriteriaID bigint, @outStatus int = 0, @segmentId bigint = 0;
               
               

                WHILE (EXISTS(SELECT 1 FROM #tempSegmentations WHERE isProccess = 0))
                BEGIN
                    SELECT TOP 1 @segmentId = SegmentId FROM #tempSegmentations(NOLOCK) WHERE isProccess = 0;
                print concat('@segmentId => ', @segmentId)
	            print concat('@logicalOperator => ', @logicalOperator)
  
	            print concat('before Usp_ContactExistsInSearch @outStatus => ', @outStatus)
                                                                      
                    EXEC Usp_ContactExistsInSearch
                        @entityname = @EntityName, @entityid = @EntityId, @CriteriaID = @segmentId, @Status = @outStatus OUTPUT;

                print concat('after Usp_ContactExistsInSearch @outStatus => ', @outStatus)  
      
                      
                  if(@logicalOperator = 'or' and @outStatus = 1)  
                  begin  
                   print 'Rule Matched'  
                   update #tempSegmentations set isProccess = 1  
                  end  
                    
                  if(@logicalOperator = 'and' and @outStatus =  0)  
                  begin  
                   print 'And Rule Matched'  
                   update #tempSegmentations set isProccess = 1   
                  end 
                    
                    SET @isSegmentMatched = @outStatus;
                    UPDATE #tempSegmentations SET isProccess = 1 WHERE SegmentId = @segmentId;
                    SELECT @outStatus = 0;
                END
                 print concat('All Segment is completed of ruleId => ', @RuleId)  
            END
				print concat(' @isSegmentMatched => ', @isSegmentMatched)
            
            
            
                if(@isSegmentMatched = 1)  
               begin  
                update #tempRules set isProcess = 1  
               end  
               update #tempRules set isProcess = 1 where id = @RuleId  
              end 

       
       
            if(@isSegmentMatched = 0)  
            begin  
             select @RuleId = 0  
            end

       
       
            IF (@isSegmentMatched = 1)
            BEGIN
            DECLARE @tempAgentTable TABLE ([id] INT IDENTITY(1, 1), [AgentId] BIGINT);

	        print concat('@SelectedUser => ', @SelectedUser)
            -- Insert selected users
            IF (@SelectedUser IS NOT NULL AND @SelectedUser <> '')
            BEGIN
                INSERT INTO @tempAgentTable([AgentId])
                SELECT [VALUE] FROM fn_Split(@SelectedUser, ',');
            END

            -- Insert collaborator team users and mapping
            DECLARE @CollabTeams NVARCHAR(MAX) = (SELECT CollaborationTeam FROM tbl_LeadAssignmentRules WHERE id = @RuleId);
			DECLARE @RuleTypeId NVARCHAR(MAX) = (SELECT ColloborationType FROM tbl_LeadAssignmentRules WHERE id = @RuleId);

           IF (@CollabTeams IS NOT NULL AND @CollabTeams <> '')
           BEGIN
               -- Insert active users of all teams into @tempAgentTable
               INSERT INTO @tempAgentTable([AgentId])
               SELECT user_id
               FROM tbl_coll_Collaboratorteams_user_mapping
               WHERE isactive = 1
                 AND team_id IN (SELECT value FROM STRING_SPLIT(@CollabTeams, ','))
           
               -- Insert mapping records for each user in these teams, fetching typeid as well
               INSERT INTO tbl_coll_Lead_collaborator_mapping(entityId, entityname, typeid, teamid, createdon, createdby, isactive, userid)
               SELECT
                   @EntityId,
                   'lead',
                   @RuleTypeId,
                   team_id,
                   GETDATE(),
                   @defaultAssignee,
                   1,
                   user_id
               FROM tbl_coll_Collaboratorteams_user_mapping
               WHERE isactive = 1
                 AND team_id IN (SELECT value FROM STRING_SPLIT(@CollabTeams, ','))
           END
           
            -- Assign the lead to the first user (existing logic, can be changed to loop for all)
            SELECT TOP 1 @defaultAssignee = [AgentId] FROM @tempAgentTable;
			 DECLARE @AgentCount INT= (SELECT COUNT(1) FROM @tempAgentTable);        
	 
                    
              IF( @AgentCount > 0 )                    
              BEGIN                    
               DECLARE @LastAgentId BIGINT= (SELECT [lastAssignedUser] FROM tbl_LeadAssignmentRules(nolock) WHERE [id] = @RuleId);                    
               DECLARE @LastSrNo INT= (SELECT [id] + 1 FROM @tempAgentTable WHERE [AgentId] = @LastAgentId);                    
               IF( NOT EXISTS(SELECT 1 FROM @tempAgentTable WHERE [AgentId] = @LastAgentId) )                    
               BEGIN                    
                SET @LastSrNo = 1;                    
               END;                    
                               
               SELECT @defaultAssignee = [AgentId] FROM   @tempAgentTable WHERE  [id] = CASE WHEN( @LastSrNo % @AgentCount ) = 0 THEN @AgentCount                    
               ELSE @LastSrNo % @AgentCount END;            
               UPDATE tbl_LeadAssignmentRules SET [lastAssignedUser] = @defaultAssignee WHERE [id] = @RuleId;                    
               
               print concat('1:@defaultAssignee: ',@defaultAssignee)                      
              END;                           
              UPDATE #tempRules SET [isProcess] = 1 WHERE [id] = @RuleId;  
                
             
                       
             end  
             print concat('@RuleMapped => ', @RuleId)  
             UPDATE UserLeads SET [AssignedTo] = @defaultAssignee WHERE [ID] = @EntityId;

            -- LeadInteractionHistory logic
            DECLARE @LeadInteractionId bigint = 0;
           
           
           
           
           
            IF EXISTS(SELECT 1 FROM LeadInteractionHistory(NOLOCK) WHERE leadno = @LeadNo AND parentid = @ParentId)
            BEGIN
                INSERT INTO LeadInteractionHistory(LeadNo, FollowUpStatus, NextStatusDate, Remarks, Products, AmountPaid, AssignedTo, ParentID, CreatedOn, CreatedBy, FollowupDate, IsReassign, id_lead)
                SELECT TOP 1 LeadNo, FollowUpStatus, NextStatusDate, Remarks, Products, AmountPaid, @defaultAssignee, ParentID, GETDATE(), CreatedBy, FollowupDate, IsReassign, @EntityId
                FROM LeadInteractionHistory(NOLOCK) WHERE ParentID = @ParentId AND LeadNo = @LeadNo ORDER BY ID DESC;
                SET @LeadInteractionId = SCOPE_IDENTITY();
            END
            ELSE
            BEGIN
                INSERT INTO LeadInteractionHistory(LeadNo, FollowUpStatus, NextStatusDate, Remarks, Products, AmountPaid, AssignedTo, ParentID, CreatedOn, CreatedBy, FollowupDate, IsReassign, id_lead)
                SELECT LeadNo, FollowUpStatus, NextStatusDate, Remarks, Products, AmountPaid, @defaultAssignee, ParentID, GETDATE(), CreatedBy, FollowupDate, 0, id
                FROM userleads(NOLOCK) WHERE id = @EntityId;
                SET @LeadInteractionId = SCOPE_IDENTITY();
            END

            IF(ISNULL(@LeadInteractionId, 0) > 0)
            BEGIN
                INSERT INTO tbl_LeadEventHistory(leadid, UserID, parentid, EventID, EventDescription, RefTables, refids)
                SELECT @EntityId, ul.createdby, ul.parentid, 37, CONCAT('Lead with ',
                    CASE WHEN ISNULL(NULLIF(ul.personname, ''), '') <> '' THEN CONCAT('name ', ul.personname) ELSE CONCAT('leadno ', CAST(ul.leadno AS nvarchar)) END,
                    ' is assigned to ', a.user_login), 'Leadnteractionhistory', @LeadInteractionId
                FROM userleads(NOLOCK) ul
                INNER JOIN User_Detail(NOLOCK) a ON ul.AssignedTo = a.User_ID
                WHERE ul.ID = @EntityId;
            END

            INSERT INTO tbl_lam_UserAssignmentHistory(parentid, assignedUserId, ruleid, leadId)
            SELECT @ParentId, @defaultAssignee, @RuleId, @EntityId;
            DECLARE @assignHistoryId bigint = SCOPE_IDENTITY();

            -- Event activity logic
            BEGIN TRY
                DECLARE @UserName nvarchar(255) = '';
                IF(@defaultAssignee > 0)
                    SELECT @UserName = User_Login FROM User_Detail(NOLOCK) WHERE User_ID = @defaultAssignee;

                DECLARE @RuleName nvarchar(255) = '';
                IF(@defaultAssignee > 0 AND @isSegmentMatched = 1)
                    SELECT @RuleName = rule_name FROM tbl_LeadAssignmentRules(NOLOCK) WHERE id = @RuleId;

                IF (@RuleId <= 0)
                BEGIN
                    IF NOT EXISTS(SELECT 1 FROM tbl_LeadEventHistory(NOLOCK) WHERE leadid = @EntityId AND eventid = 10)
                    AND EXISTS (SELECT 1 FROM leadinteractionhistory_latest(NOLOCK) WHERE leadno = @LeadNo AND parentid = @ParentId)
                    BEGIN
                        DECLARE @lih_idf bigint, @assi_id bigint, @fo_status bigint, @createdby bigint, @createduser nvarchar(100), @assign_user nvarchar(100), @eventdate datetime, @ev nvarchar(200) = 'New Interaction added', @eve_d nvarchar(2000), @foll_status nvarchar(100);
                        SELECT TOP 1 @lih_idf = id, @assi_id = AssignedTo, @fo_status = FollowUpStatus, @createdby = createdby, @eventdate = CreatedOn
                        FROM leadinteractionhistory_latest(NOLOCK) WHERE leadno = @LeadNo AND parentid = @ParentId;
                        SELECT @assign_user = user_login FROM user_detail(NOLOCK) WHERE user_id = @assi_id;
                        SELECT @createduser = user_login FROM user_detail(NOLOCK) WHERE user_id = ISNULL(NULLIF(@createdby, 0), @parentid);
                        SELECT @foll_status = FollowupStatus FROM followup_status(NOLOCK) WHERE ID = @fo_status;
                        SELECT @eve_d = @createduser + ' added a followup with status ' + @foll_status + '. Lead was assigned to ' + ISNULL(@assign_user, 'no one');
                        EXEC UspSaveEntityActivity_withid 'lead', @EntityId, @ParentId, @ParentId, @eve_d, @ev, 'leadinteractionhistory', @lih_idf;
                    END
                END

                DECLARE @EventName nvarchar(255) = (CASE WHEN @RuleId > 0 AND @isSegmentMatched = 1 THEN 'Lead is reassigned' ELSE 'Lead is no reassigned' END);
                DECLARE @EventTemplate nvarchar(max) = (CASE WHEN @RuleId > 0 AND @isSegmentMatched = 1 THEN
                    CONCAT('The lead is reassigned to ', @UserName, ' as per lead assignment rule where the rule name is ', @RuleName, '.')
                    ELSE 'The lead is not reassigned to anyone because no lead assignment rule matches' END);

                EXEC UspSaveEntityActivity_withid 'lead', @EntityId, @ParentId, @ParentId, @EventTemplate, @EventName, 'tbl_lam_UserAssignmentHistory', @assignHistoryId;
            END TRY
            BEGIN CATCH
                EXEC usp_InsertErrorInfo;
            END CATCH
        END
    END



GO

/* ============================================================
   Procedure: [dbo].[ups_mk_FollowUpStatus_GetPredefinedListByUserId]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- exec ups_mk_FollowUpStatus_GetPredefinedListByUserId null
-- exec ups_mk_FollowUpStatus_GetPredefinedListByUserId 32397            
-- exec ups_mk_FollowUpStatus_GetPredefinedListByUserId 32198
CREATE   PROCEDURE [dbo].[ups_mk_FollowUpStatus_GetPredefinedListByUserId]
(
	@UserId BIGINT
)
AS    
BEGIN    
-- Declare @UserId BIGINT = 32198  
  
 DECLARE @ParentId BIGINT = 0    
    
 SELECT @ParentId = ParentID  FROM User_Detail(nolock) UD WHERE UD.User_ID = @UserId    
 
 If(isnull(@UserId,0) > 0 and not exists (SELECT * FROM FollowUp_status(NOLOCK) FUM WHERE FUM.ParentId = @ParentId))
 Begin
	print 'User followup does not exist'
	Insert into FollowUp_status(FollowupStatus,OrderNumber,IsActive,Intent,IsCallback,IsConvert,IsDisabled,ParentId,CreatedBy,CreatedDate)
	SELECT FollowupStatus,OrderNumber,IsActive,Intent,IsCallback,IsConvert,0 as IsDisabled,@ParentId as ParentId,@UserId as CreatedBy,getdate() as CreatedDate
	FROM FollowUp_status(NOLOCK) UTM    
	WHERE UTM.ParentId IS NULL AND UTM.IsActive = 1    
	ORDER BY IsDisabled desc, OrderNumber ASC 
 End

 IF EXISTS (SELECT * FROM FollowUp_status(NOLOCK) FUM WHERE FUM.ParentId = @ParentId)    
 BEGIN    
  SELECT FollowUpStatus,ID,Intent,IsCallback,IsConvert,
  (CASE WHEN IsDisabled = 1 THEN 0 ELSE 1 END) IsDisabled    
  FROM FollowUp_status(NOLOCK) UTM    
  WHERE ParentId = @ParentId AND UTM.IsActive = 1   
  ORDER BY IsDisabled desc, OrderNumber ASC  
 END    
 ELSE    
 BEGIN    
	SELECT FollowUpStatus,ID,Intent,IsCallback,IsConvert,1 IsDisabled    
	FROM FollowUp_status(NOLOCK) UTM    
	WHERE UTM.ParentId IS NULL AND UTM.IsActive = 1    
	ORDER BY IsDisabled desc, OrderNumber ASC     
 END    
    
 EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserId    
  ,@Activity_type = 'View_FllwUp_Sttng'    
  ,@ActionType = 'S'    
  ,@RowJson = ''    
  ,@Table_name = 'FollowUp_status'    
END    



GO

