CREATE   PROCEDURE [dbo].[ups_mk_GetMobileAppDatshboardData](
	@UserId bigint,
	@ActivityDate date
)
as
begin
	-- Appointment Only
	exec usp_mk_GetTaskAppointmentForDashboard @UserId, @ActivityDate, @Mode = 'A'

	-- Task Only
