/* ============================================================
   Procedure: [dbo].[ups_mk_tsk_GetRelatedToAutoSuggestion]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- exec ups_mk_tsk_GetRelatedToAutoSuggestion 32222, ''    


CREATE   PROCEDURE ups_mk_tsk_GetRelatedToAutoSuggestion     
 @UserId     BIGINT,     
 @FilterText VARCHAR(50)    
AS    
    BEGIN    
        SELECT Top 100 ID AS LeadId, PersonName, ProfileImgFileName,  
		IIF(ISNULL(City, '') = '', '', City + ', ') + IIF(ISNULL(State, '') = '', '', State + ', ')  + ISNULL(Country, '') AS [Location],
		ParentID,
		(   
			CASE WHEN ISNULL(MobileNo, '') <> ''  
			THEN CountryCode + '-'+MobileNo  
			WHEN ISNULL(MobileNo1, '') <> ''  
			THEN CountryCode1 + '-'+MobileNo1  
			WHEN ISNULL(MobileNo2, '') <> ''  
			THEN CountryCode2 + '-'+MobileNo2  
			ELSE  
			''  
			end  
		)  
		AS MobileNo
		
		FROM UserLeads(nolock)
			WHERE ParentId =    
			(    
				SELECT ParentId    
				FROM User_Detail(nolock)    
				WHERE User_Id = @UserId    
			)
			AND ( 
				PersonName like @FilterText+'%' 
				or MobileNo like @FilterText+'%' 
				or MobileNo1 like @FilterText+'%' 
				or MobileNo2 like @FilterText+'%' 
			) 
    END;



GO

/* ============================================================
   Procedure: [dbo].[ups_mk_tsk_GetRelatedToAutoSuggestionNew]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


-- Exec ups_mk_tsk_GetRelatedToAutoSuggestionNew @TaskType='site',@UserId=34594,@FilterText='new'
-- exec ups_mk_tsk_GetRelatedToAutoSuggestionNew @TaskType=N'Territory',@UserId=41923,@FilterText=N't'
-- exec ups_mk_tsk_GetRelatedToAutoSuggestionNew @TaskType=N'Territory',@UserId=41923,@FilterText=N'an'
-- exec ups_mk_tsk_GetRelatedToAutoSuggestionNew @TaskType=N'Territory',@UserId=42233,@FilterText=N'd'
CREATE   PROCEDURE ups_mk_tsk_GetRelatedToAutoSuggestionNew    
 @TaskType VARCHAR(20) = 'lead',          
 @UserId     BIGINT,           
 @FilterText VARCHAR(50)          
as    
begin    
    
-- declare @TaskType VARCHAR(20)='site',@UserId BIGINT=34594,@FilterText VARCHAR(50)=''  
    
 declare @ParentId bigint    
 SELECT @ParentId = ParentId FROM User_Detail(nolock)   WHERE User_Id = @UserId          
    
 if(@TaskType = 'lead')    
 begin    
  SELECT Top 10 ID AS Id, PersonName, ProfileImgFileName,        
  IIF(ISNULL(City, '') = '', '', City + ', ') + IIF(ISNULL(State, '') = '', '', State + ', ')  + ISNULL(Country, '') AS [Location], ParentID,      
  (         
  case when ISNULL(MobileNo, '') <> '' then CountryCode + '-'+MobileNo        
  when ISNULL(MobileNo1, '') <> '' then CountryCode1 + '-'+MobileNo1        
  when ISNULL(MobileNo2, '') <> '' then CountryCode2 + '-'+MobileNo2        
  ELSE  '' end     
  )     
  AS MobileNo  FROM UserLeads(nolock)  WHERE ParentId = @ParentId and  1 =  ( case     
  when PersonName like @FilterText+'%' then 1    
  when MobileNo like @FilterText+'%' then 1    
  when MobileNo1 like @FilterText+'%' then 1    
  when MobileNo2 like @FilterText+'%' then 1    
  else 0 end)      
 end    
 else if(@TaskType = 'enquiry')    
 Begin    
  SELECT Top 100  EnquiryId AS Id, PersonName, ProfileImgFileName,        
   IIF(ISNULL(City, '') = '', '', City + ', ') + IIF(ISNULL(State, '') = '', '', State + ', ')  + ISNULL(Country, '') AS [Location], ParentID,      
   (     
    CASE WHEN ISNULL(MobileNo, '') <> ''        
    THEN CountryCode + '-'+MobileNo        
    WHEN ISNULL(MobileNo1, '') <> ''        
    THEN CountryCode1 + '-'+MobileNo1     
    WHEN ISNULL(MobileNo2, '') <> ''     
    THEN CountryCode2 + '-'+MobileNo2     
    ELSE        
    ''        
    end        
   )        
   AS MobileNo      
   FROM UserEnquiry(nolock)      
    WHERE ParentId = @ParentId    
    AND 1 =  ( case     
  when PersonName like @FilterText+'%' then 1    
  when MobileNo like @FilterText+'%' then 1    
  when MobileNo1 like @FilterText+'%' then 1    
  when MobileNo2 like @FilterText+'%' then 1    
  else 0 end)      
 End    
 else if(@TaskType = 'site')    
 Begin    
 --Select 'sitetype' RecordType, GeoEntitySiteId Id, GeoEntityType, GeoEntitySiteName SiteName, (case when em.GeoEntityType = 'Branch' then isnull(utnbranch.name, '') else '' End) GeoEntityName, isnull(sm.Latitude, '') Latitude, isnull(sm.longitude, '') Longitude,  GeoEntitySiteName PersonName, sm.GeoEntityId, sm.MapAddress, sm.Address, sm.City, sm.State, sm.Country, sm.PinCode, Concat(ud.FName, '' , isnull(ud.LName, '')) CreatedByName, Concat(ud2.FName, '' , isnull(ud2.LName, '')) UpdatedByName, sm.CreatedDate, sm.CreatedBy, sm.UpdatedDate, isnull(sm.UpdatedBy, 0) UpdatedBy, sm.IsActive, sm.Address [Location], '' ProfileImgFileName, em.ParentId, em.Mobile MobileNo    
 -- from TBL_ET_GeoEntitySiteMaster (nolock) sm left join TBL_ET_GeoEntityMaster (nolock) em   
 -- on sm.GeoEntityId  = em.GeoEntityId left join tbl_inv_UserTaxNumber (nolock) utnbranch   
 -- on em.EntityId = utnbranch.id and  em.GeoEntityType = 'Branch' left join User_Detail (nolock) ud   
 -- on sm.CreatedBy = ud.User_ID left join User_Detail (nolock) ud2   
 -- on sm.UpdatedBy = ud2.User_ID    
 -- where sm.GeoEntitySiteName like '%' + @FilterText + '%' and em.ParentId = @ParentId    
 -- Order By sm.GeoEntitySiteId Desc    
    
 --Select * from (    
 --Select 'sitetype' RecordType, GeoEntitySiteName SiteName, ges.GeoEntitySiteId Id,     
 --(case when ges.Latitude = '' then ue.Latitude else ges.Latitude end) Latitude,    
 --(case when ges.longitude = '' then ue.longitude else ges.longitude end) longitude,    
 -- ges.MapAddress, ges.Address, ges.CreatedDate, GeoEntitySiteName PersonName, ue.ParentID, ue.MobileNo,     
 --IIF(ISNULL(ue.City, '') = '', '', ue.City + ', ') + IIF(ISNULL(ue.State, '') = '', '', ue.State + ', ')  + ISNULL(ue.Country, '') AS [Location], ue.ProfileImgFileName from TBL_ET_GeoEntityMaster(nolock) gee     
 --inner join TBL_ET_GeoEntitySiteMaster(nolock) ges on gee.GeoEntityId = ges.GeoEntityId    
 --left join UserEnquiry(nolock) ue on gee.GeoEntityId = ue.EnquiryId     
 --Where gee.GeoEntityType = 'enquiry'    
 -- and gee.ParentId = @ParentId    
 --and ges.GeoEntitySiteName like '%' + @FilterText + '%'     
 --union    
 --Select 'sitetype' RecordType, GeoEntitySiteName SiteName, ges.GeoEntitySiteId Id,     
 --(case when ges.Latitude = '' then ue.Latitude else ges.Latitude end) Latitude,    
 --(case when ges.longitude = '' then ue.longitude else ges.longitude end) longitude,    
 -- ges.MapAddress, ges.Address, ges.CreatedDate, ges.GeoEntitySiteName PersonName, ue.ParentID, ue.MobileNo,     
 --IIF(ISNULL(ue.City, '') = '', '', ue.City + ', ') + IIF(ISNULL(ue.State, '') = '', '', ue.State + ', ')  + ISNULL(ue.Country, '') AS [Location], ue.ProfileImgFileName from TBL_ET_GeoEntityMaster(nolock) gee     
 --inner join TBL_ET_GeoEntitySiteMaster(nolock) ges on gee.GeoEntityId = ges.GeoEntityId    
 --left join UserLeads(nolock) ue on gee.GeoEntityId = ue.Id     
 --Where gee.GeoEntityType = 'lead'    
 -- and gee.ParentId = @ParentId    
 --and     
 --ges.GeoEntitySiteName like '%' + @FilterText + '%'     
 --)t    
  
  select GESM.GeoEntitySiteId Id, isnull(GESM.GeoEntitySiteName, '') as PersonName, '' as ProfileImgFileName, '' as MobileNo, '' as Location, GEM.ParentId  
 -- select *   
 from TBL_ET_GeoEntityMaster GEM (nolock) inner join TBL_ET_GeoEntitySiteMaster GESM (nolock)   
 on GEM.GeoEntityId = GESM.GEOEntityId     
 Where GEM.IsActive = 1 and GESM.IsActive = 1 and GEM.ParentId=@ParentId and GEM.GeoEntityType not in ('Branch') and isnull(GESM.GeoEntitySiteName, '') != '' and isnull(GESM.GeoEntitySiteName, '') like '%' + @FilterText + '%'     
 End    
 else if(@TaskType = 'branch')    
 Begin    
  select GESM.GeoEntitySiteId Id, isnull(GESM.GeoEntitySiteName, '') as PersonName, '' as ProfileImgFileName, '' as MobileNo, '' as Location, GEM.ParentId  
 -- select *   
 from TBL_ET_GeoEntityMaster GEM (nolock) inner join TBL_ET_GeoEntitySiteMaster GESM (nolock)   
 on GEM.GeoEntityId = GESM.GEOEntityId     
 Where GEM.IsActive = 1 and GESM.IsActive = 1 and GEM.ParentId=@ParentId and GEM.GeoEntityType='Branch' and isnull(GESM.GeoEntitySiteName, '') like '%' + @FilterText + '%'     
 End    
 else if(@TaskType = 'sitepool')    
 Begin    
 select SP.GeoEntitySitePoolId as Id, SP.GeoEntitySitePoolName as PersonName, '' as ProfileImgFileName, '' as MobileNo, '' as Location, SP.ParentID  
 -- select *   
 from TBL_ET_GeoEntitySitePool SP (nolock)     
 Where SP.Isactive=1 and SP.ParentId=@ParentId AND SP.GeoEntitySitePoolName like '%' + @FilterText + '%'  
   
 End    
 else if(@TaskType = 'territory')    
 Begin    
 SELECT TM.TerritoryId as Id, TM.TerritoryName as PersonName, '' as ProfileImgFileName, '' as MobileNo, '' as Location, TM.ParentId  
 FROM TBL_ET_TerritoryMaster TM (nolock) INNER JOIN TBL_ET_TerritoryUserMapping TUM (nolock)   
 ON  TM.TerritoryId = TUM.TerritoryId   
 WHERE   (TM.IsActive = 1) AND (TUM.IsActive = 1) AND (TUM.ParentId = @ParentId) AND TM.TerritoryName like '%' + @FilterText + '%'  
 End  
  
     
END    



