/* ============================================================
   Procedure: [dbo].[ups_TBL_ET_GetSiteLeadEnquiryLatLogByEntityId]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--ups_TBL_ET_GetSiteLeadEnquiryLatLogByEntityId 347631, 'lead'
CREATE   PROCEDURE [dbo].[ups_TBL_ET_GetSiteLeadEnquiryLatLogByEntityId](
	@Mode varchar(2),
	@EntityId bigint = 0,
	@GeoEntityType varchar(30) = 'lead',
	@UserId bigint = 32222
)
as
begin
--Declare @EntityId bigint = 347631
--Declare @GeoEntityType varchar(30) = 'lead'
if(@Mode = 'll')
Begin

if(@GeoEntityType = 'lead')
Begin
Select * from (
Select 'sitetype' RecordType, GeoEntitySiteName SiteName, ges.GeoEntitySiteId Id,
(case when ges.Latitude = '' then ul.Latitude else ges.Latitude end) Latitude,
(case when ges.longitude = '' then ul.longitude else ges.longitude end) longitude,
MapAddress, Address, ges.CreatedDate from TBL_ET_GeoEntityMaster gee 
inner join TBL_ET_GeoEntitySiteMaster ges on gee.GeoEntityId = ges.GeoEntityId
left join UserLeads ul on gee.GeoEntityId = ul.Id 
Where gee.GeoEntityType = @GeoEntityType
and gee.EntityId = @EntityId
Union
Select 'lead' RecordType, '' SiteName, ul.Id Id, ul.Latitude, ul.longitude, ul.whereAddress MapAddress, 
ul.OfficeAddress Address, ul.CreatedOn CreatedDate 
from UserLeads ul where ul.Id = @EntityId
)t
where t.Latitude != ''

End

else if(@GeoEntityType = 'enquiry')
Begin
Select * from (
Select 'sitetype' RecordType, GeoEntitySiteName SiteName, ges.GeoEntitySiteId Id, 
(case when ges.Latitude = '' then ue.Latitude else ges.Latitude end) Latitude,
(case when ges.longitude = '' then ue.longitude else ges.longitude end) longitude,
 ges.MapAddress, ges.Address, ges.CreatedDate from TBL_ET_GeoEntityMaster gee 
inner join TBL_ET_GeoEntitySiteMaster ges on gee.GeoEntityId = ges.GeoEntityId
left join UserEnquiry ue on gee.GeoEntityId = ue.EnquiryId 
Where gee.GeoEntityType = @GeoEntityType
and gee.EntityId = @EntityId
Union
Select 'enquiry' RecordType, '' SiteName, ue.EnquiryId Id, ue.Latitude, ue.longitude, 
ue.whereAddress MapAddress, ue.OfficeAddress Address, ue.CreatedDate 
from UserEnquiry ue where ue.EnquiryId = @EntityId
)tt
where tt.Latitude != ''

End	

else if(@GeoEntityType = 'location')
Begin
Select 'location' RecordType, GeoEntitySiteName SiteName, ges.GeoEntitySiteId Id,
ges.Latitude, ges.longitude, ges.MapAddress, ges.Address, ges.CreatedDate 
from TBL_ET_GeoEntityMaster gee 
inner join TBL_ET_GeoEntitySiteMaster ges on gee.GeoEntityId = ges.GeoEntityId
Where gee.GeoEntityType = @GeoEntityType
and ges.CreatedBy in (Select USER_ID from User_Detail (nolock) ud 
where ud.ParentId = (Select ParentId from User_Detail(nolock) ud2 where USER_ID = @UserId))

End

else if(@GeoEntityType = 'site')
Begin
Select 'site' RecordType, GeoEntitySiteName SiteName, ges.GeoEntitySiteId Id, 
ges.Latitude, ges.longitude, ges.MapAddress, ges.Address, ges.CreatedDate 
from TBL_ET_GeoEntityMaster gee 
inner join TBL_ET_GeoEntitySiteMaster ges on gee.GeoEntityId = ges.GeoEntityId
Where gee.GeoEntityType = @GeoEntityType
and ges.CreatedBy in (Select USER_ID from User_Detail (nolock) ud 
where ud.ParentId = (Select ParentId from User_Detail(nolock) ud2 where USER_ID = @UserId))

End

Select GetDate() CurrentDate
End
end



GO

