    or ul.MobileNo1 like @FilterText+'%'   
    or ul.MobileNo2 like @FilterText+'%')
Union all
-- ul.Id = @EntityId and 
Select 'lead' RecordType, ul.PersonName SiteName, ul.Id Id, ul.Latitude, ul.longitude, ul.whereAddress MapAddress, 
ul.OfficeAddress Address, ul.CreatedOn CreatedDate 
from UserLeads ul where (ul.PersonName like @FilterText +'%'   
    or ul.MobileNo like @FilterText+'%'   
    or ul.MobileNo1 like @FilterText+'%'   
    or ul.MobileNo2 like @FilterText+'%')  
)t
--where t.Latitude != '' 

