else if(@GeoEntityType = 'enquiry') 
Begin 
Select * from (
Select 'sitetype' RecordType, GeoEntitySiteName SiteName, ges.GeoEntitySiteId Id, 
(case when ges.Latitude = '' then ue.Latitude else ges.Latitude end) Latitude,
(case when ges.longitude = '' then ue.longitude else ges.longitude end) longitude,
 ges.MapAddress, ges.Address, ges.CreatedDate from TBL_ET_GeoEntityMaster gee 
inner join TBL_ET_GeoEntitySiteMaster ges on gee.GeoEntityId = ges.GeoEntityId
left join UserEnquiry ue on gee.GeoEntityId = ue.EnquiryId 
Where gee.GeoEntityType = @GeoEntityType
and --gee.EntityId = @EntityId  
ges.GeoEntitySiteName like '%' + @FilterText + '%' 
Union
Select 'enquiry' RecordType, '' SiteName, ue.EnquiryId Id, ue.Latitude, ue.longitude, 
ue.whereAddress MapAddress, ue.OfficeAddress Address, ue.CreatedDate 
from UserEnquiry ue where (ue.PersonName like '%' + @FilterText + '%' 
    or ue.MobileNo like @FilterText+'%'   
    or ue.MobileNo1 like @FilterText+'%'   
    or ue.MobileNo2 like @FilterText+'%')
--ue.EnquiryId = @EntityId
)tt
--where tt.Latitude != ''

End	

else if(@GeoEntityType = 'location')
Begin
Select 'location' RecordType, GeoEntitySiteName SiteName, ges.GeoEntitySiteId Id,
ges.Latitude, ges.longitude, ges.MapAddress, ges.Address, ges.CreatedDate 
from TBL_ET_GeoEntityMaster gee 
inner join TBL_ET_GeoEntitySiteMaster ges on gee.GeoEntityId = ges.GeoEntityId
Where gee.GeoEntityType = @GeoEntityType
and ges.CreatedBy in (Select USER_ID from User_Detail (nolock) ud 
where ud.ParentId = (Select ParentId from User_Detail(nolock) ud2 where USER_ID = @UserId))
and ges.GeoEntitySiteName like '%' + @FilterText + '%'
