/* ============================================================
   Procedure: [dbo].[ups_voip_CallStatusRectifing]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE ups_voip_CallStatusRectifing(
	@wehookResponseBody nvarchar(max),
	@SerProName nvarchar(255),
	@UniqueIdentity nvarchar(255) = null
)
as
begin
	--declare
	--	@wehookResponseBody nvarchar(max),
	--	@SerProName nvarchar(255),
	--	@UniqueIdentity nvarchar(255) = null

	declare @resTable as table (
			[Key] nvarchar(255),
			[Value] nvarchar(max)
		)


	set @SerProName = LTRIM(RTRIM(LOWER(@SerProName)))

		declare @ServiceProviderId bigint;  
		select @ServiceProviderId = id from tbl_voip_ServiceProvider(nolock)
			where LTRIM(RTRIM(LOWER(provider_name))) = case when lower(@SerProName) = 'mobilelikenumber'
				then 'Mobile Like Number' else @SerProName  end

		if(ISNULL(@UniqueIdentity, '')  = '')
		begin
			set @UniqueIdentity = ( case
				when @SerProName = 'voxbay'
					then ( select [value] from openjson(@wehookResponseBody) WHERE [key] = 'param1')
				when @SerProName = 'mobilelikenumber'
					then (select [value] from openjson(@wehookResponseBody) WHERE [key] = 'refno')
				else '' end 
			)
		end

	if(isnull(@wehookResponseBody, '') <> '')
	begin
		if(@SerProName = 'VOXBAY')
		begin
			insert into @resTable( [Key], [Value] )
				select [key], [value] from openjson(@wehookResponseBody)
		end

		if(@SerProName = 'CloudShope')
		begin
			insert into @resTable( [Key], [Value] )
				select [Key], [Value] from openjson(@wehookResponseBody) with ( [Key] nvarchar(255), [Value] nvarchar(2000) )
		end

		if(@SerProName = 'MobileLikeNumber')
		begin
			insert into @resTable( [Key], [Value] )
				select [key], [value] from openjson(@wehookResponseBody)
		end
	end

	if(exists( select * from @resTable ))
	begin
		declare @Duration decimal(18, 4), @CallRecording nvarchar(max), @endpointIntractionId bigint, @EntityName nvarchar(50)
		if(@SerProName = 'VOXBAY')
		begin
			select @Duration = [Value] from @resTable where [Key] = 'duration'
			select @CallRecording = [Value] from @resTable where [Key] = 'recording_URL'
			select @endpointIntractionId = id, @EntityName = EntityName from tbl_voip_endpointInteraction(nolock) where id = @UniqueIdentity
		end

		if(@SerProName = 'CloudShope')
		begin
			select @Duration = [Value] from @resTable where [Key] = 'from_number_answer_time'
			select @CallRecording = [Value] from @resTable where [Key] = 'recording_url'
			select @endpointIntractionId = id, @EntityName = EntityName from tbl_voip_endpointInteraction(nolock) where id = @UniqueIdentity
		end

		if(@SerProName = 'MobileLikeNumber')
		begin
			select @Duration = [Value] from @resTable where [Key] = 'duration'
			select @CallRecording = [Value] from @resTable where [Key] = 'RecordingUrl'
			select @endpointIntractionId = id, @EntityName = EntityName from tbl_voip_endpointInteraction(nolock) 
				where ProviderName = 'Mobile Like Number' and  refNumber = @UniqueIdentity
		end
		
		select 
			@Duration as [Duration], 
			@CallRecording as [CallRecording],
			@endpointIntractionId as [UniqueIdentity]

	end
end



