Begin  
    print 'Role Hierarchy'          
    
    -- Select Hierarchy JSON and add peer user flag
    Select @HierarchyJSON = HierarchyJSON 
    from tbl_UA_RoleHierarchy(nolock) 
    where ParentId = @ParentId and IsActive=1
    
    -- Select Role information along with permission mapping
   Select @RoleId=ISNULL(tuRolem.RoleId, sysRolem.id) , 
        
      @bAddPeerPermissionMapping=ISNULL(tuUserrm.PeerViewRoleMappingCode, '')
FROM TBL_UA_UserRoleMappingMaster(NOLOCK) tuUserrm 
LEFT JOIN TBL_UA_RoleMaster(NOLOCK) tuRolem    
    ON tuUserrm.RoleCode = tuRolem.RoleCode 
LEFT JOIN systemRoles(NOLOCK) sysRolem    
    ON tuUserrm.RoleCode = sysRolem.SysRoleCode
WHERE 
    [tuUserrm].[UserId] = @UserID  
    AND (
        (tuRolem.Active = 1 AND tuRolem.RoleId IS NOT NULL) OR 
        (sysRolem.isactive = 1 AND sysRolem.SysRoleCode IS NOT NULL)
    )
    AND tuUserrm.Active = 1;  
    
    print concat('@RoleId: ',@RoleId)  
    
