/* ============================================================
   Procedure: [dbo].[Use_GetUserDetailsforImport]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- exec Use_GetUserDetailsforImport @UserId=39702      
-- exec Use_GetUserDetailsforImport @UserId=31871      
-- exec Use_GetUserDetailsforImport @UserId=39330      
CREATE   PROCEDURE [dbo].[Use_GetUserDetailsforImport]      
(      
 @UserID BIGINT             
)      
AS             
BEGIN             
-- Declare @UserID BIGINT = 45436             
        
 DECLARE @ParentId BIGINT = 0, @RoleId bigint = 0;
 DECLARE @IsAdmin bit = 0;
 DECLARE @bAddPeerUser bit = 0;
 Declare @TeamCode varchar(10) = ''
 Declare @ScopeCode varchar(10) = ''
 Declare @UserIdTeamLst varchar(4000) = ''
 Declare @HierarchyJSON varchar(Max) = ''
          
 SELECT @ParentId = ParentID, @IsAdmin = IsAdmin FROM User_Detail(nolock) WHERE User_ID = @UserId;        
       
 if((@ParentId = @UserId or @IsAdmin = 1))          
 Begin
  print 'Parent or Admin'        
      
  SELECT ud.[User_ID], ud.User_Login , [Image]  
  FROM User_Detail(nolock) AS ud           
  WHERE ud.[ParentId] = @ParentId and ud.status = 1             
  order by User_Login asc             
 End          
 Else if Exists(select 1 from tbl_UA_RoleHierarchy(nolock) where ParentId = @ParentId and IsActive=1)
 Begin
  print 'Role Hierarchy'        
      
  Select @HierarchyJSON = HierarchyJSON, @bAddPeerUser=bAddPeerUser from tbl_UA_RoleHierarchy(nolock) where ParentId = @ParentId and IsActive=1

  Select @RoleId=tuRolem.RoleId
  FROM TBL_UA_UserRoleMappingMaster(NOLOCK) tuUserrm LEFT JOIN TBL_UA_RoleMaster(NOLOCK)  tuRolem  
  ON tuUserrm.RoleCode = tuRolem.RoleCode and tuRolem.Active=1 and tuUserrm.Active=1
  WHERE [tuUserrm].[UserId] = @UserId  

  print concat('@RoleId: ',@RoleId)
      
  drop table if Exists #TableData3      
      
  Create TABLE #TableData3 (roleid bigint, rolename Varchar(50), rolecode varchar(50), parentid bigint)
  Insert into #TableData3 (roleid, rolename, rolecode, parentid)
  Select roleid, rolename, rolecode, parentid
  from OPENJSON(@HierarchyJSON) with 
  (
	roleid bigint, 
	rolename Varchar(100), 
	rolecode Varchar(100), 
	parentid bigint
  )      
         
  If not exists(Select * from #TableData3 Where roleid=@RoleId)      
  Begin      
	print 'User does not exist in Role Hierarchy'    
   
	SELECT ud.[User_ID], ud.User_Login , [Image]         
	FROM User_Detail(nolock) AS ud         
	WHERE ud.[User_ID] = @UserID    
  End  
  Else  
  Begin  
   print 'Role Hierarchy listing'    
  print concat('@bAddPeerUser: ',@bAddPeerUser)
  
	IF(@bAddPeerUser=1)
	Begin
	   ;with CTE(roleid,rolename,rolecode,parentid)  
	   as   
	   (  
		select roleid,rolename,rolecode,parentid
		from #TableData3 where roleid = @RoleId  
		union all  
		-- recursively add children  
		select c.roleid,c.rolename,c.rolecode,c.parentid  
		from #TableData3 c  
		join CTE on c.parentid = CTE.roleid  
	   )  

		SELECT ud.[User_ID], ud.User_Login , [Image]         
		FROM User_Detail(nolock) AS ud inner join TBL_UA_UserRoleMappingMaster(NOLOCK) tuUserrm
		ON ud.user_id =tuUserrm.UserId inner JOIN TBL_UA_RoleMaster(NOLOCK)  tuRolem  
		ON tuUserrm.RoleCode = tuRolem.RoleCode and tuRolem.Active=1 and tuUserrm.Active=1 inner join CTE  
		ON tuRolem.roleid=CTE.roleid  
		WHERE ud.status = 1
	End
	Else
	Begin
	
	   ;with CTE(roleid,rolename,rolecode,parentid)  
	   as   
	   (  
		select roleid,rolename,rolecode,parentid
		from #TableData3 where roleid = @RoleId  
		union all  
		-- recursively add children  
		select c.roleid,c.rolename,c.rolecode,c.parentid  
		from #TableData3 c  
		join CTE on c.parentid = CTE.roleid  
	   )  

		SELECT ud.[User_ID], ud.User_Login , [Image]         
		FROM User_Detail(nolock) AS ud inner join TBL_UA_UserRoleMappingMaster(NOLOCK) tuUserrm
		ON ud.user_id =tuUserrm.UserId inner JOIN TBL_UA_RoleMaster(NOLOCK)  tuRolem  
		ON tuUserrm.RoleCode = tuRolem.RoleCode and tuRolem.Active=1 and tuUserrm.Active=1 inner join CTE  
		ON tuRolem.roleid=CTE.roleid  
		WHERE ud.status = 1 and ud.User_ID not in (Select tuUserrm1.UserId
			FROM TBL_UA_UserRoleMappingMaster(NOLOCK) tuUserrm1 LEFT JOIN TBL_UA_RoleMaster(NOLOCK)  tuRolem1  
			ON tuUserrm1.RoleCode = tuRolem1.RoleCode and tuRolem1.Active=1 and tuUserrm1.Active=1
			WHERE [tuUserrm1].[UserId] != @UserId and tuRolem1.RoleId=@RoleId )

	End
  
  End  

 End
 Else if Exists(select 1 from tbl_UA_UserHierarchy(nolock) where ParentId = @ParentId and IsActive=1)
 Begin
  print 'User Hierarchy'        
      
  Select @HierarchyJSON = HierarchyJSON from tbl_UA_UserHierarchy(nolock) where ParentId = @ParentId and IsActive=1
      
  drop table if Exists #TableData2      
      
  Create TABLE #TableData2 ([user_id] bigint, team_name Varchar(50), user_login varchar(50), username varchar(50), [parentid] bigint)      
  Insert into #TableData2 ([user_id], team_name, user_login,username,[parentid])      
  Select [user_id], '', user_login, username, [parentid] from OPENJSON(@HierarchyJSON) with ([user_id] bigint, user_login Varchar(100), username Varchar(100), [parentid] bigint)      
      
   select @TeamCode = TeamCode, @ScopeCode = ScopeCode, @UserIdTeamLst = UserIdTeamLst         
  from ufn_GetUserRoleScope(@UserId)      
    
  If not exists(Select * from #TableData2 Where user_id=@UserID)      
  Begin      
     print 'User does not exist in Hierarchy'          
          
  print '@ScopeCode=' + @ScopeCode          
  print '@TeamCode=' + isnull(@TeamCode, '')          
  print '@ParentId=' + cast(@ParentId as varchar(10))          
  print '@UserId=' + cast(@UserId as varchar(10))          
  print '@UserIdTeamLst=' + cast(@UserIdTeamLst as varchar)         
       
       
  if(@ScopeCode = 'TEAM')             
  Begin             
   SELECT ud.[User_ID], ud.User_Login , [Image]  
   FROM User_Detail(nolock) AS ud             
   WHERE (ud.[User_ID] in (select item from dbo.fu_SplitString(@UserIdTeamLst, ','))) and ud.status = 1       
  End     
  else if (@ScopeCode = 'GLOBAL')    
  begin    
       SELECT ud.[User_ID], ud.User_Login , [Image]  
       FROM User_Detail(nolock) AS ud           
       WHERE ud.[ParentId] = @ParentId and ud.status = 1             
       order by User_Login asc     
  end    
  else if (@ScopeCode = 'HIERARCHY')    
  begin    
     SELECT ud.[User_ID], ud.User_Login , [Image]  
     FROM User_Detail(nolock) AS ud             
     WHERE ud.[User_ID]= @UserID and ud.status = 1  
  end    
  Else             
  Begin             
   SELECT ud.[User_ID], ud.User_Login , [Image]  
   FROM User_Detail(nolock) AS ud             
   WHERE ud.[User_ID]= @UserID and ud.status = 1         
  End  
  End      
  Else      
  Begin      
   print 'User Hierarchy listing'        
      
  /*    
  if(@ScopeCode = 'TEAM')             
  Begin             
   SELECT ud.[User_ID], ud.User_Login , [Image]             
   FROM User_Detail(nolock) AS ud             
   WHERE (ud.[User_ID] in (select item from dbo.fu_SplitString(@UserIdTeamLst, ','))) and ud.status = 1       
  End     
  else     
  */     
  if (@ScopeCode = 'GLOBAL')    
   begin    
       SELECT ud.[User_ID], ud.User_Login , [Image]  
       FROM User_Detail(nolock) AS ud           
           WHERE ud.[ParentId] = @ParentId and ud.status = 1             
        order by User_Login asc     
   end    
   else if (@ScopeCode = 'HIERARCHY')    
   begin    
      
  ;with CTE(user_id,team_name,user_login,username,parentid)      
  as       
  (      
  select user_id,team_name,user_login,username,parentid      
  from #TableData2 where User_id = @UserID      
  union all      
  -- recursively add children      
  select c.user_id,c.team_name,c.user_login,c.username,c.parentid      
  from #TableData2 c      
  join CTE on c.parentid = CTE.User_id      
  )      
      
  SELECT ud.[User_ID], ud.User_Login , [Image]  
  FROM User_Detail(nolock) AS ud inner join CTE      
  ON ud.User_ID=CTE.user_id      
  WHERE ud.status = 1         
   end    
   else    
   begin    
     SELECT ud.[User_ID], ud.User_Login , [Image]  
    FROM User_Detail(nolock) AS ud             
    WHERE ud.[User_ID]= @UserID and ud.status = 1     
   end    
      
   --SELECT @UserIdTeamLst = STUFF((SELECT distinct ',' + Cast(user_id as varchar(4000))      
   --from #TableData2 where (User_id = @UserId or parentid = @UserId or parentid in (select top 1 parentid from #TableData2 where User_id = @UserId))      
   --FOR XML PATH('')),1,1,'')      
  End      
      
  --, @UserIdTeamLst = ''      
  --select @TeamCode = TeamCode, @ScopeCode = ScopeCode from ufn_GetUserRoleScope(@UserId)      
      
  --select * from #TableData2      
  --select @UserIdTeamLst       
 End
 Else          
 Begin
  select @TeamCode = TeamCode, @ScopeCode = ScopeCode, @UserIdTeamLst = UserIdTeamLst       
  from ufn_GetUserRoleScope(@UserId)           
        
  print '@ScopeCode=' + @ScopeCode        
  print '@TeamCode=' + isnull(@TeamCode, '')        
  print '@ParentId=' + cast(@ParentId as varchar(10))        
  print '@UserId=' + cast(@UserId as varchar(10))        
  print '@UserIdTeamLst=' + cast(@UserIdTeamLst as varchar)        
       
  if(@ScopeCode = 'TEAM')             
  Begin             
   SELECT ud.[User_ID], ud.User_Login , [Image]  
   FROM User_Detail(nolock) AS ud             
   WHERE (ud.[User_ID] in (select item from dbo.fu_SplitString(@UserIdTeamLst, ','))) and ud.status = 1       
  End     
  else if (@ScopeCode = 'GLOBAL')    
   begin    
       SELECT ud.[User_ID], ud.User_Login , [Image]  
       FROM User_Detail(nolock) AS ud           
       WHERE ud.[ParentId] = @ParentId and ud.status = 1             
        order by User_Login asc     
   end    
  else if (@ScopeCode = 'HIERARCHY')    
   begin    
     SELECT ud.[User_ID], ud.User_Login , [Image]  
     FROM User_Detail(nolock) AS ud             
     WHERE ud.[User_ID]= @UserID and ud.status = 1   
   end     
  Else             
  Begin             
   SELECT ud.[User_ID], ud.User_Login , [Image]  
   FROM User_Detail(nolock) AS ud             
   WHERE ud.[User_ID]= @UserID and ud.status = 1         
  End           
 End          
      
END



GO

