 -- declare @ParentId nvarchar(max)=45160,@Mode nvarchar(500)='User',@userid BIGINT=45160,@fromdate DATE='23-Aug-2024',@todate DATE='24-Aug-2024',@strCriteriaName nvarchar(max) ='45180'
