 -- declare @ParentId nvarchar(max)=43889,@Mode nvarchar(500)='UserWiseIndividual',@userid BIGINT=43889,@fromdate DATE='23-Aug-2024',@todate DATE='24-Aug-2024',@strCriteriaName nvarchar(max) =''        
    
 DECLARE @listtopivot NVARCHAR(MAX) = '';  
