 if(@Mode='Individual')        
 begin        
        
  CREATE TABLE #source (        
  sourceid INT,        
  SourceName VARCHAR(100),        
  UserID INT        
  --CONSTRAINT [PK_tmpSource2] PRIMARY KEY CLUSTERED(SourceName ASC)    
  );        
    
  CREATE TABLE #source_1 (        
  sourceid INT,        
  SourceName VARCHAR(100),        
  UserID INT        
  );        
    
 INSERT INTO #source (sourceid, SourceName, UserID)        
 SELECT distinct f.sourceid, trim(f.Name) as SourceName, @ParentId as UserID        
 FROM usersourcesettings(NOLOCK) f inner join #tbl_SourceID SD     
 ON F.SourceID = SD.SourceId LEFT JOIN prohibitedcharacters p     
 ON f.name LIKE '%' + p.charactersymbol + '%' AND p.charactersymbol <> '%'        
 WHERE isactive = 1 AND name NOT LIKE '%[%]%' AND name NOT LIKE '%.%' AND UserID = @ParentId        
 ORDER BY trim(f.Name) ASC;        
 --select * from #source        
  
 INSERT INTO #source_1 (sourceid, SourceName, UserID)        
 SELECT distinct f.sourceid, trim(f.Name) as SourceName, SD.AssignedTo as UserID        
 FROM usersourcesettings(NOLOCK) f inner join #tbl_SourceID1 SD     
 ON F.SourceID = SD.SourceId LEFT JOIN prohibitedcharacters p     
 ON f.name LIKE '%' + p.charactersymbol + '%' AND p.charactersymbol <> '%'        
 WHERE isactive = 1 AND name NOT LIKE '%[%]%' AND name NOT LIKE '%.%' AND UserID = @ParentId        
 ORDER BY trim(f.Name) ASC;      
  
 -- Step 4: Prepare list of source names for pivot        
        
        
 SELECT @listtopivot = STRING_AGG('[' + cast(SourceName as nvarchar(max)) + ']', ', '),  
     @ListPivotSelect= STRING_AGG('isnull([' + cast(SourceName as nvarchar(max)) + '],0) as [' + cast(SourceName as nvarchar(max)) + ']', ', ')  
 FROM #source  
        
 --SELECT @ListPivotSelect = @listtopivot    
 -- STRING_AGG( + QUOTENAME(SourceName) , ', ')    FROM #source;        
        
  SELECT @ListPivotSelectClickable = STRING_AGG(cast(REPLACE(REPLACE(REPLACE(QUOTENAME(SourceName), ' ', ''), '-', ''), '.', '') + '$' + QUOTENAME(sourceid) as nvarchar(max)),',')     
  FROM #source(NOLOCK)     
  --order by SourceName asc        
        
    -- DECLARE @HierarchyJSON NVARCHAR(MAX);        
        
   CREATE TABLE #HierarchyDetail        
   (        
    User_id BIGINT,        
    UserName NVARCHAR(MAX),        
    Parentid BIGINT        
   );        
        
   IF EXISTS (SELECT 1 FROM tbl_UA_UserHierarchy (NOLOCK) WHERE ParentId = @ParentId AND IsActive = 1)  
   BEGIN        
    SELECT @HierarchyJSON = HierarchyJSON         
    FROM tbl_UA_UserHierarchy (NOLOCK)         
    WHERE IsActive = 1 AND ParentId = @ParentId;        
        
    INSERT INTO #HierarchyDetail        
    SELECT DISTINCT uh.User_id, uh.UserName, uh.Parentid        
    FROM OPENJSON(@HierarchyJSON) WITH         
    (        
     parentid BIGINT,        
     username NVARCHAR(500),        
     user_id BIGINT        
    ) UH         
    INNER JOIN User_detail (NOLOCK) UD        
     ON UH.user_id = UD.user_ID;        
   END        
   ELSE IF EXISTS (SELECT 1 FROM tbl_UA_RoleHierarchy (NOLOCK) WHERE ParentId = @ParentId AND IsActive = 1)        
   BEGIN        
    PRINT 'Role Hierarchy';                
         
    SELECT @HierarchyJSON = HierarchyJSON         
    FROM tbl_UA_RoleHierarchy (NOLOCK)         
    WHERE IsActive = 1 AND ParentId = @ParentId;        
        
    SELECT DISTINCT parentid        
    INTO #UserRoleHierarchy1        
    FROM OPENJSON(@HierarchyJSON) WITH         
    (        
     parentid BIGINT        
    );        
        
    INSERT INTO #HierarchyDetail        
    SELECT UH.Parentid, FName + ' ' + LName AS username, user_id         
    FROM #UserRoleHierarchy1 UH        
    LEFT JOIN User_Detail UD ON UD.User_ID = UH.parentid          
    WHERE FName IS NOT NULL AND LName IS NOT NULL;        
        
    DROP TABLE #UserRoleHierarchy1;        
   END;        
        
   -- Recursive CTE        
  ;WITH UserHierarchy AS (        
    -- Base case: Select the top-level parents        
    SELECT         
     ParentID,         
     user_id,         
     CONCAT('<b>', Username, '</b>') AS FormattedUsername,        
     CAST(Username AS VARCHAR(MAX)) AS FormattedHierarchyPath,        
     0 AS Level        
    FROM         
     #HierarchyDetail        
    WHERE         
     ParentID = 0        
        
    UNION ALL        
        
    -- Recursive case: Select children of the current level        
    SELECT         
     u.ParentID,         
     u.user_id,         
     CASE         
      WHEN uh.Level = 0 THEN CONCAT('<b>', u.Username, '</b>')        
      ELSE REPLACE(REPLACE(u.Username, '<b>', ''), '</b>', '')         
     END AS FormattedUsername,        
     CAST(CONCAT(uh.FormattedHierarchyPath, '<br>', REPLACE(REPLACE(u.Username, '<b>', ''), '</b>', '')) AS VARCHAR(MAX)) AS FormattedHierarchyPath,        
   uh.Level + 1 AS Level        
    FROM         
     #HierarchyDetail u        
    INNER JOIN         
     UserHierarchy uh ON u.ParentID = uh.user_id        
   )        
        
   -- Select and format the results        
   SELECT          
    ParentID,         
    user_id,         
    FormattedUsername,        
    FormattedHierarchyPath,        
    Level        
   INTO #UserHierarchy        
   FROM UserHierarchy        
   ORDER BY         
    CASE WHEN ParentID = 0 THEN user_id ELSE ParentID END, -- Order by ParentID, but for root parents (ParentID = 0) use user_id        
    ParentID,         
    Level,         
    FormattedHierarchyPath;        
        
   --------------------        
          
         
        
   -- Create a temporary table to hold the results        
   CREATE TABLE #Hierarchy (        
   --Srno int,        
    ParentID INT,        
    user_id INT,        
    FormattedUsername NVARCHAR(MAX),        
    FormattedHierarchyPath NVARCHAR(MAX),        
    level INT,        
   TotalAssigned INT,        
   Pending INT,        
   ListToPivot NVARCHAR(MAX)        
   );        
        
   -- Create a cursor to loop through parent nodes        
   DECLARE ParentCursor CURSOR FOR        
   SELECT DISTINCT  ParentID, user_id, FormattedUsername, FormattedHierarchyPath, level        
   FROM #UserHierarchy --where Level <2;        
   --DECLARE @Value INT=0;        
   -- Open the cursor        
   OPEN ParentCursor;        
        
          
   -- Fetch the first row from the cursor        
   FETCH NEXT FROM ParentCursor INTO @ParentID1, @UserID1, @FormattedUsername, @FormattedHierarchyPath, @Level;        
          
   -- Loop through the parent nodes        
   WHILE @@FETCH_STATUS = 0        
   BEGIN        
    -- Insert the parent node into the temporary table        
      INSERT INTO #Hierarchy ( ParentID, user_id, FormattedUsername, FormattedHierarchyPath, level, TotalAssigned, Pending, ListToPivot)        
    VALUES (@ParentID1, @UserID, @FormattedUsername, @FormattedHierarchyPath, @Level, dbo.fn_userleadsassigned_datewise(@UserID1, @fromdate, @todate),        
   dbo.fn_userpendingfollowup_datewise(@UserID1, @fromdate, @todate), @ListPivotSelect);        
    --select * from #Hierarchy        
    -- Fetch child nodes for the current parent node        
    
    INSERT INTO #Hierarchy (ParentID, user_id, FormattedUsername, FormattedHierarchyPath, level, TotalAssigned, Pending, ListToPivot)        
    SELECT DISTINCT ParentID, user_id, FormattedUsername, FormattedHierarchyPath, level, dbo.fn_userleadsassigned_datewise(user_id, @fromdate, @todate),        
   dbo.fn_userpendingfollowup_datewise(user_id, @fromdate, @todate), @ListPivotSelect         
    FROM #UserHierarchy        
    WHERE ParentID = @UserID --and  Level >1        
  -- select * from #Hierarchy        
   --set @SrNo=@SrNo+1;        
            
    -- Fetch the next row from the cursor        
    FETCH NEXT FROM ParentCursor INTO @ParentID1, @UserID, @FormattedUsername, @FormattedHierarchyPath, @Level;        
   END        
        
   -- Close and deallocate the cursor        
   CLOSE ParentCursor;        
   DEALLOCATE ParentCursor;        
   --select ParentID, user_id, FormattedUsername, FormattedHierarchyPath,  level, TotalAssigned, Pending, ListToPivot from #Hierarchy        
        
  --drop table if exists #source         
        
  select ROW_NUMBER() OVER(ORDER BY (SELECT 1)) as SrNo,* into #Hierarchy1 from #Hierarchy        
        
  if(@strCriteriaName='')  
  begin        
 -- Step 5: Pivot the data        
 SET @sql = N'        
  SELECT Srno, User_ID, FormattedUsername as UserByName,FormattedUsername as User_Login,  
      dbo.fn_userleadsassigned_datewise(user_id, @fromdate, @todate) as TotalAssigned,        
      dbo.fn_userpendingfollowup_datewise(user_id, @fromdate, @todate) Pending,        
      ' + @ListPivotSelect + '        
  FROM (        
   SELECT a.Srno,a.ParentID,a.User_ID, a.FormattedUsername,a.level,ul.User_Login, ul.User_Login + '' ('' + isnull(ul.FName,'''') + '' '' + isnull(ul.LName,'''') + '')'' as UserByName   ,        
       b.SourceName,        
       isnull(dbo.fn_getsourcecount(a.user_id, @fromdate, @todate, b.SourceName),0) as Count        
   FROM #Hierarchy1 a        
   --LEFT JOIN #source b ON a.user_id = b.UserID        
   LEFT JOIN #source_1 b ON a.user_id = b.UserID  
   left join user_detail(nolock) ul on ul.User_ID=a.user_id          
  ) AS SourceData        
  PIVOT (        
   SUM(Count)        
   FOR SourceName IN (' + @listtopivot + ')        
  ) AS PivotTable        
 ';        
  
 print concat('@sql: ',@sql)  
 EXEC sp_executesql @sql, N'@fromdate DATE, @todate DATE', @fromdate = @fromdate, @todate = @todate;        
 end        
 else        
 begin        
 SET @sql = N'        
  SELECT Srno, User_ID, FormattedUsername as UserByName,FormattedUsername as User_Login,        
                   
      dbo.fn_userleadsassigned_datewise(user_id, @fromdate, @todate) as TotalAssigned,        
      dbo.fn_userpendingfollowup_datewise(user_id, @fromdate, @todate) Pending,        
      ' + @ListPivotSelect + '        
  FROM (        
   SELECT a.Srno,a.ParentID,a.User_ID, a.FormattedUsername,a.level,ul.User_Login, ul.User_Login + '' ('' + isnull(ul.FName,'''') + '' '' + isnull(ul.LName,'''') + '')'' as UserByName   ,        
       b.SourceName,        
       isnull(dbo.fn_getsourcecount(a.user_id, @fromdate, @todate, b.SourceName),0) as Count        
   FROM #Hierarchy1 a        
   --LEFT JOIN #source b ON a.user_id = b.UserID        
   LEFT JOIN #source_1 b ON a.user_id = b.UserID        
  left join user_detail(nolock) ul on ul.User_ID=a.user_id          
  WHERE a.user_id in('+@strCriteriaName+') or a.ParentID in('+@strCriteriaName+')        
  ) AS SourceData        
  PIVOT (        
   SUM(Count)        
   FOR SourceName IN (' + @listtopivot + ')        
  ) AS PivotTable        
 ';        
 EXEC sp_executesql @sql, N'@fromdate DATE, @todate DATE', @fromdate = @fromdate, @todate = @todate;        
        
 end        
        
        
 -- Execute the dynamic SQL        
          
        
        
        
 select @ListPivotSelectClickable as SourceNameCollections           
               
    EXEC MySMSAudit.dbo.Usp_AuditTableDataByParentId @User_id = @userid                          
   ,@Activity_type = 'View_Rpt_Lead'                          
   ,@ActionType = 'S'                          
 ,@RowJson = ''                          
   ,@Table_name = 'Userleads'         
 end        
 if(@Mode='consolidate')        
 begin        
  CREATE TABLE #source1 (        
  sourceid INT,        
  SourceName VARCHAR(100),        
  UserID INT        
  --CONSTRAINT [PK_tmpSource11] PRIMARY KEY CLUSTERED(SourceName ASC)    
 );        
        
  CREATE TABLE #source1_1 (        
  sourceid INT,        
  SourceName VARCHAR(100),        
  UserID INT        
  );        
  
  CREATE TABLE #consolidate (        
  UserID INT,        
  Name VARCHAR(100)        
           
 );        
        
 declare @HierarchyJSON1 nvarchar(max)        
 -- Step 2: Populate #Hierarchy table (your existing logic should go here)        
 -- This part of your code remains unchanged        
        
 -- Step 3: Populate #source table (your existing logic should go here)        
 INSERT INTO #source1 (sourceid, SourceName, UserID)        
 SELECT distinct f.sourceid, trim(f.Name) as SourceName, @ParentId as UserID        
 FROM usersourcesettings(NOLOCK) f inner join #tbl_SourceID SD     
 ON F.SourceID = SD.SourceId LEFT JOIN prohibitedcharacters p     
 ON f.name LIKE '%' + p.charactersymbol + '%' AND p.charactersymbol <> '%'        
 WHERE isactive = 1 AND name NOT LIKE '%[%]%' AND name NOT LIKE '%.%' AND UserID = @ParentId        
 ORDER BY trim(f.Name) ASC;        
  
 INSERT INTO #source1_1 (sourceid, SourceName, UserID)        
 SELECT distinct f.sourceid, trim(f.Name) as SourceName, SD.AssignedTo as UserID        
 FROM usersourcesettings(NOLOCK) f inner join #tbl_SourceID1 SD     
 ON F.SourceID = SD.SourceId LEFT JOIN prohibitedcharacters p     
 ON f.name LIKE '%' + p.charactersymbol + '%' AND p.charactersymbol <> '%'        
 WHERE isactive = 1 AND name NOT LIKE '%[%]%' AND name NOT LIKE '%.%' AND UserID = @ParentId        
 ORDER BY trim(f.Name) ASC;      
  
 --select * from #source        
 -- Step 4: Prepare list of source names for pivot        
 DECLARE @listtopivot1 NVARCHAR(MAX) = '';        
 DECLARE @sql1 NVARCHAR(MAX);        
 DECLARE @ListPivotSelect1 NVARCHAR(MAX) = '', @ListPivotSelectClickable1 nvarchar(max)          
        
 SELECT @listtopivot1 = STRING_AGG('[' + cast(SourceName as nvarchar(max)) + ']', ', '),  
     @ListPivotSelect1= STRING_AGG('isnull([' + cast(SourceName as nvarchar(max)) + '],0) as [' + cast(SourceName as nvarchar(max)) + ']', ', ')       
 FROM #source1;        
        
 --SELECT @ListPivotSelect1 = @listtopivot1    
 -- STRING_AGG( + QUOTENAME(SourceName) , ', ')    FROM #source1;        
    
  SELECT @ListPivotSelectClickable1 = STRING_AGG(cast(REPLACE(REPLACE(REPLACE(QUOTENAME(SourceName), ' ', ''), '-', ''), '.', '') + '$' + QUOTENAME(sourceid) as nvarchar(max)),',')       
  FROM #source1(NOLOCK)    
  --order by SourceName asc        
    
  Select @HierarchyJSON1 = HierarchyJSON from tbl_UA_UserHierarchy(nolock) where  IsActive=1 and ParentId = @ParentId        
  -- Select @HierarchyJSON        
         
  if Exists(select 1 from tbl_UA_UserHierarchy(nolock) where ParentId = @ParentId and IsActive=1)        
  Begin        
   Select distinct parentid        
  into #UserHierarchy3 from OPENJSON(@HierarchyJSON1) with         
   (        
  parentid bigint        
   )          
   insert into #consolidate        
   select UH.Parentid,FName+ ' ' +LName as Name from #UserHierarchy3 UH        
   left join User_Detail UD on UD.User_ID=UH.parentid where FName is not null and LName is not null        
   END        
   Else if Exists(select 1 from tbl_UA_RoleHierarchy(nolock) where ParentId = @ParentId and IsActive=1)        
  Begin        
   print 'Role Hierarchy'                
         
    Select @HierarchyJSON1 = HierarchyJSON from tbl_UA_RoleHierarchy(nolock) where  IsActive=1 and ParentId = @ParentId        
         
   Select distinct parentid        
  into #UserRoleHierarchy_ from OPENJSON(@HierarchyJSON1) with         
   (        
  parentid bigint        
   )         
   insert into #consolidate        
   select UH.Parentid,FName+ ' ' +LName as Name  from #UserRoleHierarchy_ UH        
   left join User_Detail UD on UD.User_ID=UH.parentid  where FName is not null and LName is not null        
         
        
  select *  from #consolidate        
        
  end        
 -- Step 5: Pivot the data        
 SET @sql1 = N'        
  SELECT UserID as User_ID, Name as User_Login ,Name as UserByName,        
                   
      dbo.fn_userleadsassigned_datewise(UserID, @fromdate, @todate) as TotalAssigned,        
      dbo.fn_userpendingfollowup_datewise(UserID, @fromdate, @todate) Pending,        
      ' + @ListPivotSelect1 + '        
  FROM (        
   SELECT a.UserID,a.Name,ul.User_Login, ul.User_Login + '' ('' + isnull(ul.FName,'''') + '' '' + isnull(ul.LName,'''') + '')'' as UserByName   ,        
       b.SourceName,        
   dbo.fn_getsourcecount(a.UserID, @fromdate, @todate, b.SourceName) as Count        
   FROM #consolidate a        
   --LEFT JOIN #source1 b ON a.UserID = b.UserID        
   LEFT JOIN #source1_1 b ON a.UserID = b.UserID        
  left join user_detail(nolock) ul on ul.User_ID=a.UserID          
  ) AS SourceData        
  PIVOT (        
   SUM(Count)        
   FOR SourceName IN (' + @listtopivot1 + ')        
  ) AS PivotTable        
 ';        
        
 -- Execute the dynamic SQL        
          
        
 EXEC sp_executesql @sql1, N'@fromdate DATE, @todate DATE', @fromdate = @fromdate, @todate = @todate;        
 select @ListPivotSelectClickable1 as SourceNameCollections           
               
    EXEC MySMSAudit.dbo.Usp_AuditTableDataByParentId @User_id = @userid                          
   ,@Activity_type = 'View_Rpt_Lead'                          
   ,@ActionType = 'S'                          
   ,@RowJson = ''                          
   ,@Table_name = 'Userleads'         
    end        
 if(@Mode='UserWiseIndividual')        
 begin        
   
  CREATE TABLE #source_2 (        
  sourceid INT,        
  SourceName VARCHAR(100),        
  UserID INT        
  --CONSTRAINT [PK_tmpSource2] PRIMARY KEY CLUSTERED(SourceName ASC)    
  );        

 -- Step 2: Populate #Hierarchy table (your existing logic should go here)        
 -- This part of your code remains unchanged        
        
 -- Step 3: Populate #source table (your existing logic should go here)        
 INSERT INTO #source_2 (sourceid, SourceName, UserID)        
 SELECT DISTINCT sourceid, Name as SourceName, @ParentId as UserID        
 FROM usersourcesettings(NOLOCK) f        
 LEFT JOIN prohibitedcharacters p ON f.name LIKE '%' + p.charactersymbol + '%' AND p.charactersymbol <> '%'        
 WHERE isactive = 1 AND name NOT LIKE '%[%]%'        
 AND UserID = @ParentId        
 ORDER BY f.Name ASC;        
 --select * from #source        
 -- Step 4: Prepare list of source names for pivot        
        
        
 SELECT @listtopivot = STRING_AGG('[' + SourceName + ']', ', ')        
 FROM #source_2;        
        
 SELECT @ListPivotSelect = STRING_AGG( + QUOTENAME(SourceName) , ', ')        
 FROM #source_2;        
        
  SELECT @ListPivotSelectClickable = coalesce( @ListPivotSelectClickable +',','') + replace(Replace(replace(QUOTENAME(SourceName),' ',''),'-',''),'.','')        
     + '$' + QUOTENAME(sourceid)        
  FROM #source_2(NOLOCK) order by SourceName asc        
        
    -- DECLARE @HierarchyJSON NVARCHAR(MAX);        
        
   CREATE TABLE #HierarchyDetail_        
   (        
    User_id BIGINT,        
    UserName NVARCHAR(MAX),        
    Parentid BIGINT        
   );        
        
   IF EXISTS (SELECT 1 FROM tbl_UA_UserHierarchy (NOLOCK) WHERE ParentId = @ParentId AND IsActive = 1)        
   BEGIN        
    SELECT @HierarchyJSON = HierarchyJSON         
    FROM tbl_UA_UserHierarchy (NOLOCK)         
    WHERE IsActive = 1 AND ParentId = @ParentId;        
        
    INSERT INTO #HierarchyDetail_        
    SELECT DISTINCT uh.User_id, uh.UserName, uh.Parentid        
    FROM OPENJSON(@HierarchyJSON) WITH         
    (        
     parentid BIGINT,        
     username NVARCHAR(500),        
     user_id BIGINT        
    ) UH         
    INNER JOIN User_detail (NOLOCK) UD        
     ON UH.user_id = UD.user_ID;        
   END        
   ELSE IF EXISTS (SELECT 1 FROM tbl_UA_RoleHierarchy (NOLOCK) WHERE ParentId = @ParentId AND IsActive = 1)        
   BEGIN        
    PRINT 'Role Hierarchy';                
         
    SELECT @HierarchyJSON = HierarchyJSON         
    FROM tbl_UA_RoleHierarchy (NOLOCK)         
    WHERE IsActive = 1 AND ParentId = @ParentId;        
        
    SELECT DISTINCT parentid        
    INTO #UserRoleHierarchy1_        
    FROM OPENJSON(@HierarchyJSON) WITH         
    (        
     parentid BIGINT        
    );        
        
    INSERT INTO #HierarchyDetail_        
    SELECT UH.Parentid, FName + ' ' + LName AS username, user_id         
    FROM #UserRoleHierarchy1_ UH        
    LEFT JOIN User_Detail UD ON UD.User_ID = UH.parentid          
    WHERE FName IS NOT NULL AND LName IS NOT NULL;        
        
    DROP TABLE #UserRoleHierarchy1_;        
   END;        
        
   -- Recursive CTE        
   ;WITH UserHierarchy AS (        
    -- Base case: Select the top-level parents        
    SELECT         
     ParentID,         
     user_id,         
     CONCAT('<b>', Username, '</b>') AS FormattedUsername,        
     CAST(Username AS VARCHAR(MAX)) AS FormattedHierarchyPath,        
     0 AS Level        
    FROM         
     #HierarchyDetail_        
    WHERE         
     ParentID = 0        
        
    UNION ALL        
        
    -- Recursive case: Select children of the current level        
    SELECT         
     u.ParentID,         
     u.user_id,         
     CASE         
      WHEN uh.Level = 0 THEN CONCAT('<b>', u.Username, '</b>')        
      ELSE REPLACE(REPLACE(u.Username, '<b>', ''), '</b>', '')         
     END AS FormattedUsername,      
     CAST(CONCAT(uh.FormattedHierarchyPath, '<br>', REPLACE(REPLACE(u.Username, '<b>', ''), '</b>', '')) AS VARCHAR(MAX)) AS FormattedHierarchyPath,        
     uh.Level + 1 AS Level        
    FROM         
     #HierarchyDetail_ u        
    INNER JOIN         
     UserHierarchy uh ON u.ParentID = uh.user_id        
   )        
        
   -- Select and format the results        
   SELECT          
    ParentID,         
    user_id,         
    FormattedUsername,        
    FormattedHierarchyPath,        
    Level        
   INTO #UserHierarchy_        
   FROM UserHierarchy        
   ORDER BY         
    CASE WHEN ParentID = 0 THEN user_id ELSE ParentID END, -- Order by ParentID, but for root parents (ParentID = 0) use user_id        
    ParentID,         
    Level,         
    FormattedHierarchyPath;        
        
   --------------------        
          
         
        
   -- Create a temporary table to hold the results        
   CREATE TABLE #Hierarchy_ (        
   --Srno int,        
    ParentID INT,        
    user_id INT,        
    FormattedUsername NVARCHAR(MAX),        
    FormattedHierarchyPath NVARCHAR(MAX),        
    level INT,        
   TotalAssigned INT,        
   Pending INT,        
   ListToPivot NVARCHAR(MAX)        
   );        
        
   -- Declare variables        
                
   -- Create a cursor to loop through parent nodes        
   DECLARE ParentCursor CURSOR FOR        
   SELECT DISTINCT  ParentID, user_id, FormattedUsername, FormattedHierarchyPath, level        
   FROM #UserHierarchy_ --where Level <2;        
          
   -- Open the cursor        
   OPEN ParentCursor;        
        
          
   -- Fetch the first row from the cursor        
   FETCH NEXT FROM ParentCursor INTO @ParentID1, @UserID1, @FormattedUsername, @FormattedHierarchyPath, @Level;        
          
   -- Loop through the parent nodes        
   WHILE @@FETCH_STATUS = 0        
   BEGIN        
    -- Insert the parent node into the temporary table        
      INSERT INTO #Hierarchy_ ( ParentID, user_id, FormattedUsername, FormattedHierarchyPath, level, TotalAssigned, Pending, ListToPivot)        
    VALUES (@ParentID1, @UserID, @FormattedUsername, @FormattedHierarchyPath, @Level, dbo.fn_userleadsassigned_datewise(@UserID1, @fromdate, @todate),        
   dbo.fn_userpendingfollowup_datewise(@UserID1, @fromdate, @todate), @ListPivotSelect);        
    --select * from #Hierarchy        
    -- Fetch child nodes for the current parent node        
        
    INSERT INTO #Hierarchy_ (ParentID, user_id, FormattedUsername, FormattedHierarchyPath, level, TotalAssigned, Pending, ListToPivot)        
    SELECT DISTINCT ParentID, user_id, FormattedUsername, FormattedHierarchyPath, level, dbo.fn_userleadsassigned_datewise(user_id, @fromdate, @todate),        
   dbo.fn_userpendingfollowup_datewise(user_id, @fromdate, @todate), @ListPivotSelect         
    FROM #UserHierarchy_        
    WHERE ParentID = @UserID --and  Level >1        
  -- select * from #Hierarchy        
   --set @SrNo=@SrNo+1;        
            
    -- Fetch the next row from the cursor        
    FETCH NEXT FROM ParentCursor INTO @ParentID1, @UserID, @FormattedUsername, @FormattedHierarchyPath, @Level;        
   END        
        
   -- Close and deallocate the cursor        
   CLOSE ParentCursor;        
   DEALLOCATE ParentCursor;        
   --select ParentID, user_id, FormattedUsername, FormattedHierarchyPath,  level, TotalAssigned, Pending, ListToPivot from #Hierarchy        
        
  --drop table if exists #source         
        
  --select ROW_NUMBER() OVER(ORDER BY (SELECT 1)) as SrNo,* into #Hierarchy1 from #Hierarchy_        
        
        
 -- Step 5: Pivot the data        
 SET @sql = N'        
  SELECT ParentID,User_ID, FormattedUsername as UserByName,FormattedUsername as User_Login,        
                   
      dbo.fn_userleadsassigned_datewise(user_id, @fromdate, @todate) as TotalAssigned,        
      dbo.fn_userpendingfollowup_datewise(user_id, @fromdate, @todate) Pending,        
      ' + @ListPivotSelect + '        
  FROM (        
   SELECT a.ParentID,a.User_ID, a.FormattedUsername,a.level,ul.User_Login, ul.User_Login + '' ('' + isnull(ul.FName,'''') + '' '' + isnull(ul.LName,'''') + '')'' as UserByName   ,        
       b.SourceName,        
       isnull(dbo.fn_getsourcecount(a.user_id, @fromdate, @todate, b.SourceName),0) as Count        
   FROM #Hierarchy_ a        
   LEFT JOIN #source_2 b ON a.user_id = b.UserID        
  left join user_detail(nolock) ul on ul.User_ID=a.user_id          
          
            
              
  ) AS SourceData        
  PIVOT (        
   SUM(Count)        
   FOR SourceName IN (' + @listtopivot + ')        
  ) AS PivotTable        
 ';        
        
 -- Execute the dynamic SQL        
  --select @sql        
        
 EXEC sp_executesql @sql, N'@fromdate DATE, @todate DATE', @fromdate = @fromdate, @todate = @todate;        
        
 select @ListPivotSelectClickable as SourceNameCollections           
               
    EXEC MySMSAudit.dbo.Usp_AuditTableDataByParentId @User_id = @userid                          
   ,@Activity_type = 'View_Rpt_Lead'                          
   ,@ActionType = 'S'                          
   ,@RowJson = ''                   
   ,@Table_name = 'Userleads and usersourcesetting'         
  
 end        
  
 drop table if Exists #TableData2  
 drop table if Exists #TableData3  
 drop table if Exists #tmp_RoleHierarchy1  
 drop table if Exists #tmp_RoleHierarchy2  
 drop table if exists #source  
 drop table if exists #tbl_SourceID  
 drop table if exists #tbl_SourceID1  
 DROP TABLE if Exists #Hierarchy;        
 DROP TABLE if Exists #Hierarchy_;        
 DROP TABLE if Exists #source1;        
 DROP TABLE if Exists #source_1;        
 DROP TABLE if Exists #source1_1;    
 DROP TABLE if Exists #source_2;
 --DROP TABLE if Exists #UserRoleHierarchy;  
 DROP TABLE if Exists #UserRoleHierarchy1;  
 DROP TABLE if Exists #UserRoleHierarchy1_;  
 DROP TABLE if Exists #UserRoleHierarchy_;  
 DROP TABLE if Exists #HierarchyDetail;  
 DROP TABLE if Exists #HierarchyDetail_;  
 DROP TABLE if Exists #UserHierarchy_;
 DROP TABLE if exists #UserHierarchy;    
 DROP TABLE if exists #UserHierarchy2;    
 DROP TABLE if exists #UserHierarchy3;    
 DROP TABLE if exists #Hierarchy1;       
 DROP TABLE if exists #consolidate;       
  
end     



GO

/* ============================================================
   Procedure: [dbo].[Use_GetUserParentDetails$]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- exec [Use_GetUserParentDetails] 45160,'User',45160,'20240624', '20240625',''  
-- exec [Use_GetUserParentDetails] 45160,'User',45243,'20240624', '20240625',''  
 CREATE   PROC [dbo].[Use_GetUserParentDetails$]
	@ParentId nvarchar(max),
	@Mode nvarchar(500),
	@userid BIGINT
   ,@fromdate DATE                    
   ,@todate DATE  
   ,@strCriteriaName nvarchar(max)    
as  
begin  
CREATE TABLE #source (  
    sourceid INT,  
    SourceName VARCHAR(100),  
    UserID INT  
);  
DECLARE @listtopivot NVARCHAR(MAX) = '';  
DECLARE @sql NVARCHAR(MAX);  
DECLARE @ListPivotSelect NVARCHAR(MAX) = '',@ListPivotSelectClickable NVARCHAR(MAX) = '';  
DECLARE @ParentID1 INT;  
        DECLARE @UserID1 INT;  
        DECLARE @FormattedUsername NVARCHAR(MAX);  
        DECLARE @FormattedHierarchyPath NVARCHAR(MAX);  
        DECLARE @Level INT;DECLARE @Value INT=0;  
  
   DECLARE @bAddPeerUser bit = 0,@RoleId bigint = 0;  
  
   drop table if Exists #TableData3   
  
if(@Mode='User')  
begin  
declare @HierarchyJSON nvarchar(max)  
  
  if Exists(select 1 from tbl_UA_UserHierarchy(nolock) where ParentId = @ParentId and IsActive=1)  
 Begin  
  Select @HierarchyJSON = HierarchyJSON from tbl_UA_UserHierarchy(nolock) where  IsActive=1 and ParentId = @ParentId  
 -- Select @HierarchyJSON  
  
  Select distinct parentid  
 into #UserHierarchy2 from OPENJSON(@HierarchyJSON) with   
  (  
 parentid bigint  
  )    
  select UH.Parentid,FName+ ' ' +LName as Name from #UserHierarchy2 UH  
  left join User_Detail UD on UD.User_ID=UH.parentid where FName is not null and LName is not null  
  END  
  Else if Exists(select 1 from tbl_UA_RoleHierarchy(nolock) where ParentId = @ParentId and IsActive=1)  
 Begin  
  --print 'Role Hierarchy'          
   
 /*  
  Select @HierarchyJSON = HierarchyJSON from tbl_UA_RoleHierarchy(nolock) where  IsActive=1 and ParentId = @ParentId  
   
  Select distinct parentid  
 into #UserRoleHierarchy from OPENJSON(@HierarchyJSON) with   
  (  
 parentid bigint  
  )   
    
  select UH.Parentid,FName+ ' ' +LName as Name from #UserRoleHierarchy UH  
  left join User_Detail UD on UD.User_ID=UH.parentid  where FName is not null and LName is not null  
  end  
  */  
  
  
    print 'Role Hierarchy'          
        
  Select @HierarchyJSON = HierarchyJSON, @bAddPeerUser=bAddPeerUser from tbl_UA_RoleHierarchy(nolock) where ParentId = @ParentId and IsActive=1  
  
  Select @RoleId=tuRolem.RoleId  
  FROM TBL_UA_UserRoleMappingMaster(NOLOCK) tuUserrm LEFT JOIN TBL_UA_RoleMaster(NOLOCK)  tuRolem    
  ON tuUserrm.RoleCode = tuRolem.RoleCode and tuRolem.Active=1 and tuUserrm.Active=1  
  WHERE [tuUserrm].[UserId] = @UserId    
  
  print concat('@RoleId: ',@RoleId)  
        
  drop table if Exists #TableData3        
        
  Create TABLE #TableData3 (roleid bigint, rolename Varchar(50), rolecode varchar(50), parentid bigint)  
  Insert into #TableData3 (roleid, rolename, rolecode, parentid)  
  Select roleid, rolename, rolecode, parentid  
  from OPENJSON(@HierarchyJSON) with   
  (  
 roleid bigint,   
 rolename Varchar(100),   
 rolecode Varchar(100),   
 parentid bigint  
  )        
           
  If not exists(Select * from #TableData3 Where roleid=@RoleId)        
  Begin        
 print 'User does not exist in Role Hierarchy'      
     
 SELECT ud.Parentid,ud.FName+ ' ' +ud.LName as Name ,ud.[User_ID]  
  --, ud.User_Login + ' ('+ ud.FName +' '+LName +')' [Name]  
  --, [Image]           
 FROM User_Detail(nolock) AS ud           
 WHERE ud.[User_ID] = @UserID      
  End    
  Else    
  Begin    
   print 'Role Hierarchy listing'      
  print concat('@bAddPeerUser: ',@bAddPeerUser)  
    
 IF(@bAddPeerUser=1)  
 Begin  
    ;with CTE(roleid,rolename,rolecode,parentid)    
    as     
    (    
  select roleid,rolename,rolecode,parentid  
  from #TableData3 where roleid = @RoleId    
  union all    
  -- recursively add children    
  select c.roleid,c.rolename,c.rolecode,c.parentid    
  from #TableData3 c    
  join CTE on c.parentid = CTE.roleid    
    )    
  
  SELECT ud.Parentid,ud.FName+ ' ' +ud.LName as Name,ud.[User_ID]  
  --, ud.User_Login + ' ('+ ud.FName +' '+LName +')' [Name]  
  --, [Image]           
  FROM User_Detail(nolock) AS ud inner join TBL_UA_UserRoleMappingMaster(NOLOCK) tuUserrm  
  ON ud.user_id =tuUserrm.UserId inner JOIN TBL_UA_RoleMaster(NOLOCK)  tuRolem    
  ON tuUserrm.RoleCode = tuRolem.RoleCode and tuRolem.Active=1 and tuUserrm.Active=1 inner join CTE    
  ON tuRolem.roleid=CTE.roleid    
  WHERE ud.status = 1  
 End  
 Else  
 Begin  
   
    ;with CTE(roleid,rolename,rolecode,parentid)    
    as     
    (    
  select roleid,rolename,rolecode,parentid  
  from #TableData3 where roleid = @RoleId    
  union all    
  -- recursively add children    
  select c.roleid,c.rolename,c.rolecode,c.parentid    
  from #TableData3 c    
  join CTE on c.parentid = CTE.roleid    
    )    
  
  SELECT ud.Parentid,ud.FName+ ' ' +ud.LName as Name ,ud.[User_ID]  
  --ud.[User_ID], ud.User_Login + ' ('+ ud.FName +' '+LName +')' [Name], [Image]           
  FROM User_Detail(nolock) AS ud inner join TBL_UA_UserRoleMappingMaster(NOLOCK) tuUserrm  
  ON ud.user_id =tuUserrm.UserId inner JOIN TBL_UA_RoleMaster(NOLOCK)  tuRolem    
  ON tuUserrm.RoleCode = tuRolem.RoleCode and tuRolem.Active=1 and tuUserrm.Active=1 inner join CTE    
  ON tuRolem.roleid=CTE.roleid    
  WHERE ud.status = 1 and ud.User_ID not in (Select tuUserrm1.UserId  
   FROM TBL_UA_UserRoleMappingMaster(NOLOCK) tuUserrm1 LEFT JOIN TBL_UA_RoleMaster(NOLOCK)  tuRolem1    
   ON tuUserrm1.RoleCode = tuRolem1.RoleCode and tuRolem1.Active=1 and tuUserrm1.Active=1  
   WHERE [tuUserrm1].[UserId] != @UserId and tuRolem1.RoleId=@RoleId )  
  
 End  
   end  
   end  
   drop table if Exists #TableData3   
      
  --drop table #UserHierarchy2  
  --drop table #UserRoleHierarchy  
    
  end  
