        FROM #UserHierarchy --where Level <2;  
  --DECLARE @Value INT=0;  
        -- Open the cursor  
        OPEN ParentCursor;  
  
    
        -- Fetch the first row from the cursor  
        FETCH NEXT FROM ParentCursor INTO @ParentID1, @UserID1, @FormattedUsername, @FormattedHierarchyPath, @Level;  
    
        -- Loop through the parent nodes  
        WHILE @@FETCH_STATUS = 0  
        BEGIN  
            -- Insert the parent node into the temporary table  
           INSERT INTO #Hierarchy ( ParentID, user_id, FormattedUsername, FormattedHierarchyPath, level, TotalAssigned, Pending, ListToPivot)  
            VALUES (@ParentID1, @UserID, @FormattedUsername, @FormattedHierarchyPath, @Level, dbo.fn_userleadsassigned_datewise(@UserID1, @fromdate, @todate),  
        dbo.fn_userpendingfollowup_datewise(@UserID1, @fromdate, @todate), @ListPivotSelect);  
   --select * from #Hierarchy  
            -- Fetch child nodes for the current parent node  
  
            INSERT INTO #Hierarchy (ParentID, user_id, FormattedUsername, FormattedHierarchyPath, level, TotalAssigned, Pending, ListToPivot)  
            SELECT DISTINCT ParentID, user_id, FormattedUsername, FormattedHierarchyPath, level, dbo.fn_userleadsassigned_datewise(user_id, @fromdate, @todate),  
        dbo.fn_userpendingfollowup_datewise(user_id, @fromdate, @todate), @ListPivotSelect   
            FROM #UserHierarchy  
            WHERE ParentID = @UserID --and  Level >1  
    -- select * from #Hierarchy  
     --set @SrNo=@SrNo+1;  
      
            -- Fetch the next row from the cursor  
            FETCH NEXT FROM ParentCursor INTO @ParentID1, @UserID, @FormattedUsername, @FormattedHierarchyPath, @Level;  
        END  
  
        -- Close and deallocate the cursor  
        CLOSE ParentCursor;  
        DEALLOCATE ParentCursor;  
  --select ParentID, user_id, FormattedUsername, FormattedHierarchyPath,  level, TotalAssigned, Pending, ListToPivot from #Hierarchy  
  
 --drop table if exists #source   
  
 select ROW_NUMBER() OVER(ORDER BY (SELECT 1)) as SrNo,* into #Hierarchy1 from #Hierarchy  
  
 if(@strCriteriaName='')begin  
