/* ============================================================
   Procedure: [dbo].[use_iPTrackTrport]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


--  use_iPTrackTrport 335,'2019-02-19','2019-02-19','','182.75.38.29'  
  CREATE   PROC use_iPTrackTrport  
 (  
 @ParentId bigint,  
 @frmDate varchar(10) ,  
 @todate varchar(10) ,  
 @pagenm varchar(100),  
 @ipAddress varchar(200)  
 )  
 as   
 begin  
  
 declare @sqlstr  varchar(max), @fltr varchar(max)  
   
 set @fltr = ''  
 set @sqlstr = 'select tk.*,ud.User_Login,pd.User_Login,ISNULL(ll.location,'''') location,  
 isnull(source_from,'''') source_from, isnull(zipcode,'''') zipcode,
  case when  isnull(mobileVer,0) = 1 then ''Mobile'' else ''Deskpot'' end as mobileVer,
  isnull(browser,'''') browser, isnull(platform,'''') platform, 
  isnull(Dmodel,'''')  Dmodel, isnull(Divos,'''') Divos
 from user_ip_track tk  
 inner join User_Detail ud  
 on ud.user_id = tk.userid  
 inner join User_Detail pd  
 on pd.user_id = tk.ParentId left outer join   
 SMS_Link_Location ll on ll.IPAddress = tk.ipAdd '    
   
 if @ParentId > 0  
 begin  
  set @fltr = ' where tk.parentid='+cast(@ParentId as varchar)  
 end   
  
 if @frmDate !='' and @todate !=''  
 begin  
 if @fltr!=''  
  set @fltr = @fltr+' and convert(date,VisitTime)             
  between '''+ @frmDate +''' and '''+@toDate+''''        
else  
 set @fltr =  ' where convert(date,VisitTime)             
  between '''+ @frmDate +''' and '''+@toDate+''''    
 end  
 if @pagenm!=''            
 begin            
 if @fltr !=''            
 set @fltr = @fltr+ ' and url like ''%'+@pagenm+'%'''            
 else            
 set @fltr = ' where url like ''%'+@pagenm+'%'''            
 end   
   
  if @ipAddress!=''            
 begin            
 if @fltr !=''            
 set @fltr = @fltr+ ' and ipAdd like ''%'+@ipAddress+'%'''            
 else            
 set @fltr = ' where ipAdd like ''%'+@ipAddress+'%'''            
 end   
 set @fltr = @fltr+' Order by VisitTime desc'  
--select  (@sqlstr+@fltr)  
exec (@sqlstr+@fltr)  
 end


GO

/* ============================================================
   Procedure: [dbo].[Use_le_GetLeadwiseDepParentDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


--exec Use_le_GetLeadwiseDepParentDetails @ParentId=N'45160',@Mode=N'DepManagerWise',@userid=45160,@fromdate='2024-08-23',@todate='2024-08-24',@strCriteriaName=N''
--exec Use_le_GetLeadwiseDepParentDetails @ParentId=N'45160',@Mode=N'DepManagerWise',@userid=45160,@fromdate='2024-08-23',@todate='2024-08-24',@strCriteriaName=N'45321'
--exec Use_le_GetLeadwiseDepParentDetails @ParentId=N'45160',@Mode=N'DepManagerWise',@userid=45160,@fromdate='2024-08-20',@todate='2024-08-21',@strCriteriaName=N''
--exec Use_le_GetLeadwiseDepParentDetails @ParentId=N'45160',@Mode=N'DepWise',@userid=45160,@fromdate='2024-08-20',@todate='2024-08-21',@strCriteriaName=N''
--exec Use_eq_GetDepParentDetails @ParentId=N'45160',@Mode=N'DepManagerWise',@userid=45160,@fromdate='2024-08-20',@todate='2024-08-21',@strCriteriaName=N''
  --Exec Use_le_GetLeadwiseDepParentDetails @ParentId=45160,@Mode='DepWise',@userid=45160,@fromdate='08-Aug-2024',@todate='09-Aug-2024',@strCriteriaName=''
  --Exec Use_le_GetLeadwiseDepParentDetails @ParentId=45160,@Mode='DepManagerWise',@userid=45160,@fromdate='08-Aug-2024',@todate='09-Aug-2024',@strCriteriaName=''
CREATE   PROC [dbo].[Use_le_GetLeadwiseDepParentDetails]
(
	@ParentId nvarchar(max)='',  
	@Mode nvarchar(500)='',  
	@userid BIGINT                    
   ,@fromdate DATE                    
   ,@todate DATE  
   ,@strCriteriaName nvarchar(max)=''  
)  
as
BEGIN  

	--declare @ParentId nvarchar(max)='45160',  
	--	@Mode nvarchar(500)='DepManagerWise',  
	--	@userid BIGINT=45160,
	--	@fromdate DATE='20-Aug-2024',
	--	@todate DATE='21-Aug-2024',
	--	@strCriteriaName nvarchar(max)='45321'  

	drop table if exists #source
	drop table if exists #source_1
	drop table if exists #Temp
	drop table if exists #tbl_SourceID
	drop table if exists #tbl_SourceID1
	DROP TABLE if exists #BrandData;  
    DROP TABLE if exists #Brand;  

    CREATE TABLE #source (  
        sourceid INT,  
        SourceName VARCHAR(100),  
        UserID INT  
		--CONSTRAINT [PK_tmpSource] PRIMARY KEY CLUSTERED(SourceName ASC)
    );  

  	 CREATE TABLE #source_1 (      
		sourceid INT,      
		SourceName VARCHAR(100),      
		UserID INT      
	 );      

    DECLARE @listtopivot NVARCHAR(MAX) = '';  
    DECLARE @sql NVARCHAR(MAX);  
    DECLARE @ListPivotSelect NVARCHAR(MAX) = '', @ListPivotSelectClickable NVARCHAR(MAX) = '';  
    DECLARE @FieldID BIGINT, @createdby NVARCHAR(MAX), @fieldvalue NVARCHAR(MAX)--, @Parentid BIGINT;  
  
	Select  UL.SourceName as SourceId, COUNT(*) as Cnt
	into	#tbl_SourceID
	from	UserLeads(nolock) UL 
	Where	UL.parentId=@ParentId
	group by	UL.SourceName
	having	count(*)>0

	Select  UL.SourceName as SourceId, UL.AssignedTo, COUNT(*) as Cnt  
	into #tbl_SourceID1  
	from UserLeads(nolock) UL   
	Where UL.parentId=@ParentId  
	group by UL.SourceName, UL.AssignedTo  
	having count(*)>0  

    -- Insert into #source  
    INSERT INTO #source (sourceid, SourceName, UserID)  
	SELECT f.sourceid, f.Name AS SourceName, @ParentId AS UserID  
    FROM usersourcesettings (NOLOCK) f inner join #tbl_SourceID SD 
	ON	F.SourceID = SD.SourceId left JOIN prohibitedcharacters(NOLOCK) p 
	ON f.name LIKE '%' + p.charactersymbol + '%' AND p.charactersymbol <> '%'  
    WHERE isactive = 1 AND name NOT LIKE '%[%]%' AND name NOT LIKE '%.%' AND UserID = @ParentId  
    ORDER BY f.Name ASC;  
	
	INSERT INTO #source_1 (sourceid, SourceName, UserID)      
	SELECT f.sourceid, trim(f.Name) as SourceName, SD.AssignedTo as UserID      
	FROM usersourcesettings(NOLOCK) f inner join #tbl_SourceID1 SD   
	ON F.SourceID = SD.SourceId LEFT JOIN prohibitedcharacters p   
	ON f.name LIKE '%' + p.charactersymbol + '%' AND p.charactersymbol <> '%'      
	WHERE isactive = 1 AND name NOT LIKE '%[%]%' AND name NOT LIKE '%.%' AND UserID = @ParentId      
	ORDER BY trim(f.Name) ASC;    

    -- Prepare list of source names for pivot  
    SELECT @listtopivot = string_agg(cast(QUOTENAME(SourceName) as nvarchar(max)),','),
	@ListPivotSelect= STRING_AGG('isnull([' + cast(SourceName as nvarchar(max)) + '],0) as [' + cast(SourceName as nvarchar(max)) + ']', ', ')
    FROM #source


	print concat('@listtopivot: ',@listtopivot)

  
	--SELECT @ListPivotSelect = @listtopivot  
	print concat('@ListPivotSelect: ',@ListPivotSelect)

	SELECT @ListPivotSelectClickable =   
    STRING_AGG(cast(REPLACE(REPLACE(REPLACE(QUOTENAME(SourceName), ' ', ''), '-', ''), '.', '') + '$' + QUOTENAME(sourceid) as nvarchar(max)),',')  
    FROM #source (NOLOCK)  
    --ORDER BY SourceName  
        
	print concat('@ListPivotSelectClickable: ',@ListPivotSelectClickable)

    IF (@Mode = 'DepWise')  
    BEGIN  
		SELECT @FieldID = field_ID   
		FROM customfields (NOLOCK)   
		WHERE fieldname ='Brand_name' AND ParentID = @ParentId;  

		-- Select distinct fieldID, EnquiryID, fieldvalue, createdby into a temporary table  
		SELECT DISTINCT fieldID, ue.ID, fieldvalue, FName + ' ' + LName as createdby,AssignedTo as createdby1, UE.ParentID  
		into #Temp 
		FROM UserLeads (NOLOCK) UE LEFT JOIN customfieldLeadvalue (NOLOCK) b 
		ON ue.ID = b.LeadID AND b.fieldID = @FieldID LEFT JOIN User_Detail(NOLOCK) UD 
		ON UD.User_ID = UE.AssignedTo  
		WHERE ue.ParentID = @ParentId and  fieldvalue is not null and fieldvalue <> '' --and cast(UE.CreatedOn as date) between @fromdate and @todate
  
        SET @sql = N'  
            SELECT 2 Total,ParentID AS User_ID, fieldvalue AS UserByName, fieldvalue AS Brand,  
                   ' + @ListPivotSelect + '  
            FROM (  
                SELECT distinct a.ParentID, a.fieldID, a.fieldvalue, ul.User_Login, ul.User_Login + '' ('' + ISNULL(ul.FName, '''') + '' '' + ISNULL(ul.LName, '''') + '')'' AS UserByName,  
                       b.SourceName,  
                       ISNULL(dbo.fn_getleadsourcecount(a.ParentID, @fromdate, @todate, b.SourceName,a.fieldvalue), 0) AS Count  
                FROM #Temp a  
                LEFT JOIN #source b ON a.ParentID = b.UserID  
                LEFT JOIN user_detail (NOLOCK) ul ON ul.User_ID = a.ParentID  
            ) AS SourceData  
            PIVOT (  
                SUM(Count)  
                FOR SourceName IN (' + @listtopivot + ')  
            ) AS PivotTable';  
		print cast(@sql as nvarchar(max))
  
        EXEC sp_executesql @sql, N'@fromdate DATE, @todate DATE', @fromdate = @fromdate, @todate = @todate;  
  
        SELECT @ListPivotSelectClickable AS SourceNameCollections;  
  
    END  
  
    IF (@Mode = 'DepManagerWise')  
    BEGIN  
        DECLARE @SrNo INT = 1;  
  
        SELECT @FieldID = field_ID   
        FROM customfields (NOLOCK)   
        WHERE fieldname = 'Brand_name' AND ParentID = @ParentId;  
  
        CREATE TABLE #BrandData (  
            fieldID BIGINT,  
            EnquiryID BIGINT,  
            fieldvalue NVARCHAR(MAX),  
            createdby NVARCHAR(MAX),  
            createdby1 BIGINT,  
            ParentID BIGINT  
        );  
  
        IF (@strCriteriaName = '')  
        BEGIN  
            INSERT INTO #BrandData  
            SELECT DISTINCT fieldID, ue.id,   
                   CONVERT(NVARCHAR(MAX), fieldvalue) AS fieldvalue,   
                   FName + ' ' + LName AS createdby,   
                   AssignedTo AS createdby1,   
                   UE.ParentID  
            FROM UserLeads (NOLOCK) UE join customfields(NOLOCK) a on a.ParentID=UE.ParentID  
            LEFT JOIN customfieldLeadvalue (NOLOCK) b ON  b.fieldID = a.field_ID and b.LeadID=UE.ID
            LEFT JOIN User_Detail(NOLOCK) UD ON UD.User_ID = UE.AssignedTo  
            WHERE ue.ParentID = @ParentId and  fieldvalue is not null and    a.fieldname = 'Brand_name'  
        END  
        ELSE  
        BEGIN  
            INSERT INTO #BrandData  
            SELECT DISTINCT fieldID, ue.ID,   
                   CONVERT(NVARCHAR(MAX), fieldvalue) AS fieldvalue,   
                   FName + ' ' + LName AS createdby,   
                   AssignedTo AS createdby1,   
                   UE.ParentID  
            FROM UserLeads (NOLOCK) UE  
            LEFT JOIN customfieldLeadvalue (NOLOCK) b ON ue.ID = b.LeadID AND b.fieldID = @FieldID  
            LEFT JOIN User_Detail(NOLOCK) UD ON UD.User_ID = UE.AssignedTo  
            WHERE ue.ParentID = @ParentId AND user_id IN (@strCriteriaName) AND fieldvalue IS NOT NULL;  
        END  
  
        CREATE TABLE #Brand (  
            SrNo INT,  
            Brands NVARCHAR(500),  
            fieldID sql_variant,  
            id BIGINT,  
			Total int  
        );  
  
        DECLARE ParentCursor CURSOR FOR  
            SELECT DISTINCT createdby,fieldvalue, createdby1  
            FROM #BrandData;  
  
        OPEN ParentCursor;  
        FETCH NEXT FROM ParentCursor INTO @createdby,@fieldvalue, @Parentid;  
  
    
  
        WHILE @@FETCH_STATUS = 0  
        BEGIN  
  --select   @createdby, @fieldvalue, @Parentid;  
            INSERT INTO #Brand (SrNo, Brands, id,fieldID,Total)  
            SELECT DISTINCT @SrNo, '<b>' +ISNULL(CAST(fieldvalue AS NVARCHAR(500)), '')+'<b>', @Parentid,  
   CAST(fieldvalue AS NVARCHAR(500)),1  
            FROM #BrandData  
            WHERE fieldvalue = @fieldvalue;  
  
            SET @SrNo += 1;  
  
            INSERT INTO #Brand (SrNo, Brands, id,fieldID,Total)  
            VALUES (@SrNo, CAST(@createdby AS NVARCHAR(500)), @Parentid,CAST(@fieldvalue AS NVARCHAR(500)),2)  
  
            SET @SrNo += 1;  
  
            FETCH NEXT FROM ParentCursor INTO @createdby, @fieldvalue,@Parentid;  
        END  
  
        CLOSE ParentCursor;  
        DEALLOCATE ParentCursor;  
  
    
        SET @sql = N'  
            SELECT distinct SrNo,Total, id AS User_ID, Brands AS UserByName, Brands AS Brand,  
                   ' + @ListPivotSelect + '  
            FROM (  
                SELECT distinct SrNo, a.id, a.Brands, b.SourceName,  
                       ISNULL(dbo.fn_getleaduserwisesourcecount(a.id, @fromdate, @todate, b.SourceName,a.fieldID), 0) AS Count,a.Total  
                FROM #Brand a  
                --LEFT JOIN #source b ON a.id = b.UserID  
                LEFT JOIN #source_1 b ON a.id = b.UserID  
                LEFT JOIN user_detail (NOLOCK) ul ON ul.User_ID = a.id  
            ) AS SourceData  
            PIVOT (  
                SUM(Count)  
                FOR SourceName IN (' + @listtopivot + ')  
            ) AS PivotTable';  
  
		print concat('@sql: ',@sql)
        EXEC sp_executesql @sql, N'@fromdate DATE, @todate DATE', @fromdate = @fromdate, @todate = @todate;  
		SELECT @ListPivotSelectClickable AS SourceNameCollections;  
    END  
  
	drop table if exists #source
	drop table if exists #source_1
	drop table if exists #Temp
	drop table if exists #tbl_SourceID
	drop table if exists #tbl_SourceID1
	DROP TABLE if exists #BrandData;  
    DROP TABLE if exists #Brand;  

END  



GO

