CREATE   PROCEDURE [dbo].[USP_ACTIVATELINK_GETSERVICENAME]--'OD_C5DFBC536E','1'    
@ODERID NVARCHAR(50),    
@FLAG INT    
AS    
SET NOCOUNT ON     
IF (@FLAG='1')    
BEGIN    
Declare @Date datetime;    
SET @DATE= (SELECT PAYMENTDATE FROM ONLINEPAYMENTDETAIL(nolock) WHERE [INVOICENO]=@ODERID);    
