/* ============================================================
   Procedure: [dbo].[usp_active_user]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--exec usp_active_user 32222    
--exec usp_active_user 34594    
--exec usp_active_user 45160  
CREATE   PROC [dbo].[usp_active_user]
	@User_Id BIGINT
AS
BEGIN
	-- DECLARE @User_Id BIGINT=45160;
	DECLARE @ParentId BIGINT;
	SET NOCOUNT ON;
	SELECT TOP 1 @ParentId=[ParentId] FROM user_detail(NOLOCK) WHERE User_ID = @User_Id;

	IF EXISTS(SELECT 1 FROM tbl_UA_UserHierarchy(NOLOCK) WHERE IsActive=1 and [ParentId] = @ParentId)
	BEGIN
		SELECT User_ID, [User_Login], [FName], [LName], [User_Login] + '(' + [FName] + ' ' + [LName] + ')' AS
		[UserName]
		FROM user_detail(NOLOCK)
		WHERE STATUS = '1'
			  AND [ParentID] = @ParentId
			  AND ( ( User_ID IN(SELECT User_ID
								 FROM OPENJSON((SELECT [HierarchyJSON] FROM [tbl_UA_UserHierarchy](NOLOCK)
								 WHERE IsActive=1 and [ParentId] = @ParentId)) WITH(user_id INT)) )
					OR ( User_ID IN(SELECT [parentid]
									FROM OPENJSON((SELECT [HierarchyJSON] FROM [tbl_UA_UserHierarchy](NOLOCK)
									WHERE IsActive=1 and [ParentId] = @ParentId)) WITH([parentid] INT)) ) )
		ORDER BY [User_Login];
	END;
	ELSE
	BEGIN
		IF( @ParentId = @User_Id )
		BEGIN
			SELECT DISTINCT
				   User_ID, [User_Login], [FName], [LName], [User_Login] + '(' + [FName] + ' ' + [LName] +
				   ')' AS [UserName]
			FROM user_detail(NOLOCK)
			WHERE User_ID = @User_ID;
		END;
		ELSE
		BEGIN
			SELECT DISTINCT
				   User_ID, [User_Login], [FName], [LName], [User_Login] + '(' + [FName] + ' ' + [LName] +
				   ')' AS [UserName]
			FROM user_detail(NOLOCK)
			WHERE ParentId = @ParentId;
		END;
	END;
	SET NOCOUNT OFF;
END;



GO

