/* ============================================================
   Procedure: [dbo].[Usp_ActivityViewDataBind]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_ActivityViewDataBind]      
    @activityid varchar(max),
    @entityname NVARCHAR(100)
AS          
BEGIN   

 --declare @activityid varchar(max) ='0x0200000048985C9FEEB4C36B8C4AD8513415FA7A393B09C9C4AECE9D53D2D1FC54E6B6F2', @entityname nvarchar(100) = 'Lead'  
  DECLARE @userids NVARCHAR(MAX), @decryptedActivityId VARCHAR(100), @user BIGINT, @parentid BIGINT, @eventid INT, @eventname NVARCHAR(100), @entityid BIGINT, @reftables NVARCHAR(MAX), @refids NVARCHAR(MAX), @seektable NVARCHAR(100), @context NVARCHAR(100), @notificationid BIGINT= 0, @ispredefined bit = 0;  
    -- Call usp_getmetadata_foractivity
	 SET @decryptedactivityid = convert(varchar(100),DecryptByPassPhrase('EncryptActivityID',CONVERT(VARBINARY(max), @activityid, 1)))
	   PRINT @decryptedActivityId;
    EXEC usp_getmetadata_foractivity @decryptedactivityid, @entityname;

    -- Select from tbl_LeadEventHistory 

   IF(@entityname = 'Lead')
BEGIN
  SELECT  @entityid = [LeadID]                        
  FROM tbl_LeadEventHistory(NOLOCK)              
  WHERE [historyid] = @decryptedactivityid;       
  
  SELECT LEH.EventDescription, LEH.ParentID, LEH.EventID, LEH.EventDate, LEH.LeadID, AM.EventName
    FROM tbl_LeadEventHistory LEH (NOLOCK)
    LEFT JOIN activitymaster AM ON LEH.EventID = AM.ID
    WHERE LEH.historyid = @decryptedactivityid;
END
   if( @entityname = 'Enquiry')
	Begin
	  SELECT  @entityid = [EnquiryID]                        
  FROM tbl_enquiryEventHistory(NOLOCK)              
  WHERE [historyid] = @decryptedactivityid; 

    SELECT EEH.EventDescription, EEH.ParentID, EEH.EventID,EEH.EventDate, EEH.EnquiryID, AM.EventName        
    FROM tbl_enquiryEventHistory EEH(NOLOCK) 
	   LEFT JOIN activitymaster AM ON EEH.EventID = AM.ID
    WHERE [historyid] = @decryptedactivityid;  
	END
   if( @entityname = 'user')
	Begin
    SELECT UEH.EventDescription, UEH.ParentID, UEH.EventID,UEH.EventDate, UEH.HistoryID,AM.EventName        
    FROM tbl_userEventHistory UEH (NOLOCK)  
	   LEFT JOIN activitymaster AM ON UEH.EventID = AM.ID
    WHERE [historyid] = @decryptedactivityid;  
	END
   if( @entityname = 'Lead')
   Begin
	select LeadNo as Number,PersonName,LeadImage as Image, 'Lead' as Type from userleads(nolock) where ID=@entityid
	END
   if( @entityname = 'Enquiry')
   Begin
   select EnquiryID as Number,PersonName,ProfileImgFileName as Image,'Enquiry' as Type from userenquiry(nolock) where EnquiryID=@entityid
   END
   if( @entityname = 'user')
   Begin
SELECT User_ID as Number, CONCAT(FName, ' ', LName) as FullName, ProfilePicturePath as Image,'User' as Type
FROM User_Detail (NOLOCK)
WHERE User_ID = @entityid;
   END
END







GO

