/* ============================================================
   Procedure: [dbo].[Usp_Ad_Cmpn_InstUpdtAcsTkn]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_Ad_Cmpn_InstUpdtAcsTkn @PersonName NVARCHAR(MAX)          
 ,@LongAccessToken NVARCHAR(MAX)          
 ,@ExpiryTimestamp NVARCHAR(MAX)          
 ,@FbUserId NVARCHAR(MAX)          
 ,@Userid BIGINT      
 ,@appid Nvarchar(max)
AS          
BEGIN          
 DECLARE @Parentid BIGINT = (          
   SELECT ParentID          
   FROM User_Detail(NOLOCK) ud          
   WHERE User_ID = @Userid          
   )          
    DECLARE @activity VARCHAR(MAX) = ''  
  ,@action VARCHAR(1) = ''  
  ,@rowJson NVARCHAR(MAX) = ''  
          
 IF (          
   EXISTS (          
    SELECT 1          
    FROM tbl_FbAdCmpgn_AccessToken          
    WHERE FbUserId = @FbUserId          
    )          
   )          
 BEGIN          
  UPDATE tbl_FbAdCmpgn_AccessToken          
  SET LongAccessToken = @LongAccessToken          
   ,ExpiryTimestamp = @ExpiryTimestamp          
   ,UpdatedOn = GETDATE()     
   ,App_Id=@appid
  WHERE FbUserId = @FbUserId;          
        
  Select 'Updated'    
  SET @rowJson = (  
      SELECT *  
      FROM tbl_FbAdCmpgn_AccessToken WITH (NOLOCK)  
      WHERE FbUserId = @FbUserId  
      FOR JSON AUTO  
       ,INCLUDE_NULL_VALUES  
      )  
    SET @activity = 'Updt_AdUserAccsTkn'  
    SET @action = 'U'  
 END          
 ELSE          
 BEGIN          
  INSERT INTO tbl_FbAdCmpgn_AccessToken (          
   PersonName          
   ,LongAccessToken          
   ,ExpiryTimestamp          
   ,FbUserId          
   ,ParentId          
   ,Userid          
   ,CreatedOn    
   ,App_Id
   )          
  VALUES (          
   @PersonName          
   ,@LongAccessToken          
   ,@ExpiryTimestamp          
   ,@FbUserId          
   ,@Parentid          
   ,@Userid          
   ,GETDATE()
   ,@appid
   );          
      declare @id bigint =scope_identity();  
   Select 'Inserted'       
   SET @rowJson = (  
      SELECT *  
      FROM tbl_FbAdCmpgn_AccessToken WITH (NOLOCK)  
      WHERE id = @id  
      FOR JSON AUTO  
       ,INCLUDE_NULL_VALUES  
      )  
    SET @activity = 'Inst_AdUserAccsTkn'  
    SET @action = 'I'  
 END          
 IF @rowJson IS NOT NULL  
 BEGIN  
  EXEC MySmsAudit_dev.dbo.Usp_AuditTableDataByParentId @User_id = @Userid  
   ,@Activity_type = @activity  
   ,@ActionType = @action  
   ,@RowJson = @rowJson  
   ,@Table_name = 'tbl_FbAdCmpgn_AccessToken'  
 END  
END; 


GO

/* ============================================================
   Procedure: [dbo].[Usp_Ad_GetAdDataForAllParent]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON



CREATE   PROCEDURE [dbo].[Usp_Ad_GetAdDataForAllParent] @parentid BIGINT = NULL          
 ,@fromdate DATETIME = NULL          
 ,@todate DATETIME = NULL          
 ,@status NVARCHAR(max) = NULL          
 ,@platform NVARCHAR(max) = NULL          
AS          
BEGIN          
 SELECT adcam.ID           
  ,adcam.Campaign_Code          
  ,Campaign_Display_Name          
  ,adobj.Objective          
  ,ud.User_Login          
  ,Concat( ud.FName          
  ,' ', ud.LName ) ParentName          
  ,adcam.Campaign_Platform          
  ,adcam.STATUS          
  ,Convert(VARCHAR, adcam.Createdon, 106) Createdon      
  ,adset.ID adsetid  
  ,adset.Adset_Code  
  ,adcret.Id as adid  
  ,adcret.Ad_Id  
  ,trgt.IndustryID
 FROM tbl_AdCampaigns adcam          
 LEFT JOIN tbl_FbAdCmpgn_FbPages fbpag on fbpag.FbPageId=adcam.Page_ID          
 LEFT JOIN tbl_adCampaignObjective adobj ON adcam.Campaign_Objective = cast (adobj.id as varchar)           
 left JOIN User_Detail Ud ON ud.User_ID = adcam.parentid          
 left Join tbl_AdSets adset on adset.CampID=adcam.ID  
 left join tbl_AdtargetingAudience trgt on adset.Target_ID=trgt.id
 left join tbl_Adcreatives adcret on adcret.AdSetid=adset.ID  
 WHERE (          
   @parentid IS NULL          
   OR adcam.parentid = @parentid          
   )          
  AND (          
   @status IS NULL          
   OR adcam.STATUS = @status          
   )          
  AND (          
   @platform IS NULL          
   OR adcam.Campaign_Platform = @platform          
   )          
  AND (          
   @fromdate IS NULL          
   OR adcam.Createdon > @fromdate          
   )          
  AND (          
   @todate IS NULL          
   OR adcam.Createdon < @todate          
   )          
  And adcam.IsActive=1          
 ORDER BY adcam.Createdon DESC          
END



GO

