/* ============================================================
   Procedure: [dbo].[Usp_ad_getaudienceIndustry]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[Usp_ad_getaudienceIndustry] @industryid NVARCHAR(max) = NULL
	,@platform NVARCHAR(100) = NULL
	,@adsetid NVARCHAR(100) = NULL
	,@mode NVARCHAR(10)
AS
BEGIN
	DECLARE @sql NVARCHAR(max)

	IF (@mode = 'aud')
	BEGIN
		IF (@platform = 'facebook')
		BEGIN
			SET @sql = 'select ID , Industry_Name , Targetted_Audience as AudID from tbl_AdIndustries_withAudiences where ID IN (' + @industryid + ')'

			PRINT @sql

			EXECUTE sp_executesql @sql
		END
		ELSE IF (@platform = 'google')
		BEGIN
			SET @sql = 'select ID , Industry_Name , Google_Targetted_Audience as AudID from tbl_AdIndustries_withAudiences where ID IN (' + @industryid + ')'

			PRINT @sql

			EXECUTE sp_executesql @sql
		END
	END

	IF (@mode = 'target')
	BEGIN
		SELECT trgt.Country
			,trgt.Country_code
			,trgt.STATE
			,trgt.State_key
			,trgt.city
			,trgt.city_key
			,trgt.Min_Age
			,trgt.Max_Age
			,trgt.Gender
			,trgt.AgeRange
			,trgt.ParentalStatus
		FROM tbl_AdSets adset
		JOIN tbl_AdtargetingAudience trgt ON adset.Target_ID = trgt.ID
		WHERE adset.ID = @adsetid
	END
END



GO

/* ============================================================
   Procedure: [dbo].[Usp_Ad_GetCampaignList]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[Usp_Ad_GetCampaignList] @userid BIGINT        
 ,@platform NVARCHAR(25) = NULL        
 ,@Objective NVARCHAR(50) = NULL        
 ,@fromdate DATETIME = NULL        
 ,@todate DATETIME = NULL        
 ,@status NVARCHAR(50) = NULL        
AS        
BEGIN        
 IF (@platform = 'All')        
 BEGIN        
  SET @platform = NULL;        
 END        
        
 IF (@Objective = '0')        
 BEGIN        
  SET @objective = NULL;        
 END        
        
 IF (@status = 'All')        
 BEGIN        
  SET @status = NULL;        
 END        
 

 SELECT adcam.ID        
  ,Campaign_Code        
  ,Campaign_Display_Name        
  ,adobj.Objective        
  ,adcam.Userid        
  ,Campaign_Platform        
  ,adcam.[Status]        
  ,Convert(VARCHAR,dbo.fn_getusertimefromindiantime(@userid,adcam.Createdon), 106) Createdon        
  ,Convert(VARCHAR,dbo.fn_getusertimefromindiantime(@userid,adbug.StartDate) , 106) StartDate        
  ,CONVERT(VARCHAR, dbo.fn_getusertimefromindiantime(@userid,adbug.EndDate), 106) EndDate        
  ,adbug.Amount        
  ,adbug.budget_type        
 FROM tbl_AdCampaigns adcam        
 JOIN tbl_adCampaignObjective adobj ON adcam.campaign_objective = cast (adobj.id as varchar)    
 LEFT JOIN tbl_AdSets adset ON adset.Campid = adcam.id        
 LEFT JOIN tbl_AdBudget adbug ON adbug.id = adset.Budget_Id        
 WHERE adcam.userid = @userid        
  AND adcam.IsActive = 1        
  AND (        
   @platform IS NULL        
   OR lower(adcam.Campaign_Platform) = lower(@platform)        
   )        
  AND (        
   @Objective IS NULL        
   OR adobj.id = @Objective        
   )        
  AND (        
   @status IS NULL        
   OR lower(adcam.STATUS) = lower(@status)        
   )        
  AND (        
   @fromdate IS NULL        
   OR adcam.Createdon > @fromdate        
   )        
  AND (        
   @todate IS NULL        
   OR adcam.Createdon < @todate        
   )   
 ORDER BY adcam.Createdon desc 
    
 EXEC MySmsAudit_dev.dbo.Usp_AuditTableDataByParentId @User_id = @userid        
  ,@Activity_type = 'View_AdCmpgnList'        
  ,@ActionType = 'S'        
  ,@RowJson = ''        
  ,@Table_name = 'tbl_AdCampaigns'        
END



GO

/* ============================================================
   Procedure: [dbo].[Usp_Ad_GetCampaignListBycampID]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[Usp_Ad_GetCampaignListBycampID] @campid BIGINT                    
 ,@userid BIGINT                    
AS                    
BEGIN                    
 SELECT adcam.ID                    
  ,adcam.Campaign_Code                    
  ,adcam.Campaign_Display_Name                    
  ,adcam.Campaign_Objective                    
  ,adcam.Userid                    
  ,adcam.Campaign_Platform                    
  ,adcam.[Status]                    
  ,adcam.Createdon                    
  ,adcam.Page_ID                    
--  ,fbid.FbUserId   
  ,adset.id as adsetid  
  ,adset.AdSet_Name                    
  ,adset.Adset_Code      
  ,adset.Platform As placement      
  ,adtaud.Country                    
  ,adtaud.Country_code                    
  ,adtaud.STATE                    
  ,adtaud.State_key                    
  ,adtaud.city                    
  ,adtaud.city_key                    
  ,adtaud.Zip_Code                    
  ,adtaud.longitude                    
  ,adtaud.latitude                    
  ,adtaud.Radius                    
  ,adtaud.Min_Age                    
  ,adtaud.Max_Age                    
  ,adtaud.Gender                    
  ,adbug.Budget_type                    
  ,Convert(VARCHAR, dbo.fn_getusertimefromindiantime(@userid,adbug.StartDate) , 106) StartDate                    
  ,Convert(VARCHAR, dbo.fn_getusertimefromindiantime(@userid,adbug.EndDate) , 106) EndDate                    
  ,adbug.Amount                  
  ,adcret.id AS adcretID          
   ,adcret.Primary_text as textId    
  ,txtdt.primarytext1            
 ,txtdt.primarytext2            
 ,txtdt.primarytext3            
 ,txtdt.primarytext4            
 ,txtdt.primarytext5            
 ,txtdt.Description1            
 ,txtdt.Description2            
 ,txtdt.Description3            
 ,txtdt.Description4            
 ,txtdt.Description5            
 ,txtdt.Headline1            
 ,txtdt.Headline2            
 ,txtdt.Headline3            
 ,txtdt.Headline4            
 ,txtdt.Headline5            
  ,adcret.Call_to_action                    
  ,adcret.Website_URL                    
  ,adcret.Media_id                  
  ,adcret.MediaType                  
  ,adcret.Thumb_id
  ,adcret.LongHeadline
  ,adcret.BusinessName
  ,Case adcam.Campaign_Platform
  when mdam.Platform
  Then mdam.AssetID 
  END AssetID                  
  ,admed.Med_Filename                  
  ,admed.Med_Path                  
  ,admed.Med_type                
  ,adtaud.IndustryId

  ,adcret.MarketingImage
  ,Case adcam.Campaign_Platform
  when mdamlm.Platform
  Then mdamlm.AssetID 
  END LandscapeImage
  ,admedlm.Med_Filename lndImgMed_Filename                  
  ,admedlm.Med_Path lndimgMed_Path                  
  ,admedlm.Med_type lndimgMed_type
  
  ,adcret.SquareImage
  ,Case adcam.Campaign_Platform
  when mdamsm.Platform
  Then mdamsm.AssetID 
  END SquareImageAsset
  ,admedsm.Med_Filename sqrImgMed_Filename                  
  ,admedsm.Med_Path sqrimgMed_Path                  
  ,admedsm.Med_type sqrimgMed_type
  
  ,adcret.LandscapeLogo
  ,Case adcam.Campaign_Platform
  when mdamll.Platform
  Then mdamll.AssetID 
  END LandscapeLogoAsset
  ,admedll.Med_Filename lndlogoMed_Filename                  
  ,admedll.Med_Path lndlogoMed_Path                  
  ,admedll.Med_type lndlogoMed_type
  
  ,adcret.SquareLogo
  ,Case adcam.Campaign_Platform
  when mdamsl.Platform
  Then mdamsl.AssetID 
  END SquareLogoAsset
  ,admedsl.Med_Filename sqrlogoMed_Filename                  
  ,admedsl.Med_Path sqrlogoMed_Path                  
  ,admedsl.Med_type sqrlogoMed_type
  ,adcret.YoutubeVideoUrl

 FROM tbl_AdCampaigns adcam                    
  left JOIN tbl_fbadcmpgn_fbpages fbpages ON adcam.page_id = fbpages.FbPageId                    
 --JOIN tbl_fbadcmpgn_accesstoken fbid ON fbpages.FbUserId = fbid.FbUserId                    
 LEFT JOIN tbl_AdSets adset ON adset.CampID= adcam.ID  
 LEFT JOIN tbl_AdtargetingAudience adtaud ON adtaud.id = adset.Target_ID                    
 LEFT JOIN tbl_AdBudget adbug ON adbug.id = adset.Budget_Id                    
 LEFT JOIN tbl_Adcreatives adcret ON adcret.AdSetid= adset.ID  
 LEFT JOIN Tbl_ad_primarytextData txtdt on adcret.Primary_text=txtdt.ID            
 LEFT JOIN tbl_AD_Media_Asset_Map mdam ON mdam.Med_ID= adcret.Media_id            
 LEFT JOIN tbl_AD_AdMedia admed ON admed.ID=mdam.Med_ID      
  LEFT JOIN tbl_AD_Media_Asset_Map mdamlm ON mdamlm.Med_ID= adcret.MarketingImage
 LEFT JOIN tbl_AD_AdMedia admedlm ON admedlm.ID=mdamlm.Med_ID 
  LEFT JOIN tbl_AD_Media_Asset_Map mdamsm ON mdamsm.Med_ID= adcret.SquareImage
 LEFT JOIN tbl_AD_AdMedia admedsm ON admedsm.ID=mdamsm.Med_ID 
  LEFT JOIN tbl_AD_Media_Asset_Map mdamll ON mdamll.Med_ID= adcret.LandscapeLogo
 LEFT JOIN tbl_AD_AdMedia admedll ON admedll.ID=mdamll.Med_ID 
  LEFT JOIN tbl_AD_Media_Asset_Map mdamsl ON mdamsl.Med_ID= adcret.SquareLogo
 LEFT JOIN tbl_AD_AdMedia admedsl ON admedsl.ID=mdamsl.Med_ID 
 WHERE adcam.userid = @userid                    
  AND adcam.ID = @campid                    
END



GO

