CREATE   PROCEDURE Usp_Ad_getCarouselData  
@carouselid bigint   
as   
begin  
  
 Select adcar.Carousel_ID, adcar.Media_ID , adcar.Media_type, adcar.Thumbid,admed.ID,admed.Med_Filename,admed.Med_Path,admed.Med_type,adas.AssetID  
