CREATE   PROCEDURE [dbo].[Usp_Ad_GetPageAudienceData]   
@mode nvarchar(max)  ,
@pagename nvarchar(max)
As  
BEGIN  
 if @mode='pages'  
 BEGIN  
  declare @tt nvarchar(max)=(select string_agg(''''+pageid+'''',',') from  tbl_ad_userpagemapping  WITH (NOLOCK) where Isactive=1)  
  declare @sql nvarchar(max) ='select ID, FbPageId, FbPageName from [tbl_FbAdCmpgn_FbPages] WITH (NOLOCK) where  FbPageId not in ( '+@tt+') 
							AND FbPageName like ''%'+@pagename+'%'''  
  print @sql  
  exec sp_executesql @sql  
 END  
  
 if @mode='audience'  
 begin  
  Select Industry_Id, Audience_Name, Audid from tbl_adIndustryaudience  WITH (NOLOCK)  where Audience_Name like '%'+@pagename+'%'
