/* ============================================================
   Procedure: [dbo].[Usp_AD_GetTargetAudience]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[Usp_AD_GetTargetAudience] @TargetAudData NVARCHAR(MAX)
	,@userid BIGINT
AS
BEGIN
	Delete from tbl_AdIndustryAudience

	INSERT INTO tbl_AdIndustryAudience (
		AudID
		,Audience_Name
		,Isactive
		,STATUS
		,CreatedBy
		,CreatedOn
		,TargetAudJson
		)
	SELECT audid
		,name
		,CASE STATUS
			WHEN 'ACTIVE'
				THEN 1
			ELSE 0
			END Isactive
		,STATUS
		,@userid
		,GETDATE()
		,TargetAudJson
	FROM openjson(@TargetAudData) WITH (
			audid NVARCHAR(max) '$.audid'
			,name VARCHAR(max) '$.name'
			,STATUS VARCHAR(max) '$.status'
			,TargetAudJson VARCHAR(max) '$.TargetAudJson  '
			)

	SELECT 'Data Inserted'
END



GO

/* ============================================================
   Procedure: [dbo].[Usp_Ad_GetTargetingAudience]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[Usp_Ad_GetTargetingAudience]  
 @audId varchar(max)  
 AS   
 BEGIN  
 --declare  @audId varchar(max)='1'  
drop table if exists #temp   
  
Create table #temp (ROW_NO bigint, Industry_id bigint, Audience_Name nvarchar(max), TargetAudJson nvarchar(max))  
declare @tempdata nvarchar(2000)  
set @tempdata=' INSERT INTO #temp (ROW_NO, Industry_id, Audience_Name, TargetAudJson)  
    select ROW_NUMBER() OVER(ORDER BY Industry_id ASC) AS ROW_NO, audt.Industry_id, audt.Audience_Name, audt.TargetAudJson from tbl_AdIndustries_withAudiences  inda  
  join tbl_AdIndustryAudience audt on inda.Targetted_Audience=audt.AudID where inda.id  in ('+@audId+')'  
print @tempdata  
exec sp_executesql @tempdata  
  
Declare @min bigint, @max bigint  
  
drop table if exists #interests  
drop table if exists #behaviors  
drop table if exists #tbl_education_statuses  
drop table if exists #industries  
drop table if exists #work_employers  
drop table if exists #work_positions  
  
create table #interests (id bigint, name nvarchar(max))  
create table #behaviors (id bigint, name nvarchar(max))  
create table #tbl_education_statuses (education_statuses bigint)  
create table #industries (id bigint, name nvarchar(max))  
create table #work_employers (id bigint, name nvarchar(max))  
create table #work_positions (id bigint, name nvarchar(max))  
  
declare @audJson nvarchar(max), @interests nvarchar(max),@behaviors nvarchar(max),@education_statuses nvarchar(max),@industries nvarchar(max),@work_employers nvarchar(max),@work_positions nvarchar(max)  
  
Set @min= (Select MIN(ROW_NO) from #TEMP)  
Set @max= (Select MAX(ROW_NO) from #TEMP)  
  
WHILE(@min<=@max)  
BEGIN  
--loop start  
Set @audJson=(SELECT TargetAudJson FROM #TEMP Where ROW_NO=@min)  
  
select @interests=interests, @behaviors=behaviors, @education_statuses=education_statuses, @industries=industries, @work_employers=work_employers, @work_positions=work_positions  
--JSON_VALUE(interests,'$[0].id') AS Id,JSON_VALUE(interests,'$[0].name') AS name,*   
from openjson(@audJson)  
with  
(  
 interests   nvarchar(max) as json,  
 behaviors   nvarchar(max) as json,  
 education_statuses nvarchar(max) as json,  
 industries   nvarchar(max) as json,  
 work_employers  nvarchar(max) as json,  
 work_positions  nvarchar(max) as json  
)  
  
insert into #interests  
select id, name  
from openjson(@interests)  
with  
(  
 id bigint   '$.id',  
 name nvarchar(max) '$.name'  
)  
  
insert into #behaviors  
select id, name  
from openjson(@behaviors)  
with  
(  
 id bigint   '$.id',  
 name nvarchar(max) '$.name'  
)  
  
insert into #tbl_education_statuses  
select value as education_statuses  
from openjson(@education_statuses)  
  
insert into #industries  
select id, name  
from openjson(@industries)  
with  
(  
 id bigint   '$.id',  
 name nvarchar(max) '$.name'  
)  
  
insert into #work_employers  
select id, name  
from openjson(@work_employers)  
with  
(  
 id bigint   '$.id',  
 name nvarchar(max) '$.name'  
)  
  
insert into #work_positions  
select id, name  
from openjson(@work_positions)  
with  
(  
 id bigint   '$.id',  
 name nvarchar(max) '$.name'  
)  
  
SET @min = @min+1  
END  
  
-- loop end  
  
declare @testjson nvarchar(max)  
set @testjson=(select distinct id,name from #interests for json auto)  
print @testjson  
  
set @interests=(select distinct id,name from #interests for json auto)  
set @behaviors=(select distinct id,name from #behaviors for json auto)  
set @industries=(select distinct id,name from #industries for json auto)  
set @work_employers=(select distinct id,name from #work_employers for json auto)  
set @education_statuses =(select distinct   STRING_AGG(education_statuses,',')   from #tbl_education_statuses)  
set @work_positions = (select  distinct id,name from #work_positions for json auto)  
  
Select @interests interests, @behaviors behaviors, @industries industries, @work_employers work_employers, @education_statuses education_statuses,  
  @work_positions work_positions   
  
--select distinct id,name from #behaviors  
--select distinct education_statuses from #tbl_education_statuses  
--select distinct id,name from #industries  
--select distinct id,name from #work_employers  
--select distinct id,name from #work_positions  
END



GO

/* ============================================================
   Procedure: [dbo].[Usp_ad_getuserpagemapped]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[Usp_ad_getuserpagemapped]    
@mode nvarchar(10)  
AS      
BEGIN      
 IF @mode='page'  
 BEGIN  
  select UPM.id, upm.PageName, UPM.parentid, UPM.pageid, UD.User_login, UD.Fname ,UD.LName  from  tbl_ad_userpagemapping UPM      
  Join User_Detail UD on Upm.ParentId = UD.ParentID      
  Join [tbl_FbAdCmpgn_FbPages] fbpg on UPM.Pageid=fbpg.FbPageId      
  AND UD.User_id=Ud.Parentid      
  and UPM.Isactive=1    
  ORDER BY UPM.Createdon  desc      
 END  
 ELSE IF @mode='indus'  
 BEGIN  
  select indus.ID,indus.Industry_Name,aud.[platform], indus.Industry_ParentId, indus.Targetted_Audience,indus.Google_Targetted_Audience, aud.Audience_Name from tbl_AdIndustries_withAudiences indus  
  join tbl_adIndustryaudience aud ON indus.targetted_audience=aud.Audid  or indus.Google_Targetted_Audience=aud.Audid 
  WHERE aud.isactive=1  
 END  
END



GO

