/* ============================================================
   Procedure: [dbo].[Usp_ad_InsertAdCarousel]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  
  
CREATE   PROCEDURE Usp_ad_InsertAdCarousel   
@carouselJson Nvarchar(MAX)='',  
@carId bigint=0  
As  
BEGIN  
  Drop Table if exists #temp  
  Create table #temp (  
  media_id bigint,  
  medtype nvarchar(max),  
  thumbid nvarchar(max)  
  )  
 if @carId=0  
 Begin  
  Declare @CarouselId BIGINT= (SELECT ISNULL(MAX(Carousel_ID),0)+1 FROM tbl_ad_Carousel)  
    
  Insert Into #temp  
  Select media_id, medtype, thumbid   
  from OPENJSON(@carouselJson)   
  with (  
    media_id bigint '$.media_id',  
    medtype nvarchar(max) '$.medtype',  
    thumbid nvarchar(max) '$.thumbid'  
  )  
  
  INSERT INTO tbl_ad_Carousel (Carousel_ID, Media_ID , Media_type, Thumbid)   
  SELECT @CarouselId, media_id, medtype, thumbid   
  From #temp  
  
  Select @CarouselId  
 END  
  
 Else If @carId>0  
 BEGIN  
  Delete From tbl_ad_Carousel where Carousel_ID=@carId   
  
  Insert Into #temp  
  Select media_id, medtype, thumbid   
  from OPENJSON(@carouselJson)   
  with (  
    media_id bigint '$.media_id',  
    medtype nvarchar(max) '$.medtype',  
    thumbid nvarchar(max) '$.thumbid'  
  )  
  
  INSERT INTO tbl_ad_Carousel (Carousel_ID, Media_ID , Media_type, Thumbid)   
  SELECT @carId, media_id, medtype, thumbid   
  From #temp  
  
  Select @carId  
 END  
  
END


GO

