   Procedure: [dbo].[Usp_Ad_InsertAdsets_Budgets_Targeting]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE Usp_Ad_InsertAdsets_Budgets_Targeting (        
 @ID BIGINT = NULL        
 ,@Country_code VARCHAR(10) = NULL        
 ,@State NVARCHAR(255) = NULL        
 ,@State_key NVARCHAR(20) = NULL        
 ,@city NVARCHAR(255) = NULL        
 ,@city_key NVARCHAR(20) = NULL        
 ,@Zip_Code BIGINT = NULL        
 ,@Country NVARCHAR(255) = NULL        
 ,@Address NVARCHAR(255) = NULL        
 ,@longitude NVARCHAR(255) = NULL        
 ,@latitude NVARCHAR(255) = NULL        
 ,@Radius INT = NULL        
 ,@Min_Age INT = NULL        
 ,@Max_Age INT = NULL        
 ,@Gender BIT = NULL        
 ,@Budget_Name NVARCHAR(MAX) = NULL        
 ,@budget_type VARCHAR(50) = NULL        
 ,@StartDate DATETIME = NULL        
 ,@EndDate DATETIME = NULL        
 ,@Amount BIGINT = NULL        
 ,@Adset_Code NVARCHAR(max) = NULL        
 ,@AdSet_Name NVARCHAR(MAX) = NULL        
 ,@Campaign_ID NVARCHAR(MAX) = NULL        
 ,@Userid BIGINT = NULL        
 ,@IsActive BIT = NULL        
 ,@CreatedBy BIGINT = NULL        
 ,@CmpStartDate DATETIME = NULL        
 ,@CmpEndDate DATETIME = NULL        
 ,@STATUS VARCHAR(20) = NULL        
 ,@IsPublished BIT = NULL        
 ,@IsDeleted BIT = NULL        
 ,@Mobile_no BIGINT = NULL        
 ,@Platform NVARCHAR(20) = NULL        
 ,@billing_event NVARCHAR(50) = NULL        
 ,@bid_amount NVARCHAR(10) = NULL        
 ,@industryid NVARCHAR(max)   =null    
 ,@AgeRange bigint = null  
 ,@ParentalStatus bigint= null  
 ,@campid bigint= null  
 ,@customaudience NVARCHAR(max)   =null   
 )        
AS        
BEGIN        
 DECLARE @parentid BIGINT = (        
   SELECT ParentID        
   FROM user_detail(NOLOCK)        
   WHERE USER_ID = @Userid        
   )        
 DECLARE @Budget_id BIGINT        
      
 Set @StartDate =[dbo].[fn_getISTtimefromusertime](@Userid,@StartDate)        
      
 Set @CmpEndDate =[dbo].[fn_getISTtimefromusertime](@Userid,@CmpEndDate)        
       
 INSERT INTO tbl_AdtargetingAudience (        
  Country        
  ,Country_code        
  ,[State]        
  ,State_key        
  ,city        
  ,city_key        
  ,Zip_Code        
  ,[Address]        
  ,longitude        
  ,latitude        
  ,Radius        
  ,Min_Age        
  ,Max_Age        
  ,Gender        
  ,IndustryId 
  ,customaudience
  ,AgeRange  
  ,ParentalStatus  
  
  )        
 VALUES (        
  @Country        
  ,@Country_code        
  ,@State        
  ,@State_key        
  ,@city        
  ,@city_key        
  ,@Zip_Code        
  ,@Address        
  ,@longitude        
  ,@latitude        
  ,@Radius        
  ,@Min_Age        
  ,@Max_Age        
  ,@Gender        
  ,@industryid 
  ,@customaudience
  ,@AgeRange  
  ,@ParentalStatus  
  )        
        
 DECLARE @targetid BIGINT = SCOPE_IDENTITY();        
        
 INSERT INTO tbl_AdBudget (        
  Budget_Name        
  ,budget_type        
  ,StartDate        
  ,EndDate        
  ,Amount        
  )        
 VALUES (        
  @Budget_Name        
  ,@budget_type        
  ,@StartDate        
  ,@EndDate        
  ,@Amount        
  )        
        
 SET @Budget_id = SCOPE_IDENTITY();        
        
 INSERT INTO tbl_AdSets (        
  Adset_Code        
  ,AdSet_Name        
  ,Campaign_ID        
  ,Userid        
  ,Parentid        
  ,Target_ID        
  ,IsActive        
  ,CreatedDate        
  ,CreatedBy        
  ,CmpStartDate        
  ,CmpEndDate        
  ,[STATUS]        
  ,IsPublished        
  ,IsDeleted        
  ,Mobile_no        
  ,Budget_Id        
  ,[PLATFORM]        
  ,billingevent        
  ,bidamount     
  ,CampID  
  )        
 VALUES (        
  @Adset_Code        
  ,@AdSet_Name        
  ,@Campaign_ID        
  ,@Userid        
  ,@parentid        
  ,@targetid        
  ,@IsActive        
  ,GETDATE()        
  ,@Userid        
  ,@CmpStartDate        
  ,@CmpEndDate        
  ,@STATUS        
  ,@IsPublished        
  ,@IsDeleted        
  ,@Mobile_no        
  ,@Budget_id        
  ,@Platform        
  ,@billing_event        
  ,@bid_amount     
  ,@campid  
  )        
        
  set @ID=SCOPE_IDENTITY();        
        
 SELECT @id, 'Adset Saved'        
 DECLARE @rowJson NVARCHAR(MAX) = (        
    SELECT *        
   FROM tbl_AdSets WITH (NOLOCK)        
    WHERE ID = @ID        
    FOR JSON AUTO        
     ,INCLUDE_NULL_VALUES        
    )        
 IF @rowJson IS NOT NULL        
BEGIN        
 EXEC MySmsAudit_dev.dbo.Usp_AuditTableDataByParentId @User_id = @Userid        
  ,@Activity_type = 'Inst_AdSets'        
  ,@ActionType = 'I'        
  ,@RowJson = @rowJson        
  ,@Table_name = 'tbl_AdSets'        
END        
END



