/* ============================================================
   Procedure: [dbo].[Usp_Ad_InsertUpdate_AdCampaigns]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[Usp_Ad_InsertUpdate_AdCampaigns] (
	@ID BIGINT = 0
	,@Campaign_Display_Name NVARCHAR(MAX) = NULL
	,@Campaign_Actual_Name NVARCHAR(MAX) = NULL
	,@Campaign_Objective NVARCHAR(MAX) = NULL
	,@Userid BIGINT = 0
	,@IsActive BIT = 1
	,@IPAddress NVARCHAR(50) = NULL
	,@Page_ID NVARCHAR(MAX) = NULL
	,@Campaign_Platform NVARCHAR(20) = NULL
	,@Status VARCHAR(20) = NULL
	,@Option NVARCHAR(10) = ''
	,@campaignCode NVARCHAR(max) = ''
	)
AS
BEGIN
	DECLARE @parentid BIGINT = (
			SELECT ParentID
			FROM user_detail(NOLOCK)
			WHERE USER_ID = @Userid
			)
	DECLARE @activity VARCHAR(MAX) = ''
		,@action VARCHAR(1) = ''
		,@rowJson NVARCHAR(MAX) = ''

	IF @Option = 'Insert'
	BEGIN
		IF NOT EXISTS (
				SELECT 1
				FROM tbl_AdCampaigns
				WHERE Campaign_Display_Name = @Campaign_Display_Name
					AND Campaign_Platform = @Campaign_Platform
					AND userid = @Userid
				)
		BEGIN
			IF (@ID = 0)
			BEGIN
				INSERT INTO tbl_AdCampaigns (
					Campaign_Code
					,Campaign_Display_Name
					,Campaign_Actual_Name
					,Campaign_Objective
					,Userid
					,parentid
					,Createdon
					,IPAddress
					,IsActive
					,Page_ID
					,Campaign_Platform
					,[Status]
					)
				VALUES (
					@campaignCode
					,@Campaign_Display_Name
					,@Campaign_Actual_Name
					,@Campaign_Objective
					,@Userid
					,@parentid
					,GETDATE()
					,@IPAddress
					,@IsActive
					,@Page_ID
					,@Campaign_Platform
					,@Status
					)

				SET @id = SCOPE_IDENTITY();

				SELECT @id
					,'Record Saved'

				SET @rowJson = (
						SELECT *
						FROM tbl_AdCampaigns WITH (NOLOCK)
						WHERE id = @id
						FOR JSON AUTO
							,INCLUDE_NULL_VALUES
						)
				SET @activity = 'Inst_AdCampgn'
				SET @action = 'I'
			END
		END
		ELSE
		BEGIN
			SELECT 'Ads Name Exits'
		END
	END
	ELSE IF @Option='Update'
	BEGIN
		UPDATE tbl_AdCampaigns
				SET Campaign_Display_Name = @Campaign_Display_Name
					,Campaign_Actual_Name = @Campaign_Actual_Name
					,Campaign_Objective = @Campaign_Objective
					,Page_ID = @Page_ID
					,ModifiedDate = GETDATE()
					,ModifiedBy = @Userid
				WHERE Campaign_Code = @ID

				SELECT 'Record Updated'

				SET @rowJson = (
						SELECT *
						FROM tbl_AdCampaigns WITH (NOLOCK)
						WHERE Campaign_Code = @id
						FOR JSON AUTO
							,INCLUDE_NULL_VALUES
						)
				SET @activity = 'Updt_AdCampgn'
				SET @action = 'U'
	END
	ELSE IF @Option = 'updtCmpnCode'
	BEGIN
		--Update tbl_AdCampaigns set Campaign_Code=@campaignCode where id=@ID            
		SELECT 'Campaign Code Updated'
	END
	ELSE IF @Option = 'Delete'
	BEGIN
		--SELECT 'Campaign Code Updated'        
		IF (@ID != '')
		BEGIN
			SET @rowJson = (
					SELECT *
					FROM tbl_AdCampaigns WITH (NOLOCK)
					WHERE id = @id
					FOR JSON AUTO
						,INCLUDE_NULL_VALUES
					)

			UPDATE tbl_AdCampaigns
			SET IsActive = 0
			WHERE ID = @ID

			SELECT 'Campaign Delete'

			SET @activity = 'Delt_AdCampgn'
			SET @action = 'D'
		END
	END

	IF @rowJson IS NOT NULL
	BEGIN
		EXEC MySmsAudit_dev.dbo.Usp_AuditTableDataByParentId @User_id = @Userid
			,@Activity_type = @activity
			,@ActionType = @action
			,@RowJson = @rowJson
			,@Table_name = 'tbl_AdCampaigns'
	END
END



GO

/* ============================================================
   Procedure: [dbo].[Usp_Ad_InstCustomAudienceFileDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE Usp_Ad_InstCustomAudienceFileDetails (        
 @User_id BIGINT = NULL,      
 @File_Name nvarchar(max)=null,      
 @File_Path nvarchar(max)=null,      
 @mode varchar(50),      
 @id bigint = null      
  ,@CustomAudience_id BIGINT = NULL        
 ,@CustomAudience_Name NVARCHAR(max) = NULL        
 ,@Session_id BIGINT = NULL       
  
 )        
AS        
BEGIN        
 DECLARE @parentid BIGINT = (        
   SELECT parentid        
   FROM mysms_dev.dbo.User_Detail(NOLOCK)        
   WHERE User_ID = @User_id        
   )        
        
 IF @mode = 'insert'        
 BEGIN        
  INSERT INTO tbl_Ad_CustomAudience (        
   user_id        
   ,parent_id        
   ,file_name        
   ,file_path        
   ,created_date        
   ,Isactive        
   )        
  VALUES (        
   @User_id        
   ,@parentid        
   ,@File_Name        
   ,@File_Path,      
   GetDate()      
   ,0    
   )        
        
  Select SCOPE_IDENTITY();            
 END       
 Else IF @mode = 'update'        
 BEGIN        
  UPDATE tbl_Ad_CustomAudience        
  SET customaudience_id=@CustomAudience_id,      
  customaudience_name=@CustomAudience_Name,      
  session_id=@Session_id,      
  customaudience_actualname=Concat(@CustomAudience_Name,'_',@parentid) ,    
  isactive=1    
  WHERE id = @id        
        
  Select 'Updated'        
 END     
   
        
       
END



GO

