   Procedure: [dbo].[Usp_Ad_InstDltCustomAudience]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON



  
CREATE   PROCEDURE Usp_Ad_InstDltCustomAudience (        
 @id BIGINT = NULL        
 ,@CustomAudience_id BIGINT = NULL        
 ,@CustomAudience_Name NVARCHAR(max) = NULL        
 ,@User_id BIGINT = NULL        
 ,@Session_id BIGINT = NULL        
 ,@mode VARCHAR(20)        
 )        
AS        
BEGIN        
 DECLARE @parentid BIGINT = (        
   SELECT parentid        
   FROM mysms.dbo.User_Detail(NOLOCK)        
   WHERE User_ID = @User_id        
   )        
        
 IF @mode = 'insert'        
 BEGIN        
  INSERT INTO tbl_Ad_CustomAudience (        
   CustomAudience_id        
   ,CustomAudience_Name        
   ,User_id        
   ,Parent_id        
   ,Session_id        
   ,Isactive        
   )        
  VALUES (        
   @CustomAudience_id        
   ,@CustomAudience_Name        
   ,@User_id        
   ,@parentid        
   ,@Session_id        
   ,1        
   )        
        
  Select 'Data Inserted'         
 END        
        
 Else IF @mode = 'delete'        
 BEGIN        
  UPDATE tbl_Ad_CustomAudience        
  SET Isactive = 0        
  WHERE id = @id        
        
  Select 'Deleted'        
 END       
        
 ELSE IF @mode='select'        
 BEGIN        
  SELECT id,        
  CustomAudience_id        
   ,CustomAudience_Name        
   ,User_id        
   ,Parent_id        
   ,Session_id        
   ,file_name        
   ,file_path       
   ,customaudience_actualname      
   ,created_date       
   ,Isactive        
  FROM tbl_Ad_CustomAudience        
  WHERE User_id =@User_id and isactive=1    
 END        
END  


GO

/* ============================================================
   Procedure: [dbo].[USP_AD_InstUpdtFbLeadForm]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


    
CREATE   PROCEDURE USP_AD_InstUpdtFbLeadForm    
 @fbformdata nvarchar(max),    
 @userid bigint,    
 @fbpageid nvarchar(max)    
AS    
BEGIN    
    
 DROP TABLE IF EXISTS #temp    
    
    
 SELECT    
  FbformId    
  ,FbformName    
  ,status    
  ,userid =@userid     
  ,fbpageid=@fbpageid    
 INTO #temp    
 FROM OPENJSON(@fbformdata) WITH (    
   FbformId VARCHAR(max) '$.FbFormId'    
   ,FbformName VARCHAR(max) '$.FbFormName'    
   ,status varchar(max) '$.status'    
   )    
    
 IF (    
   EXISTS (    
    SELECT 1    
    FROM tbl_Ad_FbPagesLeadForm    
    WHERE FbPageId = @fbpageid    
    )    
   )    
 BEGIN    
  DELETE    
  FROM tbl_Ad_FbPagesLeadForm    
  WHERE FbPageId = @fbpageid    
    
 END    
    
 INSERT INTO tbl_Ad_FbPagesLeadForm (    
  FormId    
  ,FormName    
  ,Status    
  ,userid    
  ,FbPageId    
  )    
 SELECT t.FbformId    
  ,t.FbformName    
  ,t.status    
  ,t.userid    
  ,t.fbpageid    
 FROM #temp t    
END 


GO

/* ============================================================
   Procedure: [dbo].[Usp_AD_MediaData]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[Usp_AD_MediaData] @mediaid BIGINT = NULL  
 ,@assetid VARCHAR(1000) = NULL  
 ,@Med_Filename NVARCHAR(max) = NULL  
 ,@Med_Path NVARCHAR(max) = NULL  
 ,@Med_type VARCHAR(10) = NULL  
 ,@Med_ext VARCHAR(10) = NULL  
 ,@Med_size NVARCHAR(max) = NULL  
 ,@Med_thumb_Id NVARCHAR(max) = NULL  
 ,@userid BIGINT = NULL  
 ,@platform VARCHAR(20) = NULL  
 ,@imgheight BIGINT= 0
 ,@imgwidth bigint = 0
 ,@mode INT = 0  
AS  
BEGIN  
 DECLARE @parentid BIGINT = (  
   SELECT parentid  
   FROM User_Detail  
   WHERE user_id = @userid  
   )  
   DECLARE @activity VARCHAR(MAX) = ''  
  ,@action VARCHAR(1) = ''  
  ,@rowJson NVARCHAR(MAX) = ''  
  
 IF @mode = 1  
 BEGIN  
  INSERT INTO tbl_AD_AdMedia (  
   Med_Filename  
   ,Med_Path  
   ,Med_type  
   ,Med_ext  
   ,Med_size  
   ,Med_thumb_Id  
   ,UserID  
   ,ParentId  
   ,Isactive  
   ,imgheigt
	,imgwidth

   )  
  VALUES (  
   @Med_Filename  
   ,@Med_Path  
   ,@Med_type  
   ,@Med_ext  
   ,@Med_size  
   ,@Med_thumb_Id  
   ,@userid  
   ,@parentid  
   ,1  
   ,@imgheight
	,@imgwidth
   )  
  
  SET @mediaid = SCOPE_IDENTITY();  
  
  SELECT @mediaid;  
  SET @rowJson = (  
      SELECT *  
      FROM tbl_AD_AdMedia WITH (NOLOCK)  
      WHERE id = @mediaid  
      FOR JSON AUTO  
       ,INCLUDE_NULL_VALUES  
      )  
    SET @activity = 'Inst_AdMedia'  
    SET @action = 'I'  
 END  
 ELSE IF @mode = 2  
 BEGIN  
  UPDATE tbl_AD_AdMedia  
  SET Med_thumb_Id = @Med_thumb_Id  
  WHERE id = @mediaid  
  
  SELECT 'Thumbnail added'  
  SET @rowJson = (  
      SELECT *  
      FROM tbl_AD_AdMedia WITH (NOLOCK)  
      WHERE id = @mediaid  
      FOR JSON AUTO  
       ,INCLUDE_NULL_VALUES  
      )  
    SET @activity = 'Updt_AdMedia'  
    SET @action = 'U'  
 END  
 ELSE IF @mode = 3  
 BEGIN  
  INSERT INTO tbl_AD_Media_Asset_Map (  
   AssetID  
   ,Med_ID  
   ,Platform  
   )  
  VALUES (  
   @assetid  
   ,@mediaid  
   ,@platform  
   )  
  
  SELECT 'Media mapped to ' + @platform + ''  
 END  
 IF @rowJson IS NOT NULL  
 BEGIN  
  EXEC MySmsAudit_dev.dbo.Usp_AuditTableDataByParentId @User_id = @userid  
   ,@Activity_type = @activity  
   ,@ActionType = @action  
   ,@RowJson = @rowJson  
   ,@Table_name = 'tbl_AD_AdMedia'  
 END  
END



