/* ============================================================
   Procedure: [dbo].[Usp_Ad_MediaLibrary]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[Usp_Ad_MediaLibrary]          
@userid BIGINT  ,        
@medtype varchar(20)=''        
AS          
BEGIN          
 DECLARE @sqlquery NVARCHAR(MAX)         
 IF @medtype='carousel'        
  SET @medtype=''        
 ELSE         
  SET @medtype='AND Med_type='''+@medtype+''''        
          
 SET @sqlquery='select ID, [facebook], [google], Med_Filename, Med_Path,Med_type, Med_ext, Med_size, Med_thumb_Id, UserID, ParentId, Isactive,imgheigt,imgwidth from (  
 select admd.ID, Med_Filename,  Med_Path, Med_type, Med_ext, Med_size, Med_thumb_Id, UserID, ParentId, Isactive, amam.AssetID, amam.Platform, admd.imgheigt,
		admd.imgwidth
 FROM tbl_AD_AdMedia admd         
 left JOIN tbl_AD_Media_Asset_Map amam  ON admd.ID=amam.Med_ID    
  WHERE admd.UserID='+CAST(@userid AS VARCHAR)+'      
 AND Isactive=1 '+@medtype+'  
) as p PIVOT    
(    
  MAX(p.AssetID)  
  FOR Platform IN ([facebook], [google])    
) AS PivotTable';    
                
 print @sqlquery        
 EXEC sp_executesql @sqlquery        
        
END



GO

/* ============================================================
   Procedure: [dbo].[Usp_Ad_PayementDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE Usp_Ad_PayementDetails @userid BIGINT  
 ,@mode NVARCHAR(10) = ''  
 ,@CampaignId NVARCHAR(100) = NULL  
 ,@Platform NVARCHAR(25) = NULL  
 ,@budget DECIMAL(18, 2) = NULL  
 ,@Convenience_fee DECIMAL(18, 2) = NULL  
 ,@Total_Amount DECIMAL(18, 2) = NULL  
 ,@tax DECIMAL(18, 2) = NULL  
AS  
BEGIN  
 DECLARE @MId BIGINT  
  
 SELECT @MId = M_ID  
 FROM User_Detail WITH (NOLOCK)  
 WHERE User_ID = @userid  
  
 IF @mode = 'fee'  
 BEGIN  
  IF EXISTS (  
    SELECT 1  
    FROM tbl_Ad_ConvinienceChargesRate WITH (NOLOCK)  
    WHERE userId = @userid  
    )  
  BEGIN  
   SELECT UserID  
    ,Charges_percent  
    ,Charges_amount  
    ,pud.User_Login  
   FROM tbl_Ad_ConvinienceChargesRate ccr WITH (NOLOCK)  
   JOIN User_Detail pud WITH (NOLOCK) ON pud.User_ID = ccr.ParentID  
   WHERE UserID = @userid  
  END  
  ELSE  
  BEGIN  
   SELECT UserID  
    ,Charges_percent  
    ,Charges_amount  
    ,(  
     SELECT User_Login  
     FROM User_detail WITH (NOLOCK)  
     WHERE User_id = @userid  
     ) AS User_Login  
   FROM tbl_Ad_ConvinienceChargesRate ccr WITH (NOLOCK)  
   WHERE UserID IS NULL  
  END  
  
  SELECT TOP 1 balance  
   ,*  
  FROM IntCredit_Details c WITH (NOLOCK)  
  WHERE user_ID = @userid  
  ORDER BY Credit_ID DESC  
 END  
 ELSE IF @mode = 'debit'  
 BEGIN  
  INSERT INTO tbl_Ad_PaymentDetails (  
   UserID  
   ,CampaignId  
   ,Platform  
   ,Amount  
   ,Convenience_fee  
   ,Total_Amount  
   ,TaxValue  
   )  
  VALUES (  
   @userid  
   ,@CampaignId  
   ,@Platform  
   ,@budget  
   ,@Convenience_fee  
   ,@Total_Amount  
   ,@tax  
   )  
  
  DECLARE @ID BIGINT=SCOPE_IDENTITY();  
  DECLARE @rowJson NVARCHAR(MAX) = (  
     SELECT *  
     FROM tbl_Ad_PaymentDetails WITH (NOLOCK)  
     WHERE ID = @ID  
     FOR JSON AUTO  
      ,INCLUDE_NULL_VALUES  
     )  
  declare @remark nvarchar(1000) = 'Amount deducted for Ad Campaign '
  EXEC proc_UpdateIntCreditDetail_new @M_ID = @MId  
   ,@User_ID = @userid  
   ,@Price = @Total_Amount  
   ,@BATCHID = 0  
   ,@remark = @remark
   ,@typecredit = 16  
  
  SELECT 'Payment Done'  
 END  
 IF @rowJson IS NOT NULL  
 BEGIN  
  EXEC MySmsAudit_dev.dbo.Usp_AuditTableDataByParentId @User_id = @userid  
   ,@Activity_type = 'Inst_AdPymntdetls'  
   ,@ActionType = 'I'  
   ,@RowJson = @rowJson  
   ,@Table_name = 'tbl_Ad_PaymentDetails'  
 END  
END  


GO

