   Procedure: [dbo].[Usp_AD_SaveAdDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[Usp_AD_SaveAdDetails] @id BIGINT = 0        
 ,@userid BIGINT        
 ,@adname NVARCHAR(MAX) = NULL        
 ,@description NVARCHAR(MAX) = NULL        
 ,@Primary_text NVARCHAR(MAX) = NULL        
 ,@HeadLine NVARCHAR(MAX) = NULL        
 ,@Ad_StartDate DATETIME = NULL        
 ,@Ad_EndDate DATETIME = NULL        
 ,@status NVARCHAR(50) = NULL        
 ,@Call_to_action NVARCHAR(100) = NULL        
 ,@Website_URL NVARCHAR(max) = NULL        
 ,@Media_id NVARCHAR(100) = NULL        
 ,@adcreative_Id NVARCHAR(100) = NULL        
 ,@Platform NVARCHAR(25) = NULL        
 ,@adsetId NVARCHAR(100) = NULL        
 ,@adid NVARCHAR(100) = NULL        
 ,@thumbid NVARCHAR(100) = NULL        
 ,@mediatype VARCHAR(20) = NULL        
 ,@contactno VARCHAR(20) = NULL        
 ,@formid VARCHAR(30) = NULL       
 ,@textid bigint = null      
 ,@adgrpid bigint = null    
 ,@mode VARCHAR(10) = ''   
 ,@businessname nvarchar(max) = null  
 ,@longheadline nvarchar(max) = null  
 ,@YoutubeVideoUrl nvarchar(max) = null
 ,@MarketingImage  Bigint= null
 ,@SquareImage	   Bigint= null
 ,@LandscapeLogo   Bigint=null
 ,@SquareLogo  	   Bigint=null

AS        
BEGIN        
 DECLARE @activity VARCHAR(MAX) = ''        
  ,@action VARCHAR(1) = ''        
  ,@rowJson NVARCHAR(MAX) = ''        
 DECLARE @campaignid VARCHAR(100)        
  ,@adsetcode VARCHAR(100)        
  ,@adcreativeid VARCHAR(100)        
        
 IF @mode = 'insert'        
 BEGIN        
  IF @id = 0        
  BEGIN        
   INSERT INTO Tbl_ad_primarytextData (        
    primarytext1        
    ,primarytext2        
    ,primarytext3        
    ,primarytext4        
    ,primarytext5        
    ,Description1        
    ,Description2        
    ,Description3        
    ,Description4        
    ,Description5        
    ,Headline1        
    ,Headline2        
    ,Headline3        
    ,Headline4        
    ,Headline5        
    )        
   SELECT primarytext1        
    ,primarytext2        
    ,primarytext3        
    ,primarytext4        
    ,primarytext5        
    ,descriptiontext1        
    ,descriptiontext2        
    ,descriptiontext3        
    ,descriptiontext4        
    ,descriptiontext5        
    ,headline1        
    ,headline2        
    ,headline3        
    ,headline4        
    ,headline5        
   FROM openjson(@Primary_text) WITH (        
     primarytext1 VARCHAR(max) '$.primarytext1'        
     ,primarytext2 VARCHAR(max) '$.primarytext2'        
     ,primarytext3 VARCHAR(max) '$.primarytext3'        
     ,primarytext4 VARCHAR(max) '$.primarytext4'        
     ,primarytext5 VARCHAR(max) '$.primarytext5'        
     ,descriptiontext1 VARCHAR(max) '$.descriptiontext1'        
     ,descriptiontext2 VARCHAR(max) '$.descriptiontext2'        
     ,descriptiontext3 VARCHAR(max) '$.descriptiontext3'        
     ,descriptiontext4 VARCHAR(max) '$.descriptiontext4'        
     ,descriptiontext5 VARCHAR(max) '$.descriptiontext5'        
     ,headline1 VARCHAR(max) '$.headline1'        
     ,headline2 VARCHAR(max) '$.headline2'        
     ,headline3 VARCHAR(max) '$.headline3'        
     ,headline4 VARCHAR(max) '$.headline4'        
     ,headline5 VARCHAR(max) '$.headline5'        
     )        
        
    set @textid  = Scope_identity()        
        
   INSERT INTO tbl_Adcreatives (        
    Ad_Name        
    ,Description        
    ,Primary_text        
    ,HeadLine        
    ,IsActive        
    ,CreatedDate        
    ,Ad_StartDate        
    ,Ad_EndDate        
    ,STATUS        
    ,Call_to_action        
    ,Website_URL        
    ,Media_id        
    ,IsPublished        
    ,Platform        
    ,adcreative_Id        
    ,Adset_Id        
    ,MediaType        
    ,Thumb_id        
    ,ContactNo        
    ,Formid        
 ,AdSetid    
 ,BusinessName  
 ,LongHeadline  
 ,YoutubeVideoUrl
 ,MarketingImage
,SquareImage
,LandscapeLogo
,SquareLogo

    )        
   VALUES (        
    @adname        
    ,@description        
    ,@textid      
    ,@HeadLine        
    ,1        
    ,getdate()        
    ,@Ad_StartDate        
    ,@Ad_EndDate        
    ,@status        
    ,@Call_to_action        
    ,@Website_URL        
    ,@Media_id        
    ,0        
    ,@Platform        
    ,@adcreative_Id        
    ,@adsetId        
    ,@mediatype        
    ,@thumbid        
    ,@contactno        
    ,@formid        
 ,@adgrpid    
 ,@businessname  
 ,@longheadline  
 ,@YoutubeVideoUrl 
 ,@MarketingImage  
 ,@SquareImage	   
 ,@LandscapeLogo   
 ,@SquareLogo  	   
    )        
        
   SET @id = SCOPE_IDENTITY()        
        
   SELECT @id        
        
   SET @rowJson = (        
     SELECT *        
     FROM tbl_Adcreatives WITH (NOLOCK)        
     WHERE id = @id        
     FOR JSON AUTO        
      ,INCLUDE_NULL_VALUES        
     )        
   SET @activity = 'Inst_AdCreative'        
   SET @action = 'I'        
  END        
  ELSE IF @id <> 0        
  BEGIN        
  Delete from Tbl_ad_primarytextData WHERE ID=@textid      
      
  INSERT INTO Tbl_ad_primarytextData (        
    primarytext1        
    ,primarytext2        
    ,primarytext3        
    ,primarytext4        
    ,primarytext5        
    ,Description1        
    ,Description2        
  ,Description3        
    ,Description4        
    ,Description5        
    ,Headline1        
    ,Headline2        
    ,Headline3        
    ,Headline4        
    ,Headline5        
    )        
   SELECT primarytext1        
    ,primarytext2        
    ,primarytext3        
    ,primarytext4        
    ,primarytext5        
    ,descriptiontext1        
    ,descriptiontext2        
    ,descriptiontext3        
    ,descriptiontext4        
    ,descriptiontext5        
    ,headline1        
    ,headline2        
    ,headline3        
    ,headline4        
    ,headline5        
   FROM openjson(@Primary_text) WITH (        
     primarytext1 VARCHAR(max) '$.primarytext1'        
     ,primarytext2 VARCHAR(max) '$.primarytext2'        
     ,primarytext3 VARCHAR(max) '$.primarytext3'        
     ,primarytext4 VARCHAR(max) '$.primarytext4'        
     ,primarytext5 VARCHAR(max) '$.primarytext5'        
     ,descriptiontext1 VARCHAR(max) '$.descriptiontext1'        
     ,descriptiontext2 VARCHAR(max) '$.descriptiontext2'        
     ,descriptiontext3 VARCHAR(max) '$.descriptiontext3'        
     ,descriptiontext4 VARCHAR(max) '$.descriptiontext4'        
     ,descriptiontext5 VARCHAR(max) '$.descriptiontext5'        
     ,headline1 VARCHAR(max) '$.headline1'        
     ,headline2 VARCHAR(max) '$.headline2'        
     ,headline3 VARCHAR(max) '$.headline3'        
     ,headline4 VARCHAR(max) '$.headline4'        
     ,headline5 VARCHAR(max) '$.headline5'        
     )        
  set @textid= SCOPE_IDENTITY()      
      
   UPDATE tbl_Adcreatives        
   SET Ad_Name = @adname        
    ,Description = @description        
    ,Primary_text = @textid        
    ,HeadLine = @HeadLine        
    ,Ad_StartDate = @Ad_StartDate        
    ,Ad_EndDate = @Ad_EndDate        
    ,Call_to_action = @Call_to_action        
    ,Website_URL = @Website_URL        
    ,Media_id = @Media_id        
    ,ModifiedDate = GETDATE()        
    ,adcreative_Id = @adcreative_Id        
    ,Thumb_id = @thumbid        
    ,ContactNo = @contactno        
    ,Formid = @formid        
   WHERE id = @id        
        
   SELECT 'Ad Creative Updated'        
        
   SET @rowJson = (        
     SELECT *        
     FROM tbl_Adcreatives WITH (NOLOCK)        
     WHERE id = @id        
     FOR JSON AUTO        
      ,INCLUDE_NULL_VALUES        
     )        
   SET @activity = 'Updt_AdCreative'        
   SET @action = 'U'        
  END        
 END        
        
 IF @mode = 'adId'        
 BEGIN        
  SELECT @campaignid = camp.Campaign_code        
   ,@adsetcode = adset.Adset_Code        
   ,@adcreativeid = cret.adcreative_Id        
  FROM tbl_adcampaigns camp        
  JOIN tbl_adsets adset ON camp.Campaign_code = adset.Campaign_ID        
  JOIN tbl_adcreatives cret ON adset.Adset_Code = cret.Adset_Id        
        
  UPDATE tbl_Adcreatives        
  SET Ad_Id = @adid        
   ,adcreative_Id = @adcreative_Id        
  WHERE id = @id        
        
  UPDATE tbl_adcampaigns        
  SET STATUS = 'PAUSED'        
  WHERE Campaign_code = @campaignid        
        
  UPDATE tbl_adsets        
  SET STATUS = 'PAUSED'        
  WHERE Adset_Code = @adsetcode        
  
  UPDATE tbl_adcreatives        
  SET STATUS = 'PAUSED'        
  WHERE adcreative_Id = @adcreativeid        
        
  SET @rowJson = (        
    SELECT *        
    FROM tbl_Adcreatives WITH (NOLOCK)        
    WHERE id = @id        
    FOR JSON AUTO        
     ,INCLUDE_NULL_VALUES        
    )        
  SET @activity = 'Updt_AdCreative'        
  SET @action = 'U'        
 END        
        
 IF @rowJson IS NOT NULL        
 BEGIN        
  EXEC MySmsAudit_dev.dbo.Usp_AuditTableDataByParentId @User_id = @userid        
   ,@Activity_type = @activity        
   ,@ActionType = @action        
   ,@RowJson = @rowJson        
   ,@Table_name = 'tbl_Adcreatives'        
 END        
END



GO

