/* ============================================================
   Procedure: [dbo].[Usp_Ad_UpdateAdsets_Budgets_Targeting]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE Usp_Ad_UpdateAdsets_Budgets_Targeting (    
 @Country_code VARCHAR(10) = NULL    
 ,@State NVARCHAR(255) = NULL    
 ,@State_key NVARCHAR(20) = NULL    
 ,@city NVARCHAR(255) = NULL    
 ,@city_key NVARCHAR(20) = NULL    
 ,@Zip_Code BIGINT = NULL    
 ,@Country NVARCHAR(255) = NULL    
 ,@Address NVARCHAR(255) = NULL    
 ,@longitude NVARCHAR(255) = NULL    
 ,@latitude NVARCHAR(255) = NULL    
 ,@Radius INT = NULL    
 ,@Min_Age INT = NULL    
 ,@Max_Age INT = NULL    
 ,@Gender BIT = NULL    
 ,@Budget_Name NVARCHAR(MAX) = NULL    
 ,@budget_type VARCHAR(50) = NULL    
 ,@StartDate DATETIME = NULL    
 ,@EndDate DATETIME = NULL    
 ,@Amount BIGINT = NULL    
 ,@Adset_Code NVARCHAR(max) = NULL    
 ,@AdSet_Name NVARCHAR(MAX) = NULL    
 ,@billing_event NVARCHAR(50) = NULL    
 ,@bid_amount NVARCHAR(10) = NULL    
 ,@Userid BIGINT = NULL    
 ,@industryid NVARCHAR(max)  = null  
 ,@customaudience NVARCHAR(max)  = null  
 ,@placement Nvarchar(max)= null  
 )    
AS    
BEGIN    
 DECLARE @parentid BIGINT = (    
   SELECT ParentID    
   FROM user_detail(NOLOCK)    
   WHERE USER_ID = @Userid    
   )    
 DECLARE @targetid BIGINT    
 DECLARE @Budget_id BIGINT    
    
 SELECT @targetid = Target_ID    
  ,@Budget_id = Budget_Id    
 FROM tbl_AdSets    
 WHERE Adset_Code = @Adset_Code    
    
 UPDATE tbl_AdtargetingAudience    
 SET Country = @Country    
  ,Country_code = @Country_code    
  ,[State] = @State    
  ,State_key = @State_key    
  ,city = @city    
  ,city_key = @city_key    
  ,Zip_Code = @Zip_Code    
  ,[Address] = @Address    
  ,longitude = @longitude    
  ,latitude = @latitude    
  ,Radius = @Radius    
  ,Min_Age = @Min_Age    
  ,Max_Age = @Max_Age    
  ,Gender = @Gender    
  ,IndustryId = @industryid  
  ,customaudience = @customaudience  
 WHERE id = @targetid    
    
 UPDATE tbl_AdBudget    
 SET Budget_Name = @Budget_Name    
  ,budget_type = @budget_type    
  ,StartDate = @StartDate    
  ,EndDate = @EndDate    
  ,Amount = @Amount    
 WHERE id = @Budget_id    
    
 UPDATE tbl_AdSets    
 SET AdSet_Name = @AdSet_Name    
  ,ModifiedBy = @Userid    
  ,ModifiedDate = getdate()    
  ,billingevent = @billing_event    
  ,bidamount = bidamount    
  ,Platform=@placement  
 WHERE Adset_Code = @Adset_Code    
    
 SELECT 'Adset Updated'    
  DECLARE @rowJson NVARCHAR(MAX) = (    
    SELECT *    
    FROM tbl_AdSets WITH (NOLOCK)    
    WHERE Adset_Code = @Adset_Code    
    FOR JSON AUTO    
     ,INCLUDE_NULL_VALUES    
    )    
 IF @rowJson IS NOT NULL    
BEGIN    
 EXEC MySmsAudit_dev.dbo.Usp_AuditTableDataByParentId @User_id = @Userid    
  ,@Activity_type = 'Updt_AdSets'    
  ,@ActionType = 'U'    
  ,@RowJson = @rowJson    
  ,@Table_name = 'tbl_AdSets'    
END    
END



GO

