---------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------
CREATE   PROC dbo.usp_add_contact_details @Group_ID BIGINT
	,@M_ID BIGINT
	,
	-- change all datatypes below by gaurav on 18-08-2010 according to table       
	@User_ID INT
	,@Contact_Name VARCHAR(50)
	,@Contact_Mobile VARCHAR(50)
	,@Contact_Email VARCHAR(50)
	,@Contact_BG VARCHAR(50)
	,@Contact_DOB VARCHAR(50)
	,@Contact_Anniversary VARCHAR(50)
