	,@City VARCHAR(100)
	,@State VARCHAR(100)
	,@Country VARCHAR(100)
	,@Address VARCHAR(200)
AS
IF EXISTS (
		SELECT Contact_Email
		FROM contact_detail
		WHERE m_id = @M_ID
			AND user_id = @User_ID
			AND Contact_Email = @Contact_Email
			AND group_id = @Group_ID
			AND Contact_Email IS NOT NULL
			AND Contact_Email != ''
		)
BEGIN
	SELECT 'Email ID Already Exists'
END
ELSE IF EXISTS (
		SELECT Contact_Mobile
		FROM contact_detail
		WHERE m_id = @M_ID
			AND user_id = @User_ID
			AND Contact_Mobile = @Contact_Mobile
			AND group_id = @Group_ID
		)
BEGIN
	SELECT 'Mobile No. Already Exists'
END
ELSE
BEGIN
	INSERT INTO contact_detail (
		Group_ID
		,M_ID
		,User_ID
		,Contact_Name
		,Contact_Mobile
		,Contact_Email
		,Contact_BG
		,Contact_DOB
		,Contact_Anniversary
		,CompanyName
		,City
		,STATE
		,Country
		,Address
		)
	VALUES (
		@Group_ID
		,@M_ID
		,@User_ID
		,@Contact_Name
		,@Contact_Mobile
		,@Contact_Email
		,@Contact_BG
		,@Contact_DOB
		,@Contact_Anniversary
		,@CompanyName
		,@City
		,@State
		,@Country
		,@Address
		)

	DECLARE @contactid BIGINT

	SET @contactid = scope_identity()

	SELECT 'Contact Add Successfully'

	DECLARE @rowJson NVARCHAR(MAX) = (
			SELECT *
			FROM contact_detail(NOLOCK)
			WHERE Contact_ID = @contactid
			FOR JSON AUTO
				,INCLUDE_NULL_VALUES
			)

	EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @User_ID
		,@Activity_type = 'Inst_NewCntct'
		,@ActionType = 'I'
		,@RowJson = @rowJson
		,@Table_name = 'contact_detail'
END



GO

