CREATE   PROC dbo.usp_add_group @M_ID BIGINT
	,@User_ID BIGINT
	,@Group_Name NVARCHAR(50)
AS
IF EXISTS (
		SELECT Group_Name
		FROM group_detail
		WHERE Group_Name = @Group_Name
			AND m_id = @M_ID
			AND user_id = @User_ID
		)
BEGIN
	SELECT 'Group Name Already Exists'
END
ELSE
BEGIN
	INSERT INTO group_detail (
		M_ID
		,User_ID
		,Group_Name
		)
	VALUES (
		@M_ID
		,@User_ID
		,@Group_Name
		)

	SELECT 'Group Add Successfully'

	DECLARE @rowJson NVARCHAR(MAX) = (
			SELECT *
			FROM group_detail
			WHERE Group_Name = @Group_Name
			AND m_id = @M_ID
			AND user_id = @User_ID
			FOR JSON AUTO
				,INCLUDE_NULL_VALUES
			)

	EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @User_ID
		,@Activity_type = 'Inst_usrgrp'
		,@ActionType = 'I'
		,@RowJson = @rowJson
		,@Table_name = 'group_detail'
END



