/* ============================================================
   Procedure: [dbo].[usp_add_remove_tag_bulk]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


--------------------------------------------------------------------------------


CREATE  PROCEDURE [dbo].[usp_add_remove_tag_bulk]        
    @entities AS entities READONLY,  
    @actiontype NVARCHAR(50),  
    @actiondetails NVARCHAR(MAX),
	@massbatchid bigint =0,    
 @StartDateTime VARCHAR(50)='' 
AS        
BEGIN        
    DECLARE @parentid BIGINT,  
            @entity NVARCHAR(20),  
            @entityid BIGINT,  
            @createdby BIGINT,  
            @totalRecords INT = 0; -- Variable to hold the total records count  
			if @massbatchid IS NOT NULL AND @massbatchid <> 0        
BEGIN        
 --select @EnqID= STRING_AGG(cast(Entityid as nvarchar(max)),'#') from Tbl_MassOperationDetails where SummaryId=@massbatchid         
 Update  Tbl_MassOperationSummary set BatchStartTime= GetDate(),ScheduleDateTime= @StartDateTime  where BatchID=@massbatchid         
END                                          
 declare @batchid bigint
  
    SELECT TOP 1 @entity = entity, @entityid = entityid FROM @entities;  
  declare @entities2 as entities  
    IF @entity = 'lead'        
        SELECT @parentid = parentid FROM userleads(NOLOCK) WHERE id = @entityid;  
    ELSE IF @entity = 'enquiry'        
        SELECT @parentid = parentid FROM userenquiry(NOLOCK) WHERE enquiryid = @entityid;  
  
    SELECT @createdby = @parentid;  
  declare @tag_op int=(select count(1) from @entities),@tag_op_id bigint=0  
  
while @tag_op>0  
begin  
begin try  
insert into @entities2(entity,entityid)  
select top 500 entity,entityid from @entities where entityid>@tag_op_id order by entityid  
  
    IF (@actiontype IN ('Add Tag','Remove Tag'))  
    BEGIN  
        PRINT CONCAT(FORMAT(GETDATE(), 'dd-MM-yyyy H:mm:sss'), ': add/remove tag');  
        BEGIN   
            DECLARE @tagid BIGINT;  
            SELECT TOP 1 @tagid = id FROM tagmaster(NOLOCK) WHERE parentid = @parentid AND tag = @actiondetails;  
  
            IF ISNULL(@tagid, 0) = 0 AND @actiontype = 'Add Tag'  
            BEGIN  
                INSERT INTO tagmaster(tag, ParentID, CreatedDate, CreatedBy, IsActive)  
                SELECT @actiondetails, @parentid, GETDATE(), @createdby, 1;  
                SELECT @tagid = SCOPE_IDENTITY();  
            END  
  
            DROP TABLE IF EXISTS #entity_tags;  
            CREATE TABLE #entity_tags(mappedid BIGINT, entity NVARCHAR(20), entityid BIGINT, tagid BIGINT);  
  
            IF @actiontype = 'Add Tag'  
            BEGIN  
                INSERT INTO EntityTagMapping(entity, entityid, TagID, ParentId, CreatedDate) OUTPUT  
                    inserted.id, inserted.entity, inserted.EntityID, @tagid INTO #entity_tags  
                SELECT entity, entityid, @tagid, @parentid, GETDATE() FROM @entities e WHERE NOT EXISTS  
                (SELECT 1 FROM EntityTagMapping(NOLOCK) WHERE entity = e.entity AND entityid = e.entityid AND tagid = @tagid);  
  
                SET @totalRecords = @@ROWCOUNT; -- Get the count of inserted records  
            END  
            ELSE  
            BEGIN  
                DELETE d OUTPUT deleted.id, deleted.entity, deleted.entityid, @tagid INTO #entity_tags  
                FROM EntityTagMapping d JOIN @entities e ON d.Entity = e.entity AND d.entityid = e.entityid AND d.tagid = @tagid;  
  
                SET @totalRecords = @@ROWCOUNT; -- Get the count of deleted records  
            END  
  
            DECLARE @creator_username NVARCHAR(100) = (SELECT user_login FROM User_Detail(NOLOCK) WHERE user_id = @createdby);  
            DECLARE @tbl1 AS LeadActivitywithid_Tbltype;  
              
            INSERT INTO @tbl1 (leadid, userid, parentid, eventdescription, eventname, reftable, refid)  
            SELECT entityid, @createdby, @ParentID,  
                   CASE   
                       WHEN @actiontype = 'Add Tag' THEN 'A new tag "' + @actiondetails + '" was added to lead no ' + CAST(leadno AS NVARCHAR) + ' , lead name ' + personname + ' by ' + @creator_username   
                       ELSE 'Tag "' + @actiondetails + '" was removed from lead no ' + CAST(leadno AS NVARCHAR) + ' , lead name ' + personname + ' by ' + @creator_username   
                   END,  
                   CASE   
                       WHEN @actiontype = 'Add Tag' THEN 'Tag added to lead'    
                       ELSE 'Tag removed from lead'   
                   END,  
                   'EntityTagMapping',  
                   mappedid  
            FROM #entity_tags l  
            JOIN userleads f(NOLOCK) ON f.ID = l.entityid  
            WHERE l.entity = 'lead'  
            UNION  
            SELECT entityid, @createdby, @ParentID,  
                   CASE   
                       WHEN @actiontype = 'Add Tag' THEN 'A new tag "' + @actiondetails + '" was added to enquiry no ' + CAST(enquiryid AS NVARCHAR) + ' , enquiry name ' + personname + ' by ' + @creator_username   
                       ELSE 'Tag "' + @actiondetails + '" was removed from enquiry no ' + CAST(enquiryid AS NVARCHAR) + ' , enquiry name ' + personname + ' by ' + @creator_username   
                   END,  
                   CASE   
                       WHEN @actiontype = 'Add Tag' THEN 'Tag added to enquiry'    
                       ELSE 'Tag removed from enquiry'   
                   END,  
                   'EntityTagMapping',  
                   mappedid  
            FROM #entity_tags l  
            JOIN userenquiry f(NOLOCK) ON f.enquiryID = l.entityid  
            WHERE l.entity = 'enquiry';  
  
            EXEC UspSaveentityActivity_withMultipleValue_withid_bulk @tbl1;  
			 
              if @massbatchid IS NOT NULL AND @massbatchid <> 0        
 BEGIN        
  Update  Tbl_MassOperationSummary set BatchEndTime= GetDate() , Remarks = 'Record Saved ',ScheduleDateTime= @StartDateTime, IsProcessed=1 where BatchID=@massbatchid         
 END  
            -- Return the total records processed and status message  
            SELECT @totalRecords AS TotalRecords, 'Success' AS StatusMessage;  
        END 
		END
		select @tag_op_id=max(entityid) from @entities2  
select @tag_op=@tag_op -500  
delete from @entities2  
truncate table #entity_tags  
delete from @tbl1 
		END TRY 
        BEGIN CATCH  
            EXEC Mysms.dbo.usp_InsertErrorInfo;  
            -- Return the error status message  
            SELECT 0 AS TotalRecords, 'Error' AS StatusMessage;  
        END CATCH  
    END  
END




GO

