------------------------------------------------------------------------------

CREATE   PROCEDURE [dbo].[usp_add_remove_tag_bulk1]        
@metatdata    Nvarchar(max)='',        
@IDS VARCHAR(MAX) = '',   
@UserId BIGINT,   
@actiontype NVARCHAR(50),    
@actiondetails NVARCHAR(MAX),  
@moduleType VARCHAR(MAX) = '',  
@StartDateTime VARCHAR(MAX) = ''  
 AS        
 BEGIN     
 SET NOCOUNT ON;   
  
  
      BEGIN TRY   
	   IF @IDS IS NULL OR LTRIM(RTRIM(@IDS)) = ''
        BEGIN
            -- Return message if @IDS is null or blank
            SELECT 'ID is null or blank' AS StatusMessage;
            RETURN;
        END
       DECLARE @IDsTable TABLE (ID BIGINT);  
        DECLARE @InsertedTable TABLE (EntityID BIGINT);  
        DECLARE @ParentID BIGINT;  
        DECLARE @NewBatchID BIGINT;  
   DECLARE @MassOperationName VARCHAR(50);  
  
      
        -- Fetch the ParentID using @UserId  
        SELECT @ParentID = ParentID  
        FROM User_Detail (NOLOCK)  
        WHERE User_ID = @UserId;  
   
      
       INSERT INTO Tbl_MassOperationSummary (  
            MassOperationName,  
            UserID,  
            Parentid,  
            CreatedDate,  
            IsProcessed,  
            Remarks,  
            BatchStartTime,  
            BatchEndTime,  
            EntityType,  
            isvalid,  
            metadata,  
            ErrorDetails,  
            SenderId,  
            UrlTrack,  
   TrackedUrl,  
            SmsPlaceHolder,  
   ScheduleDateTime  
        )  
        VALUES (  
            @actiontype,  
            @UserId,  
            @ParentID,  
            GETDATE(),  
            0,  
            NULL,  
            null,  
            NULL,  
            @moduleType,  
            1,  
            @metatdata, -- metadata  
            NULL,  
            NULL,  
            NULL,  
   NULL,  
            NULL,  
   @StartDateTime  
        );  
  
        -- Get the BatchID of the last inserted row  
        SELECT @NewBatchID = SCOPE_IDENTITY();  
  
        /*-- Remove braces from @IDS if they exist  
        SET @IDS = REPLACE(REPLACE(@IDS, '{', ''), '}', '');  
  
        -- Split the IDs and insert into the temporary table  
        DECLARE @Pos INT, @Str VARCHAR(MAX);  
        SET @Pos = 1;  
        WHILE CHARINDEX(',', @IDS, @Pos) > 0  
        BEGIN  
            SET @Str = SUBSTRING(@IDS, @Pos, CHARINDEX(',', @IDS, @Pos) - @Pos);  
            INSERT INTO @IDsTable (ID) VALUES (CAST(@Str AS BIGINT));  
            SET @Pos = CHARINDEX(',', @IDS, @Pos) + 1;  
        END  
        INSERT INTO @IDsTable (ID) VALUES (CAST(SUBSTRING(@IDS, @Pos, LEN(@IDS) - @Pos + 1) AS BIGINT));  */
		-- Remove braces from @IDS if they exist  
        SET @IDS = REPLACE(REPLACE(@IDS, '{', ''), '}', '');  
  
        -- Split the @IDS string and insert into the @IDsTable table using STRING_SPLIT
        INSERT INTO @IDsTable (ID)
        SELECT CAST(value AS BIGINT)
        FROM STRING_SPLIT(@IDS, ',');
  
        -- Insert records into Tbl_MassOperationDetails using the new BatchID  
        INSERT INTO Tbl_MassOperationDetails (SummaryId, EntityID)  
        SELECT @NewBatchID, ID FROM @IDsTable;  
  
  -- Call Usp_MassOperationLeadEnquiryProcess with the new BatchID        
  EXEC [dbo].[Usp_MassOperationLeadEnquiryProcess] @summary_batchid = @NewBatchID;   
        -- Return a status message and count of rows inserted for the given IDs  
        SELECT 'Success' AS StatusMessage, COUNT(*) AS TotalRecords FROM @IDsTable;  
  
    END TRY  
    BEGIN CATCH  
         EXEC usp_InsertErrorInfo;  
    END CATCH;  
  
 END 



GO

