   Procedure: [dbo].[usp_addautofollowup]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_addautofollowup
@leadid bigint
as
begin
declare @AutoLeadFollowup bit = 0    
    declare @FollowupStatus int = 0    
    declare @NextStatusDateAddUnit nvarchar(100) = ''    
    declare @FollowupRemarks nvarchar(max) = ''     
    declare @AddDayUnit nvarchar(10) = '00';     
    declare @AddHrsUnit nvarchar(10) = '00';    
    declare @AddMinutesUnit nvarchar(10) = '00' ;    
    declare @DtFLP datetime = null,@leadname nvarchar(200),@parentid bigint,@userid bigint
select @parentid=parentid,@userid=CreatedBy from userleads(nolock) where id=@leadid    

if(exists (select 1 from UserLeads(nolock) where ID = @LeadID and nullif(FollowUpStatus,0) is null))    
 Begin    
 if(exists (select 1 from crmCampaignSettings(nolock) where UserID = @ParentID ))    
     Begin    
     select top 1    
         @AutoLeadFollowup = ISNULL(nullif(AutoLeadFollowup,0),1),    
         @FollowupStatus = isnull(nullif(FollowupStatus,0),1),    
         @NextStatusDateAddUnit = ISNULL(NextStatusDateAddUnit,0),    
         @FollowupRemarks = FollowupRemarks
    from crmCampaignSettings(nolock) where UserID = @ParentID    
  End
  else
  begin
  select @AutoLeadFollowup = 1,    
         @FollowupStatus = 1,    
         @NextStatusDateAddUnit = 0,    
         @FollowupRemarks = ''
  end
         
  if(@AutoLeadFollowup = 1)    
    Begin    
      if(@NextStatusDateAddUnit <> '')    
     Begin    
        -- 00:00:00    
     --set @NextStatusDateAddUnit ='00:00:00'    
         
     SELECT @AddDayUnit = value from dbo.fn_split(@NextStatusDateAddUnit,':') where position=1-- SUBSTRING(@NextStatusDateAddUnit,1,2)    
     SELECT @AddHrsUnit = value from dbo.fn_split(@NextStatusDateAddUnit,':') where position=2-- SUBSTRING(@NextStatusDateAddUnit,4,2)    
     SELECT @AddMinutesUnit = value from dbo.fn_split(@NextStatusDateAddUnit,':') where position=3-- SUBSTRING(@NextStatusDateAddUnit,7,2)    
    
     if isnumeric(@adddayunit)=1 and isnumeric(@addhrsunit)=1 and isnumeric(@addminutesunit)=1    
     begin    
     set @DtFLP =  dateadd(MINUTE,cast(@AddMinutesUnit as int),dateadd(HOUR,cast(@AddHrsUnit as int),DATEADD(DAY,cast(@AddDayUnit as int),GETDATE())))    
     end    
     else    
     set @DtFLP=getdate()    
     --select @DtFLP     
    
            End    
       update Userleads set FollowUpStatus = @FollowupStatus     
        ,remarks = case when @FollowupRemarks is not null then @FollowupRemarks    
                    else remarks     
        end,FollowupDate = @DtFLP     
          , NextStatusDate = @DtFLP     
       ,AssignedTo=
	   COALESCE(Assignedto,((select top 1 value from fn_Split((select agents from CRMCampaignSettings where userid=@ParentID),'#')    ORDER BY NEWID())),@userid)     
        where id = @Leadid    
		declare @assagent bigint=(select assignedto from userleads(nolock) where id=@LeadId)
        /*    
     update Userleads set FollowupDate = @DtFLP     
          , NextStatusDate = @DtFLP      
     where id = @Leadid    
      
      
	  if not exists(select 1 from LeadInteractionHistory(nolock) where parentid=@ParentID and leadno=@leadno)
	  begin   
      insert into LeadInteractionHistory(LeadNo,FollowUpStatus,NextStatusDate,Remarks,AssignedTo,ParentID,CreatedOn,CreatedBy,FollowupDate)
	  select @leadno,@FollowupStatus,@DtFLP,@FollowupRemarks,@assagent,@parentid,getdate(),@ParentID,@DtFLP
	  end
	  */ 
    End    
      
      
 end    
 end


