   Procedure: [dbo].[Usp_AddCreditForPlans]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

    
/****************************************************************************                            
SP_Name        : Usp_AddCreditForPlans                                               
Author         : Ratnakar Sahoo                             
Created ON     : 05/01/2016 06:41 PM                                  
Version        : 1                            
Alter by       :  Ratnakar Sahoo                                 
Alter Date    :   -                           
Location       : PelSoftLab                            
SP Description : This SP is Used to Insert credits for KIT19                             
                                                     
****************************************************************************/        
          
          
CREATE   PROC [dbo].[Usp_AddCreditForPlans] --10181,24795,97,1                                  
(                                    
@M_ID bigint,                                                              
@User_ID int,                                                          
@MsgCount int,                                  
@NoOfPeople int,                
 @BankTransactionId nvarchar(100)                          
)                                  
as       
  
  
 --Declare @ParentID bigint = 0  
 --Declare @MID_P bigint = 0  
 --Select  @ParentID = ParentID from User_detail where User_ID = @User_ID and M_ID =  @M_ID  
 --Select  @MID_P = M_ID  from User_detail where User_ID = @ParentID   
  
  
                             
declare @BalanceMsg bigint,@creditid bigint,@FinalBalance bigint,@UsageMessage int,@default_credit bigint, @rCredit bigint, @rCredit_id bigint ,@creditType varchar(15)                   
                            
set @creditid=(select max(Credit_ID) from Credit_Details where m_id=@M_ID and User_ID=@User_ID)                 
                                                        
                            
select top 1 @rCredit=Debits,@rCredit_id=Credit_ID  from credit_details where m_id=@M_ID and user_id=@User_ID             
         
order by credit_id  desc                                              
                                                             
select @BalanceMsg=max(Balance) from Credit_Details where m_id=@M_ID and User_ID=@User_ID and Credit_ID=@creditid                              
select @default_credit=max(default_credit) from Credit_Details where m_id=@M_ID and User_ID=@User_ID and Credit_ID=@creditid                              
set @UsageMessage=(@MsgCount*@NoOfPeople)                                                    
             
                
set @FinalBalance=(@BalanceMsg+@UsageMessage)                         
                             
begin                               
   insert into credit_details(FromUser_ID,M_ID,User_ID,Debits,Credits,Balance,Validity,Default_Credit,CreatedBy)                      
values(@User_ID,@M_ID,@User_ID,0,@UsageMessage,@FinalBalance,99999,@default_credit,@User_ID)      
    
update Payment_Detail set  OldSmsBalance=@BalanceMsg ,NewSmsBalance=@FinalBalance  where BankTransactionId=@BankTransactionId                
                              
END 


GO

/* ============================================================
   Procedure: [dbo].[Usp_AddDeal]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_AddDeal  
(  
 @LeadID bigint,  
 @PipelineID bigint,  
 @PipelineStage bigint,  
 @Amount numeric(18,2),  
 @EstimatedClosureDate datetime,  
 @DealOwner bigint,  
 @CreatedBy bigint   
  
)  
as  
Begin  
    
  declare @Probability numeric(18,2) = 0  
   
  select  top 1  @Probability = isnull(Probability,0) from PipelineStages(nolock) where   
    ID = @PipelineStage  and PipelineID = @pipelineID   
 
 if(not exists(select 'x' from LeadPipelineMapping where LeadID = @LeadID))
  Begin
       
  insert into LeadPipelineMapping  
  (  
       [LeadID]  
      ,[PipelineID]  
      ,[PipeLineStage]  
      ,[Probability]  
      ,[Amount]  
      ,[Remarks]  
      ,[CreatedDate]  
      ,[CreatedBy]  
      ,[EstimatedClosureDate]  
      ,[DealOwner]  
  )  
  values  
    (  
   @LeadID,  
   @PipelineID,  
   @PipelineStage,  
   @Probability,  
   @Amount,  
   'Deal created',  
   getdate(),  
   @Createdby,  
   @EstimatedClosureDate,  
   @DealOwner  
     )  
  
  select 'Deal Saved'  
  
 end
 else
 Begin
    select 'LeadID Already Occupied'
 End
  
End


GO

/* ============================================================
   Procedure: [dbo].[Usp_AddDeal_New]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_AddDeal_New] (      
 @LeadID BIGINT      
 ,@PipelineID BIGINT      
 ,@PipelineStage BIGINT      
 ,@Amount NUMERIC(18, 2)      
 ,@EstimatedClosureDate DATETIME = NULL      
 ,@DealOwner BIGINT      
 ,@CreatedBy BIGINT      
 ,@Probability NUMERIC(18, 2)      
 ,@LostId BIGINT = 0 ,
 @LostRemark nvarchar(200) = NULL     
 )      
AS      
BEGIN      
 --declare @Probability numeric(18,2) = 0                                  
 DECLARE @pname NVARCHAR(100)      
  ,@sname NVARCHAR(100)      
 --select  top 1  @Probability = isnull(Probability,0) from PipelineStages(nolock) where                                   
 -- ID = @PipelineStage  and PipelineID = @pipelineID                                   
 DECLARE @leadpipelineid BIGINT      
 DECLARE @CurrentDateTime DATETIME = getdate()      
 
 /*
 IF (      
   NOT EXISTS (      
    SELECT 'x'      
    FROM LeadPipelineMapping with(nolock)     
    WHERE LeadID = @LeadID      
     AND PipelineID = @PipelineID      
     AND PipeLineStage = @PipelineStage      
    )      
   ) 
  */

 if(1=1)  
 BEGIN      
  INSERT INTO LeadPipelineMapping (      
   [LeadID]      
   ,[PipelineID]      
   ,[PipeLineStage]      
   ,[Probability]      
   ,[Amount]      
   ,[Remarks]      
   ,[CreatedDate]      
   ,[CreatedBy]      
   ,[EstimatedClosureDate]      
   ,[DealOwner]  
    ,[LostRemark]
   )      
  VALUES (      
   @LeadID      
   ,@PipelineID      
   ,@PipelineStage      
   ,@Probability      
   ,@Amount      
   ,'Deal created'      
   ,@CurrentDateTime      
   ,@Createdby      
   ,dbo.fn_getISTtimefromusertime(@CreatedBy, @EstimatedClosureDate)      
   ,@DealOwner 
   ,@LostRemark
   )      
      
  SELECT @leadpipelineid = SCOPE_IDENTITY()      
      
  IF (@LostId > 0)      
  BEGIN      
   UPDATE LeadPipelineMapping      
   SET LostID = @LostId      
   WHERE id = @leadpipelineid      
  END      
      
  BEGIN TRY      
   SELECT @pname = name      
   FROM Pipeline_Master(NOLOCK)      
   WHERE id = @PipelineID      
      
   SELECT @sname = Name      
   FROM PipelineStages(NOLOCK)      
   WHERE id = @PipelineStage      
      
   DECLARE @ParentID BIGINT = 0      
      
   SELECT @ParentID = isnull(ParentID, 0)      
   FROM User_Detail(NOLOCK)      
   WHERE User_ID = @CreatedBy      
      
   DECLARE @eventDesc NVARCHAR(500) = [dbo].[fn_getentityfullname]('lead', @leadid) + '''s deal created for pipeline :' + cast(@Pname AS NVARCHAR) + ', Stage :' + @sname      
      
   EXEC UspSaveLeadActivity_withid @LeadID      
    ,@Createdby      
    ,@ParentID      
    ,@eventDesc      
    ,'Deal Added'      
    ,'LeadPipelineMapping'      
    ,@leadpipelineid      
      
   IF (      
     (      
      SELECT TOP 1 [Name]      
      FROM LeadPipelineMapping lps      
      INNER JOIN PipelineStages pis ON lps.PipelineStage = pis.ID      
      WHERE PipelineStage = @PipelineStage      
      ) = 'Won'      
     )      
   BEGIN      
    --Usp_Insert_Tbl_ST_SalesActivityMaster_New            
    DECLARE @LeadNo BIGINT = (      
      SELECT TOP 1 LeadNo      
      FROM UserLeads(NOLOCK) uld      
      WHERE uld.ID = @LeadID      
      )      
      
    EXEC Usp_Insert_Tbl_ST_SalesActivityMasterNew @leadpipelineid      
     ,'LeadPipelineMapping'      
     ,@Amount      
     ,@CurrentDateTime      
     ,''      
     ,''      
     ,@PipelineID      
     ,@Createdby      
     ,@ParentID      
     ,@LeadNo      
   END      
  END TRY      
      
  BEGIN CATCH      
   EXEC usp_InsertErrorInfo      
  END CATCH      
      
  SELECT 'Deal Saved' [status]      
   ,@leadpipelineid RefId      
   ,'LeadPipelineMapping' TblRefName      
   ,@CurrentDateTime CurrentDateTime      
      
  DECLARE @rowJson NVARCHAR(MAX) = (      
    SELECT *    
    FROM LeadPipelineMapping WITH(NOLOCK)      
    WHERE ID = @leadpipelineid      
    FOR JSON AUTO      
     ,INCLUDE_NULL_VALUES      
    )      
      
  EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @CreatedBy      
   ,@Activity_type = 'Inst_deal_lead'      
   ,@ActionType = 'I'      
   ,@RowJson = @rowJson      
   ,@Table_name = 'LeadPipelineMapping'       END      
 ELSE      
 BEGIN      
  SELECT 'LeadID Already Occupied' [status]      
 END      
END 





GO

