 --  ,case when @DealOwner   =0 then dbo.fn_getleadowner(e.entityid) else @dealowner end
 --from @entities e left join  mass_replaced_content m (nolock) on m.entityid=e.entityid 
 --and m.batchid=@batchid and m.sequenceactionid=@sequenceactionid
 --and m.type=@type  

 if(1=1)    
 BEGIN        
 begin try

 
  INSERT INTO LeadPipelineMapping (        
   [LeadID]        
   ,[PipelineID]        
   ,[PipeLineStage]        
   ,[Probability]        
   ,[Amount]        
   ,[Remarks]        
   ,[CreatedDate]        
   ,[CreatedBy]        
   ,[EstimatedClosureDate]        
   ,[DealOwner]    

   )    output inserted.id,inserted.leadid into #dealid    
  select e.entityid   ,@PipelineID        
   ,@PipelineStage        
   ,@Probability        
   ,isnull(replacedcontent        ,@dealAmount)
   ,'Deal created'        
   ,getdate()        
   ,@Createdby        
   ,dbo.fn_getISTtimefromusertime(@CreatedBy, dateadd(dd,@EstimatedClosureDate,getdate()))        
   ,case when @DealOwner   =0 then dbo.fn_getleadowner(e.entityid) else @dealowner end
 from @entities e left join  mass_replaced_content m (nolock) on m.entityid=e.entityid 
 and m.batchid=@batchid and m.sequenceactionid=@sequenceactionid
 and m.type=@type
        
    SELECT @pname = name        
   FROM Pipeline_Master(NOLOCK)        
   WHERE id = @PipelineID        
        
   SELECT @sname = Name        
   FROM PipelineStages(NOLOCK)        
   WHERE id = @PipelineStage        
        
   DECLARE @ParentID BIGINT = 0        
        
   SELECT @ParentID = isnull(ParentID, 0)        
   FROM User_Detail(NOLOCK)        
   WHERE User_ID = @CreatedBy        
   
   if exists (select 1 from #dealid)
   print 'Deal created'

   DECLARE @tbl1 AS LeadActivitywithid_Tbltype      
      
   INSERT INTO @tbl1 (      
    leadid      
    ,userid      
    ,parentid      
    ,eventdescription      
    ,eventname      
    ,reftable      
    ,refid      
    )      
   SELECT leadid      
    ,@createdby      
    ,@ParentID      
 ,  [dbo].[fn_getentityfullname]('lead', leadid) + '''s deal created for pipeline :' + cast(@Pname AS NVARCHAR) + ', Stage :' + @sname
 ,'Deal Added'
    ,'LeadPipelineMapping'      
    ,l.dealid      
   FROM #dealid l      
     
  EXEC UspSaveentityActivity_withMultipleValue_withid_bulk @tbl1      
  
SELECT 'Deal Saved' [status]            
  END TRY        
        
  BEGIN CATCH    
  SELECT 'Operation failed' [status] 
   EXEC usp_InsertErrorInfo        
  END CATCH        
        
            
END   
 end 
  


