/* ============================================================
   Procedure: [dbo].[usp_AddEnquiryImportSummary_1]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  
CREATE   PROC [dbo].[usp_AddEnquiryImportSummary_1]  
(  
    @ImportData nvarchar(max),  
    @User_Id bigint,  
 @ImportTotal bigint,  
 @filename nvarchar(max),  
 @updatematching bit,  
 @isAutoLead bit,  
    @selectedValue BIGINT  
)  
AS  
BEGIN  
      
    Declare @IsAutoLeadGeneration bit=0  
    Declare @Priority numeric(18,2)=1  
  
    --Select @IsAutoLeadGeneration=AutoLeadDistribution  
    --FROM   CRMCampaignSettings      
    --WHERE  UserID=@User_Id  
  
    select @Priority=COUNT(*)/100 from openjson(@ImportData)  
    IF (@selectedValue = 0)  
 begin  
    Insert into tbl_EnquiryImportSummary(ImportData,User_Id,IsAutoLeadGeneration,[Priority],TotalRecords,ImportFilename,UpdateMatching)  
    Values(@ImportData,@User_Id,@isAutoLead,@Priority,@ImportTotal,@filename,@updatematching)  
  
    Select SCOPE_IDENTITY()  
 end  
   ELSE if(@selectedValue!=0)   
   BEGIN  
    
    DECLARE @Mapping NVARCHAR(MAX);  
    SELECT @Mapping = MappingDetails  
    FROM Enquiry_FieldMappingDetails(nolock)  
    WHERE EField_MappingId = @selectedValue;  
 print @Mapping  
    DECLARE @MappingTable TABLE (  
        OriginalColumn NVARCHAR(MAX),  
        ExcelColumn NVARCHAR(MAX),  
        IsOtherField BIT DEFAULT 0,  
        OtherFieldValue NVARCHAR(MAX) DEFAULT NULL  
    );  
  
    -- Populate Mapping Table  
    INSERT INTO @MappingTable (OriginalColumn, ExcelColumn, IsOtherField, OtherFieldValue)  
    SELECT   
        [Key],   
        CASE   
            WHEN CHARINDEX('(Other Field)', [Value]) > 0 THEN NULL  
            ELSE [Value]  
        END,  
        CASE   
            WHEN CHARINDEX('(Other Field)', [Value]) > 0 THEN 1  
            ELSE 0  
        END,  
        CASE   
            WHEN CHARINDEX('(Other Field)', [Value]) > 0 THEN REPLACE([Value], ' (Other Field)', '')  
            ELSE NULL  
        END  
    FROM OPENJSON(@Mapping);  
    DECLARE @MappedData NVARCHAR(MAX);  
  
    SET @MappedData = cast(@ImportData as nvarchar(max));  
  

  DECLARE @mTable TABLE (MData NVARCHAR(MAX));
   INSERT INTO @mTable VALUES (@MappedData);

  print concat('66: ',@MappedData)
    -- Step 2: Map Data  
    DECLARE @RowIndex INT = 1;  
    DECLARE @TotalRows INT;  
    SELECT @TotalRows = COUNT(*) FROM @MappingTable;  
  
    WHILE @RowIndex <= @TotalRows  
    BEGIN  
        DECLARE @OriginalColumn NVARCHAR(MAX), @ExcelColumn NVARCHAR(MAX);  
        DECLARE @IsOtherField BIT, @OtherFieldValue NVARCHAR(MAX);  
  
        SELECT   
            @OriginalColumn = OriginalColumn,  
            @ExcelColumn = ExcelColumn,  
            @IsOtherField = IsOtherField,  
            @OtherFieldValue = OtherFieldValue  
        FROM (  
            SELECT   
                OriginalColumn,   
                ExcelColumn,   
                IsOtherField,   
                OtherFieldValue,  
                ROW_NUMBER() OVER (ORDER BY (SELECT NULL)) AS RowNum  
            FROM @MappingTable  
        ) AS MappedRow  
        WHERE RowNum = @RowIndex;  
  
        IF @IsOtherField = 0  
        BEGIN  
            --SET @MappedData = REPLACE(cast(@MappedData as nvarchar(max)), '"' + cast(@ExcelColumn as  nvarchar(max)) + '"', '"' +cast(@OriginalColumn as nvarchar(max))+ '"');
			update @mTable SET mdata = cast(REPLACE(cast(MData as nvarchar(max)), '"' + cast(@ExcelColumn as  nvarchar(max)) + '"', '"' +cast(@OriginalColumn as nvarchar(max))+ '"') as nvarchar(max)); 
			  --print concat('96: ',@MappedData)

        END  
        ELSE IF @IsOtherField = 1  
        BEGIN  
		update @mTable SET mdata = cast(REPLACE(cast(mdata as nvarchar(max)), '{', '{"' + cast(@OriginalColumn as nvarchar(max)) + '":"' + cast(@OtherFieldValue as nvarchar(max)) + '",') as nvarchar(max));
            --SET @MappedData = REPLACE(cast(@MappedData as nvarchar(max)), '{', '{"' + cast(@OriginalColumn as nvarchar(max)) + '":"' + cast(@OtherFieldValue as nvarchar(max)) + '",');
			  --print concat('102: ',@MappedData)

        END  
  
        SET @RowIndex = @RowIndex + 1;  
    END  
 print @MappedData  
    CREATE TABLE #TempResult (COLUMN_NAME NVARCHAR(MAX), DATA_TYPE NVARCHAR(MAX), SEQUENCE INT);  
    INSERT INTO #TempResult  
    EXEC usp_GetEnquiryImportFields @User_Id;  
  
    DECLARE @MissingColumns TABLE (COLUMN_NAME NVARCHAR(MAX));  
    INSERT INTO @MissingColumns (COLUMN_NAME)  
    SELECT COLUMN_NAME  
    FROM #TempResult  
    WHERE COLUMN_NAME NOT IN (  
        SELECT OriginalColumn FROM @MappingTable  
    );
	  DECLARE @MissingColumn NVARCHAR(MAX),@tempmappeddata nvarchar(max);  
    DECLARE @MissingColumnValue NVARCHAR(MAX) = null; 
	
	
  
    DECLARE MissingCursor CURSOR FOR  
    SELECT COLUMN_NAME FROM @MissingColumns;  
  
    OPEN MissingCursor;  
    FETCH NEXT FROM MissingCursor INTO @MissingColumn;  
  
    WHILE @@FETCH_STATUS = 0  
    BEGIN  
        --SET @MappedData = REPLACE(@MappedData, '{', '{"' + @MissingColumn + '":' + @MissingColumnValue + ',');  
		SElecT @TempMappedData = cast(REPLACE(CAST(mdata AS NVARCHAR(MAX)), '{', '{"' + 
                          CAST(@MissingColumn AS NVARCHAR(MAX)) + '":null,') as nvarchar(max)) from @mTable;
		update @mTable set MData = cast(@TempMappedData as nvarchar(max))

	  --cast(REPLACE(cast(@MappedData as nvarchar(max)), '{', '{"' + cast(@MissingColumn as nvarchar(max)) + '":null,') as nvarchar(max));  
        FETCH NEXT FROM MissingCursor INTO @MissingColumn;  
    END  

	/*
    DECLARE @MissingColumn NVARCHAR(MAX);  
    DECLARE @MissingColumnValue NVARCHAR(MAX) = null;  
  
    DECLARE MissingCursor CURSOR FOR  
    SELECT COLUMN_NAME FROM @MissingColumns;  
  
    OPEN MissingCursor;  
    FETCH NEXT FROM MissingCursor INTO @MissingColumn;  
  
    WHILE @@FETCH_STATUS = 0  
    BEGIN  
        --SET @MappedData = REPLACE(@MappedData, '{', '{"' + @MissingColumn + '":' + @MissingColumnValue + ',');  
      SET @MappedData = REPLACE(cast(@MappedData as nvarchar(max)), '{', '{"' + cast(@MissingColumn as nvarchar(max)) + '":null,');  
        FETCH NEXT FROM MissingCursor INTO @MissingColumn;  
    END  
	*/
    print concat('135: ',@MappedData)

    CLOSE MissingCursor;  
    DEALLOCATE MissingCursor;  
  
    DROP TABLE #TempResult;  
  
 --if(1=1)  
 --begin  
 --   Insert into tbl_EnquiryImportSummary(ImportData,User_Id,IsAutoLeadGeneration,[Priority],TotalRecords,ImportFilename,UpdateMatching)  
 --    select mdata,@User_Id,@isAutoLead,@Priority,@ImportTotal,@filename,@updatematching from @mTable  
   
 --   SELECT SCOPE_IDENTITY();  
 --end  
END;  
  --else   
  --begin  
  --select 'Invalid data. Please look for white spaces / Unprintable characters in your sheet'  
  --end  
END  
  
  
  


