/* ============================================================
   Procedure: [dbo].[USP_AddEscortskubota_DealerDailyUpdate]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[USP_AddEscortskubota_DealerDailyUpdate]
    @ParentId BIGINT,
    @JsonDetails NVARCHAR(MAX),
    @CreatedBy BIGINT,
    @CreatedDate DATETIME,
    @NewID INT OUTPUT -- Added OUTPUT parameter to return the new ID
AS
BEGIN
    SET NOCOUNT ON;

    BEGIN TRY
        -- Insert data into Escortskubota_DealerUpdateLog
        INSERT INTO TBL_Escortskubota_DealerDailyUpdate (ParentID, JsonDetails, CreatedBy, CreatedDate)
        VALUES (@ParentId, @JsonDetails, @CreatedBy, @CreatedDate);

        -- Get the new inserted ID and assign it to the OUTPUT parameter
        SET @NewID = SCOPE_IDENTITY();
    END TRY
    BEGIN CATCH
        -- Handle errors
        DECLARE @ErrorMessage NVARCHAR(4000) = ERROR_MESSAGE();
        DECLARE @ErrorSeverity INT = ERROR_SEVERITY();
        DECLARE @ErrorState INT = ERROR_STATE();

        RAISERROR (@ErrorMessage, @ErrorSeverity, @ErrorState);
    END CATCH
END;



