/* ============================================================
   Procedure: [dbo].[Usp_AddFollowup_Lead_API]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_AddFollowup_Lead_API]              
(              
    @Lead_No BIGINT,              
    @AssignedTo BIGINT,              
    @FollowUpStatus INT,              
    @NextStatusDate VARCHAR(50),              
    @Products VARCHAR(1000),              
    @AmountPaid NUMERIC(18, 2),              
    @Remarks VARCHAR(1000),              
    @ModifiedBy BIGINT,  
    @ParentID bigint              
)              
AS              
BEGIN              
          
  --declare  @ParentID  bigint = 0  		  
   
  --select @ParentID = isnull(ParentID,0) from User_Detail where User_ID = @UserID 
   		  
		    
  declare @FollowupDate   Datetime = null              
  if(@NextStatusDate <> '' and @NextStatusDate is not null)                
  begin      
  Begin  try              
  set @FollowupDate=convert(datetime,@NextStatusDate)      
  end try      
  begin catch      
  if(@FollowupDate is null)      
   begin    
   declare @LeadID bigint = 0    
    
   select @LeadID = ID  from UserLeads where LeadNo = @Lead_No and ParentID = @ParentID     
       
    insert into followupDateError (leadid, nextstatusdate, parentid) values (@LeadID, @NextStatusDate, @ParentID)      
       
   end       
  end catch              
   End              
            
  if(@FollowupDate is not null)                
   Begin           
             
 UPDATE UserLeads              
 SET    AssignedTo = @AssignedTo,              
        FollowUpStatus = @FollowUpStatus,              
        NextStatusDate = convert(nvarchar(50),dbo.[fn_getISTtimefromusertime](ParentID,@FollowupDate),121) ,       Products = @Products,              
        AmountPaid = @AmountPaid,              
        Remarks = @Remarks,              
        ModifiedBy = @ModifiedBy ,             
        FollowupDate = dbo.[fn_getISTtimefromusertime](ParentID,@FollowupDate)           
 WHERE  LeadNo = @Lead_No  and ParentID = @ParentID             
               
  
 insert into LeadInteractionHistory          
  (          
 
  LeadNo,
  FollowUpStatus,          
  NextStatusDate,
  Products,          
  AmountPaid,
  Remarks,          
  AssignedTo,
  ParentID,          
  CreatedOn,
  CreatedBy,          
  FollowupDate          
 
 )          
 values          
 (  
   
  @Lead_No,
  @FollowUpStatus,          
  @NextStatusDate,
  @Products,          
  @AmountPaid,
  @Remarks,          
  @AssignedTo,  
  @ParentID,          
  GETDATE(),
  @ModifiedBy,          
  @FollowupDate          
   
 )               
  
    End        
  else        
    Begin        
            
   UPDATE UserLeads              
      SET AssignedTo = @AssignedTo,              
        FollowUpStatus = @FollowUpStatus,              
        NextStatusDate = @NextStatusDate,              
        Products = @Products,              
        AmountPaid = @AmountPaid,              
        Remarks = @Remarks,              
        ModifiedBy = @ModifiedBy ,             
        FollowupDate =  @FollowupDate            
        WHERE  LeadNo = @Lead_No  and ParentID = @ParentID             
   
  insert into LeadInteractionHistory          
   (          
     LeadNo,FollowUpStatus,          
     NextStatusDate,Products,          
  AmountPaid,Remarks,          
  AssignedTo,ParentID,          
  CreatedOn,CreatedBy,          
  FollowupDate          
    )          
 values          
    (  
   @Lead_No,@FollowUpStatus,          
  @NextStatusDate,@Products,          
  @AmountPaid,@Remarks,          
  @AssignedTo,  
  @ParentID ,          
  GETDATE()
  ,@ModifiedBy,          
  @FollowupDate          
    )               
   
        
            
    End             
               
               
 SELECT 'Success'              
END 


GO

/* ============================================================
   Procedure: [dbo].[USp_AddLeadEnquiryFromMeetingRegistration]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[USp_AddLeadEnquiryFromMeetingRegistration] 
@MeetingId varchar(max),
@Name varchar(max),
@CountryCode NVARCHAR(max) = '',
@Mobile varchar(max),
@Email varchar(max),
@Address varchar(max),
@Remarks varchar(max),
@Country varchar(max),
@State varchar(max),
@City varchar(max),
@CompanyName varchar(max),
@PinCode varchar(max),
@Parentid bigint ,
@Sourceid bigint ,
@MediumID bigint ,
@userid bigint ,
@entid bigint,
@Entitytype varchar(20)
AS 
BEGIN
	DECLARE @EnquiryID bigint ,@leadid BIGINT ,@leadno BIGINT = 0
if @Entitytype ='enquiry'
	BEGIN

	
	IF EXISTS (SELECT 1 FROM UserLeads_mobile_email(NOLOCK) WHERE ParentID = @Parentid
								AND (( @mobile <> ''
										AND isnull(nullif(@Mobile, ''), '1') = Mobile
										AND @CountryCode <> ''
										AND isnull(nullif(@CountryCode, ''), '3') = CountryCode
										)
									OR ( @Email <> ''
										AND isnull(nullif(@Email, ''), '2') = Email
										)
									)
							)
					BEGIN
						SELECT TOP 1 @leadno = leadno 
						FROM UserLeads_mobile_email(NOLOCK)
						WHERE ParentID = @Parentid
							AND (( @mobile <> ''
									AND isnull(nullif(@Mobile, ''), '1') = Mobile
									AND @CountryCode <> ''
									AND isnull(nullif(@CountryCode, ''), '3') = CountryCode
									)
								OR (@Email <> ''
									AND isnull(nullif(@Email, ''), '2') = Email
									))
						ORDER BY leadno
					END

					INSERT INTO UserEnquiry (
					PersonName
					,CountryCode
					,MobileNo
					,EmailID
					,ResidentialAddress
					,Country
					,State
					,City
					,CompanyName
					,PinCode
					,SourceName
					,MediumName
					,InitialRemarks
					,ParentID
					,CreatedDate
					,CreatedBy
					,CampaignName
					,LeadNo
					,enquirysource
					)
				VALUES (
					@Name
					,@CountryCode
					,@Mobile
					,@Email
					,@Address
					,@Country
					,@State
					,@City
					,@CompanyName
					,@PinCode
					,@Sourceid
					,@MediumID
					,@Remarks
					,@Parentid
					,GETDATE()
					,@userid
					,0
					,@leadno
					,9
					)

				SET @EnquiryID = SCOPE_IDENTITY()

				INSERT INTO ParsedEnquiries (
					RawEnquiryId
					,EnquiryId
					,Parentid
					,Createddate
					,EnquirySource
					)
				SELECT @entid
					,@EnquiryID
					,@Parentid
					,getdate()
					,'Webform'

				UPDATE Tbl_Meet_RegistrationFormData
				SET EntityID = @EnquiryID
				, Entitytype =@Entitytype
				WHERE ID = @entid
				DECLARE @AutoLeadDistribution BIT

				SELECT @AutoLeadDistribution = AutoLeadDistribution
				FROM CRMCampaignSettings(NOLOCK)
				WHERE UserID = @Parentid

				IF (
						@AutoLeadDistribution = 1
						AND @leadno = 0
						)
				BEGIN
					SELECT @Leadno = isnull((
								SELECT MAX(LeadNo)
								FROM UserLeads(NOLOCK)
								WHERE ParentID = @Parentid
								), 0) + 1

					INSERT INTO userleads (
						LeadNo
						,PersonName
						,MobileNo
						,EmailID
						,City
						,PinCode
						,CountryCode
						,OfficeAddress
						,Country
						,State
						,CompanyName

						,AssignedTo
						,SourceName
						,MediumName
						,CampaignName
						,ParentID
						,Remarks
						,CreatedOn
						,CreatedBy
						,--FollowUpStatus,NextStatusDate,FollowupDate,              
						enquirysource
						,LastFollowupCreatedBy
						,LastFollowupCreatedOn
						)
					SELECT @leadno
						,@Name
						,@Mobile
						,@Email
						,@City
						,@PinCode
						,@CountryCode
						,@Address
						,@Country
						,@State
						,@CompanyName
						
						,(
							SELECT TOP 1 value
							FROM fn_Split((
										SELECT agents
										FROM CRMCampaignSettings
										WHERE userid = @Parentid
										), '#')
							ORDER BY NEWID()
							)
						,@Sourceid
						,@MediumID
						,0
						,@Parentid
						,@Remarks
						,GETDATE()
						,@Parentid
						,--1,GETDATE(),GETDATE(),              
						9
						,@Parentid
						,getdate()

					set @leadid  = SCOPE_IDENTITY()

					UPDATE UserEnquiry
					SET LeadNo = @LeadNo
						,IsOpen = 1
					WHERE EnquiryID = @EnquiryID
					EXEC Usp_insertdefaultfollowup @Parentid
						,@leadid

					INSERT INTO tbl_MergeLeadsEnquiry (
						EnquiryNo
						,LeadNo
						,IsOpen
						)
					VALUES (
						@EnquiryID
						,@Leadno
						,1
						)
				END
		END
	if @Entitytype ='lead'
	BEGIN
		SELECT @Leadno = isnull((
								SELECT MAX(LeadNo)
								FROM UserLeads(NOLOCK)
								WHERE ParentID = @Parentid
								), 0) + 1

					INSERT INTO userleads (
						LeadNo
						,PersonName
						,MobileNo
						,EmailID
						,City
						,PinCode
						,CountryCode
						,OfficeAddress
						,Country
						,State
						,CompanyName

						,AssignedTo
						,SourceName
						,MediumName
						,CampaignName
						,ParentID
						,Remarks
						,CreatedOn
						,CreatedBy
						,--FollowUpStatus,NextStatusDate,FollowupDate,              
						enquirysource
						,LastFollowupCreatedBy
						,LastFollowupCreatedOn
						)
					SELECT @leadno
						,@Name
						,@Mobile
						,@Email
						,@City
						,@PinCode
						,@CountryCode
						,@Address
						,@Country
						,@State
						,@CompanyName
						
						,(
							SELECT TOP 1 value
							FROM fn_Split((
										SELECT agents
										FROM CRMCampaignSettings
										WHERE userid = @Parentid
										), '#')
							ORDER BY NEWID()
							)
						,@Sourceid
						,@MediumID
						,0
						,@Parentid
						,@Remarks
						,GETDATE()
						,@Parentid
						,--1,GETDATE(),GETDATE(),              
						9
						,@Parentid
						,getdate()

					set @leadid  = SCOPE_IDENTITY()

					EXEC Usp_insertdefaultfollowup @Parentid
						,@leadid
	END
END


GO

/* ============================================================
   Procedure: [dbo].[usp_AddLeadFollowup]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_AddLeadFollowup] (      
 @ID BIGINT      
 ,@AssignedTo BIGINT      
 ,@FollowUpStatus BIGINT      
 ,@NextStatusDate VARCHAR(50)      
 ,@Products VARCHAR(1000) = ''      
 ,@AmountPaid NUMERIC(18, 2)      
 ,@Remarks nVARCHAR(2000)      
 ,@UserId BIGINT      
 ,@IsReassign BIT      
 --,@EpUniqueIdentity nvarchar(255) = ''                  
 )      
AS      
BEGIN      
 DECLARE @FollowupDate DATETIME = NULL      
  ,@LeadNo BIGINT = 0      
  ,@ParentID BIGINT = 0      
      
 IF (@NextStatusDate <> '')      
 BEGIN      
  SET @FollowupDate = @NextStatusDate      
 END      
      
 IF (@NextStatusDate <> '')      
 BEGIN      
  UPDATE UserLeads      
  SET AssignedTo = @AssignedTo      
   ,FollowUpStatus = @FollowUpStatus      
   ,NextStatusDate = convert(NVARCHAR(100), dbo.[fn_getISTtimefromusertime](@UserId, @FollowupDate), 121)      
   ,Products = @Products      
   ,AmountPaid = @AmountPaid      
   ,Remarks = @Remarks      
   ,ModifiedBy = @UserId      
   ,FollowupDate = dbo.[fn_getISTtimefromusertime](@UserId, @FollowupDate)      
   ,@LeadNo = LeadNo      
   ,@ParentID = ParentID      
  WHERE ID = @ID      
 END      
 ELSE      
 BEGIN      
  UPDATE UserLeads      
  SET AssignedTo = @AssignedTo      
   ,FollowUpStatus = @FollowUpStatus      
   ,NextStatusDate = @NextStatusDate      
   ,Products = @Products      
   ,AmountPaid = @AmountPaid      
   ,Remarks = @Remarks      
   ,ModifiedBy = @UserId      
   ,FollowupDate = @FollowupDate      
   ,@LeadNo = LeadNo      
   ,@ParentID = ParentID      
  WHERE ID = @ID      
 END      
      
 DECLARE @lihid BIGINT      
      
 IF (@NextStatusDate <> '')      
 BEGIN      
  INSERT INTO LeadInteractionHistory (      
   LeadNo      
   ,FollowUpStatus      
   ,NextStatusDate      
   ,IsReassign      
   ,Products      
   ,AmountPaid      
   ,Remarks      
   ,AssignedTo      
   ,ParentID      
   ,CreatedOn      
   ,CreatedBy      
   ,FollowupDate      
   )      
  VALUES (      
   @LeadNo      
   ,@FollowUpStatus      
   ,convert(NVARCHAR(100), dbo.[fn_getISTtimefromusertime](@UserId, @FollowupDate), 121)      
   ,@IsReassign      
   ,@Products      
   ,@AmountPaid      
   ,@Remarks      
   ,@AssignedTo      
   ,@ParentID      
   ,GETDATE()      
   ,@UserId      
   ,dbo.[fn_getISTtimefromusertime](@UserId, @FollowupDate)      
   )      
 END      
 ELSE      
 BEGIN      
  INSERT INTO LeadInteractionHistory (      
   LeadNo      
   ,FollowUpStatus      
   ,NextStatusDate      
   ,IsReassign      
   ,Products      
   ,AmountPaid      
   ,Remarks      
   ,AssignedTo      
   ,ParentID      
   ,CreatedOn      
   ,CreatedBy      
   ,FollowupDate      
   )      
  VALUES (      
   @LeadNo      
   ,@FollowUpStatus      
   ,@NextStatusDate      
   ,@IsReassign      
   ,@Products      
   ,@AmountPaid      
   ,@Remarks      
   ,@AssignedTo      
   ,@ParentID      
   ,GETDATE()      
   ,@UserId      
   ,@FollowupDate      
   )      
 END      
      
 SELECT @lihid = SCOPE_IDENTITY()      
      
 --if(@lihid > 0)                  
 --begin                  
 --if(isnull(@EpUniqueIdentity, '') <> '')                  
 --begin                  
 -- declare @GatewayName nvarchar(255), @EntityName nvarchar(255)                  
 -- select @GatewayName = ProviderName, @EntityName = EntityName from tbl_voip_endpointInteraction(nolock)                   
 --  where id = cast(@EpUniqueIdentity as bigint)                  
 -- insert into tbl_c2c_EventActivityMapping( gateway_name, ep_interaction_id, event_history_id, EntityName )                  
 --  values( @GatewayName, cast( @EpUniqueIdentity as bigint), @lihid, @EntityName )                  
 --end                  
 --end                  
 --if(isnull(@lihid,0) > 0)                            
 IF (@@RowCount > 0)      
 BEGIN      
  SELECT 'Lead Followup Added Successfully' AS Msg      
   ,@LeadNo AS LeadNo      
      
  DECLARE @Nextprocess BIT = 0      
      
  BEGIN TRY      
   IF (@FollowUpStatus = 5)      
   BEGIN      
    SET @Nextprocess = 1      
   END     
   ELSE IF EXISTS (      
     SELECT 1      
     FROM FollowUp_Status fs(NOLOCK)      
     WHERE fs.IsConvert = 1      
      AND fs.ID = @FollowUpStatus      
      AND fs.ParentId = @ParentId      
     )      
   BEGIN      
    SET @Nextprocess = 1      
   END      
      
   IF (@Nextprocess = 1)      
   BEGIN        DECLARE @CreateDate DATETIME = GETDATE()      
      
    EXEC Usp_Insert_Tbl_ST_SalesActivityMasterNew @lihid      
     ,'LeadInteractionHistory'      
     ,@AmountPaid      
     ,@CreateDate      
     ,''      
     ,@Products      
     ,0      
     ,@UserId      
     ,@ParentID      
     ,@LeadNo      
   END      
  END TRY      
      
  BEGIN CATCH      
   EXEC usp_InsertErrorInfo      
  END CATCH      
      
  /* Start Lead Activity */      
  BEGIN TRY      
   DECLARE @UserID_LDACTV BIGINT = @UserId      
   DECLARE @ParentID_LDACTV BIGINT = @ParentID      
   DECLARE @LeadID_LDACTV BIGINT = @ID      
   DECLARE @FollowupStatusID_LDACTV INT = @FollowUpStatus      
   DECLARE @AssingedTo_LDACTV BIGINT = isnull(@AssignedTo, 0)      
      
   CREATE TABLE #tblEventDescrb (EVNT_Description NVARCHAR(max))      
      
   IF (isnull(@LeadID_LDACTV, 0) > 0)      
   BEGIN      
    INSERT INTO #tblEventDescrb      
    EXEC Usp_EventTemplate_DynamicVarReplacement 'New Interaction added'      
     ,@UserID_LDACTV      
     ,''      
     ,''      
     ,@LeadID_LDACTV      
     ,''      
     ,NULL      
     ,0      
     ,0      
     ,''      
     ,''      
     ,0      
     ,''      
     ,0      
     ,NULL      
     ,NULL      
     ,NULL      
     ,NULL      
     ,@FollowupStatusID_LDACTV      
     ,@AssingedTo_LDACTV      
     ,NULL      
     ,NULL      
     ,NULL      
     ,NULL      
     ,NULL      
     ,NULL      
     ,NULL      
     ,NULL      
     ,NULL      
     ,NULL      
     ,NULL      
     ,0      
     ,0      
     ,0      
     ,NULL      
     ,NULL      
     ,NULL      
     ,0      
     ,NULL      
     ,NULL      
     ,NULL      
     ,0      
     ,NULL      
     ,NULL      
      
    DECLARE @evntMessage NVARCHAR(max) = ''      
      
    SELECT @evntMessage = isnull(EVNT_Description, '')      
    FROM #tblEventDescrb      
      
    IF (@evntMessage <> '')      
    BEGIN      
     EXEC UspSaveLeadActivity_withid @LeadID_LDACTV      
      ,@UserID_LDACTV      
      ,@ParentID_LDACTV      
      ,@evntMessage      
      ,'New Interaction added'      
      ,'LeadInteractionHistory'      
      ,@lihid      
    END      
   END      
  END TRY      
      
  BEGIN CATCH      
   EXEC usp_InsertErrorInfo      
  END CATCH      
      
  IF OBJECT_ID('tempdb..#tblEventDescrb') IS NOT NULL -- Check for table existence                            
  BEGIN      
   DROP TABLE #tblEventDescrb      
  END      
    /* End Lead Activity */      
 END      
 ELSE      
 BEGIN      
  SELECT 'Lead Followup not Added Successfully' AS Msg      
   ,@LeadNo AS LeadNo      
 END      
      
 DECLARE @rowJson NVARCHAR(MAX) = (      
   SELECT *     
   FROM LeadInteractionHistory lih      
   WHERE lih.ID = @lihid      
   FOR JSON AUTO      
    ,INCLUDE_NULL_VALUES      
   )      
      
 IF @rowJson IS NOT NULL      
 BEGIN      
  EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserId      
   ,@Activity_type = 'Inst_flwup'      
   ,@ActionType = 'I'      
   ,@RowJson = @rowJson      
   ,@Table_name = 'leadinteractionhistory'      
 END      
END 


GO

/* ============================================================
   Procedure: [dbo].[usp_AddLeadFollowup_GetRecord]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_AddLeadFollowup_GetRecord](                
 @ID BIGINT                
 ,@AssignedTo BIGINT                
 ,@FollowUpStatus BIGINT                
 ,@NextStatusDate VARCHAR(50)                
 ,@Products VARCHAR(1000) = ''                
 ,@AmountPaid NUMERIC(18, 2)                
 ,@Remarks nVARCHAR(2000)                
 ,@UserId BIGINT                
 ,@IsReassign BIT                
 --,@EpUniqueIdentity nvarchar(255) = ''                            
 )                
AS                
BEGIN         
     
     
 --declare     
 -- @ID BIGINT                
 --,@AssignedTo BIGINT                
 --,@FollowUpStatus BIGINT                
 --,@NextStatusDate VARCHAR(50)                
 --,@Products VARCHAR(1000) = ''                
 --,@AmountPaid NUMERIC(18, 2)                
 --,@Remarks nVARCHAR(2000)                
 --,@UserId BIGINT                
 --,@IsReassign BIT        
    
 -- select @ID=14696797,@AssignedTo=32222,@FollowUpStatus=35,@NextStatusDate=N'15-May-2025 11:04:00',@Products=N'Test',@AmountPaid=10,@Remarks=N'Testing Remarks',@UserId=32222,@IsReassign=0    
      
    DECLARE @productsJson NVARCHAR(MAX) = (                  
    select value as ProductName            
       from fn_split(@products,'#')            
   FOR JSON AUTO                  
  ,INCLUDE_NULL_VALUES                  
    )                 
        
 DECLARE @FollowupDate DATETIME = NULL,@LeadNo BIGINT = 0,@ParentID BIGINT = 0
 DECLARE @hot INT, @warm INT, @cold INT, @isAdmin bit 
                
 IF (@NextStatusDate <> '')                
 BEGIN                
  SET @FollowupDate = @NextStatusDate                
 END                
                
 IF (@NextStatusDate <> '')                
 BEGIN                
  UPDATE UserLeads                
  SET AssignedTo = @AssignedTo                
   ,FollowUpStatus = @FollowUpStatus                
   ,NextStatusDate = convert(NVARCHAR(100), dbo.[fn_getISTtimefromusertime](@UserId, @FollowupDate), 121)                
   --,Products = @Products                
   ,ProductsJson = @productsJson        
   ,AmountPaid = @AmountPaid                
   ,Remarks = @Remarks                
   ,ModifiedBy = @UserId                
   ,FollowupDate = dbo.[fn_getISTtimefromusertime](@UserId, @FollowupDate)                
   ,@LeadNo = LeadNo                
   ,@ParentID = ParentID                
  WHERE ID = @ID                
 END                
 ELSE                
 BEGIN                
  UPDATE UserLeads                
  SET AssignedTo = @AssignedTo                
   ,FollowUpStatus = @FollowUpStatus                
   ,NextStatusDate = @NextStatusDate                
 --,Products = @Products                
   ,ProductsJson = @productsJson        
   ,AmountPaid = @AmountPaid                
   ,Remarks = @Remarks                
   ,ModifiedBy = @UserId                
   ,FollowupDate = @FollowupDate                
   ,@LeadNo = LeadNo                
   ,@ParentID = ParentID                
  WHERE ID = @ID                
 END                
                
 DECLARE @lihid BIGINT                
                
 IF (@NextStatusDate <> '')                
 BEGIN    
  set Context_Info 0x55555    
       
  INSERT INTO LeadInteractionHistory (                
   LeadNo                
   ,FollowUpStatus                
   ,NextStatusDate                
   ,IsReassign                
   --,Products                
   ,ProductsJson         
   ,AmountPaid                
   ,Remarks                
   ,AssignedTo                
   ,ParentID                
   ,CreatedOn                
   ,CreatedBy                
   ,FollowupDate,id_lead                
   )                
  VALUES(                
   @LeadNo                
   ,@FollowUpStatus                
   ,convert(NVARCHAR(100), dbo.[fn_getISTtimefromusertime](@UserId, @FollowupDate), 121)                
   ,@IsReassign                
   --,@Products                
   ,@productsJson        
   ,@AmountPaid                
   ,@Remarks                
   ,@AssignedTo              
   ,@ParentID                
   ,GETDATE()                
   ,@UserId                
   ,dbo.[fn_getISTtimefromusertime](@UserId, @FollowupDate) ,@ID               
   )    
       
   select @lihid = SCOPE_IDENTITY()    
 set Context_Info 0x    
 END                
 ELSE                
 BEGIN      
 set Context_Info 0x55555    
    
  INSERT INTO LeadInteractionHistory (                
   LeadNo                
   ,FollowUpStatus                
   ,NextStatusDate                
   ,IsReassign                
   --,Products                
   ,ProductsJson        
   ,AmountPaid                
   ,Remarks                
   ,AssignedTo                
   ,ParentID                
   ,CreatedOn                
   ,CreatedBy                
   ,FollowupDate,id_lead                
   )                
  VALUES (                
    @LeadNo                
   ,@FollowUpStatus                
   ,@NextStatusDate                
   ,@IsReassign                
   --,@Products                
   ,@productsJson        
   ,@AmountPaid                
   ,@Remarks                
   ,@AssignedTo                
   ,@ParentID                
   ,GETDATE()                
   ,@UserId          
   ,@FollowupDate,@ID                
   )    
       
   select @lihid = SCOPE_IDENTITY()    
   set Context_Info 0x    
    
 END       
     
    execute usp_ExecLeadInteractionTriggerTasks @lihid      
     
    
 print concat('@@RowCount => ', @@RowCount)    

 --IF (@@RowCount > 0)     
 if(isnull(@lihid, 0) > 0)    
 BEGIN                

		SELECT @IsAdmin = IsAdmin,@ParentId = ParentID
	FROM User_Detail(NOLOCK)
	WHERE User_ID = @UserId

		DECLARE @maxScore NUMERIC(18, 2) = isnull((
				SELECT (max(currentscore) * 100) / 99
				FROM lead_score_history(NOLOCK) e
				WHERE parentid = @ParentId
				), 0)

	SELECT @hot = hot,@warm = warm,@cold = cold
	FROM lead_cateogy_thresholds(NOLOCK)
	WHERE parentid = @ParentID

	IF @hot IS NULL
	BEGIN
		SELECT @hot = hot,@warm = warm,@cold = cold
		FROM lead_cateogy_thresholds(NOLOCK)
		WHERE parentid = 0
	END

		SELECT 'Lead Followup Added Successfully' AS Msg,@LeadNo AS LeadNo, lih.ID
			,fs.followupstatus AS Title
			,fs.IsConvert as [IsConvert]
			,lih.remarks AS Discription
			,lih.followupdate AS NextStatusDate
			,lih.CreatedOn
			,lih.AmountPaid
			,ul.id AS LeadId
			,iif(isnull(ltrim(rtrim(ul.mobileno)), '') <> '', CONCAT (
					ul.countrycode
					,' '
					,ul.mobileno
					), '') AS MobileNo
			,iif(isnull(ltrim(rtrim(ul.mobileno2)), '') <> '', CONCAT (
					ul.countrycode2
					,' '
					,ul.mobileno2
					), '') AS MobileNo2
			,iif(isnull(ltrim(rtrim(ul.mobileno1)), '') <> '', CONCAT (
					ul.countrycode1
					,' '
					,ul.mobileno1
					), '') AS MobileNo1
			,ul.PersonName
			,ul.ProfileImgFileName
			,iif(ul.assignedto = @UserId
				OR 1 = @IsAdmin, 1, 0) AS [IsUIActive]
			,lih.assignedto
			,ltrim(rtrim(CONCAT (
						ud.fname
						,' '
						,ud.lname
						))) AS [Owner]
			,'' AS [Status]
			,ud.parentid AS [ParentId]
			,(
				CASE 
					WHEN cast(lih.followupdate AS DATE) = cast(getdate() AS DATE)
						THEN 0
					WHEN cast(lih.followupdate AS DATE) < cast(getdate() AS DATE)
						THEN 1
					WHEN cast(lih.followupdate AS DATE) > cast(getdate() AS DATE)
						THEN 2
					WHEN cast(lih.followupdate AS DATE) IS NULL
						THEN 3
					END
				) AS [OrderSeq]
			,(
				CASE 
					WHEN cast(lih.followupdate AS DATE) = cast(getdate() AS DATE)
						THEN 'duetoday'
					WHEN cast(lih.followupdate AS DATE) < cast(getdate() AS DATE)
						THEN 'overdue'
					WHEN cast(lih.followupdate AS DATE) > cast(getdate() AS DATE)
						THEN 'scheduled'
					WHEN cast(lih.followupdate AS DATE) IS NULL
						THEN 'nofollowup'
					END
				) AS [FollowupDateStatus]
			,(
				CASE 
					WHEN ls.scoreadded > 0
						THEN 'green_up'
					WHEN ls.scoreadded < 0
						THEN 'red_down'
					ELSE ''
					END
				) AS [Profit_Loss]
			,cast(isnull((ls.currentscore / nullif(@maxScore, 0.00)) * 99, 0) AS INT) AS [CurrentScore]
			,(
				CASE 
					WHEN cast(isnull((ls.currentscore / nullif(@maxScore, 0.00)) * 99, 0) AS INT) > @warm
						THEN 'hot'
					WHEN cast(isnull((ls.currentscore / nullif(@maxScore, 0.00)) * 99, 0) AS INT) BETWEEN @cold
							AND @warm
						THEN 'warm'
					ELSE 'cold'
					END
				) AS [ThresholdColor]
		FROM leadinteractionhistory(NOLOCK) lih INNER JOIN followup_status(NOLOCK) fs 
		ON lih.followupstatus = fs.id INNER JOIN userleads(NOLOCK) ul 
		ON lih.leadno = ul.leadno AND ul.parentid = lih.parentid LEFT JOIN lead_score_history_latest(NOLOCK) ls 
		ON ls.leadid = ul.id LEFT JOIN user_detail(NOLOCK) ud 
		ON lih.assignedto = ud.user_id
		Where lih.id=@lihid

  -- SELECT 'Lead Followup Added Successfully' AS Msg,@LeadNo AS LeadNo
                
  DECLARE @Nextprocess BIT = 0                
                
  BEGIN TRY                
   IF (@FollowUpStatus = 5)                
   BEGIN                
    SET @Nextprocess = 1                
   END               
   ELSE IF EXISTS (                
     SELECT 1                
     FROM FollowUp_Status fs(NOLOCK)                
     WHERE fs.IsConvert = 1                
      AND fs.ID = @FollowUpStatus                
      AND fs.ParentId = @ParentId                
     )                
   BEGIN                
    SET @Nextprocess = 1                
   END                
                
   IF (@Nextprocess = 1)                
   BEGIN        DECLARE @CreateDate DATETIME = GETDATE()                
                
    EXEC Usp_Insert_Tbl_ST_SalesActivityMasterNew_Replication  @lihid                
     ,'LeadInteractionHistory'                
     ,@AmountPaid                
     ,@CreateDate                
     ,''                
     ,@ProductsJson                
     ,0                
     ,@UserId                
     ,@ParentID                
     ,@LeadNo                
   END                
  END TRY                
                
  BEGIN CATCH                
   EXEC usp_InsertErrorInfo                
  END CATCH                
      
  IF OBJECT_ID('tempdb..#tblEventDescrb') IS NOT NULL -- Check for table existence                                      
  BEGIN                
   DROP TABLE #tblEventDescrb                
  END                
    /* End Lead Activity */                
 END                
 ELSE                
 BEGIN                
  SELECT 'Lead Followup not Added Successfully' AS Msg, @LeadNo AS LeadNo                
 END                
                
 DECLARE @rowJson NVARCHAR(MAX) = (                
   SELECT *               
   FROM LeadInteractionHistory lih                
   WHERE lih.ID = @lihid                
   FOR JSON AUTO                
    ,INCLUDE_NULL_VALUES                
   )                
                
 IF @rowJson IS NOT NULL                
 BEGIN                
  EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserId                
   ,@Activity_type = 'Inst_flwup'                
   ,@ActionType = 'I'                
   ,@RowJson = @rowJson                
   ,@Table_name = 'leadinteractionhistory'                
 END                
END 



GO

