/* ============================================================
   Procedure: [dbo].[usp_AddLeadFollowup_Replication_Appmodkit19]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_AddLeadFollowup_Replication_Appmodkit19]    
(            
 @ID BIGINT            
 ,@AssignedTo BIGINT            
 ,@FollowUpStatus BIGINT            
 ,@NextStatusDate VARCHAR(50)            
 ,@Products VARCHAR(1000) = ''            
 ,@AmountPaid NUMERIC(18, 2)            
 ,@Remarks nVARCHAR(2000)            
 ,@UserId BIGINT            
 ,@IsReassign BIT            
 --,@EpUniqueIdentity nvarchar(255) = ''                        
 )            
AS            
BEGIN            
 DECLARE @FollowupDate DATETIME = NULL            
  ,@LeadNo BIGINT = 0            
  ,@ParentID BIGINT = 0            
               
    select top 1 @ParentID = ParentID from userleads with(nolock) where Id = @ID       
        
 Declare @QueryProducts nvarchar(max) = ''    
    DECLARE @ProductsJson NVARCHAR(4000) = ''    
    
    
   begin try    
            
  if(isnull(@Products,'') != '')    
   begin    
       
           IF EXISTS (
                    SELECT 1
                    FROM fn_split(ISNULL(@Products,''), '#')
                     WHERE [value] LIKE '%[A-Za-z]%'
                    )
         BEGIN
     --PRINT 'Contains Alphabet'
     set @QueryProducts =  CONCAT('select @ProductsJsonTemp = (      
         select t.Name as ProductName from (select [value] from fn_split('''+ isnull(@Products,'''') +''',''#'')) as tbl    
        join     
      tbl_ProductMaster_', cast(@ParentID as nvarchar(50)) ,' as t with(nolock)    
        on tbl.[value] = t.Name    
            
        FOR JSON AUTO              
          ,INCLUDE_NULL_VALUES      
     )','')    
      
      exec sp_executesql @QueryProducts, N'@ProductsJsonTemp nvarchar(4000) out ', @ProductsJson out      


          END
        ELSE 
           BEGIN
               --PRINT 'No Alphabet Found'

          set @QueryProducts =  CONCAT('select @ProductsJsonTemp = (      
              select t.Name as ProductName from (select [value] from fn_split('''+ isnull(@Products,'''') +''',''#'')) as tbl    
                 join     
             tbl_ProductMaster_', cast(@ParentID as nvarchar(50)) ,' as t with(nolock)    
                on tbl.[value] = t.ProductID    
                 FOR JSON AUTO              
                   ,INCLUDE_NULL_VALUES      
              )','')
     
      
            exec sp_executesql @QueryProducts, N'@ProductsJsonTemp nvarchar(4000) out ', @ProductsJson out      

           END




     


   end     
    end try    
    begin catch    
       exec usp_InsertErrorInfo    
    end catch    
           
    
    
 IF (@NextStatusDate <> '')            
 BEGIN            
  SET @FollowupDate = @NextStatusDate            
 END            
            
 IF (@NextStatusDate <> '')            
 BEGIN            
  UPDATE UserLeads            
  SET AssignedTo = @AssignedTo            
   ,FollowUpStatus = @FollowUpStatus            
   ,NextStatusDate = convert(NVARCHAR(100), dbo.[fn_getISTtimefromusertime](@UserId, @FollowupDate), 121)            
   ,ProductsJson = @ProductsJson            
   ,AmountPaid = @AmountPaid            
   ,Remarks = @Remarks            
   ,ModifiedBy = @UserId            
   ,FollowupDate = dbo.[fn_getISTtimefromusertime](@UserId, @FollowupDate)            
   ,@LeadNo = LeadNo            
   ,@ParentID = ParentID            
  WHERE ID = @ID            
 END            
 ELSE            
 BEGIN            
  UPDATE UserLeads            
  SET AssignedTo = @AssignedTo            
   ,FollowUpStatus = @FollowUpStatus            
   ,NextStatusDate = @NextStatusDate            
   ,ProductsJson = @ProductsJson            
   ,AmountPaid = @AmountPaid            
   ,Remarks = @Remarks            
   ,ModifiedBy = @UserId            
   ,FollowupDate = @FollowupDate            
   ,@LeadNo = LeadNo            
   ,@ParentID = ParentID            
  WHERE ID = @ID            
 END            
            
 DECLARE @lihid BIGINT            
            
 IF (@NextStatusDate <> '')            
 BEGIN            
  INSERT INTO LeadInteractionHistory (            
   LeadNo            
   ,FollowUpStatus            
   ,NextStatusDate            
   ,IsReassign            
   ,ProductsJson            
   ,AmountPaid            
   ,Remarks            
   ,AssignedTo            
   ,ParentID            
   ,CreatedOn            
   ,CreatedBy            
   ,FollowupDate,id_lead            
   )            
  VALUES (            
   @LeadNo            
   ,@FollowUpStatus            
   ,convert(NVARCHAR(100), dbo.[fn_getISTtimefromusertime](@UserId, @FollowupDate), 121)            
   ,@IsReassign            
   ,@ProductsJson            
   ,@AmountPaid            
   ,@Remarks            
   ,@AssignedTo            
   ,@ParentID            
   ,GETDATE()            
   ,@UserId            
   ,dbo.[fn_getISTtimefromusertime](@UserId, @FollowupDate),@ID            
   )            
 END            
 ELSE            
 BEGIN            
  INSERT INTO LeadInteractionHistory (            
   LeadNo            
   ,FollowUpStatus   
   ,NextStatusDate            
   ,IsReassign            
   ,ProductsJson            
   ,AmountPaid            
   ,Remarks            
   ,AssignedTo            
   ,ParentID            
   ,CreatedOn            
   ,CreatedBy            
   ,FollowupDate,id_lead            
   )            
VALUES (            
   @LeadNo            
   ,@FollowUpStatus            
   ,@NextStatusDate            
   ,@IsReassign            
   ,@ProductsJson            
   ,@AmountPaid            
   ,@Remarks            
   ,@AssignedTo            
   ,@ParentID            
   ,GETDATE()            
   ,@UserId            
   ,@FollowupDate,@ID            
   )            
 END            
            
 SELECT @lihid = SCOPE_IDENTITY()            
            
 --if(@lihid > 0)                        
 --begin                        
 --if(isnull(@EpUniqueIdentity, '') <> '')                        
 --begin                        
 -- declare @GatewayName nvarchar(255), @EntityName nvarchar(255)                        
 -- select @GatewayName = ProviderName, @EntityName = EntityName from tbl_voip_endpointInteraction(nolock)                         
 --  where id = cast(@EpUniqueIdentity as bigint)                        
 -- insert into tbl_c2c_EventActivityMapping( gateway_name, ep_interaction_id, event_history_id, EntityName )                        
 --  values( @GatewayName, cast( @EpUniqueIdentity as bigint), @lihid, @EntityName )                        
 --end                        
 --end                        
 --if(isnull(@lihid,0) > 0)                                  
 IF (@@RowCount > 0)            
 BEGIN            
  SELECT 'Lead Followup Added Successfully' AS Msg            
   ,@LeadNo AS LeadNo            
            
  DECLARE @Nextprocess BIT = 0            
            
  BEGIN TRY            
   IF (@FollowUpStatus = 5)            
   BEGIN            
    SET @Nextprocess = 1            
   END           
   ELSE IF EXISTS (            
     SELECT 1            
     FROM FollowUp_Status fs(NOLOCK)            
     WHERE fs.IsConvert = 1            
      AND fs.ID = @FollowUpStatus            
      AND fs.ParentId = @ParentId            
     )            
   BEGIN            
    SET @Nextprocess = 1            
   END            
            
   IF (@Nextprocess = 1)            
   BEGIN        DECLARE @CreateDate DATETIME = GETDATE()            
            
    EXEC Usp_Insert_Tbl_ST_SalesActivityMasterNew_Replication_Appmodkit19 @lihid            
     ,'LeadInteractionHistory'            
     ,@AmountPaid            
     ,@CreateDate            
     ,''            
     ,@Products            
     ,0            
     ,@UserId            
     ,@ParentID            
     ,@LeadNo            
   END            
  END TRY            
            
  BEGIN CATCH            
   EXEC usp_InsertErrorInfo            
  END CATCH            
            
  /* Start Lead Activity */            
  BEGIN TRY            
   DECLARE @UserID_LDACTV BIGINT = @UserId            
   DECLARE @ParentID_LDACTV BIGINT = @ParentID            
   DECLARE @LeadID_LDACTV BIGINT = @ID            
   DECLARE @FollowupStatusID_LDACTV INT = @FollowUpStatus            
   DECLARE @AssingedTo_LDACTV BIGINT = isnull(@AssignedTo, 0)            
            
   CREATE TABLE #tblEventDescrb (EVNT_Description NVARCHAR(max))            
            
   IF (isnull(@LeadID_LDACTV, 0) > 0)            
   BEGIN            
    INSERT INTO #tblEventDescrb            
    EXEC Usp_EventTemplate_DynamicVarReplacement 'New Interaction added'            
     ,@UserID_LDACTV            
     ,''            
     ,''            
     ,@LeadID_LDACTV            
     ,''            
     ,NULL            
     ,0            
     ,0            
     ,''            
     ,''            
     ,0            
     ,''            
     ,0            
     ,NULL            
     ,NULL            
     ,NULL            
     ,NULL            
     ,@FollowupStatusID_LDACTV            
     ,@AssingedTo_LDACTV            
     ,NULL            
     ,NULL            
 ,NULL            
     ,NULL            
     ,NULL            
     ,NULL            
     ,NULL            
     ,NULL            
     ,NULL            
     ,NULL            
     ,NULL            
     ,0            
     ,0            
     ,0            
     ,NULL            
     ,NULL            
     ,NULL            
     ,0            
     ,NULL            
     ,NULL            
     ,NULL            
     ,0            
     ,NULL            
     ,NULL            
            
    DECLARE @evntMessage NVARCHAR(max) = ''            
            
    SELECT @evntMessage = isnull(EVNT_Description, '')            
    FROM #tblEventDescrb            
            
    IF (@evntMessage <> '')            
    BEGIN            
     EXEC UspSaveLeadActivity_withid @LeadID_LDACTV            
      ,@UserID_LDACTV            
      ,@ParentID_LDACTV            
      ,@evntMessage            
      ,'New Interaction added'            
      ,'LeadInteractionHistory'            
      ,@lihid            
    END            
   END            
  END TRY            
            
  BEGIN CATCH            
   EXEC usp_InsertErrorInfo            
  END CATCH            
            
  IF OBJECT_ID('tempdb..#tblEventDescrb') IS NOT NULL -- Check for table existence                                  
  BEGIN            
   DROP TABLE #tblEventDescrb            
  END            
    /* End Lead Activity */            
 END            
 ELSE            
 BEGIN            
  SELECT 'Lead Followup not Added Successfully' AS Msg            
   ,@LeadNo AS LeadNo            
 END            
            
 DECLARE @rowJson NVARCHAR(MAX) = (            
   SELECT *           
   FROM LeadInteractionHistory lih            
   WHERE lih.ID = @lihid            
   FOR JSON AUTO            
    ,INCLUDE_NULL_VALUES            
   )            
            
 IF @rowJson IS NOT NULL            
 BEGIN            
  EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserId            
   ,@Activity_type = 'Inst_flwup'            
   ,@ActionType = 'I'            
   ,@RowJson = @rowJson            
   ,@Table_name = 'leadinteractionhistory'            
 END            
END 


GO

/* ============================================================
   Procedure: [dbo].[usp_AddLeadFromJson]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC usp_AddLeadFromJson  
(  
 @BatchId bigint,
 @LeadData nvarchar(max)  
)  
AS  
Begin  
  
 drop table if exists #insertedRec  
 drop table if exists #outputLeadInteraction  
   
 declare @csvLeadId nvarchar(max) = '', @CsvID nvarchar(max) = ''      
 Create table #insertedRec( iLeadId bigint, iLeadNo int, iMobileNo nvarchar(25) );  
 create table #outputLeadInteraction(id bigint)        
   
 SET Context_Info 0x55555   
 insert into UserLeads(PersonName, MobileNo, CountryCode, SourceName, ParentID, AssignedTo, CreatedBy, LeadNo, CreatedOn, enquirysource, lastfollowupcreatedby, lastfollowupcreatedon)        
     output inserted.Id, inserted.LeadNo, inserted.MobileNo into #insertedRec                
    select PersonName, MobileNo, CountryCode, SourceName, ParentID, AssignedTo, CreatedBy, LeadNo, CreatedOn, enquirysource, lastfollowupcreatedby, lastfollowupcreatedon             
     From openjson(@LeadData)   
  With (  
  PersonName    nvarchar(200) '$.PersonName',  
  MobileNo    varchar(100) '$.MobileNo',  
  CountryCode    varchar(50)  '$.CountryCode',  
  SourceName    bigint   '$.SourceName',  
  ParentID    bigint   '$.ParentID',  
  AssignedTo    bigint   '$.AssignedTo',  
  CreatedBy    bigint   '$.CreatedBy',  
  LeadNo     bigint   '$.LeadNo',  
  CreatedOn    datetime  '$.CreatedOn',  
  enquirysource   int    '$.enquirysource',  
  LastFollowupCreatedBy bigint   '$.LastFollowupCreatedBy',  
  LastFollowupCreatedOn datetime  '$.LastFollowupCreatedOn'  
  )  
      
    select @csvLeadId = STRING_AGG(ire.iLeadId, ',') from #insertedRec  ire      
      
    Exec usp_ExecLeadTriggerTasks @csvLeadId     
  
      
     insert into leadinteractionhistory(LeadNo,FollowUpStatus,NextStatusDate,Products,AmountPaid,Remarks,AssignedTo,ParentID,CreatedOn,CreatedBy,followupdate,id_lead)      
      output inserted.ID into #outputLeadInteraction      
     select LeadNo,FollowUpStatus,NextStatusDate,Products,AmountPaid,Remarks,AssignedTo,ParentID,CreatedOn,CreatedBy,followupdate,id      
      from userleads(nolock) ul inner join       
       dbo.fn_Split(@csvLeadId,  ',') cui on ul.ID = cui.[value]      
       
     select @CsvID = STRING_AGG(CONVERT(NVARCHAR(max), ID),',') From #outputLeadInteraction   
  
  exec usp_ExecLeadInteractionTriggerTasks @CsvID   
  
  SET Context_Info 0x  
  
  insert into tbl_LeadInsertedRec(BatchId, iLeadId, iLeadNo, iMobileNo)
  Select @BatchId, iLeadId, iLeadNo, iMobileNo
  from #insertedRec  
  
End  



GO

/* ============================================================
   Procedure: [dbo].[usp_AddLeadFromJson_mod]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[usp_AddLeadFromJson_mod]          
(          
 @BatchId bigint,        
 @LeadData nvarchar(max)          
)          
AS          
Begin          
          
 --declare   @BatchId bigint,        
-- @LeadData nvarchar(max)='[{"PersonName":"919821592374","MobileNo":"9821592374","CountryCode":"+91","SourceName":482125,"ParentID":32222,"AssignedTo":32222,"CreatedBy":32222,"LeadNo":180464,"CreatedOn":"2025-06-09T18:23:02.493","enquirysource":30,"LastFollowupCreatedBy":32222,"LastFollowupCreatedOn":"2025-06-09T18:23:02.493"},{"PersonName":"919833152589","MobileNo":"9833152589","CountryCode":"+91","SourceName":482125,"ParentID":32222,"AssignedTo":32222,"CreatedBy":32222,"LeadNo":180465,"CreatedOn":"2025-06-09T18:23:02.493","enquirysource":30,"LastFollowupCreatedBy":32222,"LastFollowupCreatedOn":"2025-06-09T18:23:02.493"},{"PersonName":"919833153433","MobileNo":"9833153433","CountryCode":"+91","SourceName":482125,"ParentID":32222,"AssignedTo":32222,"CreatedBy":32222,"LeadNo":180466,"CreatedOn":"2025-06-09T18:23:02.493","enquirysource":30,"LastFollowupCreatedBy":32222,"LastFollowupCreatedOn":"2025-06-09T18:23:02.493"},{"PersonName":"919833153999","MobileNo":"9833153999","CountryCode":"+91","SourceName":482125,"ParentID":32222,"AssignedTo":32222,"CreatedBy":32222,"LeadNo":180467,"CreatedOn":"2025-06-09T18:23:02.493","enquirysource":30,"LastFollowupCreatedBy":32222,"LastFollowupCreatedOn":"2025-06-09T18:23:02.493"},{"PersonName":"919833157015","MobileNo":"9833157015","CountryCode":"+91","SourceName":482125,"ParentID":32222,"AssignedTo":32222,"CreatedBy":32222,"LeadNo":180468,"CreatedOn":"2025-06-09T18:23:02.493","enquirysource":30,"LastFollowupCreatedBy":32222,"LastFollowupCreatedOn":"2025-06-09T18:23:02.493"},{"PersonName":"919833157481","MobileNo":"9833157481","CountryCode":"+91","SourceName":482125,"ParentID":32222,"AssignedTo":32222,"CreatedBy":32222,"LeadNo":180469,"CreatedOn":"2025-06-09T18:23:02.493","enquirysource":30,"LastFollowupCreatedBy":32222,"LastFollowupCreatedOn":"2025-06-09T18:23:02.493"},{"PersonName":"919833158426","MobileNo":"9833158426","CountryCode":"+91","SourceName":482125,"ParentID":32222,"AssignedTo":32222,"CreatedBy":32222,"LeadNo":180470,"CreatedOn":"2025-06-09T18:23:02.493","enquirysource":30,"LastFollowupCreatedBy":32222,"LastFollowupCreatedOn":"2025-06-09T18:23:02.493"},{"PersonName":"919833162911","MobileNo":"9833162911","CountryCode":"+91","SourceName":482125,"ParentID":32222,"AssignedTo":32222,"CreatedBy":32222,"LeadNo":180471,"CreatedOn":"2025-06-09T18:23:02.493","enquirysource":30,"LastFollowupCreatedBy":32222,"LastFollowupCreatedOn":"2025-06-09T18:23:02.493"},{"PersonName":"919833166411","MobileNo":"9833162911","CountryCode":"+91","SourceName":482125,"ParentID":32222,"AssignedTo":32222,"CreatedBy":32222,"LeadNo":180472,"CreatedOn":"2025-06-09T18:23:02.493","enquirysource":30,"LastFollowupCreatedBy":32222,"LastFollowupCreatedOn":"2025-06-09T18:23:02.493"}]'    
    
 drop table if exists #insertedRec          
 drop table if exists #outputLeadInteraction          
           
 declare @csvLeadId nvarchar(max) = '', @CsvID nvarchar(max) = '' ,@parentid bigint ,@leadno bigint            
 Create table #insertedRec( iLeadId bigint, iLeadNo int, iMobileNo nvarchar(25) );          
 create table #outputLeadInteraction(id bigint)        
       
      
drop table if exists  #userleads_new      
drop table if exists  #tempMobNo      
select *    
into #userleads_new                   
From (    
 select ROW_NUMBER() over (partition by ParentID,MobileNo  order by MobileNo) rowno ,PersonName, MobileNo, CountryCode, SourceName, ParentID, AssignedTo, CreatedBy, LeadNo, CreatedOn, enquirysource, lastfollowupcreatedby, lastfollowupcreatedon, cast(0 as 
  
bigint) as entityid        
     From openjson(@LeadData)           
  With (          
  PersonName    nvarchar(200) '$.PersonName',          
  MobileNo    varchar(100) '$.MobileNo',          
  CountryCode    varchar(50)  '$.CountryCode',          
  SourceName    bigint   '$.SourceName',          
  ParentID    bigint   '$.ParentID',          
  AssignedTo    bigint   '$.AssignedTo',          
  CreatedBy    bigint   '$.CreatedBy',          
  LeadNo     bigint   '$.LeadNo',          
  CreatedOn    datetime  '$.CreatedOn',          
  enquirysource   int    '$.enquirysource',          
  LastFollowupCreatedBy bigint   '$.LastFollowupCreatedBy',          
  LastFollowupCreatedOn datetime  '$.LastFollowupCreatedOn'          
  )       
  ) T    
  Where T.rowno=1    
    
  select top 1 @parentid=parentid from #userleads_new      
  update u set entityid=ulme_id,leadno=l.leadno from #userleads_new u join userleads_mobile_email l on u.mobileno =l.mobile and u.mobileno <>'0' and l.Parentid=u.parentid      
      
 --SET TRANSACTION ISOLATION LEVEL SERIALIZABLE;          
 begin transaction      
  
 Select *  
 into #tempMobNo  
 From (  
 Select MobileNo from UserLeads(nolock) Where ParentID=@parentid and MobileNo IS NOT NULL  AND MobileNo <> '' AND MobileNo <> '0'  
 union  
 Select MobileNo1 from UserLeads(nolock) Where ParentID=@parentid and MobileNo1 IS NOT NULL  AND MobileNo1 <> '' AND MobileNo1 <> '0'  
 union  
 Select MobileNo2 from UserLeads(nolock) Where ParentID=@parentid and MobileNo2 IS NOT NULL  AND MobileNo2 <> '' AND MobileNo2 <> '0'  
 ) T  
  
  
 select @leadno=isnull(max(leadno),0) from userleads with (UPDLOCK,HOLDLOCK) where parentid=@parentid      
 SET Context_Info 0x55555          
 insert into UserLeads(PersonName, MobileNo, CountryCode, SourceName, ParentID, AssignedTo, CreatedBy, LeadNo, CreatedOn, enquirysource, lastfollowupcreatedby, lastfollowupcreatedon)  
     output inserted.Id, inserted.LeadNo, inserted.MobileNo into #insertedRec                        
    select PersonName, MobileNo, CountryCode, SourceName, ParentID, AssignedTo, CreatedBy, (@leadno + ROW_NUMBER() over(order by rowno)), CreatedOn, enquirysource, lastfollowupcreatedby, lastfollowupcreatedon        
 -- select *   
    from    #userleads_new u  
 where isnull(u.entityid,0)=0 and u.MobileNo not in (Select t.MobileNo From #tempMobNo as t)    
         
 select @csvLeadId = STRING_AGG(cast(ire.iLeadId as nvarchar(max)), ',') from #insertedRec  ire       
       
       
 commit             
    Exec usp_ExecLeadTriggerTasks @csvLeadId             
          
         
     insert into leadinteractionhistory(LeadNo,FollowUpStatus,NextStatusDate,Products,AmountPaid,Remarks,AssignedTo,ParentID,CreatedOn,CreatedBy,followupdate,id_lead)              
      output inserted.ID into #outputLeadInteraction              
     select LeadNo,FollowUpStatus,NextStatusDate,Products,AmountPaid,Remarks,AssignedTo,ParentID,CreatedOn,CreatedBy,followupdate,id              
      from userleads(nolock) ul inner join               
       dbo.fn_Split(@csvLeadId,  ',') cui on ul.ID = cui.[value]              
               
     select @CsvID = STRING_AGG(CONVERT(NVARCHAR(max), ID),',') From #outputLeadInteraction           
          
  exec usp_ExecLeadInteractionTriggerTasks @CsvID           
          
  SET Context_Info 0x          
          
  insert into tbl_LeadInsertedRec(BatchId, iLeadId, iLeadNo, iMobileNo)        
  Select @BatchId, iLeadId, iLeadNo, iMobileNo        
  from #insertedRec       
  union      
  select @BatchId,entityid,leadno,mobileno from #userleads_new  ire where isnull(entityid,0)<>0      
      
          
End     



