/* ============================================================
   Procedure: [dbo].[Usp_AddMassFollowup_bulk]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE  PROCEDURE [dbo].[Usp_AddMassFollowup_bulk]            
(            
    @massfollowup as massfollowup readonly    
)            
AS            
BEGIN     
    
drop table if exists #massfollowup    
select m.*,ul.parentid,ul.leadno,ul.PersonName into #massfollowup from @massfollowup m join userleads(nolock) ul on ul.id=m.entityid    
declare @parentid bigint,@actiontype varchar(20)    
select top 1 @parentid=parentid,@actiontype=actiontype from #massfollowup    
    
begin try     
    
 SET Context_Info 0x55555    
 UPDATE UL            
 SET    AssignedTo = tb2.AssignedTo,            
        FollowUpStatus = tb2.FollowUpStatus,            
        NextStatusDate =  convert(nvarchar(100),dbo.[fn_getISTtimefromusertime](tb2.ParentID,tb2.FollowupDate),121),     
  Products = tb2.Products,            
        AmountPaid = tb2.AmountPaid,            
        Remarks = tb2.Remarks,            
        ModifiedBy =tb2.ModifiedBy ,    
  modifiedon= tb2.modifiedon,    
        FollowupDate = dbo.[fn_getISTtimefromusertime](tb2.ParentID,tb2.FollowupDate),    
  LastFollowupCreatedBy=tb2.parentid,    
  LastFollowupCreatedOn=getdate(),    
  ProductsJson=tb2.Productsjson    
from UserLeads UL    
inner join #massfollowup  tb2 on UL.ID = tb2.entityID where isnull(tb2.assignedto,0)<>0    
print 'lead(s) updated'
 SET Context_Info 0x    
 END TRY                
 BEGIN CATCH      
  SET Context_Info 0x    
   EXEC usp_InsertErrorInfo      
 END CATCH       
     
  DROP TABLE  IF EXISTS #output     
  CREATE TABLE #output (      
    lihid BIGINT      
    ,leadno BIGINT      
    ,parentid BIGINT      
    ,fs INT      
    )      
  SET Context_Info 0x55555    
  INSERT INTO LeadInteractionHistory                
    (                
      LeadNo,                
      FollowUpStatus,                
      NextStatusDate,                
      Products,                
      AmountPaid,                
      Remarks,                
      AssignedTo,                
      ParentID,                
      CreatedOn,                
      CreatedBy,              
      FollowupDate,    
   IsReAssign,    
   ProductsJson,id_lead    
    )               
  OUTPUT inserted.id AS lihid      
   ,inserted.LeadNo AS leadno      
   ,inserted.parentid AS parentid      
   ,inserted.FollowUpStatus AS fs      
  INTO #output      
    
   SELECT LeadNo,                
         FollowUpStatus,                
         NextStatusDate,                
         Products,                
         AmountPaid,                
         Remarks,                
         AssignedTo,                
         @ParentID,                
         GETDATE(),                
         ModifiedBy,              
         FollowupDate,    
   IsReAssign,    
   Productsjson,u1.entityid    
  FROM   #massfollowup u1   where isnull(u1.assignedto,0)<>0             
print 'follow up added'
       
   SET Context_Info 0x    
    
  BEGIN TRY      
  declare @username nvarchar(100)=(select user_login from User_Detail(nolock) where user_id=@parentid)    
   DECLARE @tbl1 AS LeadActivitywithid_Tbltype      
      
   INSERT INTO @tbl1 (      
    leadid      
    ,userid      
    ,parentid      
    ,eventdescription      
    ,eventname      
    ,reftable      
    ,refid      
    )      
   SELECT entityid      
    ,l.ModifiedBy      
    ,l.ParentID      
 ,case when @actiontype='addfollowup' then    
 @username+ ' added a followup with status '+cast(f.FollowupStatus as varchar)+'. Lead was assigned to '+u.User_Login    
 else 'Lead with name '+isnull(l.personname,'Unknown')+' is assigned to '+u.user_login+' by '+@username end    
    ,case when @actiontype='addfollowup' then 'New Interaction added'  else 'Lead Assigned to' end    
    ,'leadInteractionHistory'      
    ,o.lihid      
   FROM #massfollowup l      
   JOIN FollowUp_Status f ON f.ID = l.FollowUpStatus    
   join user_detail(nolock) u on u.user_id=l.AssignedTo    
   join #output o on o.leadno=l.LeadNo where isnull(l.assignedto,0) <>0   
    
  EXEC UspSaveentityActivity_withMultipleValue_withid_bulk @tbl1      
   DROP TABLE  IF EXISTS #leadid      
  drop table if exists #massfollowup     
   DROP TABLE   IF EXISTS #output      
    /* ReAssign End */      
    END TRY      
   BEGIN CATCH      
   SET Context_Info 0x    
    EXEC usp_InsertErrorInfo      
 END CATCH      
    
 SELECT 'Record Updated'            
     
  DECLARE @rowJson NVARCHAR(MAX) = (      
    SELECT ul.*      
    FROM UserLeads ul  (nolock)    
 join @massfollowup m on m.entityid=ul.id where isnull(m.assignedto,0)<>0     
    FOR JSON AUTO      
     ,INCLUDE_NULL_VALUES      
    )      
      
 IF @rowJson IS NOT NULL      
  BEGIN      
   EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @parentid      
    ,@Activity_type = 'Updt_msflwup_lead'      
    ,@ActionType = 'U'      
    ,@RowJson = @rowJson      
    ,@Table_name = 'UserLeads'      
  END     
      
    
END 


GO

/* ============================================================
   Procedure: [dbo].[Usp_AddMassFollowup_Replication]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

 ------------------------------------------------------------------------------------------------      
 CREATE  PROCEDURE [dbo].[Usp_AddMassFollowup_Replication]                    
(                    
    @IDS                VARCHAR(Max),                    
    @AssignedTo         BIGINT,                    
    @FollowUpStatus     INT,                    
    @NextStatusDate     VARCHAR(50),                    
    @Products           VARCHAR(1000),                    
    @AmountPaid         NUMERIC(18, 2),                    
    @Remarks            VARCHAR(1000),                    
    @ModifiedBy         BIGINT,            
 @IsReAssign         bit = 0,            
 @BatchID BIGINT = 0   ,        
 @StartDateTime VARCHAR(50)=''         
)                    
AS                    
BEGIN                   
  drop table if exists #TableData3  
  drop table if exists #TableData4  
  drop table if exists  #leadid              
 BEGIN TRY                  
            
      DECLARE @productsJson NVARCHAR(MAX) = (                    
    select value as ProductName              
       from fn_split(@products,'#')              
   FOR JSON AUTO                    
  ,INCLUDE_NULL_VALUES                    
    )          
          
          
          
CREATE TABLE #TableData3             
          (                                
              ID BIGINT            
          )            
CREATE TABLE #TableData4             
          (                                
              ID BIGINT            
          )            
              
if @BatchID IS NOT NULL AND @BatchID <> 0            
BEGIN            
 select @IDS= STRING_AGG(cast(Entityid as nvarchar(max)),',') from Tbl_MassOperationDetails where SummaryId=@BatchID             
 --Update  Tbl_MassOperationSummary set BatchStartTime= GetDate(), ScheduleDateTime= @StartDateTime  where BatchID=@BatchID       
 UPDATE Tbl_MassOperationSummary      
        SET BatchStartTime = GETDATE(),      
            ScheduleDateTime = CASE       
                                 WHEN ScheduleDateTime IS NULL OR ScheduleDateTime = '' OR ScheduleDateTime = '1900-01-01 00:00:00.000'      
                                 THEN @StartDateTime      
                                 ELSE ScheduleDateTime      
                               END      
        WHERE BatchID = @BatchID;      
      
END            
INSERT INTO #TableData4 (ID)                       
SELECT fs.[value]                                
                FROM   dbo.fn_Split(@IDS, ',') fs            
                  
declare @FollowupDate   Datetime = null                    
  if(@NextStatusDate <> '' and @NextStatusDate is not null)                      
   Begin             
   begin try                     
     set @FollowupDate=convert(datetime,@NextStatusDate)            
   end try            
   begin catch            
  if(@FollowupDate is null)            
   begin            
   insert into followupDateError (IDs, nextstatusdate, parentid) values (@IDS, @NextStatusDate, null)            
   end                    
   end catch             
   End                      
     
  declare @fm_add int=(select count(1) from #TableData4),@fm_id bigint=0   
  
while @fm_add>0  
begin  
  
insert into #TableData3(id)  
select top 100 id from #tabledata4 where id>@fm_id order by ID  
                 
 if(@FollowupDate is not null)                      
   Begin                      
          SET Context_Info 0x55555            
 UPDATE UL                    
 SET    AssignedTo = @AssignedTo,                    
        FollowUpStatus = @FollowUpStatus,                    
        NextStatusDate =  convert(nvarchar(100),dbo.[fn_getISTtimefromusertime](ParentID,@FollowupDate),121),                    
        --Products = @Products,                    
        ProductsJson = @productsJson,          
  AmountPaid = @AmountPaid,                    
        Remarks = @Remarks,                    
        ModifiedBy = @ModifiedBy ,                  
        FollowupDate = dbo.[fn_getISTtimefromusertime](ParentID,@FollowupDate)                 
from UserLeads UL            
inner join   
#TableData3  tb2 on UL.ID = tb2.ID             
 SET Context_Info 0x            
 --WHERE  ID IN (SELECT fs.[value]                    
 --              FROM   dbo.fn_Split(@IDS, ',') fs)                    
                     
    end              
 else              
    Begin              
  SET Context_Info 0x55555            
       UPDATE UL                    
 SET    AssignedTo = @AssignedTo,                    
        FollowUpStatus = @FollowUpStatus,                    
        NextStatusDate = @NextStatusDate ,                    
       --Products = @Products,                    
        productsJson = @productsJson,          
  AmountPaid = @AmountPaid,                    
        Remarks = @Remarks,                    
        ModifiedBy = @ModifiedBy ,                  
        FollowupDate =  @FollowupDate                  
from UserLeads UL            
inner join #TableData3  tb2 on UL.ID = tb2.ID             
 SET Context_Info 0x            
 --WHERE  ID IN (SELECT fs.[value]                    
 --              FROM   dbo.fn_Split(@IDS, ',') fs)                    
                  
                  
    end               
 select @fm_id=max(id) from #TableData3  
 set @fm_add=@fm_add-100  
 truncate table #tabledata3  
 end  
               
            
 Declare @ParentID bigint;            
            
 Select @ParentID = UD.ParentID from User_Detail UD(nolock) where UD.User_ID = @ModifiedBy            
            
  -- declare @FollowupDate   Datetime = null                  
  declare @conversion varchar(50)=null            
  if(@NextStatusDate <> '' and @NextStatusDate is not null)                    
   Begin                    
    begin try            
    set @FollowupDate=convert(datetime,@NextStatusDate)            
    select @FollowupDate = dbo.[fn_getISTtimefromusertime](@ParentID,@FollowupDate)            
    select @NextStatusDate = convert(nvarchar(100),@FollowupDate,121)               
    end try            
    begin catch            
    set @conversion= 'Invalid Date'            
    end catch             
   End                   
                   
                         
  DROP TABLE  IF EXISTS #output             
  CREATE TABLE #output (              
    lihid BIGINT              
    ,leadno BIGINT              
    ,parentid BIGINT              
    ,fs INT              
    )              
  
select @fm_add=count(1),@fm_id=0 from #TableData4  
    
  while @fm_add>0  
  begin  
  
  insert into #tabledata3(id)  
  select top 100 id from #TableData4 where id>@fm_id order by ID  
  
  SET Context_Info 0x55555            
  INSERT INTO LeadInteractionHistory                        
    (                        
      LeadNo,                        
      FollowUpStatus,                        
      NextStatusDate,                        
      --Products,                        
      ProductsJson,          
   AmountPaid,                        
      Remarks,                        
      AssignedTo,                        
      ParentID,                        
      CreatedOn,                        
      CreatedBy,                      
      FollowupDate,            
   IsReAssign,Id_Lead            
    )                       
  OUTPUT inserted.id AS lihid              
   ,inserted.LeadNo AS leadno              
   ,inserted.parentid AS parentid              
   ,inserted.FollowUpStatus AS fs              
  INTO #output              
            
   SELECT LeadNo,                        
         @FollowUpStatus,                        
         @NextStatusDate,                        
         --@Products,          
   @productsJson,          
         @AmountPaid,                        
         @Remarks,                        
         @AssignedTo,                        
         @ParentID,                        
         GETDATE(),                        
         @ModifiedBy,                      
         @FollowupDate,            
   @IsReAssign ,u1.id           
  FROM   UserLeads u1                        
  inner join #TableData3  tb2 on u1.ID = tb2.ID             
   SET Context_Info 0x            
            
  BEGIN TRY              
   DECLARE @username NVARCHAR(100)              
    ,@assignedlogin NVARCHAR(100)              
    ,@fs NVARCHAR(50)              
              
   SELECT @username = user_login              
   FROM user_detail(NOLOCK)              
   WHERE user_id = @ModifiedBy              
              
   SELECT @Assignedlogin = user_login              
   FROM user_detail(NOLOCK)              
   WHERE user_id = @AssignedTo              
              
   SELECT id AS leadid              
    ,personname              
    ,u.LeadNo              
    ,lihid              
    ,fs              
   INTO #leadid              
   FROM userleads(NOLOCK) u              
   JOIN #output t ON t.LeadNo = u.leadno              
    AND u.ParentID = t.ParentID              
              
   DECLARE @tbl1 AS LeadActivitywithid_Tbltype              
              
   INSERT INTO @tbl1 (         
    leadid              
    ,userid              
    ,parentid              
    ,eventdescription              
    ,eventname              
    ,reftable              
    ,refid              
    )              
   SELECT leadid              
    ,@ModifiedBy              
    ,@ParentID              
 ,@username+ ' added a followup with status '+cast(FollowupStatus as varchar)+'. Lead was assigned to '+@Assignedlogin            
    ,'New Interaction added'       
    ,'leadInteractionHistory'              
    ,lihid              
   FROM #leadid l              
   JOIN FollowUp_Status f ON f.ID = l.fs              
   --EXEC [UspSaveLeadActivity_withMultipleValue_withid] @tbl1              
  EXEC UspSaveentityActivity_withMultipleValue_withid_bulk @tbl1    
    
  
  
  
    /* ReAssign End */              
    END TRY              
   BEGIN CATCH              
   SET Context_Info 0x            
    EXEC usp_InsertErrorInfo              
              
   END CATCH              
    
select @fm_id=max(id) from #TableData3  
select @fm_add=@fm_add-100  
truncate table #tabledata3  
truncate table #output  
truncate table #leadid  
  end  
     
     
   DROP TABLE  IF EXISTS #leadid              
               
   DROP TABLE   IF EXISTS #output              
    
  
 SELECT 'Record Updated'                    
 if @BatchID IS NOT NULL AND @BatchID <> 0            
BEGIN            
 --Update  Tbl_MassOperationSummary set BatchEndTime= GetDate(),ScheduleDateTime= @StartDateTime , Remarks = 'Record Saved ', IsProcessed=1 where BatchID=@BatchID          
 UPDATE Tbl_MassOperationSummary      
        SET BatchEndTime = GETDATE(),      
            ScheduleDateTime = CASE       
                                 WHEN ScheduleDateTime IS NULL OR ScheduleDateTime = '' OR ScheduleDateTime = '1900-01-01 00:00:00.000'      
                                 THEN @StartDateTime      
                                 ELSE ScheduleDateTime      
                               END,      
            Remarks = 'Record Saved',      
            IsProcessed = 1      
        WHERE BatchID = @BatchID;      
END            
            
  DECLARE @rowJson NVARCHAR(MAX) = (              
    SELECT *              
    FROM UserLeads ul  (nolock)            
    WHERE ID IN (              
 SELECT fs.[value]              
      FROM dbo.fn_Split(@IDS, ',') fs              
      )              
    FOR JSON AUTO              
     ,INCLUDE_NULL_VALUES              
    )              
              
 IF @rowJson IS NOT NULL              
  BEGIN              
   EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @ModifiedBy              
    ,@Activity_type = 'Updt_msflwup_lead'              
    ,@ActionType = 'U'              
    ,@RowJson = @rowJson              
    ,@Table_name = 'UserLeads'              
  END              
 END TRY                        
 BEGIN CATCH              
  SET Context_Info 0x            
   EXEC usp_InsertErrorInfo              
  SELECT ERROR_NUMBER()     AS ErrorNumber,                        
         ERROR_SEVERITY()   AS ErrorSeverity,                        
         ERROR_STATE()      AS ErrorState,                        
         ERROR_PROCEDURE()  AS ErrorProcedure,                        
         ERROR_LINE()       AS ErrorLine,                        
         ERROR_MESSAGE()    AS ErrorMessage;                        
 END CATCH               
            
END 


GO

