/* ============================================================
   Procedure: [dbo].[usp_AddMoneyToAdRequest]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

 
---------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------
CREATE   PROCEDURE [dbo].[usp_AddMoneyToAdRequest] (    
 @Amount NUMERIC(18, 2)    
 ,@AdRequestID BIGINT    
 ,@UserID BIGINT    
 ,@ParentID BIGINT    
 )    
AS    
BEGIN    
 DECLARE @NewRequestID BIGINT = 0    
 DECLARE @PreviousAmount NUMERIC(18, 2) = 0;    
 DECLARE @TotalAmount NUMERIC(18, 2) = 0    
    
 SELECT TOP 1 @PreviousAmount = isnull(Amount, 0)    
 FROM AdRequests WITH (NOLOCK)    
 WHERE ID = @AdRequestID    
    
 SET @TotalAmount = @PreviousAmount + @Amount;    
    
 --update AdRequests set Amount = @Amount where ID = @AdRequestID            
 INSERT INTO AdRequests (    
  PageID    
  ,AddName    
  ,RequestType    
  ,Content    
  ,Remarks    
  ,Amount    
  ,CreatedOn    
  ,CreatedBy    
  )    
 SELECT isnull(PageID, 0)    
  ,isnull(AddName, '')    
  ,'Add Money'    
  ,Content    
  ,Remarks    
  ,@Amount    
  ,getdate()    
  ,@UserID    
 FROM AdRequests WITH (NOLOCK)    
 WHERE ID = @AdRequestID    
    
 SELECT @NewRequestID = SCOPE_IDENTITY()    
    
 UPDATE AdRequests    
 SET Amount = @TotalAmount    
 WHERE ID = @AdRequestID    
    
 INSERT INTO AdRequestHistory (    
  RequestID    
  ,URL    
  ,AssignedTo    
  ,STATUS    
  ,ScheduledDays    
  ,StartDate    
  ,EndDate    
  ,CreatedOn    
  ,CreatedBy    
  )    
 SELECT TOP 1 @NewRequestID    
  ,URL    
  ,AssignedTo    
  ,'Add Money'    
  ,''    
  ,NULL    
  ,NULL    
  ,getdate()    
  ,@UserID    
 FROM AdRequestHistory WITH (NOLOCK)    
 WHERE RequestID = @AdRequestID    
 ORDER BY ID DESC    
    
 DECLARE @debits DECIMAL = @Amount    
 DECLARE @Balance DECIMAL = 0    
 DECLARE @MID BIGINT = 0;    
    
 SELECT TOP 1 @MID = isnull(M_ID, 0)    
 FROM User_Detail WITH (NOLOCK)    
 WHERE USER_ID = @ParentID    
    
 SELECT TOP 1 @Balance = cd.Balance    
 FROM IntCredit_Details AS cd WITH (NOLOCK)    
 WHERE cd.[User_ID] = @ParentID    
 ORDER BY cd.Credit_ID DESC    
    
 DECLARE @avilableBalance decimal(18,4) = dbo.GetAvailableBalanceForService(@ParentID, 16)

 IF (@avilableBalance >= @debits)    
 BEGIN    
  INSERT INTO IntCredit_Details (    
   ID    
   ,M_ID    
   ,FromUser_ID    
   ,[User_ID]    
   ,Debits    
   ,Credits    
   ,Balance    
   ,Validity    
   ,FromDate    
   ,ToDate    
   ,DateCreated    
   ,DateUpdated    
   ,EmpUpdated    
   ,LastModified    
   ,ICD_CreatedBy    
   )    
  VALUES (    
   NEWID()    
   ,@MID    
   ,@UserID    
   ,@ParentID    
   ,@debits    
   ,0    
   ,ISNULL(@Balance, 0) - (@debits)    
   ,'999999'    
   ,GETDATE()    
   ,GETDATE()    
   ,GETDATE()    
   ,GETDATE()    
   ,GETDATE()    
   ,GETDATE()    
   ,@UserID    
   )    

  declare @intCreditId bigint = scope_identity()
  exec usp_rf_UpdateReserveFundTransaction @CreditId = @intCreditId

 END    
    
 SELECT 'Record updated'    
    
 DECLARE @rowJson VARCHAR(MAX) = (    
   SELECT *    
   FROM AdRequests(NOLOCK)    
   WHERE Id = @NewRequestID    
   FOR JSON AUTO    
    ,INCLUDE_NULL_VALUES    
   )    
    
 IF @rowJson IS NOT NULL    
 BEGIN    
  EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserId    
   ,@Activity_type = 'Inst_mny_fbprmtn'    
   ,@ActionType = 'I'    
   ,@RowJson = @rowJson    
   ,@Table_name = 'AdRequests'    
 END    
END 



GO

