/* ============================================================
   Procedure: [dbo].[usp_addremovestickyagent]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_addremovestickyagent(@appid bigint,@add int = 1)
as
begin
set @add=coalesce(@add,1)

if @add=1 and not exists(select 1 from stickyagentappids(nolock) where appid=@appid )
begin
insert into stickyagentappids(appid)
select @appid 
select concat('appid: ',@appid,' added')
end
else if @add=1 and exists(select 1 from stickyagentappids(nolock) where appid=@appid )
begin
select concat('appid: ',@appid,' already exists')
end

if @add=0
begin
delete from stickyagentappids where appid=@appid
select concat('appid: ',@appid,' removed if existed')
end

end



