CREATE   PROCEDURE [dbo].[usp_addsendermail]         
(@parentid bigint,@frommailid nvarchar(200),@isactive int,@dname nvarchar(100)=null)        
as        
begin        
  
if exists(select 1 from [FromMailIDDetails] where [User_ID]=@parentid and @frommailid=Mail_ID)        
begin        
update [FromMailIDDetails] set status=@isactive,lastmodified=getdate(),dateupdated=getdate(),displayname=@dname,processed=1  
 where  [User_ID]=@parentid and @frommailid=Mail_ID      
end        
else        
begin        
declare @m_id bigint=(select m_id from user_detail(nolock) where user_id=@parentid)     
  print concat(@frommailid ,', ',isnull(@m_id,0),', ',@parentid,', ',@isactive,', ',@dname       
  )   
insert into [FromMailIDDetails](Mail_ID,M_ID,User_ID,Status,DateCreated,DateUpdated,LastModified,Processed,[Key],DisplayName)        
select @frommailid ,@m_id,@parentid,@isactive,getdate(),getdate(),getdate(),1,'AWS',@dname       
end        
end  


