/* ============================================================
   Procedure: [dbo].[usp_AddSequence_new]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_AddSequence_new]      
    @IDS VARCHAR(MAX) = '',   
    @metatdata NVARCHAR(MAX),  
    @SequenceId BIGINT,      
    @BatchID BIGINT,      
    @Name NVARCHAR(255),      
    @UserId BIGINT,      
    @ScheduleDate VARCHAR(50) = '',      
    @SequenceType NVARCHAR(255),  
    @StartDateTime NVARCHAR(MAX) = ''  
AS      
BEGIN      
    SET NOCOUNT ON;  
    
    BEGIN TRY      
        -- Check if @IDS is NULL or blank
        IF @IDS IS NULL OR LTRIM(RTRIM(@IDS)) = ''
        BEGIN
            -- Return message if @IDS is null or blank
            SELECT 'ID is null or blank' AS StatusMessage;
            RETURN;
        END
    
        DECLARE @IDsTable TABLE (ID BIGINT);  
        DECLARE @InsertedTable TABLE (EntityID BIGINT);  
        DECLARE @ParentID BIGINT;  
        DECLARE @NewBatchID BIGINT;  
  
        -- Fetch the ParentID using @UserId  
        SELECT @ParentID = ParentID  
        FROM User_Detail (NOLOCK)  
        WHERE User_ID = @UserId;  
   
        -- Insert into Tbl_MassOperationSummary
        INSERT INTO Tbl_MassOperationSummary (  
            MassOperationName,  
            UserID,  
            Parentid,  
            CreatedDate,  
            IsProcessed,  
            Remarks,  
            BatchStartTime,  
            BatchEndTime,  
            EntityType,  
            isvalid,  
            metadata,  
            ErrorDetails,  
            SenderId,  
            UrlTrack,  
            TrackedUrl,  
            SmsPlaceHolder,  
            ScheduleDateTime  
        )  
        VALUES (  
            'Marketing Sequence',  
            @UserId,  
            @ParentID,  
            GETDATE(),  
            0,  
            NULL,  
            NULL,  
            NULL,  
            @SequenceType,  
            1,  
            @metatdata,  
            NULL,  
            NULL,  
            NULL,  
            NULL,  
            NULL,  
            @StartDateTime  
        );  
  
        -- Get the BatchID of the last inserted row  
        SELECT @NewBatchID = SCOPE_IDENTITY();  
  
        -- Remove braces from @IDS if they exist  
        SET @IDS = REPLACE(REPLACE(@IDS, '{', ''), '}', '');  
  
        -- Split the @IDS string and insert into the @IDsTable table using STRING_SPLIT
        INSERT INTO @IDsTable (ID)
        SELECT CAST(value AS BIGINT)
        FROM STRING_SPLIT(@IDS, ',');
  
        -- Insert records into Tbl_MassOperationDetails using the new BatchID  
        INSERT INTO Tbl_MassOperationDetails (SummaryId, EntityID)  
        SELECT @NewBatchID, ID FROM @IDsTable;  
  
        DECLARE @ConvertedStartDateTime DATETIME;
        SET @ConvertedStartDateTime = TRY_CAST(@StartDateTime AS DATETIME);
        
        -- Compare with current datetime
        IF @ConvertedStartDateTime IS NOT NULL
        BEGIN
            IF CONVERT(DATETIME, @ConvertedStartDateTime, 120) = CONVERT(DATETIME, GETDATE(), 120)
            BEGIN
                -- Exact same datetime
                EXEC usp_insertmassmktgsequence @batchid = @NewBatchID;
            END
            ELSE IF @ConvertedStartDateTime > GETDATE()
            BEGIN
                -- Future datetime
                EXEC [dbo].[Usp_MassOperationLeadEnquiryProcess] @summary_batchid = @NewBatchID;
            END
        END  
          
        -- Return a status message and count of rows inserted for the given IDs  
        SELECT 'Success' AS StatusMessage, COUNT(*) AS TotalRecords FROM @IDsTable;  
  
    END TRY  
    BEGIN CATCH  
        -- Handle errors
        EXEC usp_InsertErrorInfo;  
    END CATCH;  
END;


GO

/* ============================================================
   Procedure: [dbo].[usp_AddTxIntCreditDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_AddTxIntCreditDetails]     
(    
    @parentid bigint,    
    @m_id bigint,    
    @cost_in_inr_credit numeric(18,4),    
    @cost_in_inr_debit numeric(18,4),    
    @credit_type int,    
    @remarks nvarchar(1000),    
    @Batchid bigint,
    @intCredId bigint OUTPUT    
)    
AS    
BEGIN    
    SET NOCOUNT ON;    
    
    DECLARE @intid bigint;    
  select @m_id=coalesce(@m_id,10043)  
  
    INSERT INTO IntCredit_Details    
    (    
        FromUser_ID,     
        M_ID,     
        User_ID,     
        Debits,     
        Credits,     
        Balance,     
        Validity,     
        typecredit,     
        Remarks,
        batchid
    )    
    VALUES     
    (     
        @parentid,    
        @m_id,   
        @parentid,    
        @cost_in_inr_debit,    
        @cost_in_inr_credit,    
        dbo.fn_GetMoneyBalance(@parentid) + @cost_in_inr_credit - @cost_in_inr_debit,    
        99999,    
        @credit_type,    
        @remarks,
        @Batchid
    );    
    
    SELECT @intid = SCOPE_IDENTITY();    
    
    -- update reserve fund transaction    
    EXEC usp_rf_UpdateReserveFundTransaction @CreditId = @intid;    
    
    -- set output parameter    
    SET @intCredId = @intid;    
END 



