/* ============================================================
   Procedure: [dbo].[Usp_AddVariantsColumnsToProductTables]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_AddVariantsColumnsToProductTables]  -- for add variants and vcombination column with all dynamic tables
AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @ParentId BIGINT;
    DECLARE @TableName NVARCHAR(MAX);
    DECLARE @SQL NVARCHAR(MAX);

    -- Cursor to loop through all ParentIDs
    DECLARE ParentCursor CURSOR FOR 
    SELECT DISTINCT ParentID FROM User_Detail WHERE ParentID IS NOT NULL;

    OPEN ParentCursor;
    
    FETCH NEXT FROM ParentCursor INTO @ParentId;

    WHILE @@FETCH_STATUS = 0
    BEGIN
        -- Set table name dynamically
        SET @TableName = 'tbl_productmaster_' + CAST(@ParentId AS NVARCHAR);

        -- Check if table exists
        IF EXISTS (SELECT 1 FROM INFORMATION_SCHEMA.TABLES WHERE TABLE_NAME = @TableName AND TABLE_CATALOG = DB_NAME())
        BEGIN
            -- Check if VariantsJson column exists and add if not
            IF NOT EXISTS (SELECT 1 FROM INFORMATION_SCHEMA.COLUMNS WHERE TABLE_NAME = @TableName AND COLUMN_NAME = 'VariantsJson')
            BEGIN
                SET @SQL = 'ALTER TABLE ' + @TableName + ' ADD VariantsJson NVARCHAR(MAX) NULL;';
                EXEC sp_executesql @SQL;
            END

            -- Check if VCombinationJson column exists and add if not
            IF NOT EXISTS (SELECT 1 FROM INFORMATION_SCHEMA.COLUMNS WHERE TABLE_NAME = @TableName AND COLUMN_NAME = 'VCombinationJson')
            BEGIN
                SET @SQL = 'ALTER TABLE ' + @TableName + ' ADD VCombinationJson NVARCHAR(MAX) NULL;';
                EXEC sp_executesql @SQL;
            END
        END

        -- Fetch next ParentID
        FETCH NEXT FROM ParentCursor INTO @ParentId;
    END

    -- Close and deallocate cursor
    CLOSE ParentCursor;
    DEALLOCATE ParentCursor;
END


GO

