   Procedure: [dbo].[Usp_AdName_Availability]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_AdName_Availability
(
 @AdName nvarchar(500), 
 @PageName nvarchar(500),
 @ParentID bigint,
 @TypeID int 
)
as
Begin
    if(exists(select top 1 1 from PageRequests where PageName = @PageName and ParentID = @ParentID
	  --and TypeID = @TypeID 	
	))
     Begin

	 if(exists(select 1 from AdRequests where PageID in (
		 select top 1 isnull(ID,0) from PageRequests where PageName = @PageName and ParentID = @ParentID
		  )
	      and 
		  AddName = @AdName
		  ))
        Begin
		    select 'Not Available'
		End 
     else
	     Begin
		    select 'Available'
		 End     
		 		    
	 End   
	else
	 Begin
	   select 'Available'       
	 End 	  
		  
		      
End


