CREATE   PROCEDURE [dbo].[usp_ag_enrich] (
    @website nvarchar(500) = null,
    @email nvarchar(250) = null,
    @company_name nvarchar(250) = null,
    @user_id bigint, @ai_response_json nvarchar(max),
    @agent_goal nvarchar(100) = null,
    @bot_type nvarchar(50) = 'chat'
)
as  
begin  
    set nocount on;

    declare @parentid bigint = dbo.ufn_getuserparentid(@user_id);

    insert into ai_profile_enrichment(parentid,createdby,website,email,company_name,ai_response_json,agent_goal)  
    select @parentid,@user_id,@website,@email,@company_name,@ai_response_json,@agent_goal;

    
    -- Call insert proc; log errors but do not let KB insert failure break enrichment workflow
    begin try
        exec usp_ag_insert_company_with_kb @payload = @ai_response_json, @UserId = @user_id, @botType = @bot_type
    end try
    begin catch
        exec usp_InsertErrorInfo
    end catch
end 



GO

/* ============================================================
   Procedure: [dbo].[usp_ag_get_companies]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.usp_ag_get_companies
        @UserId bigint = 0,
        @PageNumber INT = 1,
        @PageSize INT = 25,
        @SearchTerm NVARCHAR(200) = NULL,
        @SortBy NVARCHAR(50) = 'CompanyName', -- allowed values: CompanyName, CreatedDate, Industry
        @SortDir NVARCHAR(4) = 'ASC',         -- ASC or DESC
        @CountryId INT = NULL, -- not used by tbl_ai_Companies schema (kept for compatibility)
        @StateId INT = NULL,   -- not used by tbl_ai_Companies schema (kept for compatibility)
        @IsActive BIT = NULL
AS
BEGIN
    SET NOCOUNT ON;

    -- normalize inputs
    IF @PageNumber < 1 SET @PageNumber = 1;
    IF @PageSize < 1 SET @PageSize = 25;
    IF @SortDir NOT IN ('ASC','DESC') SET @SortDir = 'ASC';

    declare @UserParentId bigint = dbo.ufn_getuserparentid(@UserId);

    -- map SortBy to safe, allowed column names (use actual tbl_ai_Companies columns)
    DECLARE @SortColumn NVARCHAR(200) = 
        CASE LOWER(ISNULL(@SortBy,''))
            WHEN 'companyname' THEN 'c.Name'
            WHEN 'createddate' THEN 'c.CreatedAt'
            WHEN 'industry' THEN 'c.Industry'
            ELSE 'c.Name'
        END;

    DECLARE @OrderBy NVARCHAR(240) = @SortColumn + ' ' + @SortDir;

    DECLARE @Offset INT = (@PageNumber - 1) * @PageSize;

    DECLARE @sql NVARCHAR(MAX);
    SET @sql = N'
        SELECT
            c.CompanyId,
            c.Name AS CompanyName,
            c.Industry,
            c.Website,
            c.ContactEmail,
            c.ParentId,
            c.DetailsJson,
            CASE WHEN c.IsDeleted = 0 THEN 1 ELSE 0 END AS IsActive,
            c.CreatedAt AS CreatedDate,
            COUNT(1) OVER() AS TotalCount
        FROM dbo.tbl_ai_Companies c
        WHERE 1=1
                AND c.ParentId = @UserParentId
            AND (@SearchTerm IS NULL OR (c.Name LIKE ''%'' + @SearchTerm + ''%'' OR c.Industry LIKE ''%'' + @SearchTerm + ''%'' OR c.DetailsJson LIKE ''%'' + @SearchTerm + ''%'' ))
            AND (@IsActive IS NULL OR (CASE WHEN c.IsDeleted = 0 THEN 1 ELSE 0 END) = @IsActive)
        ORDER BY ' + @OrderBy + '
        OFFSET @Offset ROWS FETCH NEXT @PageSize ROWS ONLY;';

    -- Execute parameterized dynamic SQL
    EXEC sp_executesql
        @sql,
        N'@UserParentId BIGINT, @SearchTerm NVARCHAR(200), @IsActive BIT, @Offset INT, @PageSize INT',
        @UserParentId = @UserParentId, @SearchTerm = @SearchTerm, @IsActive = @IsActive, @Offset = @Offset, @PageSize = @PageSize;
END;



GO

/* ============================================================
   Procedure: [dbo].[usp_ag_insert_company_with_kb]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_ag_insert_company_with_kb]
    @payload nvarchar(max),
    @UserId bigint = 0,
    @botType nvarchar(50) = 'chat'
as
begin

    set nocount on;

    -- Inserts a company and its knowledgebase items (and tags) from a JSON payload.
    -- Also creates an agent, widget settings, persona, trigger and goal when provided.

    declare @CompanyId bigint;
    declare @ParentId bigint = NULL;
    declare @AgentId bigint = NULL;

    begin try
        begin transaction;

        -- determine parent id from user
        if @UserId > 0
            set @ParentId = dbo.ufn_getuserparentid(@UserId);

        -- Parse and insert company
        declare @Name nvarchar(200) = JSON_VALUE(@payload, '$.companyForm.name');
        declare @Website nvarchar(400) = JSON_VALUE(@payload, '$.companyForm.websiteUrl');
        declare @Industry nvarchar(150) = JSON_VALUE(@payload, '$.companyForm.industry');
        declare @BrandColor nvarchar(50) = JSON_VALUE(@payload, '$.companyForm.brandColor');
        declare @ContactEmail nvarchar(200) = JSON_VALUE(@payload, '$.companyForm.contactEmail');
        declare @ContactPhone nvarchar(50) = JSON_VALUE(@payload, '$.companyForm.contactPhone');

        insert into dbo.tbl_ai_Companies (Name, Website, Industry, BrandColor, ContactEmail, ContactPhone, ParentId, DetailsJson, CreatedAt, CreatedOn, CreatedBy)
        values (@Name, @Website, @Industry, @BrandColor, @ContactEmail, @ContactPhone, @ParentId, @payload, getdate(), getdate(), NULLIF(@UserId,0));

        set @CompanyId = scope_identity();

        -- Insert Agent (if provided in payload.agentBasicSettingsForm)
        declare @AgentName nvarchar(200) = JSON_VALUE(@payload, '$.agentBasicSettingsForm.agentName');
        declare @AgentDescription nvarchar(max) = JSON_VALUE(@payload, '$.agentBasicSettingsForm.agentDescription');
        declare @AgentEmail nvarchar(320) = JSON_VALUE(@payload, '$.agentBasicSettingsForm.email');

        if @AgentName is not null
        begin

            declare @isPredefined bit = 0;
            declare @predefinedAgentId bigint = null
            if(isnull(@botType, '') = 'mail')
            begin
                select @isPredefined = 1, @predefinedAgentId = 4; -- Mail Bot
            end

            set @AgentName = dbo.fn_GetUniqueAgentName(@ParentId, @AgentName, NULL);
           
           insert into dbo.tbl_ai_Agents (ParentId, CompanyId, AssistantId, Name, Email, Role, Status, IsBot, DetailsJson, CreatedAt, CreatedOn, CreatedBy, is_predefined, predefined_agentid )
            values (@ParentId, @CompanyId, NULL, @AgentName, @AgentEmail, NULL, 'active', 1, JSON_QUERY(@payload, '$.agentBasicSettingsForm'), getdate(), getdate(), NULLIF(@UserId,0), @isPredefined, @predefinedAgentId);

            set @AgentId = scope_identity();
        end

        -- Insert Widget settings (if provided)
        if JSON_VALUE(@payload, '$.widgetSettingsForm.assistantName') is not null and @AgentId is not null
        begin
            insert into dbo.tbl_ai_WidgetSettings (ParentId, AgentId, AssistantName, AssistantLogoUrl, PrimaryColor, DefaultChannel, DynamicFormsEnabled, ConfigJson, DetailsJson, CreatedOn, CreatedBy)
            values (
                @ParentId,
                @AgentId,
                JSON_VALUE(@payload, '$.widgetSettingsForm.assistantName'),
                JSON_VALUE(@payload, '$.widgetSettingsForm.assistantLogo'),
                JSON_VALUE(@payload, '$.widgetSettingsForm.primaryColor'),
                JSON_VALUE(@payload, '$.widgetSettingsForm.defaultChannel'),
                CASE WHEN JSON_VALUE(@payload, '$.widgetSettingsForm.dynamicFormsEnabled') = 'true' THEN 1 ELSE 0 END,
                JSON_QUERY(@payload, '$.widgetSettingsForm'),
                JSON_QUERY(@payload, '$.widgetSettingsForm'),
                getdate(), NULLIF(@UserId,0)
            );
        end




        -- Insert Persona (from promptSettingsForm)
        if JSON_VALUE(@payload, '$.promptSettingsForm.selectedPersona') is not null and @AgentId is not null
        begin
            insert into tbl_ai_Personas (ParentId, AgentId, [Name], IconUrl, [Description], ConfigJson, DetailsJson, CreatedOn, CreatedBy, IsActive)
            values (
                @ParentId,
                @AgentId,
                JSON_VALUE(@payload, '$.promptSettingsForm.selectedPersona'),
                NULL,
                JSON_VALUE(@payload, '$.promptSettingsForm.customPersona'),
                JSON_QUERY(@payload, '$.promptSettingsForm'),
                JSON_QUERY(@payload, '$.promptSettingsForm'),
                getutcdate(), NULLIF(@UserId,0), 1
            );
        end

        -- Insert a simple Trigger to route qualified leads (optional)
        if @AgentId is not null
        begin
            declare @TriggerConditions nvarchar(max) = N'{"condition":"message_contains_contact_details"}';
            declare @TriggerActions nvarchar(max) = N'{"action":"assign_to_sales","notify":true}';

            insert into dbo.tbl_ai_Triggers (ParentId, AgentId, Name, Event, Conditions, Actions, IsEnabled, DetailsJson, CreatedOn, CreatedBy, IsActive)
            values (@ParentId, @AgentId, 'Route qualified leads to sales', 'lead_qualified', @TriggerConditions, @TriggerActions, 1, JSON_QUERY(@payload, '$.promptSettingsForm'), getdate(), NULLIF(@UserId,0), 1);
        end

        -- Insert a default Goal for lead capture (optional)
        if @AgentId is not null
        begin
            insert into dbo.tbl_ai_Goals (ParentId, AgentId, Title, Type, Metric, Target, Period, Priority, DetailsJson, CreatedOn, CreatedBy)
            values (@ParentId, @AgentId, 'Capture leads', 'lead_capture', 'Leads', '10', 'Monthly', 'High', JSON_QUERY(@payload, '$.promptSettingsForm'), getdate(), NULLIF(@UserId,0));
        end

        -- Parse knowledge base items into a table variable
        declare @KB table (
            RowId int identity(1,1) primary key,
            Title nvarchar(500),
            Category nvarchar(200),
            Description nvarchar(max),
            Content nvarchar(max),
            WebLinks nvarchar(max),
            Files nvarchar(max),
            OrigJson nvarchar(max)
        );

        insert into @KB (Title, Category, Description, Content, WebLinks, Files, OrigJson)
        select
            json_value([value], '$.title'),
            json_value([value], '$.category'),
            json_value([value], '$.description'),
            json_value([value], '$.content'),
            json_query([value], '$.webLinks'),
            json_query([value], '$.files'),
            [value]
        from openjson(@payload, '$.knowledgeBaseForm');

        declare @cnt int = (select count(1) from @KB);
        declare @i int = 1;
        declare @Title nvarchar(500);
        declare @Category nvarchar(200);
        declare @Description nvarchar(max);
        declare @Content nvarchar(max);
        declare @WebLinks nvarchar(max);
        declare @Files nvarchar(max);
        declare @OrigJson nvarchar(max);
        declare @KbId bigint;
        declare @Tag nvarchar(200);
        declare @TagId bigint;

        while @i <= @cnt
        begin
            select @Title = Title, @Category = Category, @Description = Description, @Content = Content,
                   @WebLinks = WebLinks, @Files = Files, @OrigJson = OrigJson
            from @KB where RowId = @i;

            insert into dbo.tbl_ai_KnowledgeBase (ParentId, CompanyId, Title, Category, Content, SourceUri, DetailsJson, CreatedOn, CreatedBy, CreatedAt)
            values (@ParentId, @CompanyId, @Title, @Category, @Content, JSON_VALUE(@OrigJson, '$.webLinks[0]'), @OrigJson, getdate(), NULLIF(@UserId,0), getdate());

            set @KbId = scope_identity();

            -- Link KB to Agent if agent exists
            if @AgentId is not null
            begin
                if not exists (select 1 from dbo.tbl_ai_AgentKnowledgeBase where AgentId = @AgentId and KbId = @KbId)
                    insert into dbo.tbl_ai_AgentKnowledgeBase (AgentId, ParentId, KbId) values (@AgentId, @ParentId, @KbId);
            end

            -- Insert tags if provided
            if isjson(@OrigJson) = 1 and json_query(@OrigJson, '$.tags') is not null
            begin
                declare tag_cursor cursor local for
                    select [value] from openjson(@OrigJson, '$.tags');

                open tag_cursor;
                fetch next from tag_cursor into @Tag;
                while @@fetch_status = 0
                begin
                    set @Tag = rtrim(ltrim(isnull(@Tag, '')));
                    if len(@Tag) > 0
                    begin
                        if not exists (select 1 from dbo.tbl_ai_Tags where CompanyId = @CompanyId and Name = @Tag)
                        begin
                            insert into dbo.tbl_ai_Tags (ParentId, CompanyId, Name, CreatedAt) values (@ParentId, @CompanyId, @Tag, getdate());
                            set @TagId = scope_identity();
                        end
                        else
                            select @TagId = TagId from dbo.tbl_ai_Tags where CompanyId = @CompanyId and Name = @Tag;

                        if not exists (select 1 from dbo.tbl_ai_KBTags where KbId = @KbId and TagId = @TagId)
                            insert into dbo.tbl_ai_KBTags (KbId, ParentId, TagId) values (@KbId, @ParentId, @TagId);
                    end

                    fetch next from tag_cursor into @Tag;
                end
                close tag_cursor; deallocate tag_cursor;
            end

            set @i = @i + 1;
        end

        commit transaction;

        -- Return inserted company id and optionally agent id
        select @CompanyId as CompanyId, @AgentId as AgentId;

    end try
    begin catch
        if @@trancount > 0 rollback transaction;

        exec usp_InsertErrorInfo;

    end catch
end



GO

/* ============================================================
   Procedure: [dbo].[usp_Ai_AddEnquiry]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_Ai_AddEnquiry]
(
    @PersonName VARCHAR(100) = NULL,
    @CountryCode   VARCHAR(50) = NULL,
    @MobileNo   VARCHAR(100) = NULL,
    @EmailID    VARCHAR(100) = NULL,
    @SourceID   BIGINT,
    @VisitorID   BIGINT,
    @UserId     BIGINT
)
AS
BEGIN
    SET NOCOUNT ON;
    declare @ParentID bigint, @EnquiryId bigint=0

    BEGIN TRY
        select @ParentID=ParentID from User_Detail(nolock) Where User_ID=@UserId
        

        --------------------------------------------------
        -- 🔍 Check duplicate Mobile or Email
        --------------------------------------------------

        SELECT @EnquiryId=enquiryid
        FROM dbo.Userenquiry_Mobile_Email WITH (NOLOCK)
        WHERE ParentID = @ParentID
            AND (
            concat(isnull(@CountryCode,''),ISNULL(@MobileNo,'')) = concat(CountryCode,Mobile)
            OR (ISNULL(@EmailID,'') = Email)
                )

        IF @EnquiryId>0
        BEGIN
            SELECT 0 AS Status, 'Enquiry already exists with same Mobile or Email' AS Message;
            update tbl_ai_VisitorsLastResponse set entityId=@EnquiryId,entityName='Enquiry' where id=@VisitorID
            RETURN;
        END

        --------------------------------------------------
        -- ✅ Insert new enquiry
        --------------------------------------------------
        INSERT INTO dbo.UserEnquiry
        (
            PersonName,
            CountryCode,
            MobileNo,
            EmailID,
            SourceName,
            MediumName,
            CampaignName,
            IsOpen,
            IsduplicateEmail,
            IsduplicateMobile,
            ParentID
        )
        VALUES
        (
            @PersonName,
            @CountryCode,
            @MobileNo,
            @EmailID,
            @SourceID,        -- SourceName
            0,          -- MediumName
            0,          -- CampaignName
            1,          -- IsOpen
            0,          -- IsduplicateEmail
            0,          -- IsduplicateMobile
            @ParentID
        );

        Select @EnquiryId=SCOPE_IDENTITY()

        --------------------------------------------------
        -- ✅ Success response
        --------------------------------------------------
        update tbl_ai_VisitorsLastResponse set entityId=@EnquiryId,entityName='Enquiry' where id=@VisitorID

        SELECT 1 AS Status, 'Enquiry created successfully' AS Message;

    END TRY
    BEGIN CATCH
        EXEC usp_InsertErrorInfo;

        SELECT 
            -1 AS Status,
            'Error occurred while creating enquiry' AS Message;
    END CATCH
END



GO

/* ============================================================
   Procedure: [dbo].[usp_Ai_AddLead]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON



CREATE   PROCEDURE [dbo].[usp_Ai_AddLead]
(
    @PersonName VARCHAR(100) = NULL,
    @CountryCode   VARCHAR(50) = NULL,
    @MobileNo   VARCHAR(100) = NULL,
    @EmailID    VARCHAR(100) = NULL,
    @SourceID   BIGINT,
    @VisitorID   BIGINT,
    @UserId     BIGINT,
    @Remarks    nvarchar(2000),
    @FollowupId bigint, 
    @csvProductsId varchar(1000),
    @AssignTo       bigint,
    @AmtPaid    numeric(18,2)=0,
    @FollowupDate datetime = null
)
AS
BEGIN
    SET NOCOUNT ON;
    declare @ParentID bigint, @LeadId bigint=0

    BEGIN TRY

        select @ParentID=ParentID from User_Detail(nolock) Where User_ID=@UserId

        --------------------------------------------------
        -- 🔍 Check duplicate Mobile or Email
        --------------------------------------------------
        SELECT @LeadId=ulme_id
        FROM dbo.Userleads_Mobile_Email WITH (NOLOCK)
        WHERE ParentID = @ParentID
            AND (
                concat(isnull(@CountryCode,''),ISNULL(@MobileNo,'')) = concat(CountryCode,Mobile)
                OR (ISNULL(@EmailID,'') = Email)
                )

        IF @LeadId > 0
        BEGIN
            SELECT 0 AS Status, 'Lead already exists with same Mobile or Email' AS Message;
            update tbl_ai_VisitorsLastResponse set entityId=@LeadId,entityName='Lead' where id=@VisitorID
            RETURN;
        END

        --------------------------------------------------
        -- 🔢 Generate next LeadNo safely
        --------------------------------------------------
        DECLARE @NextLeadNo BIGINT;

        SELECT @NextLeadNo = ISNULL(MAX(LeadNo), 0) + 1
        FROM dbo.UserLeads WITH (UPDLOCK, HOLDLOCK)
        WHERE ParentID = @ParentID;

        --------------------------------------------------
        -- ✅ Insert new lead
        --------------------------------------------------
        INSERT INTO dbo.UserLeads
        (
            PersonName,
            LeadNo,
            CountryCode,
            MobileNo,
            EmailID,
            SourceName,
            ParentID,
            AssignedTo,
            FollowUpStatus,
            Remarks,
            Products,
            FollowupDate,
            AmountPaid,
            IsScoreeligible
        )
        VALUES
        (
            @PersonName,
            @NextLeadNo,
            @CountryCode,
            @MobileNo,
            @EmailID,
            @SourceID,
            @ParentID,
            @AssignTo,
            @FollowupId,
            @Remarks,
            @csvProductsId,
            @FollowupDate,
            @AmtPaid,
            1
        );

        Select @LeadId=SCOPE_IDENTITY()
        
        INSERT INTO [dbo].[LeadInteractionHistory]
           ([LeadNo],[FollowUpStatus],[NextStatusDate],[Remarks],[Products],[AmountPaid],[AssignedTo],[ParentID],[CreatedOn],[CreatedBy],[FollowupDate]
           ,[IsReassign],[IsAutoEntry],[ProductsJson],[Id_Lead])
        VALUES
           (@NextLeadNo,@FollowupId,@FollowupDate,@Remarks,@csvProductsId,@AmtPaid,@AssignTo,@ParentID,GETDATE(),@UserId,@FollowupDate
           ,0,0,null,@LeadId)

        update tbl_ai_VisitorsLastResponse set entityId=@LeadId,entityName='Lead' where id=@VisitorID


        SELECT 1 AS Status, 'Lead created successfully' AS Message;

    END TRY
    BEGIN CATCH
        EXEC usp_InsertErrorInfo;

        SELECT 
            -1 AS Status,
            'Error occurred while creating lead' AS Message;
    END CATCH
END



GO

/* ============================================================
   Procedure: [dbo].[usp_ai_AddVoiceBotCampaign]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON



CREATE   PROCEDURE [dbo].[usp_ai_AddVoiceBotCampaign]
    @Userid BIGINT,
    @campaign_name NVARCHAR(MAX),
    @campaign_settings NVARCHAR(MAX),
    @audience_json NVARCHAR(MAX),
    @campaign_start_date DATETIME = NULL,
    @campaign_end_date DATETIME = NULL,
    @isactive BIT = 1,
    @campaign_id BIGINT
AS
BEGIN
    SET NOCOUNT ON
    declare @parentid BIGINT

    Select @ParentId=ParentId From User_detail(nolock) Where User_ID=@UserId

    BEGIN TRY
        INSERT INTO voice_bot_campaigns (
            parentid,
            created_by,
            created_on,
            campaign_name,
            campaign_settings,
            campaign_start_date,
            campaign_end_date,
            isactive,
            total_reach
        )
        VALUES (
            @parentid,
            @UserId,
            GETDATE(),
            @campaign_name,
            @campaign_settings,
            @campaign_start_date,
            @campaign_end_date,
            @isactive,
            0
        );
        
        SET @campaign_id = SCOPE_IDENTITY();

        if len(@audience_json) >2
        Begin
            --declare @audience_json nvarchar(max)=N'[{"countrycode":91,"mobileno":9876543210,"name":"John Doe","email":"john@example.com","company":"ABC Corp"},{"countrycode":1,"mobileno":1234567890,"name":"Jane Smith","email":"jane@example.com","company":"XYZ Ltd"}]'
            declare @RowData nvarchar(max), @FieldNames nvarchar(max)=''
            declare @SQLString nvarchar(max), @ParmDefinition nvarchar(max), @insAudienceJson nvarchar(max)

            select top 1 @RowData=value From openjson(@audience_json)

            select @FieldNames=@FieldNames+'['+[Key]+'] nvarchar(2000),' from openjson(@RowData)  

            set @FieldNames=SUBSTRING(@FieldNames,1,len(@FieldNames)-1)

            print @FieldNames

            drop table if exists #tmpAudience 

            create table #tmpAudience (id int identity);
            print 'alter table #tmpAudience add ' + @FieldNames
            exec('alter table #tmpAudience add ' + @FieldNames)

            Set @SQLString = N'insert into #tmpAudience select * from openjson(@ImptData) with (' + @FieldNames + ')'                 
            SET @ParmDefinition = N'@ImptData nvarchar(max)';
                  
            print @SQLString
            
            EXECUTE sp_executesql @SQLString, @ParmDefinition, @ImptData = @audience_json

            alter table #tmpAudience add AudienceJson nvarchar(max)
            update t set t.AudienceJson=(select * from #tmpAudience Where id=t.id for json auto)
            from #tmpAudience t

            insert into voice_bot_campaign_audience(parentid,vb_campaignid,created_on,recipient_mobile,recipient_countrycode,recipient_has_countrycode,entity_context)
            select @parentid,@campaign_id,GETDATE(), mobileno,iif(CHARINDEX('+',countrycode)>0,countrycode,concat('+',countrycode)),0,AudienceJson
            From #tmpAudience

        End
        
        SELECT @campaign_id AS campaign_id, 'Success' AS status, 'Campaign created successfully' AS message;
    END TRY
    BEGIN CATCH
        SELECT 0 AS campaign_id, 'Error' AS status, ERROR_MESSAGE() AS message;
        EXEC USP_INSERTERRORINFO;
    END CATCH
END



GO

