/* ============================================================
   Procedure: [dbo].[usp_ai_agent_InsertTokenUsage]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_ai_agent_InsertTokenUsage]  
    @entityname varchar(20),
    @entityid bigint,    
    @Agentid bigint,    
    @parentId BIGINT = NULL,  
    @threadId NVARCHAR(255) = NULL,  
    @runId NVARCHAR(255) = NULL,  
    @model NVARCHAR(100) = NULL,  
    @promptTokens INT,  
    @completionTokens INT,  
    @totalTokens INT,  
    @detailJson nvarchar(max)  
AS  
BEGIN  
  
    SET NOCOUNT ON;  
  
    DECLARE @tokenUsageId BIGINT;  
  
    BEGIN TRY  
        -- Insert token usage record  
        INSERT INTO dbo.tbl_ai_TokenUsages ( entityname,entityId, parentId, threadId, runId, model, promptTokens, completionTokens, totalTokens, detailJson,agentid )  
        VALUES ( @entityname,@entityid, @parentId, @threadId, @runId, @model, @promptTokens, @completionTokens, @totalTokens, @detailJson,@agentid );  
  
        -- Get the inserted record ID  
        SET @tokenUsageId = SCOPE_IDENTITY();  
  
        begin try  
            if(@tokenUsageId > 0)  
            begin  
                exec usp_ai_DeductAmount_AgentsTokenUsage @tokenUsageId  
            end  
        end try  
        begin catch  
            exec usp_InsertErrorInfo  
        end catch  
  
        -- Return the token usage ID  
        SELECT @tokenUsageId AS TokenUsageId;  
  
    END TRY  
    BEGIN CATCH  
        -- Log error and re-throw  
        --DECLARE @ErrorMessage NVARCHAR(4000) = ERROR_MESSAGE();  
        --DECLARE @ErrorSeverity INT = ERROR_SEVERITY();  
        --DECLARE @ErrorState INT = ERROR_STATE();  
  exec usp_InsertErrorInfo 
    END CATCH  
END  





GO

/* ============================================================
   Procedure: [dbo].[usp_ai_check_thread_exists]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON



CREATE   PROCEDURE [dbo].[usp_ai_check_thread_exists]
    @entityname VARCHAR(50),@entityid bigINT
AS
BEGIN
    SET NOCOUNT ON;
    
    SELECT TOP 1 thread_id
    FROM tbl_ai_agent_entity_status
    WHERE entityname = @entityname
        AND entityid = @entityid
        AND thread_id IS NOT NULL
    ORDER BY id DESC;
END



