/* ============================================================
   Procedure: [dbo].[usp_ai_CreateAgentApiKey]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.usp_ai_CreateAgentApiKey
    @AgentId BIGINT,
    @PlainApiKey NVARCHAR(400),
    @Name NVARCHAR(200) = NULL,
    @ExpiresAt DATETIME = NULL,
    @DetailsJson NVARCHAR(MAX) = NULL,
    @UserId BIGINT = NULL,
    @IsActive BIT = 1
AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @ParentId BIGINT;
    DECLARE @CreatedBy BIGINT;
    -- Determine ParentId and CreatedBy based on UserId
    IF(ISNULL(@UserId, 0) > 0)
    BEGIN
        SET @ParentId = dbo.ufn_getuserparentid(@UserId);
        SET @CreatedBy = @UserId;
    END
    ELSE
    BEGIN
        SET @ParentId = NULL;
        SET @CreatedBy = NULL;
    END

    -- Validate inputs
    IF @AgentId IS NULL
        THROW 51000, 'AgentId is required.', 1;

    IF @PlainApiKey IS NULL OR LEN(@PlainApiKey) = 0
        THROW 51001, 'PlainApiKey is required.', 1;

    -- Ensure agent exists and is not deleted
    IF NOT EXISTS (SELECT 1 FROM dbo.tbl_ai_Agents WITH (NOLOCK) WHERE AgentId = @AgentId AND ISNULL(IsDeleted, 0) = 0 AND ParentId = ISNULL(@ParentId, 0))
        THROW 51002, 'Agent not found.', 1;

    -- Soft-delete any existing non-deleted keys for this agent (same parent scope), then insert the new key.
    BEGIN TRY
        BEGIN TRANSACTION;

        UPDATE dbo.tbl_ai_AgentApiKeys
        SET IsDeleted = 1,
            IsActive = 0,
            DeletedOn = GETDATE(),
            DeletedBy = @CreatedBy
        WHERE AgentId = @AgentId
          AND ISNULL(IsDeleted, 0) = 0
          AND ParentId = ISNULL(@ParentId, 0);

        INSERT INTO dbo.tbl_ai_AgentApiKeys ( ParentId, AgentId, ApiKeyHash, ApiKeySalt, 
            Name, IsActive, ExpiresAt, DetailsJson, CreatedOn, CreatedBy)
        VALUES ( @ParentId, @AgentId, @PlainApiKey, NULL, 
            @Name, @IsActive, @ExpiresAt, @DetailsJson, GETDATE(), @CreatedBy);

        -- Return the new id to the caller
        SELECT CAST(SCOPE_IDENTITY() AS BIGINT) AS AgentApiKeyId;

        COMMIT TRANSACTION;
    END TRY
    BEGIN CATCH
        IF @@TRANCOUNT > 0
            ROLLBACK TRANSACTION;
        THROW; -- rethrow the current error
    END CATCH
END;



GO

/* ============================================================
   Procedure: [dbo].[usp_ai_DeductAmount_AgentsTokenUsage]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_ai_DeductAmount_AgentsTokenUsage (    
    @tokenUsageId bigint     
)    
as    
begin    
    --declare @tokenUsageId bigint = 1    
    
    declare     
        @parentId bigint = 0, @promptTokens int = 0, @completionTokens int = 0, @totalTokens int = 0, @PricePerUnit decimal(18, 4) = 0,    
        @UnitPerCredit int = 0, @visitorId bigint = 0, @agentName nvarchar(255) = '', @agentId bigint = 0, @mId bigint = 0 ,@entityname varchar(20),@entityid bigint,  
  @entitydetails nvarchar(250)  
    
    select @parentId = parentId, @promptTokens = promptTokens, @completionTokens = completionTokens,     
        @totalTokens = totalTokens, @visitorId = visitorId ,@entityid=entityid,@entityname =entityname,@agentid=agentid  
    from tbl_ai_TokenUsages(nolock) where TokenUseageId = @tokenUsageId    
   
 if @entityname='lead'  
 begin  
 select @entitydetails=concat(' Leadno ',leadno, ', Name: ',personname) from userleads(nolock) where id=@entityid  
 end  
 else if @entityname='enquiry'  
 begin  
 select @entitydetails=concat(' Enquiryno ',enquiryid, ', Name: ',personname) from userenquiry(nolock) where enquiryid=@entityid  
 end
 else if @entityname='agent'  
 begin  
 select @entitydetails=concat(' Agent ',agentid, ', Name: ',name) from tbl_ai_agents(nolock) where agentid=@entityid  
 end
 else   
 begin  
 select @entitydetails=concat(' VisitorId ',visitorid, ', Name: ',isnull(name,'Unknown')) from tbl_ai_visitors(nolock) where visitorid=@visitorid  
 end  
    
  if isnull(@agentid,0)=0   
  begin  
    select @agentId = AgentId from tbl_ai_Visitors with (nolock) where VisitorId  = @visitorId    
  end  
   select @agentName = Name from tbl_ai_Agents with (nolock) where AgentId = @agentId    
    select @mid = M_ID from User_Detail(nolock) where User_ID = @parentId    
    
    select top 1 @UnitPerCredit = Units_Per_Credit, @PricePerUnit = PricePerUnit from Price_Base_AICredits_Rate with (nolock)     
        where ParentID in (@parentId, 0) and type = 'TextChat' order by ParentID desc    
    
    declare @cost decimal(18, 4), @creditUsed int  = 0;    
    
    select @creditUsed = CEILING(@totalTokens/cast(@UnitPerCredit as float))    
    select @cost = cast((@creditUsed* @PricePerUnit) as float)    
    
    declare @remarks nvarchar(max) = concat(N'Amount ', cast(@cost as nvarchar(25)), ' debited for ', cast(@creditUsed as nvarchar(5)),     
        ' AI Credits for ', cast(@totalTokens as nvarchar(25)),    
        ' Tokens Used for '+ @entitydetails, N' by Agent ', @agentName,      
        ' on date ', format(getutcdate(), 'dd-MMM-yyyy HH:mm:ss'))    
    
    
    declare @intCreditId bigint = 0    
    
    
    exec usp_remote_deduct_or_refund_int_bal_withOutput    
        @parentid = @parentId,    
        @m_id = @mid,    
        @cost_in_inr_credit = 0,    
        @cost_in_inr_debit = @cost,    
        @credit_type = 23, -- AI credit    
        @remarks = @remarks,    
        @intCredId = @intCreditId output    
    
    update tbl_ai_TokenUsages set IntCreditId = @intCreditId where TokenUseageId = @tokenUsageId    
    
     
end 


GO

/* ============================================================
   Procedure: [dbo].[usp_AI_DelOrDupKnowledgeBase]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON



CREATE   PROC usp_AI_DelOrDupKnowledgeBase
(
    @KbId bigint,
    @UserId bigint,
    @Mode varchar(10) -- 'Delete' -- Duplicate
)
AS
Begin

    If(@Mode='Delete')
    Begin
        update tbl_ai_KnowledgeBase set IsDeleted=1,DeletedBy=@UserId,DeletedOn=getdate()  Where KbId=@KbId
    End

    If(@Mode='Duplicate')
    Begin

        INSERT INTO [dbo].[tbl_ai_KnowledgeBase]
           ([ParentId],[CompanyId],[Title],[Category],[Content],[DocumentType],[SourceUri],[FileName],[MimeType],[FileSizeBytes],[DocumentVersion]
           ,[Language],[PublishedAt],[ExtractedText],[EmbeddingsJson],[Status],[Tags],[DetailsJson],[CreatedOn],[CreatedBy],[FileMetadataJson])
        select [ParentId],[CompanyId],[Title],[Category],[Content],[DocumentType],[SourceUri],[FileName],[MimeType],[FileSizeBytes],[DocumentVersion]
           ,[Language],[PublishedAt],[ExtractedText],[EmbeddingsJson],'draft' as [Status],[Tags],[DetailsJson], getdate() as [CreatedOn], @UserId as [CreatedBy], [FileMetadataJson]
         From tbl_ai_KnowledgeBase 
         Where KbId=@KbId

         select @KbId=SCOPE_IDENTITY()

         update [tbl_ai_KnowledgeBase] Set [Title]=concat([Title],'_',@KbId) Where KbId=@KbId
    End

End



GO

/* ============================================================
   Procedure: [dbo].[usp_ai_EditVoiceBotCampaign]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


-- =============================================
-- Procedure: Update voice_bot_campaigns
-- =============================================
CREATE   PROCEDURE [dbo].[usp_ai_EditVoiceBotCampaign]
    @campaign_id BIGINT,
    @campaign_name NVARCHAR(MAX) = NULL,
    @campaign_settings NVARCHAR(MAX) = NULL,
    @audience_json NVARCHAR(MAX),
    @campaign_start_date DATETIME = NULL,
    @campaign_end_date DATETIME = NULL,
    @isactive BIT = NULL,
    @last_run DATETIME = NULL,
    @next_run DATETIME = NULL,
    @total_reach INT = NULL
AS
BEGIN
    SET NOCOUNT ON;
    declare @parentid BIGINT

    BEGIN TRY
        IF NOT EXISTS (SELECT 1 FROM voice_bot_campaigns(nolock) WHERE id = @campaign_id)
        BEGIN
            SELECT 0 AS rows_affected, 'Error' AS status, 'Campaign not found' AS message;
            RETURN;
        END
        
        UPDATE voice_bot_campaigns
        SET 
            campaign_name = ISNULL(@campaign_name, campaign_name),
            campaign_settings = ISNULL(@campaign_settings, campaign_settings),
            campaign_start_date = ISNULL(@campaign_start_date, campaign_start_date),
            campaign_end_date = ISNULL(@campaign_end_date, campaign_end_date),
            isactive = ISNULL(@isactive, isactive),
            last_run = ISNULL(@last_run, last_run),
            next_run = ISNULL(@next_run, next_run),
            --days_json = case when ISNULL(@campaign_settings, campaign_settings) is null then days_json else json_query(ISNULL(@campaign_settings, campaign_settings),'$.days') end,
            total_reach = ISNULL(@total_reach, total_reach),
            @parentid=parentid
        WHERE id = @campaign_id;

        if len(@audience_json) >2
        Begin
            --declare @audience_json nvarchar(max)=N'[{"countrycode":91,"mobileno":9876543210,"name":"John Doe","email":"john@example.com","company":"ABC Corp"},{"countrycode":1,"mobileno":1234567890,"name":"Jane Smith","email":"jane@example.com","company":"XYZ Ltd"}]'
            declare @RowData nvarchar(max), @FieldNames nvarchar(max)=''
            declare @SQLString nvarchar(max), @ParmDefinition nvarchar(max), @insAudienceJson nvarchar(max)

            select top 1 @RowData=value From openjson(@audience_json)

            select @FieldNames=@FieldNames+'['+[Key]+'] nvarchar(2000),' from openjson(@RowData)  

            set @FieldNames=SUBSTRING(@FieldNames,1,len(@FieldNames)-1)

            print @FieldNames

            drop table if exists #tmpAudience 

            create table #tmpAudience (id int identity);
            print 'alter table #tmpAudience add ' + @FieldNames
            exec('alter table #tmpAudience add ' + @FieldNames)

            Set @SQLString = N'insert into #tmpAudience select * from openjson(@ImptData) with (' + @FieldNames + ')'                 
            SET @ParmDefinition = N'@ImptData nvarchar(max)';
                  
            print @SQLString
            
            EXECUTE sp_executesql @SQLString, @ParmDefinition, @ImptData = @audience_json

            alter table #tmpAudience add AudienceJson nvarchar(max)
            update t set t.AudienceJson=(select * from #tmpAudience Where id=t.id for json auto)
            from #tmpAudience t

            delete from voice_bot_campaign_audience where vb_campaignid=@campaign_id

            insert into voice_bot_campaign_audience(parentid,vb_campaignid,created_on,recipient_mobile,recipient_countrycode,recipient_has_countrycode,entity_context)
            select @parentid,@campaign_id,GETDATE(), mobileno,iif(CHARINDEX('+',countrycode)>0,countrycode,concat('+',countrycode)),0,AudienceJson
            From #tmpAudience

        End
        
        SELECT @@ROWCOUNT AS rows_affected,'Success' AS status,'Campaign updated successfully' AS message;
    END TRY
    BEGIN CATCH
        SELECT 0 AS rows_affected,'Error' AS status,ERROR_MESSAGE() AS message;
        EXEC USP_INSERTERRORINFO;
    END CATCH
END



GO

/* ============================================================
   Procedure: [dbo].[usp_ai_GenerateEntityjActivity]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_ai_GenerateEntityjActivity](
	@EntityName nvarchar(100),
	@EntityId BIGINT,    
	@UserId BIGINT,    
	@ParentId BIGINT,    
	@EventName NVARCHAR(500),    
	@RefTables NVARCHAR(500),    
	@RefId NVARCHAR(100),
	@MetaData nvarchar(max) = null
)
as
begin
	
	--declare 
	--	@EntityName nvarchar(100),
	--	@EntityId BIGINT,    
	--	@UserId BIGINT,    
	--	@ParentId BIGINT,    
	--	@EventName NVARCHAR(500),    
	--	@RefTables NVARCHAR(500),    
	--	@RefId NVARCHAR(100),
	--	@MetaData nvarchar(max) = ''
	
	--select 
	--	@EntityName=N'lead',
	--	@EntityId=17942629,
	--	@UserId=34594,
	--	@ParentId=34594,
	--	@EventName=N'ai_message_received',
	--	@RefTables=N'tbl_ai_conversations',
	--	@RefId=20641


	declare @isStatus int=0,@Message nvarchar(500)='', @EnventDescription nvarchar(1000)=''

	if(isnull(@EntityName, '') = '' or @EntityId=0 or @UserId=0 or isnull(@EventName,'') = '' )
	begin
		select @isStatus=0,@Message='Invalid input parameters'
	end
	else
	begin
		
		if(@EventName = 'CallEnded')
		begin
			declare @direction nvarchar(50), @callduration int, @callsummary nvarchar(max), @CallDispostion nvarchar(100)

			select @direction = Direction, @callduration = Calldurationseconds, @CallDispostion = customercalldisposition from calllog with (nolock) where id = @RefId
			select @MetaData = additional_details, @callsummary = call_summary from call_summaries with (nolock) where calllog_id = @RefId

			if(@EntityName = 'lead')
			begin
				set @EventName = 'AI Voicebot Ended Call for Lead '
				set @EnventDescription = CONCAT('AI Voicebot ended call for lead. ', 'Call Direction: ', @Direction, ', ', 'Call Dispostion: ', isnull(@CallDispostion, ''), ', ', 
					'Call Duration: ', @CallDuration, ' seconds, ', 'Call Summary: ', ISNULL(@CallSummary, 'NA') );
			end

			if(@EntityName = 'enquiry')
			begin	
				set @EventName = 'AI Voicebot Ended Call for Enquiry'
				set @EnventDescription = CONCAT('AI Voicebot ended call for eqnuiry. ', 'Call Direction: ', @Direction, ', ', 
					'Call Duration: ', @CallDuration, ' seconds, ', 'Call Summary: ', ISNULL(@CallSummary, 'NA') );
			end
		end
		else if(@EventName in ('ai_message_received', 'ai_message_send'))
		begin
			
			if(@EntityName = 'lead')
			begin
				set @EnventDescription = case when @EventName = 'ai_message_received' then 'AI Bot Received message from Lead' 
					when @EventName = 'ai_message_send' then 'AI Bot Sent message to Lead' end
				set @EventName = case when @EventName = 'ai_message_received' then 'AI Bot Received message from Lead' 
					when @EventName = 'ai_message_send' then 'AI Bot Sent message to Lead' end
			end

			if(@EntityName = 'enquiry')
			begin
				set @EnventDescription = case when @EventName = 'ai_message_received' then 'AI Bot Received message from Enquiry' 
					when @EventName = 'ai_message_send' then 'AI Bot Sent message to Enquiry' end
				set @EventName = case when @EventName = 'ai_message_received' then 'AI Bot Received message from Enquiry' 
					when @EventName = 'ai_message_send' then 'AI Bot Sent message to Enquiry' end
				
			end
		end
		else if(@EventName = 'new_data_collected')
		begin

			declare @GoalSlot nvarchar(max), @Timestamp datetime = getdate()

			select @GoalSlot = goalSlotJson from tbl_ai_VisitorsLastResponse with (nolock) 
				where entityName = @EntityName and entityId = @EntityId and parentid = @ParentId

			if(@EntityName = 'lead')
			begin
				set @EnventDescription = case when @EventName = 'new_data_collected' then 'AI collected new data for {EntityType}. Goal Slot: {GoalSlot}, Timestamp: {Timestamp}' end
				set @EventName = case when @EventName = 'ai_message_received' then 'AI Bot Received message from Lead' 
					when @EventName = 'new_data_collected' then 'AI Bot Sent message to Lead' end
			end

			if(@EntityName = 'enquiry')
			begin
				set @EnventDescription = case when @EventName = 'new_data_collected' then 'AI collected new data for {EntityType}. Goal Slot: {GoalSlot}, Timestamp: {Timestamp}' end
				set @EventName = case when @EventName = 'ai_message_received' then 'AI Bot Received message from Enquiry' end
				
			end

			set @EnventDescription = REPLACE(@EnventDescription, '{GoalSlot}', ISNULL(@GoalSlot, 'NA'))
			set @EnventDescription = REPLACE(@EnventDescription, '{Timestamp}', format(@Timestamp, 'dd-MMM-yyyy HH:mm:ss'))
			set @EnventDescription = REPLACE(@EnventDescription, '{EntityType}', @EntityName)
		end


		--print concat('@EventName => ', @EventName)
		--print concat('@EnventDescription => ', @EnventDescription)
		--print concat('@MetaData => ', @MetaData)
		--print concat('@RefId => ', @RefId)
		--print concat('@RefTables => ', @RefTables)
		--print concat('@ParentId => ', @ParentId)
		--print concat('@UserId => ', @UserId)
		--print concat('@EntityId => ', @EntityId)
		--print concat('@EntityName => ', @EntityName)

		if(@EnventDescription <> '')
		begin
			exec UspSaveEntityActivity_withid 
				@entityname = @EntityName,
				@EntityID = @EntityId,
				@UserID = @UserId,
				@ParentID = @ParentId,
				@EventDescription = @EnventDescription,
				@EventName = @EventName,
				@reftables = @RefTables,
				@refid = @RefId
		end
		select @isStatus=1,@Message='Activity logged successfully'

	end

	select @isStatus as Status,@Message as Message
			
end



GO

