/* ============================================================
   Procedure: [dbo].[usp_ai_get_pending_outbox_entries]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_ai_get_pending_outbox_entries]                            
@BatchSize INT = 10,                          
    @MaxRetries INT = 3,                          
    @QueueName NVARCHAR(100) = 'Followup_agent'                          
    AS                            
BEGIN                            
    SET NOCOUNT ON;                            
   select @batchsize=case when  @queuename = 'voice_bot_obd' then 50 else @batchsize end                               
                             
    BEGIN TRAN;                            
    ;WITH cte AS (                            
        SELECT TOP (@BatchSize) id                           
        FROM tbl_ai_agent_execution_outbox WITH (UPDLOCK, READPAST, ROWLOCK)                            
        WHERE queuename = @QueueName                          
        AND isprocessed = 0                          
        AND Processing = 0                          
        AND ISNULL(AttemptCount, 0) < @MaxRetries                        
        and 1=case when queuename = 'voice_bot_obd' and priority>=10 then 1        
        when queuename = 'voice_bot_obd' and (priority=9 Or ( priority=0 and  json_value(payload,'$.campaignId') <>24))                 
        and datepart(HH,getdate()) between 10 and 20 then 1                      
        when queuename = 'voice_bot_obd' and priority=0 and  json_value(payload,'$.campaignId') =24             
        and datepart(HH,getdate()) between 15 and 18 then 1                         
        else 0 end                        
    ORDER BY priority desc,id                          
    )                            
    UPDATE a                            
    SET Processing = 1,                            
        ProcessingStartedAt = getdate(),                            
        AttemptCount = ISNULL(AttemptCount, 0) + 1                            
    OUTPUT inserted.id,inserted.agentid,inserted.queuename,inserted.asstt_id,inserted.payload,                          
        ISNULL(inserted.AttemptCount, 0) AS AttemptCount                          
        from tbl_ai_agent_execution_outbox a                          
    JOIN cte ON a.Id = cte.Id;                            
                                
    COMMIT;                            
END 


GO

