/* ============================================================
   Procedure: [dbo].[usp_ai_GetAgentApiKeyByAgentId]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE dbo.usp_ai_GetAgentApiKeyByAgentId
    @AgentId BIGINT,
    @UserId BIGINT
AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @ParentId BIGINT;
    -- Determine ParentId based on UserId
    IF(ISNULL(@UserId, 0) > 0)
    BEGIN
        SET @ParentId = dbo.ufn_getuserparentid(@UserId);
    END
    ELSE
    BEGIN
        SET @ParentId = NULL;
    END

    SELECT TOP (1)
        AgentApiKeyId,
        AgentId,
        ApiKeyHash as [PlainApiKey],
        Name,
        ExpiresAt,
        DetailsJson,
        CreatedBy,
        IsActive,
        CreatedOn
    FROM dbo.tbl_ai_AgentApiKeys with (nolock)
    WHERE AgentId = @AgentId
      AND ParentId = @ParentId
      AND IsActive = 1
      AND ISNULL(IsDeleted, 0) = 0
      AND (ExpiresAt IS NULL OR ExpiresAt > GETUTCDATE())
    ORDER BY CreatedOn DESC;
END;



GO

/* ============================================================
   Procedure: [dbo].[usp_ai_GetAgentDetailsByApiKey]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.usp_ai_GetAgentDetailsByApiKey (
    @ApiKey NVARCHAR(400)
)
AS
BEGIN
    SET NOCOUNT ON;
    
    -- DECLARE 
    --     @ApiKey NVARCHAR(400) = N'ai-studio_r25dclFDYwMEMRefRTs9Wldc_mi72oscr'

    DECLARE 
        @ParentId BIGINT, @AgentId BIGINT

    select @ParentId = ParentId, @AgentId = AgentId from dbo.tbl_ai_AgentApiKeys with (nolock)
    where ApiKeyHash COLLATE Latin1_General_CS_AS = @ApiKey COLLATE Latin1_General_CS_AS
        and IsActive = 1 and ISNULL(IsDeleted, 0) = 0 and (ExpiresAt IS NULL OR ExpiresAt > GETUTCDATE())

    IF(@AgentId IS NOT NULL)
    BEGIN
        SELECT 
            a.AgentId,
            a.Name AS AgentName,
            a.Email,
            a.Role,
            a.Status,
            a.IsBot,
            a.CreatedOn,
            a.ModifiedOn,
            a.CompanyId,
            w.WidgetId,
            w.AssistantName,
            w.DetailsJson AS WidgetDetailsJson
        FROM dbo.tbl_ai_Agents a WITH (NOLOCK)
        LEFT JOIN dbo.tbl_ai_WidgetSettings w WITH (NOLOCK) ON a.AgentId = w.AgentId
        WHERE a.AgentId = @AgentId AND a.ParentId = ISNULL(@ParentId, 0) AND a.IsDeleted = 0;
    END
END;



GO

/* ============================================================
   Procedure: [dbo].[usp_ai_GetAgentDetailsForPrompt]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE usp_ai_GetAgentDetailsForPrompt(
    @UserId bigint,
    @AgentId bigint
)
as
begin
    
    declare @ParentId bigint = 0;
    set @ParentId = dbo.ufn_getuserparentid(@UserId);

    select 
    a.AgentId,
    case when ISJSON(c.DetailsJson) = 1 
         then JSON_QUERY(c.DetailsJson) 
         else '{}' end as companyDetailJson,
    case when ISJSON(a.DetailsJson) = 1 
         then JSON_QUERY(a.DetailsJson) 
         else '{}' end as basicDetailJson,
    case when ISJSON(g.DetailsJson) = 1 
         then JSON_QUERY(g.DetailsJson) 
         else '{}' end as goalDetailJson,
    case when ISJSON(w.DetailsJson) = 1 
         then JSON_QUERY(w.DetailsJson) 
         else '{}' end as widgetDetailJson,
    case when ISJSON(p.DetailsJson) = 1 
         then JSON_QUERY(p.DetailsJson) 
         else '{}' end as promptDetailJson
from tbl_ai_Agents a with (nolock)
    left join tbl_ai_Companies c with (nolock) on c.CompanyId = a.CompanyId
    left join tbl_ai_Goals g with (nolock) on a.AgentId = g.AgentId
    left join tbl_ai_WidgetSettings w with (nolock) on w.AgentId = a.AgentId
    left join tbl_ai_Personas p with (nolock) on p.AgentId = a.AgentId
where a.AgentId = @AgentId 
  and a.ParentId = @ParentId
--for json path, without_array_wrapper;

end



GO

/* ============================================================
   Procedure: [dbo].[usp_ai_GetAgentList]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_ai_GetAgentList  
    @UserId bigint = 0 -- optional: used to scope to user's parent  
as  
begin  
    set nocount on;  
  
    declare @ParentId bigint = NULL;  
    if @UserId > 0  
        set @ParentId = dbo.ufn_getuserparentid(@UserId);  

     
    DECLARE @tblChatBots as table ( Id bigint,  IsActive bit, IsDefault bit, aiAgentId bigint )

    insert into @tblChatBots (Id, IsActive, IsDefault, aiAgentId)
    select id,isactive, is_default, aiAgentId from [10.0.0.135].MySMSConversations.dbo.tbl_ims_DailogflowCredentials with (nolock)
        where ParentId = @ParentId and DialogflowType = 'aistudio' and isnull(aiAgentId, 0) > 0
  
    select  
        a.AgentId,  
        a.Name,  
        a.Email,  
        a.Role,  
        a.Status,  
        a.IsBot,  
        a.CreatedOn,  
        a.ModifiedOn,  
        a.CompanyId,  
        c.Name as CompanyName,
        cast(isnull(b.IsActive, 0) as bit)  as [waIsActive],
        cast(isnull(b.IsDefault, 0) as bit) as [waIsDefault]
    from dbo.tbl_ai_Agents a  
    left join dbo.tbl_ai_Companies c on c.CompanyId = a.CompanyId  
    left join @tblChatBots b on a.AgentId = b.aiAgentId
    where  
        a.IsDeleted = 0  
        and a.ParentId = @ParentId
    order by a.Name;  
end  



