/* ============================================================
   Procedure: [dbo].[usp_ai_GetAgentsByMode]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_ai_GetAgentsByMode]
    @Mode NVARCHAR(50),
    @UserId BIGINT = NULL, -- Optional filter by UserId
    @AgentId BIGINT = NULL -- Optional filter by AgentId
AS
BEGIN

    
    --DECLARE
    --    @Mode NVARCHAR(50) = N'emailConfig',
    --    @UserId BIGINT = 34594, -- Optional filter by UserId
    --    @AgentId BIGINT = 230 -- Optional filter by AgentId

    SET NOCOUNT ON;
 
    DECLARE @ParentId BIGINT = NULL;
    IF @UserId IS NOT NULL AND @UserId > 0
        SET @ParentId = dbo.ufn_getuserparentid(@UserId);
 
    IF @Mode = 'basic'
    BEGIN
        SELECT a.AgentId, a.CompanyId, a.Name, a.Email, a.Role, a.Status, a.IsBot, a.DetailsJson, a.CreatedOn, a.ModifiedOn, a.is_predefined,
            p.id as [predefined_agent_id], p.agent_name as [predefined_agent_name]
        FROM
            dbo.tbl_ai_Agents a with (nolock)
            left join tbl_predefined_agents p with (nolock) on a.predefined_agentid = p.id
        WHERE
            a.IsDeleted = 0 AND a.ParentId = ISNULL(@ParentId, 0) and a.AgentId = @AgentId
 
        ORDER BY
            a.Name;
    END
    ELSE IF @Mode = 'goal'
    BEGIN
        SELECT a.AgentId, a.CompanyId, a.Name, g.DetailsJson, g.GoalId, g.Title AS GoalTitle, g.Type AS GoalType, g.Target AS GoalTarget, a.is_predefined
        FROM
            dbo.tbl_ai_Agents a with (nolock)
        LEFT JOIN
            dbo.tbl_ai_Goals g with (nolock) ON a.AgentId = g.AgentId
        WHERE
            a.IsDeleted = 0 AND a.ParentId = ISNULL(@ParentId, 0)  and a.AgentId = @AgentId
        ORDER BY
            a.Name, g.Title;
    END
    ELSE IF @Mode = 'widget'
    BEGIN
        SELECT
            a.AgentId,
            a.CompanyId,
            a.Name,
            w.DetailsJson,
            w.WidgetId,
            w.AssistantName,
            w.PrimaryColor,
            w.DefaultChannel,
            a.is_predefined
        FROM
            dbo.tbl_ai_Agents a with (nolock)
        LEFT JOIN
            dbo.tbl_ai_WidgetSettings w with (nolock) ON a.AgentId = w.AgentId
        WHERE
            a.IsDeleted = 0 AND a.ParentId = ISNULL(@ParentId, 0) and a.AgentId = @AgentId
        ORDER BY
            a.Name, w.AssistantName;
    END
    ELSE IF @Mode = 'prompt'
    BEGIN
        SELECT
            a.AgentId,
            a.CompanyId,
            a.Name,
            p.PersonaId,
            p.DetailsJson,
            a.is_predefined
        FROM
            dbo.tbl_ai_Agents a with (nolock)
        LEFT JOIN
            dbo.tbl_ai_Personas p with (nolock) ON a.AgentId = p.AgentId
        WHERE
            a.IsDeleted = 0 AND a.ParentId = ISNULL(@ParentId, 0) and a.AgentId = @AgentId
    END
    ELSE IF @Mode = 'trigger'
    BEGIN
        SELECT
            a.AgentId,
            a.CompanyId,
            a.Name,
            t.DetailsJson,
            t.TriggerId,
            t.Name AS TriggerName,
            t.Event,
            t.IsEnabled,
            a.is_predefined
        FROM
            dbo.tbl_ai_Agents a with (nolock)
        LEFT JOIN
            dbo.tbl_ai_Triggers t with (nolock) ON a.AgentId = t.AgentId
        WHERE
            a.IsDeleted = 0 AND a.ParentId = ISNULL(@ParentId, 0) and a.AgentId = @AgentId
        ORDER BY
            a.Name, t.Name;
    END
   ELSE IF @Mode = 'triggerTest'
   BEGIN
        SELECT
            a.AgentId,
            a.CompanyId,
            a.Name,
            JSON_MODIFY(
                COALESCE(a.DetailsJson, '{}'),
                '$.triggers',
                JSON_QUERY((
                        SELECT
                            t.TriggerId AS TriggerId,
                            t.Name AS TriggerName,
                            t.Event,
                            t.IsEnabled,
                            CASE
                                WHEN ISJSON(cleaned.CleanVal) = 1 THEN JSON_QUERY(cleaned.CleanVal)
                                ELSE cleaned.CleanVal
                            END AS TriggerDetails
                        FROM dbo.tbl_ai_Triggers t
                        CROSS APPLY (SELECT REPLACE(t.DetailsJson, '\\u0022', '\"') AS Replaced) r
                        CROSS APPLY (SELECT CASE WHEN LEFT(LTRIM(r.Replaced), 1) = '\"' AND RIGHT(RTRIM(r.Replaced), 1) = '\"' THEN SUBSTRING(r.Replaced, 2, LEN(r.Replaced) - 2) ELSE r.Replaced END) cleaned(CleanVal)
                        WHERE t.AgentId = a.AgentId
                        FOR JSON PATH
                    )
                )
            ) AS DetailsJson,
            (SELECT COUNT(1) FROM dbo.tbl_ai_Triggers t2 WHERE t2.AgentId = a.AgentId) AS TriggerCount,
            a.is_predefined
        FROM dbo.tbl_ai_Agents a WITH (NOLOCK)
        WHERE a.IsDeleted = 0
          AND a.ParentId = ISNULL(@ParentId, 0)
          AND a.AgentId = @AgentId
        ORDER BY a.Name;
    END
	else  IF LOWER(@Mode) = 'agentinstruction'
    BEGIN
        SELECT
            a.AgentId,
            --a.AgentName,
            a.AgentInstruction as DetailsJson,
            a.is_predefined
        FROM dbo.tbl_ai_Agents a
        WHERE (@AgentId IS NULL OR a.AgentId = @AgentId)
          --AND (@CompanyId IS NULL OR a.CompanyId = @CompanyId);
        RETURN;
    END IF (lower(@Mode) = 'emailconfig')
    BEGIN
        PRINT CONCAT('@Mode => ', @Mode)
         SELECT a.AgentId, a.CompanyId, a.Name, a.Email, a.Role, a.Status, a.IsBot, a.predefined_settings as [DetailsJson], a.CreatedOn, a.ModifiedOn, a.is_predefined,
            p.id as [predefined_agent_id], p.agent_name as [predefined_agent_name]
        FROM
            dbo.tbl_ai_Agents a with (nolock)
            left join tbl_predefined_agents p with (nolock) on a.predefined_agentid = p.id
        WHERE
            a.IsDeleted = 0 AND a.ParentId = ISNULL(@ParentId, 0) and a.AgentId = @AgentId
    END
    ELSE
    BEGIN
        -- Invalid mode
        RAISERROR ('Invalid mode specified. Valid modes are: basic, goal, widget, prompt, trigger.', 16, 1);
        RETURN;
    END

END



GO

