/* ============================================================
   Procedure: [dbo].[usp_ai_GetBotCallDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- Get all calls for a bot (first page)
-- EXEC usp_ai_GetBotCallDetails @BotId = 7, @Status = 'all', @OffsetValue = 0, @PageSize = 20;

-- Get only successful calls
-- EXEC usp_ai_GetBotCallDetails @BotId = 7, @Status = 'success', @OffsetValue = 0, @PageSize = 20;

-- Get only failed calls
-- EXEC usp_ai_GetBotCallDetails @BotId = 7, @Status = 'failure', @OffsetValue = 0, @PageSize = 20;

-- Get only failed calls with date filter
-- EXEC usp_ai_GetBotCallDetails @BotId = 7, @Status = 'failure', @FromDate = '2026-01-01', @ToDate = '2026-03-31';

-- Search by mobile number
-- EXEC usp_ai_GetBotCallDetails @BotId = 7, @MobileNo = '7840002738', @Status = 'all';

CREATE   PROCEDURE usp_ai_GetBotCallDetails
(
    @BotId BIGINT,
    @Status NVARCHAR(20) = 'all',
    @FromDate DATETIME = NULL,
    @ToDate DATETIME = NULL,
    @MobileNo NVARCHAR(50) = NULL,
    @OffsetValue INT = 0,
    @PageSize INT = 20
)
AS
BEGIN
    SET NOCOUNT ON;

    -- [Validation code same as before]
    IF @OffsetValue < 0 SET @OffsetValue = 0;
    IF @PageSize <= 0 SET @PageSize = 20;
    SET @Status = LOWER(LTRIM(RTRIM(ISNULL(@Status, 'all'))));

    Declare @GoalSlotSettings nvarchar(max)

    select @GoalSlotSettings=GoalSlotSettings from voice_bot_details(nolock) Where id=@BotId

    DECLARE @TotalRecords INT;
    
    SELECT @TotalRecords = COUNT(*)
    FROM dbo.calllog CL WITH (NOLOCK)
    WHERE CL.bot_id = @BotId
        AND CL.reftable = 'twiliocalls'
        AND (@FromDate IS NULL OR CL.Callstarttime >= @FromDate)
        AND (@ToDate IS NULL OR CL.Callstarttime <= @ToDate)
        AND (@MobileNo IS NULL OR CL.CustomerNumber LIKE '%' + @MobileNo + '%')
        AND (
            @Status = 'all'
            OR (@Status = 'success' AND CL.customercalldisposition IN ('Answer', 'ANSWERED'))
            OR (@Status = 'failure' AND (CL.customercalldisposition NOT IN ('Answer', 'ANSWERED') OR CL.customercalldisposition IS NULL))
        );

    -- Return raw JSON for flexible client-side parsing
    SELECT 
        ROW_NUMBER() OVER (ORDER BY CL.Callstarttime DESC) AS RowNum,
        @TotalRecords AS TotalRecords,
        CL.ID AS CallLogId,
        CL.CustomerNumber AS MobileNo,
        CL.Direction,
        CL.Callstarttime AS CallStartTime,
        CL.CallEndTime,
        CL.Calldurationseconds AS DurationSeconds,
        CONCAT(
            CL.Calldurationseconds / 60, 'm ', 
            CL.Calldurationseconds % 60, 's'
        ) AS DurationFormatted,
        CL.customercalldisposition AS CallDisposition,
        CL.agentcalldisposition AS AgentDisposition,
        CASE 
            WHEN CL.customerentity = 'lead' THEN UL.PersonName
            WHEN CL.customerentity = 'enquiry' THEN UE.PersonName
            ELSE NULL
        END AS PersonName,
        @GoalSlotSettings as GoalSlotSettings,
        CL.customerentity AS EntityType,
        CL.customerentityid AS EntityId,
        CL.recordurl AS RecordingUrl,
        CS.Call_Summary,
        -- Return entire JSON for flexible parsing
        CS.Additional_Details AS CallAnalytics,
        CASE 
            WHEN CL.customercalldisposition IN ('Answer', 'ANSWERED') THEN 'Success'
            ELSE 'Failure'
        END AS CallStatus
    FROM dbo.calllog CL WITH (NOLOCK)
    LEFT JOIN dbo.UserLeads UL WITH (NOLOCK)
        ON CL.customerentity = 'lead' 
        AND CL.customerentityid = UL.Id
    LEFT JOIN dbo.UserEnquiry UE WITH (NOLOCK)
        ON CL.customerentity = 'enquiry'
        AND CL.customerentityid = UE.EnquiryID
    LEFT JOIN dbo.call_summaries CS WITH (NOLOCK)
        ON CL.ID = CS.Calllog_id
    WHERE CL.bot_id = @BotId
        AND CL.reftable = 'twiliocalls'
        AND (@FromDate IS NULL OR CL.Callstarttime >= @FromDate)
        AND (@ToDate IS NULL OR CL.Callstarttime <= @ToDate)
        AND (@MobileNo IS NULL OR CL.CustomerNumber LIKE '%' + @MobileNo + '%')
        AND (
            @Status = 'all'
            OR (@Status = 'success' AND CL.customercalldisposition IN ('Answer', 'ANSWERED'))
            OR (@Status = 'failure' AND (CL.customercalldisposition NOT IN ('Answer', 'ANSWERED') OR CL.customercalldisposition IS NULL))
        )
    ORDER BY CL.Callstarttime DESC
    OFFSET @OffsetValue ROWS 
    FETCH NEXT @PageSize ROWS ONLY;

END



GO

/* ============================================================
   Procedure: [dbo].[usp_ai_GetBotPerformanceSummary]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- Exec usp_ai_GetBotPerformanceSummary @ParentId=34594, @BotId=0
-- Exec usp_ai_GetBotPerformanceSummary @ParentId=34594, @BotId=7
CREATE   PROC usp_ai_GetBotPerformanceSummary
(
    @ParentId bigint,
    @BotId bigint
)
AS
Begin
    -- declare @ParentId bigint=34594
    SELECT 
        VB.id as BotId,
        VB.Bot_name,
        COUNT(*) AS TotalCalls,
        SUM(CASE 
            WHEN CL.customercalldisposition IN ('Answer', 'ANSWERED') THEN 1 
            ELSE 0 
        END) AS SuccessfulCalls,
        SUM(CASE 
            WHEN CL.customercalldisposition NOT IN ('Answer', 'ANSWERED') 
                OR CL.customercalldisposition IS NULL 
            THEN 1 
            ELSE 0 
        END) AS FailedCalls,
        AVG(ISNULL(CL.Calldurationseconds, 0)) AS AvgCallTimeSeconds,
        CONCAT(
            AVG(ISNULL(CL.Calldurationseconds, 0)) / 60, 'm ', 
            AVG(ISNULL(CL.Calldurationseconds, 0)) % 60, 's'
        ) AS AvgCallTimeFormatted
    FROM dbo.voice_bot_details VB WITH (NOLOCK) INNER JOIN dbo.calllog CL WITH (NOLOCK)
    ON VB.id = CL.bot_id
    WHERE CL.reftable = 'twiliocalls' AND VB.parentid = @ParentId and VB.id=case when @BotId=0 then VB.id else @BotId end
    GROUP BY VB.Bot_name, VB.id
    ORDER BY TotalCalls DESC;
End



GO

