/* ============================================================
   Procedure: [dbo].[usp_ai_GetCampaignAudienceResults]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- Get all results (first page)
-- EXEC usp_ai_GetCampaignAudienceResults @CampaignId = 24, @Status = 'all', @OffsetValue = 0, @PageSize = 20;

-- Get only failures
-- EXEC usp_ai_GetCampaignAudienceResults @CampaignId = 24, @Status = 'failure';

-- Get only successful calls
-- EXEC usp_ai_GetCampaignAudienceResults @CampaignId = 24, @Status = 'success';

-- Search by mobile number with date range
-- EXEC usp_ai_GetCampaignAudienceResults @CampaignId = 24, @MobileNo = '9443167133', @FromDate = '2026-01-01', @ToDate = '2026-03-31', @Status = 'success';

-- Get second page of results
-- EXEC usp_ai_GetCampaignAudienceResults @CampaignId = 24, @OffsetValue = 20, @PageSize = 20;

CREATE   PROCEDURE usp_ai_GetCampaignAudienceResults
(
    @CampaignId BIGINT,
    @FromDate DATETIME = NULL,
    @ToDate DATETIME = NULL,
    @MobileNo NVARCHAR(50) = NULL,
    @Status NVARCHAR(20) = 'all',
    @OffsetValue INT = 0,
    @PageSize INT = 20
)
AS
BEGIN
    SET NOCOUNT ON;

    -- Validate paging parameters
    IF @OffsetValue < 0 SET @OffsetValue = 0;
    IF @PageSize <= 0 SET @PageSize = 20;

    -- Normalize status parameter
    SET @Status = LOWER(LTRIM(RTRIM(ISNULL(@Status, 'all'))));

    -- Get total count FIRST (more efficient than window function)
    DECLARE @TotalRecords INT;
    
    SELECT @TotalRecords = COUNT(*)
    FROM dbo.voice_bot_campaign_audience CA WITH (NOLOCK)
    LEFT JOIN dbo.voice_bot_campaign_execution CE WITH (NOLOCK)
        ON CA.execution_batchid = CE.id
    WHERE CA.vb_campaignid = @CampaignId
        AND (@FromDate IS NULL OR CA.executed_on >= @FromDate)
        AND (@ToDate IS NULL OR CA.executed_on <= @ToDate)
        AND (@MobileNo IS NULL OR CA.recipient_mobile LIKE '%' + @MobileNo + '%')
        AND (
            @Status = 'all'
            OR (@Status = 'success' AND CA.last_error IS NULL AND CE.last_error IS NULL)
            OR (@Status = 'failure' AND (CA.last_error IS NOT NULL OR CE.last_error IS NOT NULL))
        );

    -- Get paginated results
    SELECT 
        ROW_NUMBER() OVER (ORDER BY CA.executed_on DESC) AS RowNum,
        @TotalRecords AS TotalRecords,
        CONCAT(CA.recipient_countrycode, ' ', CA.recipient_mobile) AS MobileNo,
        CA.executed_on,
        COALESCE(CA.last_error, CE.last_error, '') AS Remarks,
        CASE 
            WHEN CA.last_error IS NULL AND CE.last_error IS NULL THEN 'Success'
            ELSE 'Failure'
        END AS CallStatus
    FROM dbo.voice_bot_campaign_audience CA WITH (NOLOCK)
    LEFT JOIN dbo.voice_bot_campaign_execution CE WITH (NOLOCK)
        ON CA.execution_batchid = CE.id
    WHERE CA.vb_campaignid = @CampaignId
        AND (@FromDate IS NULL OR CA.executed_on >= @FromDate)
        AND (@ToDate IS NULL OR CA.executed_on <= @ToDate)
        AND (@MobileNo IS NULL OR CA.recipient_mobile LIKE '%' + @MobileNo + '%')
        AND (
            @Status = 'all'
            OR (@Status = 'success' AND CA.last_error IS NULL AND CE.last_error IS NULL)
            OR (@Status = 'failure' AND (CA.last_error IS NOT NULL OR CE.last_error IS NOT NULL))
        )
    ORDER BY CA.executed_on DESC
    OFFSET @OffsetValue ROWS 
    FETCH NEXT @PageSize ROWS ONLY;

END



GO

