/* ============================================================
   Procedure: [dbo].[usp_ai_GetCampaignStats]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- Get first page (records 1-50)
-- EXEC usp_ai_GetCampaignStats @ParentId=34594, @PageNumber=1, @PageSize=50

-- Get second page (records 51-100)
-- EXEC usp_ai_GetCampaignStats @ParentId=34594, @PageNumber=2, @PageSize=50

-- Get first 25 records
-- EXEC usp_ai_GetCampaignStats @ParentId=34594, @PageNumber=1, @PageSize=25
CREATE   PROC usp_ai_GetCampaignStats
(
    @ParentId BIGINT,
    @PageNumber INT = 1,
    @PageSize INT = 50
)
AS
BEGIN
    SET NOCOUNT ON;

    -- Validate parameters
    IF @PageNumber < 1 SET @PageNumber = 1;
    IF @PageSize < 1 SET @PageSize = 50;

    -- Calculate offset
    DECLARE @Offset INT = (@PageNumber - 1) * @PageSize;

    -- Get total count for paging metadata
    DECLARE @TotalRecords INT;
    
    SELECT @TotalRecords = COUNT(DISTINCT CA.vb_campaignid)
    FROM dbo.voice_bot_campaign_audience CA WITH (NOLOCK)
    WHERE CA.parentid = @ParentId;

    -- Main query with paging
    SELECT 
        CA.parentid,
        CA.vb_campaignid,
        VBC.Campaign_Name,
        COUNT(DISTINCT CA.id) AS TotalMsg,
        SUM(CASE WHEN CA.last_error IS NULL AND CE.Last_error IS NULL THEN 1 ELSE 0 END) AS SuccessMsgCnt,
        SUM(CASE WHEN CA.last_error IS NOT NULL OR CE.Last_error IS NOT NULL THEN 1 ELSE 0 END) AS FailedMsgCnt,
        MIN(CA.created_on) AS first_created,
        MAX(CA.created_on) AS last_created,
        MIN(CA.executed_on) AS first_executed,
        MAX(CA.executed_on) AS last_executed,
        @TotalRecords AS TotalRecords,
        @PageNumber AS CurrentPage,
        @PageSize AS PageSize,
        CEILING(CAST(@TotalRecords AS FLOAT) / @PageSize) AS TotalPages
    FROM dbo.voice_bot_campaign_audience CA WITH (NOLOCK) 
    LEFT JOIN dbo.voice_bot_campaign_execution CE WITH (NOLOCK)
        ON CA.execution_batchid = CE.id 
    LEFT JOIN dbo.voice_bot_campaigns VBC WITH (NOLOCK)
        ON CA.vb_campaignid = VBC.id
    WHERE CA.parentid = @ParentId
    GROUP BY CA.parentid, CA.vb_campaignid, VBC.Campaign_Name
    ORDER BY CA.parentid, CA.vb_campaignid
    OFFSET @Offset ROWS
    FETCH NEXT @PageSize ROWS ONLY;

END



GO

/* ============================================================
   Procedure: [dbo].[usp_ai_GetChatHistoryByVisitorId]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


-- Exec usp_ai_GetChatHistoryByVisitorId @VisitorId=2932,@UserId=34594,@entityName='Lead',@entityId=17942629 
CREATE   PROCEDURE [dbo].[usp_ai_GetChatHistoryByVisitorId]  
    @VisitorId BIGINT,  
    @UserId BIGINT,  
    @entityName nvarchar(25),  
    @entityId bigint  
AS  
BEGIN  
    SET NOCOUNT ON;  
  -- declare @VisitorId BIGINT=2932,@UserId BIGINT=34594,@entityName nvarchar(25)='Lead',@entityId bigint=17942629  
  -- declare @VisitorId BIGINT=2,@UserId BIGINT=34594,@entityName nvarchar(25)='Lead',@entityId bigint=7301709  


    DECLARE @ParentId BIGINT = 0;  
    SET @ParentId = dbo.ufn_getuserparentid(@UserId);  
      
  
    SELECT   
        ConversationId,   
        '{}' as [Sender],  
        '' as 'text',  
        c.DetailsJson,  
        c.CreatedOn,  
        direction as [Direction]  
    FROM tbl_ai_Conversations c WITH (NOLOCK)  
          
    WHERE --v.VisitorId = @VisitorId  
        c.entityName = @entityName and c.EntityId = @entityId  
      AND c.ParentId = @ParentId   

      union all

      select RowId as ConversationId,   
        '{}' as [Sender],  
        '' as 'text',  
        DetailsJson,  
        CreatedOn,  
        'Activity' as [Direction]  
      from tbl_ai_VisitorActionHistory(nolock) 
      WHERE entityName = @entityName and EntityId = @entityId  
      order by c.CreatedOn asc;

END  



