/* ============================================================
   Procedure: [dbo].[usp_ai_GetCompanyAndKbByParentId]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_ai_GetCompanyAndKbByParentId](
	@url nvarchar(255),
	@ParentId bigint
)
as
begin	
	
	--DECLARE 
 --       @url nvarchar(255) = 'https://crlsolar.in/',
 --       @ParentId bigint = 47918;

    DECLARE @companyJson NVARCHAR(MAX) = N'{}'

    -- Clean @url to extract domain only
    DECLARE @CleanUrl nvarchar(255) =
    (
        SELECT REPLACE(
                    REPLACE(
                        REPLACE(
                            CASE 
                                WHEN CHARINDEX('/', @url, 9) > 0 
                                    THEN SUBSTRING(@url, 1, CHARINDEX('/', @url, 9) - 1)
                                ELSE @url
                            END,
                        'https://', ''),
                    'http://', ''),
                'www.', '')
    );

    print concat('@CleanUrl => ', @CleanUrl)

    print ' www.crlsolar.in'

    SET @companyJson = (
        SELECT TOP 1 
            JSON_QUERY(ai_response_json, '$.companyForm') AS company,
            JSON_QUERY(ai_response_json, '$.knowledgeBaseForm') AS knowledgeBase
        FROM ai_profile_enrichment WITH (NOLOCK)
        WHERE parentid = @ParentId
          AND dbo.fn_ExtractDomainWithWWW(trim(website)) = dbo.fn_ExtractDomainWithWWW(@CleanUrl)
        ORDER BY id DESC FOR JSON PATH, WITHOUT_ARRAY_WRAPPER
    )

    SELECT @companyJson AS [companyDetails]

end



