SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE dbo.usp_ai_GetCompanyListByUserId
    @UserId BIGINT
AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @ParentId BIGINT = dbo.ufn_getuserparentid(@UserId);

    SELECT CompanyId, Name as [CompanyName]
    FROM
