/* ============================================================
   Procedure: [dbo].[usp_ai_GetConversationChannelCount]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- With full filter
-- EXEC usp_ai_GetConversationChannelCount @ParentId = 34594, @SearchText = N'', @FilterText = N'{"name":"mayank","email":"mayanknigam@gmail.com","phone":"9313943059","channels":["whatsapp","email"],"dateFrom":"2025-12-31","dateTo":"2026-05-01"}',@OffsetValue = 0, @PageSize = 100;
-- With channel filter only
-- EXEC usp_ai_GetConversationChannelCount @ParentId = 34594, @SearchText = N'', @FilterText = N'{"channels":["whatsapp"]}',@OffsetValue = 0, @PageSize = 100;
-- Without filter (backward compatible)
-- EXEC usp_ai_GetConversationChannelCount @ParentId = 34594, @SearchText = N'', @OffsetValue = 0, @PageSize = 100;
CREATE   PROCEDURE usp_ai_GetConversationChannelCount
(
    @ParentId BIGINT,
    @SearchText NVARCHAR(500) = N'',
    @FilterText NVARCHAR(MAX) = NULL,  -- New parameter for JSON filters
    @OffsetValue INT = 0,
    @PageSize INT = 20
)
AS
BEGIN
    SET NOCOUNT ON;

    -- declare @ParentId BIGINT=34594,@SearchText NVARCHAR(500) = N'9313943059',@FilterText NVARCHAR(MAX) = NULL,@OffsetValue INT = 0,@PageSize INT = 20
    -- declare @ParentId BIGINT=34594,@SearchText NVARCHAR(500) = N'pel',@FilterText NVARCHAR(MAX) = NULL,@OffsetValue INT = 0,@PageSize INT = 20
    -- declare @ParentId BIGINT=34594,@SearchText NVARCHAR(500) = N'',@FilterText NVARCHAR(MAX) = NULL,@OffsetValue INT = 0,@PageSize INT = 20
    -- declare @ParentId BIGINT=34594,@SearchText NVARCHAR(500) = N'',@FilterText NVARCHAR(MAX) = '{"channels":["whatsapp"]}',@OffsetValue INT = 0,@PageSize INT = 20

    -- Validate paging parameters
    IF @OffsetValue < 0 SET @OffsetValue = 0;
    IF @PageSize <= 0 SET @PageSize = 20;

    -- Parse JSON filter parameters
    DECLARE @FilterName NVARCHAR(500) = NULL;
    DECLARE @FilterEmail NVARCHAR(500) = NULL;
    DECLARE @FilterPhone NVARCHAR(50) = NULL;
    DECLARE @FilterStatus NVARCHAR(100) = NULL;
    DECLARE @FilterDateFrom DATE = NULL;
    DECLARE @FilterDateTo DATE = NULL;
    DECLARE @FilterMilestone NVARCHAR(100) = NULL;
    DECLARE @FilterGoalSlot NVARCHAR(100) = NULL;
    
    -- Table to hold channel filters
    DECLARE @FilterChannels TABLE (ChannelName NVARCHAR(50));

    -- Parse JSON if provided
    IF @FilterText IS NOT NULL AND ISJSON(@FilterText) = 1
    BEGIN
        -- Extract scalar values
        SELECT 
            @FilterName = JSON_VALUE(@FilterText, '$.name'),
            @FilterEmail = JSON_VALUE(@FilterText, '$.email'),
            @FilterPhone = JSON_VALUE(@FilterText, '$.phone'),
            @FilterStatus = JSON_VALUE(@FilterText, '$.status.value'),
            @FilterDateFrom = TRY_CAST(JSON_VALUE(@FilterText, '$.dateFrom') AS DATE),
            @FilterDateTo = TRY_CAST(JSON_VALUE(@FilterText, '$.dateTo') AS DATE),
            @FilterMilestone = JSON_VALUE(@FilterText, '$.milestone.value'),
            @FilterGoalSlot = JSON_VALUE(@FilterText, '$.goalSlot.value');

        -- Extract channel array
        INSERT INTO @FilterChannels (ChannelName)
        SELECT LOWER(value)
        FROM OPENJSON(@FilterText, '$.channels');
    END


    ;WITH CombinedData AS (
        -- Voice calls
        SELECT 
            CASE 
                WHEN CL.customerentity = 'lead' THEN UL.PersonName
                WHEN CL.customerentity = 'enquiry' THEN UE.PersonName
                ELSE CL.CustomerNumber
            END AS PersonName,
            ISNULL(CL.customerentity, 'Visitor') AS EntityType,
            ISNULL(CL.customerentityid, CL.id) AS EntityId,
            'Voice' AS ChannelType,
            CL.callstartTime as ActionDateTime,
            CASE 
                WHEN CL.customerentity = 'lead' THEN UL.EmailID
                WHEN CL.customerentity = 'enquiry' THEN UE.EmailID
                ELSE NULL 
            END AS Email,
            CL.CustomerNumber AS Phone,
            0 AS IsGoalFulfilled,    
            0 AS IsMilestoneAchieved,    
            0 AS GoalSlotAchievedCount,
            0 AS MilestoneAchievedCount,
            '{}' AS goalSlotJson,    
            '{}' AS mileStoneJson,    
            '' AS csvMilestone,
            '' AS csvGoalSlot,
            0 AS MilestoneCount,    
            0 AS GoalSlotCount
        FROM dbo.calllog CL WITH (NOLOCK)
        LEFT JOIN dbo.UserLeads UL WITH (NOLOCK)
            ON CL.customerentity = 'lead' 
            AND CL.customerentityId = UL.Id
        LEFT JOIN dbo.UserEnquiry UE WITH (NOLOCK)
            ON CL.customerentity = 'enquiry'
            AND CL.customerentityId = UE.EnquiryID
        LEFT JOIN voice_bot_details VB WITH (NOLOCK)
            ON CL.bot_id=VB.id
        WHERE CL.parentid = @ParentId 
            AND CL.reftable = 'twiliocalls'
            AND CL.bot_id IS NOT NULL
            AND (CL.ID = (Case when CL.Direction='Incoming' then CL.ID else 0 end)
            OR CL.ID = (Case when CL.Direction in ('out','Outgoing') and CL.CallEndTime is not null and CL.customercalldisposition in ('Answer','ANSWERED') then CL.ID else 0 end))
            -- Existing search text filter
            AND (
                @SearchText = N'' 
                OR (CL.customerentity = 'lead' AND UL.PersonName LIKE @SearchText + '%')
                OR (CL.customerentity = 'enquiry' AND UE.PersonName LIKE @SearchText + '%')
                OR (CL.CustomerNumber LIKE @SearchText + '%')
                OR (VB.Bot_name LIKE @SearchText + '%')
            )
            -- New JSON filter conditions
            AND (@FilterName IS NULL OR (
                (CL.customerentity = 'lead' AND UL.PersonName LIKE '%' + isnull(@FilterName,'') + '%')
                OR (CL.customerentity = 'enquiry' AND UE.PersonName LIKE '%' + isnull(@FilterName,'') + '%')
            ))
            AND (@FilterEmail IS NULL OR (
                (CL.customerentity = 'lead' AND UL.EmailID LIKE '%' + isnull(@FilterEmail,'') + '%')
                OR (CL.customerentity = 'enquiry' AND UE.EmailID LIKE '%' + isnull(@FilterEmail,'') + '%')
            ))
            AND (@FilterPhone IS NULL OR CL.CustomerNumber LIKE '%' + isnull(@FilterPhone,'') + '%')
            AND (@FilterDateFrom IS NULL OR CAST(CL.callstartTime AS DATE) >= @FilterDateFrom)
            AND (@FilterDateTo IS NULL OR CAST(CL.callstartTime AS DATE) <= @FilterDateTo)
            AND (NOT EXISTS(SELECT 1 FROM @FilterChannels) OR EXISTS(SELECT 1 FROM @FilterChannels WHERE ChannelName = 'voice'))

        UNION ALL

        -- Visitor responses from conversations
        SELECT 
            CASE 
                WHEN v.entityname = 'lead' THEN UL.PersonName
                WHEN v.entityname = 'enquiry' THEN UE.PersonName
                ELSE 'Visitor'
            END AS PersonName,
            ISNULL(v.entityname, 'Visitor') AS EntityType,
            ISNULL(v.entityid, v.id) AS EntityId,
            v.mode AS ChannelType,
            v.createdon as ActionDateTime,
            CASE 
                WHEN v.entityname = 'lead' THEN UL.EmailID
                WHEN v.entityname = 'enquiry' THEN UE.EmailID
                ELSE NULL 
            END AS Email,
            CASE 
                WHEN v.entityname = 'lead' THEN UL.MobileNo
                WHEN v.entityname = 'enquiry' THEN UE.MobileNo
                ELSE NULL 
            END AS Phone,
            v.IsGoalFulfilled,    
            v.IsMilestoneAchieved,    
            ISNULL((SELECT COUNT(*) FROM OPENJSON(v.goalSlotJson)), 0) AS GoalSlotAchievedCount,
            ISNULL((SELECT COUNT(*) FROM OPENJSON(v.mileStoreJson,'$.completedMilestones')), 0) AS MilestoneAchievedCount,
            ISNULL(v.goalSlotJson, '{}') AS goalSlotJson,    
            ISNULL(v.mileStoreJson, '{}') AS mileStoneJson,    
            ISNULL((SELECT STRING_AGG(name, ', ') 
                    FROM tbl_ai_GoalMilestones WITH (NOLOCK)
                    WHERE IsDeleted = 0 
                        AND GoalId IN ((SELECT goalId FROM OPENJSON(v.mileStoreJson) with (goalId int)))), '') AS csvMilestone,
            ISNULL((SELECT STRING_AGG(name, ', ') 
                    FROM tbl_ai_GoalSlots WITH (NOLOCK)
                    WHERE IsDeleted = 0 
                        AND GoalId IN ((SELECT goalId FROM OPENJSON(v.mileStoreJson) with (goalId int)))), '') AS csvGoalSlot,
            ISNULL((SELECT COUNT(*) 
                    FROM tbl_ai_GoalMilestones WITH (NOLOCK)
                    WHERE IsDeleted = 0 
                        AND GoalId IN ((SELECT goalId FROM OPENJSON(v.mileStoreJson) with (goalId int)))), 0) AS MilestoneCount,
            ISNULL((SELECT COUNT(*) 
                    FROM tbl_ai_GoalSlots WITH (NOLOCK)
                    WHERE IsDeleted = 0 
                        AND GoalId IN ((SELECT goalId FROM OPENJSON(v.mileStoreJson) with (goalId int)))), 0) AS GoalSlotCount
        FROM dbo.tbl_ai_VisitorsLastResponse v WITH (NOLOCK)
        LEFT JOIN dbo.UserLeads UL WITH (NOLOCK)
            ON v.entityName = 'lead'
            AND v.entityId = UL.Id
        LEFT JOIN dbo.UserEnquiry UE WITH (NOLOCK)
            ON v.entityName = 'enquiry'
            AND v.entityId = UE.EnquiryID
        WHERE v.ParentId = @ParentId
            -- Existing search text filter
            AND (
                @SearchText = N''
                OR (v.entityname = 'lead' AND UL.PersonName LIKE @SearchText + '%')
                OR (v.entityname = 'enquiry' AND UE.PersonName LIKE @SearchText + '%')
                OR (v.entityname = 'lead' AND UL.MobileNo LIKE @SearchText + '%')
                OR (v.entityname = 'enquiry' AND UE.MobileNo LIKE @SearchText + '%')
            )
            -- New JSON filter conditions
            AND (@FilterName IS NULL OR (
                (v.entityname = 'lead' AND UL.PersonName LIKE '%' + isnull(@FilterName,'') + '%')
                OR (v.entityname = 'enquiry' AND UE.PersonName LIKE '%' + isnull(@FilterName,'') + '%')
            ))
            AND (@FilterEmail IS NULL OR (
                (v.entityname = 'lead' AND UL.EmailID LIKE '%' + isnull(@FilterEmail,'') + '%')
                OR (v.entityname = 'enquiry' AND UE.EmailID LIKE '%' + isnull(@FilterEmail,'') + '%')
            ))
            AND (@FilterPhone IS NULL OR (
                (v.entityname = 'lead' AND UL.MobileNo LIKE '%' + isnull(@FilterPhone,'') + '%')
                OR (v.entityname = 'enquiry' AND UE.MobileNo LIKE '%' + isnull(@FilterPhone,'') + '%')
            ))
            AND (@FilterDateFrom IS NULL OR CAST(v.createdon AS DATE) >= @FilterDateFrom)
            AND (@FilterDateTo IS NULL OR CAST(v.createdon AS DATE) <= @FilterDateTo)
            AND (@FilterMilestone IS NULL OR EXISTS(
                SELECT 1 FROM OPENJSON(v.mileStoreJson) WHERE value = @FilterMilestone
            ))
            AND (@FilterGoalSlot IS NULL OR EXISTS(
                SELECT 1 FROM OPENJSON(v.goalSlotJson) WHERE value = @FilterGoalSlot
            ))
            AND (NOT EXISTS(SELECT 1 FROM @FilterChannels) OR EXISTS(
                SELECT 1 FROM @FilterChannels WHERE ChannelName = LOWER(v.mode)
            ))
    ),
    AggregatedData AS (
        SELECT 
            PersonName,
            EntityType,
            EntityId,
            ChannelType,
            MAX(ActionDateTime) AS LastConversationDate,
            IsGoalFulfilled,    
            IsMilestoneAchieved,    
            GoalSlotAchievedCount,
            MilestoneAchievedCount,
            goalSlotJson,    
            mileStoneJson,    
            csvMilestone,
            csvGoalSlot,
            MilestoneCount,    
            GoalSlotCount,
            COUNT(*) AS Cnt
        FROM CombinedData
        GROUP BY 
            PersonName, EntityType, EntityId, ChannelType,
            IsGoalFulfilled, IsMilestoneAchieved, GoalSlotAchievedCount,
            MilestoneAchievedCount, goalSlotJson, mileStoneJson,
            csvMilestone, csvGoalSlot, MilestoneCount, GoalSlotCount
    ),
    PivotedData AS (
        SELECT 
            PersonName,
            EntityType,
            EntityId,
            Voice,                  
            Email,
            WebChat,
            SMS,
            WhatsApp,
            MAX(LastConversationDate) AS ConversationDate,
            IsGoalFulfilled,    
            IsMilestoneAchieved,    
            GoalSlotAchievedCount,
            MilestoneAchievedCount,
            goalSlotJson,    
            mileStoneJson,    
            csvMilestone,
            csvGoalSlot,
            MilestoneCount,    
            GoalSlotCount
        FROM (
            SELECT 
                PersonName,
                EntityType,
                EntityId,
                ChannelType,
                LastConversationDate,
                IsGoalFulfilled,    
                IsMilestoneAchieved,    
                GoalSlotAchievedCount,
                MilestoneAchievedCount,
                goalSlotJson,    
                mileStoneJson,    
                csvMilestone,
                csvGoalSlot,
                MilestoneCount,    
                GoalSlotCount,
                Cnt
            FROM AggregatedData
        ) AS SourceData
        PIVOT (
            SUM(Cnt)
            FOR ChannelType IN ([Voice], [email], [webchat], [sms], [whatsapp])
        ) AS PivotTable
        GROUP BY  
            PersonName, EntityType, EntityId,
            Voice, Email, WebChat, SMS, WhatsApp,
            IsGoalFulfilled, IsMilestoneAchieved, 
            GoalSlotAchievedCount, MilestoneAchievedCount, 
            goalSlotJson, mileStoneJson, 
            csvMilestone, csvGoalSlot, 
            MilestoneCount, GoalSlotCount
    )
    SELECT 
        ROW_NUMBER() OVER (ORDER BY ConversationDate DESC) AS RowNum,
        COUNT(*) OVER() AS TotalRecords,
        PersonName,
        EntityType,
        EntityId,
        ISNULL([Voice], 0) AS Voice,
        ISNULL([email], 0) AS Email,
        ISNULL([webchat], 0) AS WebChat,
        ISNULL([sms], 0) AS SMS,
        ISNULL([whatsapp], 0) AS WhatsApp,
        ConversationDate,
        IsGoalFulfilled,    
        IsMilestoneAchieved,    
        GoalSlotAchievedCount,
        MilestoneAchievedCount,
        goalSlotJson,    
        mileStoneJson,    
        csvMilestone,
        csvGoalSlot,
        MilestoneCount,    
        GoalSlotCount
    FROM PivotedData
    ORDER BY ConversationDate DESC
    OFFSET @OffsetValue ROWS 
    FETCH NEXT @PageSize ROWS ONLY;

END



GO

