/* ============================================================
   Procedure: [dbo].[usp_AI_GetDashboardStats]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC usp_AI_GetDashboardStats
(
    @ParentId bigint
)
AS
Begin

    -- declare @ParentId bigint=34594

    declare @TotalMsg int=0, @ActiveAgentCnt int=0, @DraftAgentCnt int=0, @HotLead INT=0

    select @ActiveAgentCnt=sum(case when Status='active' then 1 else 0 end),@DraftAgentCnt=sum(case when Status='draft' then 1 else 0 end)
    from tbl_ai_Agents(nolock) 
    Where Parentid=@ParentId and IsDeleted=0


    Select @TotalMsg=count(*) from tbl_ai_Conversations(nolock) Where Parentid=@ParentId and IsDeleted=0

    select @HotLead=count(*) from tbl_ai_VisitorsLastResponse R with(nolock) 
    Where parentid=@ParentId and is_junk=0 and IsOpen=1 and (select count(1) from tbl_ai_Conversations l(nolock) where l.entityname=R.entityname and l.EntityId=R.EntityId and l.createdon>dateadd(d,-7,getdate()))>5


    select  TotalEngaged=Count(id),
            LeadCollected=isnull(sum(case when EntityName='Lead' then 1 else 0 end),0), 
            MilestoneCount=isnull(sum(case when IsMilestoneAchieved=1 then 1 else 0 end),0),
            GoalAchieved=isnull(sum(case when IsGoalFulfilled=1 then 1 else 0 end),0),
            ColdLead=isnull(sum(case when  is_junk=0 and IsOpen=1 and isnull(lastmessage_at,Createdon) < dateadd(d,-7,getdate()) then 1 else 0 end),0),
            JunkLead=isnull(sum(case when is_junk=1 then 1 else 0 end),0),
            OverdueLead=isnull(sum(case when is_junk=0 and IsOpen=1 and isnull(lastmessage_at,Createdon) < GETDATE() then 1 else 0 end),0),
            ActiveConvCnt=isnull(sum(case when datediff(hh,last_customer_response,GETDATE())<=24 then 1 else 0 end),0),
            @TotalMsg as TotalMessages, @ActiveAgentCnt as ActiveAgentCount, @DraftAgentCnt as DraftAgentCount,@HotLead as HotLead
    from tbl_ai_VisitorsLastResponse R with(nolock) 
    Where parentid=@ParentId

End



GO

/* ============================================================
   Procedure: [dbo].[usp_ai_GetEntityConversation]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- Exec usp_ai_GetEntityConversation @ParentId=34594,@EntityType='lead',@EntityId=9470748,@FromDate=null,@ToDate=null
-- Exec usp_ai_GetEntityConversation @ParentId=34594,@EntityType='Enquiry',@EntityId=370729578,@FromDate=null,@ToDate=null
-- Exec usp_ai_GetEntityConversation @ParentId=34594,@EntityType='lead',@EntityId=3093379,@FromDate=null,@ToDate=null
-- Exec usp_ai_GetEntityConversation @ParentId=34594,@EntityType='lead',@EntityId=17942629,@FromDate=null,@ToDate=null
-- Exec usp_ai_GetEntityConversation @ParentId=34594,@EntityType='Enquiry',@EntityId=370436400,@FromDate=null,@ToDate=null
-- Exec usp_ai_GetEntityConversation @ParentId=34594,@EntityType='Visitor',@EntityId=44,@FromDate=null,@ToDate=null
CREATE   PROC usp_ai_GetEntityConversation
(
    @ParentId bigint,
    @EntityType nvarchar(50), -- Options: 'lead', 'enquiry', 'Visitor', or NULL for all
    @EntityId bigint, -- Specific entity ID, or NULL for all
    @FromDate datetime=null, -- Start date, or NULL for no lower bound
    @ToDate datetime=null -- End date, or NULL for no upper bound
)
AS
Begin

--declare @ParentId bigint=34594
--declare @EntityType nvarchar(50)='lead' -- Options: 'lead', 'enquiry', 'Visitor', or NULL for all
--declare @EntityId bigint=17942629 -- Specific entity ID, or NULL for all
--declare @FromDate datetime=null--'2024-01-01' -- Start date, or NULL for no lower bound
--declare @ToDate datetime=null--'2026-12-31' -- End date, or NULL for no upper bound

-- Get all conversations for each channel sorted by date
SELECT 
    PersonName,
    EntityType,
    EntityId,
    ChannelType,
    ConversationDate,
    ConversationId,
    Direction,
    replace(MessagePreview,'\n','') as MessagePreview,
    Status,
    RecordingUrl,
    CallDetails
FROM (
    -- Voice calls
    SELECT 
        CASE 
            WHEN CL.customerentity = 'lead' THEN UL.PersonName
            WHEN CL.customerentity = 'enquiry' THEN UE.PersonName
            ELSE CL.CustomerNumber
        END AS PersonName,
        ISNULL(CL.customerentity, 'Visitor') AS EntityType,
        ISNULL(CL.customerentityid, CL.id) AS EntityId,
        'Voice' AS ChannelType,
        ISNULL(CL.Callstarttime, CL.callcreatedon) AS ConversationDate,
        CL.id AS ConversationId,
        CL.Direction,
        CONCAT(
            'Duration: ', CL.Calldurationseconds, 's    ',
            CASE WHEN CL.agentcalldisposition IS NOT NULL 
                 THEN ' | ' + CL.agentcalldisposition 
                 ELSE '' 
            END,CS.Call_Summary
        ) AS MessagePreview,
        CL.agentcalldisposition AS Status,
        CL.recordurl as RecordingUrl,
        CS.Additional_Details as CallDetails
    FROM dbo.calllog CL WITH (NOLOCK)
    LEFT JOIN dbo.UserLeads UL WITH (NOLOCK) 
        ON CL.customerentity = 'lead' 
        AND CL.customerentityId = UL.Id
    LEFT JOIN dbo.UserEnquiry UE WITH (NOLOCK)
        ON CL.customerentity = 'enquiry'
        AND CL.customerentityId = UE.EnquiryID
    left join call_summaries(nolock) CS
        ON CL.ID=CS.Calllog_id
    WHERE CL.parentid = @ParentId 
        AND CL.reftable = 'twiliocalls'
        AND (@EntityType IS NULL OR ISNULL(CL.customerentity, 'Visitor') = @EntityType)
        AND (@EntityId IS NULL OR ISNULL(CL.customerentityid, CL.id) = @EntityId)
        AND (@FromDate IS NULL OR ISNULL(CL.Callstarttime, CL.callcreatedon) >= @FromDate)
        AND (@ToDate IS NULL OR ISNULL(CL.Callstarttime, CL.callcreatedon) <= @ToDate)

    UNION ALL

    select CASE 
            WHEN v.entityname = 'lead' THEN UL.PersonName
            WHEN v.entityname = 'enquiry' THEN UE.PersonName
            ELSE ''
        END AS PersonName,
        ISNULL(v.entityname, 'Visitor') AS EntityType,
        ISNULL(v.entityid,0) AS EntityId,
        v.Channel AS ChannelType,
        v.createdon AS ConversationDate,
        ConversationId,
        v.direction AS Direction,
        v.DetailsJson AS MessagePreview,
        '' AS Status,
        '' as RecordingUrl,
        '' as CallDetails 
    from tbl_ai_Conversations v WITH (NOLOCK)
    LEFT JOIN dbo.UserLeads UL WITH (NOLOCK)
        ON v.entityName = 'lead'
        AND v.entityId = UL.Id
    LEFT JOIN dbo.UserEnquiry UE WITH (NOLOCK)
        ON v.entityName = 'enquiry'
        AND v.entityId = UE.EnquiryID
    WHERE v.ParentId = @ParentId
        AND (@EntityType IS NULL OR ISNULL(v.entityname, 'Visitor') = @EntityType)
        AND (@EntityId IS NULL OR v.entityid = @EntityId)
        AND (@FromDate IS NULL OR v.createdon >= @FromDate)
        AND (@ToDate IS NULL OR v.createdon <= @ToDate)
) AS AllConversations
ORDER BY /*ChannelType,*/ConversationDate --DESC

END



