/* ============================================================
   Procedure: [dbo].[usp_ai_GetGoalsAndMilestonesByAgentId]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.usp_ai_GetGoalsAndMilestonesByAgentId
    @AgentId BIGINT = NULL,
    @UserId BIGINT = NULL
AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @ParentId BIGINT = NULL;
    IF @UserId IS NOT NULL AND @UserId > 0
        SET @ParentId = dbo.ufn_getuserparentid(@UserId);

    DROP TABLE IF EXISTS #GoalsWithMilestones;
    CREATE TABLE #GoalsWithMilestones (
        WttId BIGINT,
        WttTitle NVARCHAR(200),
        WttCategory NVARCHAR(50)
    );

    INSERT INTO #GoalsWithMilestones (WttId, WttTitle, WttCategory)
    SELECT g.GoalId, g.Title AS GoalTitle, 'Goal'
    FROM dbo.tbl_ai_Goals g WITH (NOLOCK)
     INNER JOIN dbo.tbl_ai_Agents a WITH (NOLOCK) ON g.AgentId = a.AgentId
        WHERE a.ParentId = ISNULL(@ParentId, 0) AND g.AgentId = @AgentId

    INSERT INTO #GoalsWithMilestones (WttId, WttTitle, WttCategory)
    SELECT gm.MilestoneId, gm.Name AS MilestoneName, 'Milestone'
    FROM dbo.tbl_ai_GoalMilestones gm WITH (NOLOCK)
     INNER JOIN dbo.tbl_ai_Goals g WITH (NOLOCK) ON gm.GoalId = g.GoalId
     INNER JOIN dbo.tbl_ai_Agents a WITH (NOLOCK) ON g.AgentId = a.AgentId
        WHERE a.ParentId = ISNULL(@ParentId, 0) AND a.AgentId = @AgentId  
    
    SELECT WttId, WttTitle, WttCategory FROM #GoalsWithMilestones ORDER BY WttCategory, WttTitle;
    
END



