CREATE   PROCEDURE [dbo].[usp_ai_GetGoalsWithSlotsByAgentId_new1]
(
    @AgentId BIGINT
) 
AS 
BEGIN

    SET NOCOUNT ON;
 
--declare  @AgentId BIGINT=211
 
  BEGIN TRY
 
        SELECT
            g.[Name] AS SlotName,
            g.[Label] AS SlotLabel,
            ISNULL(g.DetailsJson, '{}') AS DetailsJson,
            -- try common key casings for datatype and normalize to lower-case for consistency
            LOWER(
                COALESCE(
                    JSON_VALUE(ISNULL(g.DetailsJson, ''), '$.dataType'),
                    JSON_VALUE(ISNULL(g.DetailsJson, ''), '$.datatype'),
                    JSON_VALUE(ISNULL(g.DetailsJson, ''), '$.data_type')
                )
            ) AS DataType
        FROM dbo.tbl_ai_GoalSlots g with(nolock)
        WHERE g.GoalId = @AgentId
          AND g.IsDeleted = 0
        ORDER BY g.GoalId;
 
    END TRY
    BEGIN CATCH
        exec usp_InsertErrorInfo;
    END CATCH
END;



