/* ============================================================
   Procedure: [dbo].[usp_ai_GetKnowledgeBaseList]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON



CREATE   PROCEDURE usp_ai_GetKnowledgeBaseList  
    @PageNumber INT = 1,  
    @PageSize INT = 25,  
    @SearchTerm NVARCHAR(400) = NULL,  
    @CategoryId INT = NULL,  
    @Tag NVARCHAR(200) = NULL,  
    @IsPublished BIT = NULL,  
    @CompanyId INT = NULL,  
    @AuthorId INT = NULL,  
    @CreatedFrom DATETIME = NULL,  
    @CreatedTo DATETIME = NULL,  
    @SortBy NVARCHAR(64) = 'PublishedDate', -- allowed: Title, PublishedDate, Category, Author, CreatedDate  
    @SortDir NVARCHAR(4) = 'DESC',            -- ASC or DESC  
    @UserId BIGINT = 0                         -- optional: restrict results to user's parent  
AS  
BEGIN  
  SET NOCOUNT ON;  
  
  --declare     @PageNumber INT = 1,  
  --  @PageSize INT = 25,  
  --  @SearchTerm NVARCHAR(400) = NULL,  
  --  @CategoryId INT = NULL,  
  --  @Tag NVARCHAR(200) = NULL,  
  --  @IsPublished BIT = NULL,  
  --  @CompanyId INT = NULL,  
  --  @AuthorId INT = NULL,  
  --  @CreatedFrom DATETIME = NULL,  
  --  @CreatedTo DATETIME = NULL,  
  --  @SortBy NVARCHAR(64) = 'PublishedDate', -- allowed: Title, PublishedDate, Category, Author, CreatedDate  
  --  @SortDir NVARCHAR(4) = 'DESC',            -- ASC or DESC  
  --  @UserId BIGINT = 34594                         -- optional: restrict results to user's parent  



  IF @PageNumber < 1 SET @PageNumber = 1;  
  IF @PageSize < 1 SET @PageSize = 25;  
  IF @SortDir NOT IN ('ASC','DESC') SET @SortDir = 'DESC';  
  
    -- Normalize sentinel values so callers can pass 0 / empty string to mean "no filter"  
    IF @CategoryId = 0 SET @CategoryId = NULL;  
    IF @CompanyId = 0 SET @CompanyId = NULL;  
    IF @AuthorId = 0 SET @AuthorId = NULL;  
  
    IF LTRIM(RTRIM(ISNULL(@Tag, N''))) = N'' SET @Tag = NULL;  
    IF LTRIM(RTRIM(ISNULL(@SearchTerm, N''))) = N'' SET @SearchTerm = NULL;  
  
    -- Normalize sort params to defaults when empty  
    IF LTRIM(RTRIM(ISNULL(@SortBy, N''))) = N'' SET @SortBy = 'PublishedDate';  
    IF LTRIM(RTRIM(ISNULL(@SortDir, N''))) = N'' SET @SortDir = 'DESC';  
  
    -- Convert bogus/empty date sentinels ('' often converts to 1900-01-01) to NULL  
    IF @CreatedFrom IS NOT NULL AND @CreatedFrom <= '1900-01-02' SET @CreatedFrom = NULL;  
    IF @CreatedTo IS NOT NULL AND @CreatedTo <= '1900-01-02' SET @CreatedTo = NULL;  
  
  DECLARE @SortColumn NVARCHAR(200) =  
    CASE LOWER(ISNULL(@SortBy, ''))  
      WHEN 'title' THEN 'kb.Title'  
            WHEN 'publisheddate' THEN 'kb.PublishedAt'  
            WHEN 'category' THEN 'kb.Category'  
            WHEN 'author' THEN 'kb.CreatedBy'  
            WHEN 'createddate' THEN 'kb.CreatedOn'  
            ELSE 'kb.PublishedAt'  
    END;  
  
  DECLARE @OrderBy NVARCHAR(240) = @SortColumn + ' ' + @SortDir;  
  DECLARE @Offset INT = (@PageNumber - 1) * @PageSize;  
  
    -- determine parent id scoped to the user (NULL when @UserId not provided)  
    DECLARE @UserParentId BIGINT = NULL;  
    IF @UserId IS NOT NULL AND @UserId > 0  
        SET @UserParentId = dbo.ufn_getuserparentid(@UserId);  
  
  DECLARE @sql NVARCHAR(MAX) = N'  
    SELECT  
            kb.KbId AS KnowledgeBaseId,  
            kb.Title,  
            NULL AS Slug,  
            NULL AS Summary,  
            kb.Content,  
            kb.Category AS CategoryId,  
            kb.Category AS CategoryName,  
            CASE WHEN ISNULL(kb.Status,'''') = ''published'' THEN 1 ELSE 0 END AS IsPublished,  
            kb.PublishedAt AS PublishedDate,  
            kb.CreatedOn AS CreatedDate,  
            kb.UpdatedAt AS UpdatedDate,  
            kb.CompanyId,  
            comp.Name AS CompanyName,  
            kb.CreatedBy AS AuthorId,  
            NULL AS AuthorName,  
      COUNT(1) OVER() AS TotalCount  
        FROM dbo.tbl_ai_KnowledgeBase kb  
        LEFT JOIN dbo.tbl_ai_Companies comp ON comp.CompanyId = kb.CompanyId  
            WHERE kb.IsDeleted=0  
                AND (@SearchTerm IS NULL OR (kb.Title LIKE ''%'' + @SearchTerm + ''%'' OR kb.Content LIKE ''%'' + @SearchTerm + ''%'' OR kb.DetailsJson LIKE ''%'' + @SearchTerm + ''%''))   
            AND (@UserParentId IS NULL OR kb.ParentId = @UserParentId)  
        AND (@CategoryId IS NULL OR kb.Category = CONVERT(NVARCHAR(200), @CategoryId))  
                        AND (@Tag IS NULL OR EXISTS (SELECT 1 FROM dbo.tbl_ai_KBTags kbt JOIN dbo.tbl_ai_Tags t ON kbt.TagId = t.TagId WHERE kbt.KbId = kb.KbId AND t.Name LIKE ''%'' + @Tag + ''%''))   
            AND (@IsPublished IS NULL OR (CASE WHEN ISNULL(kb.Status,'''') = ''published'' THEN 1 ELSE 0 END) = @IsPublished)  
            AND (@CompanyId IS NULL OR kb.CompanyId = @CompanyId)  
            AND (@AuthorId IS NULL OR kb.CreatedBy = @AuthorId)  
            AND (@CreatedFrom IS NULL OR kb.CreatedOn >= @CreatedFrom)  
            AND (@CreatedTo IS NULL OR kb.CreatedOn <= @CreatedTo)  
    ORDER BY ' + @OrderBy + '  
    OFFSET @Offset ROWS FETCH NEXT @PageSize ROWS ONLY;  
  ';  
  
  EXEC sp_executesql  
        @sql,  
        N'@SearchTerm NVARCHAR(400), @CategoryId INT, @Tag NVARCHAR(200), @IsPublished BIT, @CompanyId INT, @AuthorId INT, @CreatedFrom DATETIME, @CreatedTo DATETIME, @UserParentId BIGINT, @Offset INT, @PageSize INT',  
        @SearchTerm = @SearchTerm,  
        @CategoryId = @CategoryId,  
        @Tag = @Tag,  
        @IsPublished = @IsPublished,  
        @CompanyId = @CompanyId,  
        @AuthorId = @AuthorId,  
        @CreatedFrom = @CreatedFrom,  
        @CreatedTo = @CreatedTo,  
        @UserParentId = @UserParentId,  
        @Offset = @Offset,  
        @PageSize = @PageSize;  
END;  



GO

/* ============================================================
   Procedure: [dbo].[usp_ai_GetLeadCounts]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  
------------------------------------------------------------  
  
  
CREATE   PROCEDURE [dbo].[usp_ai_GetLeadCounts] --34594  
(  
    @UserId BIGINT  
)  
AS  
BEGIN  
  -- declare  @UserId BIGINT=34594  
    DECLARE @ParentId BIGINT = NULL,@HotLead int=0;  
    SET NOCOUNT ON;  
  
    IF @UserId > 0  
        SET @ParentId = dbo.ufn_getuserparentid(@UserId);  
  
    PRINT CONCAT('@ParentId => ', @ParentId);  
  
      select @HotLead=count(*) from tbl_ai_VisitorsLastResponse R with(nolock) 
    Where parentid=@ParentId and is_junk=0 and IsOpen=1 and (select count(1) from tbl_ai_Conversations l(nolock) where l.entityname=R.entityname and l.EntityId=R.EntityId and l.createdon>dateadd(d,-7,getdate()))>5

    ;WITH VisitorData AS (  
        SELECT   
            lr.lastmessage_at,  
            lr.last_status_date,  
            lr.is_junk,  
            lr.IsOpen,  
            lr.Createdon,
            LOWER(ISNULL(lr.laststatus, '')) AS status,  
            lr.IsGoalFulfilled  
        FROM dbo.tbl_ai_VisitorsLastResponse lr WITH (NOLOCK)   
        WHERE lr.ParentId = @ParentId  
    )  

    SELECT  
        ISNULL(COUNT(*),0) AS [all],  
        ISNULL(SUM(CASE WHEN lastmessage_at >= CAST(GETUTCDATE() AS DATE)   
                        AND lastmessage_at < DATEADD(DAY, 1, CAST(GETUTCDATE() AS DATE))   
                        THEN 1 ELSE 0 END),0) AS [today],  
        --ISNULL(SUM(CASE WHEN last_status_date IS NOT NULL AND last_status_date < GETUTCDATE() THEN 1 ELSE 0 END),0) AS [overdue],  
        ISNULL(SUM(CASE WHEN is_junk=0 and IsOpen=1 and isnull(lastmessage_at,Createdon) < GETDATE() THEN 1 ELSE 0 END),0) AS [overdue],  
        --ISNULL(SUM(CASE WHEN status IN ('cold','cold lead') THEN 1 ELSE 0 END),0) AS [cold],  
        ISNULL(SUM(CASE WHEN is_junk=0 and IsOpen=1 and isnull(lastmessage_at,Createdon) < dateadd(d,-7,getdate()) THEN 1 ELSE 0 END),0) AS [cold],  
        --ISNULL(SUM(CASE WHEN status IN ('hot','hot lead') THEN 1 ELSE 0 END),0) AS [hot],  
        @HotLead AS [hot],  
        ISNULL(SUM(CASE WHEN status IN ('hold','on hold') THEN 1 ELSE 0 END),0) AS [hold],  
        --ISNULL(SUM(CASE WHEN status IN ('junk','spam') THEN 1 ELSE 0 END),0) AS [junk],  
        ISNULL(SUM(CASE WHEN is_junk=1 THEN 1 ELSE 0 END),0) AS [junk],  
   ISNULL(SUM(CASE WHEN IsGoalFulfilled = 1 THEN 1 ELSE 0 END),0) AS [goals]  
    FROM VisitorData;  
END  



GO

/* ============================================================
   Procedure: [dbo].[usp_AI_GetLeadDataToAnalyze]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

/*  

Related Queries for Data Extraction:
Select PersonName, LeadNo from UserLeads(nolock) where ID = 1712370 and ParentID= 32222;
EXEC usp_AI_GetLeadDataToAnalyze 1712372  , 32222, 2 ,'nalaytext', 'save response data';

*/

CREATE   PROC [dbo].[usp_AI_GetLeadDataToAnalyze]
(
  @P_LEADID BIGINT,
  @P_USERID BIGINT,
  @P_Option INT,
  @P_PromptText NVARCHAR(MAX) = '',
  @P_Response_text NVARCHAR(MAX) = ''
)
AS
BEGIN
  BEGIN TRY

    /* Variable Declarations */
    DECLARE @LeadName VARCHAR(300), 
            @LeadNo BIGINT = 0, 
            @LeadFirstInteractionDate DATE,
            @LastInteractionDate DATE,
            @LastFollowupStatus VARCHAR(100),
            @LastResponseDate DATETIME,
            @tblResponseText VARCHAR(MAX) = '',
            @ParentId BIGINT,
            @Prompt_text NVARCHAR(MAX),
            @Lead_data NVARCHAR(MAX);

    /* Fetch ParentID */
    SET @ParentId = (SELECT ParentID FROM user_detail (NOLOCK) WHERE User_ID = @P_USERID);
    PRINT '@ParentId = ' + CAST(COALESCE(@ParentId, '') AS VARCHAR(20));

   
		 /****************Lead interaction variables********************************************************/

   		 /* Fetch Lead Details */
			SELECT @LeadName = PersonName, @LeadNo = LeadNo 
			FROM UserLeads (NOLOCK) 
			WHERE ID = @P_LEADID AND ParentID = @ParentId;

			/* Fetch Interaction Dates */
			SELECT TOP 1 @LeadFirstInteractionDate = CreatedOn FROM LeadInteractionHistory (NOLOCK) 
			WHERE LEADNO = @LeadNo AND ParentID = @ParentId 
			ORDER BY ID ASC;

			SELECT TOP 1 @LastInteractionDate = CreatedOn, @LastFollowupStatus = CreatedOn FROM LeadInteractionHistory(NOLOCK) 
			WHERE LEADNO = @LeadNo AND ParentID = @ParentId 
			ORDER BY ID DESC;

			PRINT CONCAT('Lead Name: ', @LeadName, ', First Interaction Date: ', @LeadFirstInteractionDate, 
						 ', Last Interaction Date: ', @LastInteractionDate, ', Last Followup Status: ', @LastFollowupStatus);


		   SELECT @LastResponseDate =  CASE WHEN  ModifiedDate IS NULL THEN CAST(CreatedDate AS DATETIME)  ELSE CAST(ModifiedDate AS DATETIME)  END
					FROM TBL_AI_GPTCHATHISTORY (NOLOCK) 
					WHERE COALESCE(RESPONSE_TEXT, '') <> '' AND REFID = @P_LEADID AND PARENTID = @ParentId;

			
			PRINT CONCAT('Last Response Date: ', @LastResponseDate);

			/****************************************************************/


    /* Handle Options */
    IF (@P_Option = 1) 
    BEGIN  
	
		
			/* Prompt for AI Review */
			SET @Prompt_text = 'Based on the following interactions with the lead, provide a concise summary of the key points and recommended next steps. Avoid any introductory statements or irrelevant details. Focus on the most important information and limit the response to max 100 words ' + CHAR(13) + CHAR(10);
	
	
			/* PlainText Result */
			/* Fetch Lead Data as PlainText */
		  SET @Lead_data = (SELECT REPLACE(REPLACE(REPLACE(REPLACE(
			  (SELECT li.CreatedOn AS Followup_Date, 
					  li.FollowupDate AS Next_Followup_Date,
					  UL.PERSONNAME, 
					  LI.Remarks, 
					  FS.Intent, 
					  FS.FollowupStatus, 
					  UL.PERSONNAME AS leadName, 
					  UL.NextStatusDate AS NextStatusDate 
			   FROM LeadInteractionHistory(NOLOCK)  LI 
			   LEFT JOIN FollowUp_Status(NOLOCK)  FS ON FS.ID = LI.FollowUpStatus 
			   LEFT JOIN UserLeads(NOLOCK)  UL ON UL.LEADNO = LI.LEADNO AND UL.ParentID = LI.ParentID 
			   WHERE LI.ParentID = @ParentId AND LI.LeadNo = @LeadNo 
			   FOR JSON PATH), 
			   '},{', CHAR(13) + CHAR(10)), 
			   '["', ''), 
			   '"]', ''), 
			   '"', '') AS PlainTextResult);

		  PRINT 'Lead Data = ' + COALESCE(@Lead_data, '');

		  /* Check if history exists */
		  IF EXISTS(SELECT 1 FROM TBL_AI_GPTCHATHISTORY (NOLOCK) WHERE COALESCE(RESPONSE_TEXT, '') <> '' AND REFID = @P_LEADID AND PARENTID = @ParentId)
		  BEGIN
			--SELECT @LastResponseDate = CAST(ModifiedDate AS DATETIME) 
			--FROM TBL_AI_GPTCHATHISTORY (NOLOCK) 
			--WHERE COALESCE(RESPONSE_TEXT, '') <> '' AND REFID = @P_LEADID AND PARENTID = @ParentId;


			/* Fetch response text if it exists */
			SELECT @tblResponseText = COALESCE(RESPONSE_TEXT, '') FROM TBL_AI_GPTCHATHISTORY (NOLOCK)   WHERE REFID = @P_LEADID AND PARENTID = @ParentId;

			/* Fetch New Follow-Ups */
			SET @Lead_data = (SELECT REPLACE(REPLACE(REPLACE(REPLACE(
				(SELECT LI.CreatedOn AS Followup_Date, 
						LI.FollowupDate AS Next_Followup_Date, 
						UL.PERSONNAME AS leadName, 
						LI.Remarks, 
						FS.Intent, 
						FS.FollowupStatus, 
						UL.NextStatusDate AS NextStatusDate 
				 FROM LeadInteractionHistory(NOLOCK) LI  
				 LEFT JOIN FollowUp_Status(NOLOCK) FS  ON FS.ID = LI.FollowUpStatus 
				 LEFT JOIN UserLeads(NOLOCK)  UL ON UL.LEADNO = LI.LEADNO AND UL.ParentID = LI.ParentID 
				 WHERE LI.ParentID = @ParentId AND LI.LeadNo = @LeadNo AND LI.CreatedOn >= @LastResponseDate 
				 ORDER BY LI.FollowupDate DESC 
				 FOR JSON PATH), 
				 '},{', CHAR(13) + CHAR(10)), 
				 '["', ''), 
				 '"]', ''), 
				 '"', '') AS PlainTextResult);

			SET @Prompt_text = 'An initial AI review of the lead based on the interactions with the lead was: Lead name: ' + @LeadName + '1st interaction date: ' + CONVERT(VARCHAR(30), @LeadFirstInteractionDate) + ' Last interaction date: ' + CONVERT(VARCHAR(30), @LastInteractionDate) + ' Last follow-up status: ' + @LastFollowupStatus + ' AI Review: ' + @tblResponseText + ' Now the following new interaction(s) have been added to it. Can you revise the review on the basis of these?
			  Now the following new interaction(s) have been added to it. Can you revise the review on the basis of these? Please do not     
			  include any introduction and focus on most important aspects keeping the max words to 100.    
			  New follow-ups:     
			  ' + CHAR(13) + CHAR(10)  + COALESCE( @Lead_data,'');    

		  END
		  ELSE /* If no previous history */
		  BEGIN
			SET @Prompt_text = @Prompt_text + CHAR(13) + CHAR(10) + @Lead_data;
		  END

		  PRINT '@Prompt_text = ' + COALESCE(@Prompt_text, '');

		  IF(  COALESCE( @Lead_data,'') = '') begin
			SELECT 'false' AS Result;
		  END
		  ELSE BEGIN
			SELECT @Prompt_text AS Result;
		  END

    END

    /* Additional Options for JSON, Response Saving, Tabular Data Retrieval */
    /* Define cases for @P_Option = 2, 3, 4 here... */

	 IF (@P_Option =2) BEGIN  -- update response to table  
	 
		print concat( 'Response text', @P_Response_text);

		IF (@P_Response_text <> '') begin
	
			 IF NOT EXISTS(SELECT 1 FROM  TBL_AI_GPTCHATHISTORY(nolock)  WHERE   REFID = @P_LEADID  AND PARENTID = @PARENTID)  
			  BEGIN  

					print 'Insert  data - > ';

					SET @P_Response_text = 'Date['+ FORMAT(GETDATE(), 'dd-MM-yyyy HH:mm')  +']: '+@P_Response_text;

					EXEC usp_AI_SaveChatHistory @P_LEADID, 'UserLeads', 'lead', @P_PromptText, @P_Response_text, @P_USERID;
					--update tbl_AI_GPTChatHistory set response_text= 'Date['+ FORMAT(GETDATE(), 'dd-MM-yyyy HH:mm')  +']: '+@P_Response_text , ModifiedBy =@P_USERID ,   
					--ModifiedDate = GETDATE()  where RefId = @P_LEADID  and Parentid = @ParentId;  

			  END  
			  ELSE BEGIN  
					print 'Update  data - > ';
					set @P_Response_text = 'Updated  Date['+ FORMAT(GETDATE(), 'dd-MM-yyyy HH:mm') +']: '+@P_Response_text ;
	
					EXEC usp_AI_SaveChatHistory @P_LEADID, 'UserLeads', 'lead', @P_PromptText, @P_Response_text, @P_USERID;
				
					--update tbl_AI_GPTChatHistory set response_text= @P_Response_text + response_text ,   
					--ModifiedBy =@P_USERID , ModifiedDate = GETDATE()  where RefId = @P_LEADID  and Parentid = @ParentId;  

			 END

			 SELECT 'Response Saved successful.' as Result; 

			

		 END
		 ELSE BEGIN
			SELECT 'No Response text.' as Result; 
				
		 END

	END

	IF (@P_Option = 3) BEGIN /*Fetch saved response*/
		IF EXISTS(SELECT 1 FROM  TBL_AI_GPTCHATHISTORY(nolock)  WHERE  COALESCE( RESPONSE_TEXT,'') <> '' AND  REFID = @P_LEADID  AND PARENTID = @PARENTID)  
		BEGIN 
			  SELECT @tblResponseText = COALESCE(RESPONSE_TEXT, '')  FROM TBL_AI_GPTCHATHISTORY (NOLOCK)  WHERE REFID = @P_LEADID AND PARENTID = @ParentId;
		END


		/********if exist new followup ******************/
		Declare @IsNewFollowup bit = 0;
	 
		IF EXISTS( SELECT 1   FROM LeadInteractionHistory(NOLOCK) LI   LEFT JOIN UserLeads(NOLOCK) UL  ON UL.LEADNO = LI.LEADNO AND UL.ParentID = LI.ParentID 
				 WHERE LI.ParentID = @ParentId AND LI.LeadNo = @LeadNo AND LI.CreatedOn >= @LastResponseDate ) BEGIN

				set  @IsNewFollowup = 1;
		END
				 
		
		SELECT @tblResponseText as Result ,@IsNewFollowup as IsNewFollowup ;

	END
	/****************************************************/

	IF (@P_Option =10) BEGIN  --- JSON RESULT DATA    
        
     SELECT (    
     select LI.FollowupDate , LI.Remarks , FS.Intent, FS.FollowupStatus  from LeadInteractionHistory(NOLOCK) LI
		RIGHT JOIN UserLeads(nolock) UL ON UL.LeadNo = LI.LeadNo
         LEFT JOIN FollowUp_Status(NOLOCK)  FS ON FS.ID = LI.FollowUpStatus    
         where LI.ParentID = @ParentId  AND LI.LeadNo = @LeadNo    
     FOR JSON AUTO , ROOT('LEAD')    
      ) AS 'LEADDATA'    
   END    
    
   IF (@P_Option =11) BEGIN  --- tabular data    
     SELECT FOLLOWUPDATE , REMARKS , FS.INTENT, FS.FOLLOWUPSTATUS  FROM LEADINTERACTIONHISTORY(NOLOCK)  LI 
     LEFT JOIN FOLLOWUP_STATUS(NOLOCK)  FS ON FS.ID = LI.FOLLOWUPSTATUS    
     WHERE LI.PARENTID = @ParentId  AND LI.LEADNO = @LeadNo    
   END    

  END TRY

  BEGIN CATCH
    PRINT CONCAT('Error occurred: ', ERROR_MESSAGE(), ' | Error Number: ', ERROR_NUMBER(), ' | Line: ', ERROR_LINE());
  END CATCH
END



GO

/* ============================================================
   Procedure: [dbo].[usp_ai_GetMailBotCampaignsForEvent]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_ai_GetMailBotCampaignsForEvent(
	@BatchSize int
)
as
begin
	
	SET NOCOUNT ON;
    
    BEGIN TRAN;
    
    WITH cte AS (
        SELECT TOP (@BatchSize) id
        FROM tbl_mailbot_campaigns WITH (UPDLOCK, READPAST, ROWLOCK)
        WHERE isactive = 1 and isprocessed = 0 and processs_count < 5 and schdeule_datetime <= getdate()
        ORDER BY id
    )
    UPDATE a
    SET isprocessed = 1,
        process_started_on = getdate(),
        processs_count = ISNULL(processs_count, 0) + 1
    OUTPUT inserted.id, inserted.parentid, inserted.mailbotid, inserted.entityname, inserted.entityId
    FROM tbl_mailbot_campaigns a
    JOIN cte ON a.id = cte.id;
    
    COMMIT;
	
end



