/* ============================================================
   Procedure: [dbo].[usp_ai_GetMappedKnowledgeBaseIds]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_ai_GetMappedKnowledgeBaseIds(
	@AgentId bigint
)
as
begin
	
	drop table if exists #SelectedKnowledgeBaseIds

	SELECT 
		TRY_CAST(j.[value] AS bigint) AS KbId
		INTO #SelectedKnowledgeBaseIds
	FROM dbo.tbl_ai_Agents a WITH (NOLOCK)
	CROSS APPLY OPENJSON(a.DetailsJson, '$.selectedKnowledgeBaseIds') j
	WHERE a.AgentId = @AgentId;


	SELECT DISTINCT JSON_VALUE(f.value, '$.id') AS KnowledgeBaseId
	FROM dbo.tbl_ai_KnowledgeBase k WITH (NOLOCK)
	CROSS APPLY OPENJSON(COALESCE(JSON_QUERY(k.FileMetadataJson, '$.files'), k.FileMetadataJson)) f
	WHERE isjson(k.FileMetadataJson) = 1
	AND  k.KbId in ( select KbId from #SelectedKnowledgeBaseIds );
end



