/* ============================================================
   Procedure: [dbo].[usp_ai_GetPilelinesForWabaTemplates]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_ai_GetPilelinesForWabaTemplates](
	@ParentId bigint = 0
)
as
begin
	declare @pilelines nvarchar(max), @currenttemplates nvarchar(max)
	set @pilelines  = (select p.name as Pipeline ,s.name as Stage  
	from Pipeline_Master p join PipelineStages s on p.id=s.PipelineID 
	where parentid=@ParentId and p.IsDeleted=0 and s.isdeleted=0   
	order by p.id,s.Sequence for json path)

	select @currenttemplates = (select top 10 templatebody from [10.0.0.135].mysmsconversations.dbo.convtemplates with (nolock) 
		where parent_id=@parentid and templatetype = 'TextOnly' and templatestatus='APPROVED' and created_by_agent_id is null order by id desc FOR json path) 

	select @pilelines as [pilelines], @currenttemplates as [currentTemplates]
end



