/* ============================================================
   Procedure: [dbo].[usp_ai_GetPredefinedAgentSettings]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_ai_GetPredefinedAgentSettings](
	@agentId bigint,
	@userId bigint
)
as
begin

	--declare
	--	@agentId bigint = 308,
	--	@userId bigint = 34594

	declare @followUpPrompt nvarchar(max), @agentType nvarchar(25), @predefinedAgentId bigint = 0


	select @followUpPrompt = AgentInstruction, @predefinedAgentId = predefined_agentid
	from tbl_ai_Agents with (nolock) where AgentId = @agentId

	print concat('predefinedAgentId: ', cast(@predefinedAgentId as nvarchar(20)))

	if(isnull(@predefinedAgentId, 0) > 0 and isnull(@followUpPrompt, '') = '' )
	begin
		select @followUpPrompt = promptTemplate from tbl_predefined_agents where id = @predefinedAgentId
	end


	
	declare @companyName nvarchar(255), @companyType nvarchar(255), @goalName nvarchar(255),
		@personaName nvarchar(255), @contextInfo nvarchar(max)


	select @companyName = c.Name, @companyType = json_value(c.DetailsJson, '$.companyForm.businessType')  from tbl_ai_Agents a with (nolock) 
		left join tbl_ai_Companies c with (nolock) on a.CompanyId = c.CompanyId

	select @personaName = p.Name from tbl_ai_Personas p with (nolock) where p.AgentId = @agentId
	select @goalName = g.Title from tbl_ai_Goals g with (nolock) where g.AgentId = @agentId

	set @followUpPrompt = replace(@followUpPrompt, '{{CompanyName}}', isnull(@companyName, ''))
	set @followUpPrompt = replace(@followUpPrompt, '{{companyName}}', isnull(@companyName, ''))	
	set @followUpPrompt = replace(@followUpPrompt, '{{CompanyType}}', isnull(@companyType, ''))
	set @followUpPrompt = replace(@followUpPrompt, '{{goal_name}}', isnull(@goalName, ''))
	set @followUpPrompt = replace(@followUpPrompt, '{{persona_name}}', isnull(@personaName, ''))
	set @followUpPrompt = replace(@followUpPrompt, '{{contaxt_info}}', isnull(@contextInfo, ''))
	
	print @followUpPrompt


	select @followUpPrompt as [followUpPrompt]

end


GO

/* ============================================================
   Procedure: [dbo].[usp_ai_GetReecipientForTrigger]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_ai_GetReecipientForTrigger](
	@RequestId bigint,
	@Mode nvarchar(255)
)
as
begin

	--declare 
	--	@RequestId bigint = 1,
	--	@Mode nvarchar(255) = 'sender'

	declare @entityName nvarchar(255), @entityId bigint,
		@eventName nvarchar(255), @eventId bigint, @channelProfileId nvarchar(25), @personName nvarchar(25)

	select 
		@entityName = entityName,
		@entityId = entityId,
		@eventName = eventName,
		@eventId = eventId
	from tbl_ai_GoalMileStoneTriggerRequests with (nolock) where id = @RequestId

	declare @tblRecipients as table(
		sNo int identity(1,1),
		personName nvarchar(255),
		MobileNo nvarchar(25),
		emailId nvarchar(255),
		wabaId nvarchar(255)
	)

	if(@Mode in ( 'sender', 'visitor'))
	begin
		if(@entityName = 'visitor')
		begin
			insert into @tblRecipients(personName, MobileNo, emailId, wabaId)
			select 
				isnull([Name], json_value(goalSlotJson, '$.visitor_name')),
				isnull([Phone], json_value(goalSlotJson, '$.visitor_phone')),
				isnull([Email], json_value(goalSlotJson, '$.visitor_email')),
				null 
			from tbl_ai_Visitors with (nolock) where VisitorId = @entityId
		end

		if(@entityName in ('enquiry', 'lead'))
		begin
			select @channelProfileId = channelprofileid from [10.0.0.135].MySMSConversations.dbo.convusers with (nolock) 
					where entity = @entityId and entityId = @entityId and isactive = 1 order by id desc
		
			if(@entityName = 'enquiry')
			begin
				select @personName = personName from UserEnquiry with (nolock) where EnquiryID = @entityId

				insert into @tblRecipients(personName, MobileNo, emailId, wabaId)
				select @personName, Mobile, email, @channelProfileId from [dbo].[Userenquiry_Mobile_Email] v
				where v.enquiryId = @entityId

			end

			if(@entityName = 'lead')
			begin
				select @personName = personName from UserLeads with (nolock) where ID = @entityId

				insert into @tblRecipients(personName, MobileNo, emailId, wabaId)
				select @personName, Mobile, email, @channelProfileId from [dbo].[Userleads_Mobile_Email] v
				where v.ulme_id = @entityId

			end
		end

	end

	if(@Mode = 'user')
	begin
		print 'user section';

	end

	if(@Mode = 'role')
	begin
		print 'role section'
	end

	if(@Mode = '')
	begin
		print 'exact section'
	end

	select sNo, personName, MobileNo, emailId, wabaId from @tblRecipients

end



