/* ============================================================
   Procedure: [dbo].[usp_AI_GetTicketActivityDataToAnalyze]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[usp_AI_GetTicketActivityDataToAnalyze]
(
  @TICKETID BIGINT,
  @P_USERID BIGINT,
  @P_Option INT,
  @P_PromptText NVARCHAR(MAX) = '',
  @P_Response_text NVARCHAR(MAX) = ''
)
AS
BEGIN
  BEGIN TRY
  --declare 
  --@TICKETID BIGINT=4729,
  --@P_USERID BIGINT=929,
  --@P_Option INT=3,
  --@P_PromptText NVARCHAR(MAX) = '',
  --@P_Response_text NVARCHAR(MAX) = ''
  --@JsonData NVARCHAR(MAX)=''
    /* Variable Declarations */
    DECLARE @RequesterName VARCHAR(300), 
            @LeadNo BIGINT = 0, 
            @LeadFirstInteractionDate DATE,
            @LastInteractionDate DATE,
            @LastFollowupStatus VARCHAR(100),
            @LastResponseDate DATETIME,
            @tblResponseText VARCHAR(MAX) = '',
            @ParentId BIGINT,
            @Prompt_text NVARCHAR(MAX),
            @Activity_data NVARCHAR(MAX),
		    @DynamicSQL NVARCHAR(MAX); -- Variable to hold dynamic SQL

    /* Fetch ParentID */
    SET @ParentId = (SELECT ParentID FROM tbl_tp_UserLogin (NOLOCK) WHERE TpUser_Id = @P_USERID);
    PRINT '@ParentId = ' + CAST(COALESCE(@ParentId, '') AS VARCHAR(20));

	DECLARE @ActivityTable NVARCHAR(max) = 'tbl_tp_TicketActivity_' + CAST(@ParentId AS NVARCHAR(20));
   
		 /****************Lead interaction variables********************************************************/

   		 /* Fetch Lead Details */
			SET @DynamicSQL = N'
    SELECT @RequesterNameOUT = RequesterEmailID, @LeadNoOUT = TicketID 
    FROM ' + QUOTENAME('tbl_tp_TicketMaster_' + CAST(@ParentId AS NVARCHAR(20))) + N' (NOLOCK)
    WHERE TicketID = @TICKETIDIN AND ParentID = @ParentIdIN';

EXEC sp_executesql 
    @DynamicSQL, 
    N'@TICKETIDIN BIGINT, @ParentIdIN BIGINT, @RequesterNameOUT NVARCHAR(300) OUTPUT, @LeadNoOUT BIGINT OUTPUT',
    @TICKETIDIN = @TICKETID,
    @ParentIdIN = @ParentId,
    @RequesterNameOUT = @RequesterName OUTPUT,
    @LeadNoOUT = @LeadNo OUTPUT;

PRINT '@RequesterName = ' + COALESCE(@RequesterName, '') + ', @LeadNo = ' + CAST(COALESCE(@LeadNo, 0) AS VARCHAR);

			/* Fetch Interaction Dates */
			    SELECT TOP 1 @LeadFirstInteractionDate = CreatedOn FROM tbl_tp_TicketHistory (NOLOCK) 
			    WHERE TicketID = @LeadNo AND ParentID = @ParentId 
			    ORDER BY TicketHistoryID ASC;

			    SELECT TOP 1 @LastInteractionDate = CreatedOn, @LastFollowupStatus = CreatedOn FROM tbl_tp_TicketHistory(NOLOCK) 
			    WHERE TicketID = @LeadNo AND ParentID = @ParentId 
			    ORDER BY TicketHistoryID DESC;


		   SELECT @LastResponseDate =  CASE WHEN  ModifiedDate IS NULL THEN CAST(CreatedDate AS DATETIME)  ELSE CAST(ModifiedDate AS DATETIME)  END
					FROM tbl_Tp_AI_GPTChatActivityHistory (NOLOCK) 
					WHERE COALESCE(RESPONSE_TEXT, '') <> '' AND REFID = @TICKETID AND PARENTID = @ParentId;

			
			PRINT CONCAT('Last Response Date: ', @LastResponseDate);

			/****************************************************************/


    /* Handle Options */
	   IF (@P_Option = 1) 
BEGIN
    /* Prompt for AI Review */
    SET @Prompt_text = 'Show Ticket Activity summary and show major actions highlighting anything unusual and important during the activity and iportant points accrding to ActivityDatetime ,and ActivityDescription and ActivityBy generate text in 200 words in human readabilty as conclusion of data' + CHAR(13) + CHAR(10);
	     SET @DynamicSQL = N'
                    SELECT *
                    FROM (
                        SELECT 
                            CASE 
                                WHEN EntityName NOT IN (''Enquiry'', ''Lead'') THEN [dbo].[fn_getentityfullname](EntityName, EntityId) 
                                ELSE ''Customer'' 
                            END AS CommentBy,
							Subject as TicketSubject,
                            Description,
                            CreatedOn,
                            CASE 
                                WHEN EntityName IN (''Enquiry'', ''Lead'') THEN ''Customer'' 
                                ELSE ''Employee'' 
                            END AS Entity,
                            ''Reply'' AS isActivityorReplyorPrivateNote
                        FROM ' + QUOTENAME('tbl_tp_TicketMaster_' + CAST(@ParentId AS NVARCHAR(20))) + N' (NOLOCK)
                        WHERE TicketID = @TICKETIDIN 

                        UNION

                        SELECT 
                            CASE 
                                WHEN ActionContent IN (''Note'', ''Forward'') THEN [dbo].[fn_getTicketentityfullname](AssignedBy) 
                                ELSE ''Customer'' 
                            END,
							'''',
                            Note,
                            CreatedOn,
                            ''Customer'' AS Entity,
                            CASE 
                               WHEN ActionContent IN (''Note'', ''Forward'') THEN ''PrivateNote'' 
                                ELSE ''Reply'' 
                            END
                        FROM tbl_tp_TicketHistory (NOLOCK)
                        WHERE  Note !=''Ticket Created'' and TicketId = @TICKETIDIN and ParentID= '+CAST(@ParentId AS NVARCHAR(20))+'

                        UNION

                        SELECT 
                            [dbo].[fn_getTicketentityfullname](ActivityBy),
								'''',
                            ActivityDescription,
                            ActivityDatetime,
                            ''Employee'' AS Entity,
                            ''Activity''
                        FROM ' + QUOTENAME('tbl_tp_TicketActivity_' + CAST(@ParentId AS NVARCHAR(20))) + N' (NOLOCK)
                        WHERE TicketId = @TICKETIDIN
                    ) a
                    ORDER BY CreatedOn
            ';
			print @DynamicSQL
        EXEC sp_executesql 
        @DynamicSQL, 
        N'@ParentIdIN BIGINT, @TICKETIDIN BIGINT, @Activity_dataOUT NVARCHAR(MAX) OUTPUT',
        @ParentIdIN = @ParentId, 
        @TICKETIDIN = @TICKETID, 
        @Activity_dataOUT = @Activity_data OUTPUT;

    PRINT 'Lead Data = ' + COALESCE(@Activity_data, '');

END




	 IF (@P_Option = 2)
BEGIN
    -- Print the response text for debugging
    PRINT CONCAT('Response text: ', @P_Response_text);

    IF (@P_Response_text <> '')
    BEGIN
        -- Check if there is no existing record
        IF NOT EXISTS(SELECT 1 FROM tbl_Tp_AI_GPTChatActivityHistory (NOLOCK) WHERE REFID = @TICKETID AND PARENTID = @PARENTID)
        BEGIN
            PRINT 'Insert data ->';

            -- Add date prefix only if not already present
            IF CHARINDEX('Date[', @P_Response_text) = 0
            BEGIN
                SET @P_Response_text = 'Date[' + FORMAT(GETDATE(), 'dd-MM-yyyy HH:mm') + ']: ' + @P_Response_text;
            END

            -- Save chat history and update the table
            EXEC usp_Tp_AI_SaveChatHistory @TICKETID, @ActivityTable, 'Activity', @P_PromptText, @P_Response_text, @P_USERID;
            --UPDATE tbl_Tp_AI_GPTChatActivityHistory
            --SET response_text = @P_Response_text,
            --    ModifiedBy = @P_USERID,
            --    ModifiedDate = GETDATE()
            --WHERE RefId = @TICKETID AND Parentid = @ParentId;
        END
        ELSE
        BEGIN
            PRINT 'Update data ->';

            -- Add date prefix only if not already present
            IF CHARINDEX('Date[', @P_Response_text) = 0
            BEGIN
                SET @P_Response_text = 'Updated Date[' + FORMAT(GETDATE(), 'dd-MM-yyyy HH:mm') + ']: ' + @P_Response_text;
            END

            -- Append the new response text and update the table
            EXEC usp_Tp_AI_SaveChatHistory @TICKETID, @ActivityTable, 'Activity', @P_PromptText, @P_Response_text, @P_USERID;
            --UPDATE tbl_Tp_AI_GPTChatActivityHistory
            --SET response_text = @P_Response_text + response_text,
            --    ModifiedBy = @P_USERID,
            --    ModifiedDate = GETDATE()
            --WHERE RefId = @TICKETID AND Parentid = @ParentId;
        END

  
        SELECT 'Response Saved successfully.' AS Result;
    END
    ELSE
    BEGIN
        SELECT 'No Response text.' AS Result;
    END
END


	IF (@P_Option = 3) BEGIN /*Fetch saved response*/
		IF EXISTS(SELECT 1 FROM  tbl_Tp_AI_GPTChatActivityHistory(nolock)  WHERE  COALESCE( RESPONSE_TEXT,'') <> '' AND  REFID = @TICKETID  AND PARENTID = @PARENTID)  
		BEGIN 
			  SELECT @tblResponseText = COALESCE(RESPONSE_TEXT, '')  FROM tbl_Tp_AI_GPTChatActivityHistory (NOLOCK)  WHERE REFID = @TICKETID AND PARENTID = @ParentId;
		END


		/********if exist new followup ******************/
DECLARE @IsNewFollowup BIT = 0;
SET @DynamicSQL = '
IF EXISTS(
    SELECT 1 
    FROM tbl_tp_TicketHistory  as TI WITH (NOLOCK)
    LEFT JOIN ' + QUOTENAME('tbl_tp_TicketMaster_' + CAST(@ParentId AS NVARCHAR(20))) + N'  UL WITH (NOLOCK)
    ON UL.TicketID = TI.TicketId AND UL.ParentID = TI.ParentID
    WHERE TI.ParentID = @ParentId AND TI.TicketID = @TICKETID AND TI.CreatedOn >= CONVERT(VARCHAR(23), @LastResponseDate, 121)
)
BEGIN
    SET @IsNewFollowup = 1;
END

SELECT @tblResponseText AS Result, @IsNewFollowup AS IsNewFollowup;
';

-- Execute dynamic SQL
print @DynamicSQL
EXEC sp_executesql 
    @DynamicSQL, 
    N'@ParentId INT, @TICKETID INT, @LastResponseDate DATETIME, @tblResponseText NVARCHAR(MAX), @IsNewFollowup BIT OUTPUT',
    @ParentId = @ParentId,
    @TICKETID = @TICKETID,
    @LastResponseDate = @LastResponseDate,
    @tblResponseText = @tblResponseText,
    @IsNewFollowup = @IsNewFollowup OUTPUT;


--SELECT @tblResponseText AS Result, @IsNewFollowup AS IsNewFollowup;

	END
	/****************************************************/

  END TRY

  BEGIN CATCH
    PRINT CONCAT('Error occurred: ', ERROR_MESSAGE(), ' | Error Number: ', ERROR_NUMBER(), ' | Line: ', ERROR_LINE());
  END CATCH



  END





GO

/* ============================================================
   Procedure: [dbo].[usp_ai_GetTriggerRequests]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_ai_GetTriggerRequests(
	@tblRequestIds tblRequestIds readonly
)
as
begin	
	begin try	
		select 
			r.id, r.entityName, r.entityId, r.eventName, r.eventId, r.actionMasterId, r.agentId, r.createdOn,
			r.isProcessed, r.processCount, r.actionDefinition, r.actionDetail, r.actionResponse, r.actionPayload,
			r.parentId, r.actionStartAt, r.actionEndAt, r.lastError
		from tbl_ai_GoalMileStoneTriggerRequests r with (nolock)
			inner join @tblRequestIds i on r.id = i.Id


		update r set 
			r.isProcessed = 2,
			r.processCount = (isnull(r.processCount, 0) + 1),
			r.actionStartAt = getutcdate()
		from tbl_ai_GoalMileStoneTriggerRequests r with (nolock)
			inner join @tblRequestIds i on r.id = i.Id
	end try
	begin catch
		exec usp_InsertErrorInfo
	end catch
end



GO

/* ============================================================
   Procedure: [dbo].[usp_ai_GetVisitorByVisitorIdStr]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_ai_GetVisitorByVisitorIdStr](      
    @visitorId nvarchar(255)      
)      
as  
begin      
      
    --declare @visitorId nvarchar(255) = 'visitor_b1cee7b8-3375-4b72-a329-2b5b1249df8c'  
      
    declare @entityName nvarchar(255) = 'visitor', @entityId bigint = 0, @lastVisitorResponseId bigint = 0, @threadId nvarchar(255) = null  
          
  
    select @entityId = VisitorId  from tbl_ai_Visitors v with (nolock) where v.strVisitorId = @visitorId    
       
    print concat('@entityName => ', @entityName)  
    print concat('@entityId => ', @entityId)  
  
    select @lastVisitorResponseId =  id from tbl_ai_VisitorsLastResponse with (nolock) where entityName = @entityName and entityId = @entityId  
  
    select @threadId = threadId from tbl_ai_VisitorsLastResponseThreadMaps with (nolock) where mode = 'webchat'  
        and lastVisitorResponseId = @lastVisitorResponseId  
  
  
    select       
        v.VisitorId, v.ParentId, v.CompanyId, v.Name, v.Email, v.Phone, v.Organization, v.Status,       
        v.Source, v.Channel, v.LastMessage, isnull(@threadId, v.threadId) as [threadId], c.Name as [CompanyName], c.Website, c.Industry, c.BrandColor,       
        c.ContactEmail, c.ContactPhone, isnull(a.AssistantId, 'asst_7DVc1rFHEvyXWt6EkeVHU14R') as [AssistantId], a.DetailsJson as [AgentDetailJson],    
        'visitor' as [EntityName], v.VisitorId as [EntityId],    
        v.goalSlotJson as [UserGoalSlotJson], 
        (  
            select JSON_QUERY(DetailsJson, '$.slots') from tbl_ai_Goals with (nolock) where AgentId = v.AgentId  
        ) as [AgentGoalSlotJson]     
    from tbl_ai_Visitors v with (nolock)       
    --left join tbl_ai_VisitorsLastResponse vlr with (nolock) where vlr.entityName = 'visitor' and   
    inner join tbl_ai_Companies c with (nolock)  on v.CompanyId = c.CompanyId      
    inner join tbl_ai_Agents a with (nolock) on a.AgentId = v.AgentId      
      
      
    where v.strVisitorId = @visitorId    
   
  
end



