/* ============================================================
   Procedure: [dbo].[usp_ai_GetVisitorDetailByEmail]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_ai_GetVisitorDetailByEmail(
	@fromEmail nvarchar(255),
	@fromPersonName nvarchar(255),
	@AgentId bigint,
	@ParentId bigint
)
as
begin
	
	--declare 
	--	@fromEmail nvarchar(255) = 'kmukesh343@gmail.com',
	--	@fromPersonName nvarchar(255) = 'Muksh Sharma',
	--	@AgentId bigint = 230,
	--	@ParentId bigint = 34594


	declare @entityId bigint = 0, @entityName nvarchar(25)

	select @entityId = ulme_id, @entityName = 'lead' from Userleads_Mobile_Email 
		where Parentid = @ParentId and email = @fromEmail order by ulme_id desc

	if(isnull(@entityId, 0) = 0)
	begin
		select @entityId = enquiryid, @entityName = 'enquiry' from Userenquiry_Mobile_Email 
			where Parentid = @ParentId and email = @fromEmail order by enquiryid desc
	end

	if(isnull(@entityId, 0) = 0)
	begin
		select @entityId = VisitorId, @entityName = 'visitor' from tbl_ai_Visitors 
			where Parentid = @ParentId and Email = @fromEmail order by VisitorId desc
	end

	if(isnull(@entityId, 0) = 0)
	begin
		select @entityId = VisitorId from tbl_ai_Visitors with (nolock) 
			where ParentId = @ParentId and Email = @fromEmail order by VisitorId desc
	end


	declare @visitorId bigint = 0
	if(isnull(@entityId, 0) = 0)
	begin
		declare @companyId bigint
		select @companyId = CompanyId from tbl_ai_Agents with (nolock) where AgentId = @AgentId

		insert into tbl_ai_Visitors(ParentId, CompanyId, Name, Email, AgentId)
			select @ParentId, @companyId, @fromPersonName, @fromEmail, @AgentId
		select @entityId = scope_identity(), @entityName = 'visitor'
	end

	if(@entityId > 0 and @entityName = 'visitor')
	begin
		set @visitorId = @entityId
	end



	declare @lastVisitorId bigint, @currentUtcDate datetime = getutcdate()
	select @lastVisitorId = id from tbl_ai_VisitorsLastResponse with (nolock) where entityName = @entityName and entityId = @entityId

	declare @goalSlotJson nvarchar(max) = concat(N'{"visitor_name":"', @FromPersonName, N'","visitor_email":"', @FromEmail, N'"}'),
		@threadId nvarchar(255) = ''

	if(isnull(@lastVisitorId, 0) = 0)
	begin
		insert into tbl_ai_VisitorsLastResponse(entityName, entityId,lastmessage_at, createdon, mode, goalSlotJson)
			select @entityName, @entityId, @currentUtcDate, @currentUtcDate, 'email',  @goalSlotJson
		select @lastVisitorId = scope_identity()
	end

	select @threadId = threadId from tbl_ai_VisitorsLastResponseThreadMaps with (nolock) where lastVisitorResponseId = @lastVisitorId and mode = 'email'
	

	select 
		l.id,
		(case 
			when l.entityName = 'lead' then u.PersonName
			when l.entityName = 'enquiry' then e.PersonName
			else @fromPersonName end
		) as [PersonName],
		(case 
			when l.entityName = 'lead' then (COALESCE(u.EmailID2, u.EmailID1, u.EmailID))
			when l.entityName = 'enquiry' then (COALESCE(e.EmailID2, e.EmailID1, e.EmailID))
			else @fromEmail end
		) as [Email],

		(case 
			when l.entityName = 'lead' then COALESCE(u.MobileNo2, u.MobileNo1, u.MobileNo)
			when l.entityName = 'enquiry' then COALESCE(e.MobileNo2, e.MobileNo1, e.MobileNo)
			else @fromEmail end
		) as [MobileNo],

		(case 
			when l.entityName = 'lead' then COALESCE(u.CountryCode2, u.CountryCode1, u.CountryCode)
			when l.entityName = 'enquiry' then COALESCE(e.CountryCode2, e.CountryCode1, e.CountryCode)
			else '+91' end
		) as [CountryCode],
		l.entityName,
		l.entityId,
		l.goalSlotJson,
		l.mileStoreJson,
		isnull(@threadId, '') as [ThreadId]
	from tbl_ai_VisitorsLastResponse l with (nolock)
		left join UserLeads u with (nolock)  on  l.entityName = 'lead' and u.Id = l.entityId
		left join UserEnquiry e with (nolock)  on  l.entityName = 'enqury' and e.EnquiryID = l.entityId
	where l.id = @lastVisitorId
		

end



GO

/* ============================================================
   Procedure: [dbo].[usp_ai_GetVisitorListAdvance]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


-- exec usp_ai_GetVisitorListAdvance @UserId=34594,@Category=N'overdue',@SearchText=N'',@Offset=0,@PageSize=20,@FromDate='2025-12-01 00:00:00',@ToDate='2026-01-05 00:00:00'
-- exec usp_ai_GetVisitorListAdvance @UserId=34594,@Category=N'all',@SearchText=N'',@Offset=0,@PageSize=20,@FromDate=null,@ToDate=null
CREATE   PROCEDURE  [dbo].[usp_ai_GetVisitorListAdvance] (    
    @UserId bigint,    
    @Category nvarchar(25) = 'all',    
    @SearchText nvarchar(255) = '',    
    @Offset int = 0,    
    @PageSize int = 20,  
    @FromDate datetime =null,  
    @ToDate datetime =null  
)    
as    
BEGIN    
    
    --declare    
    --    @UserId bigint = 34594,    
    --    @Category nvarchar(25) = 'overdue',    
    --    @SearchText nvarchar(255) = '',    
    --    @Offset int = 0,    
    --    @PageSize int = 20,  
    --    @FromDate datetime = null--'2026-01-03' /*'03-Dec-2025'*/
    --    ,@ToDate datetime = null--'2026-01-03' --'30-Dec-2025'  
    
    set nocount on;    
    declare @ParentId bigint = 0    
    
    set @ParentId = dbo.ufn_getuserparentid(@UserId);    
  
    If(@FromDate is null)  
    Begin  
        Set @FromDate='01-Jan-1900'  
    End  
  
    If(@ToDate is null)  
    Begin  
        Set @ToDate=GETDATE()  
    End  
    
   ;WITH cteVisitors AS (    
    SELECT    
        ROW_NUMBER() OVER (ORDER BY v.lastmessage_at DESC) AS RowNum,    
        v.Id AS VisitorId,    
        v.Id AS LastResponseId,    
    
        ISNULL(CASE    
            WHEN v.entityName = 'visitor' THEN ISNULL(vi.Name, vi.strVisitorId)    
            WHEN v.entityName = 'lead' THEN ul.PersonName    
            WHEN v.entityName = 'enquiry' THEN ue.PersonName    
            ELSE ''    
        END, '') AS VisitorName,    
    
        ISNULL(CASE    
            WHEN v.entityName = 'visitor' THEN vi.Email    
            WHEN v.entityName = 'lead' THEN ul.EmailID    
            WHEN v.entityName = 'enquiry' THEN ue.EmailID    
            ELSE ''    
        END, '') AS Email,    
    
        c.CompanyId,    
        c.Name AS CompanyName,    
        v.CreatedOn AS FirstVisit,    
        v.lastmessage_at AS LastActiveAt,    
        v.LastMessage,    
        v.LastStatus,    
        '' AS AgentName,    
        v.is_junk,  
        v.isOpen,  
        -- ? LeadNo only for lead    
        CASE     
            WHEN v.entityName = 'lead' THEN ul.LeadNo    
            ELSE NULL    
        END AS LeadNo,    
    
        -- ? Always return entity info    
        v.entityName,    
        v.entityId,    
    
        v.mode AS Source,    
        CASE     
            WHEN LOWER(v.mode) = 'whatsapp' THEN    'icon-whatsapp'    
            WHEN LOWER(v.mode) = 'email' THEN       'icon-email'    
            WHEN LOWER(v.mode) = 'sms' THEN         'icon-sms'    
            WHEN LOWER(v.mode) = 'voice' THEN       'icon-voice'    
            WHEN LOWER(v.mode) = 'webhook' THEN     'icon-webhook'    
            WHEN LOWER(v.mode) = 'webchat' THEN     'icon-webchat'    
            ELSE 'icon-default'    
        END AS SourceIcon,    
    
        v.IsGoalFulfilled,    
        v.IsMilestoneAchieved,    
        isnull((SELECT COUNT(*) FROM OPENJSON(v.goalSlotJson)),0) as GoalSlotAchievedCount,
        -- Even simpler if the array length is what you need
        ISNULL((SELECT COUNT(*) FROM OPENJSON(v.mileStoreJson, '$.completedMilestones')), 0) AS MilestoneAchievedCount,
        v.goalSlotJson,    
        v.mileStoreJson as mileStoneJson,    
    --select top 100 * from tbl_ai_GoalMilestones(nolock) order by 1 desc
    --select top 100 * from tbl_ai_GoalSlots(nolock) order by 1 desc
     (select STRING_AGG(name,',') from tbl_ai_GoalMilestones(nolock) where IsDeleted=0 and GoalId in ((SELECT goalId FROM OPENJSON(v.mileStoreJson) with (goalId int)))) AS csvMilestone,
     (select STRING_AGG(name,',') from tbl_ai_GoalSlots(nolock) where IsDeleted=0 and GoalId in ((SELECT goalId FROM OPENJSON(v.mileStoreJson) with (goalId int)))) AS csvGoalSlot,
    --CASE WHEN v.IsMilestoneAchieved = 1 THEN 1 ELSE 0 END AS MilestoneCount,    
    (select count(*) from tbl_ai_GoalMilestones(nolock) where IsDeleted=0 and GoalId in ((SELECT goalId FROM OPENJSON(v.mileStoreJson) with (goalId int)))) AS MilestoneCount,    
    (select count(*) from tbl_ai_GoalSlots(nolock) where IsDeleted=0 and GoalId in ((SELECT goalId FROM OPENJSON(v.mileStoreJson) with (goalId int)))) AS GoalSlotCount,    
    --(SELECT COUNT(*) FROM OPENJSON(v.goalSlotJson)) AS GoalSlotCount,    
  v.direction,    
  CASE WHEN v.lastmessage_at >= DATEADD(HOUR, -24, GETUTCDATE())    
                    THEN 'Active'    
                ELSE 'Inactive'    
            END AS Status    
    
    FROM dbo.tbl_ai_VisitorsLastResponse v WITH (NOLOCK)    
    
    -- ? Join only when entityName = 'lead'    
    LEFT JOIN dbo.UserLeads ul WITH (NOLOCK)    
        ON v.entityName = 'lead'    
       AND v.entityId = ul.Id    
    
    -- ? Enquiry join (no LeadNo used)    
    LEFT JOIN dbo.UserEnquiry ue WITH (NOLOCK)    
        ON v.entityName = 'enquiry'    
       AND v.entityId = ue.EnquiryID    
    
    LEFT JOIN dbo.tbl_ai_Visitors vi WITH (NOLOCK)    
        ON v.entityName = 'visitor'    
       AND v.entityId = vi.VisitorId    
    
    LEFT JOIN dbo.tbl_ai_Companies c WITH (NOLOCK)    
        ON vi.CompanyId = c.CompanyId    
    
    WHERE v.ParentId = @ParentId    
      AND (    
            LOWER(ISNULL(@Category, 'all')) = 'all'    
            OR (    
                LOWER(@Category) = 'today'    
                AND v.lastmessage_at >= CAST(@FromDate AS DATE)    
                AND v.lastmessage_at < DATEADD(DAY, 1, CAST(@ToDate AS DATE))    
            )    
            OR (    
                LOWER(@Category) = 'overdue'    
                --AND v.last_status_date IS NOT NULL    
                --AND v.last_status_date < GETUTCDATE()    
                and v.is_junk=0 and v.IsOpen=1 and isnull(v.lastmessage_at,v.Createdon) < GETDATE()
            )    
            OR (    
                LOWER(@Category) IN ('cold','cold lead')    
                --AND LOWER(ISNULL(v.laststatus, '')) IN ('cold','cold lead')    
                and v.is_junk=0 and v.IsOpen=1 and isnull(v.lastmessage_at,v.Createdon) < dateadd(d,-7,getdate())
            )    
            OR (    
                LOWER(@Category) IN ('hot','hot lead')    
                --AND LOWER(ISNULL(v.laststatus, '')) IN ('hot','hot lead')    
                and v.is_junk=0 and v.IsOpen=1 and (select count(1) from tbl_ai_Conversations l(nolock) where l.entityname=v.entityname and l.EntityId=v.EntityId and l.createdon>dateadd(d,-7,getdate()))>5
            )    
            OR (    
                LOWER(@Category) IN ('junk','spam')    
                AND (LOWER(ISNULL(v.laststatus, '')) IN ('junk','spam') or v.is_junk=1)
            )    
            OR (    
                LOWER(@Category) IN ('goals')    
                AND v.IsGoalFulfilled=1
            )    
        )    
    
            --AND (    
            --    @SearchText = ''    
            --    OR v.Name LIKE '%' + @SearchText + '%'    
            --    OR v.Email LIKE '%' + @SearchText + '%'    
            --)    
    )  
     
   SELECT    
    VisitorId, LastResponseId, VisitorName, Email, CompanyId, CompanyName,    
    FirstVisit, LastActiveAt, LastMessage, AgentName, laststatus,   
    LeadNo, entityName, entityId, Source, SourceIcon, is_junk, IsOpen,   
    RowNum, IsGoalFulfilled, IsMilestoneAchieved, goalSlotJson, mileStoneJson, csvMilestone, csvGoalSlot,  
    GoalSlotAchievedCount, MilestoneAchievedCount, MilestoneCount, GoalSlotCount,direction,Status,    
    (SELECT COUNT(1) FROM cteVisitors) AS TotalRecords    
FROM cteVisitors with(nolock)    
WHERE RowNum BETWEEN (@Offset + 1)    
    AND (CASE WHEN @PageSize > 0 THEN (@Offset + @PageSize) ELSE 2147483647 END)    
ORDER BY RowNum;    
            
END  



GO

/* ============================================================
   Procedure: [dbo].[usp_ai_GetVoiceAgentsByMode]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_ai_GetVoiceAgentsByMode]       
(       
    @Mode NVARCHAR(50),       
    @UserId BIGINT = NULL,       
    @JsonData NVARCHAR(MAX) = NULL,    
    @BotID bigint = null    
)       
AS       
BEGIN       
    SET NOCOUNT ON;       
     
    --declare  @Mode NVARCHAR(50) = 'getddllist' ,       
    --  @UserId BIGINT = 34594,       
    --  @JsonData NVARCHAR(MAX) = NULL,   
    --  @BotID bigint = null    
      
      Declare @ParentId bigint;         
      Select @ParentId=ParentId From User_detail(nolock) Where User_ID=@UserId;       
    /* =========================       
       GET DDL LIST       
       ========================= */       
       If(LOWER(ISNULL(@Mode,''))='getddllist')   
       Begin   
            select id, Bot_name,is_predefined,is_editable,category,LanguageConfig from voice_bot_details(nolock)   
                where parentid in (@ParentId, 0) and isactive=1  
            --and id not in (1,20,7,8,9,10,11,12,13,14,15)   
            order by 2;  
  
       return;   
       End       /* =========================       
       GET BY ID       
       ========================= */       
    IF LOWER(@Mode) = 'getbyid'       
    BEGIN       
        DECLARE @AgentId BIGINT;             
        SET @AgentId = JSON_VALUE(@JsonData, '$.agentId');             
          
        SELECT       
            id                              AS id,       
            Bot_name                        AS bot_name,       
            Description                     AS description,       
            VoiceConfig                     AS voiceconfig,       
            LanguageConfig                  AS [language],       
            HandoffRules                    AS handoffrules,       
            ActivePrompts                   AS activeprompts,       
            BusinessRules                   AS businessrules,       
            parentid                        AS parentid,       
            createdon                       AS createdon,       
            createdby                       AS createdby,       
            modifiedby                      AS modifiedby,       
            modifiedon                      AS modifiedon,       
            bot_settings                    AS bot_settings,       
            isactive                        AS isactive,       
            bot_sp                          AS bot_sp,       
            CallTerminationSettings         AS callterminationsettings,       
            STT_Config                      AS stt_config,       
            WelcomeMessagePath              AS welcomemessagepath,       
            SystemPrompt                    AS systemprompt,       
            moh_path                        AS moh_path,       
            assistant_id                    AS assistant_id,  
            goalSlotSettings                As goalslots,  
            triggreseting                   As goaltrigger,  
            greetings                       As gretings,  
            greeting_path                   as greetingpath,  
            goalname                        as goalname,  
            is_predefined                   as is_predefined,  
           is_editable                      as is_editable,  
            category                        as category  
  
        FROM voice_bot_details WITH (NOLOCK)   
        WHERE id = @AgentId  order by 1 desc;             
        RETURN;       
    END                  
IF (@Mode = 'SaveDemoRequest')  
BEGIN  
    DECLARE @Name NVARCHAR(200),  
            @Mobile NVARCHAR(20)  
  
    SELECT  
        @Name  = JSON_VALUE(@JsonData, '$.Name'),  
        @Mobile = JSON_VALUE(@JsonData, '$.Mobile'),  
        @BotID = TRY_CAST(JSON_VALUE(@JsonData, '$.BotId') AS BIGINT);  
print concat('Name: ',@Name,', Mobile: ',@mobile,', Botid: ',@botid,', parsed: ',json_value(@jsondata,'$.BotId'), ', json: ',@jsondata)   
    IF (@Mobile IS NULL OR LEN(@Mobile) <> 10)  
    BEGIN  
        RAISERROR('Invalid mobile number', 16, 1);  
        RETURN;  
    END  
    -- Check for existing unprocessed demo request for the same mobile  
    DECLARE @ExistingRequestId BIGINT;  
    SELECT TOP (1) @ExistingRequestId = Id  
    FROM dbo.tbl_Voice_bot_demorequest WITH (NOLOCK)  
    WHERE Mobile = @Mobile  
      AND ISNULL(IsProcessed, 0) = 0 and BotId=@botid  
    ORDER BY CreatedOn DESC;  
    IF @ExistingRequestId IS NOT NULL  
    BEGIN  
        -- Inform caller that request already scheduled  
        SELECT  
            'ALREADY_SCHEDULED' AS Status,  
            @ExistingRequestId AS RequestId,  
            'Our team will reach you between 09:00 and 21:00.' AS Message;  
        RETURN;  
    END  
    -- Insert new demo request  
    INSERT INTO dbo.tbl_Voice_bot_demorequest  
    (  
        Name,  
        Mobile,  
        CreatedOn,  
        BotId  
    )  
    VALUES  
    (  
        @Name,  
        @Mobile,  
        GETDATE(),  
        @BotID  
    );  
    DECLARE @NewRequestId BIGINT = SCOPE_IDENTITY();  
    -- Call the processing procedure for the newly inserted request  
    BEGIN TRY  
        EXEC dbo.usp_processvoicebotdemo @NewRequestId;  
    END TRY  
    BEGIN CATCH  
        -- Log the error, return insert id and error  
        EXEC dbo.usp_InsertErrorInfo;  
        SELECT 'ERROR_PROCESSING' AS Status, @NewRequestId AS RequestId, ERROR_MESSAGE() AS ErrorMessage;  
        RETURN;  
    END CATCH  
    SELECT 'SUCCESS' AS Status, @NewRequestId AS RequestId;  
    RETURN;  
END;   
    IF (@Mode = 'SendMessage')       
    BEGIN       
        DECLARE       
            --@Mobile NVARCHAR(MAX),       
            @Message NVARCHAR(2500),       
            @DLTTemplateID NVARCHAR(200),       
            @IsUnicode INT = 0,       
            @Priority INT = 1;             
              
            SELECT       
            @Mobile = JSON_VALUE(@JsonData, '$.Mobile'),       
            @Message = JSON_VALUE(@JsonData, '$.Message'),       
            @DLTTemplateID = JSON_VALUE(@JsonData, '$.DLTTemplateID'),       
            @IsUnicode = ISNULL(JSON_VALUE(@JsonData, '$.IsUnicode'), 0),       
            @Priority = ISNULL(JSON_VALUE(@JsonData, '$.Priority'), 1);             
              
            EXEC usp_sendmessage_WithDLTTemplateID       
            @u_id = @UserId,       
            @message = @Message,       
            @mobile = @Mobile,       
            @sender = 'KITAPP',       
            @isunicode = @IsUnicode,       
            @priority = @Priority,       
            @DLTTemplateID = @DLTTemplateID;             
              
            SELECT 'MESSAGE_SENT' AS Status;             
            RETURN;       
    END  
   
    IF (LOWER(ISNULL(LTRIM(RTRIM(@Mode)), '')) = 'getlatestdemoconversation')    
BEGIN  
    DECLARE @AudienceId BIGINT;  
   
   set @BotId = TRY_CONVERT(BIGINT, JSON_VALUE(@JsonData,'$.botId'));  
   
    DECLARE @CallLogId BIGINT;  
    --------------------------------------------------  
   
    -- 1️⃣ Get LATEST processed demo request  
   
    --------------------------------------------------  
   
    SELECT TOP 1  
   
        @AudienceId = audienceid,  
   
        @BotId = BotId  
   
    FROM dbo.tbl_Voice_bot_demorequest WITH(NOLOCK)  
   
    WHERE BotId = @BotId  
   
      AND IsProcessed = 1  
   
    ORDER BY CreatedOn DESC;  
    --------------------------------------------------  
   
    -- 2️⃣ Get LATEST call for that audience  
   
    --------------------------------------------------  
   
    SELECT TOP 1  
   
        @CallLogId = id  
   
    FROM dbo.calllog WITH(NOLOCK)  
   
    WHERE audienceid = @AudienceId  
   
      AND bot_id = @BotId  
   
    ORDER BY Callstarttime DESC;  
    --------------------------------------------------  
   
    -- 3️⃣ Return FULL conversation  
   
    --------------------------------------------------  
   
  --------------------------------------------------  
   
-- 3️⃣ Return FULL conversation + Call Summary  
   
--------------------------------------------------  
SELECT  
   
    v.id,  
   
    v.calllog_id,  
   
    v.turn_number,  
   
    v.user_input AS Description,  
   
   v.bot_response AS ActivePrompts,  
   
    v.created_at,  
   
    v.sentiment_score,  
   
    v.ChatAgentInputTokens,  
   
    v.ChatAgentOutputTokens,  
   
    v.TTSCharacters,  
    -- ⭐ Call Summary Columns (same result set)  
   
    --cs.id AS SummaryId,  
   
   (  
    CASE   
        WHEN ISNULL(cs.call_summary, '') <> ''  
        THEN ISNULL(cs.call_summary, '')   
             + CHAR(13) + CHAR(10)   
             + 'AdditionalDetails '   
             + ISNULL(cs.additional_details, '')  
        ELSE ''  
    END  
   ) AS businessrules  
   
            
    , cs.additional_details as handoffrules   
      --cs.created_on AS SummaryCreatedOn  
FROM dbo.voice_bot_conversation_turns v WITH(NOLOCK)  
LEFT JOIN  
   
(  
   
    SELECT TOP 1 *  
   
    FROM dbo.call_summaries WITH(NOLOCK)  
   
    WHERE calllog_id = @CallLogId  
   
    ORDER BY id DESC  
   
) cs  
   
ON v.calllog_id = cs.calllog_id  
WHERE v.calllog_id = @CallLogId  
   
ORDER BY v.turn_number;  
    RETURN;  
   
END  
  
  
END;



GO

/* ============================================================
   Procedure: [dbo].[usp_ai_GetVoicebotCampaign]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- Exec usp_ai_GetVoicebotCampaign @UserId=34594, @VoiceBotCampaignId=0
-- Exec usp_ai_GetVoicebotCampaign @UserId=34594, @VoiceBotCampaignId=3
CREATE   PROC usp_ai_GetVoicebotCampaign
(
    @UserId bigint,
    @VoiceBotCampaignId bigint=0
)
as
Begin
    declare @ParentId bigint
    Select @ParentId=ParentId From User_detail(nolock) Where User_ID=@UserId

    If(@VoiceBotCampaignId = 0)
    Begin
        select VBC.id,(select top 1 Bot_name from voice_bot_details(nolock) Where id=json_value(VBC.campaign_settings,'$.botId')) as VoiceBotName,VBC.parentid, concat(UD.User_Login,'(',UD.FName,' ',UD.LName,')') as created_by,VBC.created_on,VBC.campaign_name,VBC.isactive,VBC.campaign_settings,VBC.last_run,VBC.next_run,VBC.total_reach,VBC.campaign_end_date,VBC.days_json,VBC.campaign_start_date 
        from voice_bot_campaigns(nolock) VBC left join User_detail(nolock) UD
        On  VBC.created_by=UD.User_ID
        Where VBC.parentid=@ParentId and VBC.isactive=1 and VBC.isdemo=0
        order by VBC.created_on desc
    End
    Else
    Begin
        select VBC.id,(select top 1 Bot_name from voice_bot_details(nolock) Where id=json_value(VBC.campaign_settings,'$.botId')) as VoiceBotName,VBC.parentid, concat(UD.User_Login,'(',UD.FName,' ',UD.LName,')') as created_by,VBC.created_on,VBC.campaign_name,VBC.isactive,VBC.campaign_settings,VBC.last_run,VBC.next_run,VBC.total_reach,VBC.campaign_end_date,VBC.days_json,VBC.campaign_start_date 
        from voice_bot_campaigns(nolock) VBC left join User_detail(nolock) UD
        On  VBC.created_by=UD.User_ID
        Where VBC.id=@VoiceBotCampaignId
    End

End



