/* ============================================================
   Procedure: [dbo].[usp_ai_GetWebhooksForAssistant]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_ai_GetWebhooksForAssistant](
    @assistantId nvarchar(255)
)
as
begin
  
    
    --declare @assistantId nvarchar(255) = 'asst_Nh5hNy8QDqcPEgSzFgpZPGmF'

  
    declare 
        @bot_type nvarchar(50) = 'mail',
        @bot_id nvarchar(255),
        @temperature float

    select @bot_id = AgentId, @temperature = temperature from tbl_ai_Agents with (nolock) where AssistantId = @assistantId

    SELECT  
        d.webhook_id AS webhook_id,  
        m.bot_id AS bot_id,  
        d.version AS version,  
        m.webhook_slug AS webhook_slug,  
        d.description AS description,  
        m.is_enabled AS is_enabled,  
        m.trigger_type AS trigger_type,  
        m.trigger_config AS trigger_config,  
        d.http_method AS http_method,  
        d.url_template AS url_template,  
        d.query_template AS query_template,  
        d.header_template AS header_template,  
        d.body_template AS body_template,  
        d.auth_type AS auth_type,  
        d.auth_config AS auth_config,  
        d.secret_ref AS secret_ref,  
        m.llm_parameters AS llm_parameters,  
        m.response_mode AS response_mode,  
        d.extract_slots AS extract_slots,  
        d.response_shaping AS response_shaping,  
        m.prompt_template AS prompt_template,  
        d.timeout_ms AS timeout_ms,  
        d.max_response_size_bytes AS max_response_size_bytes,  
        m.filler_while_waiting AS filler_while_waiting,  
        m.on_error_strategy AS on_error_strategy,  
        m.on_error_fallback_message AS on_error_fallback_message,  
        d.is_idempotent AS is_idempotent,  
        m.confirmation_required AS confirmation_required,  
        d.retry_max_attempts AS retry_max_attempts,  
        d.retry_base_delay_ms AS retry_base_delay_ms,  
        d.extract_on_error AS extract_on_error,
        @temperature as temperature
    FROM bot_webhook_mapping m  
    INNER JOIN webhook_definition d  
        ON d.webhook_id = m.webhook_id  
    WHERE m.bot_type   = @bot_type  
      AND m.bot_id     = @bot_id  
      AND m.is_enabled = 1  
      AND m.deleted_on IS NULL  
      AND d.deleted_on IS NULL  
    ORDER BY m.webhook_slug;  
end



