/* ============================================================
   Procedure: [dbo].[usp_ai_InitializeChat]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_ai_InitializeChat]
    @strVisitorId NVARCHAR(255) = NULL,
    @strSessionId NVARCHAR(255) = NULL,
    @DeviceId NVARCHAR(255),
    @UserAgent NVARCHAR(255) = NULL,
    @IPAddress NVARCHAR(50) = NULL,
    @AgentKey NVARCHAR(255) = '',
    @MetaData NVARCHAR(MAX) = '{}'
AS
BEGIN

    --DECLARE
    --    @strVisitorId NVARCHAR(255) = 'visitor_0001',
    --    @strSessionId NVARCHAR(255) = 'session_0001',
    --    @DeviceId NVARCHAR(255) = 'device_001',
    --    @UserAgent NVARCHAR(255) = 'window',
    --    @IPAddress NVARCHAR(255) = '127.0.0.1',
    --    @AgentKey NVARCHAR(255) = 'ai-studio_r25dclFDYwMEMRefRTs9Wldc_mi72oscr',
    --    @MetaData NVARCHAR(MAX) = '{}'

    SET NOCOUNT ON;
    
    DECLARE @NewVisitorId NVARCHAR(100);
    DECLARE @NewSessionId NVARCHAR(100);
    DECLARE @WelcomeMessage NVARCHAR(MAX);
    DECLARE @MqttTopic NVARCHAR(200);

    DECLARE @inAgentId BIGINT, @inDeviceId BIGINT, @inVisitorId BIGINT, @CompanyId BIGINT, @ParentId BIGINT;
    
    SELECT @inAgentId = AgentId, @ParentId = ParentId FROM dbo.tbl_ai_AgentApiKeys WHERE ApiKeyHash = @AgentKey AND IsActive = 1;

    IF(ISNULL(@inAgentId, 0) = 0)
    BEGIN
        RAISERROR('Invalid or inactive Agent API Key.', 16, 1);
        RETURN;
    END

    SELECT @CompanyId = CompanyId FROM dbo.tbl_ai_Agents WHERE AgentId = @inAgentId

    BEGIN TRY
        BEGIN TRANSACTION;

        SELECT @inDeviceId = Id FROM tbl_ai_Devices WITH (NOLOCK) WHERE DeviceId = @DeviceId;

        IF (ISNULL(@inDeviceId, 0) = 0)
        BEGIN
            INSERT INTO tbl_ai_Devices (DeviceId, UserAgent, IPAddress, FirstSeenAt, LastSeenAt, ParentId, DetailJson)
            VALUES (@DeviceId, @UserAgent, @IPAddress, GETDATE(), GETDATE(), @ParentId, @MetaData);
            SELECT @inDeviceId = SCOPE_IDENTITY();
        END
        ELSE
        BEGIN
            UPDATE tbl_ai_Devices 
            SET LastSeenAt = GETDATE(), 
                UserAgent = COALESCE(@UserAgent, UserAgent),
                IPAddress = COALESCE(@IPAddress, IPAddress),
                UpdatedAt = GETDATE(),
                DetailJson = @MetaData
            WHERE Id = @inDeviceId;
        END
        
        print concat('@strVisitorId => ', @strVisitorId)

        SELECT @inVisitorId = VisitorId FROM tbl_ai_Visitors WITH (NOLOCK) WHERE trim(strVisitorId) = trim(@strVisitorId)
        print concat('@inVisitorId => ', @inVisitorId)
        IF(ISNULL(@inVisitorId, 0) = 0)
        BEGIN
            INSERT INTO tbl_ai_Visitors (strVisitorId, DeviceId, AgentId, CompanyId, ParentId)
            VALUES (@strVisitorId, @inDeviceId, @inAgentId, @CompanyId, @ParentId);
            SET @inVisitorId = SCOPE_IDENTITY();
        END
        ELSE
        BEGIN
            UPDATE tbl_ai_Visitors SET ModifiedOn = GETDATE() WHERE VisitorId = @inVisitorId;
        END

        if(NOT EXISTS(select 1 from tbl_ai_VisitorsLastResponse with (nolock) where entityName = 'visitor' and entityId = @inVisitorId))
        begin
            insert into tbl_ai_VisitorsLastResponse(entityName, entityId, mode, parentid)
                values ('visitor', @inVisitorId, 'webchat', @ParentId)
        end

        
        DECLARE @inSessionId BIGINT = NULL;
        SELECT @inSessionId = Id FROM tbl_ai_ChatSessions  WITH (NOLOCK) WHERE SessionId = @strSessionId;

        IF(ISNULL(@inSessionId, 0) = 0)
        BEGIN
            INSERT INTO tbl_ai_ChatSessions (SessionId, VisitorId, DeviceId, AgentId, MqttTopic, Status, ParentId)
                VALUES (@strSessionId, @inVisitorId, @inDeviceId, @inAgentId, @MqttTopic, 'Active', @ParentId);
            SET @inSessionId = SCOPE_IDENTITY()
        END
        ELSE
        BEGIN
            UPDATE tbl_ai_ChatSessions SET  EndedAt = GETDATE() WHERE Id = @inSessionId
        END

        
        COMMIT TRANSACTION;

                -- Return existing session with history
        SELECT 
            @strSessionId AS session_id,
            @strVisitorId AS visitor_id,
            @DeviceId AS device_id,
            a.LastMessage,
            ac.DetailsJson AS agent_details,
            ws.DetailsJson AS widget_settings
        FROM tbl_ai_Visitors a WITH (NOLOCK)
        INNER JOIN tbl_ai_Agents ac WITH (NOLOCK) ON ac.AgentId = a.AgentId
        INNER JOIN tbl_ai_ChatSessions cs WITH (NOLOCK) ON cs.AgentId = a.AgentId
        INNER JOIN tbl_ai_WidgetSettings ws WITH (NOLOCK) ON ws.AgentId = cs.AgentId

        WHERE cs.Id = @inSessionId AND ac.AgentId = @inAgentId;
            
        -- Return chat history
        SELECT 
            ConversationId, 
            '{}' as [Sender],
            '' as 'text',
            cs.DetailsJson,
            cs.CreatedOn,
            direction as [Direction]
        FROM tbl_ai_Conversations cs WITH (NOLOCK)
        INNER JOIN tbl_ai_Visitors v WITH (NOLOCK) on cs.VisitorId = v.VisitorId
        WHERE cs.ChatSessionId = @inSessionId
        ORDER BY cs.CreatedOn ASC;

        DECLARE @suggestion as table (suggestion nvarchar(max))
            
        -- Return last suggestions
            insert into @suggestion(suggestion)
            SELECT DISTINCT TOP 5
                SuggestionText AS suggestion
            FROM tbl_ai_ChatSuggestions
            WHERE SessionId = @NewSessionId 
                AND MessageId = (SELECT MAX(MessageId) FROM tbl_ai_ChatMessages WHERE SessionId = @NewSessionId)
            
        if(not exists(select 1 from @suggestion))
        begin
            -- Return default suggestions
            insert into @suggestion(suggestion)
                values ('Get started'), ('Learn more'), ('Contact support')
        end

        select * from @suggestion

    END TRY
    BEGIN CATCH
        IF @@TRANCOUNT > 0
            ROLLBACK TRANSACTION;
        
        THROW;
    END CATCH
END



GO

/* ============================================================
   Procedure: [dbo].[usp_ai_insert_execution_metrics]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_ai_insert_execution_metrics]
    @AgentId BIGINT,
    @ExecutionId BIGINT = NULL,
    @OutboxId BIGINT = NULL,
    @InputTokens INT = 0,
    @OutputTokens INT = 0,
    @Cost DECIMAL(18, 4) = 0,
    @ProcessingTimeSeconds DECIMAL(18, 4) = 0,
    @MetadataJson NVARCHAR(MAX) = NULL
AS
BEGIN
    SET NOCOUNT ON;
    
    BEGIN TRY
        -- Insert input tokens metric
        IF @InputTokens > 0
        BEGIN
            INSERT INTO tbl_agent_execution_metrics (
                agentid, execution_id, outbox_id, metric_type, metric_value, metadata_json, recorded_at
            )
            VALUES (
                @AgentId, @ExecutionId, @OutboxId, 'ai_tokens_input', @InputTokens, @MetadataJson, GETUTCDATE()
            );
        END
        
        -- Insert output tokens metric
        IF @OutputTokens > 0
        BEGIN
            INSERT INTO tbl_agent_execution_metrics (
                agentid, execution_id, outbox_id, metric_type, metric_value, metadata_json, recorded_at
            )
            VALUES (
                @AgentId, @ExecutionId, @OutboxId, 'ai_tokens_output', @OutputTokens, @MetadataJson, GETUTCDATE()
            );
        END
        
        -- Insert cost metric
        IF @Cost > 0
        BEGIN
            INSERT INTO tbl_agent_execution_metrics (
                agentid, execution_id, outbox_id, metric_type, metric_value, metadata_json, recorded_at
            )
            VALUES (
                @AgentId, @ExecutionId, @OutboxId, 'cost', @Cost, @MetadataJson, GETUTCDATE()
            );
        END
        
        -- Insert processing time metric
        IF @ProcessingTimeSeconds > 0
        BEGIN
            INSERT INTO tbl_agent_execution_metrics (
                agentid, execution_id, outbox_id, metric_type, metric_value, metadata_json, recorded_at
            )
            VALUES (
                @AgentId, @ExecutionId, @OutboxId, 'api_latency', @ProcessingTimeSeconds, @MetadataJson, GETUTCDATE()
            );
        END
        
        -- Call existing procedure to update agent-level statistics
        -- This updates tbl_ai_Agents: total_executions_today, avg_cost_per_execution, success_rate
        EXEC usp_ai_update_agent_statistics @AgentId = @AgentId;
        
        -- Return success
        SELECT 1 AS Success;
        
    END TRY
    BEGIN CATCH
        -- Log error but don't fail the service
        SELECT 0 AS Success, ERROR_MESSAGE() AS ErrorMessage;
    END CATCH
END



GO

/* ============================================================
   Procedure: [dbo].[usp_ai_InsertAssistantErrorLog]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_ai_InsertAssistantErrorLog]
    @visitorId BIGINT,
    @parentId BIGINT = NULL,
    @threadId NVARCHAR(255) = NULL,
    @runId NVARCHAR(255) = NULL,
    @errorSource NVARCHAR(100) = NULL,
    @errorMessage NVARCHAR(MAX) = NULL,
    @errorType NVARCHAR(200) = NULL,
    @stackTrace NVARCHAR(MAX) = NULL,
    @additionalContext NVARCHAR(MAX) = NULL,
    @createdOn DATETIME = NULL
AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @errorLogId BIGINT;

    BEGIN TRY

        declare @agentId bigint = 0
        select @agentId = AgentId from tbl_ai_Visitors(nolock) where VisitorId  = @VisitorId

        INSERT INTO tbl_ai_errorlog (agentid, ParentId, threadId, runId, ErrorSource, ErrorMessage, ErrorType, StackTrace, additional_details, CreatedOn, visitorId )
        VALUES ( @visitorId, @parentId, @threadId, @runId, @errorSource, @errorMessage, @errorType, @stackTrace, @additionalContext, isnull(@createdOn, null),  @visitorId
        );

        -- Get the inserted record ID
        SET @errorLogId = SCOPE_IDENTITY();

        -- Return the error log ID
        SELECT @errorLogId AS ErrorLogId;

    END TRY
    BEGIN CATCH
        exec usp_InsertErrorInfo
    END CATCH
END



GO

/* ============================================================
   Procedure: [dbo].[usp_ai_InsertConversationMessage]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_ai_InsertConversationMessage]  
    @strVisitorId NVARCHAR(255),  
    @strSessionId NVARCHAR(255),  
    @AgentKey NVARCHAR(255),  
    @MessageDetail NVARCHAR(MAX),  
    @Direction NVARCHAR(25),  
    @MetaData NVARCHAR(MAX),
    @TokenUsageId BIGINT = 0
AS  
BEGIN  
  
    --declare   
    --    @strVisitorId NVARCHAR(255) = N'visitor_487ec9aa-495d-4af7-92b3-d6193187a3eb',  
    --    @strSessionId NVARCHAR(255) = N'session_86accc84-523c-4677-8b70-9376b16935a4',  
    --    @AgentKey NVARCHAR(255) = N'ai-studio_r25dclFDYwMEMRefRTs9Wldc_mi72oscr',  
    --    @MessageDetail NVARCHAR(MAX) = N'{"type":"text","text":{"body":"Ask a question"},"audio":null,"image":null,"video":null,"suggestions":null}',  
    --    @Direction NVARCHAR(25) = N'inbound',  
    --    @MetaData NVARCHAR(MAX) = N'',
    --    @TokenUsageId BIGINT = 0
      
    PRINT CONCAT('@strVisitorId => ',@strVisitorId)  
    PRINT CONCAT('strSessionId => ',@strSessionId)  
    PRINT CONCAT('@AgentKey => ',@AgentKey)  
    PRINT CONCAT('@MessageDetail => ',@MessageDetail)  
    PRINT CONCAT('@MetaData => ',@MetaData)  
  
    --select * from tbl_ai_Visitors
    --SELECT @strVisitorId=N'visitor_28fbdcfa-434b-4765-84e8-f0794b5ac989',@strSessionId=N'session_a80c37a0-e556-46d2-8059-121e29a8e381',@AgentKey=N'ai-studio_r25dclFDYwMEMRefRTs9Wldc_mi72oscr',@MessageDetail=N'{"type":"text","text":{"body":"Hi"},"audio":null,"image":null,"video":null}',@Direction=N'inbound',@MetaData=N''  
  
    BEGIN TRY  
        BEGIN TRANSACTION  
  
        DECLARE @intVisitorId BIGINT, @intSessionId BIGINT, @intAgentId BIGINT, @intMessageId BIGINT = 0, @ParentId BIGINT = 0,  
                @companyId BIGINT = 0  
  
        PRINT 'Retrieving AgentId and ParentId...'  
        SELECT @intAgentId = AgentId, @ParentId = ParentId FROM tbl_ai_AgentApiKeys WITH (NOLOCK) WHERE ApiKeyHash = @AgentKey and IsActive = 1  
  
        PRINT 'Retrieving VisitorId...'  
        SELECT @intVisitorId = VisitorId, @companyId = CompanyId FROM tbl_ai_Visitors WITH (NOLOCK) 
            WHERE ParentId = @ParentId and strVisitorId = @strVisitorId  
  
        PRINT 'Retrieving SessionId...'  
        SELECT @intSessionId = Id FROM tbl_ai_ChatSessions WITH (NOLOCK) WHERE SessionId = @strSessionId AND VisitorId = @intVisitorId  
  
        PRINT 'Inserting Conversation Message...'  
        INSERT INTO tbl_ai_Conversations (ChatSessionId, AgentId, ParentId, DetailsJson, MetaData, CreatedOn,   
            CompanyId, EntityName, EntityId, VisitorId, [Type], [Direction], TokenUsageId, IsDeleted)  
        SELECT @intSessionId, @intAgentId, @ParentId, @MessageDetail, @MetaData, GETUTCDATE(),   
            @companyId, 'visitor', @intVisitorId, @intVisitorId, JSON_VALUE(@MessageDetail, '$.type'), @Direction, @TokenUsageId, 0

        SET @intMessageId = SCOPE_IDENTITY()  
        PRINT CONCAT('Inserted Conversation Message with MessageId => ', @intMessageId)  
        SELECT @intMessageId AS [conMessageId]  
        COMMIT TRANSACTION  
        
        -- updating VisitorLastResponse
        BEGIN TRY
            UPDATE tbl_ai_VisitorsLastResponse set 
                lastmessage_at = getutcdate(),
                lastmessage = json_value(@MessageDetail, '$.text.body'),
                direction = @Direction,
                parentid = isnull(parentid, @ParentId),
                agentId = @intAgentId
            where entityName = 'visitor' and entityId = @intVisitorId
        END TRY
        BEGIN CATCH
            EXEC usp_InsertErrorInfo
        END CATCH
    END TRY  
    BEGIN CATCH  
        print error_message()
        ROLLBACK TRANSACTION  
        PRINT 'Error occurred while inserting conversation message.'  
        EXEC usp_InsertErrorInfo  
    END CATCH  
END



GO

/* ============================================================
   Procedure: [dbo].[usp_ai_InsertEmailConversationMessage]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_ai_InsertEmailConversationMessage](
		@lastVisitorId bigint = 0, 
		@entityName nvarchar(25) = '',
		@entityId bigint = 0,
		@AgentId bigint = 0,
		@ParentId bigint = 0,
		@directon nvarchar(25) = null,
		@goalSlotJson nvarchar(max) = null,
		@EmailDetails nvarchar(max) = null,
		@mileStoreJson nvarchar(max) = null
)
as
begin

	--declare 
	--	@lastVisitorId bigint = 5628, 
	--	@entityName nvarchar(25) = 'lead',
	--	@entityId bigint = 7301709,
