/* ============================================================
   Procedure: [dbo].[usp_ai_inserterror]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE  PROCEDURE usp_ai_inserterror
@agentid bigint,@error_id bigint,@additional_details nvarchar(max)
as
begin
declare @parentid bigint,@mark_dormant bit,@md_till int,@md_unit varchar(4)
select @parentid=parentid from tbl_ai_agents(nolock) where agentid=@agentid
select @mark_dormant=mark_dormant ,@md_till =mark_dormant_for,@md_unit =mark_dormant_for_unit from tbl_ai_errormaster(nolock) where id=@error_id
insert into tbl_ai_errorlog(agentid,parentid,additional_details,error_id)
select @agentid,@parentid,@additional_details,@error_id
if @mark_dormant=1
begin
update tbl_ai_Agents set dormant_till=
case 
when @md_unit='Minute' then dateadd(MI,@md_till,getutcdate()) 
when @md_unit='Hour' then dateadd(HH,@md_till,getutcdate()) 
when @md_unit='Second' then dateadd(S,@md_till,getutcdate()) 
when @md_unit='Day' then dateadd(d,@md_till,getutcdate()) 
when @md_unit='month' then dateadd(M,@md_till,getutcdate()) 
when @md_unit='year' then dateadd(Y,@md_till,getutcdate()) 
else dormant_till end
where agentid=@agentid
end

end



