/* ============================================================
   Procedure: [dbo].[usp_ai_InsertTokenUsage]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_ai_InsertTokenUsage]
    @visitorId BIGINT,
    @parentId BIGINT = NULL,
    @threadId NVARCHAR(255) = NULL,
    @runId NVARCHAR(255) = NULL,
    @model NVARCHAR(100) = NULL,
    @promptTokens INT,
    @completionTokens INT,
    @totalTokens INT,
    @detailJson nvarchar(max)
AS
BEGIN

    SET NOCOUNT ON;

    DECLARE @tokenUsageId BIGINT;

    BEGIN TRY
        -- Insert token usage record
        INSERT INTO dbo.tbl_ai_TokenUsages ( visitorId, parentId, threadId, runId, model, promptTokens, completionTokens, totalTokens, detailJson )
        VALUES ( @visitorId, @parentId, @threadId, @runId, @model, @promptTokens, @completionTokens, @totalTokens, @detailJson );

        -- Get the inserted record ID
        SET @tokenUsageId = SCOPE_IDENTITY();

        begin try
            if(@tokenUsageId > 0)
            begin
                exec usp_ai_DeductAmount_AgentsTokenUsage @tokenUsageId
            end
        end try
        begin catch
            exec usp_InsertErrorInfo
        end catch

        -- Return the token usage ID
        SELECT @tokenUsageId AS TokenUsageId;

    END TRY
    BEGIN CATCH
        -- Log error and re-throw
        DECLARE @ErrorMessage NVARCHAR(4000) = ERROR_MESSAGE();
        DECLARE @ErrorSeverity INT = ERROR_SEVERITY();
        DECLARE @ErrorState INT = ERROR_STATE();

        RAISERROR (@ErrorMessage, @ErrorSeverity, @ErrorState);
    END CATCH
END



GO

/* ============================================================
   Procedure: [dbo].[usp_ai_InsertWhatsAppOutboxMessage]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_ai_InsertWhatsAppOutboxMessage](
	@intConvId bigint =  0,
	@entityName nvarchar(25) = '',
	@entityId bigint = '',
	@ParentId bigint = 0,
	@messageBody nvarchar(max) = N'',
	@recipient nvarchar(50) = N'', 
	@sender nvarchar(50) = '',
	@direction nvarchar(25) = '',
	@mode nvarchar(25) = '',
	@detailJson nvarchar(max) = '',
	@agentId bigint,
	@tokenUsageId bigint = 0
)	
as
begin

	--declare 
	--	@intConvId bigint =  0,
	--	@entityName nvarchar = 'lead',
	--	@entityId bigint = '',
	--	@ParentId bigint = 0,
	--	@messageBody nvarchar(max) = N'Hi',
	--	@recipient nvarchar(50) = N'', 
	--	@sender nvarchar(50) = '',
	--	@direction nvarchar(25) = 'inbound',
	--	@mode nvarchar(25) = 'whatsapp',
	--	@detailJson nvarchar(max) = '{}',
	--	@agentId bigint,
	--	@tokenUsageId bigint = 0

	declare @userName nvarchar(255)
	select @userName = User_Login from User_Detail with (nolock) where User_ID = @ParentID

	declare @lastVisitoriId bigint
	select @lastVisitoriId = id from tbl_ai_VisitorsLastResponse(nolock) where entityName = @entityName and entityId = @entityId

	if(isnull(@lastVisitoriId, 0) > 0)
	begin
		update tbl_ai_VisitorsLastResponse set 
			lastmessage_at  = getutcdate(),
			mode = @mode,
			direction = @direction,
			lastmessage = @messageBody,
			agentId = @agentId,
			parentid = @ParentId
			 where id = @lastVisitoriId
		
	end
	else
	begin
		declare @goalSlotJson nvarchar(max) = '{}';

		if(@entityName = 'lead')
		begin
			select @goalSlotJson = concat('{"visitor_name": "', PersonName, '","visitor_phone": "', 
				coalesce(nullif(MobileNo, ''), nullif(MobileNo1, ''), nullif(MobileNo2, '')),  '"}')
					from UserLeads with (nolock) where ID = @entityId
		end

		if(@entityName = 'enquiry')
		begin
			select @goalSlotJson = concat('{"visitor_name": "', PersonName, '","visitor_phone": "', 
				coalesce(nullif(MobileNo, ''), nullif(MobileNo1, ''), nullif(MobileNo2, '')),  '"}')
					from UserEnquiry with (nolock) where EnquiryID = @entityId
		end
		
		insert into tbl_ai_VisitorsLastResponse(entityName, entityId, lastmessage_at, createdon, mode, direction, lastmessage, 
			convid, IsOpen, parentid, agentId, goalSlotJson)
		values( @entityName, @entityId, getutcdate(), getutcdate(), @mode, @direction, @messageBody, @intConvId, 1, @ParentId, @agentId, @goalSlotJson)
		set @lastVisitoriId = scope_identity()
	end

	declare @visitorModeId bigint;
	select @visitorModeId = id from tbl_ai_VisitorsLastResponseThreadMaps with (nolock) 
		where lastVisitorResponseId = @lastVisitoriId and mode = @mode

	if(isnull(@visitorModeId, 0) = 0)
	begin
		insert into tbl_ai_VisitorsLastResponseThreadMaps(lastVisitorResponseId, mode, threadId)
			values(@lastVisitoriId, @mode, null)
		set @visitorModeId = scope_identity()
	end

	declare @aiConversationId bigint

	insert into tbl_ai_Conversations( ParentId, VisitorId, AgentId, Channel, Type, Direction, DetailsJson, CreatedOn, 
			CreatedBy, StartedAt, LastMessageAt, Metadata, ChatSessionId, EntityName, EntityId, TokenUsageId, CompanyId,
			IsDeleted
		)
	values ( @ParentId, 0, @agentId, 'whatsapp', 'text', @direction, @detailJson, getutcdate(), 
			@ParentId, getutcdate(), getutcdate(), '{}', 0, @entityName, @entityId, @tokenUsageId, 0,
			1
		)
	set @aiConversationId = scope_identity()

	declare @AssistantId nvarchar(255)
	select @AssistantId = AssistantId from tbl_ai_Agents(nolock) where AgentId = @agentId

	declare @ThreadId nvarchar(255)
	select @ThreadId  = threadid from tbl_ai_VisitorsLastResponseThreadMaps(nolock) 
		where lastVisitorResponseId = @lastVisitoriId and mode = @mode

	select 
		@lastVisitoriId as [lastVisitoriId],
		@visitorModeId as [visitorModeId],
		@aiConversationId as [aiConversationId],
		@AssistantId as [AssistantId],
		@ThreadId as [ThreadId],
		@userName as [userName]

end



GO

