CREATE   PROCEDURE [dbo].[usp_ai_ManageOutboxData](
	@outboxId bigint,
	@addtionalData nvarchar(max) = '',
	@isprocessed int = 0, 
	@Processing int = 0,
	@mode nvarchar(25) = 'get'
)
as
begin
	

	--declare 
	--	@outboxId bigint = 3,
	--	@addtionalData nvarchar(max) = '',
	--	@isprocessed int = 0, 
	--	@Processing int = 0,
	--	@mode nvarchar(25) = 'get'


	if(@mode = 'get')
	begin
		select id, queuename, agentid, asstt_id, payload, isprocessed, AttemptCount, Processing
			from tbl_ai_agent_execution_outbox with (nolock)
		where --isnull(AttemptCount, 0) < 6 and isprocessed = 0 and 
		id = @outboxId

	end

	if(@mode = 'update')
	begin
		update tbl_ai_agent_execution_outbox set 
			AttemptCount = case when @isprocessed = 3 then (isnull(AttemptCount, 0) + 1) else AttemptCount end,
			addtionalData = @addtionalData,
			isprocessed = @isprocessed,
			Processing = @Processing
		where id = @outboxId
	end
end



