/* ============================================================
   Procedure: [dbo].[usp_ai_mark_outbox_processed]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE usp_ai_mark_outbox_processed
    @OutboxId BIGINT,
    @IsProcessed BIT,
    @ErrorMessage NVARCHAR(MAX) = NULL
AS
BEGIN
    SET NOCOUNT ON;
    
    BEGIN TRY
        -- Update outbox entry
        UPDATE tbl_ai_agent_execution_outbox
        SET isprocessed = @IsProcessed,
            Processing = 0,
            processedat = CASE WHEN @IsProcessed = 1 THEN GETUTCDATE() ELSE processedat END,
            Lasterror = @ErrorMessage
        WHERE id = @OutboxId;
        
        -- Return success indicator
        SELECT @@ROWCOUNT AS RowsAffected, 1 AS Success;
        
    END TRY
    BEGIN CATCH
        -- Return error
        exec usp_inserterrorinfo
        SELECT 0 AS RowsAffected, 0 AS Success, ERROR_MESSAGE() AS ErrorMessage;
    END CATCH
END



GO

