        --END  
        -- Check existence and get ID  
        DECLARE @VisitorLastResponseId BIGINT, @DetailsJson nvarchar(max), @entityName nvarchar(50), @entityId bigint, @EventDescription NVARCHAR(MAX),  @EventName NVARCHAR(500);  
        --SELECT   
        --    @VisitorLastResponseId = Id  
        --FROM tbl_ai_VisitorsLastResponse  
        --WHERE entityId = @VisitorId;  
  
        set @VisitorLastResponseId=@VisitorId

       -- If not found  
        IF @VisitorLastResponseId IS NULL  
        BEGIN  
            RETURN 0;  
        END  

        UPDATE tbl_ai_VisitorsLastResponse  
        SET   
            laststatus = 'NotJunk',  
            laststatusid = 15,                 -- you can set appropriate junk status id  
            last_status_by = @UserId,  
            last_status_date = GETUTCDATE(),  
            IsOpen = 0,                       -- closed because junk  
            isopen_since = NULL,  
            is_junk = 0,                    -- mark as junk  
            @entityName=entityName,
            @entityId=entityId
        WHERE Id = @VisitorLastResponseId;  
  
    -- Insert remarks if provided  
        IF ISNULL(LTRIM(RTRIM(@Remarks)), '') <> ''  
        BEGIN  
            --INSERT INTO tbl_ai_VisitorRemarks  
            --(  
            --    VisitorLastResponseId,  
            --    Remarks,  
            --    CreatedBy,  
            --    CreatedOn  
            --)  
            --VALUES  
            --(  
            --    @VisitorLastResponseId,  
            --    @Remarks,  
            --    @UserId,  
            --    GETUTCDATE()  
            --);
            
            Set @DetailsJson= (select  id as ActionId,Action as ActionType, GETUTCDATE() as ActionDate,@Remarks as Remarks, @VisitorLastResponseId as VisitorLastResponseId
            from    tbl_ai_ActionMaster(nolock)
            Where   id=15 for json auto, WITHOUT_ARRAY_WRAPPER)

            insert into tbl_ai_VisitorActionHistory(EntityName,EntityId,DetailsJson,ActionId,VisitorsLastResponseId,CreatedOn,CreatedBy)
            Select  EntityName,EntityId,@DetailsJson,15,Id,GETUTCDATE(),@UserId 
            From    tbl_ai_VisitorsLastResponse(nolock)
            Where   id=@VisitorLastResponseId

        END  
  
        Select @EventName=concat(@entityName,' Conversation marked as Not junk'), @EventDescription=concat(@entityName,' Conversation marked as Not junk on ', getutcdate())
  
        Exec UspSaveEntityActivity_withid @entityName, @entityId, @UserId, @UserId, @EventDescription, @EventName, 'tbl_ai_VisitorsLastResponse', @VisitorLastResponseId

        RETURN 1; -- success  
  
    END TRY  
    BEGIN CATCH  
          
        EXEC usp_InsertErrorInfo;    
  
        RETURN -1; -- failure  
    END CATCH  
END  



GO

/* ============================================================
   Procedure: [dbo].[usp_ai_MessageExecutionOutbox]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE usp_ai_MessageExecutionOutbox
    @QueueName NVARCHAR(255),
    @AgenttKey NVARCHAR(255) = NULL,
    @strVisitorId NVARCHAR(255),
    @payload NVARCHAR(MAX) = NULL,
    @aiAgentId bigint = null
AS
BEGIN
    /*
    DECLARE 
        @QueueName NVARCHAR(255) = N'ai_message_execution_outbox',
        @strVisitorId NVARCHAR(255) = N'visitor_28fbdcfa-434b-4765-84e8-f0794b5ac989'
    */

    PRINT CONCAT('@QueueName => ', @QueueName)
    PRINT CONCAT('@strVisitorId => ', @strVisitorId)
    PRINT CONCAT('@payload => ', @payload)

    DECLARE @intOutboxId BIGINT = 0, @agentId BIGINT = 0

    BEGIN TRY
        
        IF(isnull(@aiAgentId, 0) > 0)
        BEGIN
            SELECT @agentId = @aiAgentId
        END

        
        -- retrieve AgentId based on VisitorId if needed
        IF (@AgenttKey IS NOT NULL AND isnull(@aiAgentId, 0) = 0)
        BEGIN
            -- Retrieve AgentId logic here
            SELECT @agentId = AgentId FROM tbl_ai_AgentApiKeys WITH (NOLOCK) WHERE ApiKeyHash = @AgenttKey AND IsActive = 1
        END

        BEGIN TRANSACTION

        -- Insert logic to add a new message to the outbox if payload is provided
        IF @payload IS NOT NULL
        BEGIN
            -- Insert statement here
            INSERT INTO tbl_ai_agent_execution_outbox (QueueName, Payload, CreatedOn, IsProcessed, AgentId)
            VALUES (@QueueName, @payload, GETUTCDATE(), 0, @agentId)
            SET @intOutboxId = SCOPE_IDENTITY()
        END

        COMMIT TRANSACTION
    END TRY
    BEGIN CATCH
        ROLLBACK TRANSACTION
        PRINT 'Error occurred while retrieving message execution outbox.'
        EXEC usp_InsertErrorInfo
    END CATCH

    SELECT @intOutboxId AS OutboxId, CASE WHEN @intOutboxId > 0 THEN 'Inserted' ELSE 'No Action' END AS [Status]
END



GO

/* ============================================================
   Procedure: [dbo].[usp_ai_PublishAgentById]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_ai_PublishAgentById (
    @PublishHistoryId BIGINT = 0,
    @AgentId BIGINT,
    @Version NVARCHAR(50),
    @StatusStr NVARCHAR(50) = 'processing',
    @PublishedBy BIGINT = NULL,
    @ChangeLog NVARCHAR(MAX) = NULL
)
AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @CurrentDateTime DATETIME2 = GETUTCDATE(), @Status INT = 0, @Message NVARCHAR(255) = '';

    IF(@AgentId IS NULL OR @Version IS NULL OR @PublishedBy IS NULL)
    BEGIN
        SELECT @Status = 0, @Message = 'AgentId, Version, and PublishedBy are required parameters.';
    END


    DECLARE @Exists INT;
    SET @Exists = CASE WHEN EXISTS( SELECT 1 FROM tbl_ai_AgentPublishHistories WITH (NOLOCK)
        WHERE ISNULL(AgentId, 0) = @AgentId AND IsActive = 1 and Status = 'processing') THEN 1 ELSE 0 END;

    IF(@Exists = 1)
    BEGIN
        SELECT @Status = 0, @Message = 'An active publishing process is already in progress for this AgentId.';
    END
    ELSE
    BEGIN
        SELECT @Status = 1, @Message = 'Ready to publish agent.';
        INSERT INTO tbl_ai_AgentPublishHistories (AgentId, Version, PublishedBy, ChangeLog, Status)
            VALUES (@AgentId, @Version, @PublishedBy, @ChangeLog, @StatusStr);
        SELECT @PublishHistoryId = SCOPE_IDENTITY()
        SELECT @Status = 1, @Message = 'Agent publishing initiated successfully.';
    END
    
    IF(@PublishHistoryId > 0)
    BEGIN
        UPDATE tbl_ai_AgentPublishHistories
        SET Status = @StatusStr,
            ChangeLog = @ChangeLog,
            PublishedOn = @CurrentDateTime
        WHERE PublishHistoryId = @PublishHistoryId
        
        SELECT @Status = 1, @Message = 'Agent publishing status updated successfully.';
    END

    SELECT @Status AS Status, @Message AS Message, @PublishHistoryId as [PublishHistoryId];
    
END



GO

