/* ============================================================
   Procedure: [dbo].[usp_ai_SaveAgentByMode]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_ai_SaveAgentByMode]  
    @payload nvarchar(max),  
    @Mode nvarchar(50),  
    @UserId bigint = 0  
as  
begin  

    --declare 
    --    @payload nvarchar(max) = N'{"agentId":230,"userId":34594,"mode":"emailConfig","detailsJson":"{\"emailAddress\":\"mukeshatkit19@gmail.com\",\"emailPassword\":\"Pelsoft@2025$\",\"smtpServer\":\"smtp.gmail.com\",\"smtpPort\":587,\"imapServer\":\"imap.gmail.com\",\"imapPort\":993,\"securityType\":\"TLS\",\"useAppPassword\":false,\"outgoingType\":\"ownEmail\",\"fromMail\":\"\",\"replyToMail\":\"\"}"}',  
    --    @Mode nvarchar(50) = N'emailConfig',  
    --    @UserId bigint = 34594

    set nocount on;  
  
    declare @ParentId bigint = NULL;  
    DECLARE @effectivePayload nvarchar(max) = @payload;  
  
    if @UserId > 0 set @ParentId = dbo.ufn_getuserparentid(@UserId);  
  
    declare @ProvidedAgentIdStr nvarchar(50) = JSON_VALUE(@payload, '$.agentId');  
    declare @ProvidedAgentId bigint = case when @ProvidedAgentIdStr is null then NULL else try_convert(bigint,@ProvidedAgentIdStr) end;  
    declare @AgentName nvarchar(200) = JSON_VALUE(@payload, '$.agentName');  
    declare @AgentDescription nvarchar(max) = JSON_VALUE(@payload, '$.agentDescription');  
    declare @AgentStatus nvarchar(50) = JSON_VALUE(@payload, '$.agentStatus');  
    declare @CompanyId bigint = try_convert(bigint, JSON_VALUE(@payload, '$.selectedCompanyId'));  
    -- Goal-specific fields  
    declare @GoalType nvarchar(200) = JSON_VALUE(@payload, '$.goalType');  
  
    declare @AgentId bigint = NULL;  
    declare @Action nvarchar(20) = NULL;  
    declare @ReturnGoalId bigint = NULL;  
    declare @ReturnWidgetId bigint = NULL;  
    declare @ReturnPersonaCount int = NULL;  
    declare @ReturnTriggerCount int = NULL;  
  
    begin try  
        begin transaction;  
  
        -- Update-only behavior: require existing AgentId for all modes  
        if @ProvidedAgentId is null or @ProvidedAgentId = 0  
        begin  
            raiserror('AgentId is required for update-only operation.',16,1);  
            rollback transaction;  
            return;  
        end  
  
        
        if lower(isnull(ltrim(rtrim(@Mode)),'')) = 'basic'  
        begin  

            select @ParentId = ParentId from tbl_ai_Agents with (nolock) where AgentId = @ProvidedAgentId
            if(exists(select 1 from tbl_ai_Agents with(nolock) where ParentId = @ParentId and [Name] = @AgentName))
            begin
                set @AgentName = concat(@AgentName, '_1')
            end

            update dbo.tbl_ai_Agents set
                CompanyId = COALESCE(@CompanyId, CompanyId),  
                Name = COALESCE(@AgentName, Name),  
                Status = COALESCE(@AgentStatus, Status),  
                DetailsJson = @payload,  
                ModifiedOn = getdate(),  
                ModifiedBy = NULLIF(@UserId,0)  
            where AgentId = @ProvidedAgentId;  
  
            set @AgentId = @ProvidedAgentId;  
            set @Action = 'update';  
        end  
        else if lower(isnull(ltrim(rtrim(@Mode)),'')) = 'goal'  
        begin  
            -- Update-only for goal mode: require a matching existing goal (AgentId + Type)  
            if @GoalType is null or len(ltrim(rtrim(@GoalType))) = 0  
            begin  
                raiserror('goalType is required for goal mode update-only operation.',16,1);  
                rollback transaction;  
                return;  
            end  
  
            declare @ExistingGoalId bigint = (select top 1 GoalId from dbo.tbl_ai_Goals where AgentId = @ProvidedAgentId);  
  
            if @ExistingGoalId is null  
            begin  
                -- Insert new goal (upsert behavior)  
                insert into dbo.tbl_ai_Goals (ParentId, AgentId, Title, Type, DetailsJson, CreatedOn, CreatedBy)  
                values (@ParentId, @ProvidedAgentId, @GoalType, @GoalType, JSON_QUERY(@payload), getdate(), NULLIF(@UserId,0));  
  
                set @ExistingGoalId = scope_identity();  
                set @Action = 'insert';  
            end  
            else  
            begin  
                update dbo.tbl_ai_Goals  
                set  
                    Title = COALESCE(@GoalType, Title),  
                    DetailsJson = JSON_QUERY(@payload),  
                    ModifiedOn = getdate(),  
                    ModifiedBy = NULLIF(@UserId,0)  
                where GoalId = @ExistingGoalId;  
  
                set @Action = 'update';  
            end  
  
            -- Persist slots (delete existing then insert new from payload)  
            if isjson(@payload) = 1 and json_query(@payload, '$.slots') is not null  
            begin  
                delete from dbo.tbl_ai_GoalSlots where GoalId = @ExistingGoalId;  
  
                insert into dbo.tbl_ai_GoalSlots (ParentId, GoalId, Name, Label, IsMandatory, IsUpdatable, DetailsJson, CreatedOn, CreatedBy)  
                select  
                    @ParentId,  
                    @ExistingGoalId,  
                    json_value([value],'$.name'),  
                    json_value([value],'$.label'),  
                    case when json_value([value],'$.mandatory') = 'true' then 1 else 0 end,  
                    case when json_value([value],'$.updatable') = 'true' then 1 else 0 end,  
                    [value],  
                    getdate(), NULLIF(@UserId,0)  
                from openjson(@payload, '$.slots');  
            end  
  
            -- Persist milestones (delete existing then insert new from payload)  
            if isjson(@payload) = 1 and json_query(@payload, '$.milestones') is not null  
            begin  
                delete from dbo.tbl_ai_GoalMilestones where GoalId = @ExistingGoalId;  
  
                insert into dbo.tbl_ai_GoalMilestones (ParentId, GoalId, [Order], Name, Description, DetailsJson, CreatedOn, CreatedBy)  
                select  
                    @ParentId,  
                    @ExistingGoalId,  
                    try_convert(int,json_value([value],'$.order')),  
                    json_value([value],'$.name'),  
                    json_value([value],'$.description'),  
                    [value],  
                    getdate(), NULLIF(@UserId,0)  
                from openjson(@payload, '$.milestones');  
            end  
  
            set @ReturnGoalId = @ExistingGoalId;  
            set @AgentId = @ProvidedAgentId;  
        end  
        else if lower(isnull(ltrim(rtrim(@Mode)),'')) = 'prompt'  
        begin  
            -- One-to-one persona: upsert a single persona row for the agent.  
            declare @SelectedPersona nvarchar(200) = JSON_VALUE(@payload, '$.persona');  
            declare @CustomPersonaName nvarchar(200) = JSON_VALUE(@payload, '$.customPersonaName');  
            declare @PersonaJson nvarchar(max) = NULL;  
            declare @PersonaName nvarchar(200) = NULL;  
            declare @PersonaIcon nvarchar(400) = NULL;  
            declare @PersonaDescription nvarchar(max) = NULL;  
            declare @PersonaDetails nvarchar(max) = NULL;  
            declare @persona_cursor_item nvarchar(max);  
  
            -- Upsert one persona row for this agent  
            declare @ExistingPersonaId bigint = (select top 1 PersonaId from dbo.tbl_ai_Personas where AgentId = @ProvidedAgentId and IsDeleted = 0);  
  
            if @ExistingPersonaId is null  
            begin  
                insert into dbo.tbl_ai_Personas (ParentId, AgentId, ConfigJson, DetailsJson, CreatedOn, CreatedBy, IsActive)  
                values (@ParentId, @ProvidedAgentId, @payload, @payload, getdate(), NULLIF(@UserId,0), 1);  
  
                set @ExistingPersonaId = scope_identity();  
                set @Action = 'insert';  
            end  
            else  
            begin  
                update dbo.tbl_ai_Personas  
                set  
                    ConfigJson = COALESCE(NULLIF(@payload,''), ConfigJson),  
                    DetailsJson = case when isjson(@payload) = 1 then @payload else DetailsJson end,  
                    ModifiedOn = getdate(),  
                    ModifiedBy = NULLIF(@UserId,0)  
                where PersonaId = @ExistingPersonaId;  
  
                set @Action = 'update';  
            end  
  
  
            set @AgentId = @ProvidedAgentId;  
            set @ReturnPersonaCount = case when @ExistingPersonaId is null then 0 else 1 end;  
        end  
        else if lower(isnull(ltrim(rtrim(@Mode)),'')) = 'widget'  
        begin  
            -- Upsert widget settings for the agent  
            declare @ExistingWidgetId bigint = (select top 1 WidgetId from dbo.tbl_ai_WidgetSettings where AgentId = @ProvidedAgentId and IsDeleted = 0);  
  
            if @ExistingWidgetId is null  
            begin  
                insert into dbo.tbl_ai_WidgetSettings (ParentId, AgentId, AssistantName, AssistantLogoUrl, PrimaryColor, DefaultChannel, DynamicFormsEnabled, ConfigJson, DetailsJson, CreatedOn, CreatedBy)  
                values (  
                    @ParentId,  
                    @ProvidedAgentId,  
                    JSON_VALUE(@payload, '$.assistantName'),  
                    JSON_VALUE(@payload, '$.assistantLogo'),  
                    JSON_VALUE(@payload, '$.primaryColor'),  
                    NULL,  
                    CASE WHEN JSON_VALUE(@payload, '$.dynamicForms') = 'true' OR JSON_VALUE(@payload, '$.dynamicForms') = '1' THEN 1 ELSE 0 END,  
                    JSON_QUERY(@payload),  
                    JSON_QUERY(@payload),  
                    getdate(), NULLIF(@UserId,0)  
                );  
  
                set @ReturnWidgetId = scope_identity();  
                set @Action = 'insert';  
            end  
            else  
            begin  
                update dbo.tbl_ai_WidgetSettings  
                set  
                    AssistantName = COALESCE(NULLIF(JSON_VALUE(@payload, '$.assistantName'),''), AssistantName),  
                    AssistantLogoUrl = COALESCE(NULLIF(JSON_VALUE(@payload, '$.assistantLogo'),''), AssistantLogoUrl),  
                    PrimaryColor = COALESCE(NULLIF(JSON_VALUE(@payload, '$.primaryColor'),''), PrimaryColor),  
                    DynamicFormsEnabled = CASE WHEN JSON_VALUE(@payload, '$.dynamicForms') = 'true' OR JSON_VALUE(@payload, '$.dynamicForms') = '1' THEN 1 ELSE 0 END,  
                    ConfigJson = JSON_QUERY(@payload),  
                    DetailsJson = JSON_QUERY(@payload),  
                    ModifiedOn = getdate(),  
                    ModifiedBy = NULLIF(@UserId,0)  
                where WidgetId = @ExistingWidgetId;  
  
                set @ReturnWidgetId = @ExistingWidgetId;  
                set @Action = 'update';  
            end  
  
            set @AgentId = @ProvidedAgentId;  
        end if lower(isnull(ltrim(rtrim(@Mode)),'')) = 'agentinstruction'  
        BEGIN  
            DECLARE @Instruction nvarchar(max) = NULL;  
   
            IF ISJSON(@effectivePayload) = 1  
            BEGIN  
                SET @Instruction = COALESCE(  
                    JSON_VALUE(@effectivePayload, '$.instruction'),  
                    JSON_VALUE(@effectivePayload, '$.agentInstruction'),  
                    JSON_VALUE(@effectivePayload, '$.prompt')  
                );  
            END  
            ELSE  
            BEGIN  
                SET @Instruction = LTRIM(RTRIM(@effectivePayload));  
            END  
   
            UPDATE dbo.tbl_ai_Agents  
            SET  
                AgentInstruction = @Instruction,  
                ModifiedOn = GETDATE(),  
                ModifiedBy = NULLIF(@UserId,0)  
            WHERE AgentId = @ProvidedAgentId;  
   
            SET @AgentId = @ProvidedAgentId;  
            SET @Action = 'update';  
        END  
  
        else if lower(isnull(ltrim(rtrim(@Mode)),'')) = 'trigger'  
        begin  
            -- Upsert trigger(s) from payload.intentAlerts for the agent  
            if isjson(@payload) = 1 and json_query(@payload, '$.intentAlerts') is not null  
            begin  
                declare @triggerJson nvarchar(max);  
                declare trigger_cursor cursor local for  
                    select [value] from openjson(@payload, '$.intentAlerts');  
  
                open trigger_cursor;  
                fetch next from trigger_cursor into @triggerJson;  
                while @@fetch_status = 0  
                begin  
                    declare @Event nvarchar(200) = JSON_VALUE(@triggerJson, '$.triggerWhen');  
                    declare @Name nvarchar(400) = COALESCE(JSON_VALUE(@triggerJson, '$.name'), 'Intent Alert - ' + ISNULL(@Event, N''));  
                    declare @Conditions nvarchar(max) = JSON_QUERY(@triggerJson, '$.conditions');  
                    declare @Actions nvarchar(max) = JSON_QUERY(@triggerJson);  
                    declare @ExistingTriggerId bigint = (select top 1 TriggerId from dbo.tbl_ai_Triggers where AgentId = @ProvidedAgentId and Event = @Event and IsDeleted = 0);  
  
                    if @ExistingTriggerId is null  
                    begin  
                        insert into dbo.tbl_ai_Triggers (ParentId, AgentId, Name, Event, Conditions, Actions, IsEnabled, DetailsJson, CreatedOn, CreatedBy, IsActive)  
                        values (@ParentId, @ProvidedAgentId, @Name, @Event, @Conditions, @Actions, 1, JSON_QUERY(@triggerJson), getdate(), NULLIF(@UserId,0), 1);  
                    end  
                    else  
                    begin  
                        update dbo.tbl_ai_Triggers  
                        set Name = COALESCE(NULLIF(@Name,''), Name),  
                            Conditions = COALESCE(@Conditions, Conditions),  
                            Actions = COALESCE(@Actions, Actions),  
                            DetailsJson = JSON_QUERY(@triggerJson),  
                            ModifiedOn = getdate(),  
                            ModifiedBy = NULLIF(@UserId,0)  
                        where TriggerId = @ExistingTriggerId;  
                    end  
  
                    fetch next from trigger_cursor into @triggerJson;  
                end  
  
                close trigger_cursor; deallocate trigger_cursor;  
            end  
  
            set @AgentId = @ProvidedAgentId; set @Action = 'upsert';  
            set @ReturnTriggerCount = (select count(1) from dbo.tbl_ai_Triggers where AgentId = @ProvidedAgentId and IsDeleted = 0);  
        end  
        else  if lower (isnull(ltrim(rtrim(@Mode)), '')) = 'emailconfig'
        begin
            print 'email config section'

            update dbo.tbl_ai_Agents  
            set predefined_settings = case when isjson(@payload) = 1 then JSON_QUERY(JSON_VALUE(@payload, '$.detailsJson')) else predefined_settings end,
                ModifiedOn = getdate(), ModifiedBy = NULLIF(@UserId,0)  
            where AgentId = @ProvidedAgentId;  
  
            set @AgentId = @ProvidedAgentId; set @Action = 'emailconfig';  
        end
            --begin  
            --    -- For other modes: update DetailsJson only on the agent  
            --    update dbo.tbl_ai_Agents  
            --    set DetailsJson = case when isjson(@payload) = 1 then JSON_QUERY(@payload) else @payload end,  
            --        ModifiedOn = getdate(), ModifiedBy = NULLIF(@UserId,0)  
            --    where AgentId = @ProvidedAgentId;  
  
            --    set @AgentId = @ProvidedAgentId; set @Action = 'update';  
            --end  
  
        commit transaction;  
  
        select @AgentId as AgentId, @Action as Action, @ReturnGoalId as GoalId, @ReturnWidgetId as WidgetId, @ReturnPersonaCount as PersonaCount;  
  
    end try  
    begin catch  
        if @@trancount > 0 rollback transaction;  
        declare @ErrMsg nvarchar(4000) = ERROR_MESSAGE();  
        raiserror('usp_ai_SaveAgentByMode failed: %s',16,1,@ErrMsg);  
        return;  
    end catch  
end  


GO

/* ============================================================
   Procedure: [dbo].[usp_ai_SaveAgentSettings]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_ai_SaveAgentSettings]
(
    @ParentId bigint,
    @AgentId bigint, 
    @agentName nvarchar(255),
    @predefinedAgentName nvarchar(255),
    @AgentSettingsJson NVARCHAR(MAX) 
)
AS
BEGIN
    
    --DECLARE 
    --    @ParentId bigint = 34594,
    --    @AgentId bigint = 0,
    --    @agentName nvarchar(255),
    --    @predefinedAgentId bigint = 1,
    --    @AgentSettingsJson NVARCHAR(MAX) = N'{"segments":[{"segment_id":236902,"channel":"whatsapp"}],"is_followup":false,"followup_depth_days":0,"followup_depth_count":0,"is_task":false,"task_depth_days":0,"task_depth_count":0,"is_appointment":false,"appointment_depth_days":0,"appointment_depth_count":0,"is_quotations":false,"quotation_depth_days":0,"quotation_depth_count":0,"is_invoice":false,"invoice_depth_days":0,"invoice_depth_count":0,"is_notes":false,"notes_depth_days":0,"notes_depth_count":0,"is_documents":false,"documents_depth_days":0,"documents_depth_count":0,"is_activities":true,"activities_depth_days":0,"activities_depth_count":10,"is_pipeline":false,"pipeline_depth_days":0,"pipeline_depth_count":0,"lead_columns":"","contactFrequency":0,"primary_language":"en","max_per_lead":0,"retry_lead_after":0,"max_execution":1,"parentId":0}'
    
    BEGIN TRY

        DECLARE @currentUtcDate datetime = getutcdate(), @isInserted int = 0

        declare @predefinedAgentId bigint  = 0

        select @predefinedAgentId = id from tbl_predefined_agents with (nolock) 
            where agent_name = @predefinedAgentName

        print concat('@predefinedAgentId => ', @predefinedAgentId)

        IF (isnull(@AgentId, 0) > 0)
        BEGIN
            UPDATE tbl_ai_Agents
            SET
                predefined_settings = @AgentSettingsJson,
                ModifiedOn = @currentUtcDate,
                UpdatedAt  = @currentUtcDate
            WHERE AgentId = @AgentId;

            set @isInserted = 1;
        END
        ELSE
        BEGIN
            INSERT INTO tbl_ai_Agents( ParentId, CompanyId, is_predefined, predefined_settings, IsBot,
                CreatedOn, CreatedAt, IsDeleted, predefined_agentid, [Name] ) 
            VALUES ( @ParentId, 0, 1, @AgentSettingsJson, 1, @currentUtcDate, @currentUtcDate, 0, @predefinedAgentId, @agentName );

            set @isInserted = 1;    
        END

        select @isInserted as IsInserted
        
    END TRY
    BEGIN CATCH
        THROW;
    END CATCH
END



GO

