/* ============================================================
   Procedure: [dbo].[usp_AI_SaveChatHistory]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

/*

exec usp_AI_SaveChatHistory 7877,'leadetails' , 'lead' , 'generate summary' , 'here is the summary' , 34594

	EXEC usp_AI_SaveChatHistory 1712372, 'UserLeads', 'lead', 'nalaytext', 'save response data', 32222;

*/

CREATE   PROC usp_AI_SaveChatHistory
(
	@P_RefId bigint,
	@P_reftable_name varchar(200),
	@P_entityName varchar(200),
	@P_prompt_text nvarchar(max),
	@P_Response_text nvarchar(max),
	@P_userId bigint
)
as
Begin
	
	Declare @ParentId bigint = (select parentid from user_detail(nolock) where User_ID = @P_userId) ;
	Declare @row_id bigint , @metadata varchar(max), @ActivityType varchar(10)= '' , @ActType VARCHAR(1) = '' ; 

	BEGIN TRY
	
		IF NOT EXISTS(SELECT 1 FROM  TBL_AI_GPTCHATHISTORY(nolock)  WHERE   REFID = @P_RefId  AND PARENTID = @PARENTID)  
		BEGIN  
			SET @ActivityType = 'Insert'; set @ActType ='I';

			INSERT INTO tbl_AI_GPTChatHistory( prompt_text	,response_text,	RefId	,ReftableName	,EntityName,	Parentid	,CreatedBy,	CreatedDate )
			VALUES (@P_prompt_text, @P_Response_text , @P_RefId ,  @P_reftable_name ,@P_entityName, @ParentId , @P_userId , GETDATE() )

			SELECT  @row_id = SCOPE_IDENTITY() ;

		END
		ELSE BEGIN

			SET @ActivityType = 'Update'; set @ActType ='U';
			update tbl_AI_GPTChatHistory set response_text= coalesce( @P_Response_text,'') + char(13)+ coalesce( response_text,''), ModifiedBy =@P_USERID , ModifiedDate = GETDATE()  
			where RefId = @P_RefId  and Parentid = @ParentId;  	
			
			select @row_id = History_id from TBL_AI_GPTCHATHISTORY(nolock)  WHERE   REFID = @P_RefId  AND PARENTID = @PARENTID

		END


	END TRY
	BEGIN CATCH
		PRINT CONCAT('Error occurred: ', ERROR_MESSAGE(), ' | Error Number: ', ERROR_NUMBER(), ' | Line: ', ERROR_LINE());
		
	END CATCH


	 SET @metadata = (  SELECT *  FROM tbl_AI_GPTChatHistory(nolock)  WHERE history_id = @row_id  FOR JSON AUTO );

	 PRINT @metadata;

	EXEC MySMSAudit.dbo.Usp_AuditTableDataByParentId @User_id = @P_userId  
	,@Activity_type = @ActivityType
	,@ActionType = @ActType
	,@RowJson =''
	,@Table_name = 'tbl_AI_GPTChatHistory'  ;


end


GO

/* ============================================================
   Procedure: [dbo].[usp_ai_SaveGoalTriggerEvents]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_ai_SaveGoalTriggerEvents](
	@tpGoalMileStoneReq tpGoalMileStoneReq readonly
)
as
begin

	--declare @tpGoalMileStoneReq as dbo.tpGoalMileStoneReq
	--insert into @tpGoalMileStoneReq values(N'visitor',44,N'goal',10,10,NULL)
	--insert into @tpGoalMileStoneReq values(N'visitor',44,N'milestone',171,10,N'Initial Contact')
	--insert into @tpGoalMileStoneReq values(N'visitor',44,N'milestone',174,10,N'Name Verified')

	drop table if exists #tpGoalMileStoneReq
	create table #tpGoalMileStoneReq(
		id bigint primary key identity(1, 1),
		entityName nvarchar(25),
		entityId bigint,
		eventName nvarchar(25),
		eventId bigint,
		agentId bigint,
		parentId bigint,
		eventFullname nvarchar(255),
		actionDetailJson nvarchar(max)

	)

	insert into #tpGoalMileStoneReq( entityName, entityId, eventName, eventId, agentId, eventFullname, actionDetailJson)
	select entityName, entityId, eventName, eventId, agentId, eventFullname, null from @tpGoalMileStoneReq

	declare @goalId bigint = 0, @goalName nvarchar(255)

	if(exists(select 1 from #tpGoalMileStoneReq where eventName = 'goal' and eventId > 0))
	begin
		select @goalId = eventId from #tpGoalMileStoneReq where eventName = 'goal'
		select @goalName = Title from tbl_ai_Goals with (nolock) where GoalId = @goalId
		update #tpGoalMileStoneReq set eventFullname = @goalName where eventName = 'goal' and eventId = @goalId
	end


	update m set m.actionDetailJson = t.DetailsJson, m.parentId = t.ParentId  from tbl_ai_Triggers t with (nolock) 
		inner join #tpGoalMileStoneReq m on 
			json_value(t.DetailsJson, '$.triggerWhen.wttTitle') = m.eventFullname 
			and json_value(t.DetailsJson, '$.triggerWhen.wttId') = m.eventId

	declare @insertedRecored as table (
		id bigint
	)

	delete i from  #tpGoalMileStoneReq i inner join tbl_ai_GoalMileStoneTriggerRequests r 
	on  i.entityName = r.entityName and  i.entityId = r.entityId and i.eventName = r.eventName 
		and i.eventId = r.eventId and i.agentId = r.agentId

	insert into tbl_ai_GoalMileStoneTriggerRequests(entityName, entityId, eventName, eventId, agentId, createdOn, isProcessed, 
		processCount, actionDefinition, parentId)
	output inserted.id into @insertedRecored
	select entityName, entityId, eventName, eventId, agentId, getutcdate(), 1 , 0, actionDetailJson, parentId from #tpGoalMileStoneReq

	select * from @insertedRecored

end



GO

/* ============================================================
   Procedure: [dbo].[usp_ai_SaveKnowledgeBase]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.usp_ai_SaveKnowledgeBase
    @KbId BIGINT = 0,
    @ParentId BIGINT = NULL,
    @CompanyId BIGINT = NULL,
    @Title NVARCHAR(500) = NULL,
    @Category NVARCHAR(200) = NULL,
    @Content NVARCHAR(MAX) = NULL,
    @DocumentType NVARCHAR(100) = NULL,
    @SourceUri NVARCHAR(1000) = NULL,
    @FileName NVARCHAR(500) = NULL,
    @MimeType NVARCHAR(200) = NULL,
    @FileSizeBytes BIGINT = NULL,
    @DocumentVersion NVARCHAR(50) = NULL,
    @Language NVARCHAR(50) = NULL,
    @PublishedAt DATETIME = NULL,
    @ExtractedText NVARCHAR(MAX) = NULL,
    @EmbeddingsJson NVARCHAR(MAX) = NULL,
    @Status NVARCHAR(50) = NULL,
    @Tags NVARCHAR(2000) = NULL, -- comma separated tag names
    @DetailsJson NVARCHAR(MAX) = NULL,
    @CreatedBy BIGINT = NULL,
    @ModifiedBy BIGINT = NULL
AS
BEGIN
    SET NOCOUNT ON;
    DECLARE @Now DATETIME = GETUTCDATE();
    DECLARE @ResultKbId BIGINT;

    BEGIN TRY
        BEGIN TRAN;

        IF @KbId IS NULL OR @KbId = 0
        BEGIN
            INSERT INTO dbo.tbl_ai_KnowledgeBase
            ( ParentId, CompanyId, Title, Category, Content, DocumentType, SourceUri, FileName, MimeType, FileSizeBytes, 
                DocumentVersion, Language, PublishedAt, ExtractedText, EmbeddingsJson, Status, Tags, DetailsJson, CreatedOn, CreatedBy, 
                ModifiedOn, ModifiedBy, IsDeleted, DeletedBy, DeletedOn, CreatedAt, UpdatedAt
            )
            VALUES
            (
                @ParentId, @CompanyId, @Title, @Category, @Content, @DocumentType, @SourceUri, @FileName, @MimeType, @FileSizeBytes, 
                @DocumentVersion, @Language, @PublishedAt, @ExtractedText, @EmbeddingsJson, @Status, @Tags, @DetailsJson, @Now, @CreatedBy,
                @Now, @CreatedBy, 0, 0, null,@Now, @Now
            );

            SET @ResultKbId = SCOPE_IDENTITY();
        END
        ELSE
        BEGIN
            UPDATE dbo.tbl_ai_KnowledgeBase
            SET
                ParentId = @ParentId,
                CompanyId = @CompanyId,
                Title = @Title,
                Category = @Category,
                Content = @Content,
                DocumentType = @DocumentType,
                SourceUri = @SourceUri,
                FileName = @FileName,
                MimeType = @MimeType,
                FileSizeBytes = @FileSizeBytes,
                DocumentVersion = @DocumentVersion,
                Language = @Language,
                PublishedAt = @PublishedAt,
                ExtractedText = @ExtractedText,
                EmbeddingsJson = @EmbeddingsJson,
                Status = @Status,
                Tags = @Tags,
                DetailsJson = @DetailsJson,
                ModifiedOn = @Now,
                ModifiedBy = @ModifiedBy,
                UpdatedAt = @Now
            WHERE KbId = @KbId;

            SET @ResultKbId = @KbId;
        END

        IF @Tags IS NOT NULL AND LTRIM(RTRIM(@Tags)) <> ''
        BEGIN
            DROP TABLE IF exists #tblAiTag
            
           ;WITH Splitted AS
            (
                SELECT TRIM(value) AS TagName
                FROM STRING_SPLIT(@Tags, ',')
                WHERE TRIM(value) <> ''
            )
            SELECT DISTINCT TagName INTO #tblAiTag FROM Splitted

            -- Remove existing mappings for this KB to refresh tags
            delete t from tbl_ai_Tags p 
                inner join #tblAiTag t on p.ParentId = @ParentId and p.CompanyId = @CompanyId and 
                    p.Name = t.TagName

            drop table if exists #tblKbMap
            create table #tblKbMap( KbId bigint, TagId bigint )

            -- Insert missing tags into tbl_ai_Tags
            INSERT INTO dbo.tbl_ai_Tags (Name, CompanyId, ParentId, CreatedAt)
                OUTPUT @KbId, inserted.TagId INTO #tblKbMap
            SELECT TagName, @CompanyId, @ParentId, @Now FROM #tblAiTag

            -- Link tags to KB
            INSERT INTO tbl_ai_KBTags(KbId, TagId)
            SELECT @KbId, T.TagId FROM #tblKbMap T
           
            DROP TABLE #tblKbMap;
        END

        COMMIT TRAN;
    END TRY
    BEGIN CATCH
        IF XACT_STATE() <> 0
            ROLLBACK TRAN;

        EXEC usp_InsertErrorInfo
        
    END CATCH

     select KbId, ParentId, CompanyId, Title, Category, Content, DocumentType, SourceUri, FileName, MimeType,   
  FileSizeBytes, DocumentVersion, Language, PublishedAt, ExtractedText, EmbeddingsJson, Status, Tags, DetailsJson, CreatedOn,   
  CreatedBy, ModifiedOn, ModifiedBy, IsDeleted, DeletedBy, DeletedOn, CreatedAt, UpdatedAt  
from tbl_ai_KnowledgeBase   
  with (nolock) where ParentId = @ParentId and KbId = @ResultKbId  

END



GO

