SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_ai_SaveTriggerAction(
	@entityName nvarchar(25) ,
	@entityId bigint,
	@eventName nvarchar(25),
	@eventId bigint,
	@agentId bigint,
	@actionName nvarchar(255),
	@isProcessed int,
	@processCount int = 1,
	@parentId bigint,
	@actionDetail nvarchar(max),
	@actionResponse nvarchar(max),
	@actionStartAt datetime,
	@actionEndAt datetime,
	@actionError nvarchar(max),
	@requestId bigint
)
as
begin
	
	declare @actionMasterId bigint
	select @actionMasterId = id from tbl_ai_ActionMaster where Action = @actionName

	insert into tbl_ai_TriggerActionHistories(entityName, entityId, eventName, eventId, actionMasterId, agentId, createdOn, isProcessed, processCount, 
		actionDetail, actionResponse, parentId, actionStartAt, actionEndAt, lastError, requestId)
	values (@entityName, @entityId, @eventName, @eventId, @actionMasterId, @agentId, getutcdate(), @isProcessed, @processCount,
		@actionDetail, @actionResponse, @parentId, @actionStartAt, @actionEndAt, @actionError, @requestId)

end



