AS
BEGIN
SET NOCOUNT ON;

BEGIN TRY
    -- Check if mapping exists
    IF EXISTS (SELECT 1 FROM dbo.tbl_ai_AgentVectorStores WHERE AgentId = @AgentId)
    BEGIN
        -- Update existing
        UPDATE dbo.tbl_ai_AgentVectorStores
        SET VectorStoreId = @VectorStoreId,
            ModifiedOn = GETUTCDATE()
        WHERE AgentId = @AgentId;
    END
    ELSE
    BEGIN
        -- Insert new
        INSERT INTO dbo.tbl_ai_AgentVectorStores (AgentId, VectorStoreId, CreatedOn)
        VALUES (@AgentId, @VectorStoreId, GETUTCDATE());
    END

    SELECT @@ROWCOUNT AS AffectedRows;
        
END TRY
BEGIN CATCH
   EXEC usp_InsertErrorInfo
END CATCH
END



