/* ============================================================
   Procedure: [dbo].[usp_ai_update_agent_statistics]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_ai_update_agent_statistics]
    @AgentId BIGINT
AS
BEGIN
    SET NOCOUNT ON;
    
    DECLARE @Today DATE = CAST(GETUTCDATE() AS DATE);
    
    -- Update agent-level statistics
    UPDATE a
    SET 
        total_executions_today = ISNULL(stats.executions_today, 0),
        last_execution_at = stats.last_execution,
        avg_cost_per_execution = ISNULL(stats.avg_cost, 0),
        success_rate = ISNULL(stats.success_rate, 0)
    FROM [dbo].[tbl_ai_Agents] a
    CROSS APPLY (
        SELECT 
            COUNT(1) AS executions_today,
            MAX(e.processedat) AS last_execution,
            AVG(m.metric_value) AS avg_cost,
            CAST(SUM(CASE WHEN e.isprocessed = 1 THEN 1.0 ELSE 0 END) / 
                 NULLIF(COUNT(1), 0) * 100 AS DECIMAL(5,2)) AS success_rate
        FROM [dbo].[tbl_ai_agent_entity_for_execution] e WITH (NOLOCK)
        LEFT JOIN [dbo].[tbl_agent_execution_metrics] m WITH (NOLOCK)
            ON e.id = m.execution_id AND m.metric_type = 'cost'
        WHERE 
            e.agentid = @AgentId
            AND CAST(e.createdon AS DATE) = @Today
    ) stats
    WHERE a.AgentId = @AgentId;
END;



GO

/* ============================================================
   Procedure: [dbo].[usp_ai_update_entity_status]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- =============================================
-- Stored Procedure: usp_ai_update_entity_status
-- Description: Update or insert entity status with AI metadata
-- =============================================

CREATE   PROCEDURE usp_ai_update_entity_status
    @AgentId bigINT,
    @EntityName VARCHAR(50),
    @EntityId bigINT,
    @ThreadId VARCHAR(100),
	@dormant_till datetime,
	@ai_status nvarchar(20),
	@do_not_contact bit,
    @LeadStatus VARCHAR(20),        -- 'hot', 'warm', 'cold'
    @HumanAlert BIT,
	@last_ai_message nvarchar(max),
	@lead_score int,
    @conversion_probability decimal(5,2),
    @Metadata NVARCHAR(MAX),        -- JSON from AI: {lead_status, human_alert, reason, next_action}
    @Success BIT OUTPUT,
	@Message VARCHAR(500) OUTPUT
AS
BEGIN
    SET NOCOUNT ON;
    
    BEGIN TRY
        -- Check if record exists
        IF EXISTS (
            SELECT 1 
            FROM tbl_ai_agent_entity_status (nolock)
            WHERE agentid = @AgentId 
              AND entityname = @EntityName 
              AND entityid = @EntityId
        )
        BEGIN
            -- Update existing record
            UPDATE tbl_ai_agent_entity_status
            SET 
                thread_id = @ThreadId,
                ai_status = @ai_status,
                do_not_contact = @do_not_contact,
                human_alert = @HumanAlert,
				dormant_till=@dormant_till,
                last_contacted = GETUTCDATE(),
                metadata = @Metadata,
				total_contacts=isnull(total_contacts,0)+1,
				last_ai_message=@last_ai_message,
				lead_score=@lead_score,
				conversion_probability=@conversion_probability
            WHERE agentid = @AgentId 
              AND entityname = @EntityName 
              AND entityid = @EntityId;
            
            SET @Success = 1;
            SET @Message = 'Entity status updated successfully';
        END
        ELSE
        BEGIN
            -- Insert new record
            INSERT INTO tbl_ai_agent_entity_status (
                agentid, 
                entityname, 
                entityid, 
                thread_id, 
                ai_status, 
                lead_score, 
                human_alert, 
                last_contacted,
                metadata,
				dormant_till,
				do_not_contact,
				total_contacts,
				last_ai_message,
				conversion_probability,
                createdon
            )
            VALUES (
                @AgentId,
                @EntityName,
                @EntityId,
                @ThreadId,
                @ai_status,
                @lead_score,
                @HumanAlert,
                GETUTCDATE(),
                @Metadata,
				@dormant_till,
				@do_not_contact,
				1,
				@last_ai_message,
				@conversion_probability,
                GETUTCDATE()
            );
            
            SET @Success = 1;
            SET @Message = 'Entity status inserted successfully';
        END
    END TRY
    BEGIN CATCH
	exec usp_inserterrorinfo
        SET @Success = 0;
        SET @Message = ERROR_MESSAGE();
    END CATCH
END



