   Procedure: [dbo].[usp_ai_UpdateThreadIdByLastVisitorId]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_ai_UpdateThreadIdByLastVisitorId(
	@lastVisitorId bigint,
	@tharedId nvarchar(max),
	@mode nvarchar(25)
)
as
begin

	--declare 
	--	@lastVisitorId bigint = 5628,
	--	@tharedId nvarchar(max) = '',
	--	@mode nvarchar(25) = 'email'

	declare @vThreadId bigint = 0

	select @vThreadId = id from tbl_ai_VisitorsLastResponseThreadMaps with (nolock) 
		where lastVisitorResponseId = @lastVisitorId and mode = @mode

	if(isnull(@vThreadId, 0) = 0)
	begin
		insert into tbl_ai_VisitorsLastResponseThreadMaps(lastVisitorResponseId, mode, threadId)
		select @lastVisitorId, @mode, @tharedId
		select @vThreadId = scope_identity()
	end
	else
	begin
		update tbl_ai_VisitorsLastResponseThreadMaps set threadId = @tharedId where id = @vThreadId
	end

end



