CREATE   PROCEDURE [dbo].[usp_ai_UpdateVisitorGoalSlotJson]
(
    @visitorId BIGINT,
    @entityName NVARCHAR(25),
    @entityId BIGINT,
    @goalSlotJson NVARCHAR(MAX) = N'{}'
)
AS
BEGIN
    --SET NOCOUNT ON;

    
    UPDATE tbl_ai_VisitorsLastResponse SET goalSlotJson = @goalSlotJson
        WHERE entityName = @entityName AND entityId = @entityId;

    if(@entityName = 'visitor')
    begin
        

        UPDATE tbl_ai_Visitors SET 
            goalSlotJson = @goalSlotJson,
            [Name] = isnull([Name], json_value(@goalSlotJson, '$.visitor_name')),
            [Phone] = isnull([Phone], json_value(@goalSlotJson, '$.visitor_phone')),
            [email] = isnull([email], json_value(@goalSlotJson, '$.visitor_email'))
        where VisitorId = @visitorId
    end

END



