    --declare 
    --    @VisitorId bigint = 44,
	   -- @ThreadId nvarchar(255) = 'thread_6cBG1TyMS2wJSJiudb7tCcrS'

    -- update tbl_ai_Visitors set threadId = @ThreadId where VisitorId = @VisitorId

	 declare @entityName nvarchar(255) = 'visitor', @entityId bigint = 0, @lastVisitorResponseId bigint = 0, @lastModeId bigint = 0
        

    select @entityId = @VisitorId 
     
    print concat('@entityName => ', @entityName)
    print concat('@entityId => ', @entityId)

    select @lastVisitorResponseId =  id from tbl_ai_VisitorsLastResponse with (nolock) where entityName = @entityName and entityId = @entityId

    select @lastModeId = id from tbl_ai_VisitorsLastResponseThreadMaps with (nolock) where mode = 'webchat'
        and lastVisitorResponseId = @lastVisitorResponseId

    if(isnull(@lastModeId, 0) = 0)
    begin
        insert into tbl_ai_VisitorsLastResponseThreadMaps (lastVisitorResponseId, mode, threadId)
            values (@lastVisitorResponseId, 'webchat', @ThreadId)
    end

    if(isnull(@lastModeId, 0) > 0)
    begin
        update tbl_ai_VisitorsLastResponseThreadMaps set threadId = @ThreadId where id = @lastModeId
    end

end



