   Procedure: [dbo].[usp_ai_VoiceSummaryTriggerProcessUpdate]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_ai_VoiceSummaryTriggerProcessUpdate(
    @actionId bigint,
    @isprocessed int = null,
    @status bit = null,
    @error_description nvarchar(max) = null,
    @internal_error nvarchar(max) = null,
    @bot_reasoning nvarchar(max) = null
)
as  
begin
    --declare 
    --    @voiceSummaryId bigint,
    --    @isprocessed int,
    --    @status bit,
    --    @error_description nvarchar(max),
    --    @internal_error nvarchar(max),
    --    @bot_reasoning nvarchar(max)

    
    update voice_bot_actions_taken set
        isprocessed = isnull(@isprocessed, isprocessed),
        status = isnull(@status, status),
        error_description = isnull(@error_description, error_description),
        internal_error = isnull(@internal_error, internal_error),
        bot_reasoning = isnull(@bot_reasoning, bot_reasoning)
    where id = @actionId
end



