/* ============================================================
   Procedure: [dbo].[usp_AI_WhatsAppChatToReply]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

/*
	EXEC usp_AI_WhatsAppChatToReply  714557 , 34594, 3
	TBL_AI_GPTCHATHISTORY
--	delete from TBL_AI_GPTCHATHISTORY where history_id >10

*/

CREATE   PROC [dbo].[usp_AI_WhatsAppChatToReply]
(
	@P_SenderId BIGINT,
	@P_USERID BIGINT,
	@P_Option int,
	@P_Response_text nvarchar(max) = ''
)
AS
BEGIN

	BEGIN TRY

		Declare @ParentId bigint = ( select parentid from user_detail(nolock) where User_ID = @P_USERID) 
		Declare @SqlQuery nvarchar(max), @tableName varchar(100);
	
		print '@ParentId = ' + cast( coalesce( @ParentId,'') as varchar(20) );

		Declare @Prompt_text nvarchar(max)= 'Understand the chat below and create an appropriate, professional response in 20 words format as a chat message of below Json data. 
										Ignore links of	images and read plain text chat message. and create a reply message for them. 
										Act as chat person and your messages are in json data where Message type = sent and other messages are from customer.  
										Suggest at least 3  reply messages.	'

		, @WhatsAppChat_data Nvarchar(max);

		set @tableName = 'tbl_conversations_'+ convert(varchar(20) ,@ParentId);

		IF (@P_Option =1) BEGIN  
							
				--set @SqlQuery = ' SET  @WhatsAppChat_data = (select top 1 case when recipientid = '+CONVERT(varchar(15), @P_SenderId) +' then ''Received'' else  ''Sent'' end as MessageType  from   MyCTest.dbo.tbl_conversations_'+ CONVERT(varchar(20),@ParentId ) +' where @P_SenderId in (senderid,recipientid) order by id desc) ';

				--EXEC sp_executesql @SqlQuery, 
				--N'@P_SenderId INT, @WhatsAppChat_data NVARCHAR(MAX) OUTPUT',
				--@P_SenderId = @P_SenderId, 
				--@WhatsAppChat_data = @WhatsAppChat_data OUTPUT; 

				--if (@WhatsAppChat_data ='Received') begin
				--	Select 'False' as Message ,'Don''t send' As Result;
				--	return;
				--end


				/***/

				/*set @SqlQuery = 'SET  @WhatsAppChat_data = ( select case when recipientid = '+CONVERT(varchar(15), @P_SenderId) +' then ''Received'' else  ''Sent'' end as MessageType, 
					bodytext as chatMessage from  MySMSConversations.dbo.tbl_conversations_'+ CONVERT(varchar(15), @ParentId) +'(nolock) where @P_SenderId in (senderid,recipientid) and 
					createdon between dateadd(day,-1, getdate()) and getdate() order by id FOR JSON PATH ) ';*/
					SET @SqlQuery = '
                     SELECT CASE 
                               WHEN recipientid = ' + CONVERT(VARCHAR(15), @P_SenderId) + ' THEN ''Received'' 
                               ELSE ''Sent'' 
                            END AS MessageType, 
                            bodytext AS chatMessage 
                     FROM tbl_conversations_' + CONVERT(VARCHAR(15), @ParentId) + ' (NOLOCK) 
                     WHERE ' + CONVERT(VARCHAR(15), @P_SenderId) + ' IN (senderid, recipientid) 
                     AND createdon BETWEEN DATEADD(DAY, -1, GETDATE()) AND GETDATE() 
                     ORDER BY id 
                     FOR JSON PATH;
                 ';
                 
                 -- Call CLR procedure to execute the dynamic SQL and return JSON result
                 EXEC usp_clr_GetRemoteStringValue @SqlQuery, @retval = @WhatsAppChat_data OUT;

				print concat('Sql query: ',@SqlQuery);

				/* EXEC sp_executesql @SqlQuery, 
				   N'@P_SenderId INT, @WhatsAppChat_data NVARCHAR(MAX) OUTPUT',
                   @P_SenderId = @P_SenderId, 
                   @WhatsAppChat_data = @WhatsAppChat_data OUTPUT;   */
				
				print ' WhatsApp Chat data = '+ coalesce( @WhatsAppChat_data,'') ;

				--- check for if history exist 
				IF EXISTS( SELECT 1 FROM  TBL_AI_GPTCHATHISTORY(nolock)  WHERE  COALESCE( RESPONSE_TEXT,'')<> '' AND  REFID = @P_SenderId  AND PARENTID = @PARENTID)
				BEGIN

						select @Prompt_text = COALESCE( RESPONSE_TEXT,'') FROM TBL_AI_GPTCHATHISTORY(nolock)   WHERE REFID = @P_SenderId  AND PARENTID = @PARENTID
						
						/*set @SqlQuery = ' SET  @WhatsAppChat_data = (select top 1 case when recipientid = '+CONVERT(varchar(15), @P_SenderId) +' then ''Received'' else  ''Sent'' end as MessageType, bodytext from   MySMSConversations.dbo.tbl_conversations_'+ CONVERT(varchar(20),@ParentId ) +'(nolock) where @P_SenderId in (senderid,recipientid)
						  and createdon between dateadd(day,-1, getdate()) and getdate()  order by id desc FOR JSON PATH)  ';*/
						  SET @SqlQuery = '
                            SELECT TOP 1 
                                   CASE 
                                       WHEN recipientid = ' + CONVERT(VARCHAR(15), @P_SenderId) + ' THEN ''Received'' 
                                       ELSE ''Sent'' 
                                   END AS MessageType, 
                                   bodytext 
                            FROM tbl_conversations_' + CONVERT(VARCHAR(20), @ParentId) + ' (NOLOCK) 
                            WHERE ' + CONVERT(VARCHAR(15), @P_SenderId) + ' IN (senderid, recipientid) 
                            AND createdon BETWEEN DATEADD(DAY, -1, GETDATE()) AND GETDATE() 
                            ORDER BY id DESC 
                            FOR JSON PATH;
                        ';
                        
                        -- Call CLR procedure to execute the dynamic SQL and get the result as JSON
                        EXEC usp_clr_GetRemoteStringValue @SqlQuery, @retval = @WhatsAppChat_data OUT;

						/*EXEC sp_executesql @SqlQuery, 
						   N'@P_SenderId INT, @WhatsAppChat_data NVARCHAR(MAX) OUTPUT',
						   @P_SenderId = @P_SenderId, 
						   @WhatsAppChat_data = @WhatsAppChat_data OUTPUT; */

						-- check if chat data exist or not then send prompt.
						if( coalesce( @WhatsAppChat_data,'') <> '') begin
							set @Prompt_text = @Prompt_text +CHAR(13) + CHAR(13) + 'Generate  New response ' + CHAR(13) + CHAR(13)  + @WhatsAppChat_data + CHAR(13) + CHAR(13) + 
											   '
												   Suggest at least 3  reply messages.
												   Show response as json data in format of  SNo , Message  and  MessageType as fixed value "text" .
											   ';
						end
						else begin
							select '' as Result;
							return;
						end

					 
				END
				ELSE BEGIN   --- if history not exist
					set @Prompt_text =  @Prompt_text +CHAR(13) + CHAR(13) + @WhatsAppChat_data + '
										   Show response as json data in format of  SNo , Message  and  MessageType as fixed value "text" ';

					set @Prompt_text = coalesce(@Prompt_text , '') ;
					set @P_Response_text = coalesce( @P_Response_text,'');
					
					exec usp_AI_SaveChatHistory 
						@P_SenderId, 
						@tableName , 
						'Conversation',    
						@Prompt_text,  
						@P_Response_text,     
						@P_USERID; 

				END

				print '@Prompt_text  = '+ coalesce(@Prompt_text , '') ;
				SELECT @PROMPT_TEXT AS Result;

			END

			IF (@P_Option =2) BEGIN  -- update response to table

					update tbl_AI_GPTChatHistory set response_text= @P_Response_text , ModifiedBy =@P_USERID , ModifiedDate = GETDATE()  where RefId = @P_SenderId  and Parentid = @ParentId;
					
					select 'Response Saved successful!' as Result;
			end


			if (@P_option =3) begin

				declare @ChatDirection varchar(10);

				--set @SqlQuery = ' SET  @ChatDirection = (select top 1 direction  from   MySMSConversations.dbo.tbl_conversations_'+ CONVERT(varchar(20),@ParentId ) +'(nolock) where @P_SenderId in (senderid,recipientid) order by id desc) ';
               				SET @SqlQuery = '
                   SELECT TOP 1 direction 
                   FROM tbl_conversations_' + CONVERT(VARCHAR(20), @ParentId) + ' WITH (NOLOCK)
                   WHERE ''' + @P_SenderId + ''' IN (senderid, recipientid)
                   ORDER BY id DESC
               ';
               
               -- Now execute and assign the result to @ChatDirection
               EXEC usp_clr_GetRemoteStringValue @SqlQuery, @retval = @ChatDirection OUT;
               				
				/*EXEC sp_executesql @SqlQuery, 
				N'@P_SenderId INT, @ChatDirection NVARCHAR(MAX) OUTPUT',
				@P_SenderId = @P_SenderId, 
				@ChatDirection = @ChatDirection OUTPUT;*/ 

				if (@ChatDirection ='out') begin
					Select 'Hide' as Message 
					return;
				end
				else if (@ChatDirection ='in') begin
					Select 'Show' as Message 
					return;
				end

			end
		 
	END TRY

	BEGIN CATCH
		PRINT CONCAT('Error occurred: ', ERROR_MESSAGE(), ' | Error Number: ', ERROR_NUMBER(), ' | Line: ', ERROR_LINE());
		
	END CATCH
    
	

END



GO

