   Procedure: [dbo].[usp_AirtelShowErrorCode]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

/*************************************************  
Create by :-Raghwendr  
date :- 05072010  
For:- Gate Airtel Record in airtel Submit Detail Table   
*************************************************/  
CREATE   PROC [dbo].[usp_AirtelShowErrorCode]            
AS             
BEGIN            
 SELECT resultcode as sequencenumber,count(subreference) TotalCount           
 FROM Airtelsubmitdetail          
 WHERE isnull(issent,0)=0 and resultcode!='' and datediff(d,createdDate,getdate())=0      
 GROUP BY resultcode ORDER BY resultcode           
END


