/* ============================================================
   Procedure: [dbo].[usp_all_table_status]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_all_table_status] 
as 
SELECT rows BatchInfo FROM sysindexes WHERE id = OBJECT_ID('BatchInfo') AND indid < 2 
SELECT rows CloneMessageDeliveryStatus FROM sysindexes WHERE id = OBJECT_ID('CloneMessageDeliveryStatus') AND indid < 2 SELECT rows MessageDND FROM sysindexes WHERE id = OBJECT_ID('MessageDND') AND indid < 2 
 
 
 
 
 
SELECT rows MessageFailed FROM sysindexes WHERE id = OBJECT_ID('MessageFailed') AND indid < 2 
SELECT rows MessageMonitor FROM sysindexes WHERE id = OBJECT_ID('MessageMonitor') AND indid < 2 
--SELECT rows MessageQueue FROM sysindexes WHERE id = OBJECT_ID('MessageQueue') AND indid < 2 
