/* ============================================================
   Procedure: [dbo].[Usp_AllDealByUserId]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_AllDealByUserId] (
 	 @LeadId BIGINT = 0
	,@PipelineId BIGINT = 0
	,@PipelineStage BIGINT = 0
	,@FullText varchar(50) = ''
	,@FilterText nvarchar(max)= ''
	,@SearchText nvarchar(max)= ''
		--,@DealOwner BIGINT = 0
	,@CreatedBy BIGINT
	,@OffsetValue int = 0
	,@PagingSize int = 10
	--,@Probability NUMERIC(18, 2)
	--,@LostId BIGINT = 0
	)
AS
BEGIN

if(@FullText != '')
Begin
 set @FullText = ' and + (CreatedName + '' '' + DealOwnerName + '' '' + PipelineName + '' '' + PipeLineStageName) like ''%'+@FullText+'%'''
 set @FilterText = '';
 set @SearchText = '';
End
if(@FilterText != '')
Begin
 set @FilterText = ' and ' + @FilterText            
 set @FullText = '';
 set @SearchText = '';
End
if(@SearchText != '')          
 begin
set @SearchText = ' and tt.DealMsgStatus like ''%' + @SearchText +'%'''
set @FullText = '';
set @FilterText = '';
--set @SearchText = '';
 end          

 Declare @Query1 nvarchar(max)

set @Query1 = 'select count(*) over() as TotalRecords, * from (
select * from (
select lpm.ID , lpm.LeadID , lpm.PipelineID, lpm.PipeLineStage, lpm.Probability, lpm.Amount, lpm.Remarks, lpm.CreatedDate, lpm.CreatedBy, lpm.DealOwner,
(UD1.FName + '' '' + UD1.LName) CreatedName, (UD2.FName + '' '' + UD2.LName) DealOwnerName, pim.Name PipelineName, pis.Name PipeLineStageName, lpm.EstimatedClosureDate, ul.ProfileImgFileName as Image, ul.PersonName LeadPersonName, concat(MobileNo, iif(MobileNo1 <> '''', concat('''', 
'''', MobileNo1), ''''), iif(MobileNo2 <> '''', concat('''', '''', MobileNo2), '''')) as CsvMobileNo,concat(EmailId, iif(EmailId1 <> '''', concat('''', '''', EmailId1), ''''), iif(EmailId2 <> '''', concat('''', '''', EmailId2), '''')) as CsvEmailId, UD1.ParentId, ul.LeadNo,
 (Case   
 When ((cast(lpm.EstimatedClosureDate as Date) > cast(EOMONTH(GETDATE()) as Date)) and (lpm.CreatedBy != ' + cast(@CreatedBy as varchar(20)) +')) then ''Deals closing this month''
 When ((cast(lpm.EstimatedClosureDate as Date) > cast(EOMONTH(GETDATE(),+1) as Date)) and (lpm.CreatedBy != ' + cast(@CreatedBy as varchar(20)) +')) then ''Deals closing next month''
 When ((cast(lpm.EstimatedClosureDate as Date) < cast(GETDATE() as Date)) and (lpm.CreatedBy != ' + cast(@CreatedBy as varchar(20)) +')) then ''Expired deals''
 When ((cast(lpm.EstimatedClosureDate as Date) > cast(DateADD(DAY, 5, GETDATE()) as Date)) and (lpm.CreatedBy != ' + cast(@CreatedBy as varchar(20)) +')) then ''Deals expiring in next 5 days''
 When ((cast(lpm.EstimatedClosureDate as Date) > cast(EOMONTH(GETDATE()) as Date)) and (pis.Name = ''Won'') and (lpm.CreatedBy != ' + cast(@CreatedBy as varchar(20)) +')) then ''Deals won this month''
 When ((cast(lpm.EstimatedClosureDate as Date) > cast(EOMONTH(GETDATE()) as Date)) and (pis.Name = ''Lost'') and (lpm.CreatedBy != ' + cast(@CreatedBy as varchar(20)) +')) then ''Deals won this month''
 When ((cast(lpm.EstimatedClosureDate as Date) > cast(EOMONTH(GETDATE()) as Date)) and (lpm.CreatedBy = ' + cast(@CreatedBy as varchar(20)) +')) then ''My Deals closing this month''
 When ((cast(lpm.EstimatedClosureDate as Date) > cast(EOMONTH(GETDATE(),+1) as Date)) and (lpm.CreatedBy = ' + cast(@CreatedBy as varchar(20)) +')) then ''My Deals closing next month''
 When ((cast(lpm.EstimatedClosureDate as Date) < cast(GETDATE() as Date)) and (lpm.CreatedBy = ' + cast(@CreatedBy as varchar(20)) +')) then ''My Expired deals''
 When ((cast(lpm.EstimatedClosureDate as Date) > cast(DateADD(DAY, 5, GETDATE()) as Date)) and (lpm.CreatedBy = ' + cast(@CreatedBy as varchar(20)) +')) then ''My Deals expiring in next 5 days''
 When ((cast(lpm.EstimatedClosureDate as Date) > cast(EOMONTH(GETDATE()) as Date)) and (pis.Name = ''Won'') and (lpm.CreatedBy = ' + cast(@CreatedBy as varchar(20)) +')) then ''My Deals won this month''
 When ((cast(lpm.EstimatedClosureDate as Date) > cast(EOMONTH(GETDATE()) as Date)) and (pis.Name = ''Lost'') and (lpm.CreatedBy = ' + cast(@CreatedBy as varchar(20)) +')) then ''My Deals lost this month''
 else ''Other Deal'' End) DealMsgStatus 
 from LeadPipelineMapping(nolock) lpm 
 inner join User_Detail UD1 on lpm.CreatedBy = UD1.User_ID 
 inner join User_Detail UD2 on lpm.DealOwner = UD2.User_ID 
 inner join Pipeline_Master pim on lpm.PipelineID = pim.ID
 inner join PipelineStages pis on lpm.PipeLineStage = pis.ID 
 inner join UserLeads(nolock) ul on lpm.LeadID = ul.Id
where lpm.PipelineID > 0 and lpm.CreatedBy = ' + cast(@CreatedBy as varchar(20)) +'
 and ((lpm.LeadID = case when ' + cast(@LeadId as varchar(20)) +' = 0 then lpm.LeadID else ' + cast(@LeadId as varchar(20)) +' end)
	 or (lpm.PipelineID = case when ' + cast(@PipelineId as varchar(20)) +' = 0 then lpm.PipelineID else ' + cast(@PipelineId as varchar(20)) +' end)
	 or (lpm.PipeLineStage = case when ' + cast(@PipelineStage as varchar(20)) +' = 0 then lpm.PipeLineStage else  ' + cast(@PipelineStage as varchar(20)) +' end))
) t 
Where  ''a''=''a'' ' + @FullText + ' ' + @FilterText + '
)tt
Where  ''a''=''a'' ' + @SearchText + '  order by tt.ID desc 
  OFFSET ' + cast(@OffsetValue as varchar(20)) + ' Rows FETCH NEXT ' + cast(@PagingSize as varchar(20)) + ' ROWS ONLY' 

  print @Query1

  exec (@Query1)

--select count(*) over() as TotalRecords, * from (
--select lpm.ID , lpm.LeadID , lpm.PipelineID, lpm.PipeLineStage, lpm.Probability, lpm.Amount, lpm.Remarks, lpm.CreatedDate, lpm.CreatedBy, lpm.DealOwner,
--(UD1.FName + ' ' + UD1.LName) CreatedName, (UD2.FName + ' ' + UD2.LName) DealOwnerName, pim.Name PipelineName, pis.Name PipeLineStageName, lpm.EstimatedClosureDate, ul.ProfileImgFileName as Image, ul.PersonName LeadPersonName, concat(MobileNo, iif(MobileNo1 <> '', concat('', 
--'', MobileNo1), ''), iif(MobileNo2 <> '', concat('', '', MobileNo2), '')) as CsvMobileNo,concat(EmailId, iif(EmailId1 <> '', concat('', '', EmailId1), ''), iif(EmailId2 <> '', concat('', '', EmailId2), '')) as CsvEmailId, UD1.ParentId, ul.LeadNo,
-- '' DealMsgStatus
-- from LeadPipelineMapping(nolock) lpm 
-- inner join User_Detail UD1 on lpm.CreatedBy = UD1.User_ID 
-- inner join User_Detail UD2 on lpm.DealOwner = UD2.User_ID 
-- inner join Pipeline_Master pim on lpm.PipelineID = pim.ID
-- inner join PipelineStages pis on lpm.PipeLineStage = pis.ID 
-- inner join UserLeads(nolock) ul on lpm.LeadID = ul.Id
--where lpm.PipelineID > 0 and lpm.CreatedBy = @CreatedBy
-- and ((lpm.LeadID = case when @LeadId = 0 then lpm.LeadID else @LeadId end)
--	 or (lpm.PipelineID = case when @PipelineId = 0 then lpm.PipelineID else @PipelineId end)
--	 or (lpm.PipeLineStage = case when @PipelineStage = 0 then lpm.PipeLineStage else @PipelineStage end))
--) t 
--Where  1= 1  + ' ' + @FilterText + ' ' + @FilterText + ' ' + @SearchText
--  order by t.ID desc 
--  OFFSET @OffsetValue Rows FETCH NEXT @PagingSize ROWS ONLY

End



GO

/* ============================================================
   Procedure: [dbo].[Usp_AllEn_Lead_ConvoSerchCriteria]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_AllEn_Lead_ConvoSerchCriteria
as
begin
       drop table if exists #tempParents 
	
	    select row_number() over(order by ParentID asc ) as RowNum,ParentID into #tempParents  from User_Detail with(nolock) where User_ID = ParentID and status = 1
		           and Isnull(parentID,0) <> 0     
		           order by  RowNum asc

		--select * from #tempParents order by RowNum asc  
		declare @Count int = ( select count(1) from #tempParents) 
		Declare @Rownum int = 1
		declare @ParentID bigint = 0 

		while(@Rownum <= @Count)
		 begin
		      begin try
			   select top 1 @ParentID = ParentID from #tempParents  where Rownum = @Rownum            

			   if(not exists ( select 1 from tbl_SearchCriteria with(nolock) where ParentID = @ParentID and CriteriaName = 'All Enquiries' ))
			      begin
                      
					   insert into tbl_SearchCriteria 
						 ( CriteriaName, CriteriaType , ApplyTo ,ParentID , IsActive ,CreatedOn , ModifiedOn , CreatedBy 
						   ,ModifiedBy )
						  select 'All Enquiries','Enquiry','applyall',@ParentID,1,getdate(),getdate(), @ParentID,@ParentID	
 
						   declare @criteriaID_En bigint = scope_identity()
	 
						 insert into tbl_SearchCriteriaConditions
							  ( CriteriaID,	FieldName,	FieldType,	Operator,Value)
							  select @criteriaID_En , 'EnquiryID' ,'Enquiry', '>' ,0
				  
				  end


		    if(not exists ( select 1 from tbl_SearchCriteria with(nolock) where ParentID = @ParentID and CriteriaName = 'All Leads' ))
			      begin
                      
					         insert into tbl_SearchCriteria 
					  ( CriteriaName, CriteriaType , ApplyTo ,ParentID , IsActive ,CreatedOn , ModifiedOn , CreatedBy 

				,ModifiedBy )
					   select 'All Leads','Lead','applyall',@ParentID,1,getdate(),getdate(), @ParentID,@ParentID	
 
					 declare @criteriaID_LD bigint = scope_identity()
	 

					 insert into tbl_SearchCriteriaConditions
					  ( CriteriaID,	FieldName,	FieldType,	Operator,Value)
					  select @criteriaID_LD , 'LeadID' ,'Lead', '>' ,0
				  
				  end


               if(not exists ( select 1 from tbl_SearchCriteria with(nolock) where ParentID = @ParentID and CriteriaName = 'All Conversions' ))
			      begin
                      
				      insert into tbl_SearchCriteria 
						  ( CriteriaName, CriteriaType , ApplyTo ,ParentID , IsActive ,CreatedOn , ModifiedOn , CreatedBy 

				  	       ,ModifiedBy )

						   select 'All Conversions','Conversion','applyall',@ParentID,1,getdate(),getdate(), @ParentID,@ParentID	
 
						 declare @criteriaID_conv bigint = scope_identity()
	 

						 insert into tbl_SearchCriteriaConditions
						  ( CriteriaID,	FieldName,	FieldType,	Operator,Value)
						  select @criteriaID_conv , 'LeadID' ,'Lead', '>' ,0
				  
				  end
				  

			  end try
			  begin catch
               exec Usp_insertErrorInfo 
 			  end catch

			 set @Rownum = @Rownum + 1
		 end
		 		 
	   drop table if exists #tempParents 
end


GO

/* ============================================================
   Procedure: [dbo].[usp_allowawsmail]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_allowawsmail]         
(@userid bigint,@frommailid nvarchar(200),@isactive int,@dname nvarchar(100)=null)        
as        
begin      
select @dname=coalesce(@dname,(select value from dbo.fn_split(@frommailid,'@') where position=1))
declare @parentid bigint=(select parentid from User_Detail(nolock) where user_id=@userid)    
if exists(select 1 from awsmailroute where mailuser=@userid and @frommailid=frommailid)        
begin        
update awsmailroute set isactive=@isactive,lastmodified=getdate(),aws_d_name=@dname where mailuser=@userid and @frommailid=frommailid       
print 'record updated'        
end        
else        
begin        
insert into awsmailroute(mailuser,isactive,createdon,lastmodified,frommailid,parentid,aws_d_name)        
select @userid,@isactive,getdate(),getdate(),@frommailid,@parentid,@dname        
print 'record created'        
end      
exec [usp_addsendermail]  @userid, @frommailid,@isactive,@dname      
end    


