/* ============================================================
   Procedure: [dbo].[USP_allowDNDOrNot]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[USP_allowDNDOrNot] --'','','',''                                   
@Mobile VARCHAR(50),                              
@Message VARCHAR(50),                              
@SENDerID VARCHAR(50),                              
@U_ID INT -- from VARCHAR(50)                                     
AS                                      
BEGIN TRANSACTION                                     
SET NOCOUNT ON                                   
DECLARE @sqlInsertmsgqueue NVARCHAR(MAX)                                
DECLARE @sqlInsertmsgsource NVARCHAR(MAX)                                                        
DECLARE @sqlDelete NVARCHAR(MAX)                               
DECLARE @Sqlselect NVARCHAR(MAX)                               
DECLARE @whereClause VARCHAR(5000)                          
DECLARE @sqlInsertmsgqueueAirtel nvarchar(MAX)                             
SET  @whereClause='WHERE '                              
IF(@Mobile='')                              
BEGIN                              
SET @whereClause=@whereClause + ' 1=1 and '                              
END                              
ELSE                              
BEGIN                              
SET @whereClause=@whereClause+' Mobile='''+@Mobile+''' and '                              
END                              
IF(@Message='')                                                        
BEGIN                                                         
SET @whereClause=@whereClause +' 1=1 and '                                                        
END                                                        
ELSE                                                        
BEGIN                                                        
SET @whereClause=@whereClause+' Message like ''%'+@Message+'%'' and '                                                        
END                                                          
IF(@SENDerID='')                                                        
BEGIN                                                         
SET @whereClause=@whereClause +' 1=1 and '                                                        
END                                                        
ELSE                                                        
BEGIN                                                        
SET @whereClause=@whereClause+' SENDerID='''+@SENDerID+''' and '                                                        
END                                                         
IF(@U_ID='')                                                        
BEGIN                                                         
SET @whereClause=@whereClause +' 1=1  '                                                        
END                                                        
ELSE                                                        
BEGIN                  
SET @whereClause=@whereClause+ '   U_ID like ''%'+@U_ID+'%'' '        
END                               
 SET @Sqlselect='SELECT MessageID FROM MessageMonitor '+@whereClause      
                             
SET @sqlInsertmsgqueueAirtel= 'insert into MessageQueueAirtelPri(MessageID,Mobile,[Message],SENDerID,SmppID,Priority,U_ID,IsUniCode,                               
IsDND,Operator,Isallowdnd,BatchID) SELECT MessageID,Mobile,[Message],SENDerID,2,Priority,U_ID,IsUniCode,                         
IsDND,Operator,Isallowdnd,BatchID FROM MessageMonitor WHERE  Priority=1 and MessageID in '   --Operator=''AD'' and                     
SET @sqlInsertmsgqueueAirtel=@sqlInsertmsgqueueAirtel + '(' + @Sqlselect + ')'                          
                 
                      
SET @sqlInsertmsgsource= 'insert into Messagesource(MessageID,Mobile,[Message],SENDerID,SmppID,Priority,U_ID,IsUniCode,                                
IsDND,Operator,Isallowdnd,MessageBatchID) SELECT MessageID,Mobile,[Message],SENDerID,SmppID,Priority,U_ID,IsUniCode,                                
IsDND,Operator,Isallowdnd,BatchID FROM MessageMonitor WHERE Priority=0 and  MessageID in '                                      
SET @sqlInsertmsgsource=@sqlInsertmsgsource + '(' + @Sqlselect + ')'                                 
--END                                
                                
SET @sqlDelete='DELETE FROM MessageMonitor WHERE MessageID in '                                  
SET @sqlDelete=@sqlDelete + '(' + @Sqlselect + ')'                         
EXEC (@sqlInsertmsgqueueAirtel)                                 
--EXEC(@sqlInsertmsgqueue)        
EXEC(@sqlInsertmsgsource)                                  
EXEC(@sqlDelete)                                  
IF @@error<>0                           
BEGIN                                      
  -- Rollback the TRANSACTION                                      
    ROLLBACK                                      
    -- Raise an error and return                                      
    RAISERROR ('PleASe try again.', 16, 1)                                      
    RETURN                                      
END                                      
IF @@error=0                                      
BEGIN                                      
COMMIT TRANSACTION                                
END 


GO

