/* ============================================================
   Procedure: [dbo].[usp_allowkarixmail_all]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_allowkarixmail_all]           
(@userid bigint,@frommailid nvarchar(200),@isactive int,@dname nvarchar(100)=null,@all int=null)          
as          
begin  

select @dname=coalesce(@dname,(select value from dbo.fn_split(@frommailid,'@') where position=1))  
declare @parentid bigint=(select parentid from User_Detail(nolock) where user_id=@userid) ,@count int
drop table if exists #users
create table #users(user_id bigint)
if isnull(@all,0)=1
begin
insert into #users(user_id)
select user_id  from User_Detail(nolock) where parentid=@parentid and status=1
end
else
begin
insert into #users(user_id)
select @userid 
end
select @userid=0
select @count=count(1) from #users
while @count>0
begin
select @userid=min(user_id) from #users where user_id>@userid

if exists(select 1 from karixmailroute where mailuser=@userid and @frommailid=frommailid)          
begin          
update karixmailroute set isactive=@isactive,lastmodified=getdate(),k_d_name=@dname where mailuser=@userid and @frommailid=frommailid         
print 'record updated'          
end          
else          
begin          
insert into karixmailroute(mailuser,isactive,createdon,lastmodified,frommailid,parentid,k_d_name)          
select @userid,@isactive,getdate(),getdate(),@frommailid,@parentid,@dname          
print 'record created'          
end        
exec [usp_addsendermail]  @userid, @frommailid,@isactive,@dname        

select @count=@count-1
end      

end      


