SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_allowkarixmail_userlogin]         
(@userlogin nvarchar(200),@frommailid nvarchar(200),@isactive int,@dname nvarchar(100)=null)        
as        
begin 
declare @userid bigint
select @userid=(select user_id from user_detail(nolock) where user_login=@userlogin)
select @dname=coalesce(@dname,(select value from dbo.fn_split(@frommailid,'@') where position=1))
declare @parentid bigint=(select parentid from User_Detail(nolock) where user_id=@userid)    
if exists(select 1 from karixmailroute where mailuser=@userid and @frommailid=frommailid)        
begin        
update karixmailroute set isactive=@isactive,lastmodified=getdate(),k_d_name=@dname where mailuser=@userid and @frommailid=frommailid       
print 'record updated'        
end        
else        
begin        
insert into karixmailroute(mailuser,isactive,createdon,lastmodified,frommailid,parentid,k_d_name)        
select @userid,@isactive,getdate(),getdate(),@frommailid,@parentid,@dname        
print 'record created'        
end      
exec [usp_addsendermail]  @userid, @frommailid,@isactive,@dname      
end    
    
    


GO

/* ============================================================
   Procedure: [dbo].[USP_ALLOWMessage]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC USP_ALLOWMessage      
@tableName varchar(200),      
@senderid varchar(100)      
as      
BEGIN      
if(@tableName='MessageMonitor')      
BEGIN      
insert into MessageQueue(MessageID,Mobile,[Message],SENDerID,SmppID,Priority,U_ID,IsUniCode,                                       
IsDND,Operator,Isallowdnd,BatchID) SELECT MessageID,Mobile,[Message],SENDerID,2,Priority,U_ID,IsUniCode,                                 
IsDND,Operator,Isallowdnd,BatchID FROM MessageMonitor WHERE  Priority=1  and senderid=@senderid      
      
insert into MessageSource(MessageID,Mobile,[Message],SENDerID,SmppID,Priority,U_ID,IsUniCode,                                         
IsDND,Operator,Isallowdnd,MessageBatchID,messageInsertDate) SELECT MessageID,Mobile,[Message],SENDerID,2,Priority,U_ID,IsUniCode,                                   
IsDND,Operator,3,BatchID,messageInsertDate FROM MessageMonitor  WHERE  Priority=0 and isnull(ISAllowDND,0)=1 and senderid=@senderid      
      
insert into MessageSource(MessageID,Mobile,[Message],SENDerID,SmppID,Priority,U_ID,IsUniCode,                                         
IsDND,Operator,Isallowdnd,MessageBatchID,messageInsertDate) SELECT MessageID,Mobile,[Message],SENDerID,2,Priority,U_ID,IsUniCode,                                   
IsDND,Operator,2,BatchID,messageInsertDate FROM MessageMonitor  WHERE  Priority=0 and isnull(ISDND,0)=0 and isnull(ISAllowDND,0)=0  and senderid=@senderid      
      
delete From MessageMonitor where senderid=@senderid      
END      
      
IF @tableName='MessageSpam'      
BEGIN      
insert into MessageQueue(MessageID,Mobile,[Message],SENDerID,SmppID,Priority,U_ID,IsUniCode,                                       
IsDND,Operator,Isallowdnd,BatchID) SELECT MessageID,Mobile,[Message],SENDerID,2,Priority,U_ID,IsUniCode,                                 
IsDND,Operator,Isallowdnd,BatchID FROM MessageSpam WHERE  Priority=1  and senderid=@senderid      
      
insert into MessageSource(MessageID,Mobile,[Message],SENDerID,SmppID,Priority,U_ID,IsUniCode,                                         
IsDND,Operator,Isallowdnd,MessageBatchID) SELECT MessageID,Mobile,[Message],SENDerID,2,Priority,U_ID,IsUniCode,                                   
IsDND,Operator,3,BatchID FROM MessageSpam  WHERE  Priority=0 and isnull(ISAllowDND,0)=1 and senderid=@senderid      
      
insert into MessageSource(MessageID,Mobile,[Message],SENDerID,SmppID,Priority,U_ID,IsUniCode,                                         
IsDND,Operator,Isallowdnd,MessageBatchID) SELECT MessageID,Mobile,[Message],SENDerID,2,Priority,U_ID,IsUniCode,                                   
IsDND,Operator,2,BatchID FROM MessageSpam  WHERE  Priority=0 and isnull(ISDND,0)=0 and isnull(ISAllowDND,0)=0  and senderid=@senderid      
      
delete From MessageSpam where senderid=@senderid      
      
END      
END 



GO

