--End                     
--                  
                                
--count no of row in temptable                                                                          
  select count(MessageID) from @temptable                                     
--for custom pagging                                                             
  select ID,MessageID,Mobile,Message,SenderID,SmppID,Priority,                                    
DisplayPriority=(case Priority when 0 then 'Normal' when 1 then 'Priority' when 2 then 'Direct' end),                                    
U_ID,IsUniCode,IsDND,Operator,Isallowdnd,MessageBatchID,MessageInsertDate,tableName from @temptable  order by SenderID                                                                        
