/* ============================================================
   Procedure: [dbo].[USP_AllUserRole]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE USP_AllUserRole
(
@userid bigint
)    
as    
begin    
Declare @ParentId bigint = 0

select @ParentId = ParentId from User_detail where User_Id = @UserId
