/* ============================================================
   Procedure: [dbo].[usp_ap_GenerateTriggerActionEvents]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE usp_ap_GenerateTriggerActionEvents(
	@actionName nvarchar(max),
	@entityName nvarchar(25),
	@entityId bigint,
	@remarks nvarchar(max),
	@createdBy bigint
)
as
begin

	begin try
	
		declare 
			@actionId bigint = 0,
			@visitorLastResponeId bigint,
			@detailsJson nvarchar(max) = '{}',
			@actionDateTime nvarchar(25) = format(getutcdate(), 'dd-MMM-yyyy HH:mm:ss')

		select @actionId = id from tbl_ai_ActionMaster with (nolock) where [Action] = @actionName
		select @visitorLastResponeId = id from tbl_ai_VisitorsLastResponse with (nolock) where entityName = @entityName and entityId = @entityId



		set @detailsJson = json_modify(@detailsJson, '$.ActionId', @actionId)
		set @detailsJson = json_modify(@detailsJson, '$.ActionType', @actionName)
		set @detailsJson = json_modify(@detailsJson, '$.ActionDate', @actionDateTime)
		set @detailsJson = json_modify(@detailsJson, '$.Remarks', @remarks)
		set @detailsJson = json_modify(@detailsJson, '$.VisitorLastResponseId', @visitorLastResponeId)

		insert into tbl_ai_VisitorActionHistory ( EntityId, EntityName, DetailsJson, ActionId, VisitorsLastResponseId, CreatedOn, CreatedBy )
			values ( @entityId, @entityName, @detailsJson, @actionId, @visitorLastResponeId, @actionDateTime, @createdBy )
	end try
	begin catch
		exec usp_InsertErrorInfo
	end catch
end



GO

/* ============================================================
   Procedure: [dbo].[usp_app_GetBatchNotification_UserId]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_app_GetBatchNotification_UserId](   
 @UserId bigint,  
 @FilterText nvarchar(255) = '',      
 @OffsetValue int  = 0,      
 @PageSize int  = 10                  
)  
as   
begin   
  
SELECT ROW_NUMBER() Over(Partition by tabn.BatchNotification_Id Order by tabn.BatchNotification_Id desc) as RowNumber,     
 tabn.[BatchNotification_Id], tabd.[BatchNotificationDetail_Id], tabs.[BatchNotificationStatus_Id], [Title], [MessageText], [ImageUrl], [ClickActionUrl], [BatchSentTime], [TotalRecords],   
tabn.IsProcessed, Retries, LastStatus, tabn.[CreatedOn], tabn.CreatedBy, [IsAuto]  
 --,[ScheduledDate], [TotalProcessed], [BatchCompleteTime], [LastBatchProcessed], tabn.[IsProcessed], [CutOffTime], [CreatedOn], CreatedBy, [IsAuto]  
 from tbl_APP_BatchNotification(nolock) tabn  
 inner join tbl_APP_BatchNotificationDetail tabd on tabn.BatchNotification_Id = tabd.BatchNotification_Id   
 inner join tbl_APP_BatchNotificationStatus tabs on tabd.BatchNotificationDetail_Id = tabs.BatchNotificationDetail_Id   
 where tabd.User_ID = @UserId and [tabn].Title like '%' + @FilterText + '%'   
 Order by tabn.BatchNotification_Id desc   
  
 OFFSET @OffsetValue Rows FETCH NEXT @PageSize ROWS ONLY   
  
End  


GO

