/* ============================================================
   Procedure: [dbo].[usp_APP_GetBatchNotificationDetail_New]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[usp_APP_GetBatchNotificationDetail_New] --3598037--54717              
(                
    @BatchNotification_Id bigint                
)                
AS                
BEGIN                
   Select BND.BatchNotificationDetail_Id, BND.BatchNotification_Id, BND.User_ID, BND.LastAttemptedTime, BND.Retries, BND.LastStatus,    
 BND.IsProcessed, BND.Reason, BND.SubReason, BND.RawReason,ISNULL( BND.DeviceID,isnull(UL.DeviceID,'')) as DeviceID                
    From   [tbl_APP_BatchNotificationDetail] BND(nolock) left outer join User_Detail(nolock) UL                
    On   BND.User_ID = UL.User_ID                
    Where --BND.BatchNotificationDetail_Id = 47280         
       
   ISNULL(UL.DeviceID,'') <> ''  and       
      
 BND.BatchNotification_Id=@BatchNotification_Id and BND.IsProcessed=0               
           
    --and datediff(s,lastattemptedtime,getdate())>= cast( (select top 1 isnull(MinValue,0) from dbo.Minimum_Func(((2^Retries)+rand(1)), 32))  as integer )        
      
 and      
  (isnull(lastattemptedtime,'')='' or datediff(s,lastattemptedtime,getdate())>=cast( (select top 1 isnull(MinValue,0) from dbo.Minimum_Func(((2^Retries)+rand(1)), 32))  as integer))               
      
           
    and        
    (        
    (isnull(BND.RawReason,'') = '')        
    or        
    (        
       Bnd.RawReason not like '%UNREGISTERED%'        
    and        
       Bnd.RawReason not like '%Not%Registered%'         
    and         
       Bnd.RawReason not like '%Missing%Registration%'         
       and         
      Bnd.RawReason not like '%SENDER_ID_MISMATCH%'         
        
    )        
         
   )       
         
                
END    


