/* ============================================================
   Procedure: [dbo].[usp_app_SaveBatchNotification]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_app_SaveBatchNotification]  
(     
 @UserId bigint,     
 @Title nvarchar(255) = '',     
 @Content nvarchar(255) = '',     
 @ImageUrl nvarchar(255) = '',     
 @ClickActionUrl nvarchar(max) = '',     
 @TotalRecords int = 0,     
 @csvUserId nvarchar(max)     
)    
as     
begin     
Declare @ParentId bigint     
Declare @BatchNotification_Id bigint     
    
select @ParentId = ParentId from User_Detail (nolock) where User_ID = @UserId     
  if(ISNULL(@ImageUrl,'')='')
  begin
	Set @ImageUrl='https://www.kit19.com/Kit19New/img/logo.jpg'
  end

 INSERT INTO [dbo].[tbl_APP_BatchNotification]     
 ([Title],[MessageText],[ImageUrl],[ClickActionUrl],[BatchSentTime],[TotalRecords],[ScheduledDate],[TotalProcessed],    
 [BatchCompleteTime],[LastBatchProcessed],[IsProcessed],[CutOffTime],[CreatedOn],[CreatedBy], IsAuto)                  
 VALUES                  
 (@Title, @Content, @ImageUrl, @ClickActionUrl, null, @TotalRecords, GETDATE(), 0,     
 null, null, 0, dateadd(hh,6,GETDATE()), GETDATE(), @ParentId, @ParentId)                  
    
 Select @BatchNotification_Id = SCOPE_IDENTITY()                  
                  
 INSERT INTO [dbo].[tbl_APP_BatchNotificationDetail]    
  ([BatchNotification_Id],[User_ID],[LastAttemptedTime],[Retries],[LastStatus],[IsProcessed])                  
  Select @BatchNotification_Id, [value], null, 0, '', 0                  
  From  dbo.fn_Split(@csvUserId,',')     
    
End



