 @UserId bigint,   
 @BatchNotification_Id nvarchar(4000),  
 @StatusType nvarchar(50)  
)
as   
begin   
Declare @ParentId bigint  
  Declare @check int = 0 
 --If exists(select 1 from tbl_APP_BatchNotificationStatus tbs inner join tbl_APP_BatchNotificationDetail tbd on tbd.BatchNotificationDetail_Id = tbs.BatchNotificationDetail_Id where tbd.User_ID = @UserId and tbs.IsProcessed = 1 and cast(tbs.BatchNotificationDetail_Id as nvarchar(10)) in (select value from STRING_SPLIT(@BatchNotification_Id, ',')))      
 --   Begin      

  Update tbl_APP_BatchNotificationStatus Set IsDelivered = case when @StatusType = 'Recvd' then 1 else IsDelivered end,      
   DeliveredOn = case when @StatusType = 'Recvd' then GETDATE() else DeliveredOn end,      
   IsRead = case when @StatusType = 'Read' then 1 else IsRead end,      
