/* ============================================================
   Procedure: [dbo].[Usp_app_updateReason]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_app_updateReason
(        
  @BatchNotificationDetail_ID bigint,        
  @Reason nvarchar(500),        
  @SubReason nvarchar(500),      
  @RawReason nvarchar(max)      
          
)
as        
Begin     
  
 If(@Reason = 'NotRegistered')  
 Begin  
  declare @DeviceId nvarchar(1000)='',@UserId bigint=0,@AppVersion varchar(100),@OSVersion varchar(100),@OSName varchar(100),@ModelName varchar(100), @BatchNotification_Id bigint  
  
  Select @UserId=USER_ID, @BatchNotification_Id=BatchNotification_Id  
  From [tbl_APP_BatchNotificationDetail]   
  where  BatchNotificationDetail_Id =  @BatchNotificationDetail_ID  
   
  select @DeviceId=DeviceID,@AppVersion=AppVersion,@OSVersion=OSVersion,@OSName=OSName,@ModelName=ModelName  
  from User_Detail   
  Where User_Id=@UserId  
  
  exec usp_insertloginhistory @UserId, null, null, @DeviceId, 'Logout', null, @AppVersion,@OSVersion,@OSName,@ModelName  
  
  Update User_Detail   
  Set  DeviceID='', OTP='', AppVersion='', OSVersion='', OSName='', ModelName=''  
    , OnField=0, Presence = case when isnull(MACAddress,'') != '' then Presence else 0 end  
  Where User_Id=@UserId  
  
  update [tbl_APP_BatchNotificationDetail]   
  set  [Reason] = @Reason ,[SubReason] = @SubReason , [RawReason] = @RawReason, LastAttemptedTime = getdate(), Retries = isnull(Retries,0)+1  
    ,IsProcessed=1  
  where BatchNotificationDetail_Id =  @BatchNotificationDetail_ID  
  
  If not exists(Select * from [tbl_APP_BatchNotificationDetail] Where BatchNotification_Id=@BatchNotification_Id and IsProcessed=0)  
  Begin  
   update [tbl_APP_BatchNotification] set IsProcessed=1 Where BatchNotification_Id=@BatchNotification_Id  
  End  
 End  
 Else  
 Begin  
  update [tbl_APP_BatchNotificationDetail]   
  set  [Reason] = @Reason ,[SubReason] = @SubReason , [RawReason] = @RawReason, LastAttemptedTime = getdate(), Retries = isnull(Retries,0)+1  
  where BatchNotificationDetail_Id =  @BatchNotificationDetail_ID  
 End  
  
End



GO

/* ============================================================
   Procedure: [dbo].[usp_applycoupon]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--sp_helptext usp_applycoupon1    
    
CREATE   PROC usp_applycoupon --'dis1000',30,26705        
@couponcode NVARCHAR(50),          
@planid INT,          
@user_id BIGINT          
AS          
BEGIN      
  
  --Declare @ParentID bigint = 0  
  --Select  @ParentID = ParentID from User_detail where User_ID = @user_id  
  
  
 DECLARE @quantity INT = (      
             SELECT quantity      
             FROM   planmaster      
             WHERE  @planid = id      
         )      
       
 DECLARE @UNewUser             INT,      
         @UUserName            NVARCHAR(100),      
         @UMobile              BIGINT,      
         @UEmailID             NVARCHAR(200),      
         @UUserType            NVARCHAR(1),      
         @UUserFilter          NVARCHAR(20),      
         @UIsActive            NVARCHAR(1),      
         @ULastLoginBefore     BIGINT,      
         @ULastPurchase        DECIMAL(18, 4),      
         @ULastLogin           BIGINT      
       
 SELECT @uusername = user_login,      
        @umobile         = mobile,      
        @uemailid        = email,      
        @uusertype       = usertype,      
        @uuserfilter     = userfilter,      
        @uisactive       = STATUS      
 FROM   user_detail      
 WHERE  USER_ID          = @user_id      
       
 IF EXISTS(      
        SELECT 1      
        FROM   m_coupon      
        WHERE  @couponcode     = couponcode      
               AND STATUS      = 1      
               AND ISNULL(NULLIF(ROUTE, ''), @uuserfilter) = @uuserfilter      
               AND GETDATE() BETWEEN       
                   ValidFrom AND ValidTo      
               AND @quantity BETWEEN (MinVolume) AND (MaxVolume)      
    )      
 BEGIN      
     SELECT VALUE INTO #temp      
     FROM   dbo.fn_split(      
                (      
                    SELECT savedsearch      
                    FROM   m_coupon      
                    WHERE  CouponCode = @couponcode      
                ),      
                '#'      
            )      
           
     DECLARE @s BIGINT          
     SELECT @s = MIN(VALUE)      
     FROM   #temp      
           
     DECLARE @NewUser             INT,      
             @UserName            NVARCHAR(100),      
             @Mobile              BIGINT,      
             @EmailID             NVARCHAR(200),      
             @UserType            NVARCHAR(1),      
             @UserFilter          NVARCHAR(20),      
             @IsActive            NVARCHAR(1),      
             @LastLoginBefore     BIGINT,      
             @LastPurchase        DECIMAL(18, 4),      
             @LastLogin           BIGINT      
           
     SELECT @uLastLoginBefore = ISNULL(      
                DATEDIFF(      
                    d,      
                    CONVERT(NVARCHAR, MAX(datecreated), 112),      
                    CONVERT(NVARCHAR, GETDATE(), 112)      
                ),      
                0      
            )      
     FROM   Credit_Details      
     WHERE  USER_ID = @user_id      
           
     SELECT @ulastlogin = ISNULL(      
                DATEDIFF(      
                    d,      
                    CONVERT(NVARCHAR, MAX(createddate), 112),      
                    CONVERT(NVARCHAR, GETDATE(), 112)      
                ),      
                0      
            )      
     FROM   AddCreditDetails      
     WHERE  USERID         = @user_id      
            AND Reason     = 'Purchase'      
           
     SELECT @ulastpurchase = ISNULL(      
                (      
                    SELECT TOP 1 Pricepersms      
                    FROM   AddCreditDetails      
                    WHERE  USERID         = 26705      
                           AND Reason     = 'Purchase'      
                    ORDER BY      
                           id DESC      
                ),      
                0      
            )      
           
     WHILE @s IS NOT NULL      
     BEGIN      
         SELECT @NewUser = newuser,      
                @username            = ISNULL(NULLIF(UserName, ''), @uusername),      
                @mobile              = ISNULL(NULLIF(mobile, 0), @uMobile),      
                @emailid             = ISNULL(NULLIF(EmailID, ''), @uemailid),      
                @usertype            = ISNULL(UserType, @uusertype),      
                @userfilter          = ISNULL(NULLIF(UserFilter, ''), @uuserfilter),      
                @isactive            = ISNULL(IsActive, @uisactive),      
                @LastLoginBefore     = ISNULL(NULLIF(lastloginbefore, 0), @ulastloginbefore),      
                @lastpurchase        = ISNULL(NULLIF(LastPurchase, 0), @ulastpurchase),      
                @lastlogin           = ISNULL(NULLIF(LastLogin, 0), @ulastlogin)      
         FROM   SavedSearch      
         WHERE  ID                   = @s      
         PRINT @s      
         IF @NewUser = 1      
            AND NOT EXISTS(      
                    SELECT 1      
                    FROM   credit_details      
                    WHERE  USER_ID = @user_id      
                )      
         BEGIN      
             GOTO result      
         END      
         ELSE      
         BEGIN      
             --select @usertype,@UserName,@Mobile,@EmailID,@UserFilter,@IsActive,@LastLoginBefore,@LastLogin,@LastPurchase        
             IF EXISTS(      
                    SELECT 1      
                    FROM   user_detail      
                    WHERE  USER_ID = @user_id      
                           AND @username = @uusername      
                           AND @mobile = @uMobile      
                           AND @emailid = @uEmailID      
                           AND @usertype = @uUserType      
                           AND @userfilter = @uUserFilter      
                           AND @isactive = @uIsActive      
                           AND @LastLoginBefore <= @ulastloginbefore      
                           AND @lastpurchase <= @uLastPurchase      
                           AND @lastlogin <= @uLastLogin      
                )      
             BEGIN      
                 GOTO result      
             END      
             ELSE      
             BEGIN      
                 DELETE       
                 FROM   #temp      
                 WHERE  VALUE = @s      
                       
                 SELECT @s = MIN(VALUE)      
                 FROM   #temp      
             END      
         END      
     END       
     GOTO negativeresult      
 END      
 ELSE      
 BEGIN      
     GOTO negativeresult      
 END       
 result:      
 SELECT 'Coupon applied successfully' Result,      
        discount      
 FROM   M_Coupon      
 WHERE  @Couponcode = Couponcode      
       
 GOTO endofsp       
 Negativeresult:      
 SELECT 'Coupon invalid' Result,      
        0 discount       
        endofsp:      
END


GO

/* ============================================================
   Procedure: [dbo].[usp_applycoupon1]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--sp_helptext usp_applycoupon1

CREATE   PROC [dbo].[usp_applycoupon1] --'dis1000',30,26705  
@couponcode NVARCHAR(50),    
@planid INT,    
@user_id BIGINT    
AS    
BEGIN  
 DECLARE @quantity        INT = (  
             SELECT quantity  
             FROM   planmaster  
             WHERE  @planid = id  
         )  
   
 DECLARE @UUserFilter     NVARCHAR(20) = (  
             SELECT userfilter  
             FROM   user_detail  
             WHERE  USER_ID = @user_id  
         )  
   
 IF EXISTS(  
        SELECT 1  
        FROM   m_coupon  
        WHERE  @couponcode     = couponcode  
               AND STATUS      = 1  
               AND ISNULL(NULLIF(ROUTE, ''), @uuserfilter) = @uuserfilter  
               AND GETDATE() BETWEEN   
                   ValidFrom AND ValidTo  
               AND @quantity BETWEEN (MinVolume) AND (MaxVolume)  
    )  
 BEGIN  
     SELECT VALUE INTO #temp  
     FROM   dbo.fn_split(  
                (  
                    SELECT savedsearch  
                    FROM   m_coupon  
                    WHERE  CouponCode = @couponcode  
                ),  
                '#'  
            )  
       
     DECLARE @s BIGINT    
     SELECT @s = MIN(VALUE)  
     FROM   #temp  
       
     WHILE @s IS NOT NULL  
     BEGIN  
         --select @s  
         --select dbo.fn_UserMatchesSearch(@user_id,@s)   
         IF (  
                SELECT dbo.fn_UserMatchesSearch(@user_id, @s)  
            ) = 1  
         BEGIN  
             SELECT 'Coupon applied successfully' Result,  
                    discount  
             FROM   M_Coupon  
             WHERE  @Couponcode = Couponcode  
               
             GOTO endofsp  
         END  
         ELSE  
         BEGIN  
             DELETE   
             FROM   #temp  
             WHERE  VALUE = @s  
               
             SELECT @s = MIN(VALUE)  
             FROM   #temp  
         END  
     END   
     SELECT 'Coupon invalid' Result,  
            0 discount  
       
     GOTO endofsp  
 END  
 ELSE  
 BEGIN  
     SELECT @couponcode,  
            @UUserFilter,  
            @quantity,  
            STATUS,  
            ROUTE,  
            ValidFrom,  
            ValidTo,  
            (MinVolume),  
            (MaxVolume)  
     FROM   M_Coupon  
     WHERE  CouponCode = @couponcode  
       
     SELECT 'Coupon invalid' Result,  
            0 discount  
       
     GOTO endofsp  
 END   
 endofsp:  
END


GO

/* ============================================================
   Procedure: [dbo].[usp_ApplyCouponUserProducts]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.usp_ApplyCouponUserProducts    
 @CouponCode VARCHAR(50),    
 @ParentID BIGINT ,    
 @MobileNo VARCHAR(50) ,    
 @EmailID VARCHAR(50),    
 @BIllAmount VARCHAR(500)    
AS    
BEGIN    
  
SELECT *  
INTO   #tempcoupon  
FROM   usercouponsettings AS ucs  
WHERE  ucs.parentid = @ParentID  
       AND ucs.couponcode = @CouponCode  
       AND Datediff(day, Getdate(), ucs.expirydate) >= 0  
  
DECLARE @CouponDiscount VARCHAR(50)='Valid'  
DECLARE @MobileNo1 VARCHAR(50),  
        @EmailID1  VARCHAR(50)  
  
IF EXISTS (SELECT 'x'  
           FROM   #tempcoupon tt  
           WHERE  ismobile = 1)  
  BEGIN  
      SET @MobileNo1=@MobileNo  
  END  
ELSE IF EXISTS (SELECT 'x'  
           FROM   #tempcoupon tt  
           WHERE  isemail = 1)  
  BEGIN  
      SET @EmailID1=@EmailID  
  END  
ELSE  
  BEGIN  
      SET @EmailID1=@EmailID  
      SET @MobileNo1=@MobileNo  
  END  
  
IF EXISTS (SELECT 'x'  
           FROM   #tempcoupon tt  
           WHERE  billapplicability = 1)  
  BEGIN  
      IF EXISTS (SELECT 'x'  
                 FROM   #tempcoupon tt  
                 WHERE  billamount >= CAST( @BIllAmount as bigint)  
                        AND minbillamount <= CAST( @BIllAmount as bigint))  
        BEGIN  
            SET @CouponDiscount = 'Valid'  
        END  
      ELSE  
        BEGIN  
            SET @CouponDiscount = 'Invalid'  
        END  
  END  
  
IF EXISTS (SELECT 'x'  
           FROM   #tempcoupon tt  
           WHERE  SearchApplicability = 1)  
  BEGIN  
    
      SELECT value AS InCludeD  
      INTO   #tempInCludeDetailsSearch  
      FROM   #tempcoupon tt  
             OUTER apply Fn_split(InCludeDetails, '#')  
  
  SELECT value AS ExcludeD  
      INTO   #tempExcludeDetailsSearch  
      FROM   #tempcoupon tt  
             OUTER apply Fn_split(ExcludeDetails, '#')  
  
    
    
    SELECT fs.[value] AS SearchID INTO #TempSearchs    
     FROM   #TempCoupon tt    
            OUTER APPLY dbo.fn_Split(tt.ListID, '#') AS fs    
         
         SELECT fs.[value] AS SearchID INTO #TempSearchsExclude   
     FROM   #TempCoupon tt    
            OUTER APPLY dbo.fn_Split(tt.ListIDExclude, '#') AS fs    
        DECLARE @Count1 BIGINT = (    
                     SELECT COUNT(*)    
                     FROM   #TempSearchs    
                 )    
            DECLARE @Count2 BIGINT = (    
                     SELECT COUNT(*)    
                     FROM   #TempSearchsExclude    
                 )    
            DECLARE @Count BIGINT  
       if @Count1>@Count2  
       begin  
       set @Count=@Count1  
       end  
       else   
       begin  
       set @Count=@Count2  
       end  
    
         CREATE TABLE #temptablesearchapp    
         (    
          Campaignid             BIGINT,    
          Searchid               BIGINT,    
          Parentid               BIGINT,    
          Personname             NVARCHAR(200),    
          Companyname            NVARCHAR(200),    
          Mobileno               NVARCHAR(200),    
          Mobileno1              NVARCHAR(200),    
          Mobileno2              NVARCHAR(200),    
          Emailid                NVARCHAR(200),    
          Emailid1               NVARCHAR(200),    
          Emailid2               NVARCHAR(200),    
          City                   NVARCHAR(200),    
          STATE                  NVARCHAR(200),    
          Country                NVARCHAR(200),    
          Countrycode            NVARCHAR(200),    
          Pincode                NVARCHAR(200),    
          Residentialaddress     NVARCHAR(200),    
          Officeaddress          NVARCHAR(200),    
          Sourcename             NVARCHAR(200),    
          Mediumname             NVARCHAR(200),    
          Campaignname           NVARCHAR(200),    
          Initialremarks         NVARCHAR(1000)    
         )    
         CREATE TABLE #temptablesearchappExclude  
         (    
          Campaignid             BIGINT,    
          Searchid               BIGINT,    
          Parentid               BIGINT,    
          Personname          NVARCHAR(200),    
          Companyname            NVARCHAR(200),    
          Mobileno               NVARCHAR(200),    
          Mobileno1              NVARCHAR(200),    
          Mobileno2              NVARCHAR(200),    
          Emailid                NVARCHAR(200),    
          Emailid1               NVARCHAR(200),    
          Emailid2               NVARCHAR(200),    
          City                   NVARCHAR(200),    
          STATE                  NVARCHAR(200),    
          Country                NVARCHAR(200),    
          Countrycode            NVARCHAR(200),    
          Pincode                NVARCHAR(200),    
          Residentialaddress     NVARCHAR(200),    
          Officeaddress          NVARCHAR(200),    
          Sourcename             NVARCHAR(200),    
          Mediumname             NVARCHAR(200),    
          Campaignname           NVARCHAR(200),    
          Initialremarks         NVARCHAR(1000)    
         )    
           
          WHILE @Count <> 0    
         BEGIN    
             SET @Count = @Count -1    
                 
             DECLARE @SearchID     BIGINT = (    
                         SELECT TOP 1 SearchID    
                         FROM   #TempSearchs    
                     )    
                  
             DECLARE @SearchIDExc     BIGINT = (    
                         SELECT TOP 1 SearchID    
                         FROM   #TempSearchsExclude    
                     )    
                  
                 
                 
             DELETE     
             FROM   #TempSearchs    
             WHERE  SearchID = @SearchID    
                 
             DELETE     
             FROM   #TempSearchsExclude    
             WHERE  SearchID = @SearchIDExc    
                 
                    
                 INSERT INTO #temptablesearchappExclude    
                   (    
                     Personname,    
                     Companyname,    
                     Mobileno,    
                     Mobileno1,    
                     Mobileno2,    
                     Emailid,    
                     Emailid1,    
                     Emailid2,    
                     Country,    
                     [State],    
                     City,    
                     Pincode,    
                     Residentialaddress,    
                     Officeaddress,    
                     Sourcename,    
                     Mediumname,    
                     Campaignname,    
                     Initialremarks,    
                     Searchid,    
                     Parentid,    
                     Campaignid    
                   )    
                 EXEC Usp_executeusersearch    
                                              @ParentID,    
                      @SearchIDExc,    
                      NULL    
               
                    
                 INSERT INTO #temptablesearchapp    
                   (    
                     Personname,    
                     Companyname,    
                     Mobileno,    
                     Mobileno1,    
                     Mobileno2,    
                     Emailid,    
                     Emailid1,    
                     Emailid2,    
                     Country,    
                     [State],    
                     City,    
                     Pincode,    
                     Residentialaddress,    
                     Officeaddress,    
                     Sourcename,    
                     Mediumname,    
                     Campaignname,    
                     Initialremarks,    
                     Searchid,    
                     Parentid,    
                     Campaignid    
                   )    
                 EXEC Usp_executeusersearch    
                                              @ParentID,    
                      @SearchID,    
                      NULL    
               
         END      
         
       if exists (select 'x' from ( select isnull(Mobileno,'') as Mobileno from #temptablesearchapp usd  
    where usd.mobileno = CASE  
                                                     WHEN Isnull(@MobileNo1, '')  
                                                          =  
                                                          ''  
                                                   THEN  
                                                     usd.mobileno  
                                                     ELSE @MobileNo1  
                                                   END  
       union  
       select isnull(Mobileno1,'') from #temptablesearchapp usd  
       where usd.mobileno1 = CASE  
                                                     WHEN Isnull(@MobileNo1, '')  
                                                          =  
                                                          ''  
                                                   THEN  
                                                     usd.mobileno1  
                                                     ELSE @MobileNo1  
                                                   END  
       union  
       select isnull(Mobileno2,'') from #temptablesearchapp usd  
       where usd.mobileno2 = CASE  
                                                     WHEN Isnull(@MobileNo1, '')  
                                                          =  
                                                          ''  
                                                   THEN  
                                                     usd.mobileno2  
                                                     ELSE @MobileNo1  
                                                   END  
                                                   union  
                                                     
                                                   select isnull(Emailid,'') from #temptablesearchapp usd  
       where usd.Emailid = CASE  
                                                     WHEN Isnull(@EmailID1, '')  
                                                          =  
                                                          ''  
                                                   THEN  
                                                     usd.Emailid  
                                                     ELSE @EmailID1  
                                                   END  
       union  
       select isnull(Emailid1,'') from #temptablesearchapp usd  
       where usd.Emailid1 = CASE  
                                                     WHEN Isnull(@EmailID1, '')  
                                                          =  
                                                          ''  
                                                   THEN  
                                                     usd.Emailid1  
                                                     ELSE @EmailID1  
                                                   END  
       union  
       select isnull(Emailid2,'') from #temptablesearchapp usd  
       where usd.Emailid2 = CASE  
                                                     WHEN Isnull(@EmailID1, '')  
                                                          =  
                                                          ''  
                                                   THEN  
                                                     usd.Emailid2  
                                                     ELSE @EmailID1  
                                                   END   
                                                   union  
                                                   select Isnull(tt.InCludeD ,'') from #tempInCludeDetailsSearch tt  
                                                   ) A  
                                                   where A.Mobileno not in (  select isnull(tt.ExcludeD,'')  from #tempExcludeDetailsSearch tt  
                                                   UNION  
                                                    select isnull(Mobileno,'') as Mobileno from #temptablesearchappExclude usd  
        
       union  
       select isnull(Mobileno1,'') from #temptablesearchappExclude usd   
       union  
       select isnull(Mobileno2,'') from #temptablesearchappExclude usd   
                                                   union  
                                                     
                                                   select isnull(Emailid,'') from #temptablesearchappExclude usd   
       union  
       select isnull(Emailid1,'') from #temptablesearchappExclude usd   
       union  
       select isnull(Emailid2,'') from #temptablesearchappExclude usd  )  
                                                   )  
        BEGIN  
            IF @CouponDiscount = 'Valid'  
              BEGIN  
                  SET @CouponDiscount = 'Valid'  
              END  
        END  
      ELSE  
        BEGIN   
            SET @CouponDiscount = 'Invalid'  
        END  
         
      DROP TABLE #tempInCludeDetailsSearch  
      DROP TABLE #tempExcludeDetailsSearch  
      DROP TABLE #TempSearchs  
      DROP TABLE #TempSearchsExclude  
      DROP TABLE #temptablesearchappExclude  
      DROP TABLE #temptablesearchapp  
  END  
IF EXISTS (SELECT 'x'  
           FROM   #tempcoupon tt  
           WHERE  listapplicability = 1)  
  BEGIN  
    
      SELECT value AS InCludeD  
      INTO   #tempInCludeDetails  
      FROM   #tempcoupon tt  
             OUTER apply Fn_split(InCludeDetails, '#')  
  
  SELECT value AS ExcludeD  
      INTO   #tempExcludeDetails  
      FROM   #tempcoupon tt  
             OUTER apply Fn_split(ExcludeDetails, '#')  
  
    
    
    
      SELECT value AS ListID  
      INTO   #templist  
      FROM   #tempcoupon tt  
             OUTER apply Fn_split(listgroupid, '#')  
  
      SELECT value AS ListID  
      INTO   #templistexclude  
      FROM   #tempcoupon tt  
             OUTER apply Fn_split(listgroupidexclude, '#')  
  
      IF EXISTS (SELECT 'x'  
                 FROM   (SELECT ISNULL(Usd.mobileno,'') as mobileno  
                         FROM   usersearchdata AS Usd  
                         WHERE  Usd.parentid = @ParentID  
                                AND Usd.importedlistid IN (SELECT listid  
                                                           FROM   #templist)  
                                AND usd.mobileno = CASE  
                                                     WHEN Isnull(@MobileNo1, '')  
                                                          =  
                                                          ''  
                                                   THEN  
                                                     usd.mobileno  
                                                     ELSE @MobileNo1  
                                                   END  
                         UNION  
                         SELECT ISNULL(Usd.emailid,'')  
                         FROM   usersearchdata AS Usd  
                         WHERE  Usd.parentid = @ParentID  
                                AND Usd.importedlistid IN (SELECT listid  
                                                           FROM   #templist)  
                                AND usd.emailid = CASE  
                                                    WHEN Isnull(@EmailID1, '') =  
                                                         ''  
                                                  THEN  
                                                    usd.emailid  
                                                    ELSE @EmailID1  
                                                  END  
                         UNION  
                         SELECT ISNULL(Cd.contact_mobile,'')  
                         FROM   contact_detail AS Cd  
                                INNER JOIN contact_group_detail AS Cgd  
                                        ON Cgd.contact_id = Cd.contact_id  
                         WHERE  Cgd.group_id IN (SELECT listid  
                                                 FROM   #templist)  
    AND Cd.contact_mobile = CASE  
                                                          WHEN  
                                    Isnull(@MobileNo1, '') = '' THEN  
                                                          Cd.contact_mobile  
                                                          ELSE @MobileNo1  
                                                        END  
                          union  
                                               SELECT ISNULL(Cd.InCludeD,'')  
                                         FROM   #tempInCludeDetails AS Cd   
                                         WHERE cd.InCludeD =  CASE  
                                                          WHEN  
                                    Isnull(@MobileNo1, '') = '' THEN  
                                                         cd.InCludeD  
                                                          ELSE @MobileNo1  
                                                        END  
                                                        or cd.InCludeD =  CASE  
                                                          WHEN  
                                    Isnull(@EmailID1, '') = '' THEN  
                                                         cd.InCludeD  
                                                          ELSE @EmailID1  
                                                        END  
                                                        UNION  
                           
                         SELECT ISNULL(Cd.contact_email,'')  
                         FROM   contact_detail AS Cd  
                                INNER JOIN contact_group_detail AS Cgd  
                                        ON Cgd.contact_id = Cd.contact_id  
                         WHERE  Cgd.group_id IN (SELECT listid  
                                                 FROM   #templist)  
                                AND Cd.contact_email = CASE  
                                                         WHEN  
                                    Isnull(@EmailID1, '') = ''  
                                                       THEN  
                                                         Cd.contact_email  
                                                         ELSE @EmailID1  
                                                       END) A  
                 WHERE  mobileno NOT IN (SELECT ISNULL(Usd.mobileno,'')  
                                         FROM   usersearchdata AS Usd  
                                         WHERE  Usd.parentid = @ParentID  
                                                AND Usd.importedlistid IN (  
                                                    SELECT  
                                                    listid  
                                                                           FROM  
                                                    #templistexclude)  
                                         UNION  
                                         SELECT ISNULL(Usd.emailid,'')  
                                         FROM   usersearchdata AS Usd  
                                         WHERE  Usd.parentid = @ParentID  
                                                AND Usd.importedlistid IN (  
                                                    SELECT  
                                                    listid  
                                                                           FROM  
                                                    #templistexclude)  
                                         UNION  
                                         SELECT ISNULL(Cd.contact_mobile,'')  
                                         FROM   contact_detail AS Cd  
                                                INNER JOIN contact_group_detail  
                                                           AS  
                                                           Cgd  
                                                        ON Cgd.contact_id =  
                                                           Cd.contact_id  
                                         WHERE  Cgd.group_id IN (SELECT listid  
                                                                 FROM  
                                                #templistexclude)  
                                         UNION  
                                         SELECT ISNULL(Cd.contact_email,'')  
                                         FROM   contact_detail AS Cd  
                                                INNER JOIN contact_group_detail  
                                                           AS  
                                                           Cgd  
                                                        ON Cgd.contact_id =  
                                                           Cd.contact_id  
                                         WHERE  Cgd.group_id IN (SELECT listid  
                                                                 FROM  
                                                #templistexclude)  
                                                union  
                                               SELECT ISNULL(Cd.ExcludeD,'')  
                                         FROM   #tempExcludeDetails AS Cd   
                                            
                                        ))  
        BEGIN  
            IF @CouponDiscount = 'Valid'  
              BEGIN  
                  SET @CouponDiscount = 'Valid'  
              END  
        END  
      ELSE  
        BEGIN   
            SET @CouponDiscount = 'Invalid'  
        END  
  
  
      DROP TABLE #templist  
drop table #tempInCludeDetails  
drop table #tempExcludeDetails  
      DROP TABLE #templistexclude  
  END  
  
IF @CouponDiscount = 'Valid'  
  BEGIN  
      SELECT *  
      FROM   #tempcoupon  
  END  
   
  
DROP TABLE #tempcoupon    
END


GO

/* ============================================================
   Procedure: [dbo].[usp_ApprovePaymentRequests]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON



CREATE   PROC [dbo].[usp_ApprovePaymentRequests]              
@id int,@status bit=1 ,@Transactionid nvarchar(50)=null,@creditsupdated bigint =null            
as              
begin      
if @status =1      
begin          
declare @referid int=(select top 1 referrerID from PayoutStatus where ID=@id order by DateCreated desc)        
declare @bankdetails nvarchar(max) = (select top 1 r.BankName + ', ' + r.Branch + ', ' + cast(r.AccountNo as nvarchar(max)) from Referrer_Bank_Details r where ReferrerID=@referid order by DateCreated desc)         
declare @mop nvarchar(50) = (select modeofpayment from PayoutStatus where ID=@id)        
if exists(select top 1 1 from PayoutStatus where @id=ID and isnull(PaymentRequested,0)<>0 and ISNULL(PayoutStatus,'Open')='Open' order by DateCreated desc )        
begin        
if @mop='neft'        
begin        
update PayoutStatus set PayoutStatus='Closed',Transactionid=@Transactionid,Remarks = 'Payment transferred through neft transactionid '+ @Transactionid +' to bank ' + @bankdetails where ID=@id    
exec usp_updateuseractivity @referid,'PayOutPaid',0         
end        
else        
begin        
declare @kit19userid bigint,@kit19user nvarchar(100)        
select @kit19userid=kit19userid from Referrer_Details where ID=@referid        
select @kit19user=user_login from user_detail where USER_ID=@kit19userid        
update PayoutStatus set PayoutStatus='Closed',Remarks = 'Payment credited as ' + @creditsupdated + ' Kit19 credits in account '  + @kit19user  where ID=@id        
exec usp_updateuseractivity @referid,'PayOutPaid',0     
end        
end       
end         
end 






GO

