/* ============================================================
   Procedure: [dbo].[usp_archive_dltmsg]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_archive_dltmsg  
as  
begin   
declare @c bigint=(select count(1) from DLT_Template_MSG(nolock) d where cast(isnull(batchtime,getdate()) as datetime)<dateadd(d,-1,getdate())),@id bigint=0--56217756
--(select count(1) from DLT_Template_MSG(nolock) d join batchinfo b(nolock)  
--on d.batchid=b.batchid  
--where   
--isnull(nullif(b.scheduleddate,''),batchinserttime)<dateadd(d,-1,getdate())),@id bigint=0--56217756  
create table #output(id bigint)  
--alter table DLT_Template_MSG_bkp add batchtime datetime  
while @c>0  
begin  
select @id=min(id) from DLT_Template_MSG where id>@id
insert into DLT_Template_MSG_bkp(id,batchid,DLT_TemplateID,DLT_MSG_CreatedOn,batchtime,flash) output inserted.id into #output  
select d.id,d.batchid,d.DLT_TemplateID,d.DLT_MSG_CreatedOn,batchtime,flash  
from DLT_Template_MSG(nolock) d 
where cast(isnull(batchtime,getdate()) as datetime)<dateadd(d,-1,getdate())
--join batchinfo b(nolock) on d.batchid=b.batchid  
--where   
--isnull(nullif(b.scheduleddate,''),batchinserttime)<dateadd(d,-1,getdate())  
and d.id between @id and @id+10000  
delete d from DLT_Template_MSG d join #output o on o.id=d.id --where batchid between @batchid and @batchid+10000  
--and batchid<78071705  
truncate table #output  
set @c=@c-10000  
set @id=@id+10000  
end  
drop table #output  
end  
--delete from DLT_Template_MSG_bkp  
  
--select top 100 * from DLT_Template_MSG order by id  
  
--select max(d.batchid) from DLT_Template_MSG(nolock) d join batchinfo b(nolock)  
--on d.batchid=b.batchid  
--where   
--isnull(nullif(b.scheduleddate,''),batchinserttime)<dateadd(d,-1,getdate())


