/* ============================================================
   Procedure: [dbo].[usp_archive_msg_xml]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_archive_msg_xml  
as  
begin  
declare @c int=(select count(1) from MSG_XMLAPI_Resp(nolock) where (dlr_processed=1 and [state]='SUBMIT_ACCEPTED' ) or createddate<dateadd(d,-1,getdate())),@id bigint=0  
drop table if exists #mxml_id  
create table #mxml_id(id bigint)  
while @c>0  
begin  
insert into mysmsreport.dbo.MSG_XMLAPI_Resp_archived(ID,transactionId,[state],description,pdu,corelationId,CreatedDate,tbl_Name,DLR_Processed,DLR_ProcessedAt,Mobile,SenderID,DLT_TemplateID,DLT_PEID,  
errorcode) output inserted.id into #mxml_id  
select top 1000 ID,transactionId,[state],description,pdu,corelationId,CreatedDate,tbl_Name,DLR_Processed,DLR_ProcessedAt,Mobile,SenderID,DLT_TemplateID,DLT_PEID,  
errorcode from  MSG_XMLAPI_Resp(nolock) where --(dlr_processed=1 and [state]='SUBMIT_ACCEPTED' ) or 
createddate<dateadd(d,-1,getdate()) order by id  
  
delete m from   
MSG_XMLAPI_Resp m join #mxml_id i on i.id=m.id  
truncate table #mxml_id  
set @c=@c-1000  
end  
select @c=count(1) from  mysmsreport.dbo.MSG_XMLAPI_Resp_archived(nolock) where createddate<dateadd(m,-6,getdate())  
while @c>0  
begin  
delete m from (select top 1000 * from  mysmsreport.dbo.MSG_XMLAPI_Resp_archived(nolock) where createddate<dateadd(m,-6,getdate()) order by id)  
m  
set @c=@c-1000  
end  
  
  
end  


