/* ============================================================
   Procedure: [dbo].[usp_archive_notificationhistory]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

 CREATE   PROCEDURE usp_archive_notificationhistory
  as
  begin
  declare @c bigint=(select count(1) from notificationhistory(nolock) where createdon<dateadd(d,-30,getdate()) )
  drop table if exists #inserted
  create table #inserted(id bigint)
  while @c>0
  begin
  insert into [notificationhistory_morethan30daysold]([id],[notificationid],[reftable],[refid],[createdon],[readon],[content],[IsDeleted],[n_userid],[nmodeid]) output inserted.id into #inserted
  select top 10000 [id],[notificationid],[reftable],[refid],[createdon],[readon],[content],[IsDeleted],[n_userid],[nmodeid] from notificationhistory(nolock)
  where createdon<dateadd(d,-30,getdate()) order by id
  delete d from notificationhistory d join #inserted i on i.id=d.id
  truncate table #inserted
  select @c=@c-10000
  end
  end


