/* ============================================================
   Procedure: [dbo].[usp_Archive_Tbl_Data]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC usp_Archive_Tbl_Data
AS
Begin

	declare @iDate date
	select @iDate=min([CreatedDate]) FROM [dbo].[Tbl_DataArchive](nolock)

	while @iDate < cast(GETDATE() as date)
	Begin

		print @iDate

		INSERT INTO [dbo].[Tbl_DataArchive_History]
				([ArchiveId],[DatabaseName],[TableName],[BatchId],[RowId],[RowField],[RowData],[ActionType],[CreatedDate])
		SELECT [ArchiveId],[DatabaseName],[TableName],[BatchId],[RowId],[RowField],[RowData],[ActionType],[CreatedDate]
			FROM [dbo].[Tbl_DataArchive]
		where cast(CreatedDate as date)=@iDate

		Delete FROM [dbo].[Tbl_DataArchive] where cast(CreatedDate as date)=@iDate

		select @iDate=min([CreatedDate]) FROM [dbo].[Tbl_DataArchive](nolock)

	End

End



