/* ============================================================
   Procedure: [dbo].[usp_archivecreditdetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[usp_archivecreditdetails]  
as  
begin  
declare @c bigint=(select count(1) from credit_details(nolock) where datediff(mm,DateCreated,getdate())>6)  
create table #output(credit_id bigint)
while @c>0  
begin  
RETRY1:                                                                                                       
BEGIN TRY                                                                                                    
BEGIN TRAN   
insert into MySMSReport.dbo.credit_detailshistory(ID,Credit_ID,M_ID,FromUser_ID,User_ID,Debits,Credits,Balance,Validity,Default_Credit,FromDate,ToDate,DateCreated,DateUpdated,EmpUpdated,MachineName,LastModified,typecredit,  
batchid,CreatedBy) output inserted.credit_id as credit_id into #output  
select top 20000 ID,Credit_ID,M_ID,FromUser_ID,User_ID,Debits,Credits,Balance,Validity,Default_Credit,FromDate,ToDate,DateCreated,DateUpdated,EmpUpdated,MachineName,LastModified,typecredit,  
batchid,CreatedBy from credit_details c WITH (NOLOCK,INDEX(IX_Credit_Details_Userid_Balance))
where datediff(MM,DateCreated,getdate())>6   
and credit_id <>(select max(credit_id) from credit_details(nolock) 
where user_id=c.User_ID)  
order by credit_id   
delete c from credit_details c join #output o on o.credit_id=c.Credit_ID
truncate table #output  
select @c=@c-20000  
select @c,getdate()  
COMMIT                        
END TRY                                             
BEGIN CATCH                             
IF @@TRANCOUNT>0                                                                                
ROLLBACK                                                                           
EXECUTE USP_INSERTERRORINFO;                                                   
IF ERROR_NUMBER() = 1205 -- Deadlock Error Number                                        
BEGIN                                                              
WAITFOR DELAY '00:00:00.05' -- Wait for 5 ms                                                       
GOTO RETRY1 -- Go to Label RETRY                                                              
END                                                                                           
END CATCH                                                          
  
end  
drop table if exists #output  
end


GO

