/* ============================================================
   Procedure: [dbo].[usp_ArchiveVoipKit19Webhooks]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_ArchiveVoipKit19Webhooks
AS
BEGIN
    
    DECLARE @c BIGINT = 0
    SELECT @c = COUNT(1) FROM tbl_voip_Kit19Webhooks(NOLOCK) 
        WHERE CAST(created_on AS DATE) < DATEADD(d, -7, CAST(GETDATE() AS DATE));    

    DROP TABLE IF EXISTS #ids
    CREATE TABLE #ids(id BIGINT)

    WHILE (@c > 0)
    BEGIN    
        INSERT INTO tbl_voip_Kit19Webhooks_archived    
            (id, request_body, created_on, ParentId, srv_pro_id, UniqueIdentity, endpointid, mode)    
        OUTPUT inserted.id AS id INTO #ids    
        SELECT TOP 1000 id, request_body, created_on, ParentId, srv_pro_id, UniqueIdentity, endpointid, mode   
            FROM tbl_voip_Kit19Webhooks(NOLOCK) WHERE CAST(created_on AS DATE) < DATEADD(d, -7, CAST(GETDATE() AS DATE));    
        
        DELETE s FROM tbl_voip_Kit19Webhooks s JOIN #ids i ON i.id = s.id; 
        
        TRUNCATE TABLE #ids;    
        SET @c = @c - 1000;    
    END;    
    DROP TABLE IF EXISTS #ids;   
END;


