/* ============================================================
   Procedure: [dbo].[Usp_aud_getAuditReport]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_aud_getAuditReport @userid BIGINT
	,@fromdt DATETIME = NULL
	,@todate DATETIME = NULL
	,@createdBy VARCHAR(50) = NULL
	,@eventName NVARCHAR(MAX) = ''
	,@eventType NVARCHAR(MAX) = ''
AS
BEGIN
	DECLARE @parentid BIGINT = (
			SELECT ud.ParentID
			FROM User_Detail ud
			WHERE ud.User_ID = @userid
			)
	DECLARE @tableName VARCHAR(20) = 'tbl_Audit_' + CAST(@parentid AS VARCHAR)
	DECLARE @sr VARCHAR(MAX) = ''
		,@et NVARCHAR(MAX) = ''
		,@en NVARCHAR(MAX) = ''

	IF @fromdt IS NULL
		SET @fromdt = '01/01/1999'

	IF @todate IS NULL
		SET @todate = '12/31/9999'

	IF @createdBy IS NULL
		OR @createdBy = ''
		SET @sr = ''
	ELSE
		SET @sr = 'And  aud.User_ID IN (' + @createdBy + ')'

	IF  @eventType <> '' and  @eventType <> ''
	BEGIN
			SET @et = 'And  aud.EventType =''' + @eventType + ''' OR  aud.Activity_Code = ''' + @eventName + ''''
	END
	ELSE
	BEGIN
		IF  @eventType <> ''
		BEGIN
			SET @et = 'And  aud.EventType LIKE ''%' + @eventType + '%'''
		END	
		IF @eventName <> ''
			SET @en = 'And  aud.Activity_Code LIKE ''%' + @eventName + '%'''
	END

	DECLARE @sqlQuery NVARCHAR(MAX) = 'SELECT RowId  
  ,User_Login  
  ,Name  
  ,Activity_type  
  ,Activity_time  
  ,CONVERT (VARCHAR(20), Created_On ,106) AS Created_On  
  ,ActionType  
  ,IsImpersonation  
  ,ImpersonatorId  
  ,mac_address  
  ,RowJson  
  ,ip_adress  
  ,EventType  
  ,Activity_Code
  ,User_ID  
 FROM (  
  SELECT ta.RowId  
   ,ud.User_Login  
   ,ud.FName +' + ''' ''' + '+ ud.LName AS Name  
   ,am.EventName AS Activity_type  
   ,ta.Activity_time  
   ,dbo.fn_getusertimefromindiantime(' + CAST(@userid AS VARCHAR) + ',ta.Created_On)AS Created_On  
   ,ta.ActionType  
   ,ta.IsImpersonation  
   ,ta.ImpersonatorId  
   ,ta.mac_address  
   ,ta.RowJson  
   ,ta.ip_adress  
   ,am.EventType 
   ,am.Activity_Code
   ,ta.User_ID  
  FROM MySmsAudit.dbo.' + @tableName + 
		' ta  
  JOIN MySMS.dbo.User_Detail ud ON ta.User_ID = ud.User_ID  
  JOIN MySMS.dbo.ActivityMaster am ON ta.Activity_type=am.Activity_Code  
  where ta.IsImpersonation  =0
  ) aud   
  WHERE
  aud.Created_On >= ''' + CAST(@fromdt AS VARCHAR) + '''  
   AND  aud.Created_On<=''' + CAST(@todate AS VARCHAR) + '''  
   ' + @sr + ' ' + @en + ' ' + @et + '  
 ORDER BY aud.Created_On DESC'

	PRINT @sqlQuery

	EXECUTE sp_executesql @sqlQuery
END
	--EXEC Usp_aud_getAuditReport @userid=34594, @fromdt='03/09/2022', @createdBy='39832,34594', @todate='12/31/9999'  ,@eventName='Inst_lead_frenqry',@eventtype=''







GO

