   WHILE( @Count <= @CountCampaign )  
   BEGIN  
    DECLARE @Applicability BIGINT, @Exclusions BIGINT, @Parentid BIGINT, @Campaignid BIGINT,  
    @userid BIGINT;  
  
    SELECT @Campaignid=[Campaignid], @Parentid=[Parentid], @userid=[AccountUsed], @Applicability=  
    [tt].[Applicabilty], @Exclusions=[tt].[Exclusions]  
    FROM #temptemplate AS tt  
    WHERE [Id] = @Count;  
  
    IF( @Applicability IS NOT NULL )  
    BEGIN  
     --For contact search, uncomment the below code & use usp_executeusersearch_New3 instead of usp_executeusersearch            
     IF( ISNULL((SELECT [isgroup] FROM usersearchlist(NOLOCK) WHERE [id] = @applicability), 0)  
     = 1 )  
