      --+ CAST(@ParentId AS NVARCHAR) + ',' + CAST(@Applicability AS NVARCHAR) + ',' + CAST(  
      --@Campaignid AS NVARCHAR) +  
      --' WITH RESULT SETS (        
      --(Entityname nvarchar(20),Entityid bigint, personname NVARCHAR(200), companyname NVARCHAR(200), mobileno NVARCHAR(200), mobileno1 NVARCHAR(200), mobileno2 NVARCHAR(200), emailid NVARCHAR(200), emailid1 NVARCHAR(200), emailid2 NVARCHAR(200),country NVARCHAR(200), STATE NVARCHAR(200),city NVARCHAR(200),pincode NVARCHAR(200),residentialaddress NVARCHAR(500), officeaddress NVARCHAR(500),sourcename NVARCHAR(200), mediumname NVARCHAR(200), campaignname NVARCHAR(200), initialremarks NVARCHAR(1000),searchid BIGINT, parentid BIGINT, campaignid BIGINT))'')';  
      --PRINT 'SQLcmd123: ' + @Sqlcmd123;  
      --EXEC (@Sqlcmd123);  
  
      Delete From tbl_SearchResult Where SPId=@@spid  
      Exec Usp_executeusersearchwithid$ @ParentId, @Applicability, @Campaignid  
      insert into #temptablesearchapp(Entityname,Entityid,PersonName,CompanyName,MobileNo,MobileNo1,MobileNo2,EmailID,EmailID1,EmailID2,Country,[STATE], City, PinCode, ResidentialAddress, OfficeAddress, SourceName,MediumName,CampaignName,InitialRemarks,SearchID,ParentID,CampaignID)  SELECT EntityName,Entityid,PersonName,CompanyName,MobileNo,MobileNo1,MobileNo2,EmailID,EmailID1,EmailID2,Country,[STATE],City,PinCode,ResidentialAddress, OfficeAddress, SourceName,MediumName,CampaignName, InitialRemarks,SearchID, ParentID, CampaignID  FROM tbl_SearchResult(nolock) Where SPId=@@spid  
     END;  
    END;  
    IF( @Exclusions IS NOT NULL )  
    BEGIN  
     --For search within contacts uncomment below code            
     IF( ISNULL((SELECT [isgroup] FROM usersearchlist WHERE [id] = @Exclusions), 0) = 1 )  
     BEGIN  
      INSERT INTO #temptablesearchExcContacts([EntityName], [Contact_ID], [Contact_Name],  
      [Contact_Mobile], [Contact_Email], [Contact_DOB], [Contact_Anniversary],  
      [CompanyName], [City], STATE, [Country], [ADDRESS], [DateCreated], [Searchid],  
      [Parentid], [Campaignid], [UserId])  
      EXEC Usp_executeusersearch_New3_withid @parentid, @applicability, @campaignid,  
      @userid;  
     END;  
     ELSE  
     BEGIN  
      --DECLARE @Sqlcmd124 NVARCHAR(MAX)='';  
      --SET @Sqlcmd124=  
      --'insert into #temptablesearchexc(Entityname,Entityid,PersonName,CompanyName,MobileNo,MobileNo1,MobileNo2,EmailID,      EmailID1,EmailID2,Country,[STATE], City, PinCode, ResidentialAddress, OfficeAddress, SourceName,MediumName,CampaignName,InitialRemarks,SearchID, ParentID,CampaignID) SELECT EntityName,Entityid, PersonName, CompanyName, MobileNo, MobileNo1, MobileNo2, EmailID,EmailID1,EmailID2,Country,[STATE],City,PinCode,ResidentialAddress, OfficeAddress,SourceName,MediumName,CampaignName, InitialRemarks,SearchID, ParentID, CampaignID                   FROM OPENROWSET (''SQLNCLI'',''Server=aznetpocdbs01;Database=MySMS;Uid=kit19;PWD=P@ssword3110;'',''Exec Usp_executeusersearchwithid '  
      --+ CAST(@ParentId AS NVARCHAR) + ',' + CAST(@Exclusions AS NVARCHAR) + ',' + CAST(  
      --@Campaignid AS NVARCHAR) +  
      --' WITH RESULT SETS (        
      --(Entityname nvarchar(20),Entityid bigint, personname NVARCHAR(200), companyname NVARCHAR(200), mobileno NVARCHAR(200), mobileno1 NVARCHAR(200), mobileno2 NVARCHAR(200), emailid NVARCHAR(200), emailid1 NVARCHAR(200), emailid2 NVARCHAR(200), country NVARCHAR(200), STATE NVARCHAR(200),city NVARCHAR(200),pincode NVARCHAR(200), residentialaddress NVARCHAR(500), officeaddress NVARCHAR(500),sourcename NVARCHAR(200), mediumname NVARCHAR(200), campaignname NVARCHAR(200), initialremarks NVARCHAR(1000), searchid BIGINT, parentid BIGINT, campaignid BIGINT  ))'')';  
      --PRINT 'Sqlcmd124: ' + @Sqlcmd124;  
      --EXEC (@Sqlcmd124);  
  
        
      Delete From tbl_SearchResult Where SPId=@@spid  
      Exec Usp_executeusersearchwithid$ @ParentId, @Exclusions, @Campaignid  
      insert into #temptablesearchexc(Entityname,Entityid,PersonName,CompanyName,MobileNo,MobileNo1,MobileNo2,EmailID,EmailID1,EmailID2,Country,[STATE], City, PinCode, ResidentialAddress, OfficeAddress, SourceName,MediumName,CampaignName,InitialRemarks,SearchID,ParentID,CampaignID)  SELECT EntityName,Entityid,PersonName,CompanyName,MobileNo,MobileNo1,MobileNo2,EmailID,EmailID1,EmailID2,Country,[STATE],City,PinCode,ResidentialAddress, OfficeAddress, SourceName,MediumName,CampaignName, InitialRemarks,SearchID, ParentID, CampaignID  FROM tbl_SearchResult(nolock) Where SPId=@@spid  
     END;  
    END;  
    SET @Count=@Count + 1;  
  END;  
   --For search within contacts uncomment below code            
/*          INSERT INTO #temptablesearchapp(Entityname,Entityid,EmailID,CampaignID,ParentID,userid)              
          select Entityname,Contact_ID,Contact_Email,CampaignID,ParentID,userid from #temptablesearchContacts            
           INSERT INTO #temptablesearchexc(Entityname,Entityid,EmailID,CampaignID,ParentID,userid)              
          select Entityname,Contact_ID,Contact_Email,CampaignID,ParentID,userid from #temptablesearchExcContacts            
 */  
   SELECT [Entityname], [Entityid], [A].[EmailID], [A].[ParentID], [A].[CampaignID], [A].[userid],  
   [A].[templateid], [A].[PersonName]  
   INTO [#tempemailid]  
   FROM(SELECT DISTINCT  
      [Entityname], [Entityid], [EmailID], [ParentID], [CampaignID], [userid], [TemplateID], [PersonName]  
     FROM(SELECT [Entityname], [Entityid], [Tt2].[EmailID], [Tt2].[ParentID], [Tt2].[CampaignID],  
     [tt].[Accountused] AS [userid], [tt].[TemplateID], [tt2].[PersonName]  
       FROM #temptablesearchapp AS Tt2 JOIN #temptemplate AS tt  
       ON tt.CampaignID = tt2.campaignid  
       WHERE NULLIF([Tt2].[EmailID], '') IS NOT NULL  
       UNION  
       SELECT [Entityname], [Entityid], [Tt2].[EmailID1], [Tt2].[ParentID], [Tt2].[CampaignID],  
       [tt].[Accountused] AS [userid], [tt].[TemplateID], [tt2].[PersonName]  
       FROM #temptablesearchapp AS Tt2 JOIN #temptemplate AS tt  
       ON tt.CampaignID = tt2.campaignid  
       WHERE NULLIF([Tt2].[EmailID1], '') IS NOT NULL  
       UNION  
       SELECT [Entityname], [Entityid], [Tt2].[EmailID2], [Tt2].[ParentID], [Tt2].[CampaignID],  
       [tt].[Accountused] AS [userid], [tt].[TemplateID], [tt2].[PersonName]  
       FROM #temptablesearchapp AS Tt2 JOIN #temptemplate AS tt  
       ON tt.CampaignID = tt2.campaignid  
       WHERE NULLIF([Tt2].[EmailID2], '') IS NOT NULL) AS tt2  
     WHERE NOT EXISTS(SELECT 1  
          FROM [#temptablesearchexc] AS [Tt]  
          WHERE( [Tt2].[CampaignID] = [Tt].[CampaignID] )  
            AND ( [Tt2].[EmailID] = [Tt].[EmailID]  
            OR [Tt2].[EmailID] = [Tt].[EmailID1]  
            OR [Tt2].[EmailID] = [Tt].[EmailID2] ))) AS A;  
  
   SELECT ROW_NUMBER() OVER(  
   ORDER BY [CampaignId], [ParentId]) AS [Id], [Ucerm].[CampaignID], [Ucerm].[ParentID], [ucerm].  
   [userID], COUNT(*) AS [cnt]  
   INTO [#tempCount]  
   FROM #tempemailid AS Ucerm  
   WHERE NULLIF([ucerm].[EmailID], '') IS NOT NULL  
   GROUP BY [Ucerm].[CampaignID], [Ucerm].[ParentID], [Ucerm].[UserID];  
  
   SELECT [A].[UserID], [a].[CampaignID], [a].[cnt], SUM([b].[cnt]) AS [RunningTotal]  
   INTO [#TempTableRunningTotal]  
   FROM #tempCount AS a JOIN #tempCount AS b  
   ON a.userid = b.userid  
   WHERE [b].[CampaignID] <= [a].[CampaignID]  
   GROUP BY [A].[UserID], [a].[CampaignID], [a].[cnt]  
   ORDER BY [a].[CampaignID];  
  
   --- Calculate credits                                            
   SELECT [B].[UserID], [B].[CampaignID],  
          CASE  
          WHEN [B].[Balance] >= [B].[Credits]  
           THEN 1  
          ELSE 0  
          END AS [ValidEntries]  
   INTO [#tempMobile]  
   FROM(SELECT [A].[UserID], [A].[CampaignID], ( [A].[Credits] ) AS [Credits], [A].[Balance]  
     FROM(SELECT [Tt].[UserID], [TT].[RunningTotal] AS [Credits], [TT].[CampaignID], [dbo].  
     [fn_GetMailBalance]([dbo].[ufn_getuserparentid]([tt].[userid])) AS [Balance]  
       FROM #TempTableRunningTotal AS Tt) AS A  
     GROUP BY [A].[UserID], [A].[Balance], [A].[CampaignID], [A].[credits]) AS B;  
  
   UPDATE u SET [u].[ReasonIfNotRun]='Insufficient Balance'  
   FROM [UserCampaignHistory] [u] JOIN [#tempMobile] [t]  
   ON [u].[campaignid] = [t].[CampaignID]  
      AND [u].[jobid] = @jobid  
   WHERE [t].[validentries] = 0;  
  
   DECLARE @validCampaigns1 INT;  
   INSERT INTO Usercampaignexecutionhistory([CampaignID], [Jobid], [ExecutionTime], [IsRecipients],  
   [ParentID])  
   SELECT DISTINCT  
       [A].[CampaignID], @JobId, GETDATE(), 1, [A].[ParentID]  
   FROM(SELECT [TT].[ParentID], [TT].[CampaignID]  
     FROM #tempcount AS TT JOIN #tempMobile AS tm  
     ON tm.CampaignID = tt.CampaignID  
     WHERE [tm].[ValidEntries] = 1) AS A;  
   SELECT @validCampaigns1=@@ROWCOUNT;  
   PRINT concat('ValidCampaigns : ', @validCampaigns1, ', Time: ', GETDATE());  
  
   INSERT INTO EmailsfiltercampaignexecutionTEST2([Entityname], [Entityid], [Mail_ToEmail],  
   [Mail_InsertedDate], [ParentID], [CampaignID], [Mail_UserID], [JobId], [templateid], [EntityPersonName])  
   SELECT DISTINCT  
       [Entityname], [Entityid], [A].[EmailID], GETDATE() AS [MID], [A].[ParentID], [A].  
       [CampaignID], 0 AS [MUID], @Jobid, [TemplateID], [A].[PersonName]  
   FROM(SELECT [Entityname], [Entityid], CAST([Tt].[EmailID] COLLATE Latin1_general_ci_ai AS VARCHAR  
   (500)) AS [EmailID], [Tt].[ParentID], [Tt].[CampaignID], @JobId AS [Jobid], [tt].[TemplateID], [tt].[PersonName]  
     FROM #tempemailid AS Tt  
     WHERE [Tt].[EmailID] <> '' AND [tt].[EmailID] IS NOT NULL  
     UNION  
     SELECT 'Explicit', [fs].[position], CAST([Fs].[value] COLLATE Latin1_general_ci_ai AS  
     VARCHAR(500)), [tt].[ParentID], [tt].[CampaignID], @JobId AS [Jobid], [tt].[TemplateID], '' as PersonName  
     FROM #temptemplate AS tt(NOLOCK) OUTER APPLY Dbo.Fn_split(tt.InclusionsNumber, ',') AS Fs  
     WHERE [fs].value IS NOT NULL AND [fs].value <> '') AS A INNER JOIN #tempMobile AS TM  
   ON TM.CampaignID = A.CampaignID  
   WHERE [TM].[ValidEntries] = 1  
      AND CAST([A].[EmailID] COLLATE Latin1_general_ci_ai AS VARCHAR(500)) NOT IN(SELECT CAST(  
      ISNULL([Fs].[value], 'test') COLLATE Latin1_general_ci_ai AS VARCHAR(500))  
     FROM  
     [#temptemplate] AS [Ucm2](NOLOCK)  
     OUTER APPLY [Dbo].[Fn_split]([Ucm2].[ExclusionsNumber],',') AS [Fs]  
     WHERE [Ucm2].[ID] = [A].[CampaignID] AND [A]. [ParentID] = [Ucm2].[ParentID])  
;  
  
   UPDATE A SET [step1]=1, [step1datetime]=GETDATE(), [step1recipients]=[B].[cnt]  
   FROM [dbo].[UserCampaignHistory] [A] INNER JOIN [#tempcount] [B]  
   ON [A].[campaignid] = [B].[campaignid]  
      AND [A].[Jobid] = @JobId;  
  
   ---------------------------------Send Notification mail --------------------           
   CREATE TABLE #Batch  
   (  
    [batchid]    BIGINT,  
    [parentid]   BIGINT,  
    [campaignid] BIGINT  
   );  
   INSERT INTO Getbatchrecord([User_id], [RandNum])  
   OUTPUT [inserted].[BatchID], [inserted].User_id, [inserted].[RandNum]  
       INTO #batch  
   SELECT [TC].[ParentID], [TC].[CampaignID] FROM #tempCount AS TC;  
   DELETE Kd FROM [Getbatchrecord] [Kd] INNER JOIN [#Batch] [B]  
       ON [B].[BatchId] = [Kd].[BatchID];  
  
   INSERT INTO cloneemailsfilter([Mail_GUID], [Mail_FromEmail], [Mail_ToEmail], [Mail_Subject],  
   [Mail_TempleteName], [Messages], [Mail_InsertedDate], [Mail_UserID], [mail_Parentid], [ReplyTo],  
   [Mail_BatchID], [Mail_Priority], [Mail_ScheduleDate], [Mail_Attechement], [Mail_TempleteBody],  
   [IsMonitor], [TemplateId], Count, [Source], [mailroute])  
   SELECT NEWID(), 'contactus@email19.in', [ucm].[NotificationMail],  
   CASE  
   WHEN [tm].[ValidEntries] = 1  
    THEN 'Campaign execution alert'  
   ELSE 'Failure: Your campaign "' + [ucm].  
   [CampaignName] + '" failed due to insufficient credits'  
   END, '',  
   CASE  
   WHEN [tm].[validentries] = 1  
    THEN 'Hold tight ! Your campaign "' +  
    [Ucm].[CampaignName] + '" scheduled for ' + CAST(GETDATE()  
    AS VARCHAR(50)) +  
    ' is executing. We shall further notify you when the execution completes'  
   ELSE  
   'Oops, you don''t have sufficient mail credits to run your mail campaign "' + [Ucm].  
   [CampaignName] + '" scheduled for ' + CAST(GETDATE()  
   AS VARCHAR(50)) +  
   '. Pl refill your credit balance & rerun the campaign '  
   END, GETDATE(), 335, 335, 'contactus@kit19.com', [B].[BatchId], 1,  
    GETDATE(), 0,  
   CASE  
   WHEN [tm].[validentries] = 1  
    THEN  
    'Hold tight ! Your campaign "' + [Ucm].[CampaignName] + '" scheduled for ' + CAST(  
    GETDATE() AS VARCHAR(50)) +  
    ' is executing. We shall further notify you when the execution completes'  
   ELSE  
   'Oops, you don''t have sufficient mail credits to run your mail campaign "' + [Ucm].  
   [CampaignName] + '" scheduled for ' + CAST(GETDATE()  
   AS VARCHAR(50)) +  
   '. Pl refill your credit balance & rerun the campaign '  
   END, 1, NULL, (SELECT COUNT(1) FROM  
   [#tempcount]),  
   'Internal Notification', 'T'  
   FROM #tempcount AS Tt INNER JOIN Usercampaignmaster AS Ucm(NOLOCK)  
   ON Ucm.ID = Tt.CampaignID AND Ucm.ParentID = Tt.ParentID AND Ucm.IsActive = 1  
    INNER JOIN #tempMobile AS tm  
   ON tm.CampaignID = tt.CampaignID INNER JOIN #Batch AS B  
   ON B.CampaignID = Tt.CampaignID;  
  
   ---------------------------------Send Notification Mail End ----------------              
   ---Update the next schedule for campaign                
   SELECT [campaignid]  
   INTO [#FindCampaignsNextExecution]  
   FROM #temptemplate AS t JOIN UserCampaignMaster AS ucm(NOLOCK)  
   ON t.CampaignID = ucm.id  
   WHERE [ucm].[IsActive] = 1 AND [ucm].[IsSchedule] = 1 AND [ucm].[IsScheduled] = 1;  
  
   DECLARE @count1 INT=ISNULL((SELECT COUNT(1) FROM #FindCampaignsNextExecution), 0);  
   IF @count1 > 0  
   BEGIN  
    CREATE TABLE #nextexec1  
    (  
     [campaignid]    BIGINT,  
     [nextexecution] DATETIME  
    );  
    WHILE @Count1 > 0  
    BEGIN  
     DECLARE @Campaignid1 BIGINT=(SELECT TOP 1 [campaignid] FROM #FindCampaignsNextExecution);  
     INSERT INTO #nextexec1([campaignid], [nextexecution])  
     EXEC Usp_getnextscheduledate @Campaignid1;  
  
     DELETE FROM #FindCampaignsNextExecution WHERE [campaignid] = @Campaignid1;  
     SET @Count1=@Count1 - 1;  
    END;  
  
    UPDATE u SET [NextExecuteDateTime]=[nextexecution]  
    FROM [usercampaignmaster] [u] JOIN [#nextexec1] [n]  
    ON [n].[campaignid] = [u].[id]  
    WHERE [u].[ExpiryDate] > [nextexecution] OR [u].[ExpiryDate] IS NULL;  
  
   END;  
  
   DROP TABLE IF EXISTS #nextexec1;  
   DROP TABLE IF EXISTS #FindCampaignsNextExecution;     DROP TABLE IF EXISTS #Batch;  
   DROP TABLE IF EXISTS #output;  
   DROP TABLE IF EXISTS #tempemailid;  
   DROP TABLE IF EXISTS #temptablesearchapp;  
   DROP TABLE IF EXISTS #temptablesearchexc;  
   DROP TABLE IF EXISTS #tempCount;  
   DROP TABLE IF EXISTS #TempTableRunningTotal;  
   DROP TABLE IF EXISTS #tempMobile;  
   DROP TABLE IF EXISTS #temptemplate;  
   DROP TABLE IF EXISTS #temptablesearchContacts;  
   DROP TABLE IF EXISTS #temptablesearchExcContacts;  
  END;  
  
  IF @campid IS NULL  
  BEGIN  
   UPDATE UserCampaignExecution SET [CampaignExecutedDatetime]=@CampaignStarttime, [isevent]=0  
   WHERE [issms] = 0 AND ISNULL([isevent], 0) = 0  
  END;  
  
  UPDATE A SET [step1]=1, [step1datetime]=GETDATE()  
  FROM [dbo].[UserCampaignHistory] [A]  
  WHERE [A].[Jobid] = @JobId;  
  PRINT concat('Progress: Step 1 complete, Time: ', GETDATE());  
  
  --exec Usp_userexecutecampaignmessagesmailsnewCorrected_segregatemail_withid21102020 @jobid          
  SELECT DISTINCT [EC].[CampaignID], [EC].[ParentID], [EC].[ISCOMPLETED]  
  INTO [#EmailsfiltercampaignexecutionTEST2]  
  FROM EmailsfiltercampaignexecutionTEST2 AS EC WITH(NOLOCK)  
  WHERE [jobid] = @jobid AND [iscompleted] = 0;  
  
  DECLARE @b INT, @e_c BIGINT;  
  
  INSERT INTO campaignmessages([CampaignID], [ParentID], [messages], [Mail_Subject], [Createddate],  
  [Jobid], [templateid])  
  SELECT DISTINCT  
      [Ucm].[ID], [Ucm].[ParentID], CAST([Ucm].[MailContent] AS NVARCHAR(MAX)), [Ucm].[MailSubject],  
      GETDATE(), @Jobid, NULL  
  FROM Usercampaignmaster AS Ucm(NOLOCK) INNER JOIN #EmailsfiltercampaignexecutionTEST2 AS Ucerm(NOLOCK)  
  ON ucm.ID = Ucerm.CampaignID  
  WHERE [Ucerm].[IsCompleted] = 0 AND [Ucm].[MailReplyTo] <> '' AND [Ucm].[MailContent] <> ''  
  UNION  
  SELECT DISTINCT  
      [Ucm].[ID], [Ucm].[ParentID], [umt].[mailcontent], [Umt].[MailSubject], GETDATE(), @Jobid,  
      [ucm].[TemplateID]  
  FROM Usercampaignmaster AS Ucm(NOLOCK) JOIN UserMailTemplate AS umt(NOLOCK)  
  ON umt.ID = ucm.TemplateID INNER JOIN #EmailsfiltercampaignexecutionTEST2 AS Ucerm(NOLOCK)  
  ON ucm.ID = Ucerm.CampaignID  
  WHERE [Ucerm].[IsCompleted] = 0 AND [Ucm].[MailReplyTo] <> '' AND ISNULL([ucm].[TemplateID], 0) <> 0  
     AND [umt].[IsEnquiry] = 0 AND [umt].[IsLeads] = 0 AND [umt].[IsList] = 0 AND [umt].[IsConversion] = 0;  
  
  SELECT @e_c=COUNT(1)  
  FROM EmailsfiltercampaignexecutionTEST2 AS EC(NOLOCK) JOIN Usercampaignmaster AS Ucm(NOLOCK)  
  ON EC.CampaignId = Ucm.ID  
  WHERE [Ucm].[MailReplyTo] <> '' AND [Ucm].[MailContent] <> '' AND [jobid] = @jobid AND [iscompleted] = 0  
     AND ISNULL([ucm].[TemplateID], 0) = 0;  
  PRINT concat('Step 2: composing static mail content, Total Records: ', @e_c, ', Time: ', GETDATE());  
  
  WHILE @e_c > 0  
  BEGIN  
   UPDATE Kd SET [Kd].[Mail_FromEmail]=ISNULL([ucm].[FromMailId], 'contactus@email19.in'), [Kd].  
   [Mail_UserID]=[ucm].[AccountUsed], [Kd].[ReplyTo]=[ucm].[MailReplyTo], [Kd].[Mail_Priority]=0,  
   [Kd].[Mail_ScheduleDate]=GETDATE(), [Kd].[Mail_Attechement]=NULL, [Kd].[Mail_InsertedDate]=  
   GETDATE(), [Kd].[Mail_GUID]=NEWID(), [Kd].[IsCompleted]=1, [kd].[ispersonalized]=0  
   FROM(SELECT TOP 500 *  
     FROM [EmailsfiltercampaignexecutionTEST2] AS [EC](NOLOCK)  
     WHERE [jobid] = @jobid AND [iscompleted] = 0  
     ORDER BY [mail_id]) [kd] JOIN [Usercampaignmaster] [Ucm](NOLOCK)  
   ON [ucm].[ID] = [kd].[CampaignID]  
   WHERE [Ucm].[MailReplyTo] <> '' AND [Ucm].[MailContent] <> '' AND [jobid] = @jobid;  
   SELECT @b=@@ROWCOUNT;  
   SET @e_c=@e_c - @b;  
  END;  
  
  PRINT concat('Step 2: Completed composing static mail content, Total Records: ', @e_c, ', Time: ',  
  GETDATE());  
  
  SELECT @e_c=COUNT(1)  
  FROM Usercampaignmaster AS Ucm(NOLOCK) JOIN UserMailTemplate AS umt(nolock)  
  ON umt.ID = ucm.TemplateID JOIN EmailsfiltercampaignexecutionTEST2 AS EC(nolock)  
  ON EC.CampaignId = Ucm.ID  
  WHERE [Ucm].[MailReplyTo] <> '' AND ISNULL([ucm].[TemplateID], 0) <> 0 AND [ec].[jobid] = @jobid  
     AND [ec].[iscompleted] = 0 AND [umt].[IsEnquiry] = 0 AND [umt].[IsLeads] = 0  
     AND [umt].[IsList] = 0 AND [umt].[IsConversion] = 0;  
  PRINT concat('Step 2: composing static template content, Total Records: ', @e_c, ', Time: ', GETDATE())   
  
  WHILE @e_c > 0  
  BEGIN  
   UPDATE Kd SET [Kd].[Mail_FromEmail]=ISNULL([ucm].[FromMailId], 'contactus@email19.in'), [Kd].  
   [Mail_UserID]=[ucm].[AccountUsed], [Kd].[ReplyTo]=[ucm].[MailReplyTo], [Kd].[Mail_Priority]=0,  
   [Kd].[Mail_ScheduleDate]=GETDATE(), [Kd].[Mail_Attechement]=NULL, [Kd].[Mail_InsertedDate]=  
   GETDATE(), [Kd].[Mail_GUID]=NEWID(), [Kd].[IsCompleted]=1, [kd].[ispersonalized]=0, [kd].  
   [templateid]=[umt].[id]  
   FROM(SELECT TOP 500 *  
     FROM [EmailsfiltercampaignexecutionTEST2] AS [EC](NOLOCK)  
     WHERE [jobid] = @jobid AND [iscompleted] = 0  
     ORDER BY [mail_id]) [kd] JOIN [Usercampaignmaster] [Ucm](NOLOCK)  
   ON [ucm].[ID] = [kd].[CampaignID] JOIN [UserMailTemplate] [umt](NOLOCK)  
   ON [umt].[ID] = [ucm].[TemplateID]  
   WHERE [Ucm].[MailReplyTo] <> '' AND ISNULL([ucm].[TemplateID], 0) <> 0 AND [umt].[IsEnquiry] = 0  
      AND [umt].[IsLeads] = 0 AND [umt].[IsList] = 0 AND [umt].[IsConversion] = 0;  
  
   SELECT @b=@@ROWCOUNT;  
   SET @e_c=@e_c - @b;  
  END;  
  
  PRINT concat('Step 2: Completed composing static template content, Total Records: ', @e_c, ', Time: ',  
  GETDATE());  
  
  SELECT @e_c=COUNT(1)  
  FROM Usercampaignmaster AS Ucm(NOLOCK) JOIN UserMailTemplate AS umt(NOLOCK)  
  ON umt.ID = ucm.TemplateID JOIN EmailsfiltercampaignexecutionTEST2 AS EC(NOLOCK)  
  ON EC.CampaignId = Ucm.ID  
  WHERE [Ucm].[MailReplyTo] <> '' AND ISNULL([ucm].[TemplateID], 0) <> 0 AND [ec].[jobid] = @jobid  
     AND [ec].[iscompleted] = 0 AND [umt].[IsEnquiry] = 1;  --and ec.entityname='enquiry'          
  PRINT concat('Step 2: composing dynamic enquiry template content, Total Records: ', @e_c, ', Time: ',  
  GETDATE());  
  
  WHILE @e_c > 0  
  BEGIN  
   UPDATE Kd SET [Kd].[Mail_FromEmail]=ISNULL([ucm].[FromMailId], 'contactus@email19.in'), [Kd].  
   [Mail_Subject]=CASE  
         WHEN [kd].[entityname] = 'enquiry'  
          -- THEN [dbo].[fn_getEnquiryMessageMail_withid]([Ucm].[ParentID], [Umt].[mailsubject], [kd].[entityid])  
          THEN REPLACE([Umt].[mailsubject], '#Enquiry.PersonName#', ISNULL(kd.EntityPersonName, ''))  
         ELSE [umt].[mailsubject]  
         END, [Kd].[Messages]=CASE WHEN [kd].[entityname] = 'enquiry'  
             --THEN(SELECT CAST([dbo].[build_mailContent]([umt].[id],[kd].[campaignid], [kd].[parentid], [dbo].[fn_getEnquiryMessageMail_withid]([Ucm].[ParentID], [Umt].[MailContent], [kd].[entityid]), [kd].[Mail_ToEmail]) AS NVARCHAR(MAX)))  
             THEN REPLACE([Umt].[MailContent], '#Enquiry.PersonName#', ISNULL(kd.EntityPersonName, ''))  
            ELSE [umt].[mailcontent]  
            END,   
   [Kd].[Mail_UserID]=[ucm].[AccountUsed], [Kd].[ReplyTo]= [ucm].[MailReplyTo], [Kd].[Mail_Priority]=0, [Kd].[Mail_ScheduleDate]=GETDATE(), [Kd].[Mail_Attechement]=NULL,  
   [Kd].[Mail_TempleteBody]=CASE WHEN [kd].[entityname] = 'enquiry'  
           --THEN(SELECT CAST([dbo].[build_mailContent]([kd].[templateid],[kd].[campaignid], [kd].[parentid], [dbo].[fn_getEnquiryMessageMail_withid]([Ucm].[ParentID],[Umt].[MailContent], [kd].[entityid]), [kd].[Mail_ToEmail]) AS NVARCHAR(MAX)))   
           THEN REPLACE([Umt].[MailContent], '#Enquiry.PersonName#', ISNULL(kd.EntityPersonName, ''))  
           ELSE [umt].[mailcontent] END, [Kd].[Mail_InsertedDate]= GETDATE(), [Kd].[Mail_GUID]=NEWID(), [Kd].[IsCompleted]=1, [kd].[ispersonalized]=1  
   FROM   
   (  
    SELECT TOP 500 *  
    FROM [EmailsfiltercampaignexecutionTEST2] AS [EC](NOLOCK)  
    WHERE [jobid] = @jobid AND [iscompleted] = 0  
    ORDER BY [mail_id]  
   ) [kd] JOIN [Usercampaignmaster] [Ucm](NOLOCK)  
   ON [ucm].[ID] = [kd].[CampaignID] JOIN [UserMailTemplate] [umt](NOLOCK)  
   ON [umt].[ID] = [ucm].[TemplateID]  
   --Left Join userenquiry ue(nolock) ON ue.parentid = Ucm.ParentID AND isnull(kd.entityid,0)=ue.EnquiryID and kd.entityname='Enquiry'         
   WHERE [Ucm].[MailReplyTo] <> '' AND ISNULL([ucm].[TemplateID], 0) <> 0 AND [umt].[IsEnquiry]= 1;  
  
   SELECT @b=@@ROWCOUNT;  
   SET @e_c=@e_c - @b;  
  END;  
  
  PRINT concat('Step 2: Completed composing dynamic enquiry template content, Total Records: ', @e_c,  
  ', Time: ', GETDATE());  
  
  SELECT @e_c=COUNT(1)  
  FROM Usercampaignmaster AS Ucm(NOLOCK) JOIN UserMailTemplate AS umt(NOLOCK)  
  ON umt.ID = ucm.TemplateID JOIN EmailsfiltercampaignexecutionTEST2 AS EC(NOLOCK)  
  ON EC.CampaignId = Ucm.ID  
  WHERE [Ucm].[MailReplyTo] <> '' AND ISNULL([ucm].[TemplateID], 0) <> 0 AND [ec].[jobid] = @jobid  
     AND [ec].[iscompleted] = 0 AND ( [umt].[IsLeads] = 1 OR [umt].[IsConversion] = 1 );  
  PRINT concat('Step 2: composing dynamic lead template content, Total Records: ', @e_c, ', Time: ',  
  GETDATE());  
  
  WHILE @e_c > 0  
  BEGIN  
   UPDATE Kd SET [Kd].[Mail_FromEmail]=ISNULL([ucm].[FromMailId], 'contactus@email19.in'), [Kd].  
   [Mail_Subject]=CASE  
         WHEN [kd].[entityname] = 'lead'  
          --THEN [dbo].[fn_getLeadsMailMessage_withid]([Ucm].[ParentID], [Umt].[MailSubject], [kd].[entityid])  
          THEN REPLACE([Umt].[MailSubject], '#Lead.PersonName#', ISNULL(kd.EntityPersonName, ''))  
         ELSE [umt].[mailcontent] END,   
   [Kd].[Messages]=CASE WHEN [kd].[entityname] = 'lead'  
         --THEN [dbo].[fn_getLeadsMailMessage_withid]([Ucm].[ParentID], [Umt].[MailContent], [kd].[entityid])  
         THEN REPLACE([Umt].[MailContent], '#Lead.PersonName#', ISNULL(kd.EntityPersonName, ''))  
         ELSE [umt].[mailcontent] END,   
   [Kd].[Mail_UserID]=[ucm].[AccountUsed], [Kd].[ReplyTo]=[ucm].[MailReplyTo], [Kd].[Mail_Priority]=0,  
   [Kd].[Mail_ScheduleDate]=GETDATE(), [Kd].[Mail_Attechement]=NULL,  
   [Kd].[Mail_TempleteBody]=CASE WHEN [kd].[entityname] = 'lead'  
            --THEN [dbo].[fn_getLeadsMailMessage_withid]([Ucm].[ParentID],[Umt].[MailContent], [kd].[entityid])  
            THEN REPLACE([Umt].[MailContent], '#Lead.PersonName#', ISNULL(kd.EntityPersonName, ''))  
            ELSE [umt].[mailcontent] END, [Kd].[Mail_InsertedDate]= GETDATE(),  
   [Kd].[Mail_GUID]=NEWID(),[Kd].[IsCompleted]=1, [kd].[ispersonalized]=1  
   FROM  
   (  
    SELECT TOP 500 *  
    FROM [EmailsfiltercampaignexecutionTEST2] AS [EC](NOLOCK)  
    WHERE [jobid] = @jobid AND [iscompleted] = 0  
    ORDER BY [mail_id]  
   ) [kd] JOIN [Usercampaignmaster] [Ucm](NOLOCK)  
   ON [ucm].[ID] = [kd].[CampaignID] JOIN [UserMailTemplate] [umt](NOLOCK)  
   ON [umt].[ID] = [ucm].[TemplateID]  
   WHERE [Ucm].[MailReplyTo] <> '' AND ISNULL([ucm].[TemplateID], 0) <> 0  
      AND ( [umt].[IsLeads] = 1 OR [umt].[IsConversion] = 1 );  
  
   SELECT @b=@@ROWCOUNT;  
   SET @e_c=@e_c - @b;  
  END;  
    
  PRINT concat('Step 2: Completed composing dynamic lead template content, Total Records: ', @e_c,  
  ', Time: ', GETDATE());  
  
  UPDATE Kd SET [Ismessages]=1  
  FROM [Usercampaignexecutionhistory] [Kd] INNER JOIN [#EmailsfiltercampaignexecutionTEST2] [A](NOLOCK)  
  ON [Kd].[CampaignID] = [A].[CampaignID] AND [A].[ParentID] = [Kd].[ParentID] AND [Kd].[JobId] = @Jobid;  
  
  UPDATE Kd SET [Kd].[Step2]=1, [Step2DateTime]=GETDATE(), [Step2Recipients]=ISNULL([A].  
  [Step2Recipients], 0)  
  FROM [Usercampaignhistory] [Kd] INNER JOIN(SELECT [campaignid], COUNT([campaignid]) AS  
  [Step2Recipients], [parentid]  
                 FROM [EmailsfiltercampaignexecutionTEST2](NOLOCK)  
                 WHERE [iscompleted] = 1 AND [jobid] = @jobid  
                 GROUP BY [Parentid], [campaignid]) [A]  
  ON [Kd].[CampaignID] = [A].[CampaignID] AND [A].[ParentID] = [Kd].[ParentID] AND [Kd].[JobId] = @Jobid;  
  
  UPDATE Kd SET [Kd].[Step2]=1, [Step2DateTime]=GETDATE() FROM [Usercampaignhistory] [Kd] WHERE [JobId]  
  = @jobid;  
  
  PRINT concat('Step 2 complete, Time: ', GETDATE());  
  PRINT 'Step 3 started';  
  
  CREATE TABLE #outputb  
  (  
   [id]         INT IDENTITY(1, 1),  
   [bid]        BIGINT,  
   [u_id]       BIGINT,  
   [campaignid] BIGINT  
  );  
  
  BEGIN TRAN;  
   INSERT INTO Getbatchrecord([User_id], [RandNum])  
   OUTPUT [inserted].[BatchID] AS [bId], [inserted].User_id AS [u_id], [inserted].[RandNum] AS  
   [campaignid]  
       INTO #outputb  
   SELECT DISTINCT  
       [Ucerm].[ParentID], [Ucerm].[CampaignID]  
   FROM EmailsfiltercampaignexecutionTEST2 AS Ucerm WITH(NOLOCK)  
   WHERE [jobid] = @jobid;  
   DELETE g FROM [GetBatchRecord] [g] JOIN [#outputb] [o]  
      ON [o].[bid] = [g].[BatchID];  
  COMMIT;  
  
  SELECT ROW_NUMBER() OVER(ORDER BY [Ucerm].[CampaignId], [Ucerm].[ParentId]) AS [Id], [Ucerm].[CampaignID], [Ucerm].[ParentID],[o].[bid] AS [BatchID], [Ucerm].[Mail_FromEmail], [Ucerm].[Mail_UserID] AS [UserID], [Ucerm].[ReplyTo], COUNT(*) AS [cnt], [uce
rm].[ispersonalized], [ucerm].[templateid]  
  INTO [#tempTable]  
  FROM EmailsfiltercampaignexecutionTEST2 AS Ucerm JOIN #outputb AS o  
  ON o.u_id = ucerm.parentid AND o.campaignid = ucerm.campaignid  
  WHERE [Ucerm].[IsCompleted] = 1 AND [jobid] = @jobid  
  GROUP BY [Ucerm].[CampaignID], [Ucerm].[ParentID], [Ucerm].[Mail_FromEmail], [Ucerm].[Mail_UserID],  
  [Ucerm].[ReplyTo], [ucerm].[ispersonalized], [o].[bid], [ucerm].[templateid];  
  
  SELECT [A].[UserID], [a].[CampaignID], [a].[cnt], [A].[BatchID], SUM([b].[cnt]) AS [RunningTotal]  
  INTO [#TempTableRunningTotal3]  
  FROM #tempTable AS a INNER JOIN #tempTable AS b  
  ON b.CampaignID <= a.CampaignID  
  GROUP BY [A].[UserID], [a].[CampaignID], [a].[cnt], [A].[BatchID]  
  ORDER BY [a].[CampaignID];  
  
  DROP TABLE IF EXISTS #outputb;  
  
  --- Calculate credits         
  SELECT [B].[UserID], [B].[CampaignID],  
         CASE  
         WHEN [B].[Balance] >= [B].[Credits]  
          THEN 1  
         ELSE 0  
         END AS [ValidEntries]  
  INTO [#tempMobile3]  
  FROM(SELECT [A].[UserID], [A].[CampaignID], ( [A].[Credits] ) AS [Credits], [A].[Balance]  
    FROM(SELECT [Tt].[UserID], [TT].[RunningTotal] AS [Credits], [TT].[CampaignID], [Tt].[BatchID],  
    [dbo].[fn_getmailbalance]([dbo].[ufn_getuserparentid]([tt].[userid])) AS [Balance]  
      FROM #TempTableRunningTotal3 AS Tt) AS A  
    GROUP BY [A].[UserID], [A].[Balance], [A].[CampaignID], [A].[credits]) AS B;  
  
  UPDATE u SET [u].[ReasonIfNotRun]='Insufficient Balance'  
  FROM [UserCampaignHistory] [u] JOIN [#tempMobile3] [t]  
  ON [u].[campaignid] = [t].[CampaignID]  
     AND [u].[jobid] = @jobid  
  WHERE [t].[validentries] = 0;  
  
  DECLARE @dis_parentid INT, @c_id BIGINT=0, @p_id BIGINT, @sql_t1 NVARCHAR(MAX), @tname NVARCHAR(100);  
  CREATE TABLE #clonet  
  (  
   [tablename] NVARCHAR(100)  
  );  
  SELECT @dis_parentid=COUNT(DISTINCT [campaignid]) FROM #tempmobile3 WHERE [ValidEntries] = 1;  
  
  WHILE @dis_parentid > 0  
  BEGIN  
   SELECT @c_id=MIN([campaignid]) FROM #tempmobile3(NOLOCK) WHERE [campaignid] > @c_id  
                     AND [ValidEntries] = 1;  
   SELECT @p_id=[dbo].[ufn_getuserparentid]([userid]) FROM #tempmobile3 WHERE [campaignid] = @c_id;  
  
   INSERT INTO Mailcreditdetails([ID], [M_ID], [FromUser_ID], [User_ID], [Debits], [Credits],  
   [Balance], [Validity], [Default_Credit], [FromDate], [ToDate], [DateCreated], [DateUpdated],  
   [EmpUpdated], [MachineName], [LastModified], [typecredit], [campaignid], [batchid])  
   SELECT NEWID(), [Ud].[M_ID], @p_id, @p_id, [c].[cnt], 0, [dbo].[fn_getmailbalance](@p_id) - [c].  
   [cnt], 99999, '', GETDATE(), GETDATE(), GETDATE(), GETDATE(), '', '', GETDATE(), '', 0, [c].  
   [BatchID]  
   FROM #tempTable AS c(NOLOCK) JOIN user_detail AS ud(NOLOCK)  
   ON ud.User_ID = c.parentid  
   WHERE [c].[CampaignID] = @c_id;  
  
   -- print concat('Processing campaign :',@c_id,' for parentid: ',@p_id)        
   INSERT INTO #clonet([tablename])  
   EXEC [usp_CreateCloneEmailTable111_New] @p_id;  
   SELECT TOP 1 @tname=[tablename] FROM #clonet;  
   PRINT concat('Processing campaign :', @c_id, ' for parentid: ', @p_id, ', Mail Table: ', @tname);  
   SELECT @sql_t1='insert into ' + QUOTENAME(@tname) + ' (Mail_GUID,Mail_FromEmail,Mail_ToEmail,Mail_Subject,Mail_TempleteName,Messages,Mail_InsertedDate,Mail_UserID,Mail_ParentID,ReplyTo,Mail_BatchID,Mail_Priority,Mail_ScheduleDate,Mail_ScheduledTime,Mai
l_Attechement,Mail_TempleteBody,IsMonitor, TemplateID,Source,mailroute,count)        
   select newid(),Efce.Mail_FromEmail,Efce.Mail_ToEmail,case when efce.ispersonalized=1 and Efce.mail_subject is not null then Efce.mail_subject else c.Mail_Subject end,Efce.Mail_TempleteName,case when efce.ispersonalized=1 and Efce.Messages is not null t
hen cast(Efce.Messages as nvarchar(max)) else CAST(dbo.build_mailContent(c.templateid,c.campaignid,c.parentid,c.Messages,Efce.Mail_ToEmail) AS NVARCHAR(MAX)) end, isnull(Efce.Mail_InsertedDate,getdate()),Efce.Mail_UserID,dbo.ufn_getuserparentid(efce.mail_
userid),Efce.ReplyTo,TT.BatchID,case when tt.cnt>10 then Efce.Mail_Priority when tt.cnt<=10 then 1 else 0 end,isnull(Efce.Mail_ScheduleDate,getdate()),isnull(Efce.Mail_ScheduleDate,getdate()),Efce.Mail_Attechement, case when efce.ispersonalized=1 and Efce
.Messages is not null then cast(Efce.Messages as nvarchar(max)) else CAST(dbo.build_mailContent(c.templateid,c.campaignid,c.parentid,c.Messages,Efce.Mail_ToEmail) AS NVARCHAR(MAX)) end, (select case when status=1 and tt.cnt>plimit then 0 else 1 end from P
rocessMailLimit),efce.templateid,''Campaign : ''+cast (tt.campaignid as nvarchar),''T'',1      
    FROM EmailsfiltercampaignexecutionTEST2 AS Efce INNER JOIN #tempMobile3 Tm ON Tm.userID = Efce.Mail_UserID  and Tm.CampaignID = Efce.CampaignID AND ValidEntries = 1            
   inner join #tempTable TT on TT.campaignid=efce.campaignid        
   left join campaignmessages c on  c.campaignid=efce.campaignid and c.jobid=efce.jobid           
   WHERE  Efce.IsCompleted = 1 and efce.campaignid=' + CAST(@c_id AS NVARCHAR) + ' and efce.jobid= ' + CAST(@jobid AS NVARCHAR) + ';      
   update ' + QUOTENAME(@tname) +  
   ' set count = (select count(1) from EmailsfiltercampaignexecutionTEST2 efce WHERE       
   Efce.IsCompleted = 1 and efce.campaignid=' + CAST(@c_id AS NVARCHAR) + ' and efce.jobid= ' + CAST(@jobid AS NVARCHAR) + ');    
   -- select * from ' + QUOTENAME(@tname) +' ;    
   INSERT INTO Batchemail_infos(BatchID,UserID,SenderName,[Message],TotalRecords,TotalProcessed,ProcessTable,IsProcess,Priority_Level,    
   BatchInsertTime,BatchProcessTime,ScheduledDate,ScheduledTime,TemplateID,[Route],PageName        
   ,IsScheduled,Email_Subject,ReplyTo,ispersonalized,Mail_Source,mailroute,bmonitor,tablename)          
   SELECT s.BatchID,s.UserID,s.Mail_FromEmail,        
   case when isnull(s.templateid,0)<>0 then         
   (select MailContent from UserMailTemplate where ID=s.TemplateID)         
   when isnull(cast(c.messages as nvarchar(max)),'''')<>''''         
   then cast(c.messages as nvarchar(max))         
   else '''' end as Message,        
   C_count,0,0,0,        
   case when C_count>10 then 0 when c_count<=10 then 1 end,                                                
   Getdate(),NULL,Getdate(),Getdate(),s.TemplateID,0,0,0,        
   case when isnull(s.templateid,0)<>0         
   then (select mailsubject from UserMailTemplate where ID=s.TemplateID)         
   when isnull(c.Mail_subject,'''')<>'''' then c.mail_subject else '''' end as Mail_Subject,        
   ReplyTo,e.ispersonalized,''Campaign :''+cast(s.campaignid as nvarchar),''T'',    
   1,''' + @tname + '''          
   FROM #tempTable s (nolock) join (select campaignid,parentid,count(1) as C_count,ispersonalized from EmailsfiltercampaignexecutionTEST2(nolock) where jobid='  
   + CAST(@jobid AS NVARCHAR) +  
   ' group by  campaignid,parentid,ispersonalized) e    
   on e.CampaignID=s.CampaignID and e.ParentID=s.ParentID     
   left join campaignmessages c on c.batchid=s.batchid ';  
  
   PRINT 'Sql_t1: ' + @sql_t1;  
   EXEC sp_executesql @sql_t1;  
  
   DECLARE @tbl_activity AS dbo.LeadActivitywithid_Tbltype;  
   INSERT INTO @tbl_activity([LeadID], [UserID], [ParentID], [EventDescription], [EventName],  
   [RefTable], [refid])  
   SELECT [m].[entityid], [m].[Mail_UserID], [m].[ParentID], CAST([u].[user_login] AS NVARCHAR(100))  
   + ' sent ' + CASE  
       WHEN NULLIF([cm].[TemplateID], 0) IS NOT NULL  
        THEN ' template with name"' + ISNULL([umt].[Name], 'no name') + '"'  
       ELSE ' a mail '  
       END + ' with subject "' + CASE  
               WHEN NULLIF([cm].[TemplateID], 0) IS NOT NULL  
                THEN [umt].[MailSubject]  
               WHEN [cm].[Mail_Subject] IS NOT NULL  
                THEN [cm].[Mail_Subject]  
               ELSE ISNULL(replace([m].[mail_subject], '''', '"'), '')  
               END + '" to emailid ' + CAST([m].[Mail_ToEmail] AS  
               NVARCHAR(100)) + ' through automated campaign named ' +  
               [c].[CampaignName], 'Mail sent to ' + [m].[entityname],  
               'Batchemail_infos', [tt].[BatchID]  
   FROM user_detail(NOLOCK) AS u JOIN EmailsfiltercampaignexecutionTEST2(NOLOCK) AS m  
   ON m.Mail_UserID = u.User_ID JOIN UserCampaignMaster(NOLOCK) AS c  
   ON c.ID = m.CampaignID LEFT JOIN campaignmessages(NOLOCK) AS cm  
   ON cm.campaignid = m.campaignid AND cm.jobid = m.jobid LEFT JOIN usermailtemplate(NOLOCK) AS umt  
   ON umt.id = cm.templateid JOIN #tempTable AS tt  
   ON tt.CampaignID = m.CampaignID  
   WHERE [m].[entityname] IN ('Lead', 'Enquiry')  
      AND ISNULL([m].[entityid], 0) <> 0  
      AND [m].[jobid] = @jobid  
      AND [m].[CampaignID] = @c_id;  
  
   EXEC UspSaveEntityActivity_withMultipleValue_withid_bulk @tbl_activity;  
  
   SET @dis_parentid=@dis_parentid - 1;  
  
   TRUNCATE TABLE #clonet;  
   DELETE FROM @tbl_activity;  
  END;  
  
  UPDATE Kd SET [Executiontime]=GETDATE(), [Noofrecipients]=[Tt].[Cnt], [Batchid]=[Tt].[BatchID],  
  [Isexecuted]=CASE  
      WHEN [tm].[Validentries] = 1  
       THEN 1  
      ELSE 0  
      END  
  FROM [Usercampaignexecutionhistory] [Kd] INNER JOIN [#tempTable] [Tt]  
  ON [Tt].[CampaignID] = [Kd].[CampaignID] INNER JOIN [#tempMobile3] [Tm]  
  ON [Tm].[userID] = [Tt].[userID] AND [Tm].[CampaignID] = [Tt].[CampaignID]  
  WHERE [Jobid] = @jobId;  
  
  CREATE TABLE #batch3  
  (  
   [batchid]    BIGINT,  
   [parentid]   BIGINT,  
   [campaignid] BIGINT  
  );  
  INSERT INTO Getbatchrecord([User_id], [RandNum])  
  OUTPUT [inserted].[batchid], [inserted].user_id, [inserted].[RandNum]  
  SELECT [ParentID], [CampaignID] FROM #tempTable;  
  DELETE g FROM [Getbatchrecord] [g] JOIN [#batch3] [b]  
     ON [g].[batchid] = [b].[batchid];  
  
  INSERT INTO cloneemailsfilter([Mail_GUID], [Mail_FromEmail], [Mail_ToEmail], [Mail_Subject],  
  [Mail_TempleteName], [Messages], [Mail_InsertedDate], [Mail_UserID], [mail_Parentid], [ReplyTo],  
  [Mail_BatchID], [Mail_Priority], [Mail_ScheduleDate], [Mail_Attechement], [Mail_TempleteBody],  
  [IsMonitor], [TemplateId], Count, [Source], [mailroute])  
  SELECT NEWID(), 'contactus@email19.in', [ucm].[NotificationMail],  
  CASE  
  WHEN [TM].[ValidEntries] = 0  
   THEN 'Failure: Your campaign "' + +[UCM].  
   [CampaignName] + '" failed due to insufficient credits'  
  ELSE 'Success : Your campaign "' + [UCM].[CampaignName]  
  + '" executed successfully'  
  END AS [Mail_subject], '',  
  CASE  
  WHEN [TM].[ValidEntries] = 0  
   THEN  
   'Oops, you don''t have sufficient mail credits to run your mail campaign "' + [UCM].  
   [CampaignName] + '" scheduled for ' + CAST(GETDATE()  
   AS VARCHAR(50)) +  
   '. Pl refill your credit balance & rerun the campaign '  
  ELSE  
  'As promised , Your Mail campaign "' + [UCM].[CampaignName] + '" scheduled for ' + CAST  
  (GETDATE() AS VARCHAR(50)) +  
  ' is executed successfully. You can log in to your account & check the delivery report in the campaign history'  
  END AS [Messages], GETDATE(),  
  335, 335, 'contactus@kit19.com',  
  [B].[BatchId], 1, GETDATE(), 0,  
  CASE  
  WHEN [TM].[ValidEntries] = 0  
   THEN 'Oops, you don''t have sufficient mail credits to run your mail campaign "' +  
   [UCM].[CampaignName] + '" scheduled for ' + CAST(GETDATE()  
   AS VARCHAR(50)) + '. Pl refill your credit balance & rerun the campaign '  
  ELSE  
  'As promised , Your Mail campaign "' + [UCM].[CampaignName] + '" scheduled for ' + CAST(GETDATE()  
  AS VARCHAR(50)) + ' is executed successfully. You can log in to your account & check the delivery report in the campaign history'  
  END  
  AS [Messages],1,NULL,(SELECT COUNT(DISTINCT [campaignid]) FROM [#tempTable]),'Internal Notification','T'  
  FROM #tempTable AS Tt INNER JOIN Usercampaignmaster AS Ucm  
  ON Ucm.ID = Tt.CampaignID AND Ucm.IsScheduled = 1 AND Ucm.ParentID = Tt.ParentID INNER JOIN #tempMobile3 AS TM  
  ON TM.CampaignID = Ucm.ID INNER JOIN #Batch3 AS B  
  ON B.CampaignId = Tt.CampaignId;  
  
  DECLARE @emailcount BIGINT=(SELECT COUNT(1)  
         FROM EmailsfiltercampaignexecutionTEST2 AS Kd(NOLOCK) INNER JOIN  
         #tempTable AS Tt  
         ON Tt.CampaignID = Kd.CampaignID  
            AND jobid = @jobid);  
  WHILE @emailcount > 0  
  BEGIN  
   DELETE TOP (1000) Kd  
   FROM [EmailsfiltercampaignexecutionTEST2] [Kd] INNER JOIN [#tempTable] [Tt]  
   ON [Tt].[CampaignID] = [Kd].[CampaignID] AND [jobid] = @jobid;  
   SET @emailcount=@emailcount - 1000;  
  END;  
  
  UPDATE Kd SET [Kd].[step3]=1, [Step3DateTime]=GETDATE(),   
  [Step3Recipients]=CASE WHEN [ValidEntries] = 1 THEN [TT].[cnt] ELSE 0 END  
  FROM [usercampaignhistory] [Kd] INNER JOIN [#tempTable] [TT]  
  ON [TT].[CampaignID] = [Kd].[CampaignID] INNER JOIN [#tempMobile3] [TM]  
  ON [TM].[CampaignID] = [Kd].[CampaignID]  
  WHERE [Kd].[JobId] = @jobId;  
  
  UPDATE Kd SET [Kd].[step3]=1, [Step3DateTime]=GETDATE()  
  FROM [usercampaignhistory] [Kd]  
  WHERE [Kd].[JobId] = @jobId;  
  PRINT 'Step 3 complete';  
  
  UPDATE u SET [executeddatetime]=GETDATE()  
  FROM [usercampaignmaster] [u] JOIN [usercampaignhistory] [Kd]  
  ON [kd].[campaignid] = [u].[id] AND [Kd].[JobId] = @jobId;  
  
  SELECT [campaignid]  
  INTO [#FindCampaignsNextExecution3]  
  FROM #tempTable AS t JOIN UserCampaignMaster AS ucm  
  ON t.CampaignID = ucm.id LEFT JOIN userschedules AS us  
  ON us.id = ucm.scheduleid  
  WHERE [ucm].[IsActive] = 1 AND [ucm].[IsSchedule] = 1 AND [ucm].[IsScheduled] = 1 AND [us].[IsOnce] = 0;  
  
  DECLARE @count3 INT=ISNULL((SELECT COUNT(1) FROM #FindCampaignsNextExecution3), 0);  
  IF @count3 > 0  
  BEGIN  
   CREATE TABLE #nextexec13  
   (  
    [campaignid]    BIGINT,  
    [nextexecution] DATETIME  
   );  
   WHILE @Count3 > 0  
   BEGIN  
    DECLARE @Campaignid3 BIGINT=(SELECT TOP 1 [campaignid] FROM #FindCampaignsNextExecution3);  
  
    INSERT INTO #nextexec13([campaignid], [nextexecution])  
    EXEC Usp_getnextscheduledate @Campaignid3;  
  
    DELETE FROM #FindCampaignsNextExecution3 WHERE [campaignid] = @Campaignid3;  
    SET @Count3=@Count3 - 1;  
   END;  
  
   UPDATE u SET [NextExecuteDateTime]=[nextexecution]  
   FROM [usercampaignmaster] [u] JOIN [#nextexec13] [n]  
   ON [n].[campaignid] = [u].[id]  
   WHERE [u].[ExpiryDate] > [nextexecution] OR [u].[ExpiryDate] IS NULL;  
  
   DROP TABLE IF EXISTS #nextexec13;  
   DROP TABLE IF EXISTS #FindCampaignsNextExecution3;  
  END;  
  
  --Code added to update nextexecutiondate in usercampaignhistory end--                                             
  DROP TABLE IF EXISTS #tempMobile3;  
  DROP TABLE IF EXISTS #tempTable;  
  DROP TABLE IF EXISTS #tempMobileVirtual;  
  DROP TABLE IF EXISTS #tempTableVirtual;  
  DROP TABLE IF EXISTS #Insufficientresellerbalance;  
  DROP TABLE IF EXISTS #TempTableRunningTotal3;  
  DROP TABLE IF EXISTS #TempTableRunningTotalVirtual;  
  DROP TABLE IF EXISTS #output;  
  DROP TABLE IF EXISTS #batch3;  
  DROP TABLE IF EXISTS #EmailsfiltercampaignexecutionTEST2;  
  DROP TABLE IF EXISTS #clonet;  
  DROP TABLE IF EXISTS #outputb;  
  
  IF EXISTS(SELECT 1 FROM UserCampaignHistory WHERE [JobId] = @jobId AND [IsEventBased]=0 AND [isSMS] = 0)  
  BEGIN  
   UPDATE usercampaignexecution SET [CampaignEnddatetime]=GETDATE(), [isrunning]=0  
   WHERE [isevent] = 0 AND [isSMS] = 0;  
   --select 'updated'                              
  END;  
  
 END;  
 ELSE  
 BEGIN  
  IF @campid IS NULL AND NOT EXISTS(SELECT 1 FROM UserCampaignExecution WHERE [issms] = 0 AND ISNULL([isevent], 0) = 0 AND [isrunning] = 0)  
  BEGIN  
   IF(SELECT [Lasterrorreported] FROM UserCampaignExecution WHERE [issms] = 0 AND ISNULL([isevent], 0) = 0) IS NULL  
     OR ( DATEDIFF(mi, (SELECT ISNULL([Lasterrorreported], DATEADD([mi], -6, GETDATE()))  
         FROM UserCampaignExecution(nolock)  
         WHERE [issms] = 0 AND ISNULL([isevent], 0) = 0), GETDATE()) > 5  
       AND DATEDIFF(mi, (SELECT ISNULL([CampaignExecutedDatetime], DATEADD([mi], -6, GETDATE()))  
          FROM UserCampaignExecution(nolock)  
          WHERE [issms] = 0 AND ISNULL([isevent], 0) = 0), GETDATE()) > 5 )  
   BEGIN  
    DECLARE @campaignstart DATETIME=(SELECT [CampaignExecutedDatetime] FROM UserCampaignExecution  
    WHERE [issms] = 0 AND ISNULL([isevent], 0) = 0), @lastjobid BIGINT=(SELECT ISNULL([cjobid], (SELECT TOP 1 [jobid] FROM [usercampaignhistory](NOLOCK) WHERE [issms] = 0 AND [iseventbased] = 0 AND [campaignid] <> 0 AND [jobid] <> @jobid ORDER BY [ID] DESC))  
     FROM usercampaignexecution  
     WHERE [issms] = 0 AND [isevent] = 0);  
    SELECT TOP 1 @campaignstart=[CreatedOn] FROM usercampaignhistory(NOLOCK) WHERE [jobid] =  
    @lastjobid;  
  
    DECLARE @step INT=(SELECT TOP 1 CASE WHEN [step2datetime] IS NULL THEN 2 ELSE 3 END  
           FROM usercampaignhistory(NOLOCK)  
           WHERE [jobid] = @lastjobid);  
    DECLARE @error NVARCHAR(200)='Last Campaign with jobid ' + CAST(@lastjobid AS VARCHAR(10)) +  
    ' failed at step ' + CAST(@step AS VARCHAR) + ' running since ' + CAST(@campaignstart AS NVARCHAR(20));  
    EXEC usp_InsertCampaignError 'Mail', 0, @error;  
  
    --if @step=2          
    --begin          
    --exec Usp_userexecutecampaignmessagesmailsnewCorrected_segregatemail_withid21102020 @lastjobid          
    --end          
    --else if @step=3          
    --begin          
    --exec Usp_insertclonedeliverycampaignmailsCorrected_segregatemail_withid21102020 @lastjobid          
    --end          
    UPDATE UserCampaignExecution SET [Lasterrorreported]=GETDATE() WHERE [issms] = 0  
                      AND ISNULL([isevent], 0)  
                      = 0;  
   END;  
  END;  
 END;  
  
END;  


GO

