			DECLARE @tbl_activity AS dbo.LeadActivitywithid_Tbltype;

			if exists (select 1 from EmailsfiltercampaignexecutionTEST2(NOLOCK) m WHERE [m].[entityname] ='Lead' AND ISNULL([m].[entityid], 0) <> 0
				  AND [m].[jobid] = @jobid AND [m].[CampaignID] = @c_id)
			begin
