				DECLARE @error NVARCHAR(200)='Last Campaign with jobid ' + CAST(@lastjobid AS VARCHAR(10)) +
				' failed at step ' + CAST(@step AS VARCHAR) + ' running since ' + CAST(@campaignstart AS NVARCHAR(20));
				EXEC usp_InsertCampaignError 'Mail', 0, @error;

				--if @step=2        
