          select Entityname,Contact_ID,Contact_Email,CampaignID,ParentID,userid from #temptablesearchContacts        
           INSERT INTO #temptablesearchexc(Entityname,Entityid,EmailID,CampaignID,ParentID,userid)          
          select Entityname,Contact_ID,Contact_Email,CampaignID,ParentID,userid from #temptablesearchExcContacts        
 */                                                                                                 
 SELECT Entityname,Entityid,A.EmailID, A.ParentID, A.CampaignID, A.userid, A.templateid INTO #tempemailid FROM    
 (     
 select distinct Entityname,Entityid,EmailID, ParentID, CampaignID,userid,TemplateID from    
 (SELECT Entityname,Entityid,Tt2.EmailID, Tt2.ParentID, Tt2.CampaignID, tt.Accountused as userid,tt.TemplateID     
 FROM #temptablesearchapp Tt2 join #temptemplate tt on tt.CampaignID=tt2.campaignid WHERE nullif(Tt2.EmailID,'') is not null     
 UNION     
 SELECT Entityname,Entityid,Tt2.EmailID1, Tt2.ParentID, Tt2.CampaignID,tt.Accountused as userid,tt.TemplateID FROM #temptablesearchapp Tt2 join #temptemplate tt on tt.CampaignID=tt2.campaignid     
 WHERE nullif(Tt2.EmailID1,'') is not null     
 UNION     
 SELECT Entityname,Entityid,Tt2.EmailID2,Tt2.ParentID,Tt2.CampaignID,tt.Accountused as userid,tt.TemplateID FROM #temptablesearchapp Tt2 join #temptemplate tt on tt.CampaignID=tt2.campaignid     
 WHERE nullif(Tt2.EmailID2,'') is not null     
 ) tt2 where NOT EXISTS     
 (SELECT 1 FROM #temptablesearchexc Tt Where (Tt2.CampaignID = Tt.CampaignID )     
 AND ( Tt2.EmailID = Tt.EmailID OR Tt2.EmailID = Tt.EmailID1 OR Tt2.EmailID = Tt.EmailID2 ))    
 ) A    
                             
SELECT ROW_NUMBER() Over(order by CampaignId,ParentId) Id,Ucerm.CampaignID,Ucerm.ParentID,ucerm.userID,Count(*) cnt    
INTO   #tempCount                                        
FROM   #tempemailid Ucerm where nullif(ucerm.EmailID,'') is not null Group by  Ucerm.CampaignID,Ucerm.ParentID ,Ucerm.UserID        
                                                          
SELECT A.UserID,a.CampaignID, a.cnt,SUM(b.cnt) RunningTotal     
into #TempTableRunningTotal        
FROM   #tempCount a join #tempCount b  on a.userid=b.userid WHERE b.CampaignID <= a.CampaignID GROUP BY A.UserID, a.CampaignID, a.cnt        
ORDER BY a.CampaignID;        
              
   --- Calculate credits                                        
SELECT B.UserID,B.CampaignID,CASE WHEN B.Balance >= B.Credits THEN 1 ELSE 0 END AS ValidEntries    
INTO   #tempMobile                                        
FROM       
(SELECT A.UserID,A.CampaignID,(A.Credits)   AS Credits,A.Balance FROM       
(SELECT Tt.UserID,TT.RunningTotal AS Credits,TT.CampaignID,dbo.fn_GetMailBalance(dbo.ufn_getuserparentid(tt.userid)) AS Balance                                        
FROM   #TempTableRunningTotal Tt) A  GROUP  BY A.UserID,A.Balance,A.CampaignID,A.credits) B      
                              
update u set u.ReasonIfNotRun='Insufficient Balance' from UserCampaignHistory u join #tempMobile t      
on u.campaignid=t.CampaignID and u.jobid=@jobid where t.validentries=0        
               
declare @validCampaigns1 int         
INSERT INTO Usercampaignexecutionhistory(CampaignID,Jobid,ExecutionTime,IsRecipients,ParentID)                                              
SELECT DISTINCT A.CampaignID,@JobId,GETDATE(),1,A.ParentID FROM (SELECT TT.ParentID,TT.CampaignID from #tempcount TT join #tempMobile tm on tm.CampaignID=tt.CampaignID        
where tm.ValidEntries=1) A           
select @validCampaigns1=@@ROWCOUNT    
    
 print concat('ValidCampaigns : ',@validCampaigns1, ', Time: ',getdate())    
    
    
INSERT INTO EmailsfiltercampaignexecutionTEST2 (Entityname,Entityid,Mail_ToEmail,Mail_InsertedDate,ParentID,CampaignID,Mail_UserID,JobId,templateid)        
select distinct Entityname,Entityid,A.EmailID,GETDATE() MID,A.ParentID,A.CampaignID,0 MUID,@Jobid,TemplateID                                                
FROM   
(SELECT Entityname,Entityid,CAST(Tt.EmailID COLLATE Latin1_general_ci_ai AS VARCHAR(500)) AS EmailID,Tt.ParentID,Tt.CampaignID ,@JobId Jobid,tt.TemplateID                                               
FROM   #tempemailid Tt  WHERE  Tt.EmailID <> '' and tt.EmailID is not null                                             
UNION                                              
SELECT 'Explicit',fs.position,CAST(Fs.[value] COLLATE Latin1_general_ci_ai AS VARCHAR(500)),tt.ParentID,tt.CampaignID,@JobId  Jobid,tt.TemplateID                                              
FROM   #temptemplate AS tt  (nolock)                                            
OUTER APPLY Dbo.Fn_split(tt.InclusionsNumber, ',') AS Fs  where  fs.value is not null  and fs.value<>''                                           
) A        
Inner join #tempMobile TM on TM.CampaignID = A.CampaignID WHERE  TM.ValidEntries = 1     
and CAST(A.EmailID COLLATE Latin1_general_ci_ai AS VARCHAR(500))     
NOT IN (SELECT CAST(ISNULL(Fs.[value], 'test') COLLATE Latin1_general_ci_ai AS VARCHAR(500))    
FROM   #temptemplate AS Ucm2  (nolock) OUTER APPLY Dbo.Fn_split(Ucm2.ExclusionsNumber, ',') AS Fs                                              
WHERE  Ucm2.ID = A.CampaignID  AND A.ParentID = Ucm2.ParentID)                              
                                   
    
UPDATE A  SET step1=1,step1datetime=getdate(),step1recipients = B.cnt FROM [dbo].UserCampaignHistory A INNER JOIN  #tempcount B                                 
ON A.[campaignid] = B.[campaignid] and A.Jobid = @JobId        
        
