+ Ucm.CampaignName + '" scheduled for '+ Cast(Getdate() AS VARCHAR(50)) + '. Pl refill your credit balance & rerun the campaign ' end,    
GETDATE(),335,335,'contactus@kit19.com',B.BatchId,1,GETDATE(),0,                                         
case when tm.validentries=1     
then 'Hold tight ! Your campaign "'+ Ucm.CampaignName + '" scheduled for ' + CAST(GETDATE() AS VARCHAR(50))                +                                              
