1,null,    
(select count(1) from #tempcount),'Internal Notification','T'    
FROM   #tempcount Tt                                              
INNER JOIN Usercampaignmaster AS Ucm  (nolock) ON  Ucm.ID = Tt.CampaignID                                              
AND Ucm.ParentID = Tt.ParentID AND Ucm.IsActive = 1         
inner join #tempMobile tm on tm.CampaignID=tt.CampaignID                                             
