begin        
if     
(select Lasterrorreported from UserCampaignExecution where issms=0 and isnull(isevent,0)=0) is null or     
(DATEDIFF(mi,(select isnull(Lasterrorreported,dateadd(mi,-6,getdate())) from UserCampaignExecution where issms=0 and isnull(isevent,0)=0),getdate()      
)>5  and DATEDIFF(mi,(select isnull(CampaignExecutedDatetime,dateadd(mi,-6,getdate())) from UserCampaignExecution where issms=0 and isnull(isevent,0)=0),getdate()      
)>5)       
begin        
  declare @campaignstart datetime =(select CampaignExecutedDatetime from UserCampaignExecution where issms=0 and isnull(isevent,0)=0),      
     @lastjobid bigint =(select isnull(cjobid,(select top 1 jobid from usercampaignhistory (nolock) where issms=0 and iseventbased=0 and campaignid<>0 and jobid<>@jobid order by ID desc))       
  from usercampaignexecution where issms=0 and isevent=0)      
   select top 1 @campaignstart = CreatedOn from usercampaignhistory(nolock) where jobid=@lastjobid      
           
  declare @step int = (select top 1 case when step2datetime is null then 2 else 3 end from usercampaignhistory (nolock) where jobid=@lastjobid)        
  declare @error nvarchar(200)='Last Campaign with jobid ' + cast(@lastjobid as varchar(10)) + ' failed at step ' + cast(@step as varchar) + ' running since ' + cast(@campaignstart as nvarchar(20))        
  exec usp_InsertCampaignError'Mail',0,@error      
        
  --if @step=2      
