  --end      
  --else if @step=3      
  --begin      
  --exec Usp_insertclonedeliverycampaignmailsCorrected_segregatemail_withid21102020 @lastjobid      
  --end      
        
   update UserCampaignExecution set Lasterrorreported=GETDATE() where issms=0 and isnull(isevent,0)=0        
  end        
  end        
        
END 


