CREATE   PROCEDURE [dbo].[Usp_automatedcampaigns_mails_ViaOtherDB] --9783  
@campid bigint=null        
AS                                              
BEGIN 
   Declare @BatchIDOut bigint
 DECLARE @Body VARCHAR(500),@campaignstartdate datetime=getdate()  ,@LastExecutedTime datetime =isnull((select Top 1 CampaignExecutedDatetime from UserCampaignExecution where issms=0 and isnull(isevent,0)=0 order by id desc),getdate())          
 DEclare @JobId Bigint = (Select ISNULL(MAX(JobId),0)+1 from UserCampaignHistory UCH )      
     
 INSERT INTO Usercampaignhistory(CampaignID,ParentID,Step1,Step2,Step3,IsSMS,IsMail,IsScheduled,IsEventBased,CreatedOn,JobId)                                
 SELECT 0,0,0,0,0,0,1,1,0,@campaignstartdate,@JobId      
 print concat('Campaign started with Jobid: ',@jobid, ', Campaignid: ',isnull(@campid,0),', Start time: ',getdate())    
     
 if @campid is not null or exists(select 1 from UserCampaignExecution where issms=0 and isnull(isevent,0)=0 and isrunning=0)        
 begin        
 if @campid is null       
 update UserCampaignExecution set isrunning=1,Cjobid=@Jobid where issms=0 and isnull(isevent,0)=0      
     
 Declare @CampaignStarttime datetime = Getdate()          
 Drop table if exists #temptemplate         
             
 SELECT ROW_NUMBER()Over(Order by Ucm.ID,Ucm.ParentID) AS Id,Ucm.ID AS CampaignID,Ucm.ParentID,A.[value]  AS Applicabilty,AGL.[value] AS ApplicabiltyGroupList,    
EGL.[value] AS ExclusionsGroupList,Ucm.NotificationMail,Ucm.ExclusionsNumber,E.[value] AS Exclusions,Ucm.InclusionsNumber,Ucm.AccountUsed,    
Ucm.SenderID,Ucm.[Message],Ucm.TemplateID,Ucm.TemplateGroupID,Ucm.IsUnicode                        
INTO #temptemplate                                                                       
FROM   Usercampaignmaster Ucm   (nolock)        
Inner join  User_detail AS Ud  on Ud.[User_ID]  = AccountUsed and Ud.[Status] <> 0                                                
join (select distinct user_id as parentaccount from User_detail AS Ud(nolock)    
join Price_UserSubscriptionDetails(nolock) p on p.UserID=ud.parentid and IsNewPlan=1 and cast(planenddate as date)>=cast(getdate() as date) and ud.status=1     
and ud.user_id=ud.ParentID) p on p.parentaccount=ucm.ParentID       
OUTER APPLY Dbo.Fn_split(Ucm.Applicabilty, '#') AS A         
OUTER APPLY Dbo.Fn_split(Ucm.ApplicabiltyGroupList, '#') AS AGL        
OUTER APPLY Dbo.Fn_split(Ucm.ExclusionsGroupList, '#') AS  EGL         
OUTER APPLY Dbo.Fn_split(Ucm.Exclusions, '#') AS E                                              
WHERE     
Ucm.MailReplyTo <> ''  and isscheduled=1      
AND ((Ucm.NextExecuteDateTime between @LastExecutedTime and GETDATE()     
AND DATEDIFF(Minute,getdate(),CASE WHEN Ucm.IsNeverExpire = 1 THEN DATEADD(DAY, 1,getdate()) ELSE ISNULL(Ucm.ExpiryDate, getdate())  END)> 0                                              
AND DATEDIFF(Minute, getdate(), ISNULL(Ucm.StartDate, getdate()))  <= 0                                              
AND Ucm.IsActive = 1 and nullif(ucm.eventid,0) is null and ucm.id=case when @campid is not null then @campid else ucm.id end)     
OR ucm.id=@campid)    
    
declare @campaignsfound int    
INSERT INTO Usercampaignhistory(CampaignID,ParentID,Step1,Step2,Step3,IsSMS,IsMail,IsScheduled,IsEventBased,CreatedOn,JobId)                                
SELECT DISTINCT CampaignID,ParentID,0,0,0,0,1,1,0,@campaignstartdate,@JobId FROM   #temptemplate           
select @campaignsfound=@@ROWCOUNT    
    
print concat('Campaigns found: ',@campaignsfound)    
--select * from #temptemplate      
