(SELECT Entityname,Entityid,CAST(Tt.EmailID COLLATE Latin1_general_ci_ai AS VARCHAR(500)) AS EmailID,Tt.ParentID,Tt.CampaignID ,@JobId Jobid,tt.TemplateID                                               
