SELECT distinct Ucm.ID,Ucm.ParentID,cast(Ucm.MailContent as nvarchar(max)),Ucm.MailSubject  ,getdate(),@Jobid ,null             
FROM   Usercampaignmaster Ucm  (nolock) INNER JOIN #EmailsfiltercampaignexecutionTEST2 AS Ucerm  (nolock)                           
ON ucm.ID=Ucerm.CampaignID WHERE  Ucerm.IsCompleted = 0 AND Ucm.MailReplyTo <> '' AND Ucm.MailContent <> ''     
union    
SELECT distinct Ucm.ID,Ucm.ParentID,umt.mailcontent,Umt.MailSubject,getdate(),@Jobid,ucm.TemplateID     
FROM   Usercampaignmaster Ucm  (nolock) join UserMailTemplate umt (nolock) on umt.ID=ucm.TemplateID       
INNER JOIN #EmailsfiltercampaignexecutionTEST2 AS Ucerm  (nolock) ON ucm.ID=Ucerm.CampaignID                                                
WHERE  Ucerm.IsCompleted = 0 AND Ucm.MailReplyTo <> '' and isnull(ucm.TemplateID,0)<>0 and umt.IsEnquiry=0 and umt.IsLeads=0 and umt.IsList=0 and umt.IsConversion=0    
 

      
select @e_c=count(1) from EmailsfiltercampaignexecutionTEST2 EC (nolock) join Usercampaignmaster Ucm  (nolock)       
on EC.CampaignId = Ucm.ID  WHERE  Ucm.MailReplyTo <> '' AND Ucm.MailContent <> ''  and jobid=@jobid and iscompleted=0       
and isnull(ucm.TemplateID,0)=0      
print concat('Step 2: composing static mail content, Total Records: ',@e_c,', Time: ',getdate())    
      
while @e_c>0      
begin      
UPDATE Kd SET Kd.Mail_FromEmail = isnull(ucm.FromMailId,'contactus@email19.in'), Kd.Mail_UserID = ucm.AccountUsed, Kd.ReplyTo = ucm.MailReplyTo,     
 Kd.Mail_Priority = 0, Kd.Mail_ScheduleDate = GETDATE(), Kd.Mail_Attechement = NULL, Kd.Mail_InsertedDate = GETDATE(), Kd.Mail_GUID = NEWID(),     
 Kd.IsCompleted = 1 , kd.ispersonalized=0     
 FROM     
(select top 500 * from EmailsfiltercampaignexecutionTEST2 EC (nolock) where jobid=@jobid and iscompleted=0 order by mail_id) kd                                          
join   Usercampaignmaster Ucm  (nolock)  ON ucm.ID=kd.CampaignID                                                                  
WHERE Ucm.MailReplyTo <> ''AND Ucm.MailContent <> '' and jobid=@jobid                                                           
select @b=@@ROWCOUNT      
set @e_c=@e_c-@b      
end          
    
print concat('Step 2: Completed composing static mail content, Total Records: ',@e_c,', Time: ',getdate())    
    
      
select @e_c=count(1) from Usercampaignmaster Ucm  (nolock)  join UserMailTemplate umt on umt.ID=ucm.TemplateID        
Join EmailsfiltercampaignexecutionTEST2 EC on EC.CampaignId = Ucm.ID WHERE  Ucm.MailReplyTo <> '' and isnull(ucm.TemplateID,0)<>0                                        
and ec.jobid=@jobid and ec.iscompleted=0 and umt.IsEnquiry=0 and umt.IsLeads=0 and umt.IsList=0 and umt.IsConversion=0       
print concat('Step 2: composing static template content, Total Records: ',@e_c,', Time: ',getdate())    
    
while @e_c>0      
begin      
UPDATE Kd  SET  Kd.Mail_FromEmail = isnull(ucm.FromMailId,'contactus@email19.in'),  Kd.Mail_UserID = ucm.AccountUsed,  Kd.ReplyTo = ucm.MailReplyTo,     
 Kd.Mail_Priority = 0,  Kd.Mail_ScheduleDate = GETDATE(),  Kd.Mail_Attechement = NULL,  Kd.Mail_InsertedDate = GETDATE(),  Kd.Mail_GUID = NEWID(),     
 Kd.IsCompleted = 1 ,  kd.ispersonalized=0,  kd.templateid=umt.id     
 FROM     
 (select top 500 * from EmailsfiltercampaignexecutionTEST2 EC (nolock) where jobid=@jobid and iscompleted=0 order by mail_id) kd     
join Usercampaignmaster Ucm  (nolock)   ON ucm.ID=kd.CampaignID                      
join UserMailTemplate umt (nolock) on umt.ID=ucm.TemplateID                                        
WHERE  Ucm.MailReplyTo <> '' and isnull(ucm.TemplateID,0)<>0 and umt.IsEnquiry=0 and umt.IsLeads=0 and umt.IsList=0 and umt.IsConversion=0      
      
select @b=@@ROWCOUNT      
set @e_c=@e_c-@b      
end          
print concat('Step 2: Completed composing static template content, Total Records: ',@e_c,', Time: ',getdate())    
      
select @e_c=count(1) from Usercampaignmaster Ucm  (nolock)  join UserMailTemplate umt on umt.ID=ucm.TemplateID        
Join EmailsfiltercampaignexecutionTEST2 EC on EC.CampaignId = Ucm.ID WHERE  Ucm.MailReplyTo <> '' and isnull(ucm.TemplateID,0)<>0                                        
and ec.jobid=@jobid and ec.iscompleted=0 and umt.IsEnquiry=1  --and ec.entityname='enquiry'      
print concat('Step 2: composing dynamic enquiry template content, Total Records: ',@e_c,', Time: ',getdate())    
    
    
while @e_c>0      
begin      
UPDATE Kd SET Kd.Mail_FromEmail = isnull(ucm.FromMailId,'contactus@email19.in'), Kd.Mail_Subject = case when kd.entityname='enquiry' then dbo.[fn_getEnquiryMessageMail_withid](Ucm.ParentID,Umt.mailsubject,kd.entityid) else umt.mailsubject end,     
 Kd.Messages = case when kd.entityname='enquiry' then (select CAST(dbo.build_mailContent(umt.id,kd.campaignid,kd.parentid, dbo.[fn_getEnquiryMessageMail_withid](Ucm.ParentID,Umt.MailContent,kd.entityid),kd.Mail_ToEmail)     
 AS NVARCHAR(MAX))) else umt.mailcontent end, Kd.Mail_UserID = ucm.AccountUsed, Kd.ReplyTo = ucm.MailReplyTo, Kd.Mail_Priority = 0, Kd.Mail_ScheduleDate = GETDATE(),     
 Kd.Mail_Attechement = NULL, Kd.Mail_TempleteBody = case when kd.entityname='enquiry' then (select CAST(dbo.build_mailContent(kd.templateid,kd.campaignid,kd.parentid,     
 dbo.[fn_getEnquiryMessageMail_withid](Ucm.ParentID,Umt.MailContent,kd.entityid),kd.Mail_ToEmail) AS NVARCHAR(MAX))) else umt.mailcontent end,     
 Kd.Mail_InsertedDate = GETDATE(), Kd.Mail_GUID = NEWID(), Kd.IsCompleted = 1 , kd.ispersonalized=1     
 FROM     
 (select top 500 * from EmailsfiltercampaignexecutionTEST2 EC (nolock) where jobid=@jobid and iscompleted=0 order by mail_id) kd     
join Usercampaignmaster Ucm (nolock) ON ucm.ID=kd.CampaignID     
join UserMailTemplate umt (nolock) on umt.ID=ucm.TemplateID     
--Left Join userenquiry ue(nolock) ON ue.parentid = Ucm.ParentID AND isnull(kd.entityid,0)=ue.EnquiryID and kd.entityname='Enquiry'     
WHERE Ucm.MailReplyTo <> '' and isnull(ucm.TemplateID,0)<>0 and umt.IsEnquiry=1     
      
select @b=@@ROWCOUNT      
set @e_c=@e_c-@b      
end       
print concat('Step 2: Completed composing dynamic enquiry template content, Total Records: ',@e_c,', Time: ',getdate())    
      
select @e_c=count(1) from Usercampaignmaster Ucm  (nolock)  join UserMailTemplate umt on umt.ID=ucm.TemplateID        
Join EmailsfiltercampaignexecutionTEST2 EC on EC.CampaignId = Ucm.ID WHERE  Ucm.MailReplyTo <> '' and isnull(ucm.TemplateID,0)<>0                                        
and ec.jobid=@jobid and ec.iscompleted=0 and (umt.IsLeads=1 or umt.IsConversion=1)        
print concat('Step 2: composing dynamic lead template content, Total Records: ',@e_c,', Time: ',getdate())    
    
while @e_c>0      
begin      
UPDATE Kd SET Kd.Mail_FromEmail = isnull(ucm.FromMailId,'contactus@email19.in'), Kd.Mail_Subject = case when kd.entityname='lead' then dbo.[fn_getLeadsMailMessage_withid](Ucm.ParentID,Umt.MailSubject,kd.entityid)     
 else umt.mailcontent end, Kd.Messages = case when kd.entityname='lead' then dbo.[fn_getLeadsMailMessage_withid](Ucm.ParentID,Umt.MailContent,kd.entityid) else umt.mailcontent end ,     
 Kd.Mail_UserID = ucm.AccountUsed, Kd.ReplyTo = ucm.MailReplyTo, Kd.Mail_Priority = 0, Kd.Mail_ScheduleDate = GETDATE(), Kd.Mail_Attechement = NULL,     
 Kd.Mail_TempleteBody = case when kd.entityname='lead' then dbo.[fn_getLeadsMailMessage_withid](Ucm.ParentID,Umt.MailContent,kd.entityid) else umt.mailcontent end ,     
 Kd.Mail_InsertedDate = GETDATE(), Kd.Mail_GUID = NEWID(), Kd.IsCompleted = 1 , kd.ispersonalized=1     
 FROM     
 (select top 500 * from EmailsfiltercampaignexecutionTEST2 EC (nolock) where jobid=@jobid and iscompleted=0 order by mail_id) kd     
join Usercampaignmaster Ucm  (nolock)   ON ucm.ID=kd.CampaignID                      
join UserMailTemplate umt (nolock) on umt.ID=ucm.TemplateID                                        
WHERE  Ucm.MailReplyTo <> '' and isnull(ucm.TemplateID,0)<>0 and (umt.IsLeads=1 or umt.IsConversion=1)    
      
select @b=@@ROWCOUNT      
set @e_c=@e_c-@b      
end          
print concat('Step 2: Completed composing dynamic lead template content, Total Records: ',@e_c,', Time: ',getdate())    
    

