SET @Count3 = @Count3 - 1                                
END                              
                             
update u set NextExecuteDateTime= nextexecution from usercampaignmaster u join #nextexec13 n on n.campaignid=u.id                              
where u.ExpiryDate > nextexecution or u.ExpiryDate is null                              
    drop table if exists #nextexec13                              
