/* ============================================================
   Procedure: [dbo].[usp_automationrulesapply_activity]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--select * from convusers(nolock) where channelprofileid='919667799101' and convuserparentid=34594        
--select top 10 * from convparentid where senderid=611573 order by id desc        
CREATE  PROCEDURE [dbo].[usp_automationrulesapply_activity] --4027910,'enquiry'--'917303508146','Not Interested',2,1495779     --'919667799101','interested',2,1463343                
@activityid bigint,                  
@entity nvarchar(20)                  
as                
begin 
DECLARE @SqlQuery NVARCHAR(MAX);
declare @parentid bigint,@entityid bigint,@sequenceid bigint,@eventid int ,@convuserid bigint        
if @entity='lead'        
begin        
select @parentid=parentid,@entityid=leadid,@eventid =eventid from mysms.dbo.tbl_leadeventhistory(nolock) where historyid=@activityid          
end        
if @entity='enquiry'        
begin        
select @parentid=parentid,@entityid=enquiryid,@eventid =eventid from mysms.dbo.tbl_enquiryeventhistory(nolock) where historyid=@activityid          
end        
--select top 1 @convuserid=id from MySMSConversations.dbo.convusers(nolock) where entity=@entity and entityid=@entityid and isactive=1      
--order by id desc   
SET @SqlQuery = '
    SELECT TOP 1 id 
    FROM convusers WITH (NOLOCK) 
    WHERE entity = ''' + @entity + ''' 
    AND entityid = ' + CAST(@entityid AS NVARCHAR) + ' 
    AND isactive = 1 
    ORDER BY id DESC
';

-- Execute the query remotely and assign value to @convuserid
EXEC usp_clr_GetRemoteLongValue @SqlQuery, @retval = @convuserid OUT;
    
print 'Entity: '+@entity+',entityid: '+cast(@entityid as nvarchar)   +', eventid: '+cast(@eventid as nvarchar)      
if exists (select 1 from mysms.dbo.Price_UserSubscriptionDetails(nolock) where IsNewPlan=1 and PlanEndDate>=getdate() and UserID=@parentid )        
and exists (select 1 from mysms.dbo.triggeredcampaigns(nolock) where eventid=@eventid and isactive=1 and parentid=@parentid and isnull(sequenceid,0)<>0)        
begin        
print 'Entity: '+@entity+',entityid: '+cast(@entityid as nvarchar)        
if exists (select 1 from mysms.dbo.triggeredcampaigns(nolock) where eventid=@eventid and isactive=1 and parentid=@parentid  and isnull(sequenceid,0)<>0)                  
begin                  
drop table if exists #rules                  
drop table if exists #ruleconditions                  
select * into #rules from mysms.dbo.triggeredcampaigns(nolock) 
where parentid=@parentid and isactive=1 and eventid=@eventid  and isnull(sequenceid,0)<>0                
declare @c int=(select count(1) from #rules),@ruleid int=0,@condition varchar(10),@match int=1,@rc int,@rcid int=0,@ctype varchar(50),@searchid bigint,@keyword                  
nvarchar(200),@matchtype nvarchar(20),@actiontype nvarchar(50),@actiondetails nvarchar(max),@status int ,@rulename nvarchar(100),@audience nvarchar(max)
,@strvalue nvarchar(max),@st int=0 
create table #ruleconditions(rcid int identity(1,1),searchid bigint,id bigint)        
if @c=0                
begin                
set @match=0                
end                
while @c>0                  
begin                  
select @match=1,@rcid=0        
select @ruleid=min(id) from #rules where id>@ruleid 

exec [usp_replaceplaceholders_withrules] @ruleid,null,@activityid,@entity,'',@eventid,@strvalue output,@st output
if @st=0
begin
set @match=0
print 'Triggered campaign id: '+cast(@ruleid as nvarchar)+ ', name: '+@rulename + ' does not match rule conditions of triggered campaign. Hence, no match'                
GOTO JUMPTOEND
end

select @sequenceid=sequenceid,@rulename=cname,@audience=Audience from #rules where id=@ruleid         
print 'Audience: '+@audience      
insert into #ruleconditions(searchid,id)        
select value,@ruleid from dbo.fn_split(@audience,'#')       
if exists (select 1 from  #ruleconditions)                 
begin                  
select @rc=count(1) from #ruleconditions where id=@ruleid        
select @rcid=0         
if @rc=0                
begin                
set @match=0                
print 'Triggered campaign id: '+cast(@ruleid as nvarchar)+ ', name: '+@rulename + ' has no audience. Hence, no match'                
end         
print 'Triggered campaign id: '+cast(@ruleid as nvarchar)+ ',name: '+@rulename + ' Audience to match: '+cast(@rc as nvarchar)                
print '@rc : '+ cast(@rc as nvarchar)+ ', @match: '+ cast(@match as nvarchar)           
while @rc>0                  
begin                  
select @rcid=min(rcid) from #ruleconditions where rcid>@rcid and id=@ruleid                 
select @searchid=searchid,@ctype='user' from #ruleconditions where rcId=@rcid                  
if 1=1--@ctype='User'                  
begin
exec mysms.dbo.Usp_ContactExistsInSearch @entity,@entityid,@searchid,@Status output       
print 'Status: '+cast(@status as nvarchar)      
select @match=case when @status=1 then 1  else  0 end                  
print 'Rule condition '+@ctype + '. Condition user belongs to searchid ' +cast(@searchid as nvarchar)+       
case when @match=0 then ' does not match'  else ' matches' end                
end                  
select @rc=case when @match=1 then 0 else @rc-1 end                   
end                  
end              
print 'Triggered campaign id: '+cast(@ruleid as nvarchar)+ ',name: '+@rulename +case when @match=0 then ' does not match' else ' matches      
 and will run sequence with sequenceid : '+ @actiondetails end                
      
if @match=1                
begin 

/*insert into mysmsconversations.dbo.tbl_wa_automationtasks(ruleid,sequenceid,sequenceactionid,actiontype,actiondetails,parentid,activityid,triggeredcampaignid        
,scheduledfor,twa_entity,twa_entityid,convuserid)                  
select @ruleid,@sequenceid,sequenceactionid,actiontype,actiondetails,@parentid,@activityid,@ruleid      
,mysmsconversations.dbo.fn_getnextschedule(sequenceactionid),@entity,@entityid,@convuserid      
      
from mysmsconversations.dbo.tbl_WA_SequenceActionMaster (nolock) where sequenceid=@sequenceid and IsActive = 1 and IsDeleted = 0  */
SET @SqlQuery = '
    INSERT INTO tbl_wa_automationtasks
    (ruleid, sequenceid, sequenceactionid, actiontype, actiondetails, parentid, activityid, triggeredcampaignid,
     scheduledfor, twa_entity, twa_entityid, convuserid)
    SELECT ' + CAST(@ruleid AS NVARCHAR) + ',
           ' + CAST(@sequenceid AS NVARCHAR) + ',
           sequenceactionid,
           actiontype,
           actiondetails,
           ' + CAST(@parentid AS NVARCHAR) + ',
           ' + CAST(@activityid AS NVARCHAR) + ',
           ' + CAST(@ruleid AS NVARCHAR) + ',
           fn_getnextschedule(sequenceactionid),
           ''' + @entity + ''',
           ' + CAST(@entityid AS NVARCHAR) + ',
           ' + CAST(@convuserid AS NVARCHAR) + '
    FROM tbl_WA_SequenceActionMaster WITH (NOLOCK)
    WHERE sequenceid = ' + CAST(@sequenceid AS NVARCHAR) + ' AND IsActive = 1 AND IsDeleted = 0
';

-- Execute the insert remotely
EXEC usp_clr_ExecuteRemoteQuery @SqlQuery;
end 
JUMPTOEND:
truncate table #ruleconditions        
select @c=@c-1             
end                  
        
end                        
end        
end                  
              


