    AND actiondetails LIKE ''%#%#%''   
    AND SequenceActionId > ' + CAST(@actionid AS NVARCHAR);  
  
-- Execute dynamic SQL and store result in @actionid  
EXEC usp_clr_GetRemoteLongValue   
    @sqlquery,   
    @retval = @actionid OUT;  
  
select @ad=actiondetails from [10.0.0.135].mysmsconversations.dbo.tbl_WA_SequenceActionMaster with (nolock) where sequenceid=@sequenceid and IsActive = 1 and IsDeleted = 0 and actiontype='webhook' and actiondetails like '%#%#%' and SequenceActionId=@actio
nid  
