select top 1 @entity_mobile=mobileno from #entity_mobile e where not exists (select 1 from mysmsconversations.dbo.convusers(nolock) where convuserparentid=@parentid and ( isactive=1 or (Entityid = @entityid and Entity = @entity and isactive=0) )  and 
channelid=2 and channelprofileid =e.mobileno)    
