@parentid and isactive=1 and channelid=2    and channelprofileid in (select mobileno from #entity_mobile) and (Entityid<>@entityid or @entity<>@entity)    if @oldEntityName='lead'   select @o_leadno=leadno from userleads(nolock) where id=@oldEntityId     
print concat('Reassociate entity. ','Old entityname: ',@oldEntityName,', Oldentityid: ',@oldEntityId,', Entitymobile: ',   @entity_mobile, ', New entity: ',@entity,', New entityid: ',@entityid )   if(@oldEntityName = 'enquiry' and @entity = 'lead')  begin   
   exec MySMSConversations.dbo.usp_ims_AssociateDeissociateWrapper    @oldEntityName, @oldEntityId, 'whatsapp', @entity, @entityid, @entity_mobile, '{}', @parentid    select top 1 @convuserid=id from MySMSConversations.dbo.convusers(nolock) where entity=
   @entity and entityid=@entityid and isactive=1      
order by id desc                
    end  
 else  
 begin  
 select @errormessage=isnull(@errormessage+' ','')+ 'Mobile no. '+@entity_mobile+' is associated with another entity, that is '+@oldentityname +case when @oldEntityName='lead' then ', lead no. '+cast(@o_leadno as nvarchar) else '' end+'. Whatsapp template
 in the sequence  (if any) will not run'    
 end  
 end  
else if isnull(@convuserid,0)=0  
--if isnull(@convuserid,0)=0 and     
--exists (select 1 from mysmsconversations.dbo.convusers(nolock) where convuserparentid=@parentid and isactive=1 and channelid=2    
--and channelprofileid in (select mobileno from #entity_mobile) and (Entityid<>@entityid or @entity<>@entity))      
begin    
    
select @errormessage=isnull(@errormessage+' ','')+ 'Mobile no. is not associated with this entity. Whatsapp template in the sequence (if any) will not run'    
end    
    
print 'Entity: '+@entity+',entityid: '+cast(@entityid as nvarchar)   +', eventid: '+cast(@eventid as nvarchar)                
    
if not exists (select 1 from mysms.dbo.Price_UserSubscriptionDetails(nolock) where IsNewPlan=1 and cast(PlanEndDate as date)>=cast(getdate() as date) and UserID=@parentid )                  
