and actiondetails like '%#%#%')
begin
declare @webhook_c int=(select count(1) from mysmsconversations.dbo.tbl_WA_SequenceActionMaster (nolock) where sequenceid=@sequenceid and IsActive = 1 and IsDeleted = 0 and actiontype='webhook' and actiondetails like '%#%#%'),@replaced_ad nvarchar(max),@ad nvarchar(max),@actionid bigint=0
while @webhook_c>0
begin
select @actionid=min(sequenceactionid) from mysmsconversations.dbo.tbl_WA_SequenceActionMaster (nolock) where sequenceid=@sequenceid and IsActive = 1 and IsDeleted = 0 and actiontype='webhook' and actiondetails like '%#%#%' and SequenceActionId>@actionid
select @ad=actiondetails from mysmsconversations.dbo.tbl_WA_SequenceActionMaster (nolock) where sequenceid=@sequenceid and IsActive = 1 and IsDeleted = 0 and actiontype='webhook' and actiondetails like '%#%#%' and SequenceActionId=@actionid
exec mysms.dbo.[usp_replaceplaceholders] @activityid ,@entity ,@ad ,@eventid ,@replaced_ad OUTPUT
insert into #webhook_replace(actionid,actiondetails)
select @actionid,@replaced_ad
set @webhook_c=@webhook_c-1
end
end


  
