 DECLARE @current_dt DATETIME,    
 @from DATETIME, @to DATETIME    
 ,@from1 DATETIME;    
    
 SELECT @current_dt = GETDATE();    
 SELECT     
   @from = DATEADD(MINUTE, -60, @current_dt)    
  ,@to = DATEADD(MINUTE, -10, @current_dt)    
  ,@from1 = DATEADD(HOUR, -1, @current_dt);    
    
 DROP TABLE IF EXISTS #t;    
 DROP TABLE IF EXISTS #automation    
    
 select s.ID INTO #t from scheduledtodos s with (nolock)     
 where    
  s.createdon between @from1 and @current_dt;    
    
 select top 10 s.*into #automation from scheduledtodos s WITH (nolock)     
 INNER JOIN #t t ON t.id = s.id    
 where-- id=21636402      
 (s.isnotified=0 or (s.isnotified=2 and datediff(mi,s.processedat,@current_dt) between 10 and 240))          
 and s.scheduledaction='AutomationRules' and s.createdon between @from1 and @current_dt order by s.id;    
    
 /*DROP TABLE IF EXISTS #temp1;    
       
   CREATE TABLE #temp1 (id BIGINT, Channelid int, Entity nvarchar(200), Entityid bigint, channelprofileid nvarchar(500),isactive bit ,createdon datetime, profilejson nvarchar(500), lastmodifiedon datetime, convuserparentid bigint,lastactivitytype nvarchar
  
(100) ,lastactivitytext nvarchar(max),lastactivityid bigint,    
 lastactivityby bigint ,astactivitydate datetime,lastactivitydirection nvarchar(5),unreadconversations int ,    
 isdeactivatedon datetime,SnoozedDateTime datetime,is_blocked bit,country_iso nvarchar(5),wa_chatexpiry datetime,wa_chargesexpiry datetime);    
    
 SET @query = '    
        SELECT id , Channelid , Entity , Entityid , channelprofileid ,isactive  ,createdon , profilejson , lastmodifiedon , convuserparentid ,lastactivitytype  ,lastactivitytext ,lastactivityid ,    
