 isdeactivatedon ,SnoozedDateTime ,is_blocked ,country_iso ,wa_chatexpiry ,wa_chargesexpiry )    
 EXEC usp_clr_FillRemoteData @query;*/    
    
    
     
/*    
select top 100 * into #automation from scheduledtodos(nolock) where-- id=21636402      
(isnotified=0 or (isnotified=2 and datediff(mi,processedat,getdate()) between 10 and 60))          
and scheduledaction='AutomationRules' and createdon between dateadd(HH,-1,getdate()) and getdate() order by id            
 */         
update s set isnotified=2,processedat=getdate() from scheduledtodos s join #automation a on a.id=s.id          
    
--insert into debug_automation_null_message(s_id,isnotified,s_errormessage)    
--select id,2,null from #automation    
    
          
declare @sid bigint=0,@a_count int,@activityid bigint,@entity nvarchar(20),@parentid bigint,@entityid bigint,@sequenceid bigint,        
@eventid int ,@convuserid bigint,@errormessage nvarchar(2000),@tgname nvarchar(200),@entity_mobile nvarchar(20) ,@n_taskid bigint=0 ,@std_entityid bigint      
        
drop table if exists #entity_mobile        
create table #entity_mobile(id int identity(1,1),mobileno nvarchar(20))        
                      
select @a_count=count(1) from #automation            
            
while @a_count>0            
begin          
begin try          
select @sid=min(id),@activityid=0,@entity='',@parentid=0,@entityid=0,@eventid=0,@convuserid=0,@sequenceid=0,@errormessage=null,@entity_mobile=null,      
@n_taskid=0    
from #automation where id>@sid            
truncate table #entity_mobile        
select @activityid=activityid,@std_entityid=std_entity_id,@parentid=parentid  ,@entity=(select context from activitymaster(nolock) where id=eventid),@eventid=eventid    
from #automation where id=@sid     
 
if not exists (select 1 from mysms.dbo.Price_UserSubscriptionDetails(nolock) where IsNewPlan=1 and cast(PlanEndDate as date)>=cast(getdate() as date) and UserID=@parentid )                      
or not exists (select 1 from mysms.dbo.triggeredcampaigns(nolock) where eventid=@eventid and isactive=1 and parentid=@parentid         
and isnull(sequenceid,0)<>0)        
begin        
select @errormessage= isnull(@errormessage+' ','')+case when not exists (select 1 from mysms.dbo.Price_UserSubscriptionDetails(nolock) where IsNewPlan=1 and cast(PlanEndDate as date)>=cast(getdate() as date) and UserID=@parentid )                      
then 'Parent does not have an active subscription' else 'No active sequence in triggered campaign for this activity' end        
GOTO JUMPTOEND              
        
end        
 

if dbo.[fn_getentityactivitycount_opt](@entity,@std_entityid,@eventid,'AutomationRules',null)>99    
begin    
set @errormessage='Max day limit for the execution of this sequence for given entity has reached.'    
--select @ter=left(isnull(nullif(s_errormessage,''),'')+' '+isnull(@errormessage,'No error'),3000) from mysms.dbo.scheduledtodos where id=@sid      
update mysms.dbo.scheduledtodos set isnotified=1,processedat=getdate(),s_errormessage=left(isnull(nullif(s_errormessage,''),'')+' '+isnull(@errormessage,'No error'),3000) where id=@sid      
--update debug_automation_null_message set isnotified=1,s_errormessage=@ter where s_id=@sid    
--insert into debug_automation_null_message(isnotified,s_errormessage,s_id)    
--select 1,@ter,@sid    
end    
else    
begin    
    
    
    
if @entity='lead'                      
begin                      
select @parentid=parentid,@entityid=leadid,@eventid =eventid from mysms.dbo.tbl_leadeventhistory(nolock) where historyid=@activityid         
insert into #entity_mobile(mobileno)        
select dbo.fngetnumericvalue(coalesce(countrycode,(select countrycode from User_Detail(nolock) where user_id=@parentid),'')+mobile)        
from Userleads_Mobile_Email(nolock) where ulme_id=@entityid and mobile<>'0' order by 1        
delete from #entity_mobile where len(mobileno)<7        
end                      
if @entity='enquiry'                      
begin                      
select @parentid=parentid,@entityid=enquiryid,@eventid =eventid from mysms.dbo.tbl_enquiryeventhistory(nolock) where historyid=@activityid          
insert into #entity_mobile(mobileno)        
select dbo.fngetnumericvalue(coalesce(countrycode,(select countrycode from User_Detail(nolock) where user_id=@parentid),'')+mobile)        
from Userenquiry_Mobile_Email(nolock) where enquiryid=@entityid and mobile<>'0' order by 1        
delete from #entity_mobile where len(mobileno)<7        
end              
if @entity is null        
begin        
set @errormessage='Lead/Enquiry does not exist for this activity'        
GOTO JUMPTOEND              
        
end        
        
select top 1 @convuserid=id from [10.0.0.135].MySMSConversations.dbo.convusers with (nolock) where entity=@entity and entityid=@entityid and isactive=1          
order by id desc     
    
print concat('Convuserid: ',@convuserid)      
    
drop table if exists #tempconvusers    
create table #tempconvusers(channelprofileid nvarchar(1000))    
    
insert into #tempconvusers(channelprofileid)    
SELECT channelprofileid FROM [10.0.0.135].MySMSConversations.dbo.convusers WITH (NOLOCK) WHERE convuserparentid = @parentid AND channelid = 2 AND     
(isactive = 1 OR (Entityid = @entityid AND Entity = @entity AND isactive = 0) )    
    
    SELECT @MobileCount=COUNT(*)     
    FROM #entity_mobile em     
    WHERE em.mobileno NOT IN (    
        SELECT channelprofileid     
        FROM #tempconvusers WITH (NOLOCK)     
          )    
    
    
IF ISNULL(@convuserid, 0) = 0 AND ISNULL(@MobileCount, 0) > 0    
begin        
select top 1 @entity_mobile=mobileno from #entity_mobile e where not exists (select 1 from [10.0.0.135].mysmsconversations.dbo.convusers with (nolock) where convuserparentid=@parentid and ( isactive=1 or   
(Entityid = @entityid and Entity = @entity and   
isactive=0) )  and     
channelid=2 and channelprofileid =e.mobileno)     
    
print 'insert into convusers'        
exec [10.0.0.135].MySMSConversations.dbo.[usp_ims_InsertConversationUser] 'Whatsapp',@entity,@entityid,@entity_mobile,1,'',@parentid    
select top 1 @convuserid=id from [10.0.0.135].MySMSConversations.dbo.convusers with (nolock) where entity=@entity and entityid=@entityid and isactive=1          
order by id desc    
    
end       
    
else if isnull(@convuserid,0)=0 and         
exists (select 1 from [10.0.0.135].MysmsConversations.dbo.convusers with (nolock) where convuserparentid=@parentid and isactive=1 and channelid=2        
and channelprofileid in (select mobileno from #entity_mobile) and (Entityid<>@entityid or @entity<>@entity))        
    
begin      
declare @oldEntityName nvarchar(25), @oldEntityId bigint,@o_leadno bigint      
    
select top 1 @oldEntityName = Entity, @oldEntityId = Entityid,@entity_mobile=channelprofileid from  [10.0.0.135].MysmsConversations.dbo.convusers    where convuserparentid=    
@parentid and isactive=1 and channelid=2    and channelprofileid in (select mobileno from #entity_mobile) and (Entityid<>@entityid or @entity<>@entity)       
if @oldEntityName='lead'   select @o_leadno=leadno from userleads(nolock) where id=@oldEntityId         
    
print concat('Reassociate entity. ','Old entityname: ',@oldEntityName,', Oldentityid: ',@oldEntityId,', Entitymobile: ',   @entity_mobile, ', New entity: ',@entity,', New entityid: ',@entityid )   if(@oldEntityName = 'enquiry' and @entity = 'lead')     
begin       
     
 exec [10.0.0.135].MySMSConversations.dbo.usp_ims_AssociateDeissociateWrapper    @oldEntityName, @oldEntityId, 'whatsapp', @entity, @entityid, @entity_mobile, '{}', @parentid     
 select top 1 @convuserid=id from [10.0.0.135].MySMSConversations.dbo.convusers with (nolock) where entity=   @entity and entityid=@entityid and isactive=1          
order by id desc       

end      
 else      
 begin      
 select @errormessage=isnull(@errormessage+' ','')+ 'Mobile no. '+@entity_mobile+' is associated with another entity, that is '+@oldentityname +case when @oldEntityName='lead' then ', lead no. '+cast(@o_leadno as nvarchar) else '' end+'. Whatsapp template in the sequence  (if any) will not run'        
 end      
 end      
else if isnull(@convuserid,0)=0      
--if isnull(@convuserid,0)=0 and         
--exists (select 1 from mysmsconversations.dbo.convusers(nolock) where convuserparentid=@parentid and isactive=1 and channelid=2        
--and channelprofileid in (select mobileno from #entity_mobile) and (Entityid<>@entityid or @entity<>@entity))          
begin        
        
select @errormessage=isnull(@errormessage+' ','')+ 'Mobile no. is not associated with this entity. Whatsapp template in the sequence (if any) will not run'        
end        
        
print 'Entity: '+@entity+',entityid: '+cast(@entityid as nvarchar)   +', eventid: '+cast(@eventid as nvarchar)                    
        
        
        
if exists (select 1 from mysms.dbo.Price_UserSubscriptionDetails(nolock) where IsNewPlan=1 and cast(PlanEndDate as date)>=cast(getdate() as date) and UserID=@parentid )                      
and exists (select 1 from mysms.dbo.triggeredcampaigns(nolock) where eventid=@eventid and isactive=1 and parentid=@parentid         
and isnull(sequenceid,0)<>0)   and @entity is not null                   
begin                      
print 'Entity: '+@entity+',entityid: '+cast(@entityid as nvarchar)                      
if exists (select 1 from mysms.dbo.triggeredcampaigns(nolock) where eventid=@eventid and isactive=1 and parentid=@parentid  and isnull(sequenceid,0)<>0)                                
begin                                
drop table if exists #rules                                
drop table if exists #ruleconditions                                
select * into #rules from mysms.dbo.triggeredcampaigns(nolock)              
where parentid=@parentid and isactive=1 and eventid=@eventid  and isnull(sequenceid,0)<>0           
        
declare @c int=(select count(1) from #rules),@ruleid int=0,@condition varchar(10)='',@match int=1,@rc int=0,@rcid int=0,@ctype varchar(50)='',@searchid bigint=0,@keyword                                
nvarchar(200)='',@matchtype nvarchar(20)='',@actiontype nvarchar(50)='',@actiondetails nvarchar(max)='',@status int=0 ,@rulename nvarchar(100)='',@audience nvarchar(max)=''              
,@strvalue nvarchar(max)='',@st int=0               
create table #ruleconditions(rcid int identity(1,1),searchid bigint,id bigint)                      
if @c=0                              
begin                              
set @match=0                              
end                              
while @c>0                                
begin                                
select @match=1,@rcid=0                      
select @ruleid=min(id) from #rules where id>@ruleid               
select @tgname=cname from #rules where id=@ruleid        
              
exec [usp_replaceplaceholders_withrules] @ruleid,null,@activityid,@entity,'',@eventid,@strvalue output,@st output              
if @st=0              
begin              
set @match=0              
print 'Triggered campaign id: '+cast(@ruleid as nvarchar)+ ', name: '+@rulename + ' does not match rule conditions of triggered campaign. Hence, no match'                              
set @errormessage=isnull(@errormessage+' ','')+'Triggered Campaign '+@tgname+' does not pass the rules. '        
GOTO JUMPTOEND              
end              
              
select @sequenceid=sequenceid,@rulename=cname,@audience=Audience from #rules where id=@ruleid                       
print 'Audience: '+@audience                    
insert into #ruleconditions(searchid,id)                   
select value,@ruleid from dbo.fn_split(@audience,'#')                     
if exists (select 1 from  #ruleconditions)                               
begin                                
select @rc=count(1) from #ruleconditions where id=@ruleid                      
select @rcid=0                       
if @rc=0                              
begin                              
set @match=0                              
print 'Triggered campaign id: '+cast(@ruleid as nvarchar)+ ', name: '+@rulename + ' has no audience. Hence, no match'         
set @errormessage=isnull(@errormessage+' ','')+'Triggered Campaign '+@tgname+' failed as it has no active audience. '        
        
end                       
print 'Triggered campaign id: '+cast(@ruleid as nvarchar)+ ',name: '+@rulename + ' Audience to match: '+cast(@rc as nvarchar)                              
print '@rc : '+ cast(@rc as nvarchar)+ ', @match: '+ cast(@match as nvarchar)                         
while @rc>0                                
begin                                
select @rcid=min(rcid) from #ruleconditions where rcid>@rcid and id=@ruleid                               
select @searchid=searchid,@ctype='user' from #ruleconditions where rcId=@rcid                                
if 1=1--@ctype='User'                                
begin                          
exec mysms.dbo.Usp_ContactExistsInSearch @entity,@entityid,@searchid,@Status output                     
print 'Status: '+cast(@status as nvarchar)       
select @match=case when @status=1 then 1  else  0 end                                
print 'Rule condition '+@ctype + '. Condition user belongs to searchid ' +cast(@searchid as nvarchar)+                     
case when @match=0 then ' does not match'  else ' matches' end                              
end                                
select @rc=case when @match=1 then 0 else @rc-1 end                                 
end                                
end                            
print 'Triggered campaign id: '+cast(@ruleid as nvarchar)+ ',name: '+@rulename +case when @match=0 then ' does not match' else ' matches                    
 and will run sequence with sequenceid : '+ cast(@sequenceid as nvarchar) end                              
if @match=0        
begin        
set @errormessage=isnull(@errormessage+' ','')+'Triggered Campaign '+@tgname+' audience does not include the Lead/Enquiry. '        
end        
                    
if @match=1                              
begin                           
begin try      
--select @ruleid,@sequenceid,sequenceactionid,actiontype,actiondetails,@parentid,@activityid,@ruleid                    
--,isnull(mysmsconversations.dbo.fn_getnextschedule(sequenceactionid),getdate()),@entity,@entityid,@convuserid                    
    
--from mysmsconversations.dbo.tbl_WA_SequenceActionMaster (nolock) where sequenceid=@sequenceid and IsActive = 1 and IsDeleted = 0        
    
drop table if exists #webhook_replace    
create table #webhook_replace(actionid bigint,actiondetails nvarchar(max))    
    
if exists (select 1 from [10.0.0.135].MySMSConversations.dbo.tbl_WA_SequenceActionMaster with (nolock) where sequenceid=@sequenceid and IsActive = 1 and IsDeleted = 0 and actiontype='webhook'    
and actiondetails like '%#%#%')    
/*    
SET @SqlQuery = '    
    SELECT cast(1 as bigint)    
    FROM tbl_WA_SequenceActionMaster WITH (NOLOCK)    
    WHERE sequenceid = ' + CAST(@sequenceid AS NVARCHAR) + '    
      AND IsActive = 1     
      AND IsDeleted = 0     
      AND actiontype = ''webhook''    
      AND actiondetails LIKE ''%#%#%''';    
    
-- Then use with a CLR call    
DECLARE @exists bigint;    
EXEC usp_clr_GetRemoteLongValue @SqlQuery, @retval = @exists OUT;    
IF @exists >0    
*/    
begin    
declare @webhook_c int=(select count(1) from [10.0.0.135].mysmsconversations.dbo.tbl_WA_SequenceActionMaster with (nolock) where sequenceid=@sequenceid and IsActive = 1 and IsDeleted = 0 and actiontype='webhook' and actiondetails like '%#%#%'),  
@replaced_ad nvarchar(max),@ad nvarchar(max),@actionid bigint=0    
    
/*    
DECLARE     
    @webhook_c INT,    
    @replaced_ad NVARCHAR(MAX),    
    @ad NVARCHAR(MAX),    
    @actionid BIGINT = 0    
       
    
-- Construct the SQL query dynamically    
SET @sqlquery = '    
    SELECT COUNT(1)     
    FROM tbl_WA_SequenceActionMaster WITH (NOLOCK)     
    WHERE sequenceid = ' + CAST(@sequenceid AS NVARCHAR) + '     
    AND IsActive = 1     
    AND IsDeleted = 0     
    AND actiontype = ''webhook''     
    AND actiondetails LIKE ''%#%#%''';    
    
-- Execute the dynamic SQL via CLR    
EXEC usp_clr_GetRemoteIntValue     
    @sqlquery,     
    @retval = @webhook_c OUT;    
*/    
    
while @webhook_c>0    
begin    
select @actionid=min(sequenceactionid) from [10.0.0.135].mysmsconversations.dbo.tbl_WA_SequenceActionMaster with (nolock) where sequenceid=@sequenceid and IsActive = 1 and IsDeleted = 0 and actiontype='webhook' and actiondetails like '%#%#%'   
and SequenceActionId>@actionid    
/*    
SET @sqlquery = '    
    SELECT MIN(sequenceactionid)     
    FROM tbl_WA_SequenceActionMaster WITH (NOLOCK)     
    WHERE sequenceid = ' + CAST(@sequenceid AS NVARCHAR) + '     
    AND IsActive = 1     
    AND IsDeleted = 0     
    AND actiontype = ''webhook''     
    AND actiondetails LIKE ''%#%#%''     
    AND SequenceActionId > ' + CAST(@actionid AS NVARCHAR);    
    
-- Execute dynamic SQL and store result in @actionid    
EXEC usp_clr_GetRemoteLongValue     
    @sqlquery,     
 @retval = @actionid OUT;    
*/    
select @ad=actiondetails from [10.0.0.135].mysmsconversations.dbo.tbl_WA_SequenceActionMaster with (nolock) where sequenceid=@sequenceid and IsActive = 1 and IsDeleted = 0 and actiontype='webhook'   
and actiondetails like '%#%#%' and SequenceActionId=@actionid    
/*SET @sqlquery = '    
    SELECT actiondetails     
    FROM tbl_WA_SequenceActionMaster WITH (NOLOCK)    
    WHERE sequenceid = ' + CAST(@sequenceid AS NVARCHAR) + '    
    AND IsActive = 1     
    AND IsDeleted = 0     
    AND actiontype = ''webhook''    
    AND actiondetails LIKE ''%#%#%''     
    AND SequenceActionId = ' + CAST(@actionid AS NVARCHAR);    
    
-- Execute and store result    
EXEC usp_clr_GetRemoteStringValue     
    @sqlquery,     
    @retval = @ad OUT;*/    
exec mysms.dbo.[usp_replaceplaceholders] @activityid ,@entity ,@ad ,@eventid ,@replaced_ad OUTPUT    
insert into #webhook_replace(actionid,actiondetails)    
select @actionid,@replaced_ad    
set @webhook_c=@webhook_c-1    
end    
end    
    
    
      
insert into [10.0.0.135].mysmsconversations.dbo.tbl_wa_automationtasks(ruleid,sequenceid,sequenceactionid,actiontype,actiondetails,parentid,activityid,triggeredcampaignid    
,scheduledfor,twa_entity,twa_entityid,convuserid,isprocessed)                                
select @ruleid,@sequenceid,sequenceactionid,actiontype,isnull(r.actiondetails,t.ActionDetails),@parentid,@activityid,@ruleid                    
,isnull(dbo.fn_getnextschedule(sequenceactionid),getdate()),@entity,@entityid,@convuserid,0                    
from [10.0.0.135].mysmsconversations.dbo.tbl_WA_SequenceActionMaster as t with (nolock) left join #webhook_replace r on t.SequenceActionId=r.actionid where sequenceid=@sequenceid and IsActive = 1 and IsDeleted = 0        
select @n_taskid=scope_identity()     
    
print concat ('scheduledtodoid: ',@sid,'taskid: ',@n_taskid)      
if @n_taskid>1      
begin      
set @errormessage=isnull(@errormessage+' ','')+'Triggered Campaign '+@tgname+' is queued for Sequence execution. '        
end      
else       
begin      
set @errormessage=isnull(@errormessage+' ','')+'Triggered Campaign '+@tgname+' was queued for Sequence execution but sequence does not include any valid action. '        
      
end      
 end try      
 begin catch      
 exec usp_inserterrorinfo      
 -- select ERROR_NUMBER=ERROR_NUMBER(),ERROR_SEVERITY= ERROR_SEVERITY(),ERROR_STATE=ERROR_STATE(),ERROR_PROCEDURE=ERROR_PROCEDURE(),ERROR_LINE=ERROR_LINE(),ERROR_MESSAGE=ERROR_MESSAGE(),'Section-A'    
 end catch      
end               
JUMPTOEND:           
if OBJECT_ID('tempdb..#ruleconditions') is not null                                        
begin                                        
truncate table #ruleconditions          
end      
    
    
select @c=@c-1                           
end                                
                      
end                                      
end     
begin try    
--select @ter=left(isnull(nullif(s_errormessage,''),'')+' '+isnull(@errormessage,'No error'),3000) from mysms.dbo.scheduledtodos where id=@sid      
update scheduledtodos set isnotified=1,processedat=getdate(),s_errormessage=left(isnull(nullif(s_errormessage,''),'')+' '+isnull(@errormessage,'No error') ,3000)    
where id=@sid    
--update debug_automation_null_message set isnotified=1,s_errormessage=@ter where s_id=@sid    
    
--insert into debug_automation_null_message(isnotified,s_errormessage,s_id)    
--select 1,@ter,@sid    
end try          
begin catch          
exec usp_inserterrorinfo          
--  select ERROR_NUMBER=ERROR_NUMBER(),ERROR_SEVERITY= ERROR_SEVERITY(),ERROR_STATE=ERROR_STATE(),ERROR_PROCEDURE=ERROR_PROCEDURE(),ERROR_LINE=ERROR_LINE(),ERROR_MESSAGE=ERROR_MESSAGE(),'Section-B'    
    
end catch    
    
end    
set @a_count=@a_count-1            
print concat('Final errormessage: ', @errormessage)        
end try          
begin catch          
exec usp_inserterrorinfo          
 -- select ERROR_NUMBER=ERROR_NUMBER(),ERROR_SEVERITY= ERROR_SEVERITY(),ERROR_STATE=ERROR_STATE(),ERROR_PROCEDURE=ERROR_PROCEDURE(),ERROR_LINE=ERROR_LINE(),ERROR_MESSAGE=ERROR_MESSAGE(), 'section-C'    
    
end catch          
      
end            
drop table if exists #automation      
end try    
begin catch    
exec usp_InsertErrorInfo    
  --select ERROR_NUMBER=ERROR_NUMBER(),ERROR_SEVERITY= ERROR_SEVERITY(),ERROR_STATE=ERROR_STATE(),ERROR_PROCEDURE=ERROR_PROCEDURE(),ERROR_LINE=ERROR_LINE(),ERROR_MESSAGE=ERROR_MESSAGE(),'Section-D'    
    
end catch    
    
    
end                                


GO

