--select * from convusers(nolock) where channelprofileid='919667799101' and convuserparentid=34594                        
--select top 10 * from convparentid where senderid=611573 order by id desc                        
CREATE  PROCEDURE [dbo].[usp_automationrulesapply_activity_execute_withoutclr1] --4027910,'enquiry'--'917303508146','Not Interested',2,1495779     --'919667799101','interested',2,1463343                                
as                                
begin                         
begin try       
 declare @ter nvarchar(3000)      
 DECLARE @SqlQuery NVARCHAR(MAX),@query nvarchar(max),@sql nvarchar(max);      
 DECLARE @MobileCount BIGINT;      
 DECLARE @current_dt DATETIME,      
 @from DATETIME, @to DATETIME      
 ,@from1 DATETIME;      
      
 SELECT @current_dt = GETDATE();      
 SELECT       
   @from = DATEADD(MINUTE, -60, @current_dt)      
  ,@to = DATEADD(MINUTE, -10, @current_dt)      
  ,@from1 = DATEADD(HOUR, -1, @current_dt);      
      
 DROP TABLE IF EXISTS #t;      
 DROP TABLE IF EXISTS #automation      
      
 select s.ID INTO #t from scheduledtodos s with (nolock)       
 where      
  s.createdon between @from1 and @current_dt;      
      
 select top 100 s.*into #automation from scheduledtodos s WITH (nolock)       
 INNER JOIN #t t ON t.id = s.id      
 where-- id=21636402        
 (s.isnotified=0 or (s.isnotified=2 and datediff(mi,s.processedat,@current_dt) between 10 and 240))            
 and s.scheduledaction='AutomationRules' and s.createdon between @from1 and @current_dt 
 --and s.parentid<>47325 --and s.eventid<>144
  order by s.id;      
      
