select parentid,eventid,@activityid,getdate(),reftables,refids,0,'',getdate(),1,'AutomationRules','enquiry',enquiryid from tbl_enquiryeventhistory l with (nolock) where historyid=@activityid   and exists
(select 1 from triggeredcampaigns t with (nolock) where t.eventid=l.EventID and t.parentid=l.parentid and isactive=1 and issequenceactive=1 and sequenceid is not null)
end  
end  
                  
