   Procedure: [dbo].[usp_automationrulesapply_activity_insert_multi_wo_max]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--sp_helptext usp_automationrulesapply_activity 4027783            
            
--select * from convusers(nolock) where channelprofileid='919667799101' and convuserparentid=34594              
--select top 10 * from convparentid where senderid=611573 order by id desc              
CREATE   PROCEDURE [dbo].[usp_automationrulesapply_activity_insert_multi_wo_max]     
 @multiactivity as multiactivity readonly    
as                      
begin    
declare @entity nvarchar(20)=(select top 1 context from @multiactivity)  
if @entity='lead'    
begin    
insert into scheduledtodos(parentid,eventid,activityid,createdon,reftable,refid,isnotified,refcolumn,scheduledfor,isvalid,scheduledaction)    
select parentid,eventid,activityid,getdate(),reftables,refids,0,'',getdate(),1,'AutomationRules' from   
tbl_leadeventhistory(nolock) t join @multiactivity m on m.activityid=t.historyid  
end    
if @entity='enquiry'    
begin    
