 @APIHeader nvarchar(500) = null,      
 @Maildate datetime,      
 @Delivereddate datetime,    
 @UserId bigint = null,    
 @BatchId bigint = null    
)      
as      
begin   
begin try     
declare @id bigint,@mailsource nvarchar(50)
 insert into maildeliveries( Notificationid, FromMail, ToMail, APIHeader, Maildate, Delivereddate, createdon, batchid, user_id )      
  values( @Notificationid, @FromMail, @ToMail, @APIHeader, @Maildate, @Delivereddate, getdate(), @BatchId, @UserId)  
