  if @mailsource='InternalCRM'
  begin
  declare @et datetime=getdate()
    exec usp_insertcrmenagagementactivity @batchid,@tomail,'mail','Delivered','maildeliveries',@id,@et
  end
  end try  
  begin catch  
  exec usp_InsertErrorInfo  
  end catch  
end 


