/* ============================================================
   Procedure: [dbo].[usp_aws_updateCurrentmaildeliveryreport]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[usp_aws_updateCurrentmaildeliveryreport]           
as          
begin          
update c set status='Delivered',sentfinaldatetime=m.delivereddate from maildeliveries m join clientemails c on c.batchid=m.batchid and c.guid=m.apiheader
and sentfinaldatetime is null and m.reportupdated=0
update c set status='Bounced- '+m.bouncetype+'- '+m.bouncesubtype,sentfinaldatetime=m.createdon from mailbounces m join clientemails c on c.batchid=m.batchid 
and c.guid=m.apiheader and sentfinaldatetime is null and m.reportupdated=0

update m set reportupdated=1 from maildeliveries m join clientemails c on c.batchid=m.batchid and c.guid=m.apiheader
and sentfinaldatetime is not null and m.reportupdated=0 
update m set reportupdated=1 from mailbounces m join clientemails c on c.batchid=m.batchid and c.guid=m.apiheader
and sentfinaldatetime is not null and m.reportupdated=0
end 




GO

/* ============================================================
   Procedure: [dbo].[usp_balrequired]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_balrequired
(@tbl wa_recipients readonly)
as
begin
declare @currentbal decimal(18,4),@parentid bigint,@balrequired decimal(18,4)
select top 1 @parentid=parentid from @tbl
select top 1 @currentbal=balance from IntCredit_Details(nolock) where User_ID=@parentid order by Credit_ID desc
select u.id,countryid,cw.pfee_bi_inr,cw.price_in_eur_bi,r.rate
into #tbl
from @tbl u join m_country1(nolock) m on ltrim(rtrim(replace(countrycode,'+','')))
=left(u.waid,len(ltrim(rtrim(replace(countrycode,'+','')))))
join [country_wapricing] cw on cw.countryid=m.Country_ID
join (select top 1 * from [currencyrates] order by createdon desc) r
on 1=1
select @balrequired=sum(round(ceiling(price_in_eur_bi*rate),2)+pfee_bi_inr) from #tbl

select @currentbal as CurrentBalance,@balrequired as RequiredBalance,case when @balrequired>@currentbal
then 0 else 1 end as HasSufficientBalance 
end



GO

/* ============================================================
   Procedure: [dbo].[usp_balrequired_single]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_balrequired_single](
    @parentid bigint,
    @waid nvarchar(50)
)    
as    
begin  

    -- declare @parentid bigint = 32222, @waid nvarchar(50) = '919821592374'   
    DECLARE @sqlquery NVARCHAR(MAX);
    declare @currentbal decimal(18,4), @balrequired decimal(18,4) = 0, @u_pcid int
    
    declare @sender bigint, @recipient bigint, @iswindowopen int   

    -- select top 1 @currentbal = balance from IntCredit_Details(nolock) 
    --     where User_ID = @parentid order by Credit_ID desc 

    set @currentbal = dbo.GetAvailableBalanceForService(@parentid, 11)

    
    --select @recipient = id from mysmsconversations.dbo.convusers(nolock) 
    --    where channelprofileid = @waid and convuserparentid = @parentid  and isactive = 1
	  SET @sqlquery = '
      SELECT id
      FROM convusers WITH (NOLOCK)
      WHERE channelprofileid = ''' + CAST(@waid AS NVARCHAR) + '''
        AND convuserparentid = ' + CAST(@parentid AS NVARCHAR) + '
        AND isactive = 1;
      ';
      
      -- Execute dynamic SQL query
      EXEC usp_clr_GetRemoteLongValue @sqlquery, @retval = @recipient OUT;
      
    select top 1 @balrequired = cw.marketing + 0.10 from m_country1(nolock) m     
        join tbl_wa_countryWpricing cw(nolock) on cw.countryid = m.Country_ID
    where ltrim(rtrim(replace(countrycode, '+', ''))) = left(@waid, len(ltrim(rtrim(replace(countrycode, '+', '')))))  
        and cw.Currency = 'INR'

    if @balrequired = 0
    BEGIN
        select @balrequired = max(marketing) from tbl_wa_countryWpricing(nolock) where currency = 'INR'
    END

    select 
        @currentbal as CurrentBalance, 
        @balrequired as RequiredBalance, 
        case when @balrequired > @currentbal then 0 else 1 end as HasSufficientBalance     
end


GO

/* ============================================================
   Procedure: [dbo].[Usp_Batchupdate]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--*******************************************
-- Purpose : This Sp Check Invalid schedeledtime set in batchinfo and update it. 
--           It resolve the problem of BatchUnprocess.
--           Created By : Abhishek kr. Jaiswal
--           Created Date : 15.09.2010
--******************************************** 
CREATE   PROC [dbo].[Usp_Batchupdate]  
AS  
Begin  
Declare @shdate varchar(20)  
Declare @newshdate varchar(20)  
Declare @batchid bigint  
select top 1 @batchid=batchid,@shdate=scheduledDate from batchinfo where scheduledDate<>'' and isprocess is null and scheduledtime like '%00:00%'
 if @batchid is not null
Begin 
select @batchid,@shdate
set @newshdate=substring(@shdate,1,10)+' 01:00'+' '+substring(@shdate,len(@shdate)-1,2)  
select rtrim(@newshdate)  
update batchinfo set scheduledDate=@newshdate,scheduledtime=@newshdate where batchid=@batchid  
End
End  


GO

