   Procedure: [dbo].[USP_Bind_Credit_Detail]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[USP_Bind_Credit_Detail]-- '',''
	@FROMDATE nvarchar(15),
	@TODATE nvarchar(15)
AS
BEGIN
SET NOCOUNT ON;
IF @FROMDATE=''
SET @FROMDATE='01/01/1900'
IF @TODATE=''
SET @TODATE=1
IF (@FROMDATE='01/01/1900')
BEGIN
SELECT  [ID],[Total],[Promo],[Trans],[TRC],[Open],CONVERT(VARCHAR(15),[CREATEDDATE],106)AS CREATEDDATE From [MySMS].[dbo].[daily_credit_status]Order by convert(nvarchar,CONVERT(DATETIME,[CREATEDDATE],104),112) desc
END
ELSE
	BEGIN
	SELECT  [ID],[Total],[Promo],[Trans],[TRC],[Open],CONVERT(VARCHAR(15),[CREATEDDATE],106)AS CREATEDDATE From [MySMS].[dbo].[daily_credit_status] where convert(nvarchar,CONVERT(DATETIME,[CREATEDDATE],104),112) BETWEEN convert(nvarchar,CONVERT(DATETIME,@FROMDATE,104),112) AND 
convert(nvarchar,CONVERT(DATETIME,@TODATE,104),112) Order by convert(nvarchar,CONVERT(DATETIME,[CREATEDDATE],104),112) desc
	END
END



