/* ============================================================
   Procedure: [dbo].[Usp_BindPremiumMessageByUId]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--================================    
-- That SP get Premium Message by UserId and SenderId    
    
    
CREATE   PROC Usp_BindPremiumMessageByUId --0,'',2,20    
( @U_id Int,    
@senderid varchar(20),    
@pageindex INT,                                                    
@pagesize INT=20         
)    
AS    
Begin    
Declare @Sql VARCHAR(8000)      
if @U_id = 0    
Begin    
Set @Sql='Select Messageid,Mobile,Message,U_Id,SenderId,case(Priority) when ''0'' then ''Normal'' else ''Priority'' end as Priority from PremiumMessage with(nolock)'    
End    
else    
Begin    
set @Sql='Select Messageid,Mobile,Message,U_Id,SenderId,case(Priority) when ''0'' then ''Normal'' else ''Priority'' end as Priority from PremiumMessage with(nolock) where U_id='+Convert(varchar,@U_id,5)+' and Senderid='''+@senderId+''''    
print(@Sql)    
End    
DECLARE @temptable table                                          
(                                          
   ID INT identity(1,1),                                      
   MessageID BIGINT,                                      
   Mobile char(20),                                      
   Message VARCHAR(2500),     
   U_ID INT,                                     
   SENDerID VARCHAR(50),                                     
      Priority VARCHAR(10)                 
  )                    
                                    
insert into  @temptable(MessageID,Mobile,Message,U_ID,SENDerID,Priority) EXEC(@Sql)     
select count(mobile) FROM @temptable     
    
SELECT  ID,Messageid,Mobile,Message,U_Id,senderId,Priority FROM @temptable                                                       
  WHERE ID between ((@pageIndex-1)*@PageSize+1) AND (@pageIndex*@PageSize) order by Id Asc       
End 


GO

