/* ============================================================
   Procedure: [dbo].[USP_bindSenderId_UserID_Monitor_Mail]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

      
CREATE   PROCEDURE  [dbo].[USP_bindSenderId_UserID_Monitor_Mail]                           
AS            
BEGIN            
           
 --SELECT DISTINCT  ReplyTo  FROM  MailMonitor(NOLOCK)  ORDER BY ReplyTo            
 --SELECT ud.User_login, ud.user_id as userid FROM  MailMonitor MM(nolock)          
 --INNER JOIN [User_Detail] ud(NOLOCK) on MM.u_id=ud.user_id          
 -- GROUP BY ud.User_login,ud.user_id ORDER BY ud.User_login          
    
  /*      
 SELECT DISTINCT  ReplyTo Senderid  FROM  EmailsFilter(NOLOCK) WHERE ISNULL(IsMonitor,0)=0 ORDER BY ReplyTo            
                    
 SELECT ud.User_login, ud.user_id as userid FROM  EmailsFilter EF(nolock)          
 INNER JOIN [User_Detail] ud(NOLOCK) on  EF.Mail_UserID=ud.user_id        
 WHERE ISNULL(IsMonitor,0)=0       
 GROUP BY ud.User_login,ud.user_id ORDER BY ud.User_login          
    */     
  
SELECT DISTINCT  b.ReplyTo Senderid  FROM  batchemail_infos(NOLOCK) b join EmailsFilter EF(NOLOCK) 
on b.BatchID=ef.Mail_BatchID 
 WHERE ISNULL(bmonitor,0)=0 ORDER BY b.ReplyTo            
                    
 SELECT ud.User_login, ud.user_id as userid FROM  EmailsFilter EF(nolock)          
 INNER JOIN [User_Detail] ud(NOLOCK) on  EF.Mail_UserID=ud.user_id        
 join BatchEmail_Infos(nolock) b on b.BatchID=ef.Mail_BatchID  
 WHERE ISNULL(bmonitor,0)=0       
 GROUP BY ud.User_login,ud.user_id ORDER BY ud.User_login          
  
           
END       
      


GO

