/* ============================================================
   Procedure: [dbo].[usp_BM_GetRCSBMReport]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_BM_GetRCSBMReport](  
 @UserId bigint,  
 @FromDate nvarchar(50),  
 @ToDate nvarchar(50),  
 @BroadcastName nvarchar(50) = '',  
 @Offset int = 0,   
 @PageSize int = 100  
)  
as  
begin  
 --declare   
 -- @UserId bigint = 41584,  
 -- @FromDate nvarchar(50) = N'12 Oct 2023',  
 -- @ToDate nvarchar(50) = N'19 Oct 2023',  
 -- @BroadcastName nvarchar(50) = '',  
 -- @Offset int = 0,   
 -- @PageSize int = 100  
  
  
 declare @ParentId bigint = 0;  
 select @ParentId = ParentID from dbo.User_Detail(nolock) where User_Id = @UserId  
  
 declare @startPos int = (@Offset + 1), @endPos int = (@Offset + @PageSize )  
  
  
 declare @reportQuery nvarchar(max)
  
 set @reportQuery = concat( N'drop table if exists #tempReport ',  
 'SELECT rNo, TotalRow, RowID, BroadcastName, TotalMobileNo, SuccessMobileNo, CreatedDate into #tempReport  
 from ( select ROW_NUMBER() over( order by RowID desc) as rNo, ',  
  N'count(1) over( ) as TotalRow, RowID, BroadcastName, TotalMobileNo, SuccessMobileNo, CreatedDate ',  
  N'from Tbl_BM_JsonUpload(nolock) 
  where cast(CreatedDate as date) between cast(''', @FromDate, ''' as date) and cast(''', @ToDate, ''' as date)  and ParentId = ' + cast(@ParentId as nvarchar),  
 N' and isnull(GoogleResult, '''') <> '''')t select * from #tempReport WHERE rNo between ', @startPos, ' and ', @endPos, ' order by rNo asc')  
  
  
 --set @reportQuery = @reportQuery1 + @reportQuery2  
  
 print @reportQuery
 --print @reportQuery2  
  
 execute sp_executesql @reportQuery  
  
  
  
end 




GO

/* ============================================================
   Procedure: [dbo].[usp_BM_GetRCSBMReportDetail]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE dbo.usp_BM_GetRCSBMReportDetail
(
	@Id bigint,
	@Mode nvarchar(100),
	@Offset int = 0,   
	@PageSize int = 100
)
as
begin
	declare @tblTempRCSReport table
	(
		rNo int identity(1,1),
		TotalRow int,
		BroadcastId bigint,
		BroadcastName nvarchar(100),
		MobileNo nvarchar(100),
		[Status] nvarchar(100),
		FailureReason nvarchar(100)
	)

	declare @startPos int = (@Offset + 1), @endPos int = (@Offset + @PageSize )
	declare @broadcastName nvarchar(100)

	declare @totalMobileNo nvarchar(max)
	declare @successMobileNo nvarchar(max)

	DECLARE @Counter INT 
	SET @Counter=1

	declare @MaxId int

	select @totalMobileNo = TotalMobileNo, @broadcastName = BroadcastName, @successMobileNo = SuccessMobileNo
	from Tbl_BM_JsonUpload where RowID = @Id

	if(@Mode = 'total')
	begin
		insert into @tblTempRCSReport
		select 0, @Id, @broadcastName, item, '', ''
		from fu_SplitString(@totalMobileNo, ',')

		select @MaxId = max(rNo) from @tblTempRCSReport

		while(@Counter <= @MaxId)
		begin
			--select @Counter
			declare @SingleMobileNo nvarchar(100)
			select @SingleMobileNo = MobileNo from @tblTempRCSReport where rNo = @Counter
			if @successMobileNo like '%'+ @SingleMobileNo +'%'
			begin
				update @tblTempRCSReport
				set Status = 'Success'
				where rNo = @Counter
			end
			else
			begin
				update @tblTempRCSReport
				set Status = 'Failed', FailureReason = 'RCS not registered on given mobile number'
				where rNo = @Counter
			end

			SET @Counter  = @Counter  + 1
		end

		update @tblTempRCSReport
		set TotalRow = @MaxId
	end

	if(@Mode = 'success')
	begin
		if(@successMobileNo != '')
		begin
			insert into @tblTempRCSReport
			select 0, @Id, @broadcastName, item, 'Success', ''
			from fu_SplitString(@successMobileNo, ',')

			select @MaxId = max(rNo) from @tblTempRCSReport

			update @tblTempRCSReport
			set TotalRow = @MaxId
		end
	end

	if(@Mode = 'fail')
	begin
		declare @totalTbl table
		(
			Id int identity(1,1),
			MobileNo nvarchar(100)
		)

		declare @successTbl table
		(
			Id int identity(1,1),
			MobileNo nvarchar(100)
		)

		insert into @totalTbl
		select item
		from fu_SplitString(@totalMobileNo, ',')

		insert into @successTbl
		select item
		from fu_SplitString(@successMobileNo, ',')

		--select * from @totalTbl
		--select * from @successTbl
		select @MaxId = max(Id) from @totalTbl
		
		declare @MaxId1 int
		select @MaxId1 = max(Id) from @successTbl

		declare @Counter1 int
		set @Counter1 = 1
		set @Counter = 1

		while(@Counter <= @MaxId)
		begin
			declare @singleMobNo1 nvarchar(100)
			select @singleMobNo1 = MobileNo from @totalTbl where Id = @Counter

			declare @isExists bit
			set @isExists = 0

			while(@Counter1 <= @MaxId1)
			begin
				declare @singleMobNo2 nvarchar(100)
				select @singleMobNo2 = MobileNo from @successTbl where Id = @Counter

				if(@singleMobNo1 = @singleMobNo2)
				begin
					set @isExists = 1

					break
				end

				set @Counter1 = @Counter1 +1
			end

			if(@isExists = 0)
			begin
				insert into @tblTempRCSReport
				select 0, @Id, @broadcastName, @singleMobNo1, 'Failed', 'RCS not registered on given mobile number'
			end

			set @Counter = @Counter + 1
		end

		select @MaxId = max(rNo) from @tblTempRCSReport

		update @tblTempRCSReport
		set TotalRow = @MaxId
	end

	select * from @tblTempRCSReport WHERE rNo between @startPos and @endPos order by rNo asc
end




