/* ============================================================
   Procedure: [dbo].[usp_bn_BannerList]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_bn_BannerList](
	@UserId bigint,
	@FilterText nvarchar(255) = null,
	--@Status nvarchar(255)=null,
	--@FromDate datetime,
	--@ToDate datetime,
	@OffsetValue int = 0,
	@PagingSize int = 20
)
as
begin

	--declare 
	--	@UserId bigint = 34594,
	--	@UserIds nvarchar(max) = N'',
	--	@FilterText nvarchar(255) = null,
	--	@OffsetValue int = 0,
	--	@PagingSize int = 20
	
	declare @ParentId bigint = 0, @StartPoint int = 0, @EndPoint int = 0;

	set @StartPoint = @OffsetValue + 1
	set @EndPoint = @OffsetValue + @PagingSize

	SELECT @parentid = ParentID FROM Mysms.dbo.User_Detail(NOLOCK)
	WHERE User_ID = @UserId;

		; with banner as
		( select  
				ROW_NUMBER() over (partition by bn.ParentId order by bn.CreatedDate desc) as [SNo],Id, Contents,BannerBackground,DismissOption, BannerType , ParentId, BannerName,UserId,CreatedDate,CreatedBy,LastModifiedDate,IsActive
				from tbl_Banner_Details bn
				where UserId=@UserId and isnull(IsDelated,0)=0
				 AND (ISNULL(@FilterText, '') = '' OR bn.BannerName LIKE '%' + @FilterText + '%')

		)
		select  SNo,(select count(1) from banner) as [TotalRow], Id, Contents,BannerBackground,DismissOption, BannerType , ParentId, BannerName,UserId,CreatedDate,CreatedBy,LastModifiedDate,IsActive from banner where banner.SNo between @StartPoint and @EndPoint
		
end




