/* ============================================================
   Procedure: [dbo].[usp_bot_SaveWebhookMapping]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_bot_SaveWebhookMapping]
(
    @Mode NVARCHAR(50) = 'save',
    @UserId BIGINT,
    @mapping_id BIGINT = NULL,
    @webhook_id BIGINT = NULL,
    @bot_type NVARCHAR(50) = NULL,
    @bot_id BIGINT = NULL,
    @webhook_slug NVARCHAR(200) = NULL,
    @llm_parameters NVARCHAR(MAX) = NULL,
    @is_enabled BIT = 1,
    @trigger_type NVARCHAR(50) = NULL,
    @trigger_config NVARCHAR(MAX) = NULL,
    @response_mode NVARCHAR(50) = NULL,
    @prompt_template NVARCHAR(MAX) = NULL,
    @filler_while_waiting NVARCHAR(MAX) = NULL,
    @on_error_strategy NVARCHAR(50) = NULL,
    @on_error_fallback_message NVARCHAR(MAX) = NULL,
    @confirmation_required BIT = 0
)
AS
BEGIN
    SET NOCOUNT ON;

 

    DECLARE @Action NVARCHAR(50);

 

    BEGIN TRY
        BEGIN TRANSACTION;


   
        IF LOWER(@Mode) = 'save'
         
        BEGIN

            IF LOWER(ISNULL(@bot_type,'')) = 'voice'
            BEGIN
                UPDATE voice_bot_details
                SET use_webhooks = 1
                WHERE id = @bot_id;
            END

            IF @mapping_id IS NOT NULL AND EXISTS (SELECT 1 FROM bot_webhook_mapping WHERE mapping_id = @mapping_id)
            BEGIN
                
                UPDATE bot_webhook_mapping
                SET webhook_id = COALESCE(@webhook_id, webhook_id),
                    bot_type = COALESCE(@bot_type, bot_type),
                    bot_id = COALESCE(@bot_id, bot_id),
                    webhook_slug = COALESCE(@webhook_slug, webhook_slug),
                    llm_parameters = COALESCE(@llm_parameters, llm_parameters),
                    is_enabled = COALESCE(@is_enabled, is_enabled),
                    trigger_type = COALESCE(@trigger_type, trigger_type),
                    trigger_config = COALESCE(@trigger_config, trigger_config),
                    response_mode = COALESCE(@response_mode, response_mode),
                    prompt_template = COALESCE(@prompt_template, prompt_template),
                    filler_while_waiting = COALESCE(@filler_while_waiting, filler_while_waiting),
                    on_error_strategy = COALESCE(@on_error_strategy, on_error_strategy),
                    on_error_fallback_message = COALESCE(@on_error_fallback_message, on_error_fallback_message),
                    confirmation_required = COALESCE(@confirmation_required, confirmation_required),
                    updated_by = CAST(@UserId AS NVARCHAR(100)),
                    updated_on = GETDATE(),
                    version = ISNULL(version, 1) + 1
                WHERE mapping_id = @mapping_id;

 

                SET @Action = 'update';
            END
            ELSE
            BEGIN
                INSERT INTO bot_webhook_mapping
                (
                    webhook_id, bot_type, bot_id, webhook_slug,
                    llm_parameters, is_enabled, trigger_type, trigger_config,
                    response_mode, prompt_template, filler_while_waiting,
                    on_error_strategy, on_error_fallback_message,
                    confirmation_required, created_by, created_on, version
                )
                VALUES
                (
                    @webhook_id, @bot_type, @bot_id, @webhook_slug,
                    @llm_parameters, ISNULL(@is_enabled,1), @trigger_type, @trigger_config,
                    @response_mode, @prompt_template, @filler_while_waiting,
                    @on_error_strategy, @on_error_fallback_message,
                    ISNULL(@confirmation_required,0), CAST(@UserId AS NVARCHAR(100)), GETDATE(), 1
                );

 

                SET @mapping_id = SCOPE_IDENTITY();
                SET @Action = 'insert';
            END
        END
        ELSE IF LOWER(@Mode) = 'delete'
        BEGIN
            UPDATE bot_webhook_mapping
            SET deleted_on = GETDATE(),
                updated_by = CAST(@UserId AS NVARCHAR(100))
            WHERE mapping_id = @mapping_id;

 

            SET @Action = 'delete';
        END

 

        COMMIT;

 

        SELECT @mapping_id AS MappingId, @Action AS Action;

 

    END TRY
    BEGIN CATCH
        IF @@TRANCOUNT > 0 ROLLBACK;
        THROW;
    END CATCH
END





GO

