IF (@SOURCETABLENAME <> 'MessageDeliveryStatus')                  
   BEGIN               
SET @DELETEQUERY='DELETE '+@SOURCETABLENAME+'  FROM '+@SOURCETABLENAME+' SRC RIGHT OUTER JOIN #TEMPTABLE  ON SRC.MessageID=#TEMPTABLE.MessageID AND SRC.Mobile=#TEMPTABLE.Mobile '                
EXEC(@DELETEQUERY)             
