   BEGIN            
        SET  @QUERY='SELECT TOP '+@ROW+' MessageID,Mobile,Message,SenderID,SmppID,MessageInsertDate,case Priority when 1 then ''Priority'' when 0 then ''Normal'' when 2 then ''Direct'' end as Priority,            
    U_ID,IsUniCode,IsDND,Operator,BatchID FROM [smsstorage].[storage].dbo.'+@TABLENAME+' (nolock) WHERE '+@whereClause+''            
   END        
   ELSE IF(@TABLENAME = 'MessageDeliveryStatusTemp')      
   BEGIN      
    SET  @QUERY='SELECT TOP '+@ROW+' MessageID,Mobile,Message,SenderID,SmppID,MessageInsertDate,case Priority when 1 then ''Priority'' when 0 then ''Normal'' when 2 then ''Direct'' end as Priority,            
    U_ID,IsUniCode,BatchID FROM [smsstorage].[storage].dbo.'+@TABLENAME+' WHERE '+@whereClause+''            
   END       
 ELSE IF(@TABLENAME = 'MessageQueueDelhi')      
   BEGIN      
    SET  @QUERY='SELECT TOP '+@ROW+' MessageID,Mobile,Message,SenderID,SmppID,MessageInsertDate,case Priority when 1 then ''Priority'' when 0 then ''Normal'' when 2 then ''Direct'' end as Priority,            
    U_ID,0,BatchID FROM [Server2].[DelhiFilterDb].dbo.MessageQueueFour WHERE '+@whereClause+''            
   END  
--ADD THE SELECTION OF PROCESS TABLE    
  ELSE IF((@TABLENAME = 'ProcessTableFirst') OR (@TABLENAME = 'ProcessTableTwo') OR (@TABLENAME = 'ProcessTableThree')  OR (@TABLENAME = 'ProcessTableFour'))    
   BEGIN    
   SET  @QUERY='SELECT TOP '+@ROW+' MessageID,Mobile,Message,SenderID,SmppID,MessageInsertDate,''N/A'' as Priority,            
   U_ID,IsUniCode,IsDND,Operator,'+@BATCHID+' FROM '+@TABLENAME+' (nolock) WHERE '+@whereClause+''    
       
   END    
   ELSE            
    BEGIN            
--SELECT RECORDS FROM TABLE            
SET  @QUERY='SELECT TOP '+@ROW+' MessageID,Mobile,Message,SenderID,SmppID,MessageInsertDate,case Priority when 1 then ''Priority'' when 0 then ''Normal'' when 2 then ''Direct'' end as Priority,            
U_ID,IsUniCode,IsDND,Operator,'+@BATCHID+' FROM '+@TABLENAME+' (nolock) WHERE '+@whereClause+''            
   END            
  --EXECUTE THE QUERY           
exec (@QUERY)              
END 




GO

/* ============================================================
   Procedure: [dbo].[usp_bsnapshot]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_bsnapshot]
@period nvarchar(20)=null,
@range int=null,
@fromdate nvarchar(20)=null,
@todate nvarchar(20)=null
as
begin
--declare @period nvarchar(20)=null,
--@range int=null,
--@fromdate nvarchar(20)=null,
--@todate nvarchar(20)=null
set @period=coalesce(@period,'Week')
set @range=coalesce(@range,1)
set @fromdate = coalesce(CONVERT(DATE,@fromdate),cast(dateadd(d,-7,getdate()) as date))
set @todate = coalesce(CONVERT(DATE,@todate),cast(dateadd(dd,1,getdate()) as date))

select count(UTRBL.ParentID) as MailLinksVisited,UTRBL.ParentID
into #EmailLinksClicked 
from url_tracktbl (nolock)UTRBL
where dbo.[fn_getusertimefromindiantime](UTRBL.ParentID,UTRBL.visiteddate) between @fromdate and @todate 
group by utrbl.ParentID

select COUNT(l.parentid) as SMSLinksClicked,parentid 
into #SMSLinksClicked
from Link_smsTrack(nolock)l 
where dbo.[fn_getusertimefromindiantime](l.Parentid,visitdate) between @fromdate and @todate
group by l.ParentID  

select InquiriesCaptured,Parentid,SourceName 
into #InquiriesCaptured
from
(select COUNT(e.parentid) as InquiriesCaptured,e.Parentid,s.name SourceName
from userenquiry e (nolock) join tbl_MergeLeadsEnquiry t (nolock) on t.EnquiryNo=e.EnquiryID
left join usersourcesettings s (nolock) on s.SourceID=e.SourceName
left join usermediumsettings m (nolock) on m.MediumID=e.MediumName
where dbo.[fn_getusertimefromindiantime](e.parentid,e.CreatedDate) between @fromdate and @todate
group by e.ParentID,s.name,m.name
union
select COUNT(e.parentid) as InquiriesCaptured,e.Parentid,s.name SourceName
from userenquiry e (nolock) left join usersourcesettings s (nolock) on s.SourceID=e.SourceName
left join usermediumsettings m (nolock) on m.MediumID=e.MediumName
where s.Name in ('Landing Page') or SUBSTRING(s.name,1,8)='Webform ' 
group by e.ParentID,s.name,m.name) A

select count(parentid) Conversions,parentid,sum(AmountPaid) ConversionAmount 
into #Conversions
from leadinteractionhistory (nolock) l
where dbo.[fn_getusertimefromindiantime](l.parentid,l.CreatedOn) between @fromdate and @todate
group by ParentID

select clientID Parentid,count(clientID) IncomingCalls
into #incomingCalls 
from Kit19calls k 
where k.context <>'outbound' 
and dbo.[fn_getusertimefromindiantime](k.clientid,k.call_start_time) between @fromdate and @todate
group by clientID

select u.parentid,c.user_id,balance,c.DateCreated,T 
into #LowSMSBalance
from credit_details c(nolock)
join User_Detail u(nolock) on u.user_ID=c.User_ID 
left join 
(select user_id,sum(totalconsumption) T from DailyConsumption  where datediff(dd,Date,getdate())<=7 group by USER_ID) d on d.User_id=u.User_ID
where u.User_ID=u.parentid 
and c.Credit_ID=(select MAX(credit_id) from credit_details b (nolock) where b.user_id=c.user_id) 
and (balance <5000 or Balance <= T)
order by T desc

select u.parentid,c.user_id,balance,c.DateCreated,T 
into #LowMailBalance
from mailcreditdetails c(nolock)
join User_Detail u(nolock) on u.user_ID=c.User_ID 
left join 
(select user_id,sum(totalmailconsumption) T from DailyMailConsumption  where datediff(dd,Date,getdate())<=7 group by USER_ID) d on d.User_id=u.User_ID
where u.User_ID=u.parentid 
and c.Credit_ID=(select MAX(credit_id) from mailcreditdetails b (nolock) where b.user_id=c.user_id) 
and (balance <5000 or Balance <= T)
order by T desc

select u.parentid,p.userid,PlanEndDate,pd.planname 
into #SubscriptionNearingExpiry
from Price_UserSubscriptionDetails p
join User_Detail u(nolock) on u.user_ID=p.UserID
join Price_ServiceMaster pd on pd.PlanID=p.planid and u.Country_ID in ((select value from dbo.fn_split(pd.CountryID,',') union select '110')) 
where u.User_ID=u.parentid 
and p.IsNewPlan=1
and DATEDIFF(dd,getdate(),planenddate)<=15

select parentid,COUNT(ParentID) TotalFollowups 
 into #FollowUpsOverDue from  
userleads   
where FollowUpDate is not null and FollowUpDate<>'' and cast(FollowUpDate as date)<cast(getdate() as date)
group by parentid
  
SELECT count(m.parentID) TicketsNotResponded,m.ParentID
into #TicketsNotResponded --Query needs to be revised to match TicketRaisedTime with SLA time
       FROM [Serv_TicketMaster] m
where not exists(select 1 from Serv_TicketHistory h where m.TicketID=h.TicketID and h.Ticket_Response =1)
and not exists(select 1 from Serv_Ticket_Merg t where t.ticket1_id=m.TicketID)
and not exists(select 1 from Serv_Ticket_Split t where t.ticketid=m.TicketID)
group by m.ParentID

select parentid,coalesce(LastLogin1,
(select max(c.DateCreated) from credit_details c (nolock) where c.User_ID=u.parentid and c.user_id=c.FromUser_ID),DateCreated) LastLogin 
into #LastLogin
from user_detail(nolock) u 
where datediff(mm,lastlogin1,getdate())>6 or LastLogin1 is null


select f.clientid,count(puniqueid) CallsReceived,SUM(case when dialstatus in ('NOANSWER','Busy') then 1 else 0 end)
CallsMissed
into #CallsMissed
from Kit19CallsDialled k 
join Kit19Calls f on f.uniqueid=k.puniqueid 
where f.call_start_time between @fromdate and @todate
group by f.clientid



select u.parentid,u.mobile,u.email,e.MailLinksVisited,ic.IncomingCalls,cm.CallsMissed,c.Conversions,c.ConversionAmount
,f.TotalFollowups as FollowUpsOverDue,sum(i.InquiriesCaptured) InquiriesCaptured,l.LastLogin,lm.Balance,ls.Balance
,sl.SMSLinksClicked,s.PlanEndDate,t.TicketsNotResponded
from user_detail u (nolock) 
left join #EmailLinksClicked e on e.ParentID=u.ParentID
left join #CallsMissed cm on cm.clientid=u.ParentID
left join #Conversions c on c.ParentID=u.ParentID
left join #incomingCalls ic on ic.Parentid=u.ParentID 
left join #FollowUpsOverDue f on f.ParentID=u.ParentID
left join #InquiriesCaptured i on i.ParentID=u.ParentID
left join #LastLogin l on l.ParentID=u.ParentID
left join #LowMailBalance lm on lm.ParentID=u.ParentID
left join #LowSMSBalance ls on ls.ParentID=u.ParentID
left join #SMSLinksClicked sl on sl.Parentid=u.ParentID
left join #SubscriptionNearingExpiry s on s.ParentID=u.ParentID
left join #TicketsNotResponded t on t.ParentID=u.ParentID
group by u.parentid,u.mobile,u.email,e.MailLinksVisited,cm.CallsReceived,cm.CallsMissed,c.Conversions,c.ConversionAmount
,f.TotalFollowups,l.LastLogin,lm.Balance,ls.Balance
,sl.SMSLinksClicked,s.PlanEndDate,t.TicketsNotResponded




--select * from user_detail where mobile in ('7303294586','9716308423')



end




GO

