SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[USP_bulk_insert_groupdetail]
	@user_id INT, -- from bigint,
	@groupid BIGINT
AS
BEGIN
	--DELETE
	--FROM   Contact_Group_Detail
	--WHERE  USER_ID = @user_id
	--       AND group_id = @groupid 
	
	--INSERT INTO Contact_Group_Detail
	--  (
	--    m_id,
	--    USER_ID,
	--    group_id,
	--    contact_id
	--  )
	--SELECT m_id,
	--       USER_ID,
	--       group_id,
	--       contact_id
	--FROM   dbo.Contact_Detail
	--WHERE  USER_ID = @user_id
	--       AND group_id = @groupid
	
	
	UPDATE kd
	SET    kd.Contact_ID = cd.Contact_ID
	FROM   Contact_Group_Detail kd
	       INNER JOIN Contact_Detail AS cd
	            ON  kd.Contact_Mobile = cd.Contact_Mobile
	            AND cd.[User_ID] = @user_id
	WHERE  kd.[User_ID] = @user_id
	       AND kd.Group_ID = @groupid
END


